// Elaborates resolved surface modules into KCore while preserving observability metadata.
module SurfaceElaboration =
    open TypeSignatures

    type private TraitMemberInfo =
        { Name: string
          Scheme: TypeScheme
          DefaultDefinition: LetDefinition option }

    type private TraitInfo =
        { Identity: DeclarationIdentity
          TypeParameters: string list
          Supertraits: TraitConstraint list
          Members: Map<string, TraitMemberInfo> }
        member this.ModuleIdentity = DeclarationIdentity.moduleIdentity this.Identity
        member this.Name = DeclarationIdentity.name this.Identity

    type private InstanceInfo =
        { ModuleIdentity: ModuleIdentity
          Trait: TraitReference
          InstanceKey: string
          Constraints: TraitConstraint list
          HeadTypes: TypeExpr list
          Members: Map<string, LetDefinition> }

    type private TypeAliasInfo =
        { Identity: DeclarationIdentity
          IsOpaque: bool
          Parameters: string list
          Body: TypeExpr
          TerminationCertified: bool
          ConversionReducible: bool }
        member this.ModuleIdentity = DeclarationIdentity.moduleIdentity this.Identity
        member this.Name = DeclarationIdentity.name this.Identity

    type private TypeFacetKind =
        | TypeAliasFacet
        | DataFacet
        | EffectFacet
        | AbstractFacet

    type private TypeFacetInfo =
        { Identity: DeclarationIdentity
          FacetKind: TypeFacetKind
          IsOpaque: bool
          Scheme: TypeScheme }
        member this.ModuleIdentity = DeclarationIdentity.moduleIdentity this.Identity
        member this.Name = DeclarationIdentity.name this.Identity

    type private StaticObjectInfo =
        { Identity: SemanticObjectIdentity
          NameSegments: string list
          Scheme: TypeScheme option
          ScopedEffect: EffectSemanticDeclaration option
          TypeFacet: TypeFacetInfo option }
        member this.ObjectKind =
            SemanticObjectIdentity.kind this.Identity

    type private RecordSurfaceFieldInfo =
        { Name: string
          IsOpaque: bool
          IsImplicit: bool
          TypeTokens: Token list }

    type private RecordSurfaceInfo =
        { Fields: RecordSurfaceFieldInfo list
          RowTail: string option }

    type private BindingSchemeInfo =
        { Identity: DeclarationIdentity
          IsPattern: bool
          Scheme: TypeScheme
          TypeTokens: Token list
          ParameterLayouts: Parameter list option
          ConstructorTypeName: string option
          DefaultArguments: Map<string, SurfaceExpression> }
        member this.ModuleIdentity = DeclarationIdentity.moduleIdentity this.Identity
        member this.Name = DeclarationIdentity.name this.Identity

    type private ProjectionInfo =
        { Identity: DeclarationIdentity
          Binders: ProjectionBinder list
          ReturnType: TypeExpr
          Body: SurfaceProjectionBody option }
        member this.ModuleIdentity = DeclarationIdentity.moduleIdentity this.Identity
        member this.Name = DeclarationIdentity.name this.Identity

    type private OrdinaryVisibleTermCandidate =
        | OrdinaryVisibleBindingCandidate of ImportedOrdinaryCandidatePriority * BindingSchemeInfo
        | OrdinaryVisibleExportedBindingCandidate of ImportedOrdinaryCandidatePriority * ModuleIdentity * string
        | OrdinaryVisibleConstructorCandidate of ImportedOrdinaryCandidatePriority * BindingSchemeInfo
        | OrdinaryVisibleModuleCandidate of ImportedOrdinaryCandidatePriority * ModuleIdentity

    and private ImportedOrdinaryCandidatePriority =
        | ExplicitImportedItem
        | WildcardImportedItem

    type private VisibleOrdinaryTermGroup =
        { Binding: BindingSchemeInfo option
          Constructor: BindingSchemeInfo option
          ModuleIdentity: ModuleIdentity option
          AmbiguousCandidates: OrdinaryVisibleTermCandidate list }

    type private VisibleOrdinaryTermResolution =
        | VisibleOrdinaryBinding of BindingSchemeInfo
        | VisibleOrdinaryConstructor of BindingSchemeInfo
        | VisibleOrdinaryModule of ModuleIdentity
        | VisibleOrdinaryAmbiguous of OrdinaryVisibleTermCandidate list

    type private VisibleStaticFacetGroup =
        { StaticObject: StaticObjectInfo option
          TypeFacet: TypeFacetInfo option
          Trait: TraitInfo option }

    type private VisibleEnvironmentComponents =
        { ImportedUnschemedOrdinaryTermNames: Set<string>
          VisibleTypeAliases: Map<string, TypeAliasInfo>
          VisibleTypeFacets: Map<string, TypeFacetInfo>
          VisibleQualifiedTypeFacets: Map<string list, TypeFacetInfo>
          VisibleModulePaths: Map<string list, ModuleIdentity>
          VisibleModules: Map<string, ModuleIdentity>
          VisibleRecordTypes: Map<string, RecordSurfaceInfo>
          VisibleConstructors: Map<string, BindingSchemeInfo>
          AmbiguousVisibleOrdinaryTerms: Map<string, OrdinaryVisibleTermCandidate list>
          VisibleProjections: Map<string, ProjectionInfo>
          VisibleTraits: Map<string, TraitInfo>
          VisibleQualifiedTraits: Map<string list, TraitInfo>
          VisibleInstances: InstanceInfo list }

    let private renderOrdinaryVisibleTermCandidate candidate =
        match candidate with
        | OrdinaryVisibleBindingCandidate(_, info) when info.IsPattern ->
            $"pattern term '{info.Name}' from module '{ModuleIdentity.text info.ModuleIdentity}'"
        | OrdinaryVisibleBindingCandidate(_, info) ->
            $"term '{info.Name}' from module '{ModuleIdentity.text info.ModuleIdentity}'"
        | OrdinaryVisibleExportedBindingCandidate(_, moduleIdentity, name) ->
            $"term '{name}' from module '{ModuleIdentity.text moduleIdentity}'"
        | OrdinaryVisibleConstructorCandidate(_, info) ->
            $"constructor '{info.Name}' from module '{ModuleIdentity.text info.ModuleIdentity}'"
        | OrdinaryVisibleModuleCandidate(_, moduleIdentity) ->
            $"module '{ModuleIdentity.text moduleIdentity}'"

    let private ordinaryNameAmbiguityMessage name candidates =
        let candidateText =
            candidates
            |> List.map renderOrdinaryVisibleTermCandidate
            |> String.concat ", "

        $"Name '{name}' is ambiguous between {candidateText}. Use an explicit import item, module alias, or qualification."

    let private directVisibleOrdinaryTermCandidates (group: VisibleOrdinaryTermGroup) =
        [
            match group.Binding with
            | Some info -> OrdinaryVisibleBindingCandidate(WildcardImportedItem, info)
            | None -> ()

            match group.Constructor with
            | Some info -> OrdinaryVisibleConstructorCandidate(WildcardImportedItem, info)
            | None -> ()

            match group.ModuleIdentity with
            | Some moduleIdentity -> OrdinaryVisibleModuleCandidate(WildcardImportedItem, moduleIdentity)
            | None -> ()
        ]

    let private visibleOrdinaryTermCandidates (group: VisibleOrdinaryTermGroup) =
        if List.isEmpty group.AmbiguousCandidates then
            directVisibleOrdinaryTermCandidates group
        else
            group.AmbiguousCandidates

    let private resolveVisibleOrdinaryTermGroup (group: VisibleOrdinaryTermGroup) =
        match visibleOrdinaryTermCandidates group with
        | [ OrdinaryVisibleBindingCandidate(_, info) ] -> Some(VisibleOrdinaryBinding info)
        | [ OrdinaryVisibleConstructorCandidate(_, info) ] -> Some(VisibleOrdinaryConstructor info)
        | [ OrdinaryVisibleModuleCandidate(_, moduleIdentity) ] -> Some(VisibleOrdinaryModule moduleIdentity)
        | [] -> None
        | candidates -> Some(VisibleOrdinaryAmbiguous candidates)

    type private ProjectionDescriptorAliasInfo =
        { Projection: ProjectionInfo
          RemainingPlaceBinders: ProjectionPlaceBinder list }

    type private TermNamespaceContributor =
        | TermSignatureContributor
        | TermLetContributor
        | TermProjectionContributor
        | TermExpectationContributor

    type private TypeNamespaceContributor =
        | ExpectTypeContributor
        | OrdinaryTypeContributor
        | EffectTypeContributor

    type private TraitNamespaceContributor =
        | ExpectTraitContributor
        | OrdinaryTraitContributor

    type private ModuleSurfaceInfo =
        { TypeAliases: Map<string, TypeAliasInfo>
          TypeFacets: Map<string, TypeFacetInfo>
          RecordTypes: Map<string, RecordSurfaceInfo>
          BindingSchemes: Map<string, BindingSchemeInfo>
          TopLevelDefinitionsByName: Map<string, LetDefinition>
          Constructors: Map<string, BindingSchemeInfo>
          Projections: Map<string, ProjectionInfo>
          Traits: Map<string, TraitInfo>
          Instances: InstanceInfo list
          Imports: ImportSpec list
          ExportedTerms: Set<string>
          ExportedConstructors: Set<string>
          ExportedConstructorsByType: Map<string, Set<string>>
          ExportedTypes: Set<string>
          ExportedTraits: Set<string> }

    type private BindingLoweringEnvironment =
        { CurrentModuleIdentity: ModuleIdentity
          CurrentModuleTopLevelDefinitions: Set<string>
          ImportedUnschemedOrdinaryTermNames: Set<string>
          SurfaceIndex: Map<ModuleIdentity, ModuleSurfaceInfo>
          VisibleTypeAliases: Map<string, TypeAliasInfo>
          VisibleTypeFacets: Map<string, TypeFacetInfo>
          VisibleQualifiedTypeFacets: Map<string list, TypeFacetInfo>
          VisibleStaticGroups: Map<string list, VisibleStaticFacetGroup>
          VisibleStaticObjects: Map<string list, StaticObjectInfo>
          VisibleModulePaths: Map<string list, ModuleIdentity>
          VisibleModules: Map<string, ModuleIdentity>
          VisibleRecordTypes: Map<string, RecordSurfaceInfo>
          VisibleBindings: Map<string, BindingSchemeInfo>
          VisibleConstructors: Map<string, BindingSchemeInfo>
          VisibleOrdinaryGroups: Map<string, VisibleOrdinaryTermGroup>
          VisibleProjections: Map<string, ProjectionInfo>
          VisibleTraits: Map<string, TraitInfo>
          VisibleQualifiedTraits: Map<string list, TraitInfo>
          VisibleInstances: InstanceInfo list
          ElaborationAvailableBindings: Set<string>
          ConstraintDictionaries: Map<string, KCoreExpression>
          ConstrainedMembers: Map<string, string * string> }

    type private PreparedCallArgument =
        | ExplicitArgument of SurfaceExpression
        | ImplicitArgument of KCoreExpression

    type private PreparedCallParameter =
        { Layout: Parameter option
          ParameterType: TypeExpr
          AssignedArgument: PreparedCallArgument option }

    type private PreparedBindingCall =
        { InstantiatedScheme: TypeScheme
          ResultType: TypeExpr
          Parameters: PreparedCallParameter list
          Arguments: PreparedCallArgument list }

    type private SyntheticRecordLayout =
        { TypeKey: string
          TypeExpr: TypeExpr
          TypeName: string
          ConstructorName: string
          TypeParameters: string list
          Fields: RecordField list
          Provenance: KCoreOrigin }

    type private ConstraintResolutionResult =
        | ConstraintUnresolved
        | ConstraintResolved of InstanceInfo * Map<string, TypeExpr>
        | ConstraintAmbiguous of TraitConstraint * InstanceInfo list

    let private tokensText (tokens: Token list) =
        tokens
        |> List.map (fun token -> token.Text)
        |> String.concat " "

    let private tryParseTypeText (text: string) =
        let source = SourceText.From("__surface_elaboration_type__.kp", text)
        let lexResult = Lexer.tokenize source

        if not (List.isEmpty lexResult.Diagnostics) then
            None
        else
            TypeSignatures.parseType lexResult.Tokens

    let private tryParseSchemeText (text: string) =
        let source = SourceText.From("__surface_elaboration_type__.kp", text)
        let lexResult = Lexer.tokenize source

        if not (List.isEmpty lexResult.Diagnostics) then
            None
        else
            TypeSignatures.parseScheme lexResult.Tokens

    let private typeTextTokens (text: string) =
        let source = SourceText.From("__surface_elaboration_type__.kp", text)
        Lexer.tokenize source
        |> fun lexResult -> lexResult.Tokens
        |> List.filter (fun token -> token.Kind <> EndOfFile)

    let private significantTokens (tokens: Token list) =
        tokens
        |> List.filter (fun token ->
            match token.Kind with
            | Newline
            | Indent
            | Dedent
            | EndOfFile -> false
            | _ -> true)

    let private moduleNameText moduleName =
        moduleName
        |> Option.map SyntaxFacts.moduleNameToText
        |> Option.defaultValue "<unknown>"

    let private moduleIdentityText moduleIdentity =
        moduleIdentity
        |> Option.map ModuleIdentity.text
        |> Option.defaultValue "<unknown>"

    let private moduleIdentityOfSegments segments =
        segments |> ModuleIdentity.ofSegments

    let private moduleIdentityOfOptionalSegments segments =
        segments |> ModuleIdentity.ofOptionalSegments

    let private moduleIdentityOfModuleSpecifier specifier =
        specifier |> SymbolicIdentity.moduleIdentityOfSpecifier

    let private topLevelDeclarationIdentity moduleIdentity name kind =
        DeclarationIdentity.topLevel moduleIdentity name kind

    let private moduleDeclarationIdentity moduleIdentity =
        moduleIdentity
        |> ModuleIdentity.segments
        |> List.last
        |> fun moduleName -> DeclarationIdentity.topLevel moduleIdentity moduleName ModuleDeclaration

    let private semanticObjectIdentity declarationIdentity kind =
        SemanticObjectIdentity.create declarationIdentity kind

    let private traitReferenceSegments traitReference =
        TypeSignatures.TraitReference.segments traitReference

    let private traitReferenceText traitReference =
        TypeSignatures.TraitReference.text traitReference

    let private traitReferenceLocalName traitReference =
        TypeSignatures.TraitReference.localName traitReference

    let private traitReferenceCanonicalName traitReference =
        TypeSignatures.TraitReference.canonicalName traitReference

    let private traitReferenceRuntimeName traitReference =
        traitReferenceLocalName traitReference

    let private traitConstraintText (constraintInfo: TraitConstraint) =
        traitReferenceText constraintInfo.Trait

    let private traitConstraintLocalName (constraintInfo: TraitConstraint) =
        traitReferenceLocalName constraintInfo.Trait

    let private traitConstraintCanonicalName (constraintInfo: TraitConstraint) =
        traitReferenceCanonicalName constraintInfo.Trait

    let private traitConstraintRuntimeName (constraintInfo: TraitConstraint) =
        traitReferenceRuntimeName constraintInfo.Trait

    let private traitConstraintTypeName (constraintInfo: TraitConstraint) =
        TypeName(traitReferenceSegments constraintInfo.Trait, constraintInfo.Arguments)

    let private traitConstraintBinderStem (constraintInfo: TraitConstraint) =
        (traitConstraintText constraintInfo).Replace(".", "_", StringComparison.Ordinal)

    let private unqualifiedTraitConstraint traitName arguments =
        { Trait = TypeSignatures.TraitReference.unqualified traitName
          Arguments = arguments }

    let private qualifiedTraitConstraint traitNameSegments arguments =
        { Trait = TypeSignatures.TraitReference.ofSegments traitNameSegments
          Arguments = arguments }

    let private tryResolveVisibleTypeFacetByRoot
        (environment: BindingLoweringEnvironment)
        root
        =
        environment.VisibleStaticGroups
        |> Map.tryFind [ root ]
        |> Option.bind (fun group -> group.TypeFacet)

    let private tryResolveVisibleTraitByRoot
        (environment: BindingLoweringEnvironment)
        root
        =
        environment.VisibleStaticGroups
        |> Map.tryFind [ root ]
        |> Option.bind (fun group -> group.Trait)

    let private tryResolveTraitInfoByReference
        (environment: BindingLoweringEnvironment)
        (traitReference: TypeSignatures.TraitReference)
        =
        match TypeSignatures.TraitReference.identity traitReference with
        | Some identity ->
            environment.SurfaceIndex
            |> Map.tryFind (DeclarationIdentity.moduleIdentity identity)
            |> Option.bind (fun moduleInfo ->
                moduleInfo.Traits
                |> Map.tryFind (DeclarationIdentity.name identity)
                |> Option.filter (fun info -> info.Identity = identity))
        | None ->
            match traitReferenceSegments traitReference with
            | [] ->
                None
            | [ traitName ] ->
                tryResolveVisibleTraitByRoot environment traitName
            | _ ->
                environment.VisibleQualifiedTraits
                |> Map.tryFind (traitReferenceSegments traitReference)

    let private attachResolvedTraitReference
        (environment: BindingLoweringEnvironment)
        (traitReference: TypeSignatures.TraitReference)
        =
        tryResolveTraitInfoByReference environment traitReference
        |> Option.map (fun traitInfo -> TypeSignatures.TraitReference.attachIdentity traitInfo.Identity traitReference)
        |> Option.defaultValue traitReference

    let private attachResolvedTraitConstraint
        (environment: BindingLoweringEnvironment)
        (constraintInfo: TraitConstraint)
        =
        { constraintInfo with
            Trait = attachResolvedTraitReference environment constraintInfo.Trait }

    let private attachResolvedInstanceTrait
        (environment: BindingLoweringEnvironment)
        (instanceInfo: InstanceInfo)
        =
        match TypeSignatures.TraitReference.identity instanceInfo.Trait with
        | Some _ ->
            instanceInfo
        | None ->
            environment.SurfaceIndex
            |> Map.tryFind instanceInfo.ModuleIdentity
            |> Option.bind (fun moduleInfo ->
                moduleInfo.Traits
                |> Map.tryFind (traitReferenceLocalName instanceInfo.Trait)
                |> Option.map (fun traitInfo ->
                    { instanceInfo with
                        Trait = TypeSignatures.TraitReference.attachIdentity traitInfo.Identity instanceInfo.Trait }))
            |> Option.defaultValue instanceInfo

    let private tryFindVisibleStaticObject (environment: BindingLoweringEnvironment) nameSegments =
        environment.VisibleStaticObjects |> Map.tryFind nameSegments

    let private tryFindVisibleStaticGroup (environment: BindingLoweringEnvironment) nameSegments =
        environment.VisibleStaticGroups |> Map.tryFind nameSegments

    let private tryResolveVisibleModuleIdentity (environment: BindingLoweringEnvironment) nameSegments =
        environment.VisibleModulePaths
        |> Map.tryFind nameSegments

    let private tryResolveQualifiedModuleIdentity
        (environment: BindingLoweringEnvironment)
        moduleSegments
        =
        tryResolveVisibleModuleIdentity environment moduleSegments
        |> Option.orElseWith (fun () ->
            let moduleIdentity = moduleIdentityOfSegments moduleSegments

            environment.SurfaceIndex
            |> Map.tryFind moduleIdentity
            |> Option.map (fun _ -> moduleIdentity))

    let private bindingIdentity moduleIdentity name =
        topLevelDeclarationIdentity moduleIdentity name TermDeclaration

    let private constructorIdentity moduleIdentity name =
        topLevelDeclarationIdentity moduleIdentity name ConstructorDeclaration

    let private typeAliasIdentity moduleIdentity name =
        topLevelDeclarationIdentity moduleIdentity name TypeAliasDeclaration

    let private typeFacetIdentity moduleIdentity name =
        topLevelDeclarationIdentity moduleIdentity name TypeFacetDeclaration

    let private traitIdentity moduleIdentity name =
        topLevelDeclarationIdentity moduleIdentity name TraitDeclaration

    let private projectionIdentity moduleIdentity name =
        topLevelDeclarationIdentity moduleIdentity name ProjectionDeclaration

    let private aliasImportedSameSpellingConstructorBinding localTypeName (bindingInfo: BindingSchemeInfo) =
        let originalTypeName = bindingInfo.ConstructorTypeName |> Option.defaultValue bindingInfo.Name
        let qualifiedOriginalType =
            TypeName((ModuleIdentity.segments bindingInfo.ModuleIdentity) @ [ originalTypeName ], [])

        let substitution = Map.ofList [ originalTypeName, qualifiedOriginalType ]

        { bindingInfo with
            ConstructorTypeName = Some localTypeName
            Scheme = TypeSignatures.applySchemeSubstitution substitution bindingInfo.Scheme }

    let private bindingSchemeInfo identity isPattern scheme typeTokens parameterLayouts constructorTypeName defaultArguments =
        { Identity = identity
          IsPattern = isPattern
          Scheme = scheme
          TypeTokens = typeTokens
          ParameterLayouts = parameterLayouts
          ConstructorTypeName = constructorTypeName
          DefaultArguments = defaultArguments }

    let private staticObjectInfo identity nameSegments scheme scopedEffect typeFacet =
        { Identity = identity
          NameSegments = nameSegments
          Scheme = scheme
          ScopedEffect = scopedEffect
          TypeFacet = typeFacet }

    let private preludeModuleIdentity = ModuleIdentity.ofSegments Stdlib.PreludeModuleName

    let private knownTypeExpr knownType arguments =
        TypeSignatures.knownType knownType arguments

    let private matchesKnownType knownType nameSegments =
        CompilerKnownSymbols.KnownTypes.matchesName knownType nameSegments

    let private declarationName (declaration: TopLevelDeclaration) =
        match declaration with
        | SignatureDeclaration declaration -> Some declaration.Name
        | LetDeclaration declaration -> declaration.Name
        | DataDeclarationNode declaration -> Some declaration.Name
        | TypeAliasNode declaration -> Some declaration.Name
        | TraitDeclarationNode declaration -> Some declaration.Name
        | InstanceDeclarationNode declaration -> Some declaration.TraitName
        | ExpectDeclarationNode (ExpectTypeDeclaration declaration) -> Some declaration.Name
        | ExpectDeclarationNode (ExpectTraitDeclaration declaration) -> Some declaration.Name
        | ExpectDeclarationNode (ExpectTermDeclaration declaration) -> Some declaration.Name
        | _ -> None

    let private declarationOrigin filePath moduleIdentity declaration =
        { FilePath = filePath
          ModuleIdentity = moduleIdentity
          DeclarationName = declarationName declaration
          IntroductionKind = "source" }

    let private syntheticOrigin filePath moduleIdentity declarationName introductionKind =
        { FilePath = filePath
          ModuleIdentity = moduleIdentity
          DeclarationName = Some declarationName
          IntroductionKind = introductionKind }

    let private stableSyntheticSuffix (value: string) =
        let bytes = Encoding.UTF8.GetBytes(value)
        let hash = SHA256.HashData(bytes)

        hash
        |> Seq.take 10
        |> Seq.map (fun value -> value.ToString("x2"))
        |> String.concat ""

    let private syntheticRecordTypeName recordKey =
        "__kappa_record_" + stableSyntheticSuffix recordKey

    let private syntheticRecordConstructorName recordKey =
        syntheticRecordTypeName recordKey

    let private syntheticLetSource name =
        LetDeclaration
            { Visibility = Some Visibility.Private
              IsOpaque = false
              TotalityAssertion = None
              IsPattern = false
              Name = Some name
              Parameters = []
              HeaderTokens = []
              ReturnTypeTokens = None
              BodyTokens = []
              Body = None }

    let private lowerKCoreParameter (parameter: Parameter) (parameterType: TypeExpr option) : KCoreParameter =
        { Name = parameter.Name
          Quantity = parameter.Quantity
          IsImplicit = parameter.IsImplicit
          Type = parameterType
          TypeText =
            parameterType
            |> Option.map TypeSignatures.toText
            |> Option.orElseWith (fun () -> parameter.TypeTokens |> Option.map tokensText) }

    let private lowerSyntheticKCoreParameter
        (name: string)
        (quantity: Quantity option)
        (isImplicit: bool)
        (parameterType: TypeExpr option)
        : KCoreParameter =
        { Name = name
          Quantity = quantity
          IsImplicit = isImplicit
          Type = parameterType
          TypeText = parameterType |> Option.map TypeSignatures.toText }

    let private explicitKCoreArgument expression =
        { ArgumentKind = KCoreExplicitArgument
          Expression = expression }

    let private implicitKCoreArgument expression =
        { ArgumentKind = KCoreImplicitArgument
          Expression = expression }

    let private inoutKCoreArgument expression =
        { ArgumentKind = KCoreInoutArgument
          Expression = expression }

    let rec private lowerKCorePattern (pattern: SurfacePattern) =
        match pattern with
        | WildcardPattern ->
            KCoreWildcardPattern
        | NamePattern name ->
            KCoreNamePattern name
        | AsPattern(_, inner) ->
            lowerKCorePattern inner
        | TypedPattern(inner, _) ->
            lowerKCorePattern inner
        | LiteralPattern literal ->
            KCoreLiteralPattern literal
        | ConstructorPattern(name, arguments) ->
            KCoreConstructorPattern(name, arguments |> List.map lowerKCorePattern)
        | NamedConstructorPattern(name, fields) ->
            KCoreConstructorPattern(name, fields |> List.map (fun field -> lowerKCorePattern field.Pattern))
        | TuplePattern _ ->
            KCoreWildcardPattern
        | VariantPattern(BoundVariantPattern(name, _))
        | VariantPattern(RestVariantPattern name) ->
            KCoreNamePattern name
        | VariantPattern(WildcardVariantPattern _) ->
            KCoreWildcardPattern
        | OrPattern alternatives ->
            KCoreOrPattern(alternatives |> List.map lowerKCorePattern)
        | AnonymousRecordPattern _ ->
            KCoreWildcardPattern

    let private collectPatternNames (pattern: SurfacePattern) =
        let rec loop current =
            seq {
                match current with
                | NamePattern name -> yield name
                | AsPattern(name, inner) ->
                    yield name
                    yield! loop inner
                | TypedPattern(inner, _) ->
                    yield! loop inner
                | ConstructorPattern(_, arguments) ->
                    for argument in arguments do
                        yield! loop argument
                | NamedConstructorPattern(_, fields) ->
                    for field in fields do
                        yield! loop field.Pattern
                | TuplePattern elements ->
                    for element in elements do
                        yield! loop element
                | VariantPattern(BoundVariantPattern(name, _))
                | VariantPattern(RestVariantPattern name) ->
                    yield name
                | VariantPattern(WildcardVariantPattern _) ->
                    ()
                | OrPattern alternatives ->
                    match alternatives with
                    | first :: _ ->
                        yield! loop first
                    | [] ->
                        ()
                | AnonymousRecordPattern(fields, rest) ->
                    for field in fields do
                        yield! loop field.Pattern
                    match rest with
                    | Some(BindRecordPatternRest name) -> yield name
                    | _ -> ()
                | WildcardPattern
                | LiteralPattern _ -> ()
            }

        loop pattern |> Seq.toList

    let private isOmegaText text =
        String.Equals(text, "\u03c9", StringComparison.Ordinal)
        || String.Equals(text, "omega", StringComparison.Ordinal)

    let private isQuantityVariableToken (token: Token) =
        if token.Kind <> Identifier then
            false
        else
            let text = SyntaxFacts.trimIdentifierQuotes token.Text
            not (String.IsNullOrEmpty text) && not (Char.IsUpper text[0])

    let private tryParseQuantityPrefix (tokens: Token list) =
        match tokens with
        | { Kind = IntegerLiteral; Text = "0" } :: rest ->
            Some(QuantityZero, rest)
        | { Kind = IntegerLiteral; Text = "1" } :: rest ->
            Some(QuantityOne, rest)
        | { Kind = Operator; Text = "&" } :: { Kind = LeftBracket } :: regionToken :: { Kind = RightBracket } :: rest
            when Token.isName regionToken ->
            Some(QuantityBorrow(Some(SyntaxFacts.trimIdentifierQuotes regionToken.Text)), rest)
        | { Kind = Operator; Text = "&" } :: rest ->
            Some(QuantityBorrow None, rest)
        | { Kind = Operator; Text = "<=" } :: { Kind = IntegerLiteral; Text = "1" } :: rest ->
            Some(QuantityAtMostOne, rest)
        | { Kind = Operator; Text = ">=" } :: { Kind = IntegerLiteral; Text = "1" } :: rest ->
            Some(QuantityAtLeastOne, rest)
        | head :: rest when Token.isName head && isOmegaText head.Text ->
            Some(QuantityOmega, rest)
        | head :: rest when isQuantityVariableToken head ->
            match rest with
            | next :: _ when Token.isName next ->
                Some(QuantityVariable(SyntaxFacts.trimIdentifierQuotes head.Text), rest)
            | _ ->
                None
        | _ ->
            None

    let private tryParseSuspensionMarker (tokens: Token list) =
        match tokens with
        | head :: rest when Token.isKeyword Keyword.Thunk head ->
            Some({ head with Kind = Identifier; Text = CompilerKnownSymbols.KnownTypeNames.Thunk }, rest)
        | head :: rest when Token.isKeyword Keyword.Lazy head ->
            Some({ head with Kind = Identifier; Text = CompilerKnownSymbols.KnownTypeNames.Need }, rest)
        | _ ->
            None

    let private splitTopLevelCommaGroups (tokens: Token list) =
        let tokenArray = tokens |> List.toArray
        let groups = ResizeArray<Token list>()
        let current = ResizeArray<Token>()
        let mutable depth = 0

        for token in tokenArray do
            match token.Kind with
            | LeftParen
            | LeftBracket
            | LeftBrace
            | LeftSetBrace ->
                depth <- depth + 1
                current.Add(token)
            | RightParen
            | RightBracket
            | RightBrace
            | RightSetBrace ->
                depth <- max 0 (depth - 1)
                current.Add(token)
            | Comma when depth = 0 ->
                groups.Add(List.ofSeq current)
                current.Clear()
            | _ ->
                current.Add(token)

        if current.Count > 0 then
            groups.Add(List.ofSeq current)

        groups |> Seq.toList

    let private tryFindTopLevelToken predicate (tokens: Token list) =
        let tokenArray = tokens |> List.toArray
        let mutable depth = 0
        let mutable index = 0
        let mutable result = None

        while index < tokenArray.Length && result.IsNone do
            match tokenArray[index].Kind with
            | LeftParen
            | LeftBracket
            | LeftBrace
            | LeftSetBrace ->
                depth <- depth + 1
            | RightParen
            | RightBracket
            | RightBrace
            | RightSetBrace ->
                depth <- max 0 (depth - 1)
            | _ when depth = 0 && predicate tokenArray[index] ->
                result <- Some index
            | _ ->
                ()

            index <- index + 1

        result

    let private stripOuterParens (tokens: Token list) =
        let trimmed = significantTokens tokens

        match trimmed with
        | { Kind = LeftParen } :: rest when not (List.isEmpty rest) && (List.last rest).Kind = RightParen ->
            Some(rest |> List.take (List.length rest - 1))
        | _ ->
            None

    let private tryParseRecordSurfaceField (tokens: Token list) =
        let tokens = significantTokens tokens

        let isOpaque, afterOpaque =
            match tokens with
            | head :: rest when Token.isKeyword Keyword.Opaque head -> true, rest
            | _ -> false, tokens

        let isImplicit, afterImplicit =
            match afterOpaque with
            | { Kind = AtSign } :: rest -> true, rest
            | _ -> false, afterOpaque

        let afterQuantity =
            match tryParseQuantityPrefix afterImplicit with
            | Some(_, rest) -> rest
            | None -> afterImplicit

        let suspensionTypeToken, afterSuspension =
            match tryParseSuspensionMarker afterQuantity with
            | Some(typeToken, rest) -> Some typeToken, rest
            | None -> None, afterQuantity

        tryFindTopLevelToken (fun token -> token.Kind = Colon) afterSuspension
        |> Option.bind (fun colonIndex ->
            let tokenArray = afterSuspension |> List.toArray
            let binderTokens = tokenArray[0 .. colonIndex - 1] |> Array.toList
            let rawTypeTokens = tokenArray[colonIndex + 1 ..] |> Array.toList
            let typeTokens =
                match suspensionTypeToken with
                | Some typeToken -> typeToken :: rawTypeTokens
                | None -> rawTypeTokens

            match binderTokens, typeTokens with
            | [ nameToken ], _ when Token.isName nameToken && not (List.isEmpty typeTokens) ->
                Some
                    { Name = SyntaxFacts.trimIdentifierQuotes nameToken.Text
                      IsOpaque = isOpaque
                      IsImplicit = isImplicit
                      TypeTokens = typeTokens }
            | _ ->
                None)

    let private tryParseRecordSurfaceInfo (tokens: Token list) =
        stripOuterParens tokens
        |> Option.bind (fun innerTokens ->
            let fieldGroups = splitTopLevelCommaGroups innerTokens |> List.filter (List.isEmpty >> not)
            let fields = ResizeArray<RecordSurfaceFieldInfo>()
            let mutable rowTail = None
            let mutable valid = true

            for group in fieldGroups do
                let fieldTokens, tailTokens =
                    match tryFindTopLevelToken (fun token -> token.Kind = Operator && token.Text = "|") group with
                    | Some pipeIndex ->
                        let tokenArray = group |> List.toArray
                        tokenArray[0 .. pipeIndex - 1] |> Array.toList,
                        Some(tokenArray[pipeIndex + 1 ..] |> Array.toList)
                    | None ->
                        group, None

                match tailTokens with
                | Some tokens ->
                    match significantTokens tokens with
                    | [ rowToken ] when Token.isName rowToken ->
                        rowTail <- Some(SyntaxFacts.trimIdentifierQuotes rowToken.Text)
                    | _ ->
                        valid <- false
                | None ->
                    ()

                if not (List.isEmpty (significantTokens fieldTokens)) then
                    match tryParseRecordSurfaceField fieldTokens with
                    | Some field -> fields.Add(field)
                    | None -> valid <- false

            if valid && (fields.Count > 0 || rowTail.IsSome) then
                Some
                    { Fields = List.ofSeq fields
                      RowTail = rowTail }
            else
                None)

    let private recordSurfaceFieldNames (recordInfo: RecordSurfaceInfo) =
        recordInfo.Fields |> List.map (fun field -> field.Name) |> Set.ofList

    let private tokenText (tokens: Token list) =
        tokens
        |> significantTokens
        |> List.map (fun token -> token.Text)
        |> String.concat " "

    let private stripDelimitedParameterTokens tokens =
        match tokens with
        | { Kind = LeftParen } :: rest when not (List.isEmpty rest) && (List.last rest).Kind = RightParen ->
            Some(false, rest |> List.take (List.length rest - 1))
        | { Kind = LeftBrace } :: rest when not (List.isEmpty rest) && (List.last rest).Kind = RightBrace ->
            Some(true, rest |> List.take (List.length rest - 1))
        | _ ->
            None

    let private tryParseSignatureParameterLayout (tokens: Token list) =
        stripDelimitedParameterTokens tokens
        |> Option.bind (fun (delimiterImplicit, innerTokens) ->
            let isImplicit, innerTokens =
                match innerTokens with
                | { Kind = AtSign } :: rest -> true, rest
                | _ -> delimiterImplicit, innerTokens

            let isInout, remainingTokens =
                match innerTokens with
                | head :: rest when Token.isKeyword Keyword.Inout head -> true, rest
                | _ -> false, innerTokens

            let quantity, bodyTokens =
                if isInout then
                    Some QuantityOne, remainingTokens
                else
                    match tryParseQuantityPrefix remainingTokens with
                    | Some(parsedQuantity, rest) -> Some parsedQuantity, rest
                    | None -> None, remainingTokens

            let suspensionTypeToken, bodyTokens =
                match tryParseSuspensionMarker bodyTokens with
                | Some(typeToken, rest) -> Some typeToken, rest
                | None -> None, bodyTokens

            match bodyTokens with
            | { Kind = Underscore } as underscoreToken :: { Kind = Colon } :: typeTokens when not (List.isEmpty typeTokens) ->
                Some
                    { Name = $"__kappa_signature_wildcard_{underscoreToken.Span.Start}"
                      TypeTokens =
                        Some(suspensionTypeToken |> Option.map (fun typeToken -> typeToken :: typeTokens) |> Option.defaultValue typeTokens)
                      Quantity = quantity
                      IsImplicit = isImplicit
                      IsInout = isInout
                      IsReceiver = false }
            | nameToken :: { Kind = Colon } :: typeTokens when Token.isName nameToken && not (List.isEmpty typeTokens) ->
                Some
                    { Name = SyntaxFacts.trimIdentifierQuotes nameToken.Text
                      TypeTokens =
                        Some(suspensionTypeToken |> Option.map (fun typeToken -> typeToken :: typeTokens) |> Option.defaultValue typeTokens)
                      Quantity = quantity
                      IsImplicit = isImplicit
                      IsInout = isInout
                      IsReceiver = false }
            | _ ->
                None)

    let private bindingSignatureBodyTokens (tokens: Token list) =
        let tokenArray = significantTokens tokens |> List.toArray
        let mutable parenDepth = 0
        let mutable braceDepth = 0
        let mutable bracketDepth = 0
        let mutable bodyStart = 0

        for index = 0 to tokenArray.Length - 1 do
            match tokenArray[index].Kind with
            | LeftParen -> parenDepth <- parenDepth + 1
            | RightParen -> parenDepth <- max 0 (parenDepth - 1)
            | LeftBrace -> braceDepth <- braceDepth + 1
            | RightBrace -> braceDepth <- max 0 (braceDepth - 1)
            | LeftBracket -> bracketDepth <- bracketDepth + 1
            | RightBracket -> bracketDepth <- max 0 (bracketDepth - 1)
            | Operator when parenDepth = 0 && braceDepth = 0 && bracketDepth = 0 && String.Equals(tokenArray[index].Text, "=>", StringComparison.Ordinal) ->
                bodyStart <- index + 1
            | Equals when parenDepth = 0 && braceDepth = 0 && bracketDepth = 0 && index + 1 < tokenArray.Length ->
                match tokenArray[index + 1] with
                | { Kind = Operator; Text = ">" } ->
                    bodyStart <- index + 2
                | _ ->
                    ()
            | _ ->
                ()

        let stripLeadingForall startIndex =
            if startIndex >= tokenArray.Length then
                startIndex
            else
                match tokenArray[startIndex] with
                | token when Token.isKeyword Keyword.Forall token ->
                    let mutable index = startIndex + 1
                    let mutable parsed = true
                    let mutable bodyIndex = startIndex
                    let mutable foundDot = false

                    while parsed && not foundDot && index < tokenArray.Length do
                        match tokenArray[index] with
                        | token when Token.isName token ->
                            index <- index + 1
                        | { Kind = LeftParen } ->
                            let mutable depth = 1
                            let mutable innerIndex = index + 1

                            while depth > 0 && innerIndex < tokenArray.Length do
                                match tokenArray[innerIndex].Kind with
                                | LeftParen -> depth <- depth + 1
                                | RightParen -> depth <- depth - 1
                                | _ -> ()

                                innerIndex <- innerIndex + 1

                            if depth = 0 then
                                index <- innerIndex
                            else
                                parsed <- false
                        | { Kind = Dot } ->
                            bodyIndex <- index + 1
                            foundDot <- true
                        | _ ->
                            parsed <- false

                    if parsed && foundDot then bodyIndex else startIndex
                | _ ->
                    startIndex

        bodyStart <- stripLeadingForall bodyStart
        List.ofArray tokenArray[bodyStart..]

    let private splitSignatureParameterTokens (tokens: Token list) =
        let bodyTokens = bindingSignatureBodyTokens tokens
        let tokenArray = bodyTokens |> List.toArray
        let segments = ResizeArray<Token list>()
        let mutable parenDepth = 0
        let mutable braceDepth = 0
        let mutable bracketDepth = 0
        let mutable segmentStart = 0

        for index = 0 to tokenArray.Length - 1 do
            match tokenArray[index].Kind with
            | LeftParen -> parenDepth <- parenDepth + 1
            | RightParen -> parenDepth <- max 0 (parenDepth - 1)
            | LeftBrace -> braceDepth <- braceDepth + 1
            | RightBrace -> braceDepth <- max 0 (braceDepth - 1)
            | LeftBracket -> bracketDepth <- bracketDepth + 1
            | RightBracket -> bracketDepth <- max 0 (bracketDepth - 1)
            | Arrow when parenDepth = 0 && braceDepth = 0 && bracketDepth = 0 ->
                if index > segmentStart then
                    segments.Add(List.ofArray tokenArray[segmentStart .. index - 1])

                segmentStart <- index + 1
            | _ ->
                ()

        segments |> Seq.toList

    let private mergeParameterLayouts
        (signatureLayouts: Parameter option list option)
        (definitionLayouts: Parameter list option)
        =
        match signatureLayouts, definitionLayouts with
        | Some signatureParameters, Some definitionParameters ->
            let mergeResolvedParameter (signatureParameter: Parameter) (definitionParameter: Parameter) =
                { definitionParameter with
                    Name = signatureParameter.Name
                    TypeTokens = signatureParameter.TypeTokens |> Option.orElse definitionParameter.TypeTokens
                    Quantity = signatureParameter.Quantity |> Option.orElse definitionParameter.Quantity
                    IsImplicit = signatureParameter.IsImplicit
                    IsInout = signatureParameter.IsInout }

            let rec mergeAligned
                (signatureParameters: Parameter option list)
                (definitionParameters: Parameter list)
                (merged: Parameter list)
                =
                match signatureParameters with
                | [] ->
                    if List.isEmpty definitionParameters then
                        Some(List.rev merged)
                    else
                        None
                | signatureParameter :: restSignatureParameters ->
                    match signatureParameter, definitionParameters with
                    | Some signatureParameter, definitionParameter :: restDefinitionParameters
                        when String.Equals(signatureParameter.Name, definitionParameter.Name, StringComparison.Ordinal) ->
                        mergeAligned
                            restSignatureParameters
                            restDefinitionParameters
                            (mergeResolvedParameter signatureParameter definitionParameter :: merged)
                    | Some signatureParameter, _ ->
                        mergeAligned restSignatureParameters definitionParameters (signatureParameter :: merged)
                    | None, definitionParameter :: restDefinitionParameters ->
                        mergeAligned restSignatureParameters restDefinitionParameters (definitionParameter :: merged)
                    | None, [] ->
                        mergeAligned restSignatureParameters [] merged

            match mergeAligned signatureParameters definitionParameters [] with
            | Some merged ->
                Some merged
            | None when List.length signatureParameters = List.length definitionParameters ->
                List.zip signatureParameters definitionParameters
                |> List.map (fun (signatureParameter, definitionParameter) ->
                    match signatureParameter with
                    | Some signatureParameter -> mergeResolvedParameter signatureParameter definitionParameter
                    | None -> definitionParameter)
                |> Some
            | None ->
                definitionLayouts
        | Some signatureParameters, None when signatureParameters |> List.forall Option.isSome ->
            signatureParameters |> List.choose id |> Some
        | _ ->
            definitionLayouts

    let private stripForallOnlyParameterLayouts
        (scheme: TypeScheme)
        (parameterLayouts: Parameter list option)
        =
        parameterLayouts
        |> Option.map (fun layouts ->
            let rec stripLeadingForallLayouts
                (remainingBinders: TypeSignatures.ForallBinder list)
                (remainingLayouts: Parameter list)
                =
                match remainingBinders, remainingLayouts with
                | binder :: restBinders, layout :: restLayouts
                    when String.Equals(binder.Name, layout.Name, StringComparison.Ordinal) ->
                    stripLeadingForallLayouts restBinders restLayouts
                | _ ->
                    remainingLayouts

            stripLeadingForallLayouts scheme.Forall layouts)

    let private stripLeadingConstraintAliasParameterLayouts
        (scheme: TypeScheme)
        (parameterLayouts: Parameter list option)
        =
        let constraintMatchesLayoutType (constraintInfo: TraitConstraint) layoutType =
            match layoutType with
            | TypeName([ traitName ], arguments) ->
                [ traitName ] = traitReferenceSegments constraintInfo.Trait
                && List.length arguments = List.length constraintInfo.Arguments
                && List.forall2 TypeSignatures.definitionallyEqual arguments constraintInfo.Arguments
            | TypeName(qualifiedName, arguments) ->
                qualifiedName = traitReferenceSegments constraintInfo.Trait
                && List.length arguments = List.length constraintInfo.Arguments
                && List.forall2 TypeSignatures.definitionallyEqual arguments constraintInfo.Arguments
            | _ ->
                false

        parameterLayouts
        |> Option.map (fun layouts ->
            let rec stripLeadingConstraintLayouts
                (remainingConstraints: TraitConstraint list)
                (remainingLayouts: Parameter list)
                =
                match remainingConstraints, remainingLayouts with
                | constraintInfo :: restConstraints, layout :: restLayouts when layout.IsImplicit ->
                    let matchesConstraint =
                        layout.TypeTokens
                        |> Option.bind TypeSignatures.parseType
                        |> Option.exists (constraintMatchesLayoutType constraintInfo)

                    if matchesConstraint || layout.TypeTokens.IsNone then
                        stripLeadingConstraintLayouts restConstraints restLayouts
                    else
                        remainingLayouts
                | _ ->
                    remainingLayouts

            stripLeadingConstraintLayouts scheme.Constraints layouts)

    let private normalizedVisibleBindingParameterLayouts
        (bindingInfo: BindingSchemeInfo)
        (scheme: TypeScheme)
        =
        let signatureParameterLayouts =
            bindingInfo.TypeTokens
            |> splitSignatureParameterTokens
            |> function
                | [] -> None
                | parameterTokens -> Some(parameterTokens |> List.map tryParseSignatureParameterLayout)

        mergeParameterLayouts signatureParameterLayouts bindingInfo.ParameterLayouts
        |> stripForallOnlyParameterLayouts scheme
        |> stripLeadingConstraintAliasParameterLayouts scheme

    let private parameterLayoutNeedsApplicationMetadata (parameter: Parameter) =
        parameter.IsImplicit
        || parameter.IsInout
        || (parameter.TypeTokens
            |> Option.bind TypeSignatures.parseType
            |> Option.exists (function
                | TypeUniverse _ -> true
                | TypeIntrinsic _ -> true
                | TypeName([ "Type" ], []) -> true
                | _ -> false))

    let private annotateLambdaWithTypeTokens typeTokens value =
        let signatureParameterLayouts =
            typeTokens
            |> splitSignatureParameterTokens
            |> function
                | [] -> None
                | parameterTokens -> Some(parameterTokens |> List.map tryParseSignatureParameterLayout)

        match TypeSignatures.parseScheme typeTokens, value with
        | Some signatureScheme, Lambda(lambdaParameters, lambdaBody) ->
            let parameterTypes, _ = TypeSignatures.schemeParts signatureScheme

            if List.length parameterTypes = List.length lambdaParameters then
                let annotatedParameters =
                    List.zip lambdaParameters parameterTypes
                    |> List.mapi (fun index (parameter, parameterType) ->
                        let signatureLayout =
                            signatureParameterLayouts
                            |> Option.bind (List.tryItem index)
                            |> Option.bind id

                        { parameter with
                            TypeTokens =
                                parameter.TypeTokens
                                |> Option.orElseWith (fun () ->
                                    Some(typeTextTokens (TypeSignatures.toText parameterType)))
                            Quantity = parameter.Quantity |> Option.orElseWith (fun () -> signatureLayout |> Option.bind (fun layout -> layout.Quantity))
                            IsImplicit = parameter.IsImplicit || (signatureLayout |> Option.exists (fun layout -> layout.IsImplicit))
                            IsInout = parameter.IsInout || (signatureLayout |> Option.exists (fun layout -> layout.IsInout)) })

                Lambda(annotatedParameters, lambdaBody)
            else
                value
        | _ ->
            value

    let private tryResolveVisibleConstructorInfo
        (environment: BindingLoweringEnvironment)
        nameSegments
        =
        let matchesQualifier qualifierText (constructorInfo: BindingSchemeInfo) =
            String.Equals(ModuleIdentity.text constructorInfo.ModuleIdentity, qualifierText, StringComparison.Ordinal)
            || constructorInfo.ConstructorTypeName
               |> Option.exists (fun constructorTypeName ->
                   String.Equals(constructorTypeName, qualifierText, StringComparison.Ordinal)
                   || String.Equals(
                       $"{ModuleIdentity.text constructorInfo.ModuleIdentity}.{constructorTypeName}",
                       qualifierText,
                       StringComparison.Ordinal
                   ))

        match List.rev nameSegments with
        | [] ->
            None
        | constructorName :: reversedModuleSegments ->
            let qualifierText =
                match reversedModuleSegments with
                | [] -> None
                | _ -> Some(SyntaxFacts.moduleNameToText (List.rev reversedModuleSegments))

            let visibleMatch =
                environment.VisibleConstructors
                |> Map.tryFind constructorName
                |> Option.filter (fun constructorInfo ->
                    qualifierText
                    |> Option.map (fun qualifier -> matchesQualifier qualifier constructorInfo)
                    |> Option.defaultValue true)

            visibleMatch
            |> Option.orElseWith (fun () ->
                environment.SurfaceIndex
                |> Map.toList
                |> List.choose (fun (_, moduleInfo) -> moduleInfo.Constructors |> Map.tryFind constructorName)
                |> List.filter (fun constructorInfo ->
                    qualifierText
                    |> Option.map (fun qualifier -> matchesQualifier qualifier constructorInfo)
                    |> Option.defaultValue true)
                |> function
                    | [ constructorInfo ] -> Some constructorInfo
                    | _ -> None)

    let private typeObjectType =
        TypeUniverse None

    let private constraintObjectType =
        TypeIntrinsic ConstraintClassifier

    let private effectLabelObjectType =
        TypeIntrinsic EffLabelClassifier

    let private staticObjectTypeText (info: StaticObjectInfo) =
        info.Scheme
        |> Option.map (fun scheme -> TypeSignatures.toText scheme.Body)

    let private traitFacetScheme (traitInfo: TraitInfo) =
        let body =
            traitInfo.TypeParameters
            |> List.rev
            |> List.fold (fun current _ -> TypeArrow(QuantityOmega, typeObjectType, current)) constraintObjectType

        { Forall = []
          Constraints = []
          Body = body }

    let private typeFacetStaticObject (typeFacetInfo: TypeFacetInfo) =
        staticObjectInfo
            (semanticObjectIdentity typeFacetInfo.Identity TypeObject)
            [ typeFacetInfo.Name ]
            (Some typeFacetInfo.Scheme)
            None
            (Some typeFacetInfo)

    let private scopedEffectLabelNameSegments (declaration: EffectSemanticDeclaration) =
        EffectSemantics.labelNameSegments declaration

    let private scopedEffectInterfaceNameSegments (declaration: EffectSemanticDeclaration) =
        EffectSemantics.interfaceNameSegments declaration

    let private scopedEffectTypeStaticObject (declaration: EffectSemanticDeclaration) =
        staticObjectInfo
            (declaration.InterfaceObjectIdentity
             |> Option.defaultWith (fun () -> invalidOp $"Scoped effect '{declaration.VisibleName}' is missing a semantic identity."))
            (scopedEffectInterfaceNameSegments declaration)
            (Some
                { Forall = []
                  Constraints = []
                  Body = typeObjectType })
            (Some declaration)
            None

    let private scopedEffectLabelStaticObject (declaration: EffectSemanticDeclaration) =
        staticObjectInfo
            (declaration.LabelObjectIdentity
             |> Option.defaultWith (fun () -> invalidOp $"Scoped effect '{declaration.VisibleName}' is missing a semantic identity."))
            (scopedEffectLabelNameSegments declaration)
            (Some
                { Forall = []
                  Constraints = []
                  Body = effectLabelObjectType })
            (Some declaration)
            None

    let private traitStaticObject (traitInfo: TraitInfo) =
        staticObjectInfo
            (semanticObjectIdentity traitInfo.Identity TraitObject)
            [ traitInfo.Name ]
            (Some(traitFacetScheme traitInfo))
            None
            None

    let private tryResolveVisibleTypeFacetInfo
        (environment: BindingLoweringEnvironment)
        nameSegments
        =
        match List.rev nameSegments with
        | [] ->
            None
        | typeName :: reversedModuleSegments ->
            match reversedModuleSegments with
            | [] ->
                tryResolveVisibleTypeFacetByRoot environment typeName
            | _ ->
                environment.VisibleQualifiedTypeFacets
                |> Map.tryFind nameSegments

    let private tryResolveVisibleTraitInfo
        (environment: BindingLoweringEnvironment)
        nameSegments
        =
        match List.rev nameSegments with
        | [] ->
            None
        | traitName :: reversedModuleSegments ->
            match reversedModuleSegments with
            | [] ->
                tryResolveVisibleTraitByRoot environment traitName
            | _ ->
                environment.VisibleQualifiedTraits
                |> Map.tryFind nameSegments

    let private tryResolveStaticObject
        (environment: BindingLoweringEnvironment)
        expression
        =
        match expression with
        | KindQualifiedName(TypeKind, nameSegments) ->
            tryResolveVisibleTypeFacetInfo environment nameSegments
            |> Option.map typeFacetStaticObject
        | KindQualifiedName(TraitKind, nameSegments) ->
            tryResolveVisibleTraitInfo environment nameSegments
            |> Option.map traitStaticObject
        | KindQualifiedName(EffectLabelKind, _) ->
            None
        | KindQualifiedName(ModuleKind, nameSegments) ->
            if tryResolveVisibleModuleIdentity environment nameSegments |> Option.isSome then
                Some(staticObjectInfo (semanticObjectIdentity (moduleDeclarationIdentity (moduleIdentityOfSegments nameSegments)) ModuleObject) nameSegments None None None)
            else
                None
        | Name nameSegments when not (List.isEmpty nameSegments) ->
            tryFindVisibleStaticGroup environment nameSegments
            |> Option.bind (fun group -> group.StaticObject)
            |> Option.orElseWith (fun () ->
                match nameSegments with
                | [ root ]
                    when not (environment.VisibleBindings.ContainsKey root)
                         && Option.isNone (tryResolveVisibleConstructorInfo environment [ root ]) ->
                    tryResolveVisibleTypeFacetByRoot environment root
                    |> Option.map typeFacetStaticObject
                    |> Option.orElseWith (fun () ->
                        tryResolveVisibleTraitByRoot environment root
                        |> Option.map traitStaticObject)
                | _ ->
                    None)
        | _ ->
            None

    let private tryResolveStaticReceiverObject
        (environment: BindingLoweringEnvironment)
        expression
        =
        match expression with
        | Name nameSegments when not (List.isEmpty nameSegments) ->
            tryFindVisibleStaticGroup environment nameSegments
            |> Option.bind (fun group -> group.StaticObject)
            |> Option.orElseWith (fun () ->
                match nameSegments with
                | [ root ] ->
                    tryResolveVisibleTypeFacetByRoot environment root
                    |> Option.map typeFacetStaticObject
                | _ ->
                    None)
        | _ ->
            tryResolveStaticObject environment expression


    let private scopedEffects = AsyncLocal<Map<string, EffectSemanticDeclaration> option>()
    let private scopedEffectDeclarations = AsyncLocal<EffectSemanticDeclaration list option>()
    let private scopedEffectIdentityCounter = AsyncLocal<int option>()

    let private currentScopedEffects () =
        scopedEffects.Value |> Option.defaultValue Map.empty

    let private currentScopedEffectDeclarations () =
        scopedEffectDeclarations.Value |> Option.defaultValue []

    let private currentScopedEffectNames () =
        currentScopedEffects () |> Map.keys |> Set.ofSeq

    let private tryFindScopedEffectDeclaration name =
        currentScopedEffects () |> Map.tryFind name

    let private tryFindScopedEffectDeclarationByStaticSegments segments =
        let visibleNameSegments (declaration: EffectSemanticDeclaration) =
            declaration.VisibleName.Split('.') |> Array.toList

        currentScopedEffectDeclarations ()
        |> List.tryFind (fun declaration ->
            segments = visibleNameSegments declaration
            || segments = scopedEffectLabelNameSegments declaration
            || segments = scopedEffectInterfaceNameSegments declaration)

    let private nextScopedEffectIdentitySeed () =
        let current = scopedEffectIdentityCounter.Value |> Option.defaultValue 0
        scopedEffectIdentityCounter.Value <- Some(current + 1)
        $"surface-elaboration|{current}"

    let private nextScopedEffectDeclarationIdentity moduleIdentity declarationName =
        let current = scopedEffectIdentityCounter.Value |> Option.defaultValue 0
        scopedEffectIdentityCounter.Value <- Some(current + 1)
        DeclarationIdentity.create moduleIdentity [ $"local-effect-{current}" ] declarationName EffectDeclaration

    let private ensureScopedEffectDeclarationIdentity (declaration: EffectDeclaration) =
        if declaration.EffectInterfaceId.IsSome && declaration.EffectLabelId.IsSome && (declaration.Operations |> List.forall (fun operation -> operation.OperationId.IsSome)) then
            declaration
        else
            EffectSemantics.ensureLocal (nextScopedEffectIdentitySeed ()) declaration

    let private scopedEffectOperationMetadata (declaration: EffectSemanticDeclaration) =
        declaration.Operations
        |> List.map (fun operation ->
            { KCoreEffectOperation.OperationId = operation.OperationId
              Name = operation.Name
              ResumptionQuantity = operation.ResumptionQuantity |> Option.orElse (Some QuantityOne)
              ParameterArity = operation.ParameterArity })

    let private scopedRuntimeEffectOperationMetadata (declaration: EffectSemanticDeclaration) =
        declaration.Operations
        |> List.map (fun operation ->
            { KRuntimeEffectOperation.OperationId = operation.OperationId
              Name = operation.Name
              ResumptionQuantity = operation.ResumptionQuantity |> Option.orElse (Some QuantityOne)
              ParameterArity = operation.ParameterArity })

    let private scopedKCoreEffectLabel (declaration: EffectSemanticDeclaration) =
        KCoreEffectLabel(
            declaration.VisibleName,
            declaration.InterfaceId,
            declaration.LabelId,
            scopedEffectOperationMetadata declaration
        )

    let private scopedKRuntimeEffectLabel (declaration: EffectSemanticDeclaration) =
        KRuntimeEffectLabel(
            declaration.VisibleName,
            declaration.InterfaceId,
            declaration.LabelId,
            scopedRuntimeEffectOperationMetadata declaration
        )

    let private tryFindScopedEffectOperation effectName operationName =
        tryFindScopedEffectDeclaration effectName
        |> Option.bind (fun declaration -> EffectSemantics.tryFindOperation operationName declaration |> Option.map (fun operation -> declaration, operation))

    let private significantEffectHandlerTokens tokens =
        tokens
        |> List.filter (fun token ->
            match token.Kind with
            | Newline
            | Indent
            | Dedent
            | EndOfFile -> false
            | _ -> true)

    let private tryParseEffectHandlerArgumentName tokens =
        match significantEffectHandlerTokens tokens with
        | [ token ] when Token.isName token ->
            let name = SyntaxFacts.trimIdentifierQuotes token.Text

            if String.Equals(name, "_", StringComparison.Ordinal) then
                None
            else
                Some name
        | leftParen :: nameToken :: colonToken :: _
            when leftParen.Kind = LeftParen && Token.isName nameToken && colonToken.Kind = Colon ->
            let name = SyntaxFacts.trimIdentifierQuotes nameToken.Text

            if String.Equals(name, "_", StringComparison.Ordinal) then
                None
            else
                Some name
        | _ ->
            None

    let private scopedEffectTypeParameters (declaration: EffectSemanticDeclaration) =
        TypeSignatures.collectLeadingTypeParameters declaration.HeaderTokens

    let private scopedEffectLabelType (declaration: EffectSemanticDeclaration) =
        TypeName(scopedEffectLabelNameSegments declaration, [])

    let private scopedEffectInterfaceType (declaration: EffectSemanticDeclaration) =
        TypeName(
            scopedEffectInterfaceNameSegments declaration,
            scopedEffectTypeParameters declaration
            |> List.map TypeVariable
        )

    let private scopedEffectRowType (declaration: EffectSemanticDeclaration) =
        TypeEffectRow(
            [
                { Label = scopedEffectLabelType declaration
                  Effect = scopedEffectInterfaceType declaration }
            ],
            None
        )

    let private withScopedEffectDeclaration moduleIdentity (declaration: EffectDeclaration) work =
        let declarationIdentity =
            nextScopedEffectDeclarationIdentity moduleIdentity declaration.Name

        let declaration =
            ensureScopedEffectDeclarationIdentity declaration
            |> EffectSemantics.toSemantic (Some declarationIdentity)
        let saved = currentScopedEffects ()
        let savedDeclarations = currentScopedEffectDeclarations ()
        let savedCounter = scopedEffectIdentityCounter.Value
        scopedEffects.Value <- Some(Map.add declaration.VisibleName declaration saved)
        scopedEffectDeclarations.Value <- Some(declaration :: savedDeclarations)

        try
            work ()
        finally
            scopedEffects.Value <- Some saved
            scopedEffectDeclarations.Value <- Some savedDeclarations
            scopedEffectIdentityCounter.Value <- savedCounter

    let private withScopedEffectDeclarations moduleIdentity (declarations: EffectDeclaration list) work =
        let saved = currentScopedEffects ()
        let savedDeclarations = currentScopedEffectDeclarations ()
        let savedCounter = scopedEffectIdentityCounter.Value

        let semanticDeclarations =
            declarations
            |> List.map ensureScopedEffectDeclarationIdentity
            |> List.mapi (fun index declaration ->
                let declarationIdentity =
                    DeclarationIdentity.create moduleIdentity [ $"local-effect-batch-{index}" ] declaration.Name EffectDeclaration

                EffectSemantics.toSemantic (Some declarationIdentity) declaration)

        let merged =
            semanticDeclarations
            |> List.fold (fun state declaration -> Map.add declaration.VisibleName declaration state) saved

        scopedEffects.Value <- Some merged
        scopedEffectDeclarations.Value <- Some(semanticDeclarations @ savedDeclarations)

        try
            work ()
        finally
            scopedEffects.Value <- Some saved
            scopedEffectDeclarations.Value <- Some savedDeclarations
            scopedEffectIdentityCounter.Value <- savedCounter

    let private tryResolveScopedStaticObject
        (environment: BindingLoweringEnvironment)
        expression
        =
        let scopedEffectNames = currentScopedEffectNames ()

        match expression with
        | Name [ name ] when Set.contains name scopedEffectNames ->
            tryFindScopedEffectDeclaration name |> Option.map scopedEffectLabelStaticObject
        | Name nameSegments when not (List.isEmpty nameSegments) ->
            tryFindScopedEffectDeclarationByStaticSegments nameSegments
            |> Option.map scopedEffectLabelStaticObject
            |> Option.orElseWith (fun () -> tryResolveStaticObject environment expression)
        | KindQualifiedName(TypeKind, [ name ]) when Set.contains name scopedEffectNames ->
            tryFindScopedEffectDeclaration name |> Option.map scopedEffectTypeStaticObject
        | KindQualifiedName(TypeKind, nameSegments) when not (List.isEmpty nameSegments) ->
            tryFindScopedEffectDeclarationByStaticSegments nameSegments
            |> Option.map scopedEffectTypeStaticObject
            |> Option.orElseWith (fun () -> tryResolveStaticObject environment expression)
        | KindQualifiedName(EffectLabelKind, [ name ]) when Set.contains name scopedEffectNames ->
            tryFindScopedEffectDeclaration name |> Option.map scopedEffectLabelStaticObject
        | KindQualifiedName(EffectLabelKind, nameSegments) when not (List.isEmpty nameSegments) ->
            tryFindScopedEffectDeclarationByStaticSegments nameSegments
            |> Option.map scopedEffectLabelStaticObject
            |> Option.orElseWith (fun () -> tryResolveStaticObject environment expression)
        | _ ->
            tryResolveStaticObject environment expression

    let rec private tryResolveHandledEffectName
        (environment: BindingLoweringEnvironment)
        expression
        =
        tryResolveHandledEffectDeclaration environment expression
        |> Option.map (fun declaration -> declaration.VisibleName)

    and private tryResolveHandledEffectDeclaration
        (environment: BindingLoweringEnvironment)
        expression
        =
        tryResolveScopedStaticObject environment expression
        |> Option.bind (fun staticObject ->
            match staticObject.ObjectKind, staticObject.ScopedEffect, staticObject.NameSegments with
            | EffectLabelObject, Some declaration, _ -> Some declaration
            | EffectLabelObject, None, [ effectName ] -> tryFindScopedEffectDeclaration effectName
            | _ -> None)

    let private tryResolveEffectOperationNamePath
        (environment: BindingLoweringEnvironment)
        (nameSegments: string list)
        =
        match List.rev nameSegments with
        | operationName :: reversedPrefix when not (List.isEmpty reversedPrefix) ->
            let prefix = List.rev reversedPrefix

            tryResolveScopedStaticObject environment (Name prefix)
            |> Option.bind (fun staticObject ->
                match staticObject.ObjectKind, staticObject.ScopedEffect, staticObject.NameSegments with
                | EffectLabelObject, Some declaration, _ ->
                    EffectSemantics.tryFindOperation operationName declaration
                    |> Option.map (fun operation -> declaration.VisibleName, declaration, operation)
                | EffectLabelObject, None, [ effectName ] ->
                    tryFindScopedEffectOperation effectName operationName
                    |> Option.map (fun (declaration, operation) -> effectName, declaration, operation)
                | _ ->
                    None)
        | _ ->
            None

    let private effectResolutionCallbacks environment : EffectSemantics.EffectResolutionCallbacks =
        { TryResolveHandledEffectDeclaration = tryResolveHandledEffectDeclaration environment
          TryResolveEffectOperationNamePath =
            fun nameSegments ->
                tryResolveEffectOperationNamePath environment nameSegments
                |> Option.map (fun (_, declaration, operation) -> declaration, operation) }

    let private kindSelectorText selector =
        match selector with
        | TypeKind -> "type"
        | TraitKind -> "trait"
        | EffectLabelKind -> "effect-label"
        | ModuleKind -> "module"

    let private staticObjectExpression (staticObject: StaticObjectInfo) =
        let selector =
            match staticObject.ObjectKind with
            | TypeObject -> TypeKind
            | TraitObject -> TraitKind
            | EffectLabelObject -> EffectLabelKind
            | ModuleObject -> ModuleKind
            | ProjectionObject ->
                invalidOp "Projection objects do not reify as ordinary static-object paths."

        KindQualifiedName(selector, staticObject.NameSegments)

    let private rewriteStaticObjectAliasUse aliasName staticObject expression =
        let aliasIsBoundByPattern pattern =
            collectPatternNames pattern
            |> List.exists (fun name -> String.Equals(name, aliasName, StringComparison.Ordinal))

        let aliasIsBoundByParameters (parameters: Parameter list) =
            parameters
            |> List.exists (fun parameter -> String.Equals(parameter.Name, aliasName, StringComparison.Ordinal))

        let aliasIsBoundByName name =
            String.Equals(name, aliasName, StringComparison.Ordinal)

        let rec rewrite current =
            match current with
            | Name [ root ] when aliasIsBoundByName root ->
                staticObjectExpression staticObject
            | Name(root :: path) when aliasIsBoundByName root ->
                Name(staticObject.NameSegments @ path)
            | Name _ ->
                current
            | TypeSyntaxTokens _ ->
                current
            | SyntaxQuote inner ->
                SyntaxQuote(rewrite inner)
            | SyntaxSplice inner ->
                SyntaxSplice(rewrite inner)
            | TopLevelSyntaxSplice inner ->
                TopLevelSyntaxSplice(rewrite inner)
            | CodeQuote inner ->
                CodeQuote(rewrite inner)
            | CodeSplice inner ->
                CodeSplice(rewrite inner)
            | LocalLet(binding, value, body) ->
                let rewrittenValue = rewrite value

                if aliasIsBoundByPattern binding.Pattern then
                    LocalLet(binding, rewrittenValue, body)
                else
                    LocalLet(binding, rewrittenValue, rewrite body)
            | LocalSignature(declaration, body) ->
                if aliasIsBoundByName declaration.Name then
                    LocalSignature(declaration, body)
                else
                    LocalSignature(declaration, rewrite body)
            | LocalTypeAlias(declaration, body) ->
                LocalTypeAlias(declaration, rewrite body)
            | LocalScopedEffect(declaration, body) ->
                if aliasIsBoundByName declaration.Name then
                    LocalScopedEffect(declaration, body)
                else
                    LocalScopedEffect(declaration, rewrite body)
            | Handle(isDeep, label, body, returnClause, operationClauses) ->
                let rewriteClause (clause: SurfaceEffectHandlerClause) =
                    { clause with
                        Body = rewrite clause.Body }

                Handle(
                    isDeep,
                    rewrite label,
                    rewrite body,
                    rewriteClause returnClause,
                    operationClauses |> List.map rewriteClause
                )
            | Lambda(parameters, body) ->
                if aliasIsBoundByParameters parameters then
                    Lambda(parameters, body)
                else
                    Lambda(parameters, rewrite body)
            | IfThenElse(condition, whenTrue, whenFalse) ->
                IfThenElse(rewrite condition, rewrite whenTrue, rewrite whenFalse)
            | Match(scrutinee, cases) ->
                Match(
                    rewrite scrutinee,
                    cases
                    |> List.map (fun caseClause ->
                        if aliasIsBoundByPattern caseClause.Pattern then
                            caseClause
                        else
                            { caseClause with
                                Guard = caseClause.Guard |> Option.map rewrite
                                Body = rewrite caseClause.Body })
                )
            | RecordLiteral fields ->
                RecordLiteral(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | Seal(value, ascriptionTokens) ->
                Seal(rewrite value, ascriptionTokens)
            | RecordUpdate(receiver, fields) ->
                RecordUpdate(rewrite receiver, fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | MemberAccess(receiver, segments, arguments) ->
                MemberAccess(rewrite receiver, segments, arguments |> List.map rewrite)
            | SafeNavigation(receiver, navigation) ->
                SafeNavigation(rewrite receiver, { navigation with Arguments = navigation.Arguments |> List.map rewrite })
            | TagTest(receiver, constructorName) ->
                TagTest(rewrite receiver, constructorName)
            | Do statements ->
                let rec rewriteStatements remaining =
                    match remaining with
                    | [] -> []
                    | statement :: rest ->
                        match statement with
                        | DoLet(binding, value) ->
                            let rewritten = DoLet(binding, rewrite value)
                            if aliasIsBoundByPattern binding.Pattern then
                                rewritten :: rest
                            else
                                rewritten :: rewriteStatements rest
                        | DoLetQuestion(binding, value, failure) ->
                            let rewrittenFailure =
                                failure
                                |> Option.map (fun failureClause ->
                                    if aliasIsBoundByPattern failureClause.ResiduePattern.Pattern then
                                        failureClause
                                    else
                                        { failureClause with Body = rewriteStatements failureClause.Body })

                            let rewritten = DoLetQuestion(binding, rewrite value, rewrittenFailure)
                            if aliasIsBoundByPattern binding.Pattern then
                                rewritten :: rest
                            else
                                rewritten :: rewriteStatements rest
                        | DoBind(binding, value) ->
                            let rewritten = DoBind(binding, rewrite value)
                            if aliasIsBoundByPattern binding.Pattern then
                                rewritten :: rest
                            else
                                rewritten :: rewriteStatements rest
                        | DoUsing(binding, value) ->
                            let rewritten = DoUsing(binding, rewrite value)
                            if aliasIsBoundByPattern binding.Pattern then
                                rewritten :: rest
                            else
                                rewritten :: rewriteStatements rest
                        | DoVar(name, value) ->
                            let rewritten = DoVar(name, rewrite value)
                            if aliasIsBoundByName name then
                                rewritten :: rest
                            else
                                rewritten :: rewriteStatements rest
                        | DoAssign(name, value) ->
                            DoAssign(name, rewrite value) :: rewriteStatements rest
                        | DoDefer value ->
                            DoDefer(rewrite value) :: rewriteStatements rest
                        | DoIf(condition, whenTrue, whenFalse) ->
                            DoIf(condition |> rewrite, whenTrue |> rewriteStatements, whenFalse |> rewriteStatements)
                            :: rewriteStatements rest
                        | DoWhile(condition, body) ->
                            DoWhile(rewrite condition, rewriteStatements body) :: rewriteStatements rest
                        | DoReturn value ->
                            DoReturn(rewrite value) :: rest
                        | DoExpression value ->
                            DoExpression(rewrite value) :: rewriteStatements rest

                Do(rewriteStatements statements)
            | MonadicSplice inner ->
                MonadicSplice(rewrite inner)
            | ExplicitImplicitArgument inner ->
                ExplicitImplicitArgument(rewrite inner)
            | NamedApplicationBlock fields ->
                NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | Apply(callee, arguments) ->
                Apply(rewrite callee, arguments |> List.map rewrite)
            | InoutArgument inner ->
                InoutArgument(rewrite inner)
            | Unary(operatorName, operand) ->
                Unary(operatorName, rewrite operand)
            | Binary(left, operatorName, right) ->
                Binary(rewrite left, operatorName, rewrite right)
            | Elvis(left, right) ->
                Elvis(rewrite left, rewrite right)
            | Comprehension comprehension ->
                Comprehension { comprehension with Lowered = rewrite comprehension.Lowered }
            | PrefixedString(prefix, parts) ->
                PrefixedString(
                    prefix,
                    parts
                    |> List.map (function
                        | StringText _ as part -> part
                        | StringInterpolation(inner, format) -> StringInterpolation(rewrite inner, format))
                )
            | Literal _
            | NumericLiteral _
            | KindQualifiedName _ ->
                current

        rewrite expression

    let private rewriteNamedApplicationAliasUse
        aliasName
        (parameters: Parameter list)
        expression
        =
        let supportedParameters =
            parameters
            |> List.forall (fun parameter -> not parameter.IsImplicit && not parameter.IsInout && not parameter.IsReceiver)

        let tryReorder arguments =
            match supportedParameters, arguments with
            | true, [ NamedApplicationBlock fields ] ->
                let fieldMap =
                    fields
                    |> List.map (fun field -> field.Name, field.Value)
                    |> Map.ofList

                if parameters |> List.forall (fun parameter -> fieldMap.ContainsKey(parameter.Name)) then
                    parameters
                    |> List.map (fun parameter -> fieldMap[parameter.Name])
                    |> Some
                else
                    None
            | _ ->
                None

        let rec rewrite current =
            match current with
            | TypeSyntaxTokens _ ->
                current
            | SyntaxQuote inner ->
                SyntaxQuote(rewrite inner)
            | SyntaxSplice inner ->
                SyntaxSplice(rewrite inner)
            | TopLevelSyntaxSplice inner ->
                TopLevelSyntaxSplice(rewrite inner)
            | CodeQuote inner ->
                CodeQuote(rewrite inner)
            | CodeSplice inner ->
                CodeSplice(rewrite inner)
            | Handle(isDeep, label, body, returnClause, operationClauses) ->
                let rewriteClause (clause: SurfaceEffectHandlerClause) =
                    { clause with
                        Body = rewrite clause.Body }

                Handle(
                    isDeep,
                    rewrite label,
                    rewrite body,
                    rewriteClause returnClause,
                    operationClauses |> List.map rewriteClause
                )
            | Apply(Name [ name ], arguments) when String.Equals(name, aliasName, StringComparison.Ordinal) ->
                match tryReorder arguments with
                | Some reorderedArguments ->
                    Apply(Name [ name ], reorderedArguments |> List.map rewrite)
                | None ->
                    Apply(Name [ name ], arguments |> List.map rewrite)
            | Apply(callee, arguments) ->
                Apply(rewrite callee, arguments |> List.map rewrite)
            | LocalLet(binding, value, body) ->
                let shadowsAlias =
                    collectPatternNames binding.Pattern
                    |> List.exists (fun name -> String.Equals(name, aliasName, StringComparison.Ordinal))

                LocalLet(binding, rewrite value, if shadowsAlias then body else rewrite body)
            | LocalSignature(declaration, body) ->
                if String.Equals(declaration.Name, aliasName, StringComparison.Ordinal) then
                    current
                else
                    LocalSignature(declaration, rewrite body)
            | LocalTypeAlias(declaration, body) ->
                LocalTypeAlias(declaration, rewrite body)
            | LocalScopedEffect(declaration, body) ->
                if String.Equals(declaration.Name, aliasName, StringComparison.Ordinal) then
                    current
                else
                    LocalScopedEffect(declaration, rewrite body)
            | Lambda(parameters, body) ->
                if parameters |> List.exists (fun parameter -> String.Equals(parameter.Name, aliasName, StringComparison.Ordinal)) then
                    current
                else
                    Lambda(parameters, rewrite body)
            | IfThenElse(condition, whenTrue, whenFalse) ->
                IfThenElse(rewrite condition, rewrite whenTrue, rewrite whenFalse)
            | Match(scrutinee, cases) ->
                Match(
                    rewrite scrutinee,
                    cases
                    |> List.map (fun caseClause ->
                        { caseClause with
                            Guard = caseClause.Guard |> Option.map rewrite
                            Body = rewrite caseClause.Body })
                )
            | RecordLiteral fields ->
                RecordLiteral(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | Seal(value, ascriptionTokens) ->
                Seal(rewrite value, ascriptionTokens)
            | RecordUpdate(receiver, fields) ->
                RecordUpdate(rewrite receiver, fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | MemberAccess(receiver, segments, arguments) ->
                MemberAccess(rewrite receiver, segments, arguments |> List.map rewrite)
            | SafeNavigation(receiver, navigation) ->
                SafeNavigation(rewrite receiver, { navigation with Arguments = navigation.Arguments |> List.map rewrite })
            | TagTest(receiver, constructorName) ->
                TagTest(rewrite receiver, constructorName)
            | Do statements ->
                Do statements
            | MonadicSplice inner ->
                MonadicSplice(rewrite inner)
            | ExplicitImplicitArgument inner ->
                ExplicitImplicitArgument(rewrite inner)
            | NamedApplicationBlock fields ->
                NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | InoutArgument inner ->
                InoutArgument(rewrite inner)
            | Unary(operatorName, inner) ->
                Unary(operatorName, rewrite inner)
            | Binary(left, operatorName, right) ->
                Binary(rewrite left, operatorName, rewrite right)
            | Elvis(left, right) ->
                Elvis(rewrite left, rewrite right)
            | Comprehension comprehension ->
                Comprehension { comprehension with Lowered = rewrite comprehension.Lowered }
            | PrefixedString(prefix, parts) ->
                PrefixedString(
                    prefix,
                    parts
                    |> List.map (function
                        | StringText text -> StringText text
                        | StringInterpolation(inner, format) -> StringInterpolation(rewrite inner, format))
                )
            | Literal _
            | NumericLiteral _
            | KindQualifiedName _
            | TypeSyntaxTokens _
            | Name _ ->
                current

        rewrite expression

    let private rewriteDirectAliasUse aliasName targetName expression =
        let rec rewrite current =
            match current with
            | TypeSyntaxTokens _ ->
                current
            | SyntaxQuote inner ->
                SyntaxQuote(rewrite inner)
            | SyntaxSplice inner ->
                SyntaxSplice(rewrite inner)
            | TopLevelSyntaxSplice inner ->
                TopLevelSyntaxSplice(rewrite inner)
            | CodeQuote inner ->
                CodeQuote(rewrite inner)
            | CodeSplice inner ->
                CodeSplice(rewrite inner)
            | Handle(isDeep, label, body, returnClause, operationClauses) ->
                let rewriteClause (clause: SurfaceEffectHandlerClause) =
                    { clause with
                        Body = rewrite clause.Body }

                Handle(
                    isDeep,
                    rewrite label,
                    rewrite body,
                    rewriteClause returnClause,
                    operationClauses |> List.map rewriteClause
                )
            | Apply(Name [ name ], arguments) when String.Equals(name, aliasName, StringComparison.Ordinal) ->
                Apply(Name [ targetName ], arguments |> List.map rewrite)
            | Apply(callee, arguments) ->
                Apply(rewrite callee, arguments |> List.map rewrite)
            | LocalLet(binding, value, body) ->
                let shadowsAlias =
                    collectPatternNames binding.Pattern
                    |> List.exists (fun name -> String.Equals(name, aliasName, StringComparison.Ordinal))

                LocalLet(binding, rewrite value, if shadowsAlias then body else rewrite body)
            | LocalSignature(declaration, body) ->
                if String.Equals(declaration.Name, aliasName, StringComparison.Ordinal) then
                    current
                else
                    LocalSignature(declaration, rewrite body)
            | LocalTypeAlias(declaration, body) ->
                LocalTypeAlias(declaration, rewrite body)
            | LocalScopedEffect(declaration, body) ->
                if String.Equals(declaration.Name, aliasName, StringComparison.Ordinal) then
                    current
                else
                    LocalScopedEffect(declaration, rewrite body)
            | Lambda(parameters, body) ->
                if parameters |> List.exists (fun parameter -> String.Equals(parameter.Name, aliasName, StringComparison.Ordinal)) then
                    current
                else
                    Lambda(parameters, rewrite body)
            | IfThenElse(condition, whenTrue, whenFalse) ->
                IfThenElse(rewrite condition, rewrite whenTrue, rewrite whenFalse)
            | Match(scrutinee, cases) ->
                Match(
                    rewrite scrutinee,
                    cases
                    |> List.map (fun caseClause ->
                        { caseClause with
                            Guard = caseClause.Guard |> Option.map rewrite
                            Body = rewrite caseClause.Body })
                )
            | RecordLiteral fields ->
                RecordLiteral(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | Seal(value, ascriptionTokens) ->
                Seal(rewrite value, ascriptionTokens)
            | RecordUpdate(receiver, fields) ->
                RecordUpdate(rewrite receiver, fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | MemberAccess(receiver, segments, arguments) ->
                MemberAccess(rewrite receiver, segments, arguments |> List.map rewrite)
            | SafeNavigation(receiver, navigation) ->
                SafeNavigation(rewrite receiver, { navigation with Arguments = navigation.Arguments |> List.map rewrite })
            | TagTest(receiver, constructorName) ->
                TagTest(rewrite receiver, constructorName)
            | Do statements ->
                Do statements
            | MonadicSplice inner ->
                MonadicSplice(rewrite inner)
            | ExplicitImplicitArgument inner ->
                ExplicitImplicitArgument(rewrite inner)
            | NamedApplicationBlock fields ->
                NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | InoutArgument inner ->
                InoutArgument(rewrite inner)
            | Unary(operatorName, inner) ->
                Unary(operatorName, rewrite inner)
            | Binary(left, operatorName, right) ->
                Binary(rewrite left, operatorName, rewrite right)
            | Elvis(left, right) ->
                Elvis(rewrite left, rewrite right)
            | Comprehension comprehension ->
                Comprehension { comprehension with Lowered = rewrite comprehension.Lowered }
            | PrefixedString(prefix, parts) ->
                PrefixedString(
                    prefix,
                    parts
                    |> List.map (function
                        | StringText text -> StringText text
                        | StringInterpolation(inner, format) -> StringInterpolation(rewrite inner, format))
                )
            | Literal _
            | NumericLiteral _
            | KindQualifiedName _
            | Name _ ->
                current

        rewrite expression

    let private rewriteStaticObjectPathAliasUses (aliases: Map<string list, StaticObjectInfo>) expression =
        let sortedAliases =
            aliases
            |> Map.toList
            |> List.sortByDescending (fun (segments, _) -> List.length segments)

        let shadowsAnyAlias names (activeAliases: Map<string list, StaticObjectInfo>) =
            if Set.isEmpty names then
                false
            else
                activeAliases
                |> Map.exists (fun segments _ ->
                    match segments with
                    | root :: _ -> Set.contains root names
                    | [] -> false)

        let withoutShadowedAliases names (activeAliases: Map<string list, StaticObjectInfo>) =
            if Set.isEmpty names then
                activeAliases
            else
                activeAliases
                |> Map.filter (fun segments _ ->
                    match segments with
                    | root :: _ -> not (Set.contains root names)
                    | [] -> true)

        let tryRewriteName activeAliases segments =
            let candidates =
                activeAliases
                |> Map.toList
                |> List.sortByDescending (fun (aliasSegments, _) -> List.length aliasSegments)

            candidates
            |> List.tryPick (fun (aliasSegments, staticObject) ->
                if List.length aliasSegments <= List.length segments
                   && (segments |> List.take (List.length aliasSegments)) = aliasSegments then
                    let rest = segments |> List.skip (List.length aliasSegments)

                    if List.isEmpty rest then
                        Some(staticObjectExpression staticObject)
                    else
                        Some(Name(staticObject.NameSegments @ rest))
                else
                    None)

        let rec rewrite activeAliases current =
            match current with
            | Name segments ->
                tryRewriteName activeAliases segments
                |> Option.defaultValue current
            | TypeSyntaxTokens _ ->
                current
            | SyntaxQuote inner ->
                SyntaxQuote(rewrite activeAliases inner)
            | SyntaxSplice inner ->
                SyntaxSplice(rewrite activeAliases inner)
            | TopLevelSyntaxSplice inner ->
                TopLevelSyntaxSplice(rewrite activeAliases inner)
            | CodeQuote inner ->
                CodeQuote(rewrite activeAliases inner)
            | CodeSplice inner ->
                CodeSplice(rewrite activeAliases inner)
            | Handle(isDeep, label, body, returnClause, operationClauses) ->
                let rewriteClause (clause: SurfaceEffectHandlerClause) =
                    { clause with
                        Body = rewrite activeAliases clause.Body }

                Handle(
                    isDeep,
                    rewrite activeAliases label,
                    rewrite activeAliases body,
                    rewriteClause returnClause,
                    operationClauses |> List.map rewriteClause
                )
            | LocalLet(binding, value, body) ->
                let rewrittenValue = rewrite activeAliases value
                let shadowedNames = collectPatternNames binding.Pattern |> Set.ofList
                let bodyAliases = withoutShadowedAliases shadowedNames activeAliases

                LocalLet(binding, rewrittenValue, rewrite bodyAliases body)
            | LocalSignature(declaration, body) ->
                LocalSignature(declaration, rewrite (withoutShadowedAliases (Set.singleton declaration.Name) activeAliases) body)
            | LocalTypeAlias(declaration, body) ->
                LocalTypeAlias(declaration, rewrite activeAliases body)
            | LocalScopedEffect(declaration, body) ->
                let bodyAliases = withoutShadowedAliases (Set.singleton declaration.Name) activeAliases
                LocalScopedEffect(declaration, rewrite bodyAliases body)
            | Lambda(parameters, body) ->
                let shadowedNames = parameters |> List.map (fun parameter -> parameter.Name) |> Set.ofList
                Lambda(parameters, rewrite (withoutShadowedAliases shadowedNames activeAliases) body)
            | IfThenElse(condition, whenTrue, whenFalse) ->
                IfThenElse(rewrite activeAliases condition, rewrite activeAliases whenTrue, rewrite activeAliases whenFalse)
            | Match(scrutinee, cases) ->
                Match(
                    rewrite activeAliases scrutinee,
                    cases
                    |> List.map (fun caseClause ->
                        let shadowedNames = collectPatternNames caseClause.Pattern |> Set.ofList
                        let caseAliases = withoutShadowedAliases shadowedNames activeAliases

                        { caseClause with
                            Guard = caseClause.Guard |> Option.map (rewrite caseAliases)
                            Body = rewrite caseAliases caseClause.Body })
                )
            | RecordLiteral fields ->
                RecordLiteral(fields |> List.map (fun field -> { field with Value = rewrite activeAliases field.Value }))
            | Seal(value, ascriptionTokens) ->
                Seal(rewrite activeAliases value, ascriptionTokens)
            | RecordUpdate(receiver, fields) ->
                RecordUpdate(rewrite activeAliases receiver, fields |> List.map (fun field -> { field with Value = rewrite activeAliases field.Value }))
            | MemberAccess(receiver, segments, arguments) ->
                MemberAccess(rewrite activeAliases receiver, segments, arguments |> List.map (rewrite activeAliases))
            | SafeNavigation(receiver, navigation) ->
                SafeNavigation(rewrite activeAliases receiver, { navigation with Arguments = navigation.Arguments |> List.map (rewrite activeAliases) })
            | TagTest(receiver, constructorName) ->
                TagTest(rewrite activeAliases receiver, constructorName)
            | Do statements ->
                let rec rewriteStatements activeAliases remaining =
                    match remaining with
                    | [] -> []
                    | statement :: rest ->
                        match statement with
                        | DoLet(binding, value) ->
                            let rewritten = DoLet(binding, rewrite activeAliases value)
                            let shadowedNames = collectPatternNames binding.Pattern |> Set.ofList

                            rewritten :: rewriteStatements (withoutShadowedAliases shadowedNames activeAliases) rest
                        | DoLetQuestion(binding, value, failure) ->
                            let rewrittenFailure =
                                failure
                                |> Option.map (fun failureClause ->
                                    let shadowedNames = collectPatternNames failureClause.ResiduePattern.Pattern |> Set.ofList

                                    { failureClause with
                                        Body = rewriteStatements (withoutShadowedAliases shadowedNames activeAliases) failureClause.Body })

                            let rewritten = DoLetQuestion(binding, rewrite activeAliases value, rewrittenFailure)
                            let shadowedNames = collectPatternNames binding.Pattern |> Set.ofList

                            rewritten :: rewriteStatements (withoutShadowedAliases shadowedNames activeAliases) rest
                        | DoBind(binding, value)
                        | DoUsing(binding, value) ->
                            let rewrittenValue = rewrite activeAliases value
                            let rewritten =
                                match statement with
                                | DoBind _ -> DoBind(binding, rewrittenValue)
                                | _ -> DoUsing(binding, rewrittenValue)

                            let shadowedNames = collectPatternNames binding.Pattern |> Set.ofList
                            rewritten :: rewriteStatements (withoutShadowedAliases shadowedNames activeAliases) rest
                        | DoVar(name, value) ->
                            DoVar(name, rewrite activeAliases value)
                            :: rewriteStatements (withoutShadowedAliases (Set.singleton name) activeAliases) rest
                        | DoAssign(name, value) ->
                            DoAssign(name, rewrite activeAliases value) :: rewriteStatements activeAliases rest
                        | DoDefer value ->
                            DoDefer(rewrite activeAliases value) :: rewriteStatements activeAliases rest
                        | DoIf(condition, whenTrue, whenFalse) ->
                            DoIf(
                                rewrite activeAliases condition,
                                rewriteStatements activeAliases whenTrue,
                                rewriteStatements activeAliases whenFalse
                            )
                            :: rewriteStatements activeAliases rest
                        | DoWhile(condition, body) ->
                            DoWhile(rewrite activeAliases condition, rewriteStatements activeAliases body)
                            :: rewriteStatements activeAliases rest
                        | DoReturn value ->
                            DoReturn(rewrite activeAliases value) :: rest
                        | DoExpression value ->
                            DoExpression(rewrite activeAliases value) :: rewriteStatements activeAliases rest

                Do(rewriteStatements activeAliases statements)
            | MonadicSplice inner ->
                MonadicSplice(rewrite activeAliases inner)
            | ExplicitImplicitArgument inner ->
                ExplicitImplicitArgument(rewrite activeAliases inner)
            | NamedApplicationBlock fields ->
                NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = rewrite activeAliases field.Value }))
            | Apply(callee, arguments) ->
                Apply(rewrite activeAliases callee, arguments |> List.map (rewrite activeAliases))
            | InoutArgument inner ->
                InoutArgument(rewrite activeAliases inner)
            | Unary(operatorName, operand) ->
                Unary(operatorName, rewrite activeAliases operand)
            | Binary(left, operatorName, right) ->
                Binary(rewrite activeAliases left, operatorName, rewrite activeAliases right)
            | Elvis(left, right) ->
                Elvis(rewrite activeAliases left, rewrite activeAliases right)
            | Comprehension comprehension ->
                Comprehension { comprehension with Lowered = rewrite activeAliases comprehension.Lowered }
            | PrefixedString(prefix, parts) ->
                PrefixedString(
                    prefix,
                    parts
                    |> List.map (function
                        | StringText _ as part -> part
                        | StringInterpolation(inner, format) -> StringInterpolation(rewrite activeAliases inner, format))
                )
            | Literal _
            | NumericLiteral _
            | KindQualifiedName _ ->
                current

        if List.isEmpty sortedAliases then
            expression
        else
            rewrite aliases expression

    let rec private rewriteEffectOperationPathAliasUses
        (environment: BindingLoweringEnvironment)
        (aliases: Map<string list, EffectSemantics.ResolvedEffectOperation>)
        expression
        =
        EffectSemantics.rewriteOperationAliasUses (effectResolutionCallbacks environment) aliases expression

    and private collectScopedPatternEffectOperationAliases
        (environment: BindingLoweringEnvironment)
        pattern
        value
        =
        EffectSemantics.collectPatternOperationAliases (effectResolutionCallbacks environment) pattern value

    let private collectScopedPatternStaticAliases
        (environment: BindingLoweringEnvironment)
        pattern
        value
        =
        let rec collectExpression prefix expression aliases =
            match tryResolveScopedStaticObject environment expression with
            | Some staticObject ->
                Map.add prefix staticObject aliases
            | None ->
                match expression with
                | RecordLiteral fields ->
                    fields
                    |> List.fold (fun current field -> collectExpression (prefix @ [ field.Name ]) field.Value current) aliases
                | Seal(inner, _) ->
                    collectExpression prefix inner aliases
                | _ ->
                    aliases

        let rec collectPattern pattern value aliases =
            match pattern with
            | NamePattern name ->
                collectExpression [ name ] value aliases
            | AsPattern(name, inner) ->
                collectPattern inner value (collectExpression [ name ] value aliases)
            | TypedPattern(inner, _) ->
                collectPattern inner value aliases
            | AnonymousRecordPattern(fields, rest) ->
                fields
                |> List.fold (fun current field ->
                    let fieldExpression =
                        match value with
                        | Name segments -> Name(segments @ [ field.Name ])
                        | _ -> MemberAccess(value, [ field.Name ], [])

                    collectPattern field.Pattern fieldExpression current) aliases
                |> fun current ->
                    match rest with
                    | Some(BindRecordPatternRest name) ->
                        collectExpression [ name ] value current
                    | _ ->
                        current
            | ConstructorPattern(_, arguments) ->
                arguments |> List.fold (fun current argument -> collectPattern argument value current) aliases
            | NamedConstructorPattern(_, fields) ->
                fields |> List.fold (fun current field -> collectPattern field.Pattern value current) aliases
            | TuplePattern elements ->
                elements |> List.fold (fun current element -> collectPattern element value current) aliases
            | VariantPattern(BoundVariantPattern(name, _))
            | VariantPattern(RestVariantPattern name) ->
                collectExpression [ name ] value aliases
            | VariantPattern(WildcardVariantPattern _) ->
                aliases
            | OrPattern alternatives ->
                alternatives
                |> List.tryHead
                |> Option.map (fun first -> collectPattern first value aliases)
                |> Option.defaultValue aliases
            | WildcardPattern
            | LiteralPattern _ ->
                aliases

        collectPattern pattern value Map.empty

    let private unitType =
        knownTypeExpr CompilerKnownSymbols.UnitType []

    let private voidType =
        knownTypeExpr CompilerKnownSymbols.VoidType []

    let private boolType =
        knownTypeExpr CompilerKnownSymbols.BoolType []

    let private intType =
        knownTypeExpr CompilerKnownSymbols.IntType []

    let private integerType =
        knownTypeExpr CompilerKnownSymbols.IntegerType []

    let private floatType =
        knownTypeExpr CompilerKnownSymbols.FloatType []

    let private doubleType =
        knownTypeExpr CompilerKnownSymbols.DoubleType []

    let private stringType =
        knownTypeExpr CompilerKnownSymbols.StringType []

    let private unicodeScalarType =
        knownTypeExpr CompilerKnownSymbols.UnicodeScalarType []

    let private graphemeType =
        knownTypeExpr CompilerKnownSymbols.GraphemeType []

    let private byteType =
        knownTypeExpr CompilerKnownSymbols.ByteType []

    let private syntaxType argumentType =
        knownTypeExpr CompilerKnownSymbols.SyntaxType [ argumentType ]

    let private elabType argumentType =
        knownTypeExpr CompilerKnownSymbols.ElabType [ argumentType ]

    let private codeType argumentType =
        knownTypeExpr CompilerKnownSymbols.CodeType [ argumentType ]

    let private ioType argumentType =
        knownTypeExpr CompilerKnownSymbols.IOType [ argumentType ]

    let private effType effectRow payloadType =
        knownTypeExpr CompilerKnownSymbols.EffType [ effectRow; payloadType ]

    let private refType argumentType =
        knownTypeExpr CompilerKnownSymbols.RefType [ argumentType ]

    let private dictionaryType traitName argumentTypes =
        TypeName([ TraitRuntime.dictionaryTypeName traitName ], argumentTypes)

    let private unwrapIoType typeExpr =
        match typeExpr with
        | TypeName(nameSegments, [ inner ]) when matchesKnownType CompilerKnownSymbols.IOType nameSegments -> inner
        | TypeName(nameSegments, [ _; inner ]) when matchesKnownType CompilerKnownSymbols.IOType nameSegments -> inner
        | TypeName(nameSegments, [ inner ]) when matchesKnownType CompilerKnownSymbols.UIOType nameSegments -> inner
        | other -> other

    let private tryUnwrapEffType typeExpr =
        match typeExpr with
        | TypeName(nameSegments, [ effectRow; inner ]) when matchesKnownType CompilerKnownSymbols.EffType nameSegments -> Some(effectRow, inner)
        | _ -> None

    let rec private tryUnwrapComputationPayloadType typeExpr =
        match typeExpr with
        | TypeCapture(inner, _) -> tryUnwrapComputationPayloadType inner
        | TypeName(nameSegments, [ _; inner ]) when matchesKnownType CompilerKnownSymbols.EffType nameSegments -> Some inner
        | TypeName(nameSegments, [ inner ]) when matchesKnownType CompilerKnownSymbols.IOType nameSegments -> Some inner
        | TypeName(nameSegments, [ _; inner ]) when matchesKnownType CompilerKnownSymbols.IOType nameSegments -> Some inner
        | TypeName(nameSegments, [ inner ]) when matchesKnownType CompilerKnownSymbols.UIOType nameSegments -> Some inner
        | _ -> None

    let rec private unwrapBindPayloadType typeExpr =
        match typeExpr with
        | TypeCapture(inner, _) -> unwrapBindPayloadType inner
        | TypeName(nameSegments, [ _; inner ]) when matchesKnownType CompilerKnownSymbols.EffType nameSegments -> inner
        | TypeName(_, [ inner ]) -> inner
        | other -> unwrapIoType other

    let private typeTextOf typeExpr =
        typeExpr
        |> unwrapIoType
        |> TypeSignatures.toText

    let private tryParseParameterType (parameter: Parameter) =
        parameter.TypeTokens |> Option.bind TypeSignatures.parseType

    let private tryParseParameterTypeWithSubstitution substitution (parameter: Parameter) =
        tryParseParameterType parameter
        |> Option.map (TypeSignatures.applySubstitution substitution)

    let private tryParseReturnTypeType tokens =
        tokens |> Option.bind TypeSignatures.parseType

    let private tryParseReturnTypeTokens tokens =
        tryParseReturnTypeType tokens |> Option.map typeTextOf

    let private freshUnknownLocalType (freshCounter: int ref) =
        let name = $"__kappa_local_t{freshCounter.Value}"
        freshCounter.Value <- freshCounter.Value + 1
        TypeVariable name

    let private inferFallbackLocalType (freshCounter: int ref) expression =
        match expression with
        | Lambda(parameters, _) ->
            let resultType = freshUnknownLocalType freshCounter

            parameters
            |> List.rev
            |> List.fold
                (fun current parameter ->
                    let parameterType =
                        tryParseParameterType parameter
                        |> Option.defaultValue (freshUnknownLocalType freshCounter)

                    TypeArrow(parameter.Quantity |> Option.defaultValue QuantityOmega, parameterType, current))
                resultType
        | _ ->
            freshUnknownLocalType freshCounter

    let private tryParseLetDefinitionScheme (definition: LetDefinition) =
        match definition.ReturnTypeTokens |> Option.bind TypeSignatures.parseType with
        | Some returnType ->
            let parameterTypes =
                definition.Parameters
                |> List.map tryParseParameterType

            if parameterTypes |> List.forall Option.isSome then
                let body =
                    List.zip definition.Parameters (parameterTypes |> List.choose id)
                    |> List.rev
                    |> List.fold (fun current (parameter, parameterType) ->
                        TypeArrow(parameter.Quantity |> Option.defaultValue QuantityOmega, parameterType, current)) returnType

                Some
                    { Forall = []
                      Constraints = []
                      Body = body }
            else
                None
        | None ->
            None

    let private topLevelDefinitionNames (declarations: TopLevelDeclaration list) =
        declarations
        |> List.choose (function
            | LetDeclaration definition ->
                match definition.Name, definition.Body with
                | Some name, Some _ -> Some name
                | _ -> None
            | _ ->
                None)
        |> Set.ofList

    let private currentModuleTopLevelDefinitionShadowsVisibleImportedBinding
        (environment: BindingLoweringEnvironment)
        (localTypes: Map<string, TypeExpr>)
        name
        =
        environment.CurrentModuleTopLevelDefinitions.Contains(name)
        && not (Map.containsKey name localTypes)
        && not (
            environment.VisibleBindings
            |> Map.tryFind name
            |> Option.exists (fun bindingInfo -> bindingInfo.ModuleIdentity = environment.CurrentModuleIdentity)
        )

    let private importedVisibleDefinitionShadowsPrelude
        (environment: BindingLoweringEnvironment)
        name
        =
        match environment.SurfaceIndex |> Map.tryFind environment.CurrentModuleIdentity with
        | Some moduleInfo ->
            let importedBindingModules =
                moduleInfo.Imports
                |> List.choose (fun spec ->
                    match moduleIdentityOfModuleSpecifier spec.Source with
                    | Some importedModuleIdentity -> Some importedModuleIdentity
                    | None -> None)
                |> Set.ofList

            environment.SurfaceIndex
            |> Map.toSeq
            |> Seq.exists (fun (moduleIdentity, moduleSurface) ->
                importedBindingModules.Contains moduleIdentity
                && moduleSurface.TopLevelDefinitionsByName.ContainsKey name
                && not (moduleSurface.BindingSchemes.ContainsKey name))
        | None ->
            false

    let private ordinarySurfaceNameShadowsVisiblePreludeBinding
        (environment: BindingLoweringEnvironment)
        (localTypes: Map<string, TypeExpr>)
        name
        =
        currentModuleTopLevelDefinitionShadowsVisibleImportedBinding environment localTypes name
        || (importedVisibleDefinitionShadowsPrelude environment name && not (Map.containsKey name localTypes))

    let private topLevelDefinitionWithoutCurrentModuleSchemeShadowsVisibleBinding
        (environment: BindingLoweringEnvironment)
        (topLevelDefinitionsByName: Map<string, LetDefinition>)
        (localTypes: Map<string, TypeExpr>)
        name
        =
        topLevelDefinitionsByName.ContainsKey name
        && not (Map.containsKey name localTypes)
        && not (
            environment.VisibleBindings
            |> Map.tryFind name
            |> Option.exists (fun bindingInfo -> bindingInfo.ModuleIdentity = environment.CurrentModuleIdentity)
        )

    let private tryParseTraitMemberSignatureNameAndScheme (memberDeclaration: TraitMember) =
        let rawTokens = significantTokens memberDeclaration.Tokens
        let tokens =
            match tryParseQuantityPrefix rawTokens with
            | Some(_, rest) -> rest
            | None -> rawTokens

        let tryParseNamedSignature name schemeTokens =
            TypeSignatures.parseScheme schemeTokens
            |> Option.map (fun scheme ->
                name,
                { Name = name
                  Scheme = scheme
                  DefaultDefinition = memberDeclaration.DefaultDefinition })

        match tokens with
        | head :: colon :: schemeTokens when Token.isName head && colon.Kind = Colon ->
            tryParseNamedSignature (SyntaxFacts.trimIdentifierQuotes head.Text) schemeTokens
        | { Kind = LeftParen } :: { Kind = Operator; Text = operatorName } :: { Kind = RightParen } :: colon :: schemeTokens
            when colon.Kind = Colon ->
            tryParseNamedSignature operatorName schemeTokens
        | _ ->
            None

    let private tryParseTraitMemberInfo (memberDeclaration: TraitMember) =
        tryParseTraitMemberSignatureNameAndScheme memberDeclaration

    let rec private rewriteAssociatedTraitMembersInType
        (traitName: string)
        (traitTypeParameters: string list)
        (associatedStaticMembers: Set<string>)
        typeExpr
        =
        let traitHead =
            TypeName([ traitName ], traitTypeParameters |> List.map TypeVariable)

        let rewrite = rewriteAssociatedTraitMembersInType traitName traitTypeParameters associatedStaticMembers

        match typeExpr with
        | TypeName([ memberName ], []) when associatedStaticMembers.Contains memberName ->
            TypeProject(traitHead, memberName)
        | TypeApply(callee, arguments) ->
            TypeApply(rewrite callee, arguments |> List.map rewrite)
        | TypeLambda(parameterName, parameterSort, body) ->
            TypeLambda(parameterName, rewrite parameterSort, rewrite body)
        | TypeDelay inner ->
            TypeDelay(rewrite inner)
        | TypeMemo inner ->
            TypeMemo(rewrite inner)
        | TypeForce inner ->
            TypeForce(rewrite inner)
        | TypeProject(target, fieldName) ->
            TypeProject(rewrite target, fieldName)
        | TypeArrow(quantity, parameterType, resultType) ->
            TypeArrow(quantity, rewrite parameterType, rewrite resultType)
        | TypeEquality(left, right) ->
            TypeEquality(rewrite left, rewrite right)
        | TypeCapture(inner, captures) ->
            TypeCapture(rewrite inner, captures)
        | TypeEffectRow(entries, tail) ->
            TypeEffectRow(
                entries
                |> List.map (fun entry ->
                    { Label = rewrite entry.Label
                      Effect = rewrite entry.Effect }),
                tail |> Option.map rewrite
            )
        | TypeRecord fields ->
            TypeRecord(fields |> List.map (fun field -> { field with Type = rewrite field.Type }))
        | TypeUnion members ->
            TypeUnion(members |> List.map rewrite)
        | _ ->
            typeExpr

    let private rewriteAssociatedTraitMembersInScheme
        (traitName: string)
        (traitTypeParameters: string list)
        (associatedStaticMembers: Set<string>)
        (scheme: TypeScheme)
        =
        let rewriteType = rewriteAssociatedTraitMembersInType traitName traitTypeParameters associatedStaticMembers

        { scheme with
            Forall = scheme.Forall |> List.map (fun binder -> { binder with Sort = rewriteType binder.Sort })
            Constraints =
                scheme.Constraints
                |> List.map (fun constraintInfo ->
                    { constraintInfo with
                        Arguments = constraintInfo.Arguments |> List.map rewriteType })
            Body = rewriteType scheme.Body }

    let private splitTopLevelConstraintGroups (tokens: Token list) =
        let significant = significantTokens tokens

        let stripSingleOuterParens current =
            match current with
            | { Kind = LeftParen } :: rest ->
                let tokenArray = current |> List.toArray
                let mutable depth = 0
                let mutable closesAtEnd = false
                let mutable index = 0

                while index < tokenArray.Length do
                    match tokenArray[index].Kind with
                    | LeftParen ->
                        depth <- depth + 1
                    | RightParen ->
                        depth <- depth - 1

                        if depth = 0 then
                            closesAtEnd <- index = tokenArray.Length - 1
                    | _ ->
                        ()

                    index <- index + 1

                if closesAtEnd then
                    rest |> List.take (rest.Length - 1)
                else
                    current
            | _ ->
                current

        let flattened = stripSingleOuterParens significant
        let groups = ResizeArray<Token list>()
        let currentGroup = ResizeArray<Token>()
        let mutable parenDepth = 0
        let mutable bracketDepth = 0
        let mutable braceDepth = 0
        let mutable setBraceDepth = 0

        for token in flattened do
            match token.Kind with
            | LeftParen ->
                parenDepth <- parenDepth + 1
                currentGroup.Add(token)
            | RightParen ->
                parenDepth <- max 0 (parenDepth - 1)
                currentGroup.Add(token)
            | LeftBracket
            | LeftEffectRow ->
                bracketDepth <- bracketDepth + 1
                currentGroup.Add(token)
            | RightBracket
            | RightEffectRow ->
                bracketDepth <- max 0 (bracketDepth - 1)
                currentGroup.Add(token)
            | LeftBrace ->
                braceDepth <- braceDepth + 1
                currentGroup.Add(token)
            | RightBrace ->
                braceDepth <- max 0 (braceDepth - 1)
                currentGroup.Add(token)
            | LeftSetBrace ->
                setBraceDepth <- setBraceDepth + 1
                currentGroup.Add(token)
            | RightSetBrace ->
                setBraceDepth <- max 0 (setBraceDepth - 1)
                currentGroup.Add(token)
            | Comma when parenDepth = 0 && bracketDepth = 0 && braceDepth = 0 && setBraceDepth = 0 ->
                if currentGroup.Count > 0 then
                    groups.Add(List.ofSeq currentGroup)
                    currentGroup.Clear()
            | _ ->
                currentGroup.Add(token)

        if currentGroup.Count > 0 then
            groups.Add(List.ofSeq currentGroup)

        groups |> Seq.toList

    let private trySplitTraitHeaderTokens (tokens: Token list) =
        let tokenArray = tokens |> List.toArray
        let mutable parenDepth = 0
        let mutable bracketDepth = 0
        let mutable braceDepth = 0
        let mutable setBraceDepth = 0
        let mutable headStart = 0
        let mutable constraintEnd = 0
        let mutable index = 0

        while index < tokenArray.Length do
            match tokenArray[index].Kind with
            | LeftParen ->
                parenDepth <- parenDepth + 1
            | RightParen ->
                parenDepth <- max 0 (parenDepth - 1)
            | LeftBracket
            | LeftEffectRow ->
                bracketDepth <- bracketDepth + 1
            | RightBracket
            | RightEffectRow ->
                bracketDepth <- max 0 (bracketDepth - 1)
            | LeftBrace ->
                braceDepth <- braceDepth + 1
            | RightBrace ->
                braceDepth <- max 0 (braceDepth - 1)
            | LeftSetBrace ->
                setBraceDepth <- setBraceDepth + 1
            | RightSetBrace ->
                setBraceDepth <- max 0 (setBraceDepth - 1)
            | Operator
                when parenDepth = 0
                     && bracketDepth = 0
                     && braceDepth = 0
                     && setBraceDepth = 0
                     && String.Equals(tokenArray[index].Text, "=>", StringComparison.Ordinal) ->
                headStart <- index + 1
                constraintEnd <- index
            | Equals
                when parenDepth = 0
                     && bracketDepth = 0
                     && braceDepth = 0
                     && setBraceDepth = 0
                     && index + 1 < tokenArray.Length
                     && tokenArray[index + 1].Kind = Operator
                     && String.Equals(tokenArray[index + 1].Text, ">", StringComparison.Ordinal) ->
                headStart <- index + 2
                constraintEnd <- index
                index <- index + 1
            | _ ->
                ()

            index <- index + 1

        if headStart <= 0 then
            [], tokens
        else
            tokenArray[..constraintEnd - 1] |> Array.toList, tokenArray[headStart..] |> Array.toList

    let private tryParseTraitConstraintTokens tokens =
        TypeSignatures.parseType tokens
        |> Option.bind (function
            | TypeName(nameSegments, arguments) ->
                Some(qualifiedTraitConstraint nameSegments arguments)
            | _ ->
                None)

    let private parseTraitSupertraits (declaration: TraitDeclaration) =
        let supertraitTokens, _ = trySplitTraitHeaderTokens declaration.FullHeaderTokens

        splitTopLevelConstraintGroups supertraitTokens
        |> List.choose tryParseTraitConstraintTokens


    let private tryParseInstanceHeader (declaration: InstanceDeclaration) =
        declaration.FullHeaderTokens
        |> TypeSignatures.parseScheme
        |> Option.bind (fun scheme ->
            match scheme.Body with
            | TypeName(name, headTypes) ->
                Some(TypeSignatures.TraitReference.ofSegments name, scheme.Constraints, headTypes)
            | _ ->
                None)

    let private tryParseTypeAliasInfo moduleIdentity (declaration: TypeAlias) =
        declaration.BodyTokens
        |> Option.bind TypeSignatures.parseType
        |> Option.map (fun body ->
            declaration.Name,
            { Identity = typeAliasIdentity moduleIdentity declaration.Name
              IsOpaque = declaration.IsOpaque
              Parameters = TypeSignatures.collectLeadingTypeParameters declaration.HeaderTokens
              Body = body
              TerminationCertified = true
              ConversionReducible = true })

    let private splitHeaderKindTokens (tokens: Token list) =
        let rec loop depth index =
            if index >= tokens.Length then
                tokens, []
            else
                match tokens[index].Kind with
                | LeftParen
                | LeftBracket
                | LeftBrace
                | LeftSetBrace ->
                    loop (depth + 1) (index + 1)
                | RightParen
                | RightBracket
                | RightBrace
                | RightSetBrace ->
                    loop (max 0 (depth - 1)) (index + 1)
                | Colon when depth = 0 ->
                    List.take index tokens, List.skip (index + 1) tokens
                | _ ->
                    loop depth (index + 1)

        loop 0 0

    let private findMatchingRightParen (tokens: Token list) =
        let rec loop depth index =
            if index >= tokens.Length then
                None
            else
                match tokens[index].Kind with
                | LeftParen ->
                    loop (depth + 1) (index + 1)
                | RightParen when depth = 1 ->
                    Some index
                | RightParen ->
                    loop (max 0 (depth - 1)) (index + 1)
                | _ ->
                    loop depth (index + 1)

        loop 0 0

    let private parseBinderTypeOrDefault (binderTokens: Token list) =
        let _, typeTokens = splitHeaderKindTokens binderTokens

        match significantTokens typeTokens with
        | [] -> typeObjectType
        | tokens -> TypeSignatures.parseType tokens |> Option.defaultValue typeObjectType

    let private typeFacetParameterTypes (tokens: Token list) =
        let rec loop remaining acc =
            match significantTokens remaining with
            | [] ->
                List.rev acc
            | head :: rest when Token.isName head ->
                loop rest (typeObjectType :: acc)
            | { Kind = LeftParen } :: _ as current ->
                match findMatchingRightParen current with
                | Some rightParenIndex ->
                    let binderTokens =
                        current
                        |> List.skip 1
                        |> List.take (rightParenIndex - 1)

                    let next =
                        current |> List.skip (rightParenIndex + 1)

                    loop next (parseBinderTypeOrDefault binderTokens :: acc)
                | None ->
                    List.rev acc
            | _ :: rest ->
                loop rest acc

        loop tokens []

    let private buildTypeFacetInfo moduleIdentity name kind isOpaque headerTokens =
        let parameterTokens, kindTokens = splitHeaderKindTokens headerTokens

        let resultType =
            match significantTokens kindTokens with
            | [] -> typeObjectType
            | tokens -> TypeSignatures.parseType tokens |> Option.defaultValue typeObjectType

        let body =
            parameterTokens
            |> typeFacetParameterTypes
            |> List.rev
            |> List.fold (fun current parameterType -> TypeArrow(QuantityOmega, parameterType, current)) resultType

        name,
        { Identity = typeFacetIdentity moduleIdentity name
          FacetKind = kind
          IsOpaque = isOpaque
          Scheme =
            { Forall = []
              Constraints = []
              Body = body } }

    let private isPrivateByDefault (frontendModule: KFrontIRModule) =
        frontendModule.ModuleAttributes
        |> List.exists (fun attributeName -> String.Equals(attributeName, ModuleAttribute.PrivateByDefault, StringComparison.Ordinal))

    let private moduleHasAttribute (frontendModule: KFrontIRModule) (attributeName: string) =
        frontendModule.ModuleAttributes
        |> List.exists (fun current -> String.Equals(current, attributeName, StringComparison.Ordinal))

    let private itemHasModifier modifier (item: ImportItem) =
        item.Modifiers |> List.exists ((=) modifier)

    let private itemRequestsUnhide item =
        itemHasModifier Unhide item

    let private itemRequestsClarify item =
        itemHasModifier Clarify item

    let private isExportedVisibility isPrivateByDefault visibility =
        match visibility with
        | Some Visibility.Public -> true
        | Some Visibility.Private -> false
        | None -> not isPrivateByDefault

    let private backendSupportsMultishotEffects backendProfile =
        match backendProfile with
        | BackendProfile.Interpreter
        | BackendProfile.DotNet
        | BackendProfile.Zig -> true
        | BackendProfile.Unknown _ -> false

    let private quantityPermitsMultipleResumptions quantity =
        match quantity |> Option.defaultValue QuantityOne with
        | QuantityOmega
        | QuantityAtLeastOne
        | QuantityVariable _ ->
            true
        | QuantityZero
        | QuantityOne
        | QuantityBorrow _
        | QuantityAtMostOne ->
            false

    let private borrowedEffectResumptionQuantityDiagnostics makeDiagnostic (declaration: EffectDeclaration) =
        declaration.Operations
        |> List.choose (fun operation ->
            match operation.ResumptionQuantity with
            | Some(QuantityBorrow _ as quantity) ->
                Some(
                    makeDiagnostic
                        SimpleDiagnosticKind.EffectResumptionQuantityBorrowed
                        $"Effect operation '{declaration.Name}.{operation.Name}' declares borrowed resumption quantity '{Quantity.toSurfaceText quantity}'. Resumption quantities quantify the handler-bound resumption value itself, and borrowed resumptions are not part of the language."
                )
            | _ ->
                None)

    let private itemImportsTermName (item: ImportItem) =
        item.Namespace.IsNone || item.Namespace = Some ImportNamespace.Term

    let private itemImportsTypeName (item: ImportItem) =
        item.Namespace.IsNone || item.Namespace = Some ImportNamespace.Type

    let private itemImportsTraitName (item: ImportItem) =
        item.Namespace.IsNone || item.Namespace = Some ImportNamespace.Trait

    let private itemImportsConstructorName (item: ImportItem) =
        item.Namespace = Some ImportNamespace.Constructor

    let private itemImportsConstructorsOfType typeName (item: ImportItem) =
        item.IncludeConstructors
        && item.Namespace = Some ImportNamespace.Type
        && String.Equals(item.Name, typeName, StringComparison.Ordinal)

    let private importedItemLocalName (item: ImportItem) =
        item.Alias |> Option.defaultValue item.Name

    let private itemExportsTermName (item: ImportItem) =
        item.Namespace.IsNone || item.Namespace = Some ImportNamespace.Term

    let private itemExportsTypeName (item: ImportItem) =
        item.Namespace.IsNone || item.Namespace = Some ImportNamespace.Type

    let private itemExportsTraitName (item: ImportItem) =
        item.Namespace.IsNone || item.Namespace = Some ImportNamespace.Trait

    let private itemExportsConstructorName (item: ImportItem) =
        item.Namespace = Some ImportNamespace.Constructor

    let private tryParseConstructorScheme moduleIdentity (dataDeclaration: DataDeclaration) (constructor: DataConstructor) =
        let significantConstructorTokens = significantTokens constructor.Tokens

        let signatureScheme =
            match significantConstructorTokens with
            | _ :: { Kind = Colon } :: typeTokens ->
                TypeSignatures.parseScheme typeTokens
            | _ ->
                None

        let parameterLayouts, defaultArguments =
            match constructor.Parameters with
            | Some parameters when parameters |> List.forall (fun parameter -> parameter.ParameterName.IsSome) ->
                let layouts =
                    parameters
                    |> List.map (fun parameter ->
                        { Name = parameter.ParameterName.Value
                          TypeTokens = Some parameter.ParameterTypeTokens
                          Quantity = parameter.ParameterQuantity
                          IsImplicit = parameter.ParameterIsImplicit
                          IsInout = false
                          IsReceiver = false })

                let defaults =
                    parameters
                    |> List.choose (fun parameter ->
                        match parameter.ParameterName, parameter.DefaultValue with
                        | Some name, Some defaultValue -> Some(name, defaultValue)
                        | _ -> None)
                    |> Map.ofList

                Some layouts, defaults
            | _ ->
                None, Map.empty

        let scheme =
            match signatureScheme with
            | Some scheme ->
                scheme
            | None ->
                let typeParameters = TypeSignatures.collectLeadingTypeParameters dataDeclaration.HeaderTokens
                let resultType = TypeName([ dataDeclaration.Name ], typeParameters |> List.map TypeVariable)

                let body =
                    constructor
                    |> TypeSignatures.constructorFieldTypes
                    |> List.rev
                    |> List.fold (fun state fieldType -> TypeArrow(QuantityOmega, fieldType, state)) resultType

                { Forall = TypeSignatures.inferredTypeForallBinders typeParameters
                  Constraints = []
                  Body = body }

        Some
            (constructor.Name,
             bindingSchemeInfo
                 (constructorIdentity moduleIdentity constructor.Name)
                 false
                 scheme
                 []
                 parameterLayouts
                 (Some dataDeclaration.Name)
                 defaultArguments)

    let private exceptMatches namespaceName name (item: ExceptItem) =
        String.Equals(item.Name, name, StringComparison.Ordinal)
        && (item.Namespace.IsNone || item.Namespace = Some namespaceName)

    let private selectionImportedName
        namespaceName
        (exportedNames: Set<string>)
        itemSelector
        (selection: ImportSelection)
        (name: string)
        =
        let exported = Set.contains name exportedNames

        match selection with
        | QualifiedOnly ->
            None
        | Items items ->
            if not exported then
                None
            else
                items
                |> List.tryFind (fun item ->
                    String.Equals(item.Name, name, StringComparison.Ordinal)
                    && itemSelector item)
                |> Option.map importedItemLocalName
        | All ->
            if exported then Some name else None
        | AllExcept excludedItems ->
            if exported && not (excludedItems |> List.exists (exceptMatches namespaceName name)) then
                Some name
            else
                None

    let private selectionImportedNameWithExplicitAccess
        namespaceName
        (exportedNames: Set<string>)
        itemSelector
        itemAccessAllowed
        (selection: ImportSelection)
        (name: string)
        =
        let exported = Set.contains name exportedNames

        match selection with
        | QualifiedOnly ->
            None
        | Items items ->
            items
            |> List.tryPick (fun item ->
                if String.Equals(item.Name, name, StringComparison.Ordinal)
                   && itemSelector item
                   && itemAccessAllowed item then
                    Some(importedItemLocalName item)
                else
                    None)
        | All ->
            if exported then Some name else None
        | AllExcept excludedItems ->
            if exported && not (excludedItems |> List.exists (exceptMatches namespaceName name)) then
                Some name
            else
                None

    let private buildModuleSurfaceInfo moduleIdentity (frontendModule: KFrontIRModule) =
        let privateByDefault = isPrivateByDefault frontendModule

        let typeAliases =
            frontendModule.Declarations
            |> List.choose (function
                | TypeAliasNode declaration -> tryParseTypeAliasInfo moduleIdentity declaration
                | _ -> None)
            |> Map.ofList

        let typeFacets =
            frontendModule.Declarations
            |> List.choose (function
                | DataDeclarationNode declaration ->
                    buildTypeFacetInfo moduleIdentity declaration.Name DataFacet declaration.IsOpaque declaration.HeaderTokens
                    |> Some
                | EffectDeclarationNode declaration ->
                    buildTypeFacetInfo moduleIdentity declaration.Name EffectFacet false declaration.HeaderTokens
                    |> Some
                | TypeAliasNode declaration ->
                    buildTypeFacetInfo moduleIdentity declaration.Name TypeAliasFacet declaration.IsOpaque declaration.HeaderTokens
                    |> Some
                | _ ->
                    None)
            |> Map.ofList

        let recordTypes =
            frontendModule.Declarations
            |> List.choose (function
                | TypeAliasNode declaration ->
                    declaration.BodyTokens
                    |> Option.bind tryParseRecordSurfaceInfo
                    |> Option.map (fun recordInfo -> declaration.Name, recordInfo)
                | _ ->
                    None)
            |> Map.ofList

        let bindingSchemes =
            let signatureNames =
                frontendModule.Declarations
                |> List.choose (function
                    | SignatureDeclaration declaration -> Some declaration.Name
                    | _ -> None)
                |> Set.ofList

            let bindingDefinitions =
                frontendModule.Declarations
                |> List.choose (function
                    | LetDeclaration definition when definition.Name.IsSome ->
                        Some(definition.Name.Value, definition)
                    | _ ->
                        None)
                |> Map.ofList

            frontendModule.Declarations
            |> List.choose (function
                | SignatureDeclaration declaration ->
                    let signatureParameterLayouts =
                        declaration.TypeTokens
                        |> splitSignatureParameterTokens
                        |> function
                            | [] -> None
                            | parameterTokens -> Some(parameterTokens |> List.map tryParseSignatureParameterLayout)

                    TypeSignatures.parseScheme declaration.TypeTokens
                    |> Option.map (fun scheme ->
                        let parameterLayouts =
                            bindingDefinitions
                            |> Map.tryFind declaration.Name
                            |> Option.map (fun definition -> definition.Parameters)
                            |> mergeParameterLayouts signatureParameterLayouts
                            |> stripForallOnlyParameterLayouts scheme
                            |> stripLeadingConstraintAliasParameterLayouts scheme

                        declaration.Name,
                        bindingSchemeInfo
                            (bindingIdentity moduleIdentity declaration.Name)
                            (bindingDefinitions
                             |> Map.tryFind declaration.Name
                             |> Option.exists (fun definition -> definition.IsPattern))
                            scheme
                            declaration.TypeTokens
                            parameterLayouts
                            None
                            Map.empty)
                | ExpectDeclarationNode (ExpectTermDeclaration declaration) ->
                    let signatureParameterLayouts =
                        declaration.TypeTokens
                        |> splitSignatureParameterTokens
                        |> function
                            | [] -> None
                            | parameterTokens -> Some(parameterTokens |> List.map tryParseSignatureParameterLayout)

                    TypeSignatures.parseScheme declaration.TypeTokens
                    |> Option.map (fun scheme ->
                        let parameterLayouts =
                            mergeParameterLayouts signatureParameterLayouts None
                            |> stripForallOnlyParameterLayouts scheme
                            |> stripLeadingConstraintAliasParameterLayouts scheme
                            |> Option.bind (fun layouts ->
                                if layouts |> List.exists parameterLayoutNeedsApplicationMetadata then
                                    Some layouts
                                else
                                    None)

                        declaration.Name,
                        bindingSchemeInfo
                            (bindingIdentity moduleIdentity declaration.Name)
                            false
                            scheme
                            declaration.TypeTokens
                            parameterLayouts
                            None
                            Map.empty)
                | LetDeclaration definition
                    when definition.Name.IsSome
                         && not (Set.contains definition.Name.Value signatureNames) ->
                    tryParseLetDefinitionScheme definition
                    |> Option.map (fun scheme ->
                        let parameterLayouts =
                            Some definition.Parameters
                            |> stripForallOnlyParameterLayouts scheme
                            |> stripLeadingConstraintAliasParameterLayouts scheme

                        definition.Name.Value,
                        bindingSchemeInfo
                            (bindingIdentity moduleIdentity definition.Name.Value)
                            definition.IsPattern
                            scheme
                            (definition.ReturnTypeTokens |> Option.defaultValue [])
                            parameterLayouts
                            None
                            Map.empty)
                | _ ->
                    None)
            |> Map.ofList

        let topLevelDefinitionsByName =
            frontendModule.Declarations
            |> List.choose (function
                | LetDeclaration definition when definition.Name.IsSome ->
                    Some(definition.Name.Value, definition)
                | _ ->
                    None)
            |> Map.ofList

        let constructors =
            frontendModule.Declarations
            |> List.choose (function
                | DataDeclarationNode dataDeclaration ->
                    dataDeclaration.Constructors
                    |> List.choose (fun constructor ->
                        tryParseConstructorScheme moduleIdentity dataDeclaration constructor
                        |> Option.map (fun (name, info) -> name, info))
                    |> Some
                | _ ->
                    None)
            |> List.concat
            |> Map.ofList

        let projections =
            frontendModule.Declarations
            |> List.choose (function
                | ProjectionDeclarationNode declaration ->
                    TypeSignatures.parseType declaration.ReturnTypeTokens
                    |> Option.map (fun returnType ->
                        declaration.Name,
                        { Identity = projectionIdentity moduleIdentity declaration.Name
                          Binders = declaration.Binders
                          ReturnType = returnType
                          Body = declaration.Body })
                | _ ->
                    None)
            |> Map.ofList

        let exportedTerms =
            frontendModule.Declarations
            |> List.choose (function
                | SignatureDeclaration declaration when isExportedVisibility privateByDefault declaration.Visibility ->
                    Some declaration.Name
                | LetDeclaration definition when isExportedVisibility privateByDefault definition.Visibility ->
                    definition.Name
                | ProjectionDeclarationNode declaration when isExportedVisibility privateByDefault declaration.Visibility ->
                    Some declaration.Name
                | ExpectDeclarationNode (ExpectTermDeclaration declaration) ->
                    Some declaration.Name
                | _ ->
                    None)
            |> Set.ofList

        let exportedTypes =
            frontendModule.Declarations
            |> List.choose (function
                | DataDeclarationNode declaration when isExportedVisibility privateByDefault declaration.Visibility ->
                    Some declaration.Name
                | EffectDeclarationNode declaration when isExportedVisibility privateByDefault declaration.Visibility ->
                    Some declaration.Name
                | TypeAliasNode declaration when isExportedVisibility privateByDefault declaration.Visibility ->
                    Some declaration.Name
                | ExpectDeclarationNode (ExpectTypeDeclaration declaration) ->
                    Some declaration.Name
                | _ ->
                    None)
            |> Set.ofList

        let exportedConstructors =
            frontendModule.Declarations
            |> List.choose (function
                | DataDeclarationNode declaration
                    when isExportedVisibility privateByDefault declaration.Visibility && not declaration.IsOpaque ->
                    Some(declaration.Constructors |> List.map (fun constructor -> constructor.Name))
                | _ ->
                    None)
            |> List.concat
            |> Set.ofList

        let exportedConstructorsByType =
            frontendModule.Declarations
            |> List.choose (function
                | DataDeclarationNode declaration
                    when isExportedVisibility privateByDefault declaration.Visibility && not declaration.IsOpaque ->
                    Some(
                        declaration.Name,
                        declaration.Constructors |> List.map (fun constructor -> constructor.Name) |> Set.ofList
                    )
                | _ ->
                    None)
            |> Map.ofList

        let exportedTraits =
            frontendModule.Declarations
            |> List.choose (function
                | TraitDeclarationNode declaration when isExportedVisibility privateByDefault declaration.Visibility ->
                    Some declaration.Name
                | ExpectDeclarationNode (ExpectTraitDeclaration declaration) ->
                    Some declaration.Name
                | _ ->
                    None)
            |> Set.ofList

        let traits =
            frontendModule.Declarations
            |> List.choose (function
                | TraitDeclarationNode declaration ->
                    let supertraits = parseTraitSupertraits declaration
                    let traitTypeParameters = TypeSignatures.collectLeadingTypeParameters declaration.HeaderTokens
                    let isTraitAssociatedCompileTimeType typeExpr =
                        match typeExpr with
                        | TypeUniverse _
                        | TypeIntrinsic UniverseClassifier
                        | TypeIntrinsic ConstraintClassifier
                        | TypeIntrinsic QuantityClassifier
                        | TypeIntrinsic RegionClassifier
                        | TypeIntrinsic RecRowClassifier
                        | TypeIntrinsic VarRowClassifier
                        | TypeIntrinsic EffRowClassifier
                        | TypeIntrinsic LabelClassifier
                        | TypeIntrinsic EffLabelClassifier ->
                            true
                        | TypeName([ "Type" ], []) ->
                            true
                        | TypeName(nameSegments, []) when
                            matchesKnownType CompilerKnownSymbols.ConstraintType nameSegments
                            || matchesKnownType CompilerKnownSymbols.QuantityType nameSegments
                            || matchesKnownType CompilerKnownSymbols.RegionType nameSegments
                            || matchesKnownType CompilerKnownSymbols.RecRowType nameSegments
                            || matchesKnownType CompilerKnownSymbols.VarRowType nameSegments
                            || matchesKnownType CompilerKnownSymbols.EffRowType nameSegments
                            || matchesKnownType CompilerKnownSymbols.LabelType nameSegments
                            || matchesKnownType CompilerKnownSymbols.EffLabelType nameSegments ->
                            true
                        | _ ->
                            false

                    let associatedStaticMembers =
                        declaration.Members
                        |> List.choose (fun memberDeclaration ->
                            tryParseTraitMemberSignatureNameAndScheme memberDeclaration
                            |> Option.bind (fun (memberName, memberInfo) ->
                                if isTraitAssociatedCompileTimeType memberInfo.Scheme.Body then
                                    Some memberName
                                else
                                    None))
                        |> Set.ofList

                    let members =
                        declaration.Members
                        |> List.fold (fun state memberDeclaration ->
                            match tryParseTraitMemberInfo memberDeclaration with
                            | Some(memberName, memberInfo) ->
                                let memberInfo =
                                    { memberInfo with
                                        Scheme =
                                            rewriteAssociatedTraitMembersInScheme
                                                declaration.Name
                                                traitTypeParameters
                                                associatedStaticMembers
                                                memberInfo.Scheme }

                                let mergedInfo =
                                    match Map.tryFind memberName state with
                                    | Some existingInfo ->
                                        { memberInfo with
                                            DefaultDefinition =
                                                memberInfo.DefaultDefinition
                                                |> Option.orElse existingInfo.DefaultDefinition }
                                    | None ->
                                        memberInfo

                                Map.add memberName mergedInfo state
                            | None ->
                                match memberDeclaration.Name, memberDeclaration.DefaultDefinition with
                                | Some memberName, Some defaultDefinition ->
                                    match Map.tryFind memberName state, tryParseLetDefinitionScheme defaultDefinition with
                                    | Some existingInfo, _ ->
                                        state
                                        |> Map.add memberName { existingInfo with DefaultDefinition = Some defaultDefinition }
                                    | None, Some scheme ->
                                        state
                                        |> Map.add
                                            memberName
                                            { Name = memberName
                                              Scheme = scheme
                                              DefaultDefinition = Some defaultDefinition }
                                    | None, None ->
                                        state
                                | _ ->
                                    state) Map.empty

                    Some(
                        declaration.Name,
                        { Identity = traitIdentity moduleIdentity declaration.Name
                          TypeParameters = traitTypeParameters
                          Supertraits = supertraits
                          Members = members }
                    )
                | _ ->
                    None)
            |> Map.ofList

        let instances =
            frontendModule.Declarations
            |> List.choose (function
                | InstanceDeclarationNode declaration ->
                    tryParseInstanceHeader declaration
                    |> Option.map (fun (traitReference, constraints, headTypes) ->
                        { ModuleIdentity = moduleIdentity
                          Trait = traitReference
                          InstanceKey = TraitRuntime.instanceKeyFromTokens declaration.HeaderTokens
                          Constraints = constraints
                          HeadTypes = headTypes
                          Members =
                            declaration.Members
                            |> List.choose (fun memberDeclaration ->
                                memberDeclaration.Name
                                |> Option.map (fun memberName -> memberName, memberDeclaration))
                            |> Map.ofList })
                | _ ->
                    None)

        { TypeAliases = typeAliases
          TypeFacets = typeFacets
          RecordTypes = recordTypes
          BindingSchemes = bindingSchemes
          TopLevelDefinitionsByName = topLevelDefinitionsByName
          Constructors = constructors
          Projections = projections
          Traits = traits
          Instances = instances
          Imports = frontendModule.Imports
          ExportedTerms = exportedTerms
          ExportedConstructors = exportedConstructors
          ExportedConstructorsByType = exportedConstructorsByType
          ExportedTypes = exportedTypes
          ExportedTraits = exportedTraits }

    let private buildEffectDeclarationIndex (frontendModules: KFrontIRModule list) =
        frontendModules
        |> List.choose (fun frontendModule ->
            frontendModule.ModuleIdentity
            |> moduleIdentityOfOptionalSegments
            |> Option.map (fun moduleIdentity -> moduleIdentity, frontendModule))
        |> List.groupBy fst
        |> List.map (fun (moduleIdentity, entries) ->
            moduleIdentity,
            (entries
             |> List.map snd
             |> List.collect (fun fragment ->
                 fragment.Declarations
                 |> List.choose (function
                     | EffectDeclarationNode declaration -> Some(EffectSemantics.ensureTopLevel moduleIdentity declaration)
                     | _ -> None))))
        |> Map.ofList

    let private buildHostModuleSurfaceInfo (description: HostBindings.HostModuleDescription) =
        let moduleIdentity = description.ModuleIdentity
        let bindingSchemes =
            description.Terms
            |> List.choose (fun binding ->
                let parameterTypes =
                    binding.Parameters
                    |> List.map (fun parameter -> tryParseTypeText parameter.TypeText)

                let returnType = tryParseTypeText binding.ReturnTypeText

                if parameterTypes |> List.forall Option.isSome && returnType.IsSome then
                    let schemeBody =
                        (parameterTypes |> List.choose id)
                        |> List.rev
                        |> List.fold (fun current parameterType -> TypeArrow(QuantityOmega, parameterType, current)) returnType.Value

                    let parameterLayouts =
                        binding.Parameters
                        |> List.map (fun parameter ->
                            { Name = parameter.Name
                              TypeTokens = Some(typeTextTokens parameter.TypeText)
                              Quantity = None
                              IsImplicit = false
                              IsInout = false
                              IsReceiver = parameter.IsReceiver })

                    Some(
                        binding.Name,
                        bindingSchemeInfo
                            (bindingIdentity moduleIdentity binding.Name)
                            false
                            { Forall = []
                              Constraints = []
                              Body = schemeBody }
                            (typeTextTokens binding.ReturnTypeText)
                            (Some parameterLayouts)
                            None
                            Map.empty
                    )
                else
                    None)
            |> Map.ofList

        let typeFacets =
            description.Types
            |> List.map (fun exportedType ->
                exportedType.Name,
                { Identity = typeFacetIdentity moduleIdentity exportedType.Name
                  FacetKind = AbstractFacet
                  IsOpaque = false
                  Scheme =
                    { Forall = []
                      Constraints = []
                      Body = typeObjectType } })
            |> Map.ofList

        { TypeAliases = Map.empty
          TypeFacets = typeFacets
          RecordTypes = Map.empty
          BindingSchemes = bindingSchemes
          TopLevelDefinitionsByName = Map.empty
          Constructors = Map.empty
          Projections = Map.empty
          Traits = Map.empty
          Instances = []
          Imports = []
          ExportedTerms = description.Terms |> List.map (fun binding -> binding.Name) |> Set.ofList
          ExportedConstructors = Set.empty
          ExportedConstructorsByType = Map.empty
          ExportedTypes = description.Types |> List.map (fun exportedType -> exportedType.Name) |> Set.ofList
          ExportedTraits = Set.empty }

    let private buildStandardModuleSurfaceInfo (surfaceInfo: StandardLibraryCatalog.StandardLibrarySurface) =
        let moduleIdentity = surfaceInfo.ModuleIdentity
        let bindingSchemes =
            surfaceInfo.Terms
            |> List.choose (fun binding ->
                tryParseSchemeText binding.TypeText
                |> Option.map (fun scheme ->
                    binding.Name,
                    bindingSchemeInfo
                        (bindingIdentity moduleIdentity binding.Name)
                        false
                        scheme
                        (typeTextTokens binding.TypeText)
                        None
                        None
                        Map.empty))
            |> Map.ofList

        let typeFacets =
            surfaceInfo.Types
            |> List.map (fun typeName ->
                typeName,
                { Identity = typeFacetIdentity moduleIdentity typeName
                  FacetKind = AbstractFacet
                  IsOpaque = false
                  Scheme =
                    { Forall = []
                      Constraints = []
                      Body = typeObjectType } })
            |> Map.ofList

        let traits =
            surfaceInfo.Traits
            |> List.map (fun traitInfo ->
                let members =
                    traitInfo.Members
                    |> List.choose (fun memberInfo ->
                        TypeSignatures.parseScheme (typeTextTokens memberInfo.TypeText)
                        |> Option.map (fun scheme ->
                            memberInfo.Name,
                            { Name = memberInfo.Name
                              Scheme = scheme
                              DefaultDefinition = None }))
                    |> Map.ofList

                traitInfo.Name,
                { Identity = traitIdentity moduleIdentity traitInfo.Name
                  TypeParameters = [ for index in 1 .. traitInfo.TypeParameterCount -> $"t{index}" ]
                  Supertraits = []
                  Members = members })
            |> Map.ofList

        { TypeAliases = Map.empty
          TypeFacets = typeFacets
          RecordTypes = Map.empty
          BindingSchemes = bindingSchemes
          TopLevelDefinitionsByName = Map.empty
          Constructors = Map.empty
          Projections = Map.empty
          Traits = traits
          Instances = []
          Imports = []
          ExportedTerms = surfaceInfo.Terms |> List.map (fun binding -> binding.Name) |> Set.ofList
          ExportedConstructors = Set.empty
          ExportedConstructorsByType = Map.empty
          ExportedTypes = surfaceInfo.Types |> Set.ofList
          ExportedTraits = surfaceInfo.Traits |> List.map (fun traitInfo -> traitInfo.Name) |> Set.ofList }

    let private mergeSurfaceInfoMaps
        (left: Map<string, 'value>)
        (right: Map<string, 'value>)
        =
        right |> Map.fold (fun state name info -> Map.add name info state) left

    let private mergeSurfaceInfoSetMaps
        (left: Map<string, Set<string>>)
        (right: Map<string, Set<string>>)
        =
        right
        |> Map.fold (fun state name values ->
            let mergedValues =
                state
                |> Map.tryFind name
                |> Option.map (Set.union values)
                |> Option.defaultValue values

            Map.add name mergedValues state) left

    let private mergeModuleSurfaceInfo (left: ModuleSurfaceInfo) (right: ModuleSurfaceInfo) =
        { TypeAliases = mergeSurfaceInfoMaps left.TypeAliases right.TypeAliases
          TypeFacets = mergeSurfaceInfoMaps left.TypeFacets right.TypeFacets
          RecordTypes = mergeSurfaceInfoMaps left.RecordTypes right.RecordTypes
          BindingSchemes = mergeSurfaceInfoMaps left.BindingSchemes right.BindingSchemes
          TopLevelDefinitionsByName = mergeSurfaceInfoMaps left.TopLevelDefinitionsByName right.TopLevelDefinitionsByName
          Constructors = mergeSurfaceInfoMaps left.Constructors right.Constructors
          Projections = mergeSurfaceInfoMaps left.Projections right.Projections
          Traits = mergeSurfaceInfoMaps left.Traits right.Traits
          Instances = left.Instances @ right.Instances
          Imports = left.Imports @ right.Imports
          ExportedTerms = Set.union left.ExportedTerms right.ExportedTerms
          ExportedConstructors = Set.union left.ExportedConstructors right.ExportedConstructors
          ExportedConstructorsByType =
            mergeSurfaceInfoSetMaps left.ExportedConstructorsByType right.ExportedConstructorsByType
          ExportedTypes = Set.union left.ExportedTypes right.ExportedTypes
          ExportedTraits = Set.union left.ExportedTraits right.ExportedTraits }

    let private buildSurfaceIndex
        (frontendModules: KFrontIRModule list)
        (hostModules: Map<ModuleIdentity, HostBindings.HostModuleDescription>)
        =
        let moduleGroups =
            frontendModules
            |> List.choose (fun moduleDump ->
                moduleDump.ModuleIdentity
                |> moduleIdentityOfOptionalSegments
                |> Option.map (fun moduleIdentity -> moduleIdentity, moduleDump))
            |> List.groupBy fst
            |> List.map (fun (moduleIdentity, entries) -> moduleIdentity, (entries |> List.map snd))
            |> Map.ofList

        let directUserSurfaceIndex =
            moduleGroups
            |> Map.map (fun moduleIdentity moduleDumps ->
                moduleDumps
                |> List.map (buildModuleSurfaceInfo moduleIdentity)
                |> List.reduce mergeModuleSurfaceInfo)

        let hostSurfaceIndex =
            hostModules
            |> Map.toList
            |> List.map (fun (moduleIdentity, description) -> moduleIdentity, buildHostModuleSurfaceInfo description)
            |> Map.ofList

        let standardSurfaceIndex =
            StandardLibraryCatalog.syntheticModules
            |> List.map (fun description ->
                let surfaceInfo = description.Surface
                surfaceInfo.ModuleIdentity, buildStandardModuleSurfaceInfo surfaceInfo)
            |> Map.ofList

        let directIndex =
            directUserSurfaceIndex
            |> fun state -> standardSurfaceIndex |> Map.fold (fun current moduleIdentity moduleInfo -> Map.add moduleIdentity moduleInfo current) state
            |> fun state -> hostSurfaceIndex |> Map.fold (fun current moduleIdentity moduleInfo -> Map.add moduleIdentity moduleInfo current) state

        let addReexportedItem (importedModule: ModuleSurfaceInfo) (moduleInfo: ModuleSurfaceInfo) (item: ImportItem) =
            let exportedName = item.Name
            let localName = importedItemLocalName item
            let exportsType = Set.contains exportedName importedModule.ExportedTypes && itemExportsTypeName item
            let exportsTerm = Set.contains exportedName importedModule.ExportedTerms && itemExportsTermName item
            let exportsTrait = Set.contains exportedName importedModule.ExportedTraits && itemExportsTraitName item
            let exportsConstructor = Set.contains exportedName importedModule.ExportedConstructors && itemExportsConstructorName item
            let exportsBundledConstructors = itemImportsConstructorsOfType exportedName item
            let exportsSameSpellingConstructor =
                item.Namespace.IsNone
                && Set.contains exportedName importedModule.ExportedTypes
                && Set.contains exportedName importedModule.ExportedConstructors

            let moduleInfo =
                { moduleInfo with
                    ExportedTerms =
                        if exportsTerm then Set.add localName moduleInfo.ExportedTerms else moduleInfo.ExportedTerms
                    ExportedTypes =
                        if exportsType then Set.add localName moduleInfo.ExportedTypes else moduleInfo.ExportedTypes
                    ExportedTraits =
                        if exportsTrait then Set.add localName moduleInfo.ExportedTraits else moduleInfo.ExportedTraits
                    ExportedConstructors =
                        moduleInfo.ExportedConstructors
                        |> fun constructors ->
                            if exportsConstructor || exportsSameSpellingConstructor then
                                Set.add localName constructors
                            else
                                constructors }

            let moduleInfo =
                if exportsType then
                    { moduleInfo with
                        TypeAliases =
                            importedModule.TypeAliases
                            |> Map.tryFind exportedName
                            |> Option.map (fun info -> Map.add localName info moduleInfo.TypeAliases)
                            |> Option.defaultValue moduleInfo.TypeAliases
                        TypeFacets =
                            importedModule.TypeFacets
                            |> Map.tryFind exportedName
                            |> Option.map (fun info -> Map.add localName info moduleInfo.TypeFacets)
                            |> Option.defaultValue moduleInfo.TypeFacets
                        RecordTypes =
                            importedModule.RecordTypes
                            |> Map.tryFind exportedName
                            |> Option.map (fun info -> Map.add localName info moduleInfo.RecordTypes)
                            |> Option.defaultValue moduleInfo.RecordTypes }
                else
                    moduleInfo

            if exportsBundledConstructors then
                let bundledConstructors =
                    importedModule.ExportedConstructorsByType
                    |> Map.tryFind exportedName
                    |> Option.defaultValue Set.empty

                { moduleInfo with
                    ExportedConstructors = Set.union moduleInfo.ExportedConstructors bundledConstructors
                    ExportedConstructorsByType = Map.add localName bundledConstructors moduleInfo.ExportedConstructorsByType }
            else
                moduleInfo

        let addWildcardReexports (importedModule: ModuleSurfaceInfo) (moduleInfo: ModuleSurfaceInfo) excludedItems =
            let notExcluded namespaceName name = not (excludedItems |> List.exists (exceptMatches namespaceName name))
            let sameSpellingConstructors =
                Set.intersect importedModule.ExportedConstructors importedModule.ExportedTypes
                |> Set.filter (notExcluded ImportNamespace.Constructor)

            let reexportedTypeAliases =
                importedModule.TypeAliases
                |> Map.fold (fun state name info ->
                    if Set.contains name importedModule.ExportedTypes && notExcluded ImportNamespace.Type name then
                        Map.add name info state
                    else
                        state) moduleInfo.TypeAliases

            let reexportedTypeFacets =
                importedModule.TypeFacets
                |> Map.fold (fun state name info ->
                    if Set.contains name importedModule.ExportedTypes && notExcluded ImportNamespace.Type name then
                        Map.add name info state
                    else
                        state) moduleInfo.TypeFacets

            let reexportedRecordTypes =
                importedModule.RecordTypes
                |> Map.fold (fun state name info ->
                    if Set.contains name importedModule.ExportedTypes && notExcluded ImportNamespace.Type name then
                        Map.add name info state
                    else
                        state) moduleInfo.RecordTypes

            let reexportedConstructorsByType =
                importedModule.ExportedConstructorsByType
                |> Map.fold (fun state typeName constructors ->
                    if notExcluded ImportNamespace.Type typeName then
                        Map.add typeName constructors state
                    else
                        state) moduleInfo.ExportedConstructorsByType

            { moduleInfo with
                TypeAliases = reexportedTypeAliases
                TypeFacets = reexportedTypeFacets
                RecordTypes = reexportedRecordTypes
                ExportedTerms = Set.union moduleInfo.ExportedTerms (Set.filter (notExcluded ImportNamespace.Term) importedModule.ExportedTerms)
                ExportedTypes = Set.union moduleInfo.ExportedTypes (Set.filter (notExcluded ImportNamespace.Type) importedModule.ExportedTypes)
                ExportedTraits = Set.union moduleInfo.ExportedTraits (Set.filter (notExcluded ImportNamespace.Trait) importedModule.ExportedTraits)
                ExportedConstructors = Set.union moduleInfo.ExportedConstructors sameSpellingConstructors
                ExportedConstructorsByType = reexportedConstructorsByType }

        let applyReexportSpec (surfaceIndex: Map<ModuleIdentity, ModuleSurfaceInfo>) (moduleInfo: ModuleSurfaceInfo) (spec: ImportSpec) =
            match moduleIdentityOfModuleSpecifier spec.Source with
            | None ->
                moduleInfo
            | Some importedModuleIdentity ->
                match Map.tryFind importedModuleIdentity surfaceIndex with
                | None ->
                    moduleInfo
                | Some importedModule ->
                    match spec.Selection with
                    | QualifiedOnly ->
                        moduleInfo
                    | Items items ->
                        items
                        |> List.filter (fun item -> List.isEmpty item.Modifiers)
                        |> List.fold (addReexportedItem importedModule) moduleInfo
                    | All ->
                        addWildcardReexports importedModule moduleInfo []
                    | AllExcept excludedItems ->
                        addWildcardReexports importedModule moduleInfo excludedItems

        let rec saturate surfaceIndex =
            let updatedUserSurfaceIndex =
                moduleGroups
                |> Map.map (fun moduleIdentity moduleDumps ->
                    let directModuleInfo = Map.find moduleIdentity directUserSurfaceIndex

                    moduleDumps
                    |> List.collect (fun moduleDump ->
                        moduleDump.Declarations
                        |> List.choose (function
                            | ImportDeclaration (true, specs) -> Some specs
                            | _ -> None)
                        |> List.concat)
                    |> List.fold (applyReexportSpec surfaceIndex) directModuleInfo)

            let nextSurfaceIndex =
                updatedUserSurfaceIndex
                |> fun state -> standardSurfaceIndex |> Map.fold (fun current moduleIdentity moduleInfo -> Map.add moduleIdentity moduleInfo current) state
                |> fun state -> hostSurfaceIndex |> Map.fold (fun current moduleIdentity moduleInfo -> Map.add moduleIdentity moduleInfo current) state

            if nextSurfaceIndex = surfaceIndex then
                surfaceIndex
            else
                saturate nextSurfaceIndex

        saturate directIndex

    let private importedModuleInfos (surfaceIndex: Map<ModuleIdentity, ModuleSurfaceInfo>) moduleIdentity =
        surfaceIndex
        |> Map.tryFind moduleIdentity
        |> Option.map (fun moduleInfo ->
            moduleInfo.Imports
            |> List.choose (fun spec ->
                match moduleIdentityOfModuleSpecifier spec.Source with
                | Some importedModuleIdentity ->
                    surfaceIndex
                    |> Map.tryFind importedModuleIdentity
                    |> Option.map (fun importedModule -> spec, importedModuleIdentity, importedModule)
                | None ->
                    None))
        |> Option.defaultValue []

    let private importedEffectDeclarations
        (surfaceIndex: Map<ModuleIdentity, ModuleSurfaceInfo>)
        (effectDeclarationsByModule: Map<ModuleIdentity, EffectDeclaration list>)
        (moduleIdentity: ModuleIdentity)
        =
        let importedEffectsForSpec (spec: ImportSpec, importedModuleIdentity: ModuleIdentity, importedModule: ModuleSurfaceInfo) =
            let importedModuleName = ModuleIdentity.text importedModuleIdentity

            effectDeclarationsByModule
            |> Map.tryFind importedModuleIdentity
            |> Option.defaultValue []
            |> List.choose (fun declaration ->
                let canImportType =
                    Set.contains declaration.Name importedModule.ExportedTypes

                let importedName =
                    match spec.Selection with
                    | QualifiedOnly ->
                        if canImportType then
                            let qualifiedPrefix = spec.Alias |> Option.defaultValue importedModuleName
                            Some(qualifiedPrefix + "." + declaration.Name)
                        else
                            None
                    | _ ->
                        selectionImportedNameWithExplicitAccess
                            ImportNamespace.Type
                            importedModule.ExportedTypes
                            itemImportsTypeName
                            (fun item -> canImportType || itemRequestsUnhide item)
                            spec.Selection
                            declaration.Name

                importedName
                |> Option.map (fun localName ->
                    declaration |> EffectSemantics.importAs localName))

        importedModuleInfos surfaceIndex moduleIdentity
        |> List.collect importedEffectsForSpec

    let private appendVisibleCandidate localName candidate state =
        let updatedCandidates =
            state
            |> Map.tryFind localName
            |> Option.defaultValue []
            |> fun existing -> candidate :: existing

        Map.add localName updatedCandidates state

    let private importedOrdinaryCandidatePriority selection =
        match selection with
        | Items _ -> ExplicitImportedItem
        | All
        | AllExcept _
        | QualifiedOnly -> WildcardImportedItem

    let private collectImportedOrdinaryTermCandidates (surfaceIndex: Map<ModuleIdentity, ModuleSurfaceInfo>) moduleIdentity =
        importedModuleInfos surfaceIndex moduleIdentity
        |> List.fold (fun state (spec, importedModuleIdentity, importedModule) ->
            let candidatePriority = importedOrdinaryCandidatePriority spec.Selection
            let importedModuleName = ModuleIdentity.text importedModuleIdentity

            let visibleBindingCandidateNames =
                Set.union
                    importedModule.ExportedTerms
                    (importedModule.BindingSchemes |> Map.keys |> Set.ofSeq)

            let withBindings =
                visibleBindingCandidateNames
                |> Set.fold (fun current name ->
                    match
                        selectionImportedNameWithExplicitAccess
                            ImportNamespace.Term
                            importedModule.ExportedTerms
                            itemImportsTermName
                            (fun item -> Set.contains name importedModule.ExportedTerms || itemRequestsUnhide item)
                            spec.Selection
                            name
                    with
                    | Some localName ->
                        let candidate =
                            match importedModule.BindingSchemes |> Map.tryFind name with
                            | Some info -> OrdinaryVisibleBindingCandidate(candidatePriority, info)
                            | None -> OrdinaryVisibleExportedBindingCandidate(candidatePriority, importedModuleIdentity, name)

                        appendVisibleCandidate localName candidate current
                    | None ->
                        current) state

            let withConstructors =
                importedModule.Constructors
                |> Map.fold (fun current name info ->
                    let parentTypeInfo =
                        info.ConstructorTypeName
                        |> Option.bind (fun typeName -> importedModule.TypeFacets |> Map.tryFind typeName)

                    let constructorAccessAllowed item =
                        match info.ConstructorTypeName, parentTypeInfo with
                        | Some typeName, Some typeInfo ->
                            let parentExported = Set.contains typeName importedModule.ExportedTypes
                            let canSeeParent = parentExported || itemRequestsUnhide item
                            let canClarifyParent = not typeInfo.IsOpaque || itemRequestsClarify item
                            canSeeParent && canClarifyParent
                        | _ ->
                            false

                    let importedName =
                        match spec.Selection with
                        | QualifiedOnly ->
                            None
                        | All
                        | AllExcept _ ->
                            None
                        | Items items ->
                            items
                            |> List.tryPick (fun item ->
                                if not (constructorAccessAllowed item) then
                                    None
                                elif String.Equals(item.Name, name, StringComparison.Ordinal)
                                     && itemImportsConstructorName item then
                                    Some(importedItemLocalName item, false)
                                elif item.Namespace.IsNone
                                     && info.ConstructorTypeName
                                        |> Option.exists (fun typeName -> String.Equals(typeName, item.Name, StringComparison.Ordinal))
                                     && String.Equals(item.Name, name, StringComparison.Ordinal) then
                                    Some(importedItemLocalName item, true)
                                else
                                    match info.ConstructorTypeName with
                                    | Some typeName when itemImportsConstructorsOfType typeName item ->
                                        Some(name, false)
                                    | _ ->
                                        None)

                    match importedName with
                    | Some(localName, sameSpellingAlias) ->
                        let aliasedInfo =
                            if sameSpellingAlias && not (String.Equals(localName, name, StringComparison.Ordinal)) then
                                aliasImportedSameSpellingConstructorBinding localName info
                            else
                                info

                        appendVisibleCandidate localName (OrdinaryVisibleConstructorCandidate(candidatePriority, aliasedInfo)) current
                    | None ->
                        current) withBindings

            match spec.Source, spec.Alias, spec.Selection with
            | Dotted moduleSegments, Some alias, QualifiedOnly ->
                let importedModuleIdentity = moduleIdentityOfSegments moduleSegments
                appendVisibleCandidate alias (OrdinaryVisibleModuleCandidate(candidatePriority, importedModuleIdentity)) withConstructors
            | Dotted moduleSegments, None, QualifiedOnly ->
                let importedModuleIdentity = moduleIdentityOfSegments moduleSegments
                let importedModuleName = ModuleIdentity.text importedModuleIdentity

                if surfaceIndex.ContainsKey importedModuleIdentity then
                    appendVisibleCandidate importedModuleName (OrdinaryVisibleModuleCandidate(candidatePriority, importedModuleIdentity)) withConstructors
                else
                    withConstructors
            | _ ->
                withConstructors) Map.empty

    let private collectImportedOrdinarySurfaceNames (surfaceIndex: Map<ModuleIdentity, ModuleSurfaceInfo>) moduleIdentity =
        importedModuleInfos surfaceIndex moduleIdentity
        |> List.fold (fun state (spec, _importedModuleIdentity, importedModule) ->
            let visibleBindingCandidateNames =
                Set.union
                    importedModule.ExportedTerms
                    (importedModule.BindingSchemes |> Map.keys |> Set.ofSeq)

            let withTerms =
                visibleBindingCandidateNames
                |> Set.fold (fun current name ->
                    match
                        selectionImportedNameWithExplicitAccess
                            ImportNamespace.Term
                            importedModule.ExportedTerms
                            itemImportsTermName
                            (fun item -> Set.contains name importedModule.ExportedTerms || itemRequestsUnhide item)
                            spec.Selection
                            name
                    with
                    | Some localName ->
                        Set.add localName current
                    | None ->
                        current) state

            match spec.Selection with
            | Items items ->
                items
                |> List.fold (fun current item ->
                    let constructorInfo =
                        importedModule.Constructors
                        |> Map.tryFind item.Name

                    let constructorAccessAllowed info item =
                        let parentTypeInfo =
                            info.ConstructorTypeName
                            |> Option.bind (fun typeName -> importedModule.TypeFacets |> Map.tryFind typeName)

                        match info.ConstructorTypeName, parentTypeInfo with
                        | Some typeName, Some typeInfo ->
                            let parentExported = Set.contains typeName importedModule.ExportedTypes
                            let canSeeParent = parentExported || itemRequestsUnhide item
                            let canClarifyParent = not typeInfo.IsOpaque || itemRequestsClarify item
                            canSeeParent && canClarifyParent
                        | _ ->
                            false

                    let withConstructorName =
                        let importsSameSpellingConstructor =
                            item.Namespace.IsNone
                            && (constructorInfo
                                |> Option.exists (fun info ->
                                    String.Equals(info.Name, item.Name, StringComparison.Ordinal)
                                    && (info.ConstructorTypeName
                                        |> Option.exists (fun typeName -> String.Equals(typeName, item.Name, StringComparison.Ordinal)))))

                        if itemImportsConstructorName item || importsSameSpellingConstructor then
                            match constructorInfo with
                            | Some info when Set.contains item.Name importedModule.ExportedConstructors && constructorAccessAllowed info item ->
                                Set.add (importedItemLocalName item) current
                            | _ ->
                                current
                        else
                            current

                    let bundledConstructors =
                        if itemImportsConstructorsOfType item.Name item then
                            importedModule.Constructors
                            |> Map.fold (fun state constructorName info ->
                                match info.ConstructorTypeName with
                                | Some typeName
                                    when String.Equals(typeName, item.Name, StringComparison.Ordinal)
                                         && constructorAccessAllowed info item ->
                                    Set.add constructorName state
                                | _ ->
                                    state) Set.empty
                        else
                            Set.empty

                    if Set.isEmpty bundledConstructors then
                        withConstructorName
                    else
                        Set.union withConstructorName bundledConstructors) withTerms
            | _ ->
                withTerms) Set.empty

    let private partitionImportedOrdinaryTermCandidates candidateMap =
        candidateMap
        |> Map.fold (fun (bindings, constructors, modules, ambiguities) localName reversedCandidates ->
            let candidates = List.rev reversedCandidates

            match candidates with
            | [ OrdinaryVisibleBindingCandidate(_, info) ] ->
                Map.add localName info bindings, constructors, modules, ambiguities
            | [ OrdinaryVisibleExportedBindingCandidate _ ] ->
                bindings, constructors, modules, ambiguities
            | [ OrdinaryVisibleConstructorCandidate(_, info) ] ->
                bindings, Map.add localName info constructors, modules, ambiguities
            | [ OrdinaryVisibleModuleCandidate(_, moduleIdentity) ] ->
                bindings, constructors, Map.add localName moduleIdentity modules, ambiguities
            | _ ->
                bindings, constructors, modules, Map.add localName candidates ambiguities)
            (Map.empty, Map.empty, Map.empty, Map.empty)

    let private shadowAmbiguousVisibleTermCandidates
        (visibleBindings: Map<string, BindingSchemeInfo>)
        (visibleConstructors: Map<string, BindingSchemeInfo>)
        (visibleModules: Map<string, ModuleIdentity>)
        (ambiguities: Map<string, OrdinaryVisibleTermCandidate list>)
        =
        let shadowingNames =
            [ visibleBindings |> Map.keys |> Set.ofSeq
              visibleConstructors |> Map.keys |> Set.ofSeq
              visibleModules |> Map.keys |> Set.ofSeq ]
            |> Set.unionMany

        ambiguities
        |> Map.filter (fun localName _ -> not (Set.contains localName shadowingNames))

    let private importedUnschemedOrdinaryTermNamesFromCandidates
        (candidatesByName: Map<string, OrdinaryVisibleTermCandidate list>)
        =
        let priorityRank priority =
            match priority with
            | ExplicitImportedItem -> 0
            | WildcardImportedItem -> 1

        let tryOrdinaryCandidatePriority candidate =
            match candidate with
            | OrdinaryVisibleBindingCandidate(priority, _) -> Some priority
            | OrdinaryVisibleExportedBindingCandidate(priority, _, _) -> Some priority
            | _ ->
                None

        candidatesByName
        |> Map.toSeq
        |> Seq.choose (fun (localName, reversedCandidates) ->
            let ordinaryCandidates =
                reversedCandidates
                |> List.rev
                |> List.choose (fun candidate -> tryOrdinaryCandidatePriority candidate |> Option.map (fun priority -> priority, candidate))

            ordinaryCandidates
            |> List.sortBy (fun (priority, _) -> priorityRank priority)
            |> function
                | [] ->
                    None
                | (bestPriority, _) :: _ ->
                    let highestPriorityCandidates =
                        ordinaryCandidates
                        |> List.filter (fun (priority, _) -> priority = bestPriority)
                        |> List.map snd

                    match highestPriorityCandidates with
                    | [ OrdinaryVisibleExportedBindingCandidate _ ] -> Some localName
                    | _ -> None)
        |> Set.ofSeq

    let private mergeVisibleBindings (surfaceIndex: Map<ModuleIdentity, ModuleSurfaceInfo>) moduleIdentity =
        let importedTermCandidates = collectImportedOrdinaryTermCandidates surfaceIndex moduleIdentity
        let importedBindings, _, _, _ = partitionImportedOrdinaryTermCandidates importedTermCandidates

        let preludeBindings =
            surfaceIndex
            |> Map.tryFind preludeModuleIdentity
            |> Option.map (fun moduleInfo -> moduleInfo.BindingSchemes)
            |> Option.defaultValue Map.empty

        let moduleBindings =
            surfaceIndex
            |> Map.tryFind moduleIdentity
            |> Option.map (fun moduleInfo -> moduleInfo.BindingSchemes)
            |> Option.defaultValue Map.empty

        importedBindings
        |> Map.fold (fun state name info -> Map.add name info state) preludeBindings
        |> fun state -> moduleBindings |> Map.fold (fun current name info -> Map.add name info current) state

    let private mergeVisibleBindingDefinitions (surfaceIndex: Map<ModuleIdentity, ModuleSurfaceInfo>) moduleIdentity =
        let importedDefinitions =
            importedModuleInfos surfaceIndex moduleIdentity
            |> List.fold (fun state (spec, _importedModuleIdentity, importedModule) ->
                let visibleDefinitionCandidateNames =
                    Set.union
                        importedModule.ExportedTerms
                        (importedModule.TopLevelDefinitionsByName |> Map.keys |> Set.ofSeq)

                visibleDefinitionCandidateNames
                |> Set.fold (fun current name ->
                    match
                        selectionImportedNameWithExplicitAccess
                            ImportNamespace.Term
                            importedModule.ExportedTerms
                            itemImportsTermName
                            (fun item -> Set.contains name importedModule.ExportedTerms || itemRequestsUnhide item)
                            spec.Selection
                            name
                    with
                    | Some localName ->
                        if importedModule.BindingSchemes.ContainsKey name then
                            current
                        else
                            importedModule.TopLevelDefinitionsByName
                            |> Map.tryFind name
                            |> Option.map (fun definition -> Map.add localName definition current)
                            |> Option.defaultValue current
                    | None ->
                        current) state) Map.empty

        let moduleDefinitions =
            surfaceIndex
            |> Map.tryFind moduleIdentity
            |> Option.map (fun moduleInfo -> moduleInfo.TopLevelDefinitionsByName)
            |> Option.defaultValue Map.empty

        importedDefinitions
        |> fun state -> moduleDefinitions |> Map.fold (fun current name definition -> Map.add name definition current) state

    let private mergeVisibleConstructors (surfaceIndex: Map<ModuleIdentity, ModuleSurfaceInfo>) moduleIdentity =
        let importedTermCandidates = collectImportedOrdinaryTermCandidates surfaceIndex moduleIdentity
        let _, importedConstructors, _, _ = partitionImportedOrdinaryTermCandidates importedTermCandidates

        let preludeConstructors =
            surfaceIndex
            |> Map.tryFind preludeModuleIdentity
            |> Option.map (fun moduleInfo ->
                moduleInfo.Constructors
                |> Map.filter (fun name _ -> List.contains name Stdlib.FixedPreludeConstructors))
            |> Option.defaultValue Map.empty

        let moduleConstructors =
            surfaceIndex
            |> Map.tryFind moduleIdentity
            |> Option.map (fun moduleInfo -> moduleInfo.Constructors)
            |> Option.defaultValue Map.empty

        importedConstructors
        |> Map.fold (fun state name info -> Map.add name info state) preludeConstructors
        |> fun state -> moduleConstructors |> Map.fold (fun current name info -> Map.add name info current) state

    let private mergeVisibleProjections (surfaceIndex: Map<ModuleIdentity, ModuleSurfaceInfo>) moduleIdentity =
        let importedProjections =
            importedModuleInfos surfaceIndex moduleIdentity
            |> List.fold (fun state (spec, _importedModuleIdentity, importedModule) ->
                importedModule.Projections
                |> Map.fold (fun current name info ->
                    match
                        selectionImportedNameWithExplicitAccess
                            ImportNamespace.Term
                            importedModule.ExportedTerms
                            itemImportsTermName
                            (fun item -> Set.contains name importedModule.ExportedTerms || itemRequestsUnhide item)
                            spec.Selection
                            name
                    with
                    | Some localName -> Map.add localName info current
                    | None -> current) state) Map.empty

        let moduleProjections =
            surfaceIndex
            |> Map.tryFind moduleIdentity
            |> Option.map (fun moduleInfo -> moduleInfo.Projections)
            |> Option.defaultValue Map.empty

        moduleProjections
        |> Map.fold (fun state name info -> Map.add name info state) importedProjections

    let private mergeVisibleTypeAliases (surfaceIndex: Map<ModuleIdentity, ModuleSurfaceInfo>) moduleIdentity =
        let importedAliases =
            importedModuleInfos surfaceIndex moduleIdentity
            |> List.fold (fun state (spec, _importedModuleIdentity, importedModule) ->
                importedModule.TypeAliases
                |> Map.fold (fun current name info ->
                    match
                        selectionImportedNameWithExplicitAccess
                            ImportNamespace.Type
                            importedModule.ExportedTypes
                            itemImportsTypeName
                            (fun item ->
                                (Set.contains name importedModule.ExportedTypes || itemRequestsUnhide item)
                                && (not info.IsOpaque || itemRequestsClarify item))
                            spec.Selection
                            name
                    with
                    | Some localName -> Map.add localName info current
                    | None -> current) state) Map.empty

        let preludeAliases =
            surfaceIndex
            |> Map.tryFind preludeModuleIdentity
            |> Option.map (fun moduleInfo -> moduleInfo.TypeAliases)
            |> Option.defaultValue Map.empty

        let moduleAliases =
            surfaceIndex
            |> Map.tryFind moduleIdentity
            |> Option.map (fun moduleInfo -> moduleInfo.TypeAliases)
            |> Option.defaultValue Map.empty

        preludeAliases
        |> Map.fold (fun state name info -> Map.add name info state) importedAliases
        |> fun state -> moduleAliases |> Map.fold (fun current name info -> Map.add name info current) state

    let private mergeVisibleTypeFacets (surfaceIndex: Map<ModuleIdentity, ModuleSurfaceInfo>) moduleIdentity =
        let importedFacets =
            importedModuleInfos surfaceIndex moduleIdentity
            |> List.fold (fun state (spec, _importedModuleIdentity, importedModule) ->
                importedModule.TypeFacets
                |> Map.fold (fun current name info ->
                    match
                        selectionImportedNameWithExplicitAccess
                            ImportNamespace.Type
                            importedModule.ExportedTypes
                            itemImportsTypeName
                            (fun item -> Set.contains name importedModule.ExportedTypes || itemRequestsUnhide item)
                            spec.Selection
                            name
                    with
                    | Some localName -> Map.add localName info current
                    | None -> current) state) Map.empty

        let preludeFacets =
            surfaceIndex
            |> Map.tryFind preludeModuleIdentity
            |> Option.map (fun moduleInfo -> moduleInfo.TypeFacets)
            |> Option.defaultValue Map.empty

        let moduleFacets =
            surfaceIndex
            |> Map.tryFind moduleIdentity
            |> Option.map (fun moduleInfo -> moduleInfo.TypeFacets)
            |> Option.defaultValue Map.empty

        preludeFacets
        |> Map.fold (fun state name info -> Map.add name info state) importedFacets
        |> fun state -> moduleFacets |> Map.fold (fun current name info -> Map.add name info current) state

    let private mergeVisibleQualifiedTypeFacets (surfaceIndex: Map<ModuleIdentity, ModuleSurfaceInfo>) moduleIdentity =
        let importedQualifiedFacets =
            importedModuleInfos surfaceIndex moduleIdentity
            |> List.fold (fun state (spec, importedModuleIdentity, importedModule) ->
                match spec.Selection with
                | QualifiedOnly ->
                    let qualifiedPrefix =
                        spec.Alias
                        |> Option.map List.singleton
                        |> Option.defaultValue (ModuleIdentity.segments importedModuleIdentity)

                    importedModule.TypeFacets
                    |> Map.fold (fun current name info ->
                        if Set.contains name importedModule.ExportedTypes then
                            Map.add (qualifiedPrefix @ [ name ]) info current
                        else
                            current) state
                | _ ->
                    state) Map.empty

        let moduleQualifiedFacets =
            surfaceIndex
            |> Map.tryFind moduleIdentity
            |> Option.map (fun moduleInfo ->
                let qualifiedPrefix = ModuleIdentity.segments moduleIdentity

                moduleInfo.TypeFacets
                |> Map.fold (fun current name info -> Map.add (qualifiedPrefix @ [ name ]) info current) Map.empty)
            |> Option.defaultValue Map.empty

        importedQualifiedFacets
        |> Map.fold (fun state nameSegments info -> Map.add nameSegments info state) moduleQualifiedFacets

    let private mergeVisibleModules (surfaceIndex: Map<ModuleIdentity, ModuleSurfaceInfo>) moduleIdentity =
        let importedTermCandidates = collectImportedOrdinaryTermCandidates surfaceIndex moduleIdentity
        let _, _, importedModules, _ = partitionImportedOrdinaryTermCandidates importedTermCandidates

        Map.add (ModuleIdentity.text moduleIdentity) moduleIdentity importedModules

    let private mergeVisibleModulePaths (surfaceIndex: Map<ModuleIdentity, ModuleSurfaceInfo>) moduleIdentity =
        let importedModulePaths =
            importedModuleInfos surfaceIndex moduleIdentity
            |> List.fold (fun state (spec, importedModuleIdentity, _importedModule) ->
                match spec.Selection, spec.Alias with
                | QualifiedOnly, Some alias ->
                    Map.add [ alias ] importedModuleIdentity state
                | QualifiedOnly, None ->
                    Map.add (ModuleIdentity.segments importedModuleIdentity) importedModuleIdentity state
                | _ ->
                    state) Map.empty

        importedModulePaths
        |> Map.add (ModuleIdentity.segments moduleIdentity) moduleIdentity

    let private mergeAmbiguousVisibleOrdinaryTerms (surfaceIndex: Map<ModuleIdentity, ModuleSurfaceInfo>) moduleIdentity =
        let importedTermCandidates = collectImportedOrdinaryTermCandidates surfaceIndex moduleIdentity
        let importedBindings, importedConstructors, importedModules, importedAmbiguities =
            partitionImportedOrdinaryTermCandidates importedTermCandidates

        let preludeBindings =
            surfaceIndex
            |> Map.tryFind preludeModuleIdentity
            |> Option.map (fun moduleInfo -> moduleInfo.BindingSchemes)
            |> Option.defaultValue Map.empty

        let moduleBindings =
            surfaceIndex
            |> Map.tryFind moduleIdentity
            |> Option.map (fun moduleInfo -> moduleInfo.BindingSchemes)
            |> Option.defaultValue Map.empty

        let visibleBindings =
            preludeBindings
            |> Map.fold (fun state name info -> Map.add name info state) importedBindings
            |> fun state -> moduleBindings |> Map.fold (fun current name info -> Map.add name info current) state

        let preludeConstructors =
            surfaceIndex
            |> Map.tryFind preludeModuleIdentity
            |> Option.map (fun moduleInfo ->
                moduleInfo.Constructors
                |> Map.filter (fun name _ -> List.contains name Stdlib.FixedPreludeConstructors))
            |> Option.defaultValue Map.empty

        let moduleConstructors =
            surfaceIndex
            |> Map.tryFind moduleIdentity
            |> Option.map (fun moduleInfo -> moduleInfo.Constructors)
            |> Option.defaultValue Map.empty

        let visibleConstructors =
            preludeConstructors
            |> Map.fold (fun state name info -> Map.add name info state) importedConstructors
            |> fun state -> moduleConstructors |> Map.fold (fun current name info -> Map.add name info current) state

        let visibleModules = Map.add (ModuleIdentity.text moduleIdentity) moduleIdentity importedModules

        shadowAmbiguousVisibleTermCandidates visibleBindings visibleConstructors visibleModules importedAmbiguities

    let private buildVisibleOrdinaryGroups
        (visibleBindings: Map<string, BindingSchemeInfo>)
        (visibleConstructors: Map<string, BindingSchemeInfo>)
        (visibleModules: Map<string, ModuleIdentity>)
        (ambiguities: Map<string, OrdinaryVisibleTermCandidate list>)
        =
        [ visibleBindings |> Map.keys |> Set.ofSeq
          visibleConstructors |> Map.keys |> Set.ofSeq
          visibleModules |> Map.keys |> Set.ofSeq
          ambiguities |> Map.keys |> Set.ofSeq ]
        |> Set.unionMany
        |> Seq.fold (fun state localName ->
            Map.add
                localName
                { Binding = visibleBindings |> Map.tryFind localName
                  Constructor = visibleConstructors |> Map.tryFind localName
                  ModuleIdentity = visibleModules |> Map.tryFind localName
                  AmbiguousCandidates = ambiguities |> Map.tryFind localName |> Option.defaultValue [] }
                state)
                Map.empty

    let private buildVisibleStaticGroups
        (visibleTypeFacets: Map<string, TypeFacetInfo>)
        (visibleStaticObjects: Map<string list, StaticObjectInfo>)
        (visibleTraits: Map<string, TraitInfo>)
        =
        [ visibleTypeFacets |> Map.keys |> Seq.map List.singleton |> Set.ofSeq
          visibleStaticObjects |> Map.keys |> Set.ofSeq
          visibleTraits |> Map.keys |> Seq.map List.singleton |> Set.ofSeq ]
        |> Set.unionMany
        |> Seq.fold (fun state nameSegments ->
            let localRoot =
                match nameSegments with
                | [ root ] -> Some root
                | _ -> None

            Map.add
                nameSegments
                { StaticObject = visibleStaticObjects |> Map.tryFind nameSegments
                  TypeFacet = localRoot |> Option.bind (fun root -> visibleTypeFacets |> Map.tryFind root)
                  Trait = localRoot |> Option.bind (fun root -> visibleTraits |> Map.tryFind root) }
                state)
                Map.empty

    let private buildBaseBindingLoweringEnvironment
        (surfaceIndex: Map<ModuleIdentity, ModuleSurfaceInfo>)
        (moduleIdentity: ModuleIdentity)
        (currentModuleTopLevelDefinitions: Set<string>)
        (visibleBindings: Map<string, BindingSchemeInfo>)
        (components: VisibleEnvironmentComponents)
        =
        let visibleOrdinaryGroups =
            buildVisibleOrdinaryGroups
                visibleBindings
                components.VisibleConstructors
                components.VisibleModules
                components.AmbiguousVisibleOrdinaryTerms

        let visibleStaticGroups =
            buildVisibleStaticGroups components.VisibleTypeFacets Map.empty components.VisibleTraits

        { CurrentModuleIdentity = moduleIdentity
          CurrentModuleTopLevelDefinitions = currentModuleTopLevelDefinitions
          ImportedUnschemedOrdinaryTermNames = components.ImportedUnschemedOrdinaryTermNames
          SurfaceIndex = surfaceIndex
          VisibleTypeAliases = components.VisibleTypeAliases
          VisibleTypeFacets = components.VisibleTypeFacets
          VisibleQualifiedTypeFacets = components.VisibleQualifiedTypeFacets
          VisibleStaticGroups = visibleStaticGroups
          VisibleStaticObjects = Map.empty
          VisibleModulePaths = components.VisibleModulePaths
          VisibleModules = components.VisibleModules
          VisibleRecordTypes = components.VisibleRecordTypes
          VisibleBindings = visibleBindings
          VisibleConstructors = components.VisibleConstructors
          VisibleOrdinaryGroups = visibleOrdinaryGroups
          VisibleProjections = components.VisibleProjections
          VisibleTraits = components.VisibleTraits
          VisibleQualifiedTraits = components.VisibleQualifiedTraits
          VisibleInstances = components.VisibleInstances
          ElaborationAvailableBindings =
            visibleBindings
            |> Map.keys
            |> Set.ofSeq
            |> Set.intersect (IntrinsicCatalog.elaborationAvailableIntrinsicTermNames ())
          ConstraintDictionaries = Map.empty
          ConstrainedMembers = Map.empty }

    let private withVisibleStaticObjects
        (environment: BindingLoweringEnvironment)
        (staticObjects: Map<string list, StaticObjectInfo>)
        =
        let visibleStaticGroups =
            buildVisibleStaticGroups
                environment.VisibleTypeFacets
                staticObjects
                environment.VisibleTraits

        { environment with
            VisibleStaticGroups = visibleStaticGroups
            VisibleStaticObjects = staticObjects }

    let private mergeVisibleRecordTypes (surfaceIndex: Map<ModuleIdentity, ModuleSurfaceInfo>) moduleIdentity =
        let importedRecordTypes =
            importedModuleInfos surfaceIndex moduleIdentity
            |> List.fold (fun state (spec, _importedModuleIdentity, importedModule) ->
                importedModule.RecordTypes
                |> Map.fold (fun current name info ->
                    match
                        selectionImportedNameWithExplicitAccess
                            ImportNamespace.Type
                            importedModule.ExportedTypes
                            itemImportsTypeName
                            (fun item ->
                                match importedModule.TypeFacets |> Map.tryFind name with
                                | Some facetInfo when facetInfo.FacetKind = TypeAliasFacet ->
                                    (Set.contains name importedModule.ExportedTypes || itemRequestsUnhide item)
                                    && (not facetInfo.IsOpaque || itemRequestsClarify item)
                                | None ->
                                    false
                                | Some _ ->
                                    false)
                            spec.Selection
                            name
                    with
                    | Some localName -> Map.add localName info current
                    | None -> current) state) Map.empty

        let moduleRecordTypes =
            surfaceIndex
            |> Map.tryFind moduleIdentity
            |> Option.map (fun moduleInfo -> moduleInfo.RecordTypes)
            |> Option.defaultValue Map.empty

        moduleRecordTypes
        |> Map.fold (fun state name info -> Map.add name info state) importedRecordTypes

    let private mergeVisibleTraits (surfaceIndex: Map<ModuleIdentity, ModuleSurfaceInfo>) moduleIdentity =
        let importedTraits =
            importedModuleInfos surfaceIndex moduleIdentity
            |> List.fold (fun state (spec, _importedModuleIdentity, importedModule) ->
                importedModule.Traits
                |> Map.fold (fun current name info ->
                    match
                        selectionImportedNameWithExplicitAccess
                            ImportNamespace.Trait
                            importedModule.ExportedTraits
                            itemImportsTraitName
                            (fun item -> Set.contains name importedModule.ExportedTraits || itemRequestsUnhide item)
                            spec.Selection
                            name
                    with
                    | Some localName -> Map.add localName info current
                    | None -> current) state) Map.empty

        let preludeTraits =
            surfaceIndex
            |> Map.tryFind preludeModuleIdentity
            |> Option.map (fun moduleInfo -> moduleInfo.Traits)
            |> Option.defaultValue Map.empty

        let moduleTraits =
            surfaceIndex
            |> Map.tryFind moduleIdentity
            |> Option.map (fun moduleInfo -> moduleInfo.Traits)
            |> Option.defaultValue Map.empty

        preludeTraits
        |> Map.fold (fun state name info -> Map.add name info state) importedTraits
        |> fun state -> moduleTraits |> Map.fold (fun current name info -> Map.add name info current) state

    let private mergeVisibleQualifiedTraits (surfaceIndex: Map<ModuleIdentity, ModuleSurfaceInfo>) moduleIdentity =
        let importedQualifiedTraits =
            importedModuleInfos surfaceIndex moduleIdentity
            |> List.fold (fun state (spec, importedModuleIdentity, importedModule) ->
                match spec.Selection with
                | QualifiedOnly ->
                    let qualifiedPrefix =
                        spec.Alias
                        |> Option.map List.singleton
                        |> Option.defaultValue (ModuleIdentity.segments importedModuleIdentity)

                    importedModule.Traits
                    |> Map.fold (fun current name info ->
                        if Set.contains name importedModule.ExportedTraits then
                            Map.add (qualifiedPrefix @ [ name ]) info current
                        else
                            current) state
                | _ ->
                    state) Map.empty

        let moduleQualifiedTraits =
            surfaceIndex
            |> Map.tryFind moduleIdentity
            |> Option.map (fun moduleInfo ->
                let qualifiedPrefix = ModuleIdentity.segments moduleIdentity

                moduleInfo.Traits
                |> Map.fold (fun current name info -> Map.add (qualifiedPrefix @ [ name ]) info current) Map.empty)
            |> Option.defaultValue Map.empty

        importedQualifiedTraits
        |> Map.fold (fun state nameSegments info -> Map.add nameSegments info state) moduleQualifiedTraits

    let private moduleDependencyClosure (surfaceIndex: Map<ModuleIdentity, ModuleSurfaceInfo>) moduleIdentity =
        let rec visit visited currentModuleIdentity =
            if Set.contains currentModuleIdentity visited then
                visited
            else
                let visited = Set.add currentModuleIdentity visited

                let dependencies =
                    surfaceIndex
                    |> Map.tryFind currentModuleIdentity
                    |> Option.map (fun moduleInfo ->
                        moduleInfo.Imports
                        |> List.choose (fun spec ->
                            match moduleIdentityOfModuleSpecifier spec.Source with
                            | Some importedModuleIdentity when surfaceIndex.ContainsKey importedModuleIdentity -> Some importedModuleIdentity
                            | _ -> None))
                    |> Option.defaultValue []

                dependencies |> List.fold visit visited

        visit Set.empty moduleIdentity |> Set.toList |> List.sortBy ModuleIdentity.text

    let private visibleInstances (surfaceIndex: Map<ModuleIdentity, ModuleSurfaceInfo>) moduleIdentity =
        moduleDependencyClosure surfaceIndex moduleIdentity
        |> List.collect (fun visibleModuleIdentity ->
            surfaceIndex
            |> Map.tryFind visibleModuleIdentity
            |> Option.map (fun moduleInfo -> moduleInfo.Instances)
            |> Option.defaultValue [])
        |> List.sortBy (fun instanceInfo ->
            ModuleIdentity.text instanceInfo.ModuleIdentity,
            traitReferenceCanonicalName instanceInfo.Trait,
            instanceInfo.InstanceKey)

    let private computeVisibleEnvironmentComponents
        (surfaceIndex: Map<ModuleIdentity, ModuleSurfaceInfo>)
        moduleIdentity
        =
        { ImportedUnschemedOrdinaryTermNames =
            collectImportedOrdinaryTermCandidates surfaceIndex moduleIdentity
            |> importedUnschemedOrdinaryTermNamesFromCandidates
          VisibleTypeAliases = mergeVisibleTypeAliases surfaceIndex moduleIdentity
          VisibleTypeFacets = mergeVisibleTypeFacets surfaceIndex moduleIdentity
          VisibleQualifiedTypeFacets = mergeVisibleQualifiedTypeFacets surfaceIndex moduleIdentity
          VisibleModulePaths = mergeVisibleModulePaths surfaceIndex moduleIdentity
          VisibleModules = mergeVisibleModules surfaceIndex moduleIdentity
          VisibleRecordTypes = mergeVisibleRecordTypes surfaceIndex moduleIdentity
          VisibleConstructors = mergeVisibleConstructors surfaceIndex moduleIdentity
          AmbiguousVisibleOrdinaryTerms = mergeAmbiguousVisibleOrdinaryTerms surfaceIndex moduleIdentity
          VisibleProjections = mergeVisibleProjections surfaceIndex moduleIdentity
          VisibleTraits = mergeVisibleTraits surfaceIndex moduleIdentity
          VisibleQualifiedTraits = mergeVisibleQualifiedTraits surfaceIndex moduleIdentity
          VisibleInstances = visibleInstances surfaceIndex moduleIdentity }

    let private buildStaticObjectAliasesForModule
        (environment: BindingLoweringEnvironment)
        (declarations: TopLevelDeclaration list)
        =
        let transparentSealFields ascriptionTokens =
            match tryParseRecordSurfaceInfo ascriptionTokens with
            | Some recordInfo ->
                recordInfo.Fields
                |> List.filter (fun field -> not field.IsOpaque)
                |> List.map (fun field -> field.Name)
                |> Set.ofList
                |> Some
            | None ->
                match significantTokens ascriptionTokens with
                | [ nameToken ] when Token.isName nameToken ->
                    environment.VisibleRecordTypes
                    |> Map.tryFind (SyntaxFacts.trimIdentifierQuotes nameToken.Text)
                    |> Option.map (fun recordInfo ->
                        recordInfo.Fields
                        |> List.filter (fun field -> not field.IsOpaque)
                        |> List.map (fun field -> field.Name)
                        |> Set.ofList)
                | _ ->
                    None

        let copyNestedAliasesFiltered
            (sourcePrefix: string list)
            (targetPrefix: string list)
            (fieldFilter: string -> bool)
            (aliases: Map<string list, StaticObjectInfo>)
            =
            aliases
            |> Map.toList
            |> List.filter (fun (segments, _) ->
                match List.tryItem sourcePrefix.Length segments with
                | Some firstSuffixSegment
                    when List.length segments > sourcePrefix.Length
                         && List.take sourcePrefix.Length segments = sourcePrefix ->
                    fieldFilter firstSuffixSegment
                | _ ->
                    false)
            |> List.fold (fun (current: Map<string list, StaticObjectInfo>) (segments, staticObject) ->
                let suffixSegments = segments |> List.skip sourcePrefix.Length
                Map.add (targetPrefix @ suffixSegments) staticObject current) aliases

        let copyNestedAliases sourcePrefix targetPrefix aliases =
            copyNestedAliasesFiltered sourcePrefix targetPrefix (fun _ -> true) aliases

        let rec collectAliases
            (environment: BindingLoweringEnvironment)
            (prefix: string list)
            (expression: SurfaceExpression)
            (aliases: Map<string list, StaticObjectInfo>)
            =
            let aliasEnvironment =
                withVisibleStaticObjects environment aliases

            match tryResolveStaticObject aliasEnvironment expression with
            | Some staticObject ->
                let aliases = Map.add prefix staticObject aliases

                match expression with
                | Name sourcePrefix -> copyNestedAliases sourcePrefix prefix aliases
                | _ -> aliases
            | None ->
                match expression with
                | RecordLiteral fields ->
                    fields
                    |> List.fold (fun current field -> collectAliases environment (prefix @ [ field.Name ]) field.Value current) aliases
                | Seal(value, ascriptionTokens) ->
                    match value, transparentSealFields ascriptionTokens with
                    | Name sourcePrefix, Some transparentFields ->
                        copyNestedAliasesFiltered sourcePrefix prefix (fun fieldName -> Set.contains fieldName transparentFields) aliases
                    | RecordLiteral fields, Some transparentFields ->
                        fields
                        |> List.filter (fun field -> Set.contains field.Name transparentFields)
                        |> List.fold (fun current field -> collectAliases environment (prefix @ [ field.Name ]) field.Value current) aliases
                    | _, Some _ ->
                        aliases
                    | _ ->
                        collectAliases environment prefix value aliases
                | _ ->
                    aliases

        declarations
        |> List.fold (fun aliases declaration ->
            match declaration with
            | LetDeclaration definition when definition.Name.IsSome && definition.Body.IsSome ->
                collectAliases environment [ definition.Name.Value ] definition.Body.Value aliases
            | _ ->
                aliases) Map.empty

    let private normalizeTypeAliases (aliases: Map<string, TypeAliasInfo>) =
        let rec loop visited typeExpr =
            match typeExpr with
            | TypeLevelLiteral _ ->
                typeExpr
            | TypeUniverse None ->
                typeExpr
            | TypeUniverse(Some universeExpr) ->
                TypeUniverse(Some(loop visited universeExpr))
            | TypeIntrinsic _ ->
                typeExpr
            | TypeApply(callee, arguments) ->
                TypeApply(loop visited callee, arguments |> List.map (loop visited))
            | TypeLambda(parameterName, parameterSort, body) ->
                TypeLambda(parameterName, loop visited parameterSort, loop visited body)
            | TypeDelay inner ->
                TypeDelay(loop visited inner)
            | TypeMemo inner ->
                TypeMemo(loop visited inner)
            | TypeForce inner ->
                TypeForce(loop visited inner)
            | TypeProject(target, fieldName) ->
                TypeProject(loop visited target, fieldName)
            | TypeVariable _ ->
                typeExpr
            | TypeArrow(quantity, parameterType, resultType) ->
                TypeArrow(quantity, loop visited parameterType, loop visited resultType)
            | TypeEquality(left, right) ->
                TypeEquality(loop visited left, loop visited right)
            | TypeCapture(inner, captures) ->
                TypeCapture(loop visited inner, captures)
            | TypeEffectRow(entries, tail) ->
                TypeEffectRow(
                    entries
                    |> List.map (fun entry ->
                        { Label = loop visited entry.Label
                          Effect = loop visited entry.Effect }),
                    tail |> Option.map (loop visited)
                )
            | TypeRecord fields ->
                TypeRecord(
                    fields
                    |> List.map (fun field ->
                        { field with
                            Type = loop visited field.Type })
                )
            | TypeUnion members ->
                TypeUnion(members |> List.map (loop visited))
            | TypeName(nameSegments, [ inner ]) when matchesKnownType CompilerKnownSymbols.IOType nameSegments ->
                TypeName(nameSegments, [ voidType; loop visited inner ])
            | TypeName([ name ], arguments) ->
                let normalizedArguments = arguments |> List.map (loop visited)

                match aliases |> Map.tryFind name with
                | Some aliasInfo
                    when not (Set.contains name visited)
                         && aliasInfo.ConversionReducible
                         && List.length aliasInfo.Parameters = List.length normalizedArguments ->
                    let substitution = List.zip aliasInfo.Parameters normalizedArguments |> Map.ofList
                    aliasInfo.Body
                    |> TypeSignatures.applySubstitution substitution
                    |> loop (Set.add name visited)
                | _ ->
                    TypeName([ name ], normalizedArguments)
            | TypeName(name, arguments) ->
                TypeName(name, arguments |> List.map (loop visited))

        loop Set.empty

    let rec private tryUnwrapBindablePayloadType
        (aliases: Map<string, TypeAliasInfo>)
        typeExpr
        =
        match normalizeTypeAliases aliases typeExpr with
        | TypeCapture(inner, _) ->
            tryUnwrapBindablePayloadType aliases inner
        | TypeName(nameSegments, [ _; inner ]) when matchesKnownType CompilerKnownSymbols.EffType nameSegments -> Some inner
        | TypeName(nameSegments, [ inner ]) when matchesKnownType CompilerKnownSymbols.IOType nameSegments -> Some inner
        | TypeName(nameSegments, [ _; inner ]) when matchesKnownType CompilerKnownSymbols.IOType nameSegments -> Some inner
        | TypeName(nameSegments, [ inner ]) when matchesKnownType CompilerKnownSymbols.UIOType nameSegments -> Some inner
        | TypeName(_, [ inner ]) -> Some inner
        | _ -> None

    let rec private isCallableValidationType
        (aliases: Map<string, TypeAliasInfo>)
        typeExpr
        =
        match normalizeTypeAliases aliases typeExpr with
        | TypeCapture(inner, _) ->
            isCallableValidationType aliases inner
        | TypeVariable _
        | TypeArrow _
        | TypeLambda _ ->
            true
        | TypeName(nameSegments, _) when matchesKnownType CompilerKnownSymbols.ProjectorType nameSegments ->
            true
        | _ ->
            false

    type private EffectRowSplitResult =
        | SplitResolved of TypeExpr
        | SplitMismatch
        | SplitNeedsTailRefinement

    let private trySplitHandledEffectRow
        (aliases: Map<string, TypeAliasInfo>)
        (declaration: EffectSemanticDeclaration)
        effectRow
        =
        let normalize = normalizeTypeAliases aliases
        let expectedLabel = scopedEffectLabelType declaration |> normalize
        let expectedInterface = scopedEffectInterfaceType declaration |> normalize

        let matchesLabel typeExpr =
            TypeSignatures.definitionallyEqual (normalize typeExpr) expectedLabel

        let matchesInterface typeExpr =
            TypeSignatures.tryUnify (normalize typeExpr) expectedInterface
            |> Option.isSome

        let rec split current =
            match normalize current with
            | TypeEffectRow(entries, tail) ->
                let handledEntryIndex =
                    entries
                    |> List.tryFindIndex (fun entry ->
                        matchesLabel entry.Label
                        && matchesInterface entry.Effect)

                match handledEntryIndex with
                | Some entryIndex ->
                    let remainingEntries =
                        entries
                        |> List.mapi (fun index entry -> index, entry)
                        |> List.choose (fun (index, entry) ->
                            if index = entryIndex then
                                None
                            else
                                Some entry)

                    match remainingEntries, tail |> Option.map normalize with
                    | [], Some tailExpr ->
                        SplitResolved tailExpr
                    | _ ->
                        SplitResolved(TypeEffectRow(remainingEntries, tail |> Option.map normalize))
                | None ->
                    let mismatchedHandledLabel =
                        entries
                        |> List.exists (fun entry ->
                            matchesLabel entry.Label
                            && not (matchesInterface entry.Effect))

                    if mismatchedHandledLabel then
                        SplitMismatch
                    else
                        match tail with
                        | Some tailExpr ->
                            match split tailExpr with
                            | SplitResolved remainderTail ->
                                if List.isEmpty entries then
                                    SplitResolved remainderTail
                                else
                                    match normalize remainderTail with
                                    | TypeEffectRow(remainderEntries, remainderTailTail) ->
                                        SplitResolved(TypeEffectRow(entries @ remainderEntries, remainderTailTail))
                                    | _ ->
                                        SplitResolved(TypeEffectRow(entries, Some remainderTail))
                            | SplitMismatch ->
                                SplitMismatch
                            | SplitNeedsTailRefinement ->
                                SplitNeedsTailRefinement
                        | None ->
                            SplitMismatch
            | TypeVariable _ ->
                SplitNeedsTailRefinement
            | _ ->
                SplitMismatch

        split effectRow

    let private renderSurfaceSchemeTokens (scheme: TypeScheme) =
        let binderText (binder: TypeSignatures.ForallBinder) =
            let quantityPrefix =
                match binder.Quantity with
                | QuantityZero -> ""
                | quantity -> Quantity.toSurfaceText quantity + " "

            $"({quantityPrefix}{binder.Name} : {TypeSignatures.toText binder.Sort})"

        let constraintText (constraintInfo: TypeSignatures.TraitConstraint) =
            match constraintInfo.Arguments with
            | [] -> traitConstraintText constraintInfo
            | arguments ->
                String.concat " " ((traitConstraintText constraintInfo) :: (arguments |> List.map TypeSignatures.toText))

        let forallPrefix =
            match scheme.Forall with
            | [] -> ""
            | binders ->
                "forall " + (binders |> List.map binderText |> String.concat " ") + ". "

        let constraintsPrefix =
            match scheme.Constraints with
            | [] -> ""
            | constraints ->
                (constraints |> List.map constraintText |> String.concat ", ") + " => "

        typeTextTokens (forallPrefix + constraintsPrefix + TypeSignatures.toText scheme.Body)

    let private rewriteLocalTypeAliasesInSurfaceExpression
        currentModuleIdentity
        (visibleAliases: Map<string, TypeAliasInfo>)
        expression
        =
        let mergeAliases localAliases =
            visibleAliases
            |> Map.fold (fun state name info -> Map.add name info state) localAliases

        let expandTypeTokens localAliases tokens =
            let aliases = mergeAliases localAliases

            match TypeSignatures.parseScheme tokens with
            | Some scheme ->
                { scheme with
                    Forall = scheme.Forall |> List.map (fun binder -> { binder with Sort = normalizeTypeAliases aliases binder.Sort })
                    Constraints =
                        scheme.Constraints
                        |> List.map (fun constraintInfo ->
                            { constraintInfo with
                                Arguments = constraintInfo.Arguments |> List.map (normalizeTypeAliases aliases) })
                    Body = normalizeTypeAliases aliases scheme.Body }
                |> renderSurfaceSchemeTokens
            | None ->
                tokens
                |> TypeSignatures.parseType
                |> Option.map (normalizeTypeAliases aliases)
                |> Option.map TypeSignatures.toText
                |> Option.map typeTextTokens
                |> Option.defaultValue tokens

        let expandTypeTokenOption localAliases tokens =
            tokens |> Option.map (expandTypeTokens localAliases)

        let expandParameter localAliases (parameter: Parameter) =
            { parameter with
                TypeTokens = expandTypeTokenOption localAliases parameter.TypeTokens }

        let expandBinding localAliases (binding: SurfaceBindPattern) =
            { binding with
                TypeTokens = expandTypeTokenOption localAliases binding.TypeTokens }

        let expandEffectDeclaration localAliases (declaration: EffectDeclaration) =
            { declaration with
                HeaderTokens = expandTypeTokens localAliases declaration.HeaderTokens
                Operations =
                    declaration.Operations
                    |> List.map (fun operation ->
                        { operation with
                            SignatureTokens = expandTypeTokens localAliases operation.SignatureTokens }) }

        let expandTypeAlias localAliases (declaration: TypeAlias) =
            { declaration with
                HeaderTokens = expandTypeTokens localAliases declaration.HeaderTokens
                BodyTokens = expandTypeTokenOption localAliases declaration.BodyTokens }

        let rec rewritePattern localAliases pattern =
            match pattern with
            | TypedPattern(inner, typeTokens) ->
                TypedPattern(rewritePattern localAliases inner, expandTypeTokens localAliases typeTokens)
            | AsPattern(name, inner) ->
                AsPattern(name, rewritePattern localAliases inner)
            | ConstructorPattern(name, items) ->
                ConstructorPattern(name, items |> List.map (rewritePattern localAliases))
            | NamedConstructorPattern(name, fields) ->
                NamedConstructorPattern(
                    name,
                    fields
                    |> List.map (fun field ->
                        { field with
                            Pattern = rewritePattern localAliases field.Pattern })
                )
            | OrPattern items ->
                OrPattern(items |> List.map (rewritePattern localAliases))
            | TuplePattern items ->
                TuplePattern(items |> List.map (rewritePattern localAliases))
            | AnonymousRecordPattern(fields, rest) ->
                AnonymousRecordPattern(
                    fields |> List.map (fun field -> { field with Pattern = rewritePattern localAliases field.Pattern }),
                    rest
                )
            | VariantPattern variantPattern ->
                let rewrittenVariant =
                    match variantPattern with
                    | BoundVariantPattern(name, typeTokens) ->
                        BoundVariantPattern(name, expandTypeTokenOption localAliases typeTokens)
                    | WildcardVariantPattern typeTokens ->
                        WildcardVariantPattern(expandTypeTokenOption localAliases typeTokens)
                    | RestVariantPattern _ ->
                        variantPattern

                VariantPattern rewrittenVariant
            | WildcardPattern
            | NamePattern _
            | LiteralPattern _ ->
                pattern

        let rec rewriteDoStatement localAliases statement =
            match statement with
            | DoLet(binding, inner) ->
                DoLet(expandBinding localAliases binding, rewriteExpression localAliases inner)
            | DoLetQuestion(binding, inner, failure) ->
                let rewrittenFailure =
                    failure
                    |> Option.map (fun failure ->
                        { failure with
                            ResiduePattern = expandBinding localAliases failure.ResiduePattern
                            Body = failure.Body |> List.map (rewriteDoStatement localAliases) })

                DoLetQuestion(expandBinding localAliases binding, rewriteExpression localAliases inner, rewrittenFailure)
            | DoBind(binding, inner) ->
                DoBind(expandBinding localAliases binding, rewriteExpression localAliases inner)
            | DoUsing(binding, inner) ->
                DoUsing(expandBinding localAliases binding, rewriteExpression localAliases inner)
            | DoVar(name, inner) ->
                DoVar(name, rewriteExpression localAliases inner)
            | DoAssign(name, inner) ->
                DoAssign(name, rewriteExpression localAliases inner)
            | DoDefer inner ->
                DoDefer(rewriteExpression localAliases inner)
            | DoIf(condition, whenTrue, whenFalse) ->
                DoIf(
                    rewriteExpression localAliases condition,
                    whenTrue |> List.map (rewriteDoStatement localAliases),
                    whenFalse |> List.map (rewriteDoStatement localAliases)
                )
            | DoWhile(condition, body) ->
                DoWhile(rewriteExpression localAliases condition, body |> List.map (rewriteDoStatement localAliases))
            | DoReturn inner ->
                DoReturn(rewriteExpression localAliases inner)
            | DoExpression inner ->
                DoExpression(rewriteExpression localAliases inner)

        and rewriteExpression localAliases current =
            match current with
            | TypeSyntaxTokens _ ->
                current
            | SyntaxQuote inner ->
                SyntaxQuote(rewriteExpression localAliases inner)
            | SyntaxSplice inner ->
                SyntaxSplice(rewriteExpression localAliases inner)
            | TopLevelSyntaxSplice inner ->
                TopLevelSyntaxSplice(rewriteExpression localAliases inner)
            | CodeQuote inner ->
                CodeQuote(rewriteExpression localAliases inner)
            | CodeSplice inner ->
                CodeSplice(rewriteExpression localAliases inner)
            | Handle(isDeep, label, body, returnClause, operationClauses) ->
                let rewriteClause (clause: SurfaceEffectHandlerClause) =
                    { clause with
                        ArgumentTokens = clause.ArgumentTokens |> List.map (expandTypeTokens localAliases)
                        Body = rewriteExpression localAliases clause.Body }

                Handle(
                    isDeep,
                    rewriteExpression localAliases label,
                    rewriteExpression localAliases body,
                    rewriteClause returnClause,
                    operationClauses |> List.map rewriteClause
                )
            | LocalSignature(declaration, body) ->
                let expandedDeclaration =
                    { declaration with
                        TypeTokens = expandTypeTokens localAliases declaration.TypeTokens }

                LocalSignature(expandedDeclaration, rewriteExpression localAliases body)
            | LocalTypeAlias(declaration, body) ->
                let expandedDeclaration = expandTypeAlias localAliases declaration

                match tryParseTypeAliasInfo currentModuleIdentity expandedDeclaration with
                | Some(_, aliasInfo) ->
                    rewriteExpression (Map.add declaration.Name aliasInfo localAliases) body
                | None ->
                    LocalTypeAlias(expandedDeclaration, rewriteExpression localAliases body)
            | LocalLet(binding, value, body) ->
                LocalLet(expandBinding localAliases binding, rewriteExpression localAliases value, rewriteExpression localAliases body)
            | LocalScopedEffect(declaration, body) ->
                LocalScopedEffect(expandEffectDeclaration localAliases declaration, rewriteExpression localAliases body)
            | Lambda(parameters, body) ->
                Lambda(parameters |> List.map (expandParameter localAliases), rewriteExpression localAliases body)
            | IfThenElse(condition, whenTrue, whenFalse) ->
                IfThenElse(
                    rewriteExpression localAliases condition,
                    rewriteExpression localAliases whenTrue,
                    rewriteExpression localAliases whenFalse
                )
            | Match(scrutinee, cases) ->
                Match(
                    rewriteExpression localAliases scrutinee,
                    cases
                    |> List.map (fun caseClause ->
                        { caseClause with
                            Pattern = rewritePattern localAliases caseClause.Pattern
                            Guard = caseClause.Guard |> Option.map (rewriteExpression localAliases)
                            Body = rewriteExpression localAliases caseClause.Body })
                )
            | RecordLiteral fields ->
                RecordLiteral(fields |> List.map (fun field -> { field with Value = rewriteExpression localAliases field.Value }))
            | Seal(value, ascriptionTokens) ->
                Seal(rewriteExpression localAliases value, expandTypeTokens localAliases ascriptionTokens)
            | RecordUpdate(receiver, fields) ->
                RecordUpdate(rewriteExpression localAliases receiver, fields |> List.map (fun field -> { field with Value = rewriteExpression localAliases field.Value }))
            | MemberAccess(receiver, segments, arguments) ->
                MemberAccess(rewriteExpression localAliases receiver, segments, arguments |> List.map (rewriteExpression localAliases))
            | SafeNavigation(receiver, navigation) ->
                SafeNavigation(
                    rewriteExpression localAliases receiver,
                    { navigation with
                        Arguments = navigation.Arguments |> List.map (rewriteExpression localAliases) }
                )
            | TagTest(receiver, constructorName) ->
                TagTest(rewriteExpression localAliases receiver, constructorName)
            | Do statements ->
                Do(statements |> List.map (rewriteDoStatement localAliases))
            | MonadicSplice inner ->
                MonadicSplice(rewriteExpression localAliases inner)
            | Apply(callee, arguments) ->
                Apply(rewriteExpression localAliases callee, arguments |> List.map (rewriteExpression localAliases))
            | ExplicitImplicitArgument inner ->
                ExplicitImplicitArgument(rewriteExpression localAliases inner)
            | NamedApplicationBlock fields ->
                NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = rewriteExpression localAliases field.Value }))
            | InoutArgument inner ->
                InoutArgument(rewriteExpression localAliases inner)
            | Unary(operatorName, inner) ->
                Unary(operatorName, rewriteExpression localAliases inner)
            | Binary(left, operatorName, right) ->
                Binary(rewriteExpression localAliases left, operatorName, rewriteExpression localAliases right)
            | Elvis(left, right) ->
                Elvis(rewriteExpression localAliases left, rewriteExpression localAliases right)
            | Comprehension comprehension ->
                Comprehension { comprehension with Lowered = rewriteExpression localAliases comprehension.Lowered }
            | PrefixedString(prefix, parts) ->
                PrefixedString(
                    prefix,
                    parts
                    |> List.map (function
                        | StringText text -> StringText text
                        | StringInterpolation(inner, format) -> StringInterpolation(rewriteExpression localAliases inner, format))
                )
            | Literal _
            | NumericLiteral _
            | KindQualifiedName _
            | Name _ ->
                current

        rewriteExpression Map.empty expression

    let private tryUnwrapElabType aliases typeExpr =
        let normalize = normalizeTypeAliases aliases

        match normalize typeExpr with
        | TypeName(nameSegments, [ inner ]) when
            matchesKnownType CompilerKnownSymbols.ElabType nameSegments ->
            Some inner
        | _ -> None

    let private tryUnwrapSyntaxType aliases typeExpr =
        let normalize = normalizeTypeAliases aliases

        match normalize typeExpr with
        | TypeName(nameSegments, [ inner ]) when
            matchesKnownType CompilerKnownSymbols.SyntaxType nameSegments ->
            Some inner
        | _ -> None

    let private tryUnwrapTopLevelSyntaxSpliceType aliases typeExpr =
        tryUnwrapSyntaxType aliases typeExpr
        |> Option.orElseWith (fun () ->
            typeExpr
            |> tryUnwrapElabType aliases
            |> Option.bind (tryUnwrapSyntaxType aliases))

    let private tryCanonicalRecordType
        (aliases: Map<string, TypeAliasInfo>)
        typeExpr
        =
        match normalizeTypeAliases aliases typeExpr with
        | TypeRecord fields ->
            Some(TypeRecord fields)
        | _ ->
            None

    let rec private eraseSyntheticRecordTypeExpr typeExpr =
        match typeExpr with
        | TypeLevelLiteral _ ->
            typeExpr
        | TypeUniverse None ->
            typeExpr
        | TypeUniverse(Some universeExpr) ->
            TypeUniverse(Some(eraseSyntheticRecordTypeExpr universeExpr))
        | TypeIntrinsic _ ->
            typeExpr
        | TypeApply(callee, arguments) ->
            TypeApply(eraseSyntheticRecordTypeExpr callee, arguments |> List.map eraseSyntheticRecordTypeExpr)
        | TypeLambda(parameterName, parameterSort, body) ->
            TypeLambda(parameterName, eraseSyntheticRecordTypeExpr parameterSort, eraseSyntheticRecordTypeExpr body)
        | TypeDelay inner ->
            TypeDelay(eraseSyntheticRecordTypeExpr inner)
        | TypeMemo inner ->
            TypeMemo(eraseSyntheticRecordTypeExpr inner)
        | TypeForce inner ->
            TypeForce(eraseSyntheticRecordTypeExpr inner)
        | TypeProject(target, fieldName) ->
            TypeProject(eraseSyntheticRecordTypeExpr target, fieldName)
        | TypeVariable name ->
            TypeVariable name
        | TypeName(name, arguments) ->
            TypeName(name, arguments |> List.map eraseSyntheticRecordTypeExpr)
        | TypeArrow(_, parameterType, resultType) ->
            TypeArrow(QuantityOmega, eraseSyntheticRecordTypeExpr parameterType, eraseSyntheticRecordTypeExpr resultType)
        | TypeEquality(left, _) ->
            eraseSyntheticRecordTypeExpr left
        | TypeCapture(inner, _) ->
            eraseSyntheticRecordTypeExpr inner
        | TypeEffectRow(entries, tail) ->
            TypeEffectRow(
                entries
                |> List.map (fun entry ->
                    { Label = eraseSyntheticRecordTypeExpr entry.Label
                      Effect = eraseSyntheticRecordTypeExpr entry.Effect }),
                tail |> Option.map eraseSyntheticRecordTypeExpr
            )
        | TypeRecord fields ->
            fields
            |> List.choose (fun field ->
                if field.Quantity = QuantityZero then
                    None
                else
                    Some
                        { field with
                            Quantity = QuantityOmega
                            Type = eraseSyntheticRecordTypeExpr field.Type })
            |> TypeRecord
        | TypeUnion members ->
            TypeUnion(members |> List.map eraseSyntheticRecordTypeExpr)

    let private ensureSyntheticRecordLayout
        (moduleIdentity: ModuleIdentity)
        (filePath: string)
        (layouts: Map<string, SyntheticRecordLayout> ref)
        recordType
        =
        let erasedRecordType = eraseSyntheticRecordTypeExpr recordType
        let recordKey = TypeSignatures.toText erasedRecordType
        let canonicalRecordType = tryParseTypeText recordKey |> Option.defaultValue erasedRecordType

        match Map.tryFind recordKey layouts.Value with
        | Some layout ->
            layout
        | None ->
            let fields =
                match canonicalRecordType with
                | TypeRecord fields -> fields
                | _ -> []

            let typeName = syntheticRecordTypeName recordKey
            let constructorName = syntheticRecordConstructorName recordKey
            let provenance = syntheticOrigin filePath (Some moduleIdentity) typeName "synthetic-record"
            let typeParameters = TypeSignatures.collectFreeTypeVariables canonicalRecordType

            let layout =
                { TypeKey = recordKey
                  TypeExpr = canonicalRecordType
                  TypeName = typeName
                  ConstructorName = constructorName
                  TypeParameters = typeParameters
                  Fields = fields
                  Provenance = provenance }

            layouts.Value <- Map.add recordKey layout layouts.Value
            layout

    let private composeTypeSubstitution
        (existing: Map<string, TypeExpr>)
        (next: Map<string, TypeExpr>)
        =
        let rewrittenExisting =
            existing
            |> Map.map (fun _ value -> TypeSignatures.applySubstitution next value)

        next
        |> Map.fold (fun state name value -> Map.add name value state) rewrittenExisting

    let private isCompileTimeArgumentType
        (aliases: Map<string, TypeAliasInfo>)
        parameterType
        =
        match normalizeTypeAliases aliases parameterType with
        | TypeUniverse _
        | TypeIntrinsic UniverseClassifier
        | TypeIntrinsic ConstraintClassifier
        | TypeIntrinsic QuantityClassifier
        | TypeIntrinsic RegionClassifier
        | TypeIntrinsic RecRowClassifier
        | TypeIntrinsic VarRowClassifier
        | TypeIntrinsic EffRowClassifier
        | TypeIntrinsic LabelClassifier
        | TypeIntrinsic EffLabelClassifier ->
            true
        | TypeName([ "Type" ], []) ->
            true
        | TypeName(nameSegments, []) when
            matchesKnownType CompilerKnownSymbols.ConstraintType nameSegments
            || matchesKnownType CompilerKnownSymbols.QuantityType nameSegments
            || matchesKnownType CompilerKnownSymbols.RegionType nameSegments
            || matchesKnownType CompilerKnownSymbols.RecRowType nameSegments
            || matchesKnownType CompilerKnownSymbols.VarRowType nameSegments
            || matchesKnownType CompilerKnownSymbols.EffRowType nameSegments
            || matchesKnownType CompilerKnownSymbols.LabelType nameSegments
            || matchesKnownType CompilerKnownSymbols.EffLabelType nameSegments ->
            true
        | _ ->
            false

    let private isReifiedStaticObjectType
        (aliases: Map<string, TypeAliasInfo>)
        typeExpr
        =
        let rec loop current =
            match normalizeTypeAliases aliases current with
            | TypeUniverse _
            | TypeIntrinsic UniverseClassifier
            | TypeIntrinsic ConstraintClassifier
            | TypeIntrinsic QuantityClassifier
            | TypeIntrinsic RegionClassifier
            | TypeIntrinsic RecRowClassifier
            | TypeIntrinsic VarRowClassifier
            | TypeIntrinsic EffRowClassifier
            | TypeIntrinsic LabelClassifier
            | TypeIntrinsic EffLabelClassifier ->
                true
            | TypeName([ "Type" ], []) ->
                true
            | TypeName(nameSegments, []) when
                matchesKnownType CompilerKnownSymbols.ConstraintType nameSegments
                || matchesKnownType CompilerKnownSymbols.QuantityType nameSegments
                || matchesKnownType CompilerKnownSymbols.RegionType nameSegments
                || matchesKnownType CompilerKnownSymbols.RecRowType nameSegments
                || matchesKnownType CompilerKnownSymbols.VarRowType nameSegments
                || matchesKnownType CompilerKnownSymbols.EffRowType nameSegments
                || matchesKnownType CompilerKnownSymbols.LabelType nameSegments
                || matchesKnownType CompilerKnownSymbols.EffLabelType nameSegments ->
                true
            | TypeArrow(_, _, resultType) ->
                loop resultType
            | _ ->
                false

        loop typeExpr

    let private tryUnifyVisibleTypes
        (aliases: Map<string, TypeAliasInfo>)
        (pairs: (TypeExpr * TypeExpr) list)
        =
        let normalize = normalizeTypeAliases aliases
        pairs
        |> List.map (fun (left, right) -> normalize left, normalize right)
        |> TypeSignatures.tryUnifyMany

    let private qualifyVisibleTypeNames
        (environment: BindingLoweringEnvironment)
        typeExpr
        =
        let rec loop current =
            match normalizeTypeAliases environment.VisibleTypeAliases current with
            | TypeLevelLiteral _ ->
                current
            | TypeUniverse None ->
                current
            | TypeUniverse(Some universeExpr) ->
                TypeUniverse(Some(loop universeExpr))
            | TypeIntrinsic _ ->
                current
            | TypeApply(callee, arguments) ->
                TypeApply(loop callee, arguments |> List.map loop)
            | TypeLambda(parameterName, parameterSort, body) ->
                TypeLambda(parameterName, loop parameterSort, loop body)
            | TypeDelay inner ->
                TypeDelay(loop inner)
            | TypeMemo inner ->
                TypeMemo(loop inner)
            | TypeForce inner ->
                TypeForce(loop inner)
            | TypeProject(target, fieldName) ->
                TypeProject(loop target, fieldName)
            | TypeName(nameSegments, arguments) ->
                match tryResolveHandledEffectDeclaration environment (Name nameSegments), nameSegments with
                | Some declaration, _ ->
                    TypeName(scopedEffectInterfaceNameSegments declaration, arguments |> List.map loop)
                | None, [ name ] ->
                    match tryFindVisibleStaticGroup environment [ name ] with
                    | Some group when group.StaticObject |> Option.exists (fun staticObject -> staticObject.ObjectKind = TypeObject) ->
                        let staticObject = group.StaticObject.Value
                        TypeName(staticObject.NameSegments, arguments |> List.map loop)
                    | Some group when group.TypeFacet.IsSome ->
                        let typeFacet = group.TypeFacet.Value
                        let qualifiedName =
                            (ModuleIdentity.segments typeFacet.ModuleIdentity) @ [ typeFacet.Name ]

                        TypeName(qualifiedName, arguments |> List.map loop)
                    | _ ->
                        let aliasedSameSpellingTypeName =
                            environment.VisibleConstructors
                            |> Map.toSeq
                            |> Seq.tryPick (fun (localName, bindingInfo) ->
                                if not (String.Equals(localName, name, StringComparison.Ordinal))
                                   && String.Equals(bindingInfo.Name, name, StringComparison.Ordinal)
                                   && (bindingInfo.ConstructorTypeName
                                       |> Option.exists (fun constructorTypeName -> String.Equals(constructorTypeName, name, StringComparison.Ordinal))) then
                                    Some localName
                                else
                                    None)

                        match aliasedSameSpellingTypeName with
                        | Some localAlias ->
                            TypeName([ localAlias ], arguments |> List.map loop)
                        | None ->
                            TypeName(nameSegments, arguments |> List.map loop)
                | _ ->
                    TypeName(nameSegments, arguments |> List.map loop)
            | TypeArrow(quantity, parameterType, resultType) ->
                TypeArrow(quantity, loop parameterType, loop resultType)
            | TypeEquality(left, right) ->
                TypeEquality(loop left, loop right)
            | TypeCapture(inner, captures) ->
                TypeCapture(loop inner, captures)
            | TypeEffectRow(entries, tail) ->
                TypeEffectRow(
                    entries
                    |> List.map (fun entry ->
                        { Label = qualifyScopedEffectLabel entry.Label
                          Effect = loop entry.Effect }),
                    tail |> Option.map loop
                )
            | TypeRecord fields ->
                TypeRecord(
                    fields
                    |> List.map (fun field ->
                        { field with
                            Type = loop field.Type })
                )
            | TypeUnion members ->
                TypeUnion(members |> List.map loop)
            | TypeVariable _ ->
                current

        and qualifyScopedEffectLabel current =
            match normalizeTypeAliases environment.VisibleTypeAliases current with
            | TypeName(nameSegments, []) when not (List.isEmpty nameSegments) ->
                match tryResolveHandledEffectDeclaration environment (Name nameSegments) with
                | Some declaration -> scopedEffectLabelType declaration
                | None -> loop current
            | _ ->
                loop current

        loop typeExpr

    let private extendPatternLocalTypes
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (localTypes: Map<string, TypeExpr>)
        expectedType
        pattern
        =
        let tryAlignConstructorPatternParameterTypes layouts parameterTypes =
            let remaining = ref parameterTypes
            let aligned = ResizeArray<TypeExpr>()
            let mutable success = true

            for layout in layouts do
                match tryParseParameterType layout with
                | Some layoutType when isCompileTimeArgumentType environment.VisibleTypeAliases layoutType ->
                    aligned.Add(layoutType)

                    match !remaining with
                    | parameterType :: rest
                        when TypeSignatures.definitionallyEqual
                                 (normalizeTypeAliases environment.VisibleTypeAliases layoutType)
                                 (normalizeTypeAliases environment.VisibleTypeAliases parameterType) ->
                        remaining := rest
                    | _ ->
                        ()
                | Some layoutType when layout.IsImplicit ->
                    aligned.Add(layoutType)

                    match !remaining with
                    | parameterType :: rest
                        when TypeSignatures.definitionallyEqual
                                 (normalizeTypeAliases environment.VisibleTypeAliases layoutType)
                                 (normalizeTypeAliases environment.VisibleTypeAliases parameterType) ->
                        remaining := rest
                    | _ ->
                        ()
                | _ ->
                    match !remaining with
                    | parameterType :: rest ->
                        aligned.Add(parameterType)
                        remaining := rest
                    | [] ->
                        success <- false

            if success then
                Some(List.ofSeq aligned)
            else
                None

        let rec loop locals expected currentPattern =
            match currentPattern with
            | WildcardPattern
            | LiteralPattern _ ->
                locals
            | NamePattern name ->
                match expected with
                | Some expectedType -> Map.add name expectedType locals
                | None -> locals
            | AsPattern(name, inner) ->
                let locals =
                    match expected with
                    | Some expectedType -> Map.add name expectedType locals
                    | None -> locals

                loop locals expected inner
            | TypedPattern(inner, typeTokens) ->
                let ascribedType =
                    TypeSignatures.parseType typeTokens
                    |> Option.map (qualifyVisibleTypeNames environment)
                    |> Option.orElse expected

                loop locals ascribedType inner
            | TuplePattern elements ->
                let tupleFields =
                    elements
                    |> List.mapi (fun index element ->
                        { Name = $"_{index + 1}"
                          IsImplicit = false
                          Pattern = element })

                loop locals expected (AnonymousRecordPattern(tupleFields, None))
            | AnonymousRecordPattern(fields, rest) ->
                match expected |> Option.bind (tryCanonicalRecordType environment.VisibleTypeAliases) with
                | Some(TypeRecord recordFields) ->
                    let afterFields =
                        fields
                        |> List.fold (fun state field ->
                            let fieldType =
                                recordFields
                                |> List.tryFind (fun recordField -> String.Equals(recordField.Name, field.Name, StringComparison.Ordinal))
                                |> Option.map (fun recordField -> recordField.Type)

                            loop state fieldType field.Pattern) locals

                    match rest with
                    | Some(BindRecordPatternRest name) ->
                        let mentioned =
                            fields |> List.map (fun field -> field.Name) |> Set.ofList

                        let residualFields =
                            recordFields
                            |> List.filter (fun field -> not (Set.contains field.Name mentioned))

                        Map.add name (TypeRecord residualFields) afterFields
                    | _ ->
                        afterFields
                | _ ->
                    let afterFields = fields |> List.fold (fun state field -> loop state None field.Pattern) locals

                    match rest with
                    | Some(BindRecordPatternRest name) ->
                        Map.add name (TypeRecord []) afterFields
                    | _ ->
                        afterFields
            | ConstructorPattern(nameSegments, arguments) ->
                let argumentTypes =
                    match expected, tryResolveVisibleConstructorInfo environment nameSegments with
                    | Some expectedResultType, Some constructorInfo ->
                        let instantiated = TypeSignatures.instantiate "t" freshCounter.Value constructorInfo.Scheme
                        freshCounter.Value <- freshCounter.Value + instantiated.Forall.Length

                        let parameterTypes, constructorResultType = TypeSignatures.schemeParts instantiated
                        let alignedParameterTypes =
                            constructorInfo.ParameterLayouts
                            |> Option.bind (fun layouts ->
                                tryAlignConstructorPatternParameterTypes layouts parameterTypes)
                            |> Option.orElseWith (fun () ->
                                if List.length parameterTypes = List.length arguments then
                                    Some parameterTypes
                                else
                                    None)

                        match alignedParameterTypes with
                        | Some alignedParameterTypes when List.length alignedParameterTypes = List.length arguments ->
                            match
                                TypeSignatures.tryUnifyMany
                                    [
                                        qualifyVisibleTypeNames environment constructorResultType,
                                        qualifyVisibleTypeNames environment expectedResultType
                                    ]
                            with
                            | Some substitution ->
                                alignedParameterTypes
                                |> List.map (TypeSignatures.applySubstitution substitution >> Some)
                            | None ->
                                List.replicate arguments.Length None
                        | _ ->
                            List.replicate arguments.Length None
                    | Some _, None ->
                        List.replicate arguments.Length None
                    | _ ->
                        List.replicate arguments.Length None

                List.zip arguments argumentTypes
                |> List.fold (fun state (argumentPattern, argumentType) -> loop state argumentType argumentPattern) locals
            | NamedConstructorPattern(nameSegments, fields) ->
                let argumentTypes =
                    match expected, tryResolveVisibleConstructorInfo environment nameSegments with
                    | Some expectedResultType, Some constructorInfo ->
                        let instantiated = TypeSignatures.instantiate "t" freshCounter.Value constructorInfo.Scheme
                        freshCounter.Value <- freshCounter.Value + instantiated.Forall.Length

                        let parameterTypes, constructorResultType = TypeSignatures.schemeParts instantiated
                        let alignedFieldTypes =
                            constructorInfo.ParameterLayouts
                            |> Option.bind (fun layouts ->
                                tryAlignConstructorPatternParameterTypes layouts parameterTypes
                                |> Option.map (fun alignedTypes ->
                                    List.zip layouts alignedTypes
                                    |> List.filter (fun (parameter, _) -> not parameter.IsImplicit)
                                    |> List.map (fun (parameter, fieldType) -> parameter.Name, fieldType)
                                    |> Map.ofList))
                            |> Option.defaultValue Map.empty

                        match
                            TypeSignatures.tryUnifyMany
                                [
                                    qualifyVisibleTypeNames environment constructorResultType,
                                    qualifyVisibleTypeNames environment expectedResultType
                                ]
                        with
                        | Some substitution ->
                            alignedFieldTypes
                            |> Map.map (fun _ fieldType -> TypeSignatures.applySubstitution substitution fieldType)
                        | None ->
                            Map.empty
                    | _ ->
                        Map.empty

                fields
                |> List.fold (fun state field ->
                    let fieldType = argumentTypes |> Map.tryFind field.Name
                    loop state fieldType field.Pattern) locals
            | VariantPattern(BoundVariantPattern(name, Some typeTokens)) ->
                match TypeSignatures.parseType typeTokens with
                | Some parsedType ->
                    Map.add name (qualifyVisibleTypeNames environment parsedType) locals
                | None ->
                    locals
            | VariantPattern(BoundVariantPattern(name, None))
            | VariantPattern(RestVariantPattern name) ->
                match expected with
                | Some expectedType -> Map.add name expectedType locals
                | None -> locals
            | VariantPattern(WildcardVariantPattern _) ->
                locals
            | OrPattern alternatives ->
                match alternatives with
                | first :: _ ->
                    loop locals expected first
                | [] ->
                    locals

        loop localTypes expectedType pattern

    let private extendBindingLocalTypes
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (localTypes: Map<string, TypeExpr>)
        (binding: SurfaceBindPattern)
        expectedType
        =
        let extendedLocals =
            extendPatternLocalTypes environment freshCounter localTypes expectedType binding.Pattern

        if binding.IsImplicit then
            collectPatternNames binding.Pattern
            |> List.fold (fun state name ->
                match Map.tryFind name extendedLocals with
                | Some boundType -> Map.add $"__kappa_implicit_{name}" boundType state
                | None -> state) extendedLocals
        else
            extendedLocals

    let private unwrapInstantiatedCallType
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (scheme: TypeScheme)
        (argumentTypes: TypeExpr list)
        =
        let instantiated = TypeSignatures.instantiate "t" freshCounter.Value scheme
        freshCounter.Value <- freshCounter.Value + instantiated.Forall.Length

        let parameterTypes, resultType = TypeSignatures.schemeParts instantiated

        if List.length parameterTypes <> List.length argumentTypes then
            None
        else
            tryUnifyVisibleTypes environment.VisibleTypeAliases (List.zip parameterTypes argumentTypes)
            |> Option.map (fun substitution ->
                instantiated
                |> TypeSignatures.applySchemeSubstitution substitution,
                TypeSignatures.applySubstitution substitution resultType)

    let private inferLiteralType literal =
        match literal with
        | LiteralValue.Integer _ -> intType
        | LiteralValue.Float _ -> floatType
        | LiteralValue.String _ -> stringType
        | LiteralValue.Character _ -> unicodeScalarType
        | LiteralValue.Grapheme _ -> graphemeType
        | LiteralValue.Byte _ -> byteType
        | LiteralValue.Unit -> unitType

    let private inferSurfaceNumericLiteralType literal =
        match literal with
        | SurfaceIntegerLiteral _ -> intType
        | SurfaceRealLiteral _ -> floatType

    let private lowerBindingReturnTypeExpr
        (scheme: TypeScheme option)
        (parameters: Parameter list)
        (fallbackTokens: Token list option)
        =
        match tryParseReturnTypeType fallbackTokens with
        | Some explicitReturnType ->
            Some explicitReturnType
        | None ->
            match scheme with
            | Some scheme ->
                let resultType =
                    if List.isEmpty parameters then
                        scheme.Body
                    else
                        let _, resultType = TypeSignatures.schemeParts scheme
                        resultType

                Some resultType
            | None ->
                None

    let private lowerBindingReturnType
        (scheme: TypeScheme option)
        (parameters: Parameter list)
        (fallbackTokens: Token list option)
        =
        lowerBindingReturnTypeExpr scheme parameters fallbackTokens
        |> Option.map typeTextOf

    let private splitLeadingForallParameters
        (scheme: TypeScheme option)
        (parameters: Parameter list)
        =
        match scheme with
        | Some scheme ->
            let rec loop
                (remainingBinders: TypeSignatures.ForallBinder list)
                (remainingParameters: Parameter list)
                (consumed: Parameter list)
                =
                match remainingBinders, remainingParameters with
                | binder :: restBinders, parameter :: restParameters
                    when String.Equals(binder.Name, parameter.Name, StringComparison.Ordinal) ->
                    loop restBinders restParameters (parameter :: consumed)
                | _ ->
                    List.rev consumed, remainingParameters

            loop scheme.Forall parameters []
        | None ->
            [], parameters

    let private buildBindingParameters
        (_aliases: Map<string, TypeAliasInfo>)
        (scheme: TypeScheme option)
        (parameters: Parameter list)
        =
        match scheme with
        | Some scheme ->
            let leadingForallParameters, runtimeParameters = splitLeadingForallParameters (Some scheme) parameters
            let parameterTypes, _ = TypeSignatures.schemeParts scheme

            let typedLeadingForallParameters =
                if List.length leadingForallParameters <= List.length scheme.Forall then
                    List.zip leadingForallParameters (scheme.Forall |> List.take (List.length leadingForallParameters))
                    |> List.map (fun (parameter, binder) -> lowerKCoreParameter parameter (Some binder.Sort))
                else
                    []

            let typedRuntimeParameters =
                if List.length parameterTypes = List.length runtimeParameters then
                    List.zip runtimeParameters parameterTypes
                    |> List.map (fun (parameter, parameterType) ->
                        lowerKCoreParameter parameter (Some parameterType))
                else
                    runtimeParameters
                    |> List.map (fun parameter -> lowerKCoreParameter parameter (parameter.TypeTokens |> Option.bind TypeSignatures.parseType))

            if List.length typedLeadingForallParameters = List.length leadingForallParameters then
                typedLeadingForallParameters @ typedRuntimeParameters
            else
                parameters
                |> List.map (fun parameter -> lowerKCoreParameter parameter (parameter.TypeTokens |> Option.bind TypeSignatures.parseType))
        | None ->
            parameters |> List.map (fun parameter -> lowerKCoreParameter parameter (parameter.TypeTokens |> Option.bind TypeSignatures.parseType))

    let private buildLocalTypes
        (scheme: TypeScheme option)
        (parameters: Parameter list)
        =
        let implicitMarkerName name = $"__kappa_implicit_{name}"

        let forallLocals =
            match scheme with
            | Some scheme ->
                scheme.Forall
                |> List.map (fun binder -> binder.Name, binder.Sort)
            | None ->
                []

        let fromScheme =
            match scheme with
            | Some scheme ->
                let _, runtimeParameters = splitLeadingForallParameters (Some scheme) parameters
                let parameterTypes, _ = TypeSignatures.schemeParts scheme
                if List.length parameterTypes = List.length runtimeParameters then
                    List.zip runtimeParameters parameterTypes
                    |> List.map (fun (parameter, parameterType) -> parameter.Name, parameterType)
                else
                    []
            | None ->
                []

        let fromAnnotations =
            parameters
            |> List.choose (fun parameter ->
                tryParseParameterType parameter
                |> Option.map (fun parameterType -> parameter.Name, parameterType))

        let fromConstraints =
            match scheme with
            | Some scheme ->
                scheme.Constraints
                |> List.mapi (fun index constraintInfo ->
                    let dictionaryParameterName = $"__kappa_dict_{traitConstraintBinderStem constraintInfo}_{index}"
                    dictionaryParameterName, traitConstraintTypeName constraintInfo)
            | None ->
                []

        let implicitMarkers =
            (match scheme with
             | Some scheme ->
                 let _, runtimeParameters = splitLeadingForallParameters (Some scheme) parameters
                 let parameterTypes, _ = TypeSignatures.schemeParts scheme

                 if List.length parameterTypes = List.length runtimeParameters then
                     List.zip runtimeParameters parameterTypes
                     |> List.choose (fun (parameter, parameterType) ->
                         if parameter.IsImplicit then
                             Some(implicitMarkerName parameter.Name, parameterType)
                         else
                             None)
                 else
                     []
             | None ->
                 [])
            @
                (parameters
                 |> List.choose (fun parameter ->
                     if parameter.IsImplicit then
                         tryParseParameterType parameter
                         |> Option.map (fun parameterType -> implicitMarkerName parameter.Name, parameterType)
                     else
                         None))

        forallLocals @ fromScheme @ fromAnnotations @ fromConstraints @ implicitMarkers

    let private buildLocalImplicitTypes
        (scheme: TypeScheme option)
        (parameters: Parameter list)
        =
        let fromScheme =
            match scheme with
            | Some scheme ->
                let _, runtimeParameters = splitLeadingForallParameters (Some scheme) parameters
                let parameterTypes, _ = TypeSignatures.schemeParts scheme

                if List.length parameterTypes = List.length runtimeParameters then
                    List.zip runtimeParameters parameterTypes
                    |> List.choose (fun (parameter, parameterType) ->
                        if parameter.IsImplicit then
                            Some(parameter.Name, parameterType)
                        else
                            None)
                else
                    []
            | None ->
                []

        let fromAnnotations =
            parameters
            |> List.choose (fun parameter ->
                if parameter.IsImplicit then
                    tryParseParameterType parameter
                    |> Option.map (fun parameterType -> parameter.Name, parameterType)
                else
                    None)

        let fromConstraints =
            match scheme with
            | Some scheme ->
                scheme.Constraints
                |> List.mapi (fun index constraintInfo ->
                    let dictionaryParameterName = $"__kappa_dict_{traitConstraintBinderStem constraintInfo}_{index}"
                    dictionaryParameterName, traitConstraintTypeName constraintInfo)
            | None ->
                []

        fromScheme @ fromAnnotations @ fromConstraints
        |> List.fold (fun state (name, parameterType) -> Map.add name parameterType state) Map.empty

    let private buildSourceBindingInfosByName
        (moduleIdentity: ModuleIdentity)
        (declarations: TopLevelDeclaration list)
        =
        let moduleTopLevelDefinitionsByName =
            declarations
            |> List.choose (function
                | LetDeclaration candidate ->
                    match candidate.Name, candidate.Body with
                    | Some name, Some _ -> Some(name, candidate)
                    | _ -> None
                | _ ->
                    None)
            |> Map.ofList

        let sourceBindingInfosByName =
            let signatureBindingInfos =
                declarations
                |> List.choose (function
                    | SignatureDeclaration declaration ->
                        let signatureParameterLayouts =
                            declaration.TypeTokens
                            |> splitSignatureParameterTokens
                            |> function
                                | [] -> None
                                | parameterTokens -> Some(parameterTokens |> List.map tryParseSignatureParameterLayout)

                        TypeSignatures.parseScheme declaration.TypeTokens
                        |> Option.map (fun scheme ->
                            let parameterLayouts =
                                moduleTopLevelDefinitionsByName
                                |> Map.tryFind declaration.Name
                                |> Option.map (fun definition -> definition.Parameters)
                                |> mergeParameterLayouts signatureParameterLayouts
                                |> stripForallOnlyParameterLayouts scheme
                                |> stripLeadingConstraintAliasParameterLayouts scheme

                            declaration.Name,
                            bindingSchemeInfo
                                (bindingIdentity moduleIdentity declaration.Name)
                                (moduleTopLevelDefinitionsByName
                                 |> Map.tryFind declaration.Name
                                 |> Option.exists (fun definition -> definition.IsPattern))
                                scheme
                                declaration.TypeTokens
                                parameterLayouts
                                None
                                Map.empty)
                    | _ ->
                        None)
                |> Map.ofList

            declarations
            |> List.choose (function
                | LetDeclaration definition ->
                    match definition.Name, tryParseLetDefinitionScheme definition with
                    | Some name, Some scheme when not (Map.containsKey name signatureBindingInfos) ->
                        Some(
                            name,
                            bindingSchemeInfo
                                (bindingIdentity moduleIdentity name)
                                definition.IsPattern
                                scheme
                                (definition.ReturnTypeTokens |> Option.defaultValue [])
                                (Some definition.Parameters
                                 |> stripForallOnlyParameterLayouts scheme
                                 |> stripLeadingConstraintAliasParameterLayouts scheme)
                                None
                                Map.empty
                        )
                    | _ ->
                        None
                | _ ->
                    None)
            |> List.fold (fun state (name, bindingInfo) -> Map.add name bindingInfo state) signatureBindingInfos

        moduleTopLevelDefinitionsByName, sourceBindingInfosByName

    let private tryOptionPayloadType
        (aliases: Map<string, TypeAliasInfo>)
        (typeExpr: TypeExpr)
        =
        match normalizeTypeAliases aliases typeExpr with
        | TypeName(nameSegments, [ payloadType ]) when
            matchesKnownType CompilerKnownSymbols.OptionType nameSegments ->
            Some payloadType
        | _ ->
            None

    let private tryProjectVisibleRecordType
        (aliases: Map<string, TypeAliasInfo>)
        currentType
        path
        =
        let normalize = normalizeTypeAliases aliases

        let rec loop typeExpr remainingPath =
            match remainingPath, normalize typeExpr with
            | [], normalizedType ->
                Some normalizedType
            | fieldName :: rest, TypeRecord fields ->
                fields
                |> List.tryFind (fun field -> String.Equals(field.Name, fieldName, StringComparison.Ordinal))
                |> Option.bind (fun field -> loop field.Type rest)
            | _ ->
                None

        loop currentType path

    let private instantiateVisibleBindingResultType
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        name
        =
        environment.VisibleBindings
        |> Map.tryFind name
        |> Option.map (fun bindingInfo ->
            let instance = TypeSignatures.instantiate "t" freshCounter.Value bindingInfo.Scheme
            freshCounter.Value <- freshCounter.Value + instance.Forall.Length
            snd (TypeSignatures.schemeParts instance))

    let private instantiateVisibleBindingBodyType
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        name
        =
        environment.VisibleBindings
        |> Map.tryFind name
        |> Option.map (fun bindingInfo ->
            let instance = TypeSignatures.instantiate "t" freshCounter.Value bindingInfo.Scheme
            freshCounter.Value <- freshCounter.Value + instance.Forall.Length
            instance.Body)

    let private instantiateVisibleConstructorBodyType
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        name
        =
        environment.VisibleConstructors
        |> Map.tryFind name
        |> Option.map (fun constructorInfo ->
            let instance = TypeSignatures.instantiate "t" freshCounter.Value constructorInfo.Scheme
            freshCounter.Value <- freshCounter.Value + instance.Forall.Length
            instance.Body)

    let private tryInterpolatedMacroResultType
        (aliases: Map<string, TypeAliasInfo>)
        (typeExpr: TypeExpr)
        =
        let normalize = normalizeTypeAliases aliases

        match normalize typeExpr with
        | TypeName(nameSegments, [ resultType ]) when
            matchesKnownType CompilerKnownSymbols.InterpolatedMacroType nameSegments ->
            Some resultType
        | TypeName(nameSegments, [ dictionaryConstraint ]) when
            matchesKnownType CompilerKnownSymbols.DictType nameSegments ->
            match normalize dictionaryConstraint with
            | TypeName(innerNameSegments, [ resultType ]) when
                matchesKnownType CompilerKnownSymbols.InterpolatedMacroType innerNameSegments ->
                Some resultType
            | _ ->
                None
        | TypeName([ dictionaryTypeName ], [ resultType ])
            when String.Equals(dictionaryTypeName, TraitRuntime.dictionaryTypeName "InterpolatedMacro", StringComparison.Ordinal) ->
            Some resultType
        | _ ->
            None

    let private tryElabInterpolatedMacroResultType
        (aliases: Map<string, TypeAliasInfo>)
        (typeExpr: TypeExpr)
        =
        typeExpr
        |> tryUnwrapElabType aliases
        |> Option.bind (tryInterpolatedMacroResultType aliases)

    let private tryInferPrefixedStringMacroResultType
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (localTypes: Map<string, TypeExpr>)
        prefix
        =
        let tryResolve allowPlainDictionary resolvedType =
            tryElabInterpolatedMacroResultType environment.VisibleTypeAliases resolvedType
            |> Option.orElseWith (fun () ->
                if allowPlainDictionary then
                    tryInterpolatedMacroResultType environment.VisibleTypeAliases resolvedType
                else
                    None)

        match localTypes |> Map.tryFind prefix with
        | Some localType ->
            tryResolve false localType
        | None ->
            instantiateVisibleBindingResultType environment freshCounter prefix
            |> Option.bind (tryResolve (Set.contains prefix environment.ElaborationAvailableBindings))

    let private tryInferVisibleAppliedType
        (aliases: Map<string, TypeAliasInfo>)
        (qualifyTypeNames: TypeExpr -> TypeExpr)
        (inferArgumentType: SurfaceExpression -> TypeExpr option)
        headType
        arguments
        =
        let normalize = normalizeTypeAliases aliases

        let rec loop currentType remainingArguments =
            match remainingArguments with
            | [] ->
                Some currentType
            | argument :: rest ->
                match normalize currentType with
                | TypeArrow(_, parameterType, resultType) ->
                    inferArgumentType argument
                    |> Option.map qualifyTypeNames
                    |> Option.bind (fun argumentType ->
                        tryUnifyVisibleTypes aliases [ parameterType, argumentType ]
                        |> Option.map (fun substitution ->
                            TypeSignatures.applySubstitution substitution resultType)
                        |> Option.orElseWith (fun () ->
                            if TypeSignatures.definitionallyEqual (normalize parameterType) (normalize argumentType) then
                                Some resultType
                            else
                                None))
                    |> Option.bind (fun nextType -> loop nextType rest)
                | _ ->
                    None

        loop (qualifyTypeNames headType) arguments

    let private tryInferLocalAppliedType
        (aliases: Map<string, TypeAliasInfo>)
        (qualifyTypeNames: TypeExpr -> TypeExpr)
        (inferArgumentType: SurfaceExpression -> TypeExpr option)
        (localTypes: Map<string, TypeExpr>)
        expression
        =
        match expression with
        | Apply(Name [ calleeName ], arguments) ->
            localTypes
            |> Map.tryFind calleeName
            |> Option.bind (fun localType ->
                tryInferVisibleAppliedType aliases qualifyTypeNames inferArgumentType localType arguments)
        | _ ->
            None

    let private tryInferSafeNavigationMemberType
        (aliases: Map<string, TypeAliasInfo>)
        (qualifyTypeNames: TypeExpr -> TypeExpr)
        (inferArgumentType: SurfaceExpression -> TypeExpr option)
        payloadType
        (navigation: SurfaceSafeNavigationMember)
        =
        tryProjectVisibleRecordType aliases payloadType navigation.Segments
        |> Option.bind (fun headType -> tryInferVisibleAppliedType aliases qualifyTypeNames inferArgumentType headType navigation.Arguments)

    let rec private tryParseTypeLikeSurfaceExpression expression =
        match expression with
        | Name segments when not (List.isEmpty segments) ->
            Some(TypeName(segments, []))
        | NumericLiteral(SurfaceIntegerLiteral(value, _, None)) when value = 0I || value = 1I ->
            Some(TypeName([ value.ToString() ], []))
        | Apply(head, arguments) ->
            match tryParseTypeLikeSurfaceExpression head, arguments |> List.map tryParseTypeLikeSurfaceExpression with
            | Some(TypeName(name, existingArguments)), parsedArguments when parsedArguments |> List.forall Option.isSome ->
                Some(TypeName(name, existingArguments @ (parsedArguments |> List.choose id)))
            | _ ->
                None
        | ExplicitImplicitArgument inner ->
            tryParseTypeLikeSurfaceExpression inner
        | _ ->
            None

    type private QueryCarrierShape =
        { ExpectedMode: QuerySemantics.QueryModeInfo
          ExpectedItemQuantity: ResourceModel.ResourceQuantity
          Comprehension: SurfaceComprehension }

    type private QueryPlanShape =
        { InferredMode: QuerySemantics.QueryModeInfo
          InferredItemQuantity: ResourceModel.ResourceQuantity
          InferredItemType: TypeExpr }

    let private tryMatchQueryCarrierShape expression =
        let tryExplicit modeExpression itemQuantityExpression comprehension =
            match
                tryParseTypeLikeSurfaceExpression modeExpression |> Option.bind QuerySemantics.tryParseModeExpr,
                tryParseTypeLikeSurfaceExpression itemQuantityExpression |> Option.bind QuerySemantics.tryParseQuantityExpr
            with
            | Some modeInfo, Some itemQuantity ->
                Some
                    { ExpectedMode = modeInfo
                      ExpectedItemQuantity = itemQuantity
                      Comprehension = comprehension }
            | _ ->
                None

        match expression with
        | Apply(Name nameSegments, [ Comprehension comprehension ]) ->
            match nameSegments |> List.tryLast with
            | Some CompilerKnownSymbols.KnownTypeNames.Query ->
                Some
                    { ExpectedMode = QuerySemantics.reusableZeroOrMoreMode
                      ExpectedItemQuantity = ResourceQuantity.omega
                      Comprehension = comprehension }
            | Some CompilerKnownSymbols.KnownTypeNames.OnceQuery ->
                Some
                    { ExpectedMode = QuerySemantics.oneShotZeroOrMoreMode
                      ExpectedItemQuantity = ResourceQuantity.omega
                      Comprehension = comprehension }
            | _ ->
                None
        | Apply(Name nameSegments, [ modeExpression; itemQuantityExpression; Comprehension comprehension ])
            when nameSegments |> List.tryLast = Some CompilerKnownSymbols.KnownTypeNames.QueryCore ->
            tryExplicit modeExpression itemQuantityExpression comprehension
        | _ ->
            None

    let private tryInferComprehensionPlanShape
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (localTypes: Map<string, TypeExpr>)
        (inferExpressionType: Map<string, TypeExpr> -> SurfaceExpression -> TypeExpr option)
        (comprehension: SurfaceComprehension)
        =
        let normalize = normalizeTypeAliases environment.VisibleTypeAliases

        let trySourceInfo currentLocals sourceExpression =
            inferExpressionType currentLocals sourceExpression
            |> Option.bind (QuerySemantics.tryInferBuiltinQuerySource normalize)

        let addPatternQuantities
            (quantity: ResourceQuantity)
            (binding: SurfaceBindPattern)
            (quantities: Map<string, ResourceQuantity>)
            =
            ResourceCheckingSurface.collectPatternNames binding.Pattern
            |> List.fold (fun current name -> Map.add name quantity current) quantities

        let rec loop
            (currentMode: QuerySemantics.QueryModeInfo)
            currentLocals
            (currentQuantities: Map<string, ResourceQuantity>)
            clauses
            =
            match clauses with
            | [] ->
                let inferYield expression =
                    inferExpressionType currentLocals expression
                    |> Option.map (fun itemType ->
                        let itemQuantity =
                            match expression with
                            | Name [ name ] ->
                                currentQuantities |> Map.tryFind name |> Option.defaultValue ResourceQuantity.omega
                            | _ ->
                                ResourceQuantity.omega

                        { InferredMode = currentMode
                          InferredItemQuantity = itemQuantity
                          InferredItemType = itemType })

                match comprehension.Yield with
                | YieldValue value ->
                    inferYield value
                | YieldKeyValue(_, value) ->
                    inferYield value
            | clause :: rest ->
                match clause with
                | ForClause(_, _, binding, source) ->
                    trySourceInfo currentLocals source
                    |> Option.bind (fun sourceInfo ->
                        let nextLocals =
                            extendPatternLocalTypes environment freshCounter currentLocals (Some sourceInfo.Query.ItemType) binding.Pattern

                        let nextQuantities =
                            addPatternQuantities sourceInfo.Query.ItemQuantity binding currentQuantities

                        let nextMode : QuerySemantics.QueryModeInfo =
                            { Use = QuerySemantics.composeUse currentMode.Use sourceInfo.Query.Mode.Use
                              Card = QuerySemantics.multiplyCard currentMode.Card sourceInfo.Query.Mode.Card }

                        loop nextMode nextLocals nextQuantities rest)
                | LetClause(_, binding, value) ->
                    let nextLocals =
                        match inferExpressionType currentLocals value with
                        | Some valueType ->
                            extendPatternLocalTypes environment freshCounter currentLocals (Some valueType) binding.Pattern
                        | None ->
                            currentLocals

                    let nextQuantities =
                        let quantity =
                            binding.Quantity
                            |> Option.map ResourceQuantity.ofSurface
                            |> Option.defaultValue ResourceQuantity.omega

                        addPatternQuantities quantity binding currentQuantities

                    loop currentMode nextLocals nextQuantities rest
                | JoinClause(binding, source, _) ->
                    trySourceInfo currentLocals source
                    |> Option.bind (fun sourceInfo ->
                        let nextLocals =
                            extendPatternLocalTypes environment freshCounter currentLocals (Some sourceInfo.Query.ItemType) binding.Pattern

                        let nextQuantities =
                            addPatternQuantities sourceInfo.Query.ItemQuantity binding currentQuantities

                        let nextMode : QuerySemantics.QueryModeInfo =
                            { Use = QuerySemantics.composeUse currentMode.Use sourceInfo.Query.Mode.Use
                              Card = QuerySemantics.multiplyCard currentMode.Card sourceInfo.Query.Mode.Card }

                        loop { nextMode with Card = QuerySemantics.filterCard nextMode.Card } nextLocals nextQuantities rest)
                | IfClause _ ->
                    loop { currentMode with Card = QuerySemantics.filterCard currentMode.Card } currentLocals currentQuantities rest
                | GroupByClause(_, _, intoName) ->
                    let nextLocals =
                        Map.add intoName (TypeVariable $"__kappa_group_{intoName}") Map.empty

                    loop currentMode nextLocals Map.empty rest
                | OrderByClause _ ->
                    loop currentMode currentLocals currentQuantities rest
                | DistinctClause
                | DistinctByClause _ ->
                    loop currentMode currentLocals currentQuantities rest
                | SkipClause _
                | TakeClause _ ->
                    loop { currentMode with Card = QuerySemantics.filterCard currentMode.Card } currentLocals currentQuantities rest
                | LeftJoinClause(_, source, _, intoName) ->
                    trySourceInfo currentLocals source
                    |> Option.bind (fun sourceInfo ->
                        let intoQueryType =
                            TypeName(
                                CompilerKnownSymbols.KnownTypePaths.bare CompilerKnownSymbols.KnownTypeNames.QueryCore,
                                [
                                    TypeName(
                                        [ CompilerKnownSymbols.KnownTypeNames.QueryMode; CompilerKnownSymbols.KnownTypeNames.QueryMode ],
                                        [
                                            TypeName(
                                                [ CompilerKnownSymbols.KnownTypeNames.QueryUse
                                                  match sourceInfo.Query.Mode.Use with
                                                  | QuerySemantics.Reusable -> CompilerKnownSymbols.KnownTypeNames.QueryModeReusable
                                                  | QuerySemantics.OneShot -> CompilerKnownSymbols.KnownTypeNames.QueryModeOneShot ],
                                                []
                                            )
                                            TypeName(
                                                [ CompilerKnownSymbols.KnownTypeNames.QueryCard
                                                  match sourceInfo.Query.Mode.Card with
                                                  | QuerySemantics.QZero -> CompilerKnownSymbols.KnownTypeNames.QueryCardZero
                                                  | QuerySemantics.QOne -> CompilerKnownSymbols.KnownTypeNames.QueryCardOne
                                                  | QuerySemantics.QZeroOrOne -> CompilerKnownSymbols.KnownTypeNames.QueryCardZeroOrOne
                                                  | QuerySemantics.QOneOrMore -> CompilerKnownSymbols.KnownTypeNames.QueryCardOneOrMore
                                                  | QuerySemantics.QZeroOrMore -> CompilerKnownSymbols.KnownTypeNames.QueryCardZeroOrMore ],
                                                []
                                            )
                                        ]
                                    )
                                    TypeName([ ResourceQuantity.toSurfaceText sourceInfo.Query.ItemQuantity ], [])
                                    sourceInfo.Query.ItemType
                                ]
                            )

                        let nextLocals = Map.add intoName intoQueryType currentLocals
                        loop currentMode nextLocals currentQuantities rest)

        loop
            { Use = QuerySemantics.Reusable
              Card = QuerySemantics.QOne }
            localTypes
            Map.empty
            comprehension.Clauses

    let private tryInferQueryCarrierType
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (localTypes: Map<string, TypeExpr>)
        (inferExpressionType: Map<string, TypeExpr> -> SurfaceExpression -> TypeExpr option)
        expression
        =
        tryMatchQueryCarrierShape expression
        |> Option.bind (fun carrier ->
            tryInferComprehensionPlanShape environment freshCounter localTypes inferExpressionType carrier.Comprehension
            |> Option.map (fun plan ->
                TypeName(
                    CompilerKnownSymbols.KnownTypePaths.bare CompilerKnownSymbols.KnownTypeNames.QueryCore,
                    [
                        TypeName(
                            [ CompilerKnownSymbols.KnownTypeNames.QueryMode; CompilerKnownSymbols.KnownTypeNames.QueryMode ],
                            [
                                TypeName(
                                    [ CompilerKnownSymbols.KnownTypeNames.QueryUse
                                      match carrier.ExpectedMode.Use with
                                      | QuerySemantics.Reusable -> CompilerKnownSymbols.KnownTypeNames.QueryModeReusable
                                      | QuerySemantics.OneShot -> CompilerKnownSymbols.KnownTypeNames.QueryModeOneShot ],
                                    []
                                )
                                TypeName(
                                    [ CompilerKnownSymbols.KnownTypeNames.QueryCard
                                      match carrier.ExpectedMode.Card with
                                      | QuerySemantics.QZero -> CompilerKnownSymbols.KnownTypeNames.QueryCardZero
                                      | QuerySemantics.QOne -> CompilerKnownSymbols.KnownTypeNames.QueryCardOne
                                      | QuerySemantics.QZeroOrOne -> CompilerKnownSymbols.KnownTypeNames.QueryCardZeroOrOne
                                      | QuerySemantics.QOneOrMore -> CompilerKnownSymbols.KnownTypeNames.QueryCardOneOrMore
                                      | QuerySemantics.QZeroOrMore -> CompilerKnownSymbols.KnownTypeNames.QueryCardZeroOrMore ],
                                    []
                                )
                            ]
                        )
                        TypeName([ ResourceQuantity.toSurfaceText carrier.ExpectedItemQuantity ], [])
                        plan.InferredItemType
                    ]
                )))

    type private TypedQueryOrderedness =
        | TypedKnownOrdered
        | TypedKnownUnordered
        | TypedUnknownOrderedness

    type private TypedQueryState =
        { RowsExpression: SurfaceExpression
          RowNames: string list
          CurrentLocals: Map<string, TypeExpr>
          Orderedness: TypedQueryOrderedness }

    let private tryBuildTypedComprehensionLoweredExpression
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (localTypes: Map<string, TypeExpr>)
        (inferExpressionType: Map<string, TypeExpr> -> SurfaceExpression -> TypeExpr option)
        (comprehension: SurfaceComprehension)
        =
        let unsupportedClause =
            comprehension.Clauses
            |> List.exists (function
                | GroupByClause _
                | DistinctClause
                | DistinctByClause _
                | LeftJoinClause _ -> true
                | _ -> false)

        if unsupportedClause then
            None
        else
            let normalizeVisibleType = normalizeTypeAliases environment.VisibleTypeAliases
            let preludeResConstructorName = [ CompilerKnownSymbols.KnownTypeNames.Res; ":&" ]

            let freshSyntheticName prefix =
                let id = freshCounter.Value
                freshCounter.Value <- freshCounter.Value + 1
                $"{prefix}_{id}"

            let rec renderTypedTypeText current =
                let renderTypeName name =
                    if List.length name = List.length CompilerKnownSymbols.KnownModules.Prelude + 1
                       && (CompilerKnownSymbols.KnownTypes.tryClassifyName name |> Option.isSome) then
                        List.last name
                    else
                        SyntaxFacts.moduleNameToText name

                let renderArgument current =
                    match current with
                    | TypeLevelLiteral _
                    | TypeUniverse None
                    | TypeUniverse(Some(TypeLevelLiteral _))
                    | TypeIntrinsic _
                    | TypeName(_, [])
                    | TypeVariable _ ->
                        renderTypedTypeText current
                    | _ ->
                        $"({renderTypedTypeText current})"

                match current with
                | TypeName(name, []) ->
                    renderTypeName name
                | TypeName(name, arguments) ->
                    let argumentText = arguments |> List.map renderArgument |> String.concat " "
                    $"{renderTypeName name} {argumentText}"
                | TypeApply(callee, arguments) ->
                    let argumentText = arguments |> List.map renderArgument |> String.concat " "
                    $"{renderArgument callee} {argumentText}"
                | _ ->
                    TypeSignatures.toText current

            let typedTokens typeExpr =
                typeTextTokens $"({renderTypedTypeText typeExpr})"

            let makeParameterWithType name parameterType =
                { Name = name
                  TypeTokens = Some(typedTokens parameterType)
                  Quantity = None
                  IsImplicit = false
                  IsInout = false
                  IsReceiver = false }

            let makeTypedNameBinding name bindingType =
                { Pattern = NamePattern name
                  Quantity = None
                  IsImplicit = false
                  TypeTokens = Some(typedTokens bindingType)
                  BinderSpans = Map.empty }

            let bindTypedName name bindingType value body = LocalLet(makeTypedNameBinding name bindingType, value, body)

            let applyName name arguments = Apply(Name [ name ], arguments)
            let listNil = Name [ "Nil" ]
            let boolTrue = Name [ "True" ]
            let boolFalse = Name [ "False" ]
            let cons head tail = Apply(Name [ "::" ], [ head; tail ])

            let extendRowNames existingNames newNames =
                let newNameSet = newNames |> Set.ofList
                (existingNames |> List.filter (fun name -> not (Set.contains name newNameSet))) @ newNames

            let rec rowTypeOf rowNames currentLocals =
                let missingType prefix =
                    let id = freshCounter.Value
                    freshCounter.Value <- freshCounter.Value + 1
                    TypeVariable $"{prefix}{id}"

                match rowNames with
                | [] ->
                    unitType
                | [ name ] ->
                    currentLocals |> Map.tryFind name |> Option.defaultValue (missingType "queryRow")
                | name :: rest ->
                    TypeName(
                        CompilerKnownSymbols.KnownTypePaths.bare CompilerKnownSymbols.KnownTypeNames.Res,
                        [
                            currentLocals |> Map.tryFind name |> Option.defaultValue (missingType "queryRow")
                            rowTypeOf rest currentLocals
                        ]
                    )

            let listType itemType = knownTypeExpr CompilerKnownSymbols.ListType [ itemType ]

            let functionType parameterTypes resultType =
                parameterTypes
                |> List.rev
                |> List.fold (fun state parameterType -> TypeArrow(QuantityOmega, parameterType, state)) resultType

            let cloneBindingWithTypeIfMissing (binding: SurfaceBindPattern) bindingType =
                if binding.TypeTokens.IsSome then
                    binding
                else
                    { binding with
                        TypeTokens = Some(typedTokens bindingType) }

            let patternBoundNames (pattern: SurfacePattern) = collectPatternNames pattern

            let rec makeRowExpression rowNames =
                match rowNames with
                | [] ->
                    Literal LiteralValue.Unit
                | [ name ] ->
                    Name [ name ]
                | name :: rest ->
                    Apply(Name preludeResConstructorName, [ Name [ name ]; makeRowExpression rest ])

            let wrapPatternBindings (binding: SurfaceBindPattern) value body = LocalLet(binding, value, body)

            let wrapRowBindings rowNames currentLocals rowExpression body =
                let rowBindingType = rowTypeOf rowNames currentLocals

                let rec makeRowPattern names =
                    match names with
                    | [] -> WildcardPattern
                    | [ name ] -> NamePattern name
                    | name :: rest -> ConstructorPattern(preludeResConstructorName, [ NamePattern name; makeRowPattern rest ])

                match rowNames with
                | [] ->
                    body
                | [ name ] ->
                    wrapPatternBindings (makeTypedNameBinding name rowBindingType) rowExpression body
                | _ ->
                    wrapPatternBindings
                        { Pattern = makeRowPattern rowNames
                          Quantity = None
                          IsImplicit = false
                          TypeTokens = Some(typedTokens rowBindingType)
                          BinderSpans = Map.empty }
                        rowExpression
                        body

            let makeListMatch listExpression headName tailName consBody nilBody =
                Match(
                    listExpression,
                    [
                        { Pattern = ConstructorPattern([ "::" ], [ NamePattern headName; NamePattern tailName ])
                          Guard = None
                          Body = consBody }
                        { Pattern = ConstructorPattern([ "Nil" ], [])
                          Guard = None
                          Body = nilBody }
                    ]
                )

            let trySourceInfo currentLocals sourceExpression =
                inferExpressionType currentLocals sourceExpression
                |> Option.bind (QuerySemantics.tryInferBuiltinQuerySource normalizeVisibleType)

            let unwrapEnumeratedSource expression =
                match expression with
                | Apply(Name [ CompilerKnownSymbols.KnownTypeNames.Set ], [ items ]) ->
                    items, TypedKnownUnordered
                | _ ->
                    expression, TypedUnknownOrderedness

            let tryBuildStreamingComprehension () =
                let supportsStreamingLowering =
                    comprehension.Clauses
                    |> List.forall (function
                        | ForClause _
                        | LetClause _
                        | IfClause _ -> true
                        | _ -> false)

                if not supportsStreamingLowering then
                    None
                else
                    tryInferComprehensionPlanShape environment freshCounter localTypes inferExpressionType comprehension
                    |> Option.map (fun plan ->
                        let resultListType = listType plan.InferredItemType

                        let yieldExpression =
                            match comprehension.Yield with
                            | YieldValue valueExpression ->
                                valueExpression
                            | YieldKeyValue(keyExpression, valueExpression) ->
                                Apply(Name preludeResConstructorName, [ keyExpression; valueExpression ])

                        let rec lowerStreaming currentLocals clauses nextExpression =
                            match clauses with
                            | [] ->
                                cons yieldExpression nextExpression
                            | clause :: rest ->
                                match clause with
                                | ForClause(_, _, binding, sourceExpression) ->
                                    let enumeratedSourceExpression, _ = unwrapEnumeratedSource sourceExpression
                                    let loopName = freshSyntheticName "__query_stream_for"
                                    let sourceItemsName = freshSyntheticName "__query_stream_source"
                                    let itemName = freshSyntheticName "__query_stream_item"
                                    let itemTailName = freshSyntheticName "__query_stream_tail"
                                    let sourceInfo = trySourceInfo currentLocals sourceExpression
                                    let itemType =
                                        sourceInfo
                                        |> Option.map (fun info -> info.Query.ItemType)
                                        |> Option.defaultValue (TypeVariable "QueryItem")
                                    let sourceItemsType =
                                        inferExpressionType currentLocals enumeratedSourceExpression
                                        |> Option.defaultValue (listType itemType)
                                    let loopType = functionType [ sourceItemsType ] resultListType
                                    let typedBinding = cloneBindingWithTypeIfMissing binding itemType
                                    let nextLocals =
                                        extendBindingLocalTypes environment freshCounter currentLocals typedBinding (Some itemType)

                                    bindTypedName
                                        loopName
                                        loopType
                                        (Lambda(
                                            [ makeParameterWithType sourceItemsName sourceItemsType ],
                                            makeListMatch
                                                (Name [ sourceItemsName ])
                                                itemName
                                                itemTailName
                                                (wrapPatternBindings
                                                    typedBinding
                                                    (Name [ itemName ])
                                                    (lowerStreaming nextLocals rest (applyName loopName [ Name [ itemTailName ] ])))
                                                nextExpression
                                        ))
                                        (applyName loopName [ enumeratedSourceExpression ])
                                | LetClause(_, binding, valueExpression) ->
                                    let valueType =
                                        inferExpressionType currentLocals valueExpression
                                        |> Option.defaultValue (TypeVariable "QueryLet")
                                    let typedBinding = cloneBindingWithTypeIfMissing binding valueType
                                    let nextLocals =
                                        extendBindingLocalTypes environment freshCounter currentLocals typedBinding (Some valueType)

                                    wrapPatternBindings
                                        typedBinding
                                        valueExpression
                                        (lowerStreaming nextLocals rest nextExpression)
                                | IfClause conditionExpression ->
                                    IfThenElse(
                                        conditionExpression,
                                        lowerStreaming currentLocals rest nextExpression,
                                        nextExpression
                                    )
                                | _ ->
                                    nextExpression

                        lowerStreaming localTypes comprehension.Clauses listNil)

            let transformForClause (state: TypedQueryState) (binding: SurfaceBindPattern) sourceExpression =
                let nextRowNames = extendRowNames state.RowNames (patternBoundNames binding.Pattern)
                let enumeratedSourceExpression, sourceOrderedness = unwrapEnumeratedSource sourceExpression
                let loopRowsName = freshSyntheticName "__query_for_rows"
                let remainingRowsName = freshSyntheticName "__query_for_remaining_rows"
                let rowName = freshSyntheticName "__query_for_row"
                let rowTailName = freshSyntheticName "__query_for_row_tail"
                let loopItemsName = freshSyntheticName "__query_for_items"
                let itemName = freshSyntheticName "__query_for_item"
                let itemTailName = freshSyntheticName "__query_for_item_tail"
                let sourceItemsName = freshSyntheticName "__query_for_source_items"
                let currentRowType = rowTypeOf state.RowNames state.CurrentLocals
                let sourceInfo = trySourceInfo state.CurrentLocals sourceExpression
                let itemType = sourceInfo |> Option.map (fun info -> info.Query.ItemType) |> Option.defaultValue (TypeVariable "QueryItem")
                let nextLocals = extendBindingLocalTypes environment freshCounter state.CurrentLocals binding (Some itemType)
                let nextRowType = rowTypeOf nextRowNames nextLocals
                let currentRowsType = listType currentRowType
                let sourceItemsType =
                    inferExpressionType state.CurrentLocals enumeratedSourceExpression
                    |> Option.defaultValue (listType itemType)
                let nextRowsType = listType nextRowType
                let loopRowsType = functionType [ currentRowsType ] nextRowsType
                let loopItemsType = functionType [ sourceItemsType ] nextRowsType

                let transformedExpression =
                    bindTypedName
                        loopRowsName
                        loopRowsType
                        (Lambda(
                            [ makeParameterWithType remainingRowsName currentRowsType ],
                            makeListMatch
                                (Name [ remainingRowsName ])
                                rowName
                                rowTailName
                                (wrapRowBindings
                                    state.RowNames
                                    state.CurrentLocals
                                    (Name [ rowName ])
                                    (bindTypedName
                                        loopItemsName
                                        loopItemsType
                                        (Lambda(
                                            [ makeParameterWithType sourceItemsName sourceItemsType ],
                                            makeListMatch
                                                (Name [ sourceItemsName ])
                                                itemName
                                                itemTailName
                                                (wrapPatternBindings
                                                    (cloneBindingWithTypeIfMissing binding itemType)
                                                    (Name [ itemName ])
                                                    (cons
                                                        (makeRowExpression nextRowNames)
                                                        (applyName loopItemsName [ Name [ itemTailName ] ])))
                                                (applyName loopRowsName [ Name [ rowTailName ] ])
                                        ))
                                        (applyName loopItemsName [ enumeratedSourceExpression ])))
                                listNil
                        ))
                        (applyName loopRowsName [ state.RowsExpression ])

                let nextOrderedness =
                    match state.Orderedness, sourceOrderedness with
                    | TypedKnownUnordered, _
                    | _, TypedKnownUnordered -> TypedKnownUnordered
                    | TypedKnownOrdered, TypedKnownOrdered -> TypedKnownOrdered
                    | _ -> TypedUnknownOrderedness

                { RowsExpression = transformedExpression
                  RowNames = nextRowNames
                  CurrentLocals = nextLocals
                  Orderedness = nextOrderedness }

            let transformLetClause (state: TypedQueryState) (binding: SurfaceBindPattern) valueExpression =
                let nextRowNames = extendRowNames state.RowNames (patternBoundNames binding.Pattern)
                let loopName = freshSyntheticName "__query_let_loop"
                let remainingRowsName = freshSyntheticName "__query_let_rows"
                let rowName = freshSyntheticName "__query_let_row"
                let rowTailName = freshSyntheticName "__query_let_row_tail"
                let currentRowType = rowTypeOf state.RowNames state.CurrentLocals
                let currentRowsType = listType currentRowType
                let valueType =
                    inferExpressionType state.CurrentLocals valueExpression
                    |> Option.defaultValue (TypeVariable "QueryLet")
                let typedBinding = cloneBindingWithTypeIfMissing binding valueType
                let nextLocals = extendBindingLocalTypes environment freshCounter state.CurrentLocals typedBinding (Some valueType)
                let nextRowType = rowTypeOf nextRowNames nextLocals
                let nextRowsType = listType nextRowType
                let loopType = functionType [ currentRowsType ] nextRowsType

                let transformedExpression =
                    bindTypedName
                        loopName
                        loopType
                        (Lambda(
                            [ makeParameterWithType remainingRowsName currentRowsType ],
                            makeListMatch
                                (Name [ remainingRowsName ])
                                rowName
                                rowTailName
                                (wrapRowBindings
                                    state.RowNames
                                    state.CurrentLocals
                                    (Name [ rowName ])
                                    (wrapPatternBindings
                                        typedBinding
                                        valueExpression
                                        (cons
                                            (makeRowExpression nextRowNames)
                                            (applyName loopName [ Name [ rowTailName ] ]))))
                                listNil
                        ))
                        (applyName loopName [ state.RowsExpression ])

                { state with
                    RowsExpression = transformedExpression
                    RowNames = nextRowNames
                    CurrentLocals = nextLocals }

            let transformIfClause (state: TypedQueryState) conditionExpression =
                let loopName = freshSyntheticName "__query_if_loop"
                let remainingRowsName = freshSyntheticName "__query_if_rows"
                let rowName = freshSyntheticName "__query_if_row"
                let rowTailName = freshSyntheticName "__query_if_row_tail"
                let filteredTailName = freshSyntheticName "__query_if_tail_filtered"
                let currentRowType = rowTypeOf state.RowNames state.CurrentLocals
                let rowsType = listType currentRowType
                let loopType = functionType [ rowsType ] rowsType
                let transformedExpression =
                    bindTypedName
                        loopName
                        loopType
                        (Lambda(
                            [ makeParameterWithType remainingRowsName rowsType ],
                            makeListMatch
                                (Name [ remainingRowsName ])
                                rowName
                                rowTailName
                                (wrapRowBindings
                                    state.RowNames
                                    state.CurrentLocals
                                    (Name [ rowName ])
                                    (bindTypedName
                                        filteredTailName
                                        rowsType
                                        (applyName loopName [ Name [ rowTailName ] ])
                                        (IfThenElse(
                                            conditionExpression,
                                            cons (Name [ rowName ]) (Name [ filteredTailName ]),
                                            Name [ filteredTailName ]
                                        ))))
                                listNil
                        ))
                        (applyName loopName [ state.RowsExpression ])

                { state with RowsExpression = transformedExpression }

            let transformOrderByClause (state: TypedQueryState) direction keyExpression =
                let insertName = freshSyntheticName "__query_order_insert"
                let sortName = freshSyntheticName "__query_order_sort"
                let projectName = freshSyntheticName "__query_order_project"
                let remainingRowsName = freshSyntheticName "__query_order_rows"
                let sortedPairsName = freshSyntheticName "__query_order_pairs"
                let rowName = freshSyntheticName "__query_order_row"
                let rowTailName = freshSyntheticName "__query_order_row_tail"
                let pairName = freshSyntheticName "__query_order_pair"
                let headPairName = freshSyntheticName "__query_order_head_pair"
                let pairTailName = freshSyntheticName "__query_order_pair_tail"
                let currentKeyName = freshSyntheticName "__query_order_key"
                let currentRowValueName = freshSyntheticName "__query_order_row_value"
                let existingKeyName = freshSyntheticName "__query_order_existing_key"
                let existingRowValueName = freshSyntheticName "__query_order_existing_row"
                let currentRowType = rowTypeOf state.RowNames state.CurrentLocals
                let rowsType = listType currentRowType
                let keyType =
                    inferExpressionType state.CurrentLocals keyExpression
                    |> Option.defaultValue (TypeVariable "QueryOrderKey")
                let pairType = knownTypeExpr CompilerKnownSymbols.ResType [ keyType; currentRowType ]
                let pairListType = listType pairType
                let insertType = functionType [ pairType; pairListType ] pairListType
                let sortType = functionType [ rowsType ] pairListType
                let projectType = functionType [ pairListType ] rowsType
                let pairBinding name keyName rowValueName =
                    { Pattern = ConstructorPattern(preludeResConstructorName, [ NamePattern keyName; NamePattern rowValueName ])
                      Quantity = None
                      IsImplicit = false
                      TypeTokens = Some(typedTokens pairType)
                      BinderSpans = Map.empty }

                let orderedBeforeExisting =
                    match direction with
                    | Some Descending ->
                        Binary(
                            Binary(Name [ currentKeyName ], ">", Name [ existingKeyName ]),
                            "||",
                            Binary(Name [ currentKeyName ], "==", Name [ existingKeyName ])
                        )
                    | _ ->
                        Binary(
                            Binary(Name [ currentKeyName ], "<", Name [ existingKeyName ]),
                            "||",
                            Binary(Name [ currentKeyName ], "==", Name [ existingKeyName ])
                        )

                let transformedExpression =
                    bindTypedName
                        insertName
                        insertType
                        (Lambda(
                            [ makeParameterWithType pairName pairType
                              makeParameterWithType sortedPairsName pairListType ],
                            wrapPatternBindings
                                (pairBinding pairName currentKeyName currentRowValueName)
                                (Name [ pairName ])
                                (makeListMatch
                                    (Name [ sortedPairsName ])
                                    headPairName
                                    pairTailName
                                    (wrapPatternBindings
                                        (pairBinding headPairName existingKeyName existingRowValueName)
                                        (Name [ headPairName ])
                                        (IfThenElse(
                                            orderedBeforeExisting,
                                            cons (Name [ pairName ]) (Name [ sortedPairsName ]),
                                            cons
                                                (Name [ headPairName ])
                                                (applyName insertName [ Name [ pairName ]; Name [ pairTailName ] ])
                                        )))
                                    (cons (Name [ pairName ]) listNil))
                        ))
                        (bindTypedName
                            sortName
                            sortType
                            (Lambda(
                                [ makeParameterWithType remainingRowsName rowsType ],
                                makeListMatch
                                    (Name [ remainingRowsName ])
                                    rowName
                                    rowTailName
                                    (wrapRowBindings
                                        state.RowNames
                                        state.CurrentLocals
                                        (Name [ rowName ])
                                        (bindTypedName
                                            pairName
                                            pairType
                                            (Apply(Name preludeResConstructorName, [ keyExpression; Name [ rowName ] ]))
                                            (applyName
                                                insertName
                                                [ Name [ pairName ]
                                                  applyName sortName [ Name [ rowTailName ] ] ])))
                                    listNil
                            ))
                            (bindTypedName
                                projectName
                                projectType
                                (Lambda(
                                    [ makeParameterWithType sortedPairsName pairListType ],
                                    makeListMatch
                                        (Name [ sortedPairsName ])
                                        headPairName
                                        pairTailName
                                        (wrapPatternBindings
                                            (pairBinding headPairName existingKeyName existingRowValueName)
                                            (Name [ headPairName ])
                                            (cons
                                                (Name [ existingRowValueName ])
                                                (applyName projectName [ Name [ pairTailName ] ])))
                                        listNil
                                ))
                                (applyName projectName [ applyName sortName [ state.RowsExpression ] ])))

                { state with
                    RowsExpression = transformedExpression
                    Orderedness = TypedKnownOrdered }

            let transformSkipTakeClause (state: TypedQueryState) isTake countExpression =
                let loopName = freshSyntheticName (if isTake then "__query_take_loop" else "__query_skip_loop")
                let remainingRowsName = freshSyntheticName (if isTake then "__query_take_rows" else "__query_skip_rows")
                let remainingCountName =
                    freshSyntheticName (if isTake then "__query_take_count" else "__query_skip_count")
                let rowName = freshSyntheticName (if isTake then "__query_take_row" else "__query_skip_row")
                let rowTailName =
                    freshSyntheticName (if isTake then "__query_take_row_tail" else "__query_skip_row_tail")
                let currentRowType = rowTypeOf state.RowNames state.CurrentLocals
                let rowsType = listType currentRowType
                let countType =
                    inferExpressionType state.CurrentLocals countExpression
                    |> Option.defaultValue intType
                let loopType = functionType [ rowsType; countType ] rowsType
                let zeroLiteral = NumericLiteral(SurfaceIntegerLiteral(0I, "0", None))
                let decremented =
                    Binary(Name [ remainingCountName ], "-", NumericLiteral(SurfaceIntegerLiteral(1I, "1", None)))
                let countPositiveBranch =
                    if isTake then
                        cons (Name [ rowName ]) (applyName loopName [ Name [ rowTailName ]; decremented ])
                    else
                        applyName loopName [ Name [ rowTailName ]; decremented ]

                let countExhaustedBranch =
                    if isTake then
                        listNil
                    else
                        cons
                            (Name [ rowName ])
                            (applyName loopName [ Name [ rowTailName ]; Name [ remainingCountName ] ])

                let transformedExpression =
                    bindTypedName
                        loopName
                        loopType
                        (Lambda(
                            [ makeParameterWithType remainingRowsName rowsType
                              makeParameterWithType remainingCountName countType ],
                            makeListMatch
                                (Name [ remainingRowsName ])
                                rowName
                                rowTailName
                                (IfThenElse(
                                    Binary(Name [ remainingCountName ], ">", zeroLiteral),
                                    countPositiveBranch,
                                    countExhaustedBranch
                                ))
                                listNil
                        ))
                        (applyName loopName [ state.RowsExpression; countExpression ])

                { state with RowsExpression = transformedExpression }

            let mapYield (state: TypedQueryState) yieldedExpression =
                let loopName = freshSyntheticName "__query_yield_loop"
                let remainingRowsName = freshSyntheticName "__query_yield_rows"
                let rowName = freshSyntheticName "__query_yield_row"
                let tailName = freshSyntheticName "__query_yield_tail"
                let currentRowType = rowTypeOf state.RowNames state.CurrentLocals
                let yieldedType =
                    inferExpressionType state.CurrentLocals yieldedExpression
                    |> Option.defaultValue (TypeVariable "QueryYield")
                let rowsType = listType currentRowType
                let resultRowsType = listType yieldedType
                let loopType = functionType [ rowsType ] resultRowsType

                bindTypedName
                    loopName
                    loopType
                    (Lambda(
                        [ makeParameterWithType remainingRowsName rowsType ],
                        makeListMatch
                            (Name [ remainingRowsName ])
                            rowName
                            tailName
                            (wrapRowBindings
                                state.RowNames
                                state.CurrentLocals
                                (Name [ rowName ])
                                (cons yieldedExpression (applyName loopName [ Name [ tailName ] ])))
                            listNil
                    ))
                    (applyName loopName [ state.RowsExpression ])

            let mapYieldEntries (state: TypedQueryState) keyExpression valueExpression =
                mapYield state (Apply(Name preludeResConstructorName, [ keyExpression; valueExpression ]))

            let rec lowerClauses (state: TypedQueryState) clauses =
                match clauses with
                | [] ->
                    match comprehension.Yield with
                    | YieldValue valueExpression ->
                        mapYield state valueExpression
                    | YieldKeyValue(keyExpression, valueExpression) ->
                        mapYieldEntries state keyExpression valueExpression
                | clause :: rest ->
                    let nextState =
                        match clause with
                        | ForClause(_, _, binding, sourceExpression) ->
                            transformForClause state binding sourceExpression
                        | JoinClause(binding, sourceExpression, conditionExpression) ->
                            transformIfClause (transformForClause state binding sourceExpression) conditionExpression
                        | LetClause(_, binding, valueExpression) ->
                            transformLetClause state binding valueExpression
                        | IfClause conditionExpression ->
                            transformIfClause state conditionExpression
                        | OrderByClause(direction, keyExpression) ->
                            transformOrderByClause state direction keyExpression
                        | SkipClause countExpression ->
                            transformSkipTakeClause state false countExpression
                        | TakeClause countExpression ->
                            transformSkipTakeClause state true countExpression
                        | GroupByClause _
                        | DistinctClause
                        | DistinctByClause _
                        | LeftJoinClause _ ->
                            state

                    lowerClauses nextState rest

            let initialState =
                { RowsExpression = Apply(Name [ "::" ], [ Literal LiteralValue.Unit; Name [ "Nil" ] ])
                  RowNames = []
                  CurrentLocals = localTypes
                  Orderedness = TypedKnownOrdered }

            match tryBuildStreamingComprehension () with
            | Some expression ->
                Some expression
            | None ->
                Some(lowerClauses initialState comprehension.Clauses)

    let private tryInstantiateTraitSupertraits
        (traitInfo: TraitInfo)
        (arguments: TypeExpr list)
        =
        if List.length traitInfo.TypeParameters = List.length arguments then
            let substitution = List.zip traitInfo.TypeParameters arguments |> Map.ofList
            traitInfo.Supertraits
            |> List.map (TypeSignatures.applyConstraintSubstitution substitution)
            |> Some
        else
            None

    let private reachableTraitConstraints
        (environment: BindingLoweringEnvironment)
        (constraintInfo: TraitConstraint)
        =
        let rec visit visited acc (current: TraitConstraint) =
            let current = attachResolvedTraitConstraint environment current
            let key =
                (TypeSignatures.TraitReference.identity current.Trait
                 |> Option.map (fun identity ->
                     ModuleIdentity.text (DeclarationIdentity.moduleIdentity identity),
                     DeclarationIdentity.name identity)
                 |> Option.defaultValue ("", traitConstraintText current)),
                (current.Arguments
                 |> List.map (normalizeTypeAliases environment.VisibleTypeAliases >> TypeSignatures.toText))

            if Set.contains key visited then
                visited, acc
            else
                let visited = Set.add key visited
                let acc = current :: acc

                let nextConstraints =
                    tryResolveTraitInfoByReference environment current.Trait
                    |> Option.bind (fun traitInfo -> tryInstantiateTraitSupertraits traitInfo current.Arguments)
                    |> Option.defaultValue []

                nextConstraints |> List.fold (fun (visitedState, accState) next -> visit visitedState accState next) (visited, acc)

        visit Set.empty [] constraintInfo |> snd |> List.rev

    let private tryResolveTraitMemberFromReceiverType
        (environment: BindingLoweringEnvironment)
        (receiverType: TypeExpr)
        memberName
        =
        let tryFindOwnerTrait traitReference arguments memberName =
            let rootConstraint: TraitConstraint =
                { Trait = attachResolvedTraitReference environment traitReference
                  Arguments = arguments }

            reachableTraitConstraints environment rootConstraint
            |> List.tryPick (fun candidateConstraint ->
                tryResolveTraitInfoByReference environment candidateConstraint.Trait
                |> Option.bind (fun candidateTraitInfo ->
                    if candidateTraitInfo.Members.ContainsKey(memberName) then
                        Some(candidateTraitInfo, memberName, candidateConstraint.Arguments)
                    else
                        None))

        match normalizeTypeAliases environment.VisibleTypeAliases receiverType with
        | TypeName([ traitName ], arguments) ->
            tryResolveVisibleTraitByRoot environment traitName
            |> Option.bind (fun _ -> tryFindOwnerTrait (TypeSignatures.TraitReference.unqualified traitName) arguments memberName)
        | TypeName(qualifiedName, arguments) ->
            tryResolveVisibleTraitInfo environment qualifiedName
            |> Option.bind (fun _ -> tryFindOwnerTrait (TypeSignatures.TraitReference.ofSegments qualifiedName) arguments memberName)
        | _ ->
            None

    let private tryResolveTraitMemberProjection
        (environment: BindingLoweringEnvironment)
        (localTypes: Map<string, TypeExpr>)
        nameSegments
        =
        match nameSegments with
        | receiverName :: [ memberName ] ->
            localTypes
            |> Map.tryFind receiverName
            |> Option.orElseWith (fun () ->
                environment.VisibleBindings
                |> Map.tryFind receiverName
                |> Option.map (fun bindingInfo -> snd (TypeSignatures.schemeParts bindingInfo.Scheme)))
            |> Option.bind (fun receiverType ->
                tryResolveTraitMemberFromReceiverType environment receiverType memberName
                |> Option.map (fun (traitInfo, resolvedMemberName, resolvedArguments) ->
                    traitInfo, resolvedMemberName, resolvedArguments, receiverName))
        | _ ->
            None

    let private tryReceiverProjection
        (environment: BindingLoweringEnvironment)
        (localTypes: Map<string, TypeExpr>)
        receiverName
        memberName
        =
        let receiverType =
            localTypes
            |> Map.tryFind receiverName
            |> Option.orElseWith (fun () ->
                environment.VisibleBindings
                |> Map.tryFind receiverName
                |> Option.map (fun bindingInfo -> snd (TypeSignatures.schemeParts bindingInfo.Scheme)))
            |> Option.map (normalizeTypeAliases environment.VisibleTypeAliases)

        let binderMatchesReceiverType (binder: ProjectionPlaceBinder) =
            match receiverType, TypeSignatures.parseType binder.TypeTokens with
            | Some actualType, Some expectedType ->
                TypeSignatures.definitionallyEqual
                    actualType
                    (normalizeTypeAliases environment.VisibleTypeAliases expectedType)
            | _ ->
                true

        environment.VisibleProjections
        |> Map.tryFind memberName
        |> Option.bind (fun projectionInfo ->
            let placeBinders =
                projectionInfo.Binders
                |> List.choose (function
                    | ProjectionPlaceBinder binder -> Some binder
                    | ProjectionValueBinder _ -> None)

            match placeBinders with
            | [ binder ] when binder.IsReceiver && binderMatchesReceiverType binder ->
                Some projectionInfo
            | _ ->
                None)

    let private tryBuildReceiverMethodArguments
        (bindingInfo: BindingSchemeInfo)
        receiverExpression
        arguments
        =
        let tryReceiverMethodCallInfo () =
            bindingInfo.ParameterLayouts
            |> Option.bind (fun layouts ->
                let receiverParameters =
                    layouts
                    |> List.mapi (fun index layout -> index, layout)
                    |> List.filter (fun (_, layout) -> layout.IsReceiver)

                match receiverParameters with
                | [ receiverIndex, _ ] ->
                    let precedingExplicitCount =
                        layouts
                        |> List.take receiverIndex
                        |> List.filter (fun layout -> not layout.IsImplicit)
                        |> List.length

                    let requiredExplicitArgumentCount =
                        layouts
                        |> List.filter (fun layout -> not layout.IsImplicit)
                        |> List.length
                        |> fun count -> max 0 (count - 1)

                    Some(precedingExplicitCount, requiredExplicitArgumentCount)
                | _ ->
                    None)

        tryReceiverMethodCallInfo ()
        |> Option.bind (fun (precedingExplicitCount, _) ->
            if List.length arguments >= precedingExplicitCount then
                let precedingArguments = arguments |> List.take precedingExplicitCount
                let followingArguments = arguments |> List.skip precedingExplicitCount
                Some(precedingArguments @ [ receiverExpression ] @ followingArguments)
            else
                None)

    let private receiverMethodCallHasRequiredExplicitArguments
        (bindingInfo: BindingSchemeInfo)
        (arguments: SurfaceExpression list)
        =
        bindingInfo.ParameterLayouts
        |> Option.bind (fun layouts ->
            let receiverParameters =
                layouts
                |> List.filter (fun layout -> layout.IsReceiver)

            let requiredExplicitArgumentCount =
                layouts
                |> List.filter (fun layout -> not layout.IsImplicit)
                |> List.length
                |> fun count -> max 0 (count - 1)

            if List.length receiverParameters = 1 then
                Some(List.length arguments >= requiredExplicitArgumentCount)
            else
                None)
        |> Option.defaultValue true

    let private tryResolveIntrinsicTraitInstance
        (environment: BindingLoweringEnvironment)
        (constraintInfo: TraitConstraint)
        =
        let supportsIntrinsicTraitEvidenceType argumentType =
            match argumentType with
            | TypeName([ traitName ], _) ->
                tryResolveVisibleTraitByRoot environment traitName |> Option.isSome
            | TypeName(qualifiedName, _) ->
                tryResolveVisibleTraitInfo environment qualifiedName |> Option.isSome
            | _ ->
                false

        let normalizedArguments =
            constraintInfo.Arguments
            |> List.map (normalizeTypeAliases environment.VisibleTypeAliases)

        let constraintInfo = attachResolvedTraitConstraint environment constraintInfo
        let constraintTraitName = traitConstraintLocalName constraintInfo

        let canonicalArgumentTexts, moduleIdentity, instancePrefix =
            match constraintTraitName, normalizedArguments with
            | "IsTrait", [ argumentType ] ->
                (if supportsIntrinsicTraitEvidenceType argumentType then
                     Some [ TypeSignatures.toText argumentType ]
                 else
                     None),
                Some Stdlib.PreludeModuleIdentity,
                "builtin-prelude"
            | CompilerKnownSymbols.KnownTypeNames.IsProp, [ argumentType ] ->
                (if supportsIntrinsicTraitEvidenceType argumentType then
                     Some [ TypeSignatures.toText argumentType ]
                 else
                     None),
                Some Stdlib.PreludeModuleIdentity,
                "builtin-prelude"
            | "Eq", [ argumentType ] ->
                IntrinsicCatalog.tryCanonicalBuiltinPreludeEqHeadTypeText argumentType
                |> Option.map List.singleton,
                Some Stdlib.PreludeModuleIdentity,
                "builtin-prelude"
            | "Ord", [ argumentType ] ->
                IntrinsicCatalog.tryCanonicalBuiltinPreludeOrdHeadTypeText argumentType
                |> Option.map List.singleton,
                Some Stdlib.PreludeModuleIdentity,
                "builtin-prelude"
            | "Show", [ argumentType ] ->
                IntrinsicCatalog.tryCanonicalBuiltinPreludeShowHeadTypeText argumentType
                |> Option.map List.singleton,
                Some Stdlib.PreludeModuleIdentity,
                "builtin-prelude"
            | "Rangeable", [ argumentType ] ->
                IntrinsicCatalog.tryCanonicalBuiltinPreludeRangeableHeadTypeText argumentType
                |> Option.map List.singleton,
                Some Stdlib.PreludeModuleIdentity,
                "builtin-prelude"
            | _ ->
                None, None, ""

        match canonicalArgumentTexts, moduleIdentity with
        | Some canonicalArgumentTexts, Some moduleIdentity ->
            let normalizedArgumentText =
                canonicalArgumentTexts |> String.concat ","

            let instanceKey =
                $"{instancePrefix}:{constraintTraitName}:{normalizedArgumentText}"

            Some
                { ModuleIdentity = moduleIdentity
                  Trait =
                    TypeSignatures.TraitReference.unqualified constraintTraitName
                    |> TypeSignatures.TraitReference.attachIdentity (traitIdentity moduleIdentity constraintTraitName)
                  InstanceKey = instanceKey
                  Constraints = []
                  HeadTypes = normalizedArguments
                  Members = Map.empty }
        | _ ->
            None

    let private tryLowerCompilerIssuedTraitEvidence
        (environment: BindingLoweringEnvironment)
        parameterType
        =
        let supportsIntrinsicTraitEvidenceType argumentType =
            match normalizeTypeAliases environment.VisibleTypeAliases argumentType with
            | TypeName([ traitName ], _) ->
                tryResolveVisibleTraitByRoot environment traitName |> Option.isSome
            | TypeName(qualifiedName, _) ->
                tryResolveVisibleTraitInfo environment qualifiedName |> Option.isSome
            | _ ->
                false

        let normalizedParameterType =
            normalizeTypeAliases environment.VisibleTypeAliases parameterType

        let constraintInfo =
            match normalizedParameterType with
            | TypeName(nameSegments, [ argumentType ])
                when matchesKnownType CompilerKnownSymbols.IsTraitType nameSegments
                     && supportsIntrinsicTraitEvidenceType argumentType ->
                Some(unqualifiedTraitConstraint "IsTrait" [ argumentType ])
            | _ ->
                None

        constraintInfo
        |> Option.bind (fun constraintInfo ->
            tryResolveIntrinsicTraitInstance environment constraintInfo
            |> Option.map (fun instanceInfo ->
                KCoreDictionaryValue(
                    ModuleIdentity.text instanceInfo.ModuleIdentity,
                    traitReferenceRuntimeName instanceInfo.Trait,
                    instanceInfo.InstanceKey,
                    []
                )))

    let private resolveConstraintInstanceDetailedWithSubstitution
        (environment: BindingLoweringEnvironment)
        (constraintInfo: TraitConstraint)
        =
        let normalizeConstraint (constraintInfo: TraitConstraint) =
            let constraintInfo = attachResolvedTraitConstraint environment constraintInfo
            let normalizedArguments =
                constraintInfo.Arguments
                |> List.map (normalizeTypeAliases environment.VisibleTypeAliases >> TypeSignatures.toText)
                |> String.concat ","

            $"{traitConstraintCanonicalName constraintInfo}({normalizedArguments})"

        let rec solve visited (goal: TraitConstraint) =
            let goal = attachResolvedTraitConstraint environment goal
            let goalKey = normalizeConstraint goal

            if Set.contains goalKey visited then
                ConstraintUnresolved
            else
                let visited = Set.add goalKey visited

                let mutable nestedAmbiguity = None

                let survivingCandidates =
                    environment.VisibleInstances
                    |> List.choose (fun instanceInfo ->
                        let instanceInfo = attachResolvedInstanceTrait environment instanceInfo

                        if not (TypeSignatures.TraitReference.matches instanceInfo.Trait goal.Trait) then
                            None
                        elif List.length instanceInfo.HeadTypes <> List.length goal.Arguments then
                            None
                        else
                            tryUnifyVisibleTypes environment.VisibleTypeAliases (List.zip instanceInfo.HeadTypes goal.Arguments)
                            |> Option.bind (fun substitution ->
                                let instantiatedPremises =
                                    instanceInfo.Constraints
                                    |> List.map (TypeSignatures.applyConstraintSubstitution substitution)

                                let rec premisesSatisfied premises =
                                    match premises with
                                    | [] ->
                                        true
                                    | premise :: rest ->
                                        match solve visited premise with
                                        | ConstraintResolved _ ->
                                            premisesSatisfied rest
                                        | ConstraintUnresolved ->
                                            false
                                        | ConstraintAmbiguous(ambiguousGoal, candidates) ->
                                            nestedAmbiguity <- Some(ambiguousGoal, candidates)
                                            false

                                if premisesSatisfied instantiatedPremises then
                                    Some(instanceInfo, substitution)
                                else
                                    None))
                    |> List.sortBy (fun (instanceInfo, _) ->
                        let instanceInfo = attachResolvedInstanceTrait environment instanceInfo
                        ModuleIdentity.text instanceInfo.ModuleIdentity,
                        traitReferenceCanonicalName instanceInfo.Trait,
                        instanceInfo.InstanceKey)

                match nestedAmbiguity with
                | Some(ambiguousGoal, candidates) ->
                    ConstraintAmbiguous(ambiguousGoal, candidates)
                | None ->
                    match survivingCandidates with
                    | [] ->
                        match tryResolveIntrinsicTraitInstance environment goal with
                        | Some instanceInfo ->
                            ConstraintResolved(instanceInfo, Map.empty)
                        | None ->
                            ConstraintUnresolved
                    | [ instanceInfo, substitution ] ->
                        ConstraintResolved(instanceInfo, substitution)
                    | candidates ->
                        ConstraintAmbiguous(goal, candidates |> List.map fst)

        solve Set.empty constraintInfo

    let private resolveConstraintInstanceWithSubstitution
        (environment: BindingLoweringEnvironment)
        (constraintInfo: TraitConstraint)
        =
        match resolveConstraintInstanceDetailedWithSubstitution environment constraintInfo with
        | ConstraintResolved(instanceInfo, substitution) ->
            Some(instanceInfo, substitution)
        | ConstraintUnresolved
        | ConstraintAmbiguous _ ->
            None

    let private resolveConstraintInstance
        (environment: BindingLoweringEnvironment)
        (constraintInfo: TraitConstraint)
        =
        resolveConstraintInstanceWithSubstitution environment constraintInfo
        |> Option.map fst

    let private normalizedConstraintKey
        (environment: BindingLoweringEnvironment)
        (constraintInfo: TraitConstraint)
        =
        let constraintInfo = attachResolvedTraitConstraint environment constraintInfo
        let normalizedArguments =
            constraintInfo.Arguments
            |> List.map (normalizeTypeAliases environment.VisibleTypeAliases >> TypeSignatures.toText)
            |> String.concat ","

        $"{traitConstraintCanonicalName constraintInfo}({normalizedArguments})"

    let private addReachableConstraintDictionary
        (environment: BindingLoweringEnvironment)
        (constraintInfo: TraitConstraint)
        (dictionaryExpression: KCoreExpression)
        (state: Map<string, KCoreExpression>)
        =
        reachableTraitConstraints environment constraintInfo
        |> List.fold (fun current reachableConstraint ->
            let key = normalizedConstraintKey environment reachableConstraint

            if Map.containsKey key current then
                current
            else
                Map.add key dictionaryExpression current) state

    let private buildConstraintDictionaries
        (environment: BindingLoweringEnvironment)
        (entries: (TraitConstraint * KCoreExpression) list)
        =
        entries
        |> List.fold (fun state (constraintInfo, dictionaryExpression) ->
            addReachableConstraintDictionary environment constraintInfo dictionaryExpression state) Map.empty

    let private constraintHasLocalDictionary
        (environment: BindingLoweringEnvironment)
        (constraintInfo: TraitConstraint)
        =
        environment.ConstraintDictionaries
        |> Map.containsKey (normalizedConstraintKey environment constraintInfo)

    let private tryLowerResolvedDictionaryValue
        (environment: BindingLoweringEnvironment)
        (constraintInfo: TraitConstraint)
        =
        let localKey = normalizedConstraintKey environment constraintInfo

        let rec lower visited currentConstraint =
            let currentKey = normalizedConstraintKey environment currentConstraint

            if Set.contains currentKey visited then
                None
            else
                match environment.ConstraintDictionaries |> Map.tryFind currentKey with
                | Some dictionaryExpression ->
                    Some dictionaryExpression
                | None ->
                    resolveConstraintInstanceWithSubstitution environment currentConstraint
                    |> Option.bind (fun (instanceInfo, substitution) ->
                        let nextVisited = Set.add currentKey visited

                        let rec lowerPremises pending =
                            match pending with
                            | [] ->
                                Some []
                            | premise :: rest ->
                                let instantiatedPremise = TypeSignatures.applyConstraintSubstitution substitution premise

                                lower nextVisited instantiatedPremise
                                |> Option.bind (fun loweredPremise ->
                                    lowerPremises rest
                                    |> Option.map (fun loweredRest -> loweredPremise :: loweredRest))

                        lowerPremises instanceInfo.Constraints
                        |> Option.map (fun loweredPremises ->
                            KCoreDictionaryValue(
                                ModuleIdentity.text instanceInfo.ModuleIdentity,
                                traitReferenceRuntimeName instanceInfo.Trait,
                                instanceInfo.InstanceKey,
                                loweredPremises
                            )))

        environment.ConstraintDictionaries
        |> Map.tryFind localKey
        |> Option.orElseWith (fun () -> lower Set.empty constraintInfo)

    let private lowerResolvedOwningDictionaryValue
        (environment: BindingLoweringEnvironment)
        (traitName: string)
        (preparedCall: PreparedBindingCall)
        (fallbackInstanceInfo: InstanceInfo)
        =
        match preparedCall.InstantiatedScheme.Constraints with
        | owningConstraint :: _
            when String.Equals(traitConstraintLocalName (attachResolvedTraitConstraint environment owningConstraint), traitName, StringComparison.Ordinal) ->
            tryLowerResolvedDictionaryValue environment owningConstraint
            |> Option.defaultValue (
                KCoreDictionaryValue(
                    ModuleIdentity.text fallbackInstanceInfo.ModuleIdentity,
                    traitReferenceRuntimeName fallbackInstanceInfo.Trait,
                    fallbackInstanceInfo.InstanceKey,
                    []
                )
            )
        | _ ->
            KCoreDictionaryValue(
                ModuleIdentity.text fallbackInstanceInfo.ModuleIdentity,
                traitReferenceRuntimeName fallbackInstanceInfo.Trait,
                fallbackInstanceInfo.InstanceKey,
                []
            )

    let private tryTraitConstraintFromType
        (environment: BindingLoweringEnvironment)
        parameterType
        =
        match normalizeTypeAliases environment.VisibleTypeAliases parameterType with
        | TypeName([ traitName ], arguments) ->
            match tryResolveVisibleTraitByRoot environment traitName with
            | Some traitInfo ->
                Some
                    { Trait = TypeSignatures.TraitReference.unqualified traitName |> TypeSignatures.TraitReference.attachIdentity traitInfo.Identity
                      Arguments = arguments }
            | None ->
                environment.VisibleTraits
                |> Map.toSeq
                |> Seq.tryFind (fun (_, traitInfo) ->
                    String.Equals(traitName, TraitRuntime.dictionaryTypeName traitInfo.Name, StringComparison.Ordinal))
                |> Option.map (fun (_, traitInfo) ->
                    { Trait = TypeSignatures.TraitReference.unqualified traitInfo.Name |> TypeSignatures.TraitReference.attachIdentity traitInfo.Identity
                      Arguments = arguments })
        | TypeName(qualifiedName, arguments) ->
            tryResolveVisibleTraitInfo environment qualifiedName
            |> Option.map (fun traitInfo ->
                { Trait = TypeSignatures.TraitReference.ofSegments qualifiedName |> TypeSignatures.TraitReference.attachIdentity traitInfo.Identity
                  Arguments = arguments })
        | _ ->
            None

    let private semanticallyMatchesTraitConstraintType
        (environment: BindingLoweringEnvironment)
        leftType
        rightType
        =
        match
            tryTraitConstraintFromType environment leftType,
            tryTraitConstraintFromType environment rightType
        with
        | Some leftConstraint, Some rightConstraint ->
            let leftConstraint = attachResolvedTraitConstraint environment leftConstraint
            let rightConstraint = attachResolvedTraitConstraint environment rightConstraint
            TypeSignatures.TraitReference.matches leftConstraint.Trait rightConstraint.Trait
            && List.length leftConstraint.Arguments = List.length rightConstraint.Arguments
            && List.forall2
                (fun leftArgument rightArgument ->
                    TypeSignatures.definitionallyEqual
                        (normalizeTypeAliases environment.VisibleTypeAliases leftArgument)
                        (normalizeTypeAliases environment.VisibleTypeAliases rightArgument))
                leftConstraint.Arguments
                rightConstraint.Arguments
        | _ ->
            false

    let private forallInstantiationSubstitution (sourceScheme: TypeScheme) (instantiatedScheme: TypeScheme) =
        if List.length sourceScheme.Forall <> List.length instantiatedScheme.Forall then
            Map.empty
        else
            List.zip sourceScheme.Forall instantiatedScheme.Forall
            |> List.map (fun (sourceBinder, instantiatedBinder) ->
                sourceBinder.Name, TypeVariable instantiatedBinder.Name)
            |> Map.ofList

    let private localTraitConstraints
        (environment: BindingLoweringEnvironment)
        (localTypes: Map<string, TypeExpr>)
        =
        localTypes
        |> Map.toList
        |> List.choose (fun (name, localType) ->
            tryTraitConstraintFromType environment localType
            |> Option.map (fun constraintInfo -> name, constraintInfo))

    let private buildConstrainedMembers
        (environment: BindingLoweringEnvironment)
        (constraints: TraitConstraint list)
        =
        let addConstraintMembers state dictionaryParameterName constraintInfo =
            reachableTraitConstraints environment constraintInfo
            |> List.fold (fun current reachableConstraint ->
                tryResolveTraitInfoByReference environment reachableConstraint.Trait
                |> Option.map (fun traitInfo ->
                    traitInfo.Members
                    |> Map.toList
                    |> List.fold (fun innerState (memberName, _) ->
                        if Map.containsKey memberName innerState then
                            innerState
                        else
                            Map.add memberName (traitConstraintRuntimeName reachableConstraint, dictionaryParameterName) innerState) current)
                |> Option.defaultValue current) state

        constraints
        |> List.mapi (fun index constraintInfo ->
            let dictionaryParameterName = $"__kappa_dict_{traitConstraintBinderStem constraintInfo}_{index}"
            constraintInfo, dictionaryParameterName)
        |> List.fold (fun state (constraintInfo, dictionaryParameterName) ->
            addConstraintMembers state dictionaryParameterName constraintInfo) Map.empty

    let private buildParameterConstrainedMembers
        (environment: BindingLoweringEnvironment)
        (scheme: TypeScheme)
        (parameters: Parameter list)
        =
        let tryAlignParameterTypesWithParameters () =
            let parameterTypes, _ = TypeSignatures.schemeParts scheme
            let remaining = ref parameterTypes
            let aligned = ResizeArray<Parameter * TypeExpr>()
            let mutable success = true

            for parameter in parameters do
                match tryParseParameterType parameter with
                | Some parameterLayoutType when isCompileTimeArgumentType environment.VisibleTypeAliases parameterLayoutType ->
                    aligned.Add(parameter, parameterLayoutType)

                    match !remaining with
                    | parameterType :: rest
                        when TypeSignatures.definitionallyEqual
                                 (normalizeTypeAliases environment.VisibleTypeAliases parameterLayoutType)
                                 (normalizeTypeAliases environment.VisibleTypeAliases parameterType) ->
                        remaining := rest
                    | _ ->
                        ()
                | Some parameterLayoutType
                    when parameter.IsImplicit
                         && (tryTraitConstraintFromType environment parameterLayoutType |> Option.isSome) ->
                    aligned.Add(parameter, parameterLayoutType)

                    match !remaining with
                    | parameterType :: rest
                        when semanticallyMatchesTraitConstraintType environment parameterLayoutType parameterType ->
                        remaining := rest
                    | _ ->
                        ()
                | _ ->
                    match !remaining with
                    | parameterType :: rest ->
                        aligned.Add(parameter, parameterType)
                        remaining := rest
                    | [] ->
                        success <- false

            if success && aligned.Count = parameters.Length then
                Some(List.ofSeq aligned)
            else
                None

        match tryAlignParameterTypesWithParameters () with
        | Some alignedParameters ->
            alignedParameters
            |> List.fold (fun state (parameter, parameterType) ->
                if parameter.IsImplicit && not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType) then
                    match tryTraitConstraintFromType environment parameterType with
                    | Some constraintInfo ->
                        reachableTraitConstraints environment constraintInfo
                        |> List.fold (fun current reachableConstraint ->
                            tryResolveTraitInfoByReference environment reachableConstraint.Trait
                            |> Option.map (fun traitInfo ->
                                traitInfo.Members
                                |> Map.toList
                                |> List.fold (fun innerState (memberName, _) ->
                                    if Map.containsKey memberName innerState then
                                        innerState
                                    else
                                        Map.add memberName (traitConstraintRuntimeName reachableConstraint, parameter.Name) innerState) current)
                            |> Option.defaultValue current) state
                    | None ->
                        state
                else
                    state) Map.empty
        | _ ->
            Map.empty

    let private buildParameterConstraintDictionaries
        (environment: BindingLoweringEnvironment)
        (scheme: TypeScheme)
        (parameters: Parameter list)
        =
        let tryAlignParameterTypesWithParameters () =
            let parameterTypes, _ = TypeSignatures.schemeParts scheme
            let remaining = ref parameterTypes
            let aligned = ResizeArray<Parameter * TypeExpr>()
            let mutable success = true

            for parameter in parameters do
                match tryParseParameterType parameter with
                | Some parameterLayoutType when isCompileTimeArgumentType environment.VisibleTypeAliases parameterLayoutType ->
                    aligned.Add(parameter, parameterLayoutType)

                    match !remaining with
                    | parameterType :: rest
                        when TypeSignatures.definitionallyEqual
                                 (normalizeTypeAliases environment.VisibleTypeAliases parameterLayoutType)
                                 (normalizeTypeAliases environment.VisibleTypeAliases parameterType) ->
                        remaining := rest
                    | _ ->
                        ()
                | Some parameterLayoutType
                    when parameter.IsImplicit
                         && (tryTraitConstraintFromType environment parameterLayoutType |> Option.isSome) ->
                    aligned.Add(parameter, parameterLayoutType)

                    match !remaining with
                    | parameterType :: rest
                        when semanticallyMatchesTraitConstraintType environment parameterLayoutType parameterType ->
                        remaining := rest
                    | _ ->
                        ()
                | _ ->
                    match !remaining with
                    | parameterType :: rest ->
                        aligned.Add(parameter, parameterType)
                        remaining := rest
                    | [] ->
                        success <- false

            if success && aligned.Count = parameters.Length then
                Some(List.ofSeq aligned)
            else
                None

        match tryAlignParameterTypesWithParameters () with
        | Some alignedParameters ->
            alignedParameters
            |> List.fold (fun state (parameter, parameterType) ->
                if parameter.IsImplicit && not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType) then
                    match tryTraitConstraintFromType environment parameterType with
                    | Some constraintInfo ->
                        addReachableConstraintDictionary environment constraintInfo (KCoreName [ parameter.Name ]) state
                    | None ->
                        state
                else
                    state) Map.empty
        | _ ->
            Map.empty

    let private buildParameterConstraintLocalTypes
        (environment: BindingLoweringEnvironment)
        (scheme: TypeScheme)
        (parameters: Parameter list)
        =
        let parameterTypes, _ = TypeSignatures.schemeParts scheme
        let remaining = ref parameterTypes
        let aligned = ResizeArray<string * TypeExpr>()
        let mutable success = true

        for parameter in parameters do
            match tryParseParameterType parameter with
            | Some parameterLayoutType when isCompileTimeArgumentType environment.VisibleTypeAliases parameterLayoutType ->
                if parameter.IsImplicit then
                    match tryTraitConstraintFromType environment parameterLayoutType with
                    | Some _ ->
                        aligned.Add(parameter.Name, parameterLayoutType)
                    | None ->
                        ()

                match !remaining with
                | parameterType :: rest
                    when TypeSignatures.definitionallyEqual
                             (normalizeTypeAliases environment.VisibleTypeAliases parameterLayoutType)
                             (normalizeTypeAliases environment.VisibleTypeAliases parameterType) ->
                    remaining := rest
                | _ ->
                    ()
            | Some parameterLayoutType
                when parameter.IsImplicit
                     && (tryTraitConstraintFromType environment parameterLayoutType |> Option.isSome) ->
                aligned.Add(parameter.Name, parameterLayoutType)

                match !remaining with
                | parameterType :: rest
                    when semanticallyMatchesTraitConstraintType environment parameterLayoutType parameterType ->
                    remaining := rest
                | _ ->
                    ()
            | _ ->
                match !remaining with
                | _ :: rest ->
                    remaining := rest
                | [] ->
                    success <- false

        if success then
            List.ofSeq aligned
        else
            []

    let private renderTraitConstraint (environment: BindingLoweringEnvironment) (constraintInfo: TraitConstraint) =
        let normalizedArguments =
            constraintInfo.Arguments
            |> List.map (normalizeTypeAliases environment.VisibleTypeAliases >> TypeSignatures.toText)
            |> String.concat ", "

        if String.IsNullOrWhiteSpace normalizedArguments then
            traitConstraintText constraintInfo
        else
            $"{traitConstraintText constraintInfo} {normalizedArguments}"

    let private renderInstanceCandidate (instanceInfo: InstanceInfo) =
        let headArguments =
            instanceInfo.HeadTypes
            |> List.map TypeSignatures.toText
            |> String.concat ", "

        let headText =
            if String.IsNullOrWhiteSpace headArguments then
                traitReferenceCanonicalName instanceInfo.Trait
            else
                $"{traitReferenceCanonicalName instanceInfo.Trait} {headArguments}"

        $"{ModuleIdentity.text instanceInfo.ModuleIdentity}:{headText}"

    let private matchesBuiltinNumericTarget
        (aliases: Map<string, TypeAliasInfo>)
        literal
        expectedType
        =
        let isIntegerLiteral =
            match literal with
            | SurfaceIntegerLiteral _ -> true
            | _ -> false

        let isRealLiteral =
            match literal with
            | SurfaceRealLiteral _ -> true
            | _ -> false

        match normalizeTypeAliases aliases expectedType with
        | TypeName(nameSegments, [])
            when isIntegerLiteral
                 && (matchesKnownType CompilerKnownSymbols.IntType nameSegments
                     || matchesKnownType CompilerKnownSymbols.IntegerType nameSegments
                     || matchesKnownType CompilerKnownSymbols.NatType nameSegments) ->
            true
        | TypeName(nameSegments, [])
            when isRealLiteral
                 && (matchesKnownType CompilerKnownSymbols.FloatType nameSegments
                     || matchesKnownType CompilerKnownSymbols.DoubleType nameSegments
                     || matchesKnownType CompilerKnownSymbols.RealType nameSegments) ->
            true
        | _ ->
            false

    let private numericLiteralConstraintName literal =
        match literal with
        | SurfaceIntegerLiteral _ -> "FromInteger"
        | SurfaceRealLiteral _ -> "FromFloat"

    let private tryResolveNumericStaticObjectTarget
        (environment: BindingLoweringEnvironment)
        expectedType
        =
        let rec loop visited current =
            let normalizedCurrent =
                normalizeTypeAliases environment.VisibleTypeAliases current

            let candidateKey = TypeSignatures.toText normalizedCurrent

            if Set.contains candidateKey visited then
                None
            else
                let visited = Set.add candidateKey visited

                match normalizedCurrent with
                | TypeName(nameSegments, []) ->
                    tryFindVisibleStaticObject environment nameSegments
                    |> Option.bind (fun staticObject ->
                        match staticObject.ObjectKind with
                        | TypeObject ->
                            loop visited (TypeName(staticObject.NameSegments, []))
                        | _ ->
                            None)
                    |> Option.orElseWith (fun () ->
                        if Set.isEmpty visited then
                            None
                        else
                            Some normalizedCurrent)
                | _ ->
                    if Set.isEmpty visited then
                        None
                    else
                        Some normalizedCurrent

        loop Set.empty expectedType

    let private tryResolveNumericLiteralContext
        (environment: BindingLoweringEnvironment)
        expectedType
        literal
        =
        let candidateTypes =
            expectedType
            :: (tryResolveNumericStaticObjectTarget environment expectedType |> Option.toList)

        let tryResolveAgainstTarget targetType =
            let normalizedTargetType =
                normalizeTypeAliases environment.VisibleTypeAliases targetType

            if isCompileTimeArgumentType environment.VisibleTypeAliases normalizedTargetType then
                None
            elif matchesBuiltinNumericTarget environment.VisibleTypeAliases literal normalizedTargetType then
                Some(expectedType, None)
            else
                let constraintInfo =
                    unqualifiedTraitConstraint (numericLiteralConstraintName literal) [ normalizedTargetType ]

                resolveConstraintInstance environment constraintInfo
                |> Option.map (fun instanceInfo -> expectedType, Some instanceInfo)

        candidateTypes
        |> List.tryPick tryResolveAgainstTarget

    let private tryInferNumericLiteralTypeFromContext
        (environment: BindingLoweringEnvironment)
        expectedType
        literal
        =
        tryResolveNumericLiteralContext environment expectedType literal
        |> Option.map fst

    let private tryInferNumericExpressionTypeFromContext
        (environment: BindingLoweringEnvironment)
        expectedType
        expression
        =
        match expression with
        | NumericLiteral literal ->
            tryInferNumericLiteralTypeFromContext environment expectedType literal
        | Unary("-", NumericLiteral literal) ->
            tryInferNumericLiteralTypeFromContext environment expectedType literal
        | _ ->
            None

    let private tryLowerNumericLiteralForRuntime literal =
        match literal with
        | SurfaceIntegerLiteral(value, _, _) when value >= BigInteger(Int64.MinValue) && value <= BigInteger(Int64.MaxValue) ->
            Some(KCoreLiteral(LiteralValue.Integer(int64 value)))
        | SurfaceRealLiteral(_, text, _) ->
            match Double.TryParse(text, Globalization.NumberStyles.Float, Globalization.CultureInfo.InvariantCulture) with
            | true, value ->
                Some(KCoreLiteral(LiteralValue.Float value))
            | _ ->
                None
        | _ ->
            None

    let private tryLowerNumericExpressionForRuntime expression =
        match expression with
        | NumericLiteral literal ->
            tryLowerNumericLiteralForRuntime literal
        | Unary("-", NumericLiteral(SurfaceIntegerLiteral(value, text, suffix))) ->
            tryLowerNumericLiteralForRuntime (SurfaceIntegerLiteral(-value, "-" + text, suffix))
        | Unary("-", NumericLiteral(SurfaceRealLiteral(decimalValue, text, suffix))) ->
            tryLowerNumericLiteralForRuntime (SurfaceRealLiteral(decimalValue |> Option.map (~-), "-" + text, suffix))
        | _ ->
            None

    let private trySynthesizeImplicitArgument
        (environment: BindingLoweringEnvironment)
        (tryResolveLocalImplicit: TypeExpr -> KCoreExpression option)
        parameterType
        =
        match tryResolveLocalImplicit parameterType with
        | Some implicitArgument ->
            Some implicitArgument
        | None ->
            tryLowerCompilerIssuedTraitEvidence environment parameterType
            |> Option.orElseWith (fun () ->
            tryTraitConstraintFromType environment parameterType
            |> Option.bind (tryLowerResolvedDictionaryValue environment))

    let private noLocalImplicit (_: TypeExpr) : KCoreExpression option =
        None

    type private LocalImplicitResolution =
        | NoLocalImplicitCandidate
        | UniqueLocalImplicitCandidate of KCoreExpression
        | AmbiguousLocalImplicitCandidates

    let private classifyLocalImplicitByType
        (environment: BindingLoweringEnvironment)
        (localTypes: Map<string, TypeExpr>)
        parameterType
        =
        let tryDecodeImplicitLocalName (name: string) =
            let implicitPrefix = "__kappa_implicit_"
            let dictionaryPrefix = "__kappa_dict_"

            if name.StartsWith(implicitPrefix, StringComparison.Ordinal) then
                Some(name.Substring(implicitPrefix.Length))
            elif name.StartsWith(dictionaryPrefix, StringComparison.Ordinal) then
                Some name
            else
                None

        let normalizeVisible currentType =
            currentType
            |> qualifyVisibleTypeNames environment
            |> normalizeTypeAliases environment.VisibleTypeAliases

        let normalizedGoal =
            normalizeVisible parameterType

        let matches =
            localTypes
            |> Map.toList
            |> List.choose (fun (name, localType) ->
                tryDecodeImplicitLocalName name
                |> Option.filter (fun _ ->
                    TypeSignatures.definitionallyEqual
                        (normalizeVisible localType)
                        normalizedGoal)
                |> Option.map (fun actualName -> actualName, localType))

        match matches with
        | [ name, _ ] ->
            UniqueLocalImplicitCandidate(KCoreName [ name ])
        | _ :: _ ->
            AmbiguousLocalImplicitCandidates
        | [] ->
            match tryTraitConstraintFromType environment parameterType with
            | Some goalConstraint ->
                let implicitConstraintLocals =
                    localTypes
                    |> Map.toList
                    |> List.choose (fun (name, localType) ->
                        tryDecodeImplicitLocalName name
                        |> Option.map (fun actualName -> actualName, localType))
                    |> Map.ofList

                let projectedMatches =
                    localTraitConstraints environment implicitConstraintLocals
                    |> List.filter (fun (_, localConstraint: TraitConstraint) ->
                        reachableTraitConstraints environment localConstraint
                        |> List.exists (fun (reachableConstraint: TraitConstraint) ->
                            traitReferenceSegments reachableConstraint.Trait = traitReferenceSegments goalConstraint.Trait
                            && List.length reachableConstraint.Arguments = List.length goalConstraint.Arguments
                            && List.forall2
                                (fun left right ->
                                    TypeSignatures.definitionallyEqual
                                        (normalizeTypeAliases environment.VisibleTypeAliases left)
                                        (normalizeTypeAliases environment.VisibleTypeAliases right))
                                reachableConstraint.Arguments
                                goalConstraint.Arguments))

                match projectedMatches with
                | [ name, _ ] ->
                    UniqueLocalImplicitCandidate(KCoreName [ name ])
                | _ :: _ ->
                    AmbiguousLocalImplicitCandidates
                | [] ->
                    NoLocalImplicitCandidate
            | None ->
                NoLocalImplicitCandidate

    let private tryResolveUniqueLocalImplicitByType
        (environment: BindingLoweringEnvironment)
        (localTypes: Map<string, TypeExpr>)
        parameterType
        =
        match classifyLocalImplicitByType environment localTypes parameterType with
        | UniqueLocalImplicitCandidate candidate ->
            Some candidate
        | NoLocalImplicitCandidate
        | AmbiguousLocalImplicitCandidates ->
            None

    let private tryResolveUniqueLocalImplicitByTypeWithSubstitution
        (environment: BindingLoweringEnvironment)
        (localTypes: Map<string, TypeExpr>)
        substitution
        parameterType
        =
        let substitutedLocalTypes =
            localTypes
            |> Map.map (fun _ localType -> TypeSignatures.applySubstitution substitution localType)

        let substitutedParameterType =
            TypeSignatures.applySubstitution substitution parameterType

        tryResolveUniqueLocalImplicitByType environment substitutedLocalTypes substitutedParameterType

    let private tryAlignParameterTypesWithLayouts
        (environment: BindingLoweringEnvironment)
        (layoutTypeSubstitution: Map<string, TypeExpr>)
        (layouts: Parameter list)
        (parameterTypes: TypeExpr list)
        =
        let remaining = ref parameterTypes
        let aligned = ResizeArray<TypeExpr>()
        let mutable success = true

        for layout in layouts do
            match tryParseParameterTypeWithSubstitution layoutTypeSubstitution layout with
            | Some layoutType when isCompileTimeArgumentType environment.VisibleTypeAliases layoutType ->
                aligned.Add(layoutType)

                match !remaining with
                | parameterType :: rest
                    when TypeSignatures.definitionallyEqual
                             (normalizeTypeAliases environment.VisibleTypeAliases layoutType)
                             (normalizeTypeAliases environment.VisibleTypeAliases parameterType) ->
                    remaining := rest
                | _ ->
                    ()
            | Some layoutType
                when layout.IsImplicit
                     && (tryTraitConstraintFromType environment layoutType |> Option.isSome) ->
                aligned.Add(layoutType)
                match !remaining with
                | parameterType :: rest
                    when semanticallyMatchesTraitConstraintType environment layoutType parameterType ->
                    remaining := rest
                | _ ->
                    ()
            | _ ->
                match !remaining with
                | parameterType :: rest ->
                    aligned.Add(parameterType)
                    remaining := rest
                | [] ->
                    success <- false

        if success then
            Some(List.ofSeq aligned, List.ofSeq !remaining)
        else
            None

    type private ParameterAlignmentSlot =
        { Layout: Parameter option
          ParameterType: TypeExpr }

    let private tryBuildParameterAlignmentSlots
        (environment: BindingLoweringEnvironment)
        (layoutTypeSubstitution: Map<string, TypeExpr>)
        (layouts: Parameter list)
        (parameterTypes: TypeExpr list)
        =
        let slots = ResizeArray<ParameterAlignmentSlot>()
        let mutable remaining = parameterTypes
        let mutable success = true

        let consumeFirst remaining =
            match remaining with
            | head :: rest -> Some(head, rest)
            | [] -> None

        let tryFindDeclaredTypeMatch layoutType remaining =
            remaining
            |> List.tryFindIndex (fun parameterType ->
                TypeSignatures.definitionallyEqual
                    (normalizeTypeAliases environment.VisibleTypeAliases layoutType)
                    (normalizeTypeAliases environment.VisibleTypeAliases parameterType))

        for layout in layouts do
            match tryParseParameterTypeWithSubstitution layoutTypeSubstitution layout with
            | Some layoutType when isCompileTimeArgumentType environment.VisibleTypeAliases layoutType ->
                slots.Add(
                    { Layout = Some layout
                      ParameterType = layoutType }
                )

                match remaining with
                | parameterType :: rest
                    when TypeSignatures.definitionallyEqual
                             (normalizeTypeAliases environment.VisibleTypeAliases layoutType)
                             (normalizeTypeAliases environment.VisibleTypeAliases parameterType) ->
                    remaining <- rest
                | _ ->
                    ()
            | Some layoutType
                when layout.IsImplicit
                     && (tryTraitConstraintFromType environment layoutType |> Option.isSome) ->
                slots.Add(
                    { Layout = Some layout
                      ParameterType = layoutType }
                )

                match remaining with
                | parameterType :: rest when semanticallyMatchesTraitConstraintType environment layoutType parameterType ->
                    remaining <- rest
                | _ ->
                    ()
            | Some layoutType ->
                match tryFindDeclaredTypeMatch layoutType remaining with
                | Some matchIndex when matchIndex > 0 ->
                    let hiddenLeading = remaining |> List.take matchIndex
                    let matchedParameterType = remaining[matchIndex]
                    let rest = remaining |> List.skip (matchIndex + 1)

                    hiddenLeading
                    |> List.iter (fun parameterType ->
                        slots.Add(
                            { Layout = None
                              ParameterType = parameterType }
                        ))

                    slots.Add(
                        { Layout = Some layout
                          ParameterType = matchedParameterType }
                    )

                    remaining <- rest
                | Some _ ->
                    match consumeFirst remaining with
                    | Some(parameterType, rest) ->
                        slots.Add(
                            { Layout = Some layout
                              ParameterType = parameterType }
                        )

                        remaining <- rest
                    | None ->
                        success <- false
                | None ->
                    match consumeFirst remaining with
                    | Some(parameterType, rest) ->
                        slots.Add(
                            { Layout = Some layout
                              ParameterType = parameterType }
                        )

                        remaining <- rest
                    | None ->
                        success <- false
            | None ->
                match consumeFirst remaining with
                | Some(parameterType, rest) ->
                    slots.Add(
                        { Layout = Some layout
                          ParameterType = parameterType }
                    )

                    remaining <- rest
                | None ->
                    success <- false

        remaining
        |> List.iter (fun parameterType ->
            slots.Add(
                { Layout = None
                  ParameterType = parameterType }
            ))

        if success then
            Some(List.ofSeq slots)
        else
            None

    let rec private tryPrepareVisibleBindingCall
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (bindingInfo: BindingSchemeInfo)
        (localImplicitTypes: Map<string, TypeExpr> option)
        (inferArgumentType: SurfaceExpression -> TypeExpr option)
        (tryResolveLocalImplicit: TypeExpr -> KCoreExpression option)
        (arguments: SurfaceExpression list)
        =
        let rec tryInferConstructorExpressionType argument =
            let tryPrepareConstructorCall constructorName constructorArguments =
                environment.VisibleConstructors
                |> Map.tryFind constructorName
                |> Option.bind (fun constructorInfo ->
                    tryPrepareVisibleBindingCall
                        environment
                        freshCounter
                        constructorInfo
                        localImplicitTypes
                        inferArgumentType
                        tryResolveLocalImplicit
                        constructorArguments
                    |> Option.map (fun preparedCall -> preparedCall.ResultType))

            match argument with
            | Name [ constructorName ] ->
                tryPrepareConstructorCall constructorName []
            | Apply(Name [ constructorName ], constructorArguments) ->
                tryPrepareConstructorCall constructorName constructorArguments
            | Seal(inner, _) ->
                tryInferConstructorExpressionType inner
            | ExplicitImplicitArgument inner
            | InoutArgument inner ->
                tryInferConstructorExpressionType inner
            | _ ->
                None

        let inferArgumentTypeForParameter parameterType argument =
            tryInferNumericExpressionTypeFromContext environment parameterType argument
            |> Option.orElseWith (fun () -> inferArgumentType argument)
            |> Option.orElseWith (fun () -> tryInferConstructorExpressionType argument)

        let rec tryParseVisibleTypeLikeArgument expression =
            match expression with
            | Name [ name ] ->
                match inferArgumentType expression with
                | Some inferredType when isCompileTimeArgumentType environment.VisibleTypeAliases inferredType ->
                    Some(TypeVariable name)
                | _ ->
                    Some(TypeName([ name ], []))
            | Name segments when not (List.isEmpty segments) ->
                Some(TypeName(segments, []))
            | NumericLiteral(SurfaceIntegerLiteral(value, _, None)) when value = 0I || value = 1I ->
                Some(TypeName([ value.ToString() ], []))
            | Apply(head, arguments) ->
                match
                    tryParseVisibleTypeLikeArgument head,
                    arguments |> List.map tryParseVisibleTypeLikeArgument
                with
                | Some(TypeName(name, existingArguments)), parsedArguments
                    when parsedArguments |> List.forall Option.isSome ->
                    Some(TypeName(name, existingArguments @ (parsedArguments |> List.choose id)))
                | _ ->
                    None
            | ExplicitImplicitArgument inner ->
                tryParseVisibleTypeLikeArgument inner
            | _ ->
                None

        let isLeadingCompileTimeApplicationArgument argument =
            match argument with
            | ExplicitImplicitArgument explicitArgument ->
                tryParseVisibleTypeLikeArgument explicitArgument |> Option.isSome
            | _ ->
                inferArgumentType argument
                |> Option.exists (isCompileTimeArgumentType environment.VisibleTypeAliases)

        let instantiated = TypeSignatures.instantiate "t" freshCounter.Value bindingInfo.Scheme
        freshCounter.Value <- freshCounter.Value + instantiated.Forall.Length

        let rec consumeCompileTimeApplications
            (remainingForall: TypeSignatures.ForallBinder list)
            (remainingArguments: SurfaceExpression list)
            substitution
            =
            match remainingForall, remainingArguments with
            | binder :: restForall, ExplicitImplicitArgument explicitArgument :: restArguments ->
                match tryParseVisibleTypeLikeArgument explicitArgument with
                | Some explicitTypeArgument ->
                    consumeCompileTimeApplications
                        restForall
                        restArguments
                        (composeTypeSubstitution substitution (Map.ofList [ binder.Name, explicitTypeArgument ]))
                | None ->
                    None
            | _, _ ->
                Some(substitution, remainingArguments)

        let explicitTypeApplicationsValid, instantiated, arguments =
            match consumeCompileTimeApplications instantiated.Forall arguments Map.empty with
            | Some(substitution, remainingArguments) ->
                true,
                TypeSignatures.applySchemeSubstitution substitution instantiated,
                remainingArguments
            | None ->
                false,
                instantiated,
                arguments

        let normalizedParameterLayouts =
            normalizedVisibleBindingParameterLayouts bindingInfo instantiated
            |> Option.orElse bindingInfo.ParameterLayouts
        let layoutTypeSubstitution = forallInstantiationSubstitution bindingInfo.Scheme instantiated

        let debugVisibleBindingCall _ = ()

        let hasApplicationOnlyArgument arguments =
            arguments
            |> List.exists (function
                | ExplicitImplicitArgument _
                | NamedApplicationBlock _ -> true
                | _ -> false)

        let hasDefaultArgument (parameterLayout: Parameter) =
            bindingInfo.DefaultArguments.ContainsKey(parameterLayout.Name)

        let tryResolveCurrentLocalImplicit substitution parameterType =
            match localImplicitTypes with
            | Some localTypes ->
                tryResolveUniqueLocalImplicitByTypeWithSubstitution
                    environment
                    localTypes
                    substitution
                    parameterType
            | None ->
                tryResolveLocalImplicit parameterType

        let tryPrepareSchemeOnlyCall instantiated arguments =
            let trySynthesizeSchemeOnlyImplicit substitution parameterType =
                trySynthesizeImplicitArgument
                    environment
                    (tryResolveCurrentLocalImplicit substitution)
                    parameterType
            let schemeParameterTypes, _ = TypeSignatures.schemeParts instantiated
            let maxLeadingImplicitCount = List.length schemeParameterTypes - List.length arguments

            if maxLeadingImplicitCount < 0 then
                None
            else
                let tryCandidate leadingImplicitCount =
                    let leadingImplicitTypes =
                        schemeParameterTypes |> List.take leadingImplicitCount

                    let remainingParameterTypes =
                        schemeParameterTypes |> List.skip leadingImplicitCount

                    let explicitParameterTypes =
                        remainingParameterTypes |> List.truncate arguments.Length

                    let trailingParameterTypes =
                        remainingParameterTypes |> List.skip arguments.Length

                    if List.length explicitParameterTypes <> List.length arguments then
                        None
                    else
                        let explicitArgumentTypes =
                            List.zip explicitParameterTypes arguments
                            |> List.map (fun (parameterType, argument) ->
                                inferArgumentTypeForParameter parameterType argument)

                        if explicitArgumentTypes |> List.exists Option.isNone then
                            None
                        else
                            let explicitArgumentTypes = explicitArgumentTypes |> List.choose id

                            tryUnifyVisibleTypes
                                environment.VisibleTypeAliases
                                (List.zip explicitParameterTypes explicitArgumentTypes)
                            |> Option.bind (fun explicitSubstitution ->
                                let instantiatedScheme =
                                    TypeSignatures.applySchemeSubstitution explicitSubstitution instantiated

                                let substitutedLeadingImplicitTypes =
                                    leadingImplicitTypes
                                    |> List.map (TypeSignatures.applySubstitution explicitSubstitution)

                                let substitutedTrailingParameterTypes =
                                    trailingParameterTypes
                                    |> List.map (TypeSignatures.applySubstitution explicitSubstitution)

                                let rec synthesizeLeadingImplicits
                                    pendingImplicitTypes
                                    synthesizedArguments
                                    synthesizedTypes
                                    =
                                    match pendingImplicitTypes with
                                    | [] ->
                                        Some(List.rev synthesizedArguments, List.rev synthesizedTypes)
                                    | parameterType :: rest ->
                                        match trySynthesizeSchemeOnlyImplicit explicitSubstitution parameterType with
                                        | Some implicitArgument ->
                                            synthesizeLeadingImplicits
                                                rest
                                                (ImplicitArgument implicitArgument :: synthesizedArguments)
                                                (parameterType :: synthesizedTypes)
                                        | None ->
                                            None

                                synthesizeLeadingImplicits
                                    substitutedLeadingImplicitTypes
                                    []
                                    []
                                |> Option.map (fun (implicitArguments, implicitArgumentTypes) ->
                                    let _, substitutedResultType = TypeSignatures.schemeParts instantiatedScheme

                                    let appliedResultType =
                                        substitutedTrailingParameterTypes
                                        |> List.rev
                                        |> List.fold
                                            (fun current parameterType ->
                                                TypeArrow(QuantityOmega, parameterType, current))
                                            substitutedResultType

                                    { InstantiatedScheme = instantiatedScheme
                                      ResultType = appliedResultType
                                      Parameters = []
                                      Arguments = implicitArguments @ (arguments |> List.map ExplicitArgument) }))

                [ maxLeadingImplicitCount .. -1 .. 0 ]
                |> List.tryPick tryCandidate

        match normalizedParameterLayouts with
        | None ->
            debugVisibleBindingCall "no normalized parameter layouts"
            if (not explicitTypeApplicationsValid) || hasApplicationOnlyArgument arguments then
                None
            else
                tryPrepareSchemeOnlyCall instantiated arguments
        | Some parameterLayouts when List.isEmpty parameterLayouts ->
            debugVisibleBindingCall "empty normalized parameter layouts"
            if (not explicitTypeApplicationsValid) || hasApplicationOnlyArgument arguments then
                None
            else
                tryPrepareSchemeOnlyCall instantiated arguments
        | Some parameterLayouts ->
            debugVisibleBindingCall $"parameter layouts = {parameterLayouts.Length}; scheme constraints = {instantiated.Constraints.Length}"
            if not explicitTypeApplicationsValid then
                None
            else
                let schemeParameterTypes, resultType = TypeSignatures.schemeParts instantiated
                let sourceForallNames =
                    bindingInfo.Scheme.Forall |> List.map (fun binder -> binder.Name) |> String.concat ","
                let instantiatedForallNames =
                    instantiated.Forall |> List.map (fun binder -> binder.Name) |> String.concat ","

                debugVisibleBindingCall
                    $"scheme forall = {sourceForallNames}; instantiated forall = {instantiatedForallNames}; layout substitution size = {layoutTypeSubstitution.Count}"

                match
                    tryAlignParameterTypesWithLayouts
                        environment
                        layoutTypeSubstitution
                        parameterLayouts
                        schemeParameterTypes
                with
                | None ->
                    None
                | Some(parameterTypes, trailingParameterTypes) ->
                    let alignedParameterTypeText =
                        parameterTypes
                        |> List.map TypeSignatures.toText
                        |> String.concat "; "

                    debugVisibleBindingCall
                        $"aligned parameter types = {alignedParameterTypeText}"
                    let splitNamedBlock (arguments: SurfaceExpression list) =
                        let indexedNamedBlocks =
                            arguments
                            |> List.mapi (fun index argument ->
                                match argument with
                                | NamedApplicationBlock fields -> Some(index, fields)
                                | _ -> None)
                            |> List.choose id

                        match indexedNamedBlocks with
                        | [] ->
                            Some(arguments, None)
                        | [ index, fields ] when index = List.length arguments - 1 ->
                            Some(arguments |> List.take index, Some fields)
                        | _ ->
                            None

                    match splitNamedBlock arguments with
                    | None ->
                        debugVisibleBindingCall "splitNamedBlock failed"
                        None
                    | Some(positionalArguments, namedFields) ->
                        let tryPrepareLeadingRuntimeImplicits
                            (layouts: Parameter list)
                            (types: TypeExpr list)
                            (positionalArguments: SurfaceExpression list)
                            =
                            if
                                List.isEmpty positionalArguments
                                || (positionalArguments
                                    |> List.exists (function
                                        | ExplicitImplicitArgument _ -> true
                                        | _ -> false))
                            then
                                None
                            else
                                let rec splitLeading
                                    (pendingLayouts: Parameter list)
                                    (pendingTypes: TypeExpr list)
                                    (consumedLeading: (Parameter * TypeExpr) list)
                                    =
                                    match pendingLayouts, pendingTypes with
                                    | layout :: restLayouts, parameterType :: restTypes
                                        when layout.IsImplicit
                                             && not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType) ->
                                        splitLeading restLayouts restTypes ((layout, parameterType) :: consumedLeading)
                                    | _ ->
                                        List.rev consumedLeading, pendingLayouts, pendingTypes

                                let (leadingImplicits: (Parameter * TypeExpr) list), (remainingLayouts: Parameter list), (remainingTypes: TypeExpr list) =
                                    splitLeading layouts types []

                                let rec collectExplicitParameterTypes
                                    (pendingLayouts: Parameter list)
                                    (pendingTypes: TypeExpr list)
                                    (pendingArguments: SurfaceExpression list)
                                    (explicitParameterTypes: TypeExpr list)
                                    =
                                    match pendingArguments with
                                    | [] ->
                                        Some(List.rev explicitParameterTypes)
                                    | _ ->
                                        match pendingLayouts, pendingTypes with
                                        | layout :: restLayouts, parameterType :: restTypes
                                            when isCompileTimeArgumentType environment.VisibleTypeAliases parameterType ->
                                            None
                                        | layout :: restLayouts, parameterType :: restTypes
                                            when layout.IsImplicit ->
                                            collectExplicitParameterTypes restLayouts restTypes pendingArguments explicitParameterTypes
                                        | _ :: restLayouts, parameterType :: restTypes ->
                                            match pendingArguments with
                                            | _ :: restArguments ->
                                                collectExplicitParameterTypes
                                                    restLayouts
                                                    restTypes
                                                    restArguments
                                                    (parameterType :: explicitParameterTypes)
                                            | [] ->
                                                Some(List.rev explicitParameterTypes)
                                        | _ ->
                                            None

                                collectExplicitParameterTypes remainingLayouts remainingTypes positionalArguments []
                                |> Option.bind (fun explicitParameterTypes ->
                                    debugVisibleBindingCall $"leading implicits = {leadingImplicits.Length}; explicit parameter types = {explicitParameterTypes.Length}; positional arguments = {positionalArguments.Length}"
                                    if List.isEmpty leadingImplicits then
                                        None
                                    elif List.length explicitParameterTypes <> List.length positionalArguments then
                                        None
                                    else
                                        let explicitArgumentTypes =
                                            List.zip explicitParameterTypes positionalArguments
                                            |> List.map (fun (parameterType, argument) ->
                                                inferArgumentTypeForParameter parameterType argument)

                                        if explicitArgumentTypes |> List.exists Option.isNone then
                                            debugVisibleBindingCall "explicit argument types contained None during leading implicit prep"
                                            None
                                        else
                                            let explicitArgumentTypes = explicitArgumentTypes |> List.choose id
                                            let explicitArgumentTypeText =
                                                explicitArgumentTypes
                                                |> List.map TypeSignatures.toText
                                                |> String.concat "; "
                                            let explicitParameterTypeText =
                                                explicitParameterTypes
                                                |> List.map TypeSignatures.toText
                                                |> String.concat "; "
                                            debugVisibleBindingCall
                                                $"explicit argument types = {explicitArgumentTypeText}; explicit parameter types = {explicitParameterTypeText}"

                                            tryUnifyVisibleTypes
                                                environment.VisibleTypeAliases
                                                (List.zip explicitParameterTypes explicitArgumentTypes)
                                            |> function
                                                | None ->
                                                    debugVisibleBindingCall "unification for leading implicit prep failed"
                                                    None
                                                | Some initialSubstitution ->
                                                    debugVisibleBindingCall $"initial substitution size = {initialSubstitution.Count}"
                                                    let rec synthesize
                                                        (pendingImplicits: (Parameter * TypeExpr) list)
                                                        (preparedArguments: PreparedCallArgument list)
                                                        (preparedParameters: PreparedCallParameter list)
                                                        =
                                                        match pendingImplicits with
                                                        | [] ->
                                                            Some(List.rev preparedArguments, List.rev preparedParameters)
                                                        | (layout, rawParameterType) :: rest ->
                                                            let parameterType =
                                                                TypeSignatures.applySubstitution initialSubstitution rawParameterType

                                                            match
                                                                trySynthesizeImplicitArgument
                                                                    environment
                                                                    (tryResolveCurrentLocalImplicit initialSubstitution)
                                                                    parameterType
                                                            with
                                                            | Some implicitArgument ->
                                                                debugVisibleBindingCall $"synthesized leading implicit {layout.Name} : {TypeSignatures.toText parameterType}"
                                                                synthesize
                                                                    rest
                                                                    (ImplicitArgument implicitArgument :: preparedArguments)
                                                                    ({ Layout = Some layout
                                                                       ParameterType = parameterType
                                                                       AssignedArgument = Some(ImplicitArgument implicitArgument) }
                                                                     :: preparedParameters)
                                                            | None ->
                                                                debugVisibleBindingCall $"failed to synthesize leading implicit {layout.Name} : {TypeSignatures.toText parameterType}"
                                                                None

                                                    synthesize leadingImplicits [] []
                                                    |> Option.map (fun (preparedImplicitArguments, preparedImplicitParameters) ->
                                                        preparedImplicitArguments,
                                                        preparedImplicitParameters,
                                                        initialSubstitution,
                                                        remainingLayouts,
                                                        remainingTypes))

                        let (initialPreparedArguments: PreparedCallArgument list), (initialPreparedParameters: PreparedCallParameter list), initialSubstitution, (parameterLayoutsToProcess: Parameter list), (parameterTypesToProcess: TypeExpr list) =
                            match tryPrepareLeadingRuntimeImplicits parameterLayouts parameterTypes positionalArguments with
                            | Some(preparedImplicitArguments, preparedImplicitParameters, initialSubstitution, remainingLayouts, remainingTypes) ->
                                preparedImplicitArguments,
                                preparedImplicitParameters,
                                initialSubstitution,
                                remainingLayouts,
                                remainingTypes
                            | None ->
                                [],
                                [],
                                Map.empty,
                                parameterLayouts,
                                parameterTypes

                        let mutable remainingArguments = positionalArguments
                        let mutable substitution = initialSubstitution
                        let preparedArguments = ResizeArray<PreparedCallArgument>(initialPreparedArguments)
                        let preparedParameters = ResizeArray<PreparedCallParameter>(initialPreparedParameters)
                        let remainingParameters = ResizeArray<Parameter * TypeExpr>()
                        let mutable usedNamedFields = Set.empty<string>
                        let mutable success = true
                        let mutable stoppedAtPartialApplication = false

                        let namedFieldCounts =
                            namedFields
                            |> Option.map (fun fields -> fields |> List.countBy (fun field -> field.Name) |> Map.ofList)
                            |> Option.defaultValue Map.empty

                        let tryTakeNamedArgument (parameterLayout: Parameter) =
                            namedFields
                            |> Option.bind (fun fields ->
                                fields
                                |> List.tryFind (fun field -> String.Equals(field.Name, parameterLayout.Name, StringComparison.Ordinal)))
                            |> Option.bind (fun field ->
                                if field.IsImplicit then
                                    None
                                else
                                    usedNamedFields <- Set.add field.Name usedNamedFields
                                    Some field.Value)

                        for parameterLayout, rawParameterType in List.zip parameterLayoutsToProcess parameterTypesToProcess do
                            let parameterType = TypeSignatures.applySubstitution substitution rawParameterType

                            if stoppedAtPartialApplication then
                                remainingParameters.Add(parameterLayout, parameterType)
                            elif parameterLayout.IsImplicit then
                                match remainingArguments with
                                | ExplicitImplicitArgument explicitArgument :: rest ->
                                    if isCompileTimeArgumentType environment.VisibleTypeAliases parameterType then
                                        match tryParseVisibleTypeLikeArgument explicitArgument with
                                        | Some explicitTypeArgument ->
                                            remainingArguments <- rest
                                            substitution <-
                                                composeTypeSubstitution
                                                    substitution
                                                    (Map.ofList [ parameterLayout.Name, explicitTypeArgument ])
                                            preparedParameters.Add(
                                                { Layout = Some parameterLayout
                                                  ParameterType = parameterType
                                                  AssignedArgument = None }
                                            )
                                        | None ->
                                            success <- false
                                    else
                                        match inferArgumentType explicitArgument with
                                        | Some argumentType ->
                                            match tryUnifyVisibleTypes environment.VisibleTypeAliases [ parameterType, argumentType ] with
                                            | Some inferredSubstitution ->
                                                preparedArguments.Add(ExplicitArgument explicitArgument)
                                                preparedParameters.Add(
                                                    { Layout = Some parameterLayout
                                                      ParameterType = parameterType
                                                      AssignedArgument = Some(ExplicitArgument explicitArgument) }
                                                )
                                                remainingArguments <- rest
                                                let termSubstitution =
                                                    tryParseVisibleTypeLikeArgument explicitArgument
                                                    |> Option.map (fun argumentType -> Map.ofList [ parameterLayout.Name, argumentType ])
                                                    |> Option.defaultValue Map.empty

                                                substitution <-
                                                    composeTypeSubstitution
                                                        (composeTypeSubstitution substitution inferredSubstitution)
                                                        termSubstitution
                                            | None ->
                                                success <- false
                                        | None ->
                                            success <- false
                                | _ ->
                                    match
                                        trySynthesizeImplicitArgument
                                            environment
                                            (tryResolveCurrentLocalImplicit substitution)
                                            parameterType
                                    with
                                    | Some implicitArgument ->
                                        preparedArguments.Add(ImplicitArgument implicitArgument)
                                        preparedParameters.Add(
                                            { Layout = Some parameterLayout
                                              ParameterType = parameterType
                                              AssignedArgument = Some(ImplicitArgument implicitArgument) }
                                        )
                                    | None ->
                                        success <- false
                            elif isCompileTimeArgumentType environment.VisibleTypeAliases parameterType then
                                match remainingArguments with
                                | ExplicitImplicitArgument _ :: _ ->
                                    success <- false
                                | nextArgument :: rest ->
                                    match tryParseVisibleTypeLikeArgument nextArgument with
                                    | Some explicitTypeArgument ->
                                        remainingArguments <- rest
                                        substitution <-
                                            composeTypeSubstitution
                                                substitution
                                                (Map.ofList [ parameterLayout.Name, explicitTypeArgument ])
                                        preparedParameters.Add(
                                            { Layout = Some parameterLayout
                                              ParameterType = parameterType
                                              AssignedArgument = None }
                                        )
                                    | None ->
                                        success <- false
                                | [] ->
                                    match tryTakeNamedArgument parameterLayout with
                                    | Some namedArgument ->
                                        match tryParseVisibleTypeLikeArgument namedArgument with
                                        | Some explicitTypeArgument ->
                                            substitution <-
                                                composeTypeSubstitution
                                                    substitution
                                                    (Map.ofList [ parameterLayout.Name, explicitTypeArgument ])
                                            preparedParameters.Add(
                                                { Layout = Some parameterLayout
                                                  ParameterType = parameterType
                                                  AssignedArgument = None }
                                            )
                                        | None ->
                                            success <- false
                                    | None ->
                                        if namedFields.IsSome && not (hasDefaultArgument parameterLayout) then
                                            success <- false
                                        else
                                            if namedFields.IsSome then
                                                preparedParameters.Add(
                                                    { Layout = Some parameterLayout
                                                      ParameterType = parameterType
                                                      AssignedArgument = None }
                                                )
                                            else
                                                stoppedAtPartialApplication <- true
                                                remainingParameters.Add(parameterLayout, parameterType)
                            else
                                let explicitArgument =
                                    match remainingArguments with
                                    | ExplicitImplicitArgument _ :: _ ->
                                        success <- false
                                        None
                                    | nextArgument :: rest ->
                                        remainingArguments <- rest
                                        Some nextArgument
                                    | [] ->
                                        match tryTakeNamedArgument parameterLayout with
                                        | Some namedArgument ->
                                            Some namedArgument
                                        | None ->
                                            if namedFields.IsSome && not (hasDefaultArgument parameterLayout) then
                                                success <- false
                                                None
                                            else
                                                if namedFields.IsSome then
                                                    preparedParameters.Add(
                                                        { Layout = Some parameterLayout
                                                          ParameterType = parameterType
                                                          AssignedArgument = None }
                                                    )
                                                else
                                                    stoppedAtPartialApplication <- true
                                                    remainingParameters.Add(parameterLayout, parameterType)
                                                None

                                explicitArgument
                                |> Option.iter (fun nextArgument ->
                                    match inferArgumentTypeForParameter parameterType nextArgument with
                                    | Some argumentType ->
                                        match tryUnifyVisibleTypes environment.VisibleTypeAliases [ parameterType, argumentType ] with
                                        | Some inferredSubstitution ->
                                            preparedArguments.Add(ExplicitArgument nextArgument)
                                            preparedParameters.Add(
                                                { Layout = Some parameterLayout
                                                  ParameterType = parameterType
                                                  AssignedArgument = Some(ExplicitArgument nextArgument) }
                                            )
                                            let termSubstitution =
                                                tryParseVisibleTypeLikeArgument nextArgument
                                                |> Option.map (fun argumentType -> Map.ofList [ parameterLayout.Name, argumentType ])
                                                |> Option.defaultValue Map.empty

                                            substitution <-
                                                composeTypeSubstitution
                                                    (composeTypeSubstitution substitution inferredSubstitution)
                                                    termSubstitution
                                        | None ->
                                            success <- false
                                    | None ->
                                        success <- false)

                        let namedFieldsValid =
                            namedFieldCounts
                            |> Map.forall (fun _ count -> count = 1)
                            && (namedFields
                                |> Option.map (fun fields ->
                                    fields
                                    |> List.forall (fun field -> Set.contains field.Name usedNamedFields))
                                |> Option.defaultValue true)

                        if success && namedFieldsValid && List.isEmpty remainingArguments then
                            debugVisibleBindingCall "prepared call succeeded"
                            let instantiatedScheme = TypeSignatures.applySchemeSubstitution substitution instantiated
                            let appliedResultType =
                                let loweredRemainingParameters =
                                    remainingParameters
                                    |> Seq.toList
                                    |> List.map (fun (parameterLayout, parameterType) ->
                                        parameterLayout.Quantity |> Option.defaultValue QuantityOmega,
                                        TypeSignatures.applySubstitution substitution parameterType)

                                let trailingParameters =
                                    trailingParameterTypes
                                    |> List.map (fun parameterType ->
                                        QuantityOmega,
                                        TypeSignatures.applySubstitution substitution parameterType)

                                loweredRemainingParameters @ trailingParameters
                                |> List.rev
                                |> List.fold
                                    (fun current (parameterQuantity, parameterType) ->
                                        TypeArrow(parameterQuantity, parameterType, current))
                                    (TypeSignatures.applySubstitution substitution resultType)

                            Some
                                { InstantiatedScheme = instantiatedScheme
                                  ResultType = appliedResultType
                                  Parameters = List.ofSeq preparedParameters
                                  Arguments = List.ofSeq preparedArguments }
                        else
                            debugVisibleBindingCall $"prepared call failed success={success} namedFieldsValid={namedFieldsValid} remainingArguments={remainingArguments.Length}"
                            if hasApplicationOnlyArgument arguments || namedFields.IsSome then
                                None
                            else
                                tryPrepareSchemeOnlyCall instantiated arguments

    let private tryPrepareExpectedVisibleBindingValue
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (bindingInfo: BindingSchemeInfo)
        (localImplicitTypes: Map<string, TypeExpr> option)
        (inferArgumentType: SurfaceExpression -> TypeExpr option)
        (tryResolveLocalImplicit: TypeExpr -> KCoreExpression option)
        expectedType
        =
        let parameterConsumesCompileTimeArgument (layout: Parameter) (parameterType: TypeExpr) =
            match tryParseParameterType layout with
            | Some declaredParameterType ->
                isCompileTimeArgumentType environment.VisibleTypeAliases declaredParameterType
            | None ->
                isCompileTimeArgumentType environment.VisibleTypeAliases parameterType

        let instantiated = TypeSignatures.instantiate "t" freshCounter.Value bindingInfo.Scheme
        freshCounter.Value <- freshCounter.Value + instantiated.Forall.Length

        let normalizedParameterLayouts =
            normalizedVisibleBindingParameterLayouts bindingInfo instantiated
            |> Option.orElse bindingInfo.ParameterLayouts
        let layoutTypeSubstitution = forallInstantiationSubstitution bindingInfo.Scheme instantiated

        let tryResolveCurrentLocalImplicit substitution parameterType =
            match localImplicitTypes with
            | Some localTypes ->
                tryResolveUniqueLocalImplicitByTypeWithSubstitution
                    environment
                    localTypes
                    substitution
                    parameterType
            | None ->
                tryResolveLocalImplicit parameterType

        let schemeParameterTypes, schemeResultType = TypeSignatures.schemeParts instantiated

        let tryPrepareSchemeOnlyExpectedValue () =
            let fallbackInstantiated = TypeSignatures.instantiate "t" freshCounter.Value bindingInfo.Scheme
            freshCounter.Value <- freshCounter.Value + fallbackInstantiated.Forall.Length

            let fallbackParameterTypes, fallbackResultType = TypeSignatures.schemeParts fallbackInstantiated

            tryUnifyVisibleTypes environment.VisibleTypeAliases [ fallbackResultType, expectedType ]
            |> Option.bind (fun inferredSubstitution ->
                let instantiatedScheme =
                    TypeSignatures.applySchemeSubstitution inferredSubstitution fallbackInstantiated

                let substitutedParameterTypes =
                    fallbackParameterTypes
                    |> List.map (TypeSignatures.applySubstitution inferredSubstitution)

                let preparedParameters = ResizeArray<PreparedCallParameter>()
                let preparedArguments = ResizeArray<PreparedCallArgument>()
                let mutable success = true

                for parameterType in substitutedParameterTypes do
                    if isCompileTimeArgumentType environment.VisibleTypeAliases parameterType then
                        ()
                    else
                        match
                            trySynthesizeImplicitArgument
                                environment
                                (tryResolveCurrentLocalImplicit inferredSubstitution)
                                parameterType
                        with
                        | Some implicitArgument ->
                            preparedArguments.Add(ImplicitArgument implicitArgument)
                            preparedParameters.Add(
                                { Layout = None
                                  ParameterType = parameterType
                                  AssignedArgument = Some(ImplicitArgument implicitArgument) }
                            )
                        | None ->
                            success <- false

                if success then
                    Some
                        { InstantiatedScheme = instantiatedScheme
                          ResultType = TypeSignatures.applySubstitution inferredSubstitution fallbackResultType
                          Parameters = List.ofSeq preparedParameters
                          Arguments = List.ofSeq preparedArguments }
                else
                    None)

        let alignmentSlots =
            match normalizedParameterLayouts with
            | Some parameterLayouts ->
                tryBuildParameterAlignmentSlots
                    environment
                    layoutTypeSubstitution
                    parameterLayouts
                    schemeParameterTypes
            | None ->
                None

        let residualShape =
            match alignmentSlots with
            | Some slots ->
                let residualParameters =
                    slots
                    |> List.choose (fun slot ->
                        match slot.Layout with
                        | Some layout when layout.IsImplicit || parameterConsumesCompileTimeArgument layout slot.ParameterType ->
                            None
                        | Some layout ->
                            Some(layout.Quantity |> Option.defaultValue QuantityOmega, slot.ParameterType)
                        | None when
                            isCompileTimeArgumentType environment.VisibleTypeAliases slot.ParameterType
                            || (tryTraitConstraintFromType environment slot.ParameterType |> Option.isSome) ->
                            None
                        | None ->
                            Some(QuantityOmega, slot.ParameterType))

                Some(slots, residualParameters)
            | None ->
                None

        let residualType =
            match residualShape with
            | Some(_, residualParameters) ->
                residualParameters
                |> List.rev
                |> List.fold
                    (fun current (parameterQuantity, parameterType) ->
                        TypeArrow(parameterQuantity, parameterType, current))
                    schemeResultType
            | None ->
                instantiated.Body

        let layoutDrivenResult =
            tryUnifyVisibleTypes environment.VisibleTypeAliases [ residualType, expectedType ]
            |> Option.map (fun inferredSubstitution ->
                let instantiatedScheme = TypeSignatures.applySchemeSubstitution inferredSubstitution instantiated

                match residualShape with
                | Some(alignmentSlots, _) ->
                    let substitutedAlignmentSlots =
                        alignmentSlots
                        |> List.map (fun slot ->
                            { slot with
                                ParameterType = TypeSignatures.applySubstitution inferredSubstitution slot.ParameterType })

                    let preparedParameters = ResizeArray<PreparedCallParameter>()
                    let preparedArguments = ResizeArray<PreparedCallArgument>()
                    let remainingParameters = ResizeArray<Quantity * TypeExpr>()
                    let mutable success = true

                    for slot in substitutedAlignmentSlots do
                        match slot.Layout with
                        | Some parameterLayout when parameterLayout.IsImplicit ->
                            match
                                trySynthesizeImplicitArgument
                                    environment
                                    (tryResolveCurrentLocalImplicit inferredSubstitution)
                                    slot.ParameterType
                            with
                            | Some implicitArgument ->
                                preparedArguments.Add(ImplicitArgument implicitArgument)
                                preparedParameters.Add(
                                    ({ Layout = Some parameterLayout
                                       ParameterType = slot.ParameterType
                                       AssignedArgument = Some(ImplicitArgument implicitArgument) }: PreparedCallParameter)
                                )
                            | None ->
                                success <- false
                        | Some parameterLayout when parameterConsumesCompileTimeArgument parameterLayout slot.ParameterType ->
                            preparedParameters.Add(
                                ({ Layout = Some parameterLayout
                                   ParameterType = slot.ParameterType
                                   AssignedArgument = None }: PreparedCallParameter)
                            )
                        | Some parameterLayout ->
                            preparedParameters.Add(
                                ({ Layout = Some parameterLayout
                                   ParameterType = slot.ParameterType
                                   AssignedArgument = None }: PreparedCallParameter)
                            )
                            remainingParameters.Add(parameterLayout.Quantity |> Option.defaultValue QuantityOmega, slot.ParameterType)
                        | None when isCompileTimeArgumentType environment.VisibleTypeAliases slot.ParameterType ->
                            ()
                        | None ->
                            match
                                trySynthesizeImplicitArgument
                                    environment
                                    (tryResolveCurrentLocalImplicit inferredSubstitution)
                                    slot.ParameterType
                            with
                            | Some implicitArgument ->
                                preparedArguments.Add(ImplicitArgument implicitArgument)
                                preparedParameters.Add(
                                    ({ Layout = None
                                       ParameterType = slot.ParameterType
                                       AssignedArgument = Some(ImplicitArgument implicitArgument) }: PreparedCallParameter)
                                )
                            | None ->
                                remainingParameters.Add(QuantityOmega, slot.ParameterType)

                    if success then
                        let appliedResultType =
                            remainingParameters
                            |> Seq.toList
                            |> List.rev
                            |> List.fold
                                (fun current (parameterQuantity, parameterType) ->
                                    TypeArrow(parameterQuantity, parameterType, current))
                                (TypeSignatures.applySubstitution inferredSubstitution schemeResultType)

                        Some
                            { InstantiatedScheme = instantiatedScheme
                              ResultType = appliedResultType
                              Parameters = List.ofSeq preparedParameters
                              Arguments = List.ofSeq preparedArguments }
                    else
                        None
                | None ->
                    Some
                        { InstantiatedScheme = instantiatedScheme
                          ResultType = TypeSignatures.applySubstitution inferredSubstitution residualType
                          Parameters = []
                          Arguments = [] })
            |> Option.flatten

        layoutDrivenResult
        |> Option.orElseWith tryPrepareSchemeOnlyExpectedValue

    let private bindingHasRuntimeImplicitParameter
        (environment: BindingLoweringEnvironment)
        (bindingInfo: BindingSchemeInfo)
        =
        let normalizedParameterLayouts =
            normalizedVisibleBindingParameterLayouts bindingInfo bindingInfo.Scheme
            |> Option.orElse bindingInfo.ParameterLayouts

        match normalizedParameterLayouts with
        | Some layouts ->
            let parameterTypes, _ = TypeSignatures.schemeParts bindingInfo.Scheme

            if List.length layouts = List.length parameterTypes then
                List.zip layouts parameterTypes
                |> List.exists (fun (layout, parameterType) ->
                    layout.IsImplicit
                    && not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType))
            else
                layouts |> List.exists (fun layout -> layout.IsImplicit)
        | None ->
            false

    let private bindingHasResolvableLocalRuntimeImplicitParameter
        (environment: BindingLoweringEnvironment)
        (localTypes: Map<string, TypeExpr>)
        (bindingInfo: BindingSchemeInfo)
        =
        let normalizedParameterLayouts =
            normalizedVisibleBindingParameterLayouts bindingInfo bindingInfo.Scheme
            |> Option.orElse bindingInfo.ParameterLayouts

        match normalizedParameterLayouts with
        | Some layouts ->
            let parameterTypes, _ = TypeSignatures.schemeParts bindingInfo.Scheme

            if List.length layouts = List.length parameterTypes then
                List.zip layouts parameterTypes
                |> List.exists (fun (layout, parameterType) ->
                    layout.IsImplicit
                    && not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType)
                    && (match classifyLocalImplicitByType environment localTypes parameterType with
                        | UniqueLocalImplicitCandidate _ -> true
                        | NoLocalImplicitCandidate
                        | AmbiguousLocalImplicitCandidates -> false))
            else
                false
        | None ->
            false

    let private tryPrepareVisibleTraitMemberCall
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        memberName
        (inferArgumentType: SurfaceExpression -> TypeExpr option)
        (arguments: SurfaceExpression list)
        =
        let candidates =
            environment.VisibleTraits
            |> Map.toList
            |> List.choose (fun (_, traitInfo) ->
                traitInfo.Members
                |> Map.tryFind memberName
                |> Option.bind (fun memberInfo ->
                    let candidateCounter = ref freshCounter.Value

                    let overloadedScheme =
                        { memberInfo.Scheme with
                            Constraints =
                                unqualifiedTraitConstraint traitInfo.Name (traitInfo.TypeParameters |> List.map TypeVariable)
                                :: memberInfo.Scheme.Constraints }

                    let bindingInfo =
                        bindingSchemeInfo
                            (bindingIdentity traitInfo.ModuleIdentity memberName)
                            false
                            overloadedScheme
                            []
                            None
                            None
                            Map.empty

                    tryPrepareVisibleBindingCall environment candidateCounter bindingInfo None inferArgumentType noLocalImplicit arguments
                    |> Option.bind (fun preparedCall ->
                        match preparedCall.InstantiatedScheme.Constraints with
                        | owningConstraint :: [] when String.Equals(traitConstraintLocalName owningConstraint, traitInfo.Name, StringComparison.Ordinal) ->
                            resolveConstraintInstance environment owningConstraint
                            |> Option.map (fun instanceInfo ->
                                traitInfo, memberInfo, preparedCall, instanceInfo, candidateCounter.Value)
                        | _ ->
                            None)))

        match candidates with
        | [ traitInfo, memberInfo, preparedCall, instanceInfo, nextFreshValue ] ->
            freshCounter.Value <- nextFreshValue
            Some(traitInfo, memberInfo, preparedCall, instanceInfo)
        | _ ->
            None

    let private tryPrepareResolvedTraitProjectionCall
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (localTypes: Map<string, TypeExpr>)
        nameSegments
        (inferArgumentType: SurfaceExpression -> TypeExpr option)
        (arguments: SurfaceExpression list)
        =
        tryResolveTraitMemberProjection environment localTypes nameSegments
        |> Option.bind (fun (traitInfo, resolvedMemberName, resolvedArguments, _) ->
            traitInfo.Members
            |> Map.tryFind resolvedMemberName
            |> Option.bind (fun memberInfo ->
                let specializedScheme =
                    if List.length traitInfo.TypeParameters = List.length resolvedArguments then
                        List.zip traitInfo.TypeParameters resolvedArguments
                        |> Map.ofList
                        |> fun substitution -> TypeSignatures.applySchemeSubstitution substitution memberInfo.Scheme
                    else
                        memberInfo.Scheme

                let bindingInfo =
                    bindingSchemeInfo
                        (bindingIdentity traitInfo.ModuleIdentity resolvedMemberName)
                        false
                        specializedScheme
                        []
                        None
                        None
                        Map.empty

                tryPrepareVisibleBindingCall
                    environment
                    freshCounter
                    bindingInfo
                    None
                    inferArgumentType
                    noLocalImplicit
                    arguments))

    let private constructorResultBelongsToType
        (environment: BindingLoweringEnvironment)
        (typeObject: StaticObjectInfo)
        (constructorInfo: BindingSchemeInfo)
        =
        match typeObject.ObjectKind, typeObject.TypeFacet with
        | TypeObject, Some typeFacetInfo ->
            let _, resultType = TypeSignatures.schemeParts constructorInfo.Scheme

            match normalizeTypeAliases environment.VisibleTypeAliases resultType with
            | TypeName(resultName, _) ->
                tryResolveVisibleTypeFacetInfo environment resultName
                |> Option.exists (fun resultTypeFacet -> resultTypeFacet.Identity = typeFacetInfo.Identity)
            | _ ->
                false
        | _ ->
            false

    let private tryResolveStaticConstructor
        (environment: BindingLoweringEnvironment)
        receiverExpression
        memberName
        =
        tryResolveStaticReceiverObject environment receiverExpression
        |> Option.bind (fun typeObject ->
            let visibleResolution () =
                environment.VisibleConstructors
                |> Map.tryFind memberName
                |> Option.filter (constructorResultBelongsToType environment typeObject)

            match typeObject.ObjectKind, typeObject.TypeFacet with
            | TypeObject, Some typeFacetInfo ->
                environment.SurfaceIndex
                |> Map.tryFind typeFacetInfo.ModuleIdentity
                |> Option.bind (fun moduleSurface ->
                    moduleSurface.Constructors
                    |> Map.tryFind memberName
                    |> Option.filter (constructorResultBelongsToType environment typeObject))
                |> Option.orElseWith visibleResolution
            | _ ->
                visibleResolution ())

    let private tryInferStaticConstructorCall
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (inferArgumentType: SurfaceExpression -> TypeExpr option)
        receiverExpression
        memberName
        arguments
        =
        tryResolveStaticConstructor environment receiverExpression memberName
        |> Option.bind (fun constructorInfo ->
            tryPrepareVisibleBindingCall
                environment
                freshCounter
                constructorInfo
                None
                inferArgumentType
                noLocalImplicit
                arguments
            |> Option.map (fun preparedCall -> preparedCall.ResultType))


    let rec private inferValidationExpressionTypeWithContext
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (localTypes: Map<string, TypeExpr>)
        (localImplicitTypes: Map<string, TypeExpr>)
        expression
        =
        let inferExpressionType =
            inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes
        let normalizeVisibleType typeExpr =
            typeExpr |> qualifyVisibleTypeNames environment |> normalizeTypeAliases environment.VisibleTypeAliases
        let visibleTypeEquals left right =
            TypeSignatures.definitionallyEqual (normalizeVisibleType left) (normalizeVisibleType right)

        let tryInferMemberAccessType receiver segments arguments =
            match segments with
            | [] ->
                inferExpressionType receiver
                |> Option.bind (fun receiverType ->
                    tryInferVisibleAppliedType
                        environment.VisibleTypeAliases
                        (qualifyVisibleTypeNames environment)
                        inferExpressionType
                        receiverType
                        arguments)
            | [ memberName ] ->
                (tryResolveHandledEffectDeclaration environment receiver
                 |> Option.bind (fun declaration ->
                     EffectSemantics.tryFindOperation memberName declaration
                     |> Option.bind (fun operation ->
                         operation.SignatureTokens
                         |> TypeSignatures.parseType
                         |> Option.map (qualifyVisibleTypeNames environment)
                         |> Option.bind (fun operationType ->
                             let parameterTypes, resultType = TypeSignatures.functionParts operationType

                             if List.length arguments = List.length parameterTypes then
                                 Some(effType (scopedEffectRowType declaration) resultType)
                             else
                                 tryInferVisibleAppliedType
                                     environment.VisibleTypeAliases
                                     (qualifyVisibleTypeNames environment)
                                     inferExpressionType
                                     operationType
                                     arguments))))
                |> Option.orElseWith (fun () ->
                    tryInferStaticConstructorCall environment freshCounter inferExpressionType receiver memberName arguments)
                |> Option.orElseWith (fun () ->
                    environment.VisibleBindings
                    |> Map.tryFind memberName
                    |> Option.bind (fun bindingInfo ->
                        if receiverMethodCallHasRequiredExplicitArguments bindingInfo arguments then
                            tryBuildReceiverMethodArguments bindingInfo receiver arguments
                            |> Option.bind (fun receiverArguments ->
                                tryPrepareVisibleBindingCall
                                    environment
                                    freshCounter
                                    bindingInfo
                                    (Some localImplicitTypes)
                                    inferExpressionType
                                    (tryResolveUniqueLocalImplicitByType environment localImplicitTypes)
                                    receiverArguments
                                |> Option.map (fun preparedCall -> preparedCall.ResultType))
                        else
                            None))
                |> Option.orElseWith (fun () ->
                    inferExpressionType receiver
                    |> Option.bind (fun receiverType ->
                        tryProjectVisibleRecordType environment.VisibleTypeAliases receiverType [ memberName ]
                        |> Option.bind (fun memberType ->
                            tryInferVisibleAppliedType
                                environment.VisibleTypeAliases
                                (qualifyVisibleTypeNames environment)
                                inferExpressionType
                                memberType
                                arguments)))
                |> Option.orElseWith (fun () ->
                    inferExpressionType receiver
                    |> Option.bind (fun receiverType ->
                        tryResolveTraitMemberFromReceiverType environment receiverType memberName
                        |> Option.bind (fun (traitInfo, resolvedMemberName, resolvedArguments) ->
                            traitInfo.Members
                            |> Map.tryFind resolvedMemberName
                            |> Option.bind (fun memberInfo ->
                                let specializedScheme =
                                    if List.length traitInfo.TypeParameters = List.length resolvedArguments then
                                        List.zip traitInfo.TypeParameters resolvedArguments
                                        |> Map.ofList
                                        |> fun substitution -> TypeSignatures.applySchemeSubstitution substitution memberInfo.Scheme
                                    else
                                        memberInfo.Scheme

                                tryInferVisibleAppliedType
                                    environment.VisibleTypeAliases
                                    (qualifyVisibleTypeNames environment)
                                    inferExpressionType
                                    specializedScheme.Body
                                    arguments))))
            | memberName :: rest ->
                inferExpressionType (MemberAccess(MemberAccess(receiver, [ memberName ], []), rest, arguments))

        match expression with
        | Literal literal ->
            Some(inferLiteralType literal)
        | NumericLiteral literal ->
            match SurfaceNumericLiteral.suffix literal with
            | Some suffixName ->
                inferValidationExpressionTypeWithContext
                    environment
                    freshCounter
                    localTypes
                    localImplicitTypes
                    (Apply(Name [ suffixName ], [ NumericLiteral(SurfaceNumericLiteral.withoutSuffix literal) ]))
            | None ->
                Some(inferSurfaceNumericLiteralType literal)
        | TypeSyntaxTokens tokens ->
            TypeSignatures.parseType tokens |> Option.map (fun _ -> TypeName([ "Type" ], []))
        | SyntaxQuote inner ->
            inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes inner
            |> Option.map syntaxType
        | SyntaxSplice inner ->
            inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes inner
            |> Option.bind (tryUnwrapSyntaxType environment.VisibleTypeAliases)
        | TopLevelSyntaxSplice inner ->
            inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes inner
            |> Option.bind (tryUnwrapTopLevelSyntaxSpliceType environment.VisibleTypeAliases)
        | CodeQuote inner ->
            inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes inner
            |> Option.map codeType
        | CodeSplice inner ->
            inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes inner
            |> Option.bind (function
                | TypeName(nameSegments, [ innerType ]) when
                    matchesKnownType CompilerKnownSymbols.CodeType nameSegments -> Some innerType
                | _ -> None)
        | Name [ "True" ]
        | Name [ "False" ] ->
            Some boolType
        | KindQualifiedName _ ->
            tryResolveScopedStaticObject environment expression
            |> Option.bind (fun staticObject -> staticObject.Scheme)
            |> Option.map (fun scheme -> scheme.Body)
        | Name [ effectName ] when tryFindScopedEffectDeclaration effectName |> Option.isSome ->
            Some(TypeIntrinsic EffLabelClassifier)
        | Name(root :: path) ->
            let scopedEffectOperationType =
                match path with
                | [ operationName ] ->
                    tryFindScopedEffectOperation root operationName
                    |> Option.bind (fun (_, operation) ->
                        operation.SignatureTokens
                            |> TypeSignatures.parseType
                            |> Option.map (qualifyVisibleTypeNames environment))
                | _ ->
                    None

            let resolvedEffectOperationType =
                tryResolveEffectOperationNamePath environment (root :: path)
                |> Option.bind (fun (_, _, operation) ->
                    operation.SignatureTokens
                    |> TypeSignatures.parseType
                    |> Option.map (qualifyVisibleTypeNames environment))

            let ordinaryResolution =
                localTypes
                |> Map.tryFind root
                |> Option.orElseWith (fun () ->
                    environment.VisibleBindings
                    |> Map.tryFind root
                    |> Option.bind (fun bindingInfo ->
                        if bindingHasResolvableLocalRuntimeImplicitParameter environment localImplicitTypes bindingInfo then
                            tryPrepareVisibleBindingCall
                                environment
                                freshCounter
                                bindingInfo
                                (Some localImplicitTypes)
                                (inferValidationExpressionTypeWithContext
                                    environment
                                    freshCounter
                                    localTypes
                                    localImplicitTypes)
                                (tryResolveUniqueLocalImplicitByType environment localImplicitTypes)
                                []
                            |> Option.map (fun preparedCall -> preparedCall.ResultType)
                            |> Option.orElseWith (fun () -> instantiateVisibleBindingBodyType environment freshCounter root)
                        elif bindingHasRuntimeImplicitParameter environment bindingInfo then
                            None
                        else
                            instantiateVisibleBindingBodyType environment freshCounter root))
                |> Option.orElseWith (fun () ->
                    environment.VisibleConstructors
                    |> Map.tryFind root
                    |> Option.bind (fun _ -> instantiateVisibleConstructorBodyType environment freshCounter root))
                |> Option.orElseWith (fun () ->
                    tryResolveScopedStaticObject environment (Name [ root ])
                    |> Option.bind (fun staticObject ->
                        if List.isEmpty path then
                            staticObject.Scheme |> Option.map (fun scheme -> scheme.Body)
                        else
                            None))
                |> Option.bind (fun rootType -> tryProjectVisibleRecordType environment.VisibleTypeAliases rootType path)

            let receiverBindingResolution memberName =
                environment.VisibleBindings
                |> Map.tryFind memberName
                |> Option.bind (fun bindingInfo ->
                    tryBuildReceiverMethodArguments bindingInfo (Name [ root ]) []
                    |> Option.bind (fun receiverArguments ->
                        tryPrepareVisibleBindingCall
                            environment
                            freshCounter
                            bindingInfo
                            (Some localImplicitTypes)
                            (inferValidationExpressionTypeWithContext
                                environment
                                freshCounter
                                localTypes
                                localImplicitTypes)
                            (tryResolveUniqueLocalImplicitByType environment localImplicitTypes)
                            receiverArguments
                        |> Option.map (fun preparedCall -> preparedCall.ResultType)))
                |> Option.orElseWith (fun () ->
                    tryPrepareResolvedTraitProjectionCall
                        environment
                        freshCounter
                        localTypes
                        [ root; memberName ]
                        (inferValidationExpressionTypeWithContext
                            environment
                            freshCounter
                            localTypes
                            localImplicitTypes)
                        []
                    |> Option.map (fun preparedCall -> preparedCall.ResultType))
                |> Option.orElseWith (fun () ->
                    tryPrepareVisibleTraitMemberCall
                        environment
                        freshCounter
                        memberName
                        (inferValidationExpressionTypeWithContext
                            environment
                            freshCounter
                            localTypes
                            localImplicitTypes)
                        [ Name [ root ] ]
                    |> Option.map (fun (_, _, preparedCall, _) -> preparedCall.ResultType))

            match path with
            | [ memberName ] ->
                scopedEffectOperationType
                |> Option.orElse resolvedEffectOperationType
                |> Option.orElseWith (fun () -> receiverBindingResolution memberName)
                |> Option.orElseWith (fun () ->
                    tryInferStaticConstructorCall
                        environment
                        freshCounter
                        (inferValidationExpressionTypeWithContext
                            environment
                            freshCounter
                            localTypes
                            localTypes)
                        (Name [ root ])
                        memberName
                        [])
                |> Option.orElse ordinaryResolution
            | _ ->
                resolvedEffectOperationType
                |> Option.orElse ordinaryResolution
        | Name [] ->
            None
        | Apply(MemberAccess(receiver, [ memberName ], []), arguments) ->
            match
                tryResolveHandledEffectDeclaration environment receiver
                |> Option.bind (fun declaration ->
                    EffectSemantics.tryFindOperation memberName declaration
                    |> Option.bind (fun operation ->
                        operation.SignatureTokens
                        |> TypeSignatures.parseType
                        |> Option.map (qualifyVisibleTypeNames environment)
                        |> Option.map TypeSignatures.functionParts
                        |> Option.map (fun (parameterTypes, resultType) -> declaration, parameterTypes, resultType)))
            with
            | Some(declaration, parameterTypes, resultType) when List.length parameterTypes = List.length arguments ->
                Some(effType (scopedEffectRowType declaration) resultType)
            | _ ->
                match
                    tryInferQueryCarrierType
                        environment
                        freshCounter
                        localTypes
                        (fun currentLocals currentExpression ->
                            inferValidationExpressionTypeWithContext
                                environment
                                freshCounter
                                currentLocals
                                localImplicitTypes
                                currentExpression)
                        expression
                with
                | Some queryCarrierType -> Some queryCarrierType
                | None ->
                    inferValidationApplicationTypeWithContext
                        environment
                        freshCounter
                        localTypes
                        localImplicitTypes
                        expression
        | Apply(Name nameSegments, arguments) ->
            match
                tryResolveEffectOperationNamePath environment nameSegments
                |> Option.bind (fun (_, declaration, operation) ->
                    operation.SignatureTokens
                    |> TypeSignatures.parseType
                    |> Option.map (qualifyVisibleTypeNames environment)
                    |> Option.map (fun signature -> declaration, TypeSignatures.functionParts signature))
            with
            | Some(declaration, (parameterTypes, resultType)) when List.length parameterTypes = List.length arguments ->
                Some(effType (scopedEffectRowType declaration) resultType)
            | _ ->
                match
                    tryInferQueryCarrierType
                        environment
                        freshCounter
                        localTypes
                        (fun currentLocals currentExpression ->
                            inferValidationExpressionTypeWithContext
                                environment
                                freshCounter
                                currentLocals
                                localImplicitTypes
                                currentExpression)
                        expression
                with
                | Some queryCarrierType -> Some queryCarrierType
                | None ->
                    inferValidationApplicationTypeWithContext
                        environment
                        freshCounter
                        localTypes
                        localImplicitTypes
                        expression
        | LocalSignature(_, body) ->
            inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes body
        | LocalTypeAlias _ ->
            inferValidationExpressionTypeWithContext
                environment
                freshCounter
                localTypes
                localImplicitTypes
                (rewriteLocalTypeAliasesInSurfaceExpression environment.CurrentModuleIdentity environment.VisibleTypeAliases expression)
        | LocalLet(binding, value, body) ->
            let bindingNames = collectPatternNames binding.Pattern

            let nextLocals =
                match inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes value with
                | Some valueType ->
                    extendBindingLocalTypes environment freshCounter localTypes binding (Some valueType)
                | None ->
                    extendBindingLocalTypes
                        environment
                        freshCounter
                        localTypes
                        binding
                        (Some(inferFallbackLocalType freshCounter value))

            let bodyForInference =
                match bindingNames, tryResolveScopedStaticObject environment value with
                | [ aliasName ], Some staticObject ->
                    rewriteStaticObjectAliasUse aliasName staticObject body
                | _ ->
                    body

            inferValidationExpressionTypeWithContext
                environment
                freshCounter
                nextLocals
                localImplicitTypes
                bodyForInference
        | LocalScopedEffect(declaration, body) ->
            withScopedEffectDeclaration environment.CurrentModuleIdentity declaration (fun () ->
                inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes body)
        | Handle(_, label, body, returnClause, _) ->
            let handledResultType =
                match
                    tryResolveHandledEffectDeclaration environment label,
                    inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes body
                    |> Option.bind tryUnwrapEffType
                with
                | Some declaration, Some(effectRow, payloadType) ->
                    match trySplitHandledEffectRow environment.VisibleTypeAliases declaration effectRow with
                    | SplitResolved remainderRow -> Some(effType remainderRow payloadType)
                    | _ -> None
                | _ ->
                    None

            handledResultType
            |> Option.orElseWith (fun () ->
                inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes returnClause.Body)
        | Lambda(parameters, body) ->
            let parameterTypes =
                parameters
                |> List.map (fun parameter ->
                    tryParseParameterType parameter
                    |> Option.map (qualifyVisibleTypeNames environment)
                    |> Option.defaultValue (TypeVariable $"lambda{freshCounter.Value}"))

            let parameterQuantities =
                parameters
                |> List.map (fun parameter -> parameter.Quantity |> Option.defaultValue QuantityOmega)

            let lambdaLocals =
                List.zip parameters parameterTypes
                |> List.fold (fun state (parameter, parameterType) -> Map.add parameter.Name parameterType state) localTypes
            let lambdaImplicitLocals =
                List.zip parameters parameterTypes
                |> List.fold (fun state (parameter, parameterType) ->
                    if parameter.IsImplicit then
                        Map.add parameter.Name parameterType state
                    else
                        state) localImplicitTypes

            inferValidationExpressionTypeWithContext
                environment
                freshCounter
                lambdaLocals
                lambdaImplicitLocals
                body
            |> Option.map (fun resultType ->
                List.zip parameterTypes parameterQuantities
                |> List.rev
                |> List.fold (fun state (parameterType, quantity) -> TypeArrow(quantity, parameterType, state)) resultType)
        | IfThenElse(_, whenTrue, whenFalse) ->
            match
                inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes whenTrue,
                inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes whenFalse
            with
            | Some trueType, Some falseType when trueType = falseType ->
                Some trueType
            | _ ->
                None
        | Match(scrutinee, cases) ->
            let scrutineeType =
                inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes scrutinee

            cases
            |> List.choose (fun caseClause ->
                let caseLocals =
                    extendPatternLocalTypes environment freshCounter localTypes scrutineeType caseClause.Pattern

                inferValidationExpressionTypeWithContext
                    environment
                    freshCounter
                    caseLocals
                    localImplicitTypes
                    caseClause.Body)
            |> function
                | first :: rest when rest |> List.forall ((=) first) -> Some first
                | _ -> None
        | RecordLiteral fields ->
            let inferredFields =
                fields
                |> List.map (fun field ->
                    inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes field.Value
                    |> Option.map (fun fieldType ->
                        ({ Name = field.Name
                           Quantity = if field.IsImplicit then QuantityZero else QuantityOmega
                           Type = fieldType }: TypeSignatures.RecordField)))

            if inferredFields |> List.forall Option.isSome then
                inferredFields
                |> List.choose id
                |> TypeRecord
                |> Some
            else
                None
        | Seal(value, _) ->
            inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes value
        | RecordUpdate(receiver, _) ->
            inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes receiver
        | MemberAccess(receiver, segments, arguments) ->
            tryInferMemberAccessType receiver segments arguments
        | SafeNavigation(receiver, navigation) ->
            inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes receiver
            |> Option.bind (fun receiverType ->
                tryOptionPayloadType environment.VisibleTypeAliases receiverType
                |> Option.bind (fun payloadType ->
                    tryInferSafeNavigationMemberType
                        environment.VisibleTypeAliases
                        (qualifyVisibleTypeNames environment)
                        (inferValidationExpressionTypeWithContext
                            environment
                            freshCounter
                            localTypes
                            localImplicitTypes)
                        payloadType
                        navigation
                    |> Option.map (fun memberType ->
                        match tryOptionPayloadType environment.VisibleTypeAliases memberType with
                        | Some _ -> memberType
                        | None -> knownTypeExpr CompilerKnownSymbols.OptionType [ memberType ])))
        | TagTest _ ->
            Some boolType
        | Do statements ->
            inferValidationDoResultTypeWithContext
                environment
                freshCounter
                localTypes
                localImplicitTypes
                statements
        | MonadicSplice inner ->
            inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes inner
            |> Option.map unwrapIoType
        | ExplicitImplicitArgument inner ->
            inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes inner
        | NamedApplicationBlock _ ->
            None
        | InoutArgument inner ->
            inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes inner
        | Apply _ as application ->
            inferValidationApplicationTypeWithContext
                environment
                freshCounter
                localTypes
                localImplicitTypes
                application
        | Unary("not", _) ->
            Some boolType
        | Unary("negate", operand) ->
            inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes operand
        | Unary _ ->
            None
        | Binary(left, ("+" | "-" | "*" | "/"), right) ->
            match
                inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes left,
                inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes right
            with
            | Some leftType, Some rightType when visibleTypeEquals leftType intType && visibleTypeEquals rightType intType ->
                Some intType
            | Some leftType, Some rightType when visibleTypeEquals leftType floatType && visibleTypeEquals rightType floatType ->
                Some floatType
            | _ ->
                None
        | Binary(_, ("==" | "!=" | "<" | ">" | "<=" | ">=" | "&&" | "||"), _) ->
            Some boolType
        | Binary(left, operatorName, right) ->
            inferValidationExpressionTypeWithContext
                environment
                freshCounter
                localTypes
                localImplicitTypes
                (Apply(Name [ operatorName ], [ left; right ]))
        | Elvis(left, right) ->
            match
                inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes left,
                inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes right
            with
            | Some leftType, Some defaultType ->
                tryOptionPayloadType environment.VisibleTypeAliases leftType
                |> Option.bind (fun payloadType ->
                    tryUnifyVisibleTypes environment.VisibleTypeAliases [ payloadType, defaultType ]
                    |> Option.map (fun substitution -> TypeSignatures.applySubstitution substitution payloadType)
                    |> Option.orElseWith (fun () ->
                        if
                            TypeSignatures.definitionallyEqual
                                (normalizeTypeAliases environment.VisibleTypeAliases payloadType)
                                (normalizeTypeAliases environment.VisibleTypeAliases defaultType)
                        then
                            Some payloadType
                        else
                            None))
            | _ ->
                None
        | Comprehension comprehension ->
            inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes comprehension.Lowered
        | PrefixedString(prefix, _) ->
            tryInferPrefixedStringMacroResultType environment freshCounter localTypes prefix

    and private inferValidationApplicationTypeWithContext
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (localTypes: Map<string, TypeExpr>)
        (localImplicitTypes: Map<string, TypeExpr>)
        application
        =
        tryInferQueryCarrierType
            environment
            freshCounter
            localTypes
            (fun currentLocals currentExpression ->
                inferValidationExpressionTypeWithContext
                    environment
                    freshCounter
                    currentLocals
                    localImplicitTypes
                    currentExpression)
            application
        |> Option.orElseWith (fun () ->
            match application with
            | Apply(Name [ receiverName; memberName ], arguments) ->
                tryInferStaticConstructorCall
                    environment
                    freshCounter
                    (inferValidationExpressionTypeWithContext
                        environment
                        freshCounter
                        localTypes
                        localImplicitTypes)
                    (Name [ receiverName ])
                    memberName
                    arguments
                |> Option.orElseWith (fun () ->
                    tryPrepareResolvedTraitProjectionCall
                        environment
                        freshCounter
                        localTypes
                        [ receiverName; memberName ]
                        (inferValidationExpressionTypeWithContext
                            environment
                            freshCounter
                            localTypes
                            localImplicitTypes)
                        arguments
                    |> Option.map (fun preparedCall -> preparedCall.ResultType))
                |> Option.orElseWith (fun () ->
                    environment.VisibleBindings
                    |> Map.tryFind memberName
                    |> Option.bind (fun bindingInfo ->
                        tryBuildReceiverMethodArguments bindingInfo (Name [ receiverName ]) arguments
                        |> Option.bind (fun receiverArguments ->
                            tryPrepareVisibleBindingCall
                                environment
                                freshCounter
                                bindingInfo
                                (Some localImplicitTypes)
                                (inferValidationExpressionTypeWithContext
                                    environment
                                    freshCounter
                                    localTypes
                                    localImplicitTypes)
                                (tryResolveUniqueLocalImplicitByType environment localImplicitTypes)
                                receiverArguments
                            |> Option.map (fun preparedCall -> preparedCall.ResultType))))
            | Apply(Name [ calleeName ], arguments) ->
                localTypes
                |> Map.tryFind calleeName
                |> Option.bind (fun localType ->
                    tryInferVisibleAppliedType
                        environment.VisibleTypeAliases
                        (qualifyVisibleTypeNames environment)
                        (inferValidationExpressionTypeWithContext
                            environment
                            freshCounter
                            localTypes
                            localImplicitTypes)
                        localType
                        arguments)
                |> Option.orElseWith (fun () ->
                    environment.VisibleBindings
                    |> Map.tryFind calleeName
                    |> Option.bind (fun bindingInfo ->
                        let preparedResultType =
                            tryPrepareVisibleBindingCall
                                environment
                                freshCounter
                                bindingInfo
                                (Some localImplicitTypes)
                                (inferValidationExpressionTypeWithContext
                                    environment
                                    freshCounter
                                    localTypes
                                    localImplicitTypes)
                                (tryResolveUniqueLocalImplicitByType environment localImplicitTypes)
                                arguments
                            |> Option.map (fun preparedCall -> preparedCall.ResultType)

                        preparedResultType
                        |> Option.orElseWith (fun () ->
                            instantiateVisibleBindingBodyType environment freshCounter calleeName
                            |> Option.bind (fun bodyType ->
                                tryInferVisibleAppliedType
                                    environment.VisibleTypeAliases
                                    (qualifyVisibleTypeNames environment)
                                    (inferValidationExpressionTypeWithContext
                                        environment
                                        freshCounter
                                        localTypes
                                        localImplicitTypes)
                                    bodyType
                                    arguments))))
                |> Option.orElseWith (fun () ->
                    environment.VisibleConstructors
                    |> Map.tryFind calleeName
                    |> Option.bind (fun constructorInfo ->
                        tryPrepareVisibleBindingCall
                            environment
                            freshCounter
                            constructorInfo
                            (Some localImplicitTypes)
                            (inferValidationExpressionTypeWithContext
                                environment
                                freshCounter
                                localTypes
                                localImplicitTypes)
                            (tryResolveUniqueLocalImplicitByType environment localImplicitTypes)
                            arguments
                        |> Option.map (fun preparedCall -> preparedCall.ResultType)))
                |> Option.orElseWith (fun () ->
                    tryPrepareVisibleTraitMemberCall
                        environment
                        freshCounter
                        calleeName
                        (inferValidationExpressionTypeWithContext
                            environment
                            freshCounter
                            localTypes
                            localImplicitTypes)
                        arguments
                    |> Option.map (fun (_, _, preparedCall, _) -> preparedCall.ResultType))
            | _ ->
                None)

    and private inferValidationDoResultTypeWithContext
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (localTypes: Map<string, TypeExpr>)
        (localImplicitTypes: Map<string, TypeExpr>)
        statements
        =
        let tryMergeBranchResultTypes leftType rightType =
            tryUnifyVisibleTypes environment.VisibleTypeAliases [ leftType, rightType ]
            |> Option.map (fun substitution -> TypeSignatures.applySubstitution substitution leftType)
            |> Option.orElseWith (fun () ->
                if
                    TypeSignatures.definitionallyEqual
                        (normalizeTypeAliases environment.VisibleTypeAliases leftType)
                        (normalizeTypeAliases environment.VisibleTypeAliases rightType)
                then
                    Some leftType
                else
                    None)

        match statements with
        | [] ->
            Some unitType
        | DoExpression expression :: [] ->
            inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes expression
        | DoExpression _ :: rest ->
            inferValidationDoResultTypeWithContext environment freshCounter localTypes localImplicitTypes rest
        | DoLet(binding, expression) :: rest ->
            let nextLocals =
                inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes expression
                |> Option.map (fun valueType ->
                    extendPatternLocalTypes environment freshCounter localTypes (Some valueType) binding.Pattern)
                |> Option.defaultValue localTypes

            inferValidationDoResultTypeWithContext environment freshCounter nextLocals localImplicitTypes rest
        | DoLetQuestion(binding, expression, failure) :: rest ->
            let nextLocals =
                inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes expression
                |> Option.map (fun valueType ->
                    extendPatternLocalTypes environment freshCounter localTypes (Some valueType) binding.Pattern)
                |> Option.defaultValue localTypes

            failure
            |> Option.iter (fun failure ->
                inferValidationDoResultTypeWithContext environment freshCounter localTypes localImplicitTypes failure.Body
                |> ignore)

            inferValidationDoResultTypeWithContext environment freshCounter nextLocals localImplicitTypes rest
        | DoBind(binding, expression) :: rest ->
            let nextLocals =
                inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes expression
                |> Option.bind (tryUnwrapBindablePayloadType environment.VisibleTypeAliases)
                |> Option.map (fun valueType ->
                    extendPatternLocalTypes
                        environment
                        freshCounter
                        localTypes
                        (Some valueType)
                        binding.Pattern)
                |> Option.defaultValue localTypes

            inferValidationDoResultTypeWithContext environment freshCounter nextLocals localImplicitTypes rest
        | DoUsing(binding, expression) :: rest ->
            let nextLocals =
                inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes expression
                |> Option.map (fun valueType ->
                    extendPatternLocalTypes
                        environment
                        freshCounter
                        localTypes
                        (Some(unwrapIoType valueType))
                        binding.Pattern)
                |> Option.defaultValue localTypes

            inferValidationDoResultTypeWithContext environment freshCounter nextLocals localImplicitTypes rest
        | DoVar(bindingName, expression) :: rest ->
            let nextLocals =
                match inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes expression with
                | Some valueType -> Map.add bindingName (refType valueType) localTypes
                | None -> localTypes

            inferValidationDoResultTypeWithContext environment freshCounter nextLocals localImplicitTypes rest
        | DoAssign _ :: rest ->
            inferValidationDoResultTypeWithContext environment freshCounter localTypes localImplicitTypes rest
        | DoDefer _ :: rest ->
            inferValidationDoResultTypeWithContext environment freshCounter localTypes localImplicitTypes rest
        | DoIf(_, whenTrue, whenFalse) :: [] ->
            match
                inferValidationDoResultTypeWithContext environment freshCounter localTypes localImplicitTypes whenTrue,
                inferValidationDoResultTypeWithContext environment freshCounter localTypes localImplicitTypes whenFalse
            with
            | Some whenTrueType, Some whenFalseType ->
                tryMergeBranchResultTypes whenTrueType whenFalseType
            | _ ->
                None
        | DoIf(_, _, _) :: rest ->
            inferValidationDoResultTypeWithContext environment freshCounter localTypes localImplicitTypes rest
        | DoWhile _ :: rest ->
            inferValidationDoResultTypeWithContext environment freshCounter localTypes localImplicitTypes rest
        | DoReturn expression :: _ ->
            inferValidationExpressionTypeWithContext environment freshCounter localTypes localImplicitTypes expression

    let private inferValidationExpressionType
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (localTypes: Map<string, TypeExpr>)
        expression
        =
        inferValidationExpressionTypeWithContext environment freshCounter localTypes localTypes expression

    let private inferValidationApplicationType
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (localTypes: Map<string, TypeExpr>)
        application
        =
        inferValidationApplicationTypeWithContext environment freshCounter localTypes localTypes application

    let private inferValidationDoResultType
        (environment: BindingLoweringEnvironment)
        (freshCounter: int ref)
        (localTypes: Map<string, TypeExpr>)
        statements
        =
        inferValidationDoResultTypeWithContext environment freshCounter localTypes localTypes statements

    let private tryResolveTopLevelManifestStaticFieldFromFunctionResult
        (environment: BindingLoweringEnvironment)
        (topLevelDefinitionsByName: Map<string, LetDefinition>)
        calleeName
        (arguments: SurfaceExpression list)
        fieldName
        =
        let rec tryResolveStaticValue parameterStaticObjects expression =
            match expression with
            | Name [ name ] ->
                parameterStaticObjects
                |> Map.tryFind name
                |> Option.orElseWith (fun () -> tryResolveScopedStaticObject environment expression)
            | Seal(inner, _) ->
                tryResolveStaticValue parameterStaticObjects inner
            | _ ->
                tryResolveScopedStaticObject environment expression

        let rec tryResolveField parameterStaticObjects expression =
            match expression with
            | RecordLiteral fields ->
                fields
                |> List.tryFind (fun field -> String.Equals(field.Name, fieldName, StringComparison.Ordinal))
                |> Option.bind (fun field -> tryResolveStaticValue parameterStaticObjects field.Value)
            | Seal(inner, _) ->
                tryResolveField parameterStaticObjects inner
            | _ ->
                None

        topLevelDefinitionsByName
        |> Map.tryFind calleeName
        |> Option.bind (fun calleeDefinition ->
            if List.length calleeDefinition.Parameters <> List.length arguments then
                None
            else
                let parameterStaticObjects =
                    List.zip calleeDefinition.Parameters arguments
                    |> List.choose (fun (parameter, argument) ->
                        tryResolveScopedStaticObject environment argument
                        |> Option.map (fun staticObject -> parameter.Name, staticObject))
                    |> Map.ofList

                calleeDefinition.Body
                |> Option.bind (tryResolveField parameterStaticObjects))

    let private rewriteTopLevelManifestStaticFieldUses
        (environment: BindingLoweringEnvironment)
        (topLevelDefinitionsByName: Map<string, LetDefinition>)
        expression
        =
        let rec rewrite current =
            match current with
            | MemberAccess(Apply(Name [ calleeName ], callArguments), [ fieldName ], [])
                when topLevelDefinitionsByName.ContainsKey(calleeName) ->
                match
                    tryResolveTopLevelManifestStaticFieldFromFunctionResult
                        environment
                        topLevelDefinitionsByName
                        calleeName
                        callArguments
                        fieldName
                with
                | Some staticObject ->
                    Name staticObject.NameSegments
                | None ->
                    MemberAccess(
                        Apply(Name [ calleeName ], callArguments |> List.map rewrite),
                        [ fieldName ],
                        []
                    )
            | LocalLet(binding, value, body) ->
                LocalLet(binding, rewrite value, rewrite body)
            | LocalSignature(signature, body) ->
                LocalSignature(signature, rewrite body)
            | LocalTypeAlias(declaration, body) ->
                LocalTypeAlias(declaration, rewrite body)
            | LocalScopedEffect(declaration, body) ->
                LocalScopedEffect(declaration, rewrite body)
            | Handle(isDeep, label, body, returnClause, operationClauses) ->
                Handle(
                    isDeep,
                    rewrite label,
                    rewrite body,
                    { returnClause with Body = rewrite returnClause.Body },
                    operationClauses
                    |> List.map (fun clause ->
                        { clause with
                            Body = rewrite clause.Body })
                )
            | Lambda(parameters, body) ->
                Lambda(parameters, rewrite body)
            | IfThenElse(condition, whenTrue, whenFalse) ->
                IfThenElse(rewrite condition, rewrite whenTrue, rewrite whenFalse)
            | Match(scrutinee, cases) ->
                Match(
                    rewrite scrutinee,
                    cases
                    |> List.map (fun caseClause ->
                        { caseClause with
                            Guard = caseClause.Guard |> Option.map rewrite
                            Body = rewrite caseClause.Body })
                )
            | RecordLiteral fields ->
                RecordLiteral(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | Seal(value, ascriptionTokens) ->
                Seal(rewrite value, ascriptionTokens)
            | RecordUpdate(receiver, fields) ->
                RecordUpdate(rewrite receiver, fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | MemberAccess(receiver, segments, arguments) ->
                MemberAccess(rewrite receiver, segments, arguments |> List.map rewrite)
            | SafeNavigation(receiver, navigation) ->
                SafeNavigation(
                    rewrite receiver,
                    { navigation with
                        Arguments = navigation.Arguments |> List.map rewrite }
                )
            | TagTest(receiver, constructorName) ->
                TagTest(rewrite receiver, constructorName)
            | Do statements ->
                let rec rewriteDoStatement statement =
                    match statement with
                    | DoLet(binding, inner) -> DoLet(binding, rewrite inner)
                    | DoLetQuestion(binding, inner, failure) ->
                        let rewrittenFailure =
                            failure
                            |> Option.map (fun block ->
                                { block with
                                    Body = block.Body |> List.map rewriteDoStatement })

                        DoLetQuestion(binding, rewrite inner, rewrittenFailure)
                    | DoBind(binding, inner) -> DoBind(binding, rewrite inner)
                    | DoVar(name, inner) -> DoVar(name, rewrite inner)
                    | DoAssign(name, inner) -> DoAssign(name, rewrite inner)
                    | DoUsing(binding, inner) -> DoUsing(binding, rewrite inner)
                    | DoDefer inner -> DoDefer(rewrite inner)
                    | DoIf(condition, whenTrue, whenFalse) ->
                        DoIf(rewrite condition, whenTrue |> List.map rewriteDoStatement, whenFalse |> List.map rewriteDoStatement)
                    | DoWhile(condition, body) ->
                        DoWhile(rewrite condition, body |> List.map rewriteDoStatement)
                    | DoReturn inner -> DoReturn(rewrite inner)
                    | DoExpression inner -> DoExpression(rewrite inner)

                Do(statements |> List.map rewriteDoStatement)
            | MonadicSplice inner ->
                MonadicSplice(rewrite inner)
            | ExplicitImplicitArgument inner ->
                ExplicitImplicitArgument(rewrite inner)
            | NamedApplicationBlock fields ->
                NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | InoutArgument inner ->
                InoutArgument(rewrite inner)
            | Apply(callee, arguments) ->
                Apply(rewrite callee, arguments |> List.map rewrite)
            | Unary(operatorName, inner) ->
                Unary(operatorName, rewrite inner)
            | Binary(left, operatorName, right) ->
                Binary(rewrite left, operatorName, rewrite right)
            | Elvis(left, right) ->
                Elvis(rewrite left, rewrite right)
            | Comprehension comprehension ->
                Comprehension { comprehension with Lowered = rewrite comprehension.Lowered }
            | PrefixedString(prefix, parts) ->
                PrefixedString(
                    prefix,
                    parts
                    |> List.map (function
                        | StringText _ as part -> part
                        | StringInterpolation(inner, format) -> StringInterpolation(rewrite inner, format))
                )
            | SyntaxQuote inner ->
                SyntaxQuote(rewrite inner)
            | SyntaxSplice inner ->
                SyntaxSplice(rewrite inner)
            | TopLevelSyntaxSplice inner ->
                TopLevelSyntaxSplice(rewrite inner)
            | CodeQuote inner ->
                CodeQuote(rewrite inner)
            | CodeSplice inner ->
                CodeSplice(rewrite inner)
            | Literal _
            | NumericLiteral _
            | KindQualifiedName _
            | TypeSyntaxTokens _
            | Name _ ->
                current

        rewrite expression

    let private tryRewriteLegacyRecordDestructuringParametersForBinding
        (visibleTypeAliases: Map<string, TypeAliasInfo>)
        (bindingScheme: TypeScheme)
        (parameters: Parameter list)
        (body: SurfaceExpression option)
        =
        let parameterTypes, _ = TypeSignatures.schemeParts bindingScheme

        match parameterTypes, parameters, body with
        | [ recordType ], firstParameter :: remainingParameters, Some body ->
            match normalizeTypeAliases visibleTypeAliases recordType with
            | TypeRecord fields when not (List.isEmpty fields) ->
                let parameterCountMatches = List.length fields = List.length parameters
                let collapsedLegacyRecordParameter = List.length parameters = 1 && List.length fields > 1

                let trailingParametersMatchFieldTypes =
                    if parameterCountMatches then
                        remainingParameters
                        |> List.zip (fields |> List.skip 1)
                        |> List.forall (fun (field, parameter) ->
                            String.Equals(parameter.Name, field.Name, StringComparison.Ordinal)
                            && (parameter.TypeTokens
                                |> Option.bind TypeSignatures.parseType
                                |> Option.map (fun parameterType ->
                                    TypeSignatures.definitionallyEqual
                                        (normalizeTypeAliases visibleTypeAliases parameterType)
                                        (normalizeTypeAliases visibleTypeAliases field.Type))
                                |> Option.defaultValue false))
                    else
                        false

                let firstParameterMatchesFirstField =
                    String.Equals(firstParameter.Name, fields.Head.Name, StringComparison.Ordinal)

                if not firstParameterMatchesFirstField
                   || not (collapsedLegacyRecordParameter || (parameterCountMatches && trailingParametersMatchFieldTypes)) then
                    None
                else
                    let syntheticParameterName = "__kappa_record_param_0"
                    let recordTypeText = TypeSignatures.toText recordType

                    let syntheticParameter =
                        { Name = syntheticParameterName
                          TypeTokens = Some(typeTextTokens recordTypeText)
                          Quantity = None
                          IsImplicit = false
                          IsInout = false
                          IsReceiver = false }

                    let destructuringBinding =
                        { Pattern =
                            AnonymousRecordPattern(
                                fields
                                |> List.map (fun field ->
                                    { Name = field.Name
                                      IsImplicit = false
                                      Pattern = NamePattern field.Name }),
                                None
                            )
                          Quantity = None
                          IsImplicit = false
                          TypeTokens = Some(typeTextTokens recordTypeText)
                          BinderSpans = Map.empty }

                    Some([ syntheticParameter ], Some(LocalLet(destructuringBinding, Name [ syntheticParameterName ], body)))
            | _ ->
                None
        | _ ->
            None

    let private validateBuiltInExpressionsForBinding
        (environment: BindingLoweringEnvironment)
        (filePath: string)
        (knownSurfaceTermNames: Set<string>)
        (allowUnresolvedCallDiagnostics: bool)
        (explicitSignatureNames: Set<string>)
        (sourceSignatureScheme: TypeScheme option)
        (topLevelDefinitionsByName: Map<string, LetDefinition>)
        (definition: LetDefinition)
        (scheme: TypeScheme option)
        =
        let freshCounter = ref 0
        let effectiveScheme = sourceSignatureScheme |> Option.orElse scheme
        let rewrittenDefinitionBody =
            definition.Body
            |> Option.map (rewriteTopLevelManifestStaticFieldUses environment topLevelDefinitionsByName)

        let effectiveParameters, effectiveBody =
            match definition.Parameters, rewrittenDefinitionBody, effectiveScheme with
            | parameters, body, Some bindingScheme ->
                match
                    tryRewriteLegacyRecordDestructuringParametersForBinding
                        environment.VisibleTypeAliases
                        bindingScheme
                        parameters
                        body
                with
                | Some rewritten ->
                    rewritten
                | None ->
                    parameters, body
            | parameters, body, None ->
                parameters, body

        let makeDiagnostic kind message =
            Diagnostics.errorFact "KFrontIR" (Some(KFrontIRPhase.phaseName CORE_LOWERING)) None [] (DiagnosticFact.simple kind message)

        let sourceText =
            lazy (
                if System.IO.File.Exists(filePath) then
                    Some(SourceText.From(filePath, System.IO.File.ReadAllText(filePath)))
                else
                    None
            )

        let makeLocatedDiagnostic kind message location =
            { (makeDiagnostic kind message) with
                Location = location }

        let tokenMatchesName expectedName (token: Token) =
            Token.isName token
            && String.Equals(SyntaxFacts.trimIdentifierQuotes token.Text, expectedName, StringComparison.Ordinal)

        let tryFindHeaderBinderLocation binderName =
            definition.HeaderTokens
            |> List.tryFind (tokenMatchesName binderName)
            |> Option.bind (fun token ->
                sourceText.Value
                |> Option.map (fun source -> source.GetLocation(token.Span)))

        let tryFindArgumentLocation calleeName argument =
            let significantBodyTokens = significantTokens definition.BodyTokens |> List.toArray

            let findFollowingArgument argumentName =
                [ 0 .. significantBodyTokens.Length - 2 ]
                |> List.tryPick (fun index ->
                    if tokenMatchesName calleeName significantBodyTokens[index]
                       && tokenMatchesName argumentName significantBodyTokens[index + 1] then
                        sourceText.Value
                        |> Option.map (fun source -> source.GetLocation(significantBodyTokens[index + 1].Span))
                    else
                        None)

            match argument with
            | Name [ argumentName ] ->
                findFollowingArgument argumentName
                |> Option.orElseWith (fun () ->
                    significantBodyTokens
                    |> Array.tryFind (tokenMatchesName argumentName)
                    |> Option.bind (fun token ->
                        sourceText.Value
                        |> Option.map (fun source -> source.GetLocation(token.Span))))
            | InoutArgument(Name [ argumentName ]) ->
                findFollowingArgument argumentName
                |> Option.orElseWith (fun () ->
                    significantBodyTokens
                    |> Array.tryFind (tokenMatchesName argumentName)
                    |> Option.bind (fun token ->
                        sourceText.Value
                        |> Option.map (fun source -> source.GetLocation(token.Span))))
            | _ ->
                None

        let tupleParameterLocalTypes =
            effectiveParameters
            |> List.collect (fun parameter ->
                parameter.TypeTokens
                |> Option.map significantTokens
                |> Option.map splitTopLevelCommaGroups
                |> Option.map (fun groups ->
                    groups
                    |> List.skip 1
                    |> List.choose (fun group ->
                        match significantTokens group with
                        | nameToken :: colonToken :: typeTokens
                            when Token.isName nameToken && colonToken.Kind = Colon ->
                            typeTokens
                            |> TypeSignatures.parseType
                            |> Option.map (fun fieldType -> SyntaxFacts.trimIdentifierQuotes nameToken.Text, fieldType)
                        | _ ->
                            None))
                |> Option.defaultValue [])

        let recordParameterLocalTypes =
            effectiveParameters
            |> List.collect (fun parameter ->
                parameter.TypeTokens
                |> Option.bind tryParseRecordSurfaceInfo
                |> Option.map (fun recordInfo ->
                    recordInfo.Fields
                    |> List.choose (fun field ->
                        field.TypeTokens
                        |> TypeSignatures.parseType
                        |> Option.map (fun fieldType -> field.Name, fieldType)))
                |> Option.defaultValue [])

        let declaredParameterLocalTypes =
            buildLocalTypes effectiveScheme effectiveParameters
            |> Map.ofList

        let inoutReturnTypeContainsThreadedField parameterName resultType =
            let peeledResultType =
                tryUnwrapBindablePayloadType environment.VisibleTypeAliases resultType
                |> Option.defaultValue resultType
                |> normalizeTypeAliases environment.VisibleTypeAliases

            match peeledResultType with
            | TypeRecord fields ->
                fields
                |> List.exists (fun field ->
                    field.Quantity = QuantityOne
                    && String.Equals(field.Name, parameterName, StringComparison.Ordinal))
            | _ ->
                false

        let inoutDeclarationDiagnostics =
            let declaredResultType =
                effectiveScheme
                |> Option.map (fun bindingScheme -> TypeSignatures.schemeParts bindingScheme |> snd)
                |> Option.orElseWith (fun () ->
                    definition.ReturnTypeTokens
                    |> Option.bind TypeSignatures.parseType
                    |> Option.map (qualifyVisibleTypeNames environment))

            effectiveParameters
            |> List.filter (fun parameter -> parameter.IsInout)
            |> List.collect (fun parameter ->
                match declaredResultType with
                | Some resultType when inoutReturnTypeContainsThreadedField parameter.Name resultType ->
                    []
                | Some _ ->
                    [
                        makeLocatedDiagnostic
                            SimpleDiagnosticKind.QttInoutThreadedFieldMissing
                            $"An 'inout' parameter '{parameter.Name}' requires the result type to contain a quantity-1 field named '{parameter.Name}' after peeling any enclosing monad."
                            (tryFindHeaderBinderLocation parameter.Name)
                    ]
                | None ->
                    [])

        let bodyInferredNumericParameterTypes =
            let parameterNames =
                effectiveParameters
                |> List.map (fun parameter -> parameter.Name)
                |> Set.ofList

            let annotatedParameterLocals =
                effectiveParameters
                |> List.choose (fun parameter ->
                    tryParseParameterType parameter
                    |> Option.map (fun parameterType -> parameter.Name, parameterType))
                |> Map.ofList

            let normalize typeExpr =
                normalizeTypeAliases environment.VisibleTypeAliases typeExpr

            let isSupportedArithmeticType normalizedTypeExpr =
                match normalizedTypeExpr with
                | TypeName(nameSegments, []) when
                    matchesKnownType CompilerKnownSymbols.IntType nameSegments
                    || matchesKnownType CompilerKnownSymbols.FloatType nameSegments
                    || matchesKnownType CompilerKnownSymbols.DoubleType nameSegments ->
                    true
                | _ ->
                    false

            let tryInferNumericOperandType expression =
                match expression with
                | NumericLiteral literal ->
                    Some(inferSurfaceNumericLiteralType literal)
                | Unary("-", NumericLiteral literal) ->
                    Some(inferSurfaceNumericLiteralType literal)
                | _ ->
                    inferValidationExpressionType environment freshCounter annotatedParameterLocals expression
                    |> Option.map normalize
                    |> Option.filter isSupportedArithmeticType

            let addExpectation parameterName inferredType expectations =
                match Map.tryFind parameterName expectations with
                | Some existingType
                    when TypeSignatures.definitionallyEqual
                             (normalize existingType)
                             (normalize inferredType) ->
                    expectations
                | Some _ ->
                    expectations
                | None ->
                    Map.add parameterName inferredType expectations

            let rec walk expectations expression =
                let addFromOperand parameterExpression counterpart currentExpectations =
                    match parameterExpression with
                    | Name [ parameterName ]
                        when Set.contains parameterName parameterNames ->
                        match tryInferNumericOperandType counterpart with
                        | Some inferredType ->
                            addExpectation parameterName inferredType currentExpectations
                        | None ->
                            currentExpectations
                    | _ ->
                        currentExpectations

                let descend currentExpression currentExpectations =
                    walk currentExpectations currentExpression

                match expression with
                | Binary(left, ("+" | "-" | "*" | "/"), right) ->
                    expectations
                    |> addFromOperand left right
                    |> addFromOperand right left
                    |> descend left
                    |> descend right
                | Binary(left, _, right)
                | Elvis(left, right) ->
                    expectations |> descend left |> descend right
                | Apply(callee, arguments) ->
                    (descend callee expectations, arguments)
                    ||> List.fold (fun state argument -> descend argument state)
                | LocalLet(_, value, nestedBody) ->
                    expectations |> descend value |> descend nestedBody
                | LocalSignature(_, nestedBody)
                | LocalTypeAlias(_, nestedBody)
                | LocalScopedEffect(_, nestedBody)
                | Lambda(_, nestedBody)
                | SyntaxQuote nestedBody
                | SyntaxSplice nestedBody
                | TopLevelSyntaxSplice nestedBody
                | CodeQuote nestedBody
                | CodeSplice nestedBody
                | MonadicSplice nestedBody
                | ExplicitImplicitArgument nestedBody
                | InoutArgument nestedBody
                | Unary(_, nestedBody)
                | Seal(nestedBody, _)
                | TagTest(nestedBody, _) ->
                    descend nestedBody expectations
                | TypeSyntaxTokens _ ->
                    expectations
                | Handle(_, label, nestedBody, returnClause, operationClauses) ->
                    expectations
                    |> descend label
                    |> descend nestedBody
                    |> descend returnClause.Body
                    |> fun state ->
                        operationClauses
                        |> List.fold (fun clauseState clause -> descend clause.Body clauseState) state
                | IfThenElse(condition, whenTrue, whenFalse) ->
                    expectations
                    |> descend condition
                    |> descend whenTrue
                    |> descend whenFalse
                | Match(scrutinee, cases) ->
                    expectations
                    |> descend scrutinee
                    |> fun state ->
                        cases
                        |> List.fold
                            (fun caseState caseClause ->
                                caseState
                                |> fun innerState ->
                                    match caseClause.Guard with
                                    | Some guard -> descend guard innerState
                                    | None -> innerState
                                |> descend caseClause.Body)
                            state
                | RecordLiteral fields ->
                    fields |> List.fold (fun state field -> descend field.Value state) expectations
                | RecordUpdate(receiver, fields) ->
                    expectations
                    |> descend receiver
                    |> fun state -> fields |> List.fold (fun innerState field -> descend field.Value innerState) state
                | MemberAccess(receiver, _, arguments) ->
                    expectations
                    |> descend receiver
                    |> fun state -> arguments |> List.fold (fun innerState argument -> descend argument innerState) state
                | SafeNavigation(receiver, navigation) ->
                    expectations
                    |> descend receiver
                    |> fun state -> navigation.Arguments |> List.fold (fun innerState argument -> descend argument innerState) state
                | Do statements ->
                    statements
                    |> List.fold
                        (fun state statement ->
                            match statement with
                            | DoLet(_, value)
                            | DoBind(_, value)
                            | DoUsing(_, value)
                            | DoVar(_, value)
                            | DoAssign(_, value)
                            | DoDefer value
                            | DoExpression value
                            | DoReturn value ->
                                descend value state
                            | DoLetQuestion(_, value, failure) ->
                                let nextState = descend value state

                                match failure with
                                | Some block ->
                                    block.Body
                                    |> List.fold
                                        (fun innerState nestedStatement ->
                                            match nestedStatement with
                                            | DoLet(_, nestedValue)
                                            | DoBind(_, nestedValue)
                                            | DoUsing(_, nestedValue)
                                            | DoVar(_, nestedValue)
                                            | DoAssign(_, nestedValue)
                                            | DoDefer nestedValue
                                            | DoExpression nestedValue
                                            | DoReturn nestedValue ->
                                                descend nestedValue innerState
                                            | DoIf(condition, whenTrue, whenFalse) ->
                                                let afterCondition = descend condition innerState

                                                let descendDoBody bodyStatements bodyState =
                                                    bodyStatements
                                                    |> List.fold
                                                        (fun bodyInnerState bodyStatement ->
                                                            match bodyStatement with
                                                            | DoLet(_, bodyValue)
                                                            | DoBind(_, bodyValue)
                                                            | DoUsing(_, bodyValue)
                                                            | DoVar(_, bodyValue)
                                                            | DoAssign(_, bodyValue)
                                                            | DoDefer bodyValue
                                                            | DoExpression bodyValue
                                                            | DoReturn bodyValue ->
                                                                descend bodyValue bodyInnerState
                                                            | _ ->
                                                                bodyInnerState)
                                                        bodyState

                                                afterCondition |> descendDoBody whenTrue |> descendDoBody whenFalse
                                            | _ ->
                                                innerState)
                                        nextState
                                | None ->
                                    nextState
                            | DoIf(condition, whenTrue, whenFalse) ->
                                let nextState = descend condition state

                                let descendDoBody bodyStatements bodyState =
                                    bodyStatements
                                    |> List.fold
                                        (fun innerState nestedStatement ->
                                            match nestedStatement with
                                            | DoLet(_, nestedValue)
                                            | DoBind(_, nestedValue)
                                            | DoUsing(_, nestedValue)
                                            | DoVar(_, nestedValue)
                                            | DoAssign(_, nestedValue)
                                            | DoDefer nestedValue
                                            | DoExpression nestedValue
                                            | DoReturn nestedValue ->
                                                descend nestedValue innerState
                                            | _ ->
                                                innerState)
                                        bodyState

                                nextState |> descendDoBody whenTrue |> descendDoBody whenFalse
                            | DoWhile(condition, doBody) ->
                                let nextState = descend condition state

                                doBody
                                |> List.fold
                                    (fun innerState nestedStatement ->
                                        match nestedStatement with
                                        | DoLet(_, nestedValue)
                                        | DoBind(_, nestedValue)
                                        | DoUsing(_, nestedValue)
                                        | DoVar(_, nestedValue)
                                        | DoAssign(_, nestedValue)
                                        | DoDefer nestedValue
                                        | DoExpression nestedValue
                                        | DoReturn nestedValue ->
                                            descend nestedValue innerState
                                        | _ ->
                                            innerState)
                                    nextState)
                        expectations
                | Comprehension comprehension ->
                    descend comprehension.Lowered expectations
                | PrefixedString(_, parts) ->
                    parts
                    |> List.fold
                        (fun state part ->
                            match part with
                            | StringText _ -> state
                            | StringInterpolation(inner, _) -> descend inner state)
                        expectations
                | NamedApplicationBlock fields ->
                    fields |> List.fold (fun state field -> descend field.Value state) expectations
                | Literal _
                | NumericLiteral _
                | KindQualifiedName _
                | Name _ ->
                    expectations

            effectiveBody
            |> Option.map (walk Map.empty)
            |> Option.defaultValue Map.empty

        let inferredParameterLocalTypes =
            bodyInferredNumericParameterTypes
            |> Map.toList
            |> List.filter (fun (name, _) -> not (Map.containsKey name declaredParameterLocalTypes))

        let localTypes =
            (inferredParameterLocalTypes @ tupleParameterLocalTypes @ recordParameterLocalTypes)
            |> List.fold (fun state (name, fieldType) -> Map.add name fieldType state) declaredParameterLocalTypes

        let parameterNames =
            [ effectiveParameters |> List.map (fun parameter -> parameter.Name)
              inferredParameterLocalTypes |> List.map fst
              tupleParameterLocalTypes |> List.map fst
              recordParameterLocalTypes |> List.map fst ]
            |> List.concat
            |> Set.ofList

        let preludeContract = IntrinsicCatalog.bundledPreludeExpectContract ()
        let standardRuntimeNames =
            Set.ofList
                [ "bindModule"; "bindModuleOwned"; "bridgePackageValue"; "bridgePackageOrigin"; "bridgeFailureToCastBlame"
                  "checkedCast"; "checkedCastWith"; "sameDynRep"; "toDyn"; "toDynWith"
                  "Conservative"; "Exact"; "IntoKappa"; "LaterUse"; "Lossy"; "OutOfKappa" ]

        let compilerKnownSurfaceTerms =
            Set.ofList
                [ "thunk"
                  "lazy"
                  "force"
                  "captureBorrow"
                  "withBorrowView"
                  "break"
                  "continue"
                  "fork"
                  "defEqSyntax"
                  "headSymbolSyntax"
                  "sameSymbol" ]

        let visibleTraitMemberNames =
            environment.VisibleTraits
            |> Map.values
            |> Seq.collect (fun traitInfo -> traitInfo.Members.Keys)
            |> Set.ofSeq

        let knownValueNames =
            [ preludeContract.TermNames
              Set.ofList Stdlib.FixedPreludeConstructors
              IntrinsicCatalog.namedIntrinsicTermNames ()
              standardRuntimeNames
              compilerKnownSurfaceTerms
              environment.VisibleBindings |> Map.keys |> Set.ofSeq
              environment.VisibleConstructors |> Map.keys |> Set.ofSeq
              visibleTraitMemberNames
              environment.ConstrainedMembers |> Map.keys |> Set.ofSeq ]
            |> Set.unionMany
            |> Set.remove "<anonymous>"

        let knownTermLikeNames =
            [ knownSurfaceTermNames
              knownValueNames
              topLevelDefinitionsByName |> Map.keys |> Set.ofSeq
              explicitSignatureNames
              environment.VisibleProjections |> Map.keys |> Set.ofSeq ]
            |> Set.unionMany
            |> fun names ->
                Set.difference
                    names
                    (environment.VisibleModulePaths
                     |> Map.keys
                     |> Seq.choose (function
                         | [ root ] -> Some root
                         | _ -> None)
                     |> Set.ofSeq)
            |> Set.remove "<anonymous>"

        let makeDiagnostic kind message =
            Diagnostics.errorFact "KFrontIR" (Some(KFrontIRPhase.phaseName CORE_LOWERING)) None [] (DiagnosticFact.simple kind message)

        let makeSurfaceElaborationDiagnostic evidence =
            Diagnostics.errorFact
                "KFrontIR"
                (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                None
                []
                (DiagnosticFact.surfaceElaboration evidence)

        let makeTraitConstraintUnresolvedDiagnostic constraintInfo =
            makeSurfaceElaborationDiagnostic
                (TraitConstraintUnresolved(renderTraitConstraint environment constraintInfo))

        let makeImplicitTraitConstraintUnresolvedDiagnostic constraintInfo =
            makeSurfaceElaborationDiagnostic
                (ImplicitTraitConstraintUnresolved(renderTraitConstraint environment constraintInfo))

        let makeTraitConstraintAmbiguousDiagnostic ambiguousGoal candidates =
            let candidateText =
                candidates
                |> List.map renderInstanceCandidate

            makeSurfaceElaborationDiagnostic
                (TraitConstraintAmbiguous(renderTraitConstraint environment ambiguousGoal, candidateText))

        let makeNameUnresolvedDiagnostic name =
            Diagnostics.errorFact
                "KFrontIR"
                (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                None
                []
                (DiagnosticFact.nameUnresolved name)

        let tryVisibleOrdinaryTermAmbiguityCandidates localName =
            environment.VisibleOrdinaryGroups
            |> Map.tryFind localName
            |> Option.bind (fun group ->
                match resolveVisibleOrdinaryTermGroup group with
                | Some(VisibleOrdinaryAmbiguous candidates) -> Some candidates
                | _ -> None)

        let tryVisiblePatternHeadAmbiguityCandidates localName =
            tryVisibleOrdinaryTermAmbiguityCandidates localName
            |> Option.bind (fun candidates ->
                let admissible =
                    candidates
                    |> List.filter (function
                        | OrdinaryVisibleConstructorCandidate _ -> true
                        | OrdinaryVisibleBindingCandidate(_, info) when info.IsPattern -> true
                        | _ -> false)

                if List.length admissible > 1 then Some admissible else None)

        let ordinaryNameAmbiguityDiagnostic name candidates =
            Diagnostics.errorFact
                "KFrontIR"
                (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                None
                []
                (DiagnosticFact.nameAmbiguous name (candidates |> List.map renderOrdinaryVisibleTermCandidate))

        let declaredParameterContextConflictDiagnostics =
            bodyInferredNumericParameterTypes
            |> Map.toList
            |> List.choose (fun (parameterName, inferredType) ->
                declaredParameterLocalTypes
                |> Map.tryFind parameterName
                |> Option.bind (fun declaredType ->
                    let normalizedDeclaredType = normalizeTypeAliases environment.VisibleTypeAliases declaredType
                    let normalizedInferredType = normalizeTypeAliases environment.VisibleTypeAliases inferredType

                    match normalizedDeclaredType with
                    | TypeVariable _
                        when not (TypeSignatures.definitionallyEqual normalizedDeclaredType normalizedInferredType) ->
                        Some(
                            makeDiagnostic
                                SimpleDiagnosticKind.TypeEqualityMismatch
                                $"Parameter '{parameterName}' is used in a numeric context that requires '{TypeSignatures.toText inferredType}', but its declared type is '{TypeSignatures.toText declaredType}'."
                        )
                    | _ ->
                        None))

        let tryInstantiateVisibleBindingType name =
            let instantiate (bindingInfo: BindingSchemeInfo) =
                let probe = ref freshCounter.Value
                let instance = TypeSignatures.instantiate "t" probe.Value bindingInfo.Scheme
                snd (TypeSignatures.schemeParts instance)

            environment.VisibleBindings
            |> Map.tryFind name
            |> Option.map instantiate
            |> Option.orElseWith (fun () ->
                environment.VisibleConstructors
                |> Map.tryFind name
                |> Option.map instantiate)

        let rec tryInferExpressionTypeWithSiblingFallback
            (visitedTopLevelNames: Set<string>)
            (localTypes: Map<string, TypeExpr>)
            (expression: SurfaceExpression)
            =
            inferValidationExpressionType environment (ref freshCounter.Value) localTypes expression
            |> Option.orElseWith (fun () ->
                match expression with
                | Name [ name ] ->
                    Map.tryFind name localTypes
                    |> Option.orElseWith (fun () -> tryInferSiblingBindingType visitedTopLevelNames name)
                | Apply(Name [ calleeName ], arguments) ->
                    tryInferExpressionTypeWithSiblingFallback visitedTopLevelNames localTypes (Name [ calleeName ])
                    |> Option.bind (fun calleeType ->
                        tryInferVisibleAppliedType
                            environment.VisibleTypeAliases
                            (qualifyVisibleTypeNames environment)
                            (fun argument ->
                                tryInferExpressionTypeWithSiblingFallback visitedTopLevelNames localTypes argument)
                            calleeType
                            arguments)
                    |> Option.orElseWith (fun () ->
                        tryInferSiblingApplicationResultType
                            visitedTopLevelNames
                            localTypes
                            calleeName
                            arguments)
                | Binary(left, ("+" | "-" | "*" | "/"), right) ->
                    match
                        tryInferExpressionTypeWithSiblingFallback visitedTopLevelNames localTypes left,
                        tryInferExpressionTypeWithSiblingFallback visitedTopLevelNames localTypes right
                    with
                    | Some leftType, Some rightType
                        when TypeSignatures.definitionallyEqual
                                 (normalizeTypeAliases environment.VisibleTypeAliases leftType)
                                 intType
                             && TypeSignatures.definitionallyEqual
                                 (normalizeTypeAliases environment.VisibleTypeAliases rightType)
                                 intType ->
                        Some intType
                    | Some leftType, Some rightType
                        when TypeSignatures.definitionallyEqual
                                 (normalizeTypeAliases environment.VisibleTypeAliases leftType)
                                 floatType
                             && TypeSignatures.definitionallyEqual
                                 (normalizeTypeAliases environment.VisibleTypeAliases rightType)
                                 floatType ->
                        Some floatType
                    | _ ->
                        None
                | Do statements ->
                    tryInferDoResultTypeWithSiblingFallback visitedTopLevelNames localTypes statements
                | _ ->
                    None)

        and tryInferDoResultTypeWithSiblingFallback
            (visitedTopLevelNames: Set<string>)
            (localTypes: Map<string, TypeExpr>)
            (statements: SurfaceDoStatement list)
            =
            match statements with
            | [] ->
                Some unitType
            | DoExpression expression :: [] ->
                tryInferExpressionTypeWithSiblingFallback visitedTopLevelNames localTypes expression
                |> Option.map unwrapIoType
            | DoExpression _ :: rest ->
                tryInferDoResultTypeWithSiblingFallback visitedTopLevelNames localTypes rest
            | DoLet(binding, expression) :: rest ->
                let nextLocals =
                    tryInferExpressionTypeWithSiblingFallback visitedTopLevelNames localTypes expression
                    |> Option.map (fun valueType ->
                        extendPatternLocalTypes
                            environment
                            (ref freshCounter.Value)
                            localTypes
                            (Some valueType)
                            binding.Pattern)
                    |> Option.defaultValue localTypes

                tryInferDoResultTypeWithSiblingFallback visitedTopLevelNames nextLocals rest
            | DoLetQuestion(binding, expression, failure) :: rest ->
                let nextLocals =
                    tryInferExpressionTypeWithSiblingFallback visitedTopLevelNames localTypes expression
                    |> Option.map (fun valueType ->
                        extendPatternLocalTypes
                            environment
                            (ref freshCounter.Value)
                            localTypes
                            (Some valueType)
                            binding.Pattern)
                    |> Option.defaultValue localTypes

                failure
                |> Option.iter (fun failureBlock ->
                    tryInferDoResultTypeWithSiblingFallback visitedTopLevelNames localTypes failureBlock.Body
                    |> ignore)

                tryInferDoResultTypeWithSiblingFallback visitedTopLevelNames nextLocals rest
            | DoBind(binding, expression) :: rest ->
                let nextLocals =
                    tryInferExpressionTypeWithSiblingFallback visitedTopLevelNames localTypes expression
                    |> Option.bind (tryUnwrapBindablePayloadType environment.VisibleTypeAliases)
                    |> Option.map (fun payloadType ->
                        extendPatternLocalTypes
                            environment
                            (ref freshCounter.Value)
                            localTypes
                            (Some payloadType)
                            binding.Pattern)
                    |> Option.defaultValue localTypes

                tryInferDoResultTypeWithSiblingFallback visitedTopLevelNames nextLocals rest
            | DoUsing(binding, expression) :: rest ->
                let nextLocals =
                    tryInferExpressionTypeWithSiblingFallback visitedTopLevelNames localTypes expression
                    |> Option.map (fun valueType ->
                        extendPatternLocalTypes
                            environment
                            (ref freshCounter.Value)
                            localTypes
                            (Some(unwrapIoType valueType))
                            binding.Pattern)
                    |> Option.defaultValue localTypes

                tryInferDoResultTypeWithSiblingFallback visitedTopLevelNames nextLocals rest
            | DoVar(bindingName, expression) :: rest ->
                let nextLocals =
                    match tryInferExpressionTypeWithSiblingFallback visitedTopLevelNames localTypes expression with
                    | Some valueType -> Map.add bindingName (refType valueType) localTypes
                    | None -> localTypes

                tryInferDoResultTypeWithSiblingFallback visitedTopLevelNames nextLocals rest
            | DoAssign _ :: rest
            | DoDefer _ :: rest
            | DoIf _ :: rest
            | DoWhile _ :: rest ->
                tryInferDoResultTypeWithSiblingFallback visitedTopLevelNames localTypes rest
            | DoReturn expression :: _ ->
                tryInferExpressionTypeWithSiblingFallback visitedTopLevelNames localTypes expression

        and tryInferSiblingApplicationResultType
            (visitedTopLevelNames: Set<string>)
            (localTypes: Map<string, TypeExpr>)
            calleeName
            (arguments: SurfaceExpression list)
            =
            let hasApplicationOnlyArgument =
                arguments
                |> List.exists (function
                    | ExplicitImplicitArgument _
                    | NamedApplicationBlock _ -> true
                    | _ -> false)

            if Set.contains calleeName visitedTopLevelNames || hasApplicationOnlyArgument then
                None
            else
                topLevelDefinitionsByName
                |> Map.tryFind calleeName
                |> Option.bind (fun siblingDefinition ->
                    siblingDefinition.Body
                    |> Option.bind (fun siblingBody ->
                        let nextVisited = Set.add calleeName visitedTopLevelNames
                        let parameters = siblingDefinition.Parameters

                        if List.length arguments > List.length parameters then
                            None
                        else
                            let bodyInferredParameterTypes =
                                tryInferSiblingParameterTypesFromNumericUse nextVisited parameters siblingBody

                            let explicitArgumentTypes =
                                arguments
                                |> List.map (tryInferExpressionTypeWithSiblingFallback visitedTopLevelNames localTypes)

                            if explicitArgumentTypes |> List.exists Option.isNone then
                                None
                            else
                                let explicitArgumentTypes = explicitArgumentTypes |> List.choose id
                                let remainingParameters = parameters |> List.skip arguments.Length

                                let remainingParameterTypes =
                                    remainingParameters
                                    |> List.map (fun parameter ->
                                        tryParseParameterType parameter
                                        |> Option.orElseWith (fun () -> Map.tryFind parameter.Name bodyInferredParameterTypes))

                                if remainingParameterTypes |> List.exists Option.isNone then
                                    None
                                else
                                    let remainingParameterTypes = remainingParameterTypes |> List.choose id
                                    let allParameterTypes = explicitArgumentTypes @ remainingParameterTypes

                                    let siblingLocals =
                                        List.zip parameters allParameterTypes
                                        |> List.fold (fun state (parameter, parameterType) ->
                                            Map.add parameter.Name parameterType state) Map.empty

                                    tryInferExpressionTypeWithSiblingFallback nextVisited siblingLocals siblingBody
                                    |> Option.map (fun resultType ->
                                        List.zip remainingParameters remainingParameterTypes
                                        |> List.rev
                                        |> List.fold
                                            (fun current (parameter, parameterType) ->
                                                TypeArrow(parameter.Quantity |> Option.defaultValue QuantityOmega, parameterType, current))
                                            resultType)))

        and tryInferSiblingParameterTypesFromNumericUse
            (visitedTopLevelNames: Set<string>)
            (parameters: Parameter list)
            (body: SurfaceExpression)
            =
            let parameterNames =
                parameters
                |> List.map (fun parameter -> parameter.Name)
                |> Set.ofList

            let annotatedLocals =
                parameters
                |> List.choose (fun parameter ->
                    tryParseParameterType parameter
                    |> Option.map (fun parameterType -> parameter.Name, parameterType))
                |> Map.ofList

            let normalize typeExpr =
                normalizeTypeAliases environment.VisibleTypeAliases typeExpr

            let isSupportedArithmeticType normalizedTypeExpr =
                match normalizedTypeExpr with
                | TypeName(nameSegments, []) when
                    matchesKnownType CompilerKnownSymbols.IntType nameSegments
                    || matchesKnownType CompilerKnownSymbols.FloatType nameSegments
                    || matchesKnownType CompilerKnownSymbols.DoubleType nameSegments ->
                    true
                | _ ->
                    false

            let tryInferNumericOperandType expression =
                match expression with
                | NumericLiteral literal ->
                    Some(inferSurfaceNumericLiteralType literal)
                | Unary("-", NumericLiteral literal) ->
                    Some(inferSurfaceNumericLiteralType literal)
                | _ ->
                    tryInferExpressionTypeWithSiblingFallback visitedTopLevelNames annotatedLocals expression
                    |> Option.map normalize
                    |> Option.filter isSupportedArithmeticType

            let addExpectation parameterName inferredType expectations =
                match Map.tryFind parameterName expectations with
                | Some existingType
                    when TypeSignatures.definitionallyEqual
                             (normalize existingType)
                             (normalize inferredType) ->
                    expectations
                | Some _ ->
                    expectations
                | None ->
                    Map.add parameterName inferredType expectations

            let rec walk expectations expression =
                let addFromOperand parameterExpression counterpart currentExpectations =
                    match parameterExpression with
                    | Name [ parameterName ] when Set.contains parameterName parameterNames ->
                        match tryInferNumericOperandType counterpart with
                        | Some inferredType ->
                            addExpectation parameterName inferredType currentExpectations
                        | None ->
                            currentExpectations
                    | _ ->
                        currentExpectations

                let descend currentExpression currentExpectations =
                    walk currentExpectations currentExpression

                match expression with
                | Binary(left, ("+" | "-" | "*" | "/"), right) ->
                    expectations
                    |> addFromOperand left right
                    |> addFromOperand right left
                    |> descend left
                    |> descend right
                | Binary(left, _, right) ->
                    expectations |> descend left |> descend right
                | Apply(callee, arguments) ->
                    (descend callee expectations, arguments)
                    ||> List.fold (fun state argument -> descend argument state)
                | LocalLet(_, value, nestedBody) ->
                    expectations |> descend value |> descend nestedBody
                | LocalSignature(_, nestedBody)
                | LocalTypeAlias(_, nestedBody)
                | LocalScopedEffect(_, nestedBody)
                | Lambda(_, nestedBody)
                | SyntaxQuote nestedBody
                | SyntaxSplice nestedBody
                | TopLevelSyntaxSplice nestedBody
                | CodeQuote nestedBody
                | CodeSplice nestedBody
                | MonadicSplice nestedBody
                | ExplicitImplicitArgument nestedBody
                | InoutArgument nestedBody
                | Unary(_, nestedBody)
                | Seal(nestedBody, _)
                | TagTest(nestedBody, _) ->
                    descend nestedBody expectations
                | TypeSyntaxTokens _ ->
                    expectations
                | Handle(_, label, nestedBody, returnClause, operationClauses) ->
                    expectations
                    |> descend label
                    |> descend nestedBody
                    |> descend returnClause.Body
                    |> fun state ->
                        operationClauses
                        |> List.fold (fun clauseState clause -> descend clause.Body clauseState) state
                | IfThenElse(condition, whenTrue, whenFalse) ->
                    expectations
                    |> descend condition
                    |> descend whenTrue
                    |> descend whenFalse
                | Match(scrutinee, cases) ->
                    expectations
                    |> descend scrutinee
                    |> fun state ->
                        cases
                        |> List.fold
                            (fun caseState caseClause ->
                                caseState
                                |> fun innerState ->
                                    match caseClause.Guard with
                                    | Some guard -> descend guard innerState
                                    | None -> innerState
                                |> descend caseClause.Body)
                            state
                | RecordLiteral fields ->
                    fields |> List.fold (fun state field -> descend field.Value state) expectations
                | RecordUpdate(receiver, fields) ->
                    expectations
                    |> descend receiver
                    |> fun state -> fields |> List.fold (fun innerState field -> descend field.Value innerState) state
                | MemberAccess(receiver, _, arguments) ->
                    expectations
                    |> descend receiver
                    |> fun state -> arguments |> List.fold (fun innerState argument -> descend argument innerState) state
                | SafeNavigation(receiver, navigation) ->
                    expectations
                    |> descend receiver
                    |> fun state -> navigation.Arguments |> List.fold (fun innerState argument -> descend argument innerState) state
                | Do statements ->
                    statements
                    |> List.fold
                        (fun state statement ->
                            match statement with
                            | DoLet(_, value)
                            | DoBind(_, value)
                            | DoUsing(_, value)
                            | DoVar(_, value)
                            | DoAssign(_, value)
                            | DoDefer value
                            | DoExpression value
                            | DoReturn value ->
                                descend value state
                            | DoLetQuestion(_, value, failure) ->
                                let nextState = descend value state

                                match failure with
                                | Some block ->
                                    block.Body |> List.fold (fun innerState nested -> walk innerState (Do [ nested ])) nextState
                                | None ->
                                    nextState
                            | DoIf(condition, whenTrue, whenFalse) ->
                                let nextState = descend condition state
                                let descendDoBody bodyStatements bodyState =
                                    bodyStatements |> List.fold (fun innerState nested -> walk innerState (Do [ nested ])) bodyState

                                nextState
                                |> descendDoBody whenTrue
                                |> descendDoBody whenFalse
                            | DoWhile(condition, doBody) ->
                                let nextState = descend condition state
                                doBody |> List.fold (fun innerState nested -> walk innerState (Do [ nested ])) nextState)
                        expectations
                | Elvis(left, right) ->
                    expectations |> descend left |> descend right
                | Comprehension comprehension ->
                    descend comprehension.Lowered expectations
                | PrefixedString(_, parts) ->
                    parts
                    |> List.fold
                        (fun state part ->
                            match part with
                            | StringText _ -> state
                            | StringInterpolation(inner, _) -> descend inner state)
                        expectations
                | NamedApplicationBlock fields ->
                    fields |> List.fold (fun state field -> descend field.Value state) expectations
                | Literal _
                | NumericLiteral _
                | KindQualifiedName _
                | Name _ ->
                    expectations

            walk Map.empty body

        and tryInferSiblingBindingType (visitedTopLevelNames: Set<string>) name =
            if Set.contains name visitedTopLevelNames then
                None
            else
                let inferFromSiblingDefinition () =
                    topLevelDefinitionsByName
                    |> Map.tryFind name
                    |> Option.bind (fun siblingDefinition ->
                        siblingDefinition.Body
                        |> Option.bind (fun siblingBody ->
                            let nextVisited = Set.add name visitedTopLevelNames

                            match siblingDefinition.Parameters with
                            | [] ->
                                tryInferExpressionTypeWithSiblingFallback nextVisited Map.empty siblingBody
                            | parameters ->
                                let bodyInferredParameterTypes =
                                    tryInferSiblingParameterTypesFromNumericUse nextVisited parameters siblingBody

                                let parameterTypes =
                                    parameters
                                    |> List.map (fun parameter ->
                                        tryParseParameterType parameter
                                        |> Option.orElseWith (fun () -> Map.tryFind parameter.Name bodyInferredParameterTypes))

                                if parameterTypes |> List.exists Option.isNone then
                                    None
                                else
                                    let parameterTypes = parameterTypes |> List.choose id
                                    let siblingLocals =
                                        List.zip parameters parameterTypes
                                        |> List.fold (fun state (parameter, parameterType) ->
                                            Map.add parameter.Name parameterType state) Map.empty

                                    tryInferExpressionTypeWithSiblingFallback nextVisited siblingLocals siblingBody
                                    |> Option.map (fun resultType ->
                                        List.zip parameters parameterTypes
                                        |> List.rev
                                        |> List.fold
                                            (fun current (parameter, parameterType) ->
                                                TypeArrow(parameter.Quantity |> Option.defaultValue QuantityOmega, parameterType, current))
                                            resultType)))

                let siblingDefinitionShadowsVisibleBinding =
                    topLevelDefinitionsByName.ContainsKey name

                if Set.contains name explicitSignatureNames then
                    tryInstantiateVisibleBindingType name
                    |> Option.orElseWith inferFromSiblingDefinition
                elif siblingDefinitionShadowsVisibleBinding then
                    inferFromSiblingDefinition ()
                else
                    inferFromSiblingDefinition ()
                    |> Option.orElseWith (fun () -> tryInstantiateVisibleBindingType name)

        let typeIsMetaPhaseTransferType typeExpr =
            let normalized = normalizeTypeAliases environment.VisibleTypeAliases typeExpr

            match normalized with
            | TypeName(nameSegments, [ _ ]) when
                matchesKnownType CompilerKnownSymbols.SyntaxType nameSegments
                || matchesKnownType CompilerKnownSymbols.ElabType nameSegments
                || matchesKnownType CompilerKnownSymbols.CodeType nameSegments
                || matchesKnownType CompilerKnownSymbols.ClosedCodeType nameSegments
                || matchesKnownType CompilerKnownSymbols.ComprehensionPlanType nameSegments ->
                true
            | TypeName(nameSegments, []) when
                matchesKnownType CompilerKnownSymbols.SyntaxOriginType nameSegments
                || matchesKnownType CompilerKnownSymbols.SyntaxFragmentType nameSegments
                || matchesKnownType CompilerKnownSymbols.ElabGoalType nameSegments ->
                true
            | _ ->
                isCompileTimeArgumentType environment.VisibleTypeAliases normalized

        let rec typeMentionsMacroReflectionType typeExpr =
            let normalized = normalizeTypeAliases environment.VisibleTypeAliases typeExpr

            match normalized with
            | TypeName(nameSegments, [ _ ]) when
                matchesKnownType CompilerKnownSymbols.SyntaxType nameSegments
                || matchesKnownType CompilerKnownSymbols.ElabType nameSegments
                || matchesKnownType CompilerKnownSymbols.CodeType nameSegments
                || matchesKnownType CompilerKnownSymbols.ClosedCodeType nameSegments ->
                true
            | TypeName(nameSegments, []) when
                matchesKnownType CompilerKnownSymbols.SyntaxOriginType nameSegments
                || matchesKnownType CompilerKnownSymbols.SyntaxFragmentType nameSegments
                || matchesKnownType CompilerKnownSymbols.ElabGoalType nameSegments ->
                true
            | TypeArrow(_, parameterType, resultType) ->
                typeMentionsMacroReflectionType parameterType
                || typeMentionsMacroReflectionType resultType
            | TypeApply(callee, arguments) ->
                typeMentionsMacroReflectionType callee
                || (arguments |> List.exists typeMentionsMacroReflectionType)
            | TypeLambda(_, parameterSort, body) ->
                typeMentionsMacroReflectionType parameterSort
                || typeMentionsMacroReflectionType body
            | TypeDelay inner
            | TypeMemo inner
            | TypeForce inner ->
                typeMentionsMacroReflectionType inner
            | TypeProject(receiver, _) ->
                typeMentionsMacroReflectionType receiver
            | TypeCapture(baseType, _) ->
                typeMentionsMacroReflectionType baseType
            | TypeRecord fields ->
                fields |> List.exists (fun field -> typeMentionsMacroReflectionType field.Type)
            | TypeEffectRow(entries, tail) ->
                (entries
                 |> List.exists (fun entry ->
                     typeMentionsMacroReflectionType entry.Label
                     || typeMentionsMacroReflectionType entry.Effect))
                || (tail |> Option.exists typeMentionsMacroReflectionType)
            | TypeUnion options ->
                options |> List.exists typeMentionsMacroReflectionType
            | TypeEquality(left, right) ->
                typeMentionsMacroReflectionType left
                || typeMentionsMacroReflectionType right
            | TypeName(_, arguments) ->
                arguments |> List.exists typeMentionsMacroReflectionType
            | TypeVariable _
            | TypeLevelLiteral _
            | TypeUniverse _
            | TypeIntrinsic _ ->
                false

        let tryInferPureElabResultType locals expression =
            let isPureElabPayloadType typeExpr =
                match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
                | TypeName(nameSegments, [ _ ]) when
                    matchesKnownType CompilerKnownSymbols.SyntaxType nameSegments
                    || matchesKnownType CompilerKnownSymbols.CodeType nameSegments
                    || matchesKnownType CompilerKnownSymbols.ClosedCodeType nameSegments ->
                    true
                | TypeName(nameSegments, []) when
                    matchesKnownType CompilerKnownSymbols.SyntaxOriginType nameSegments
                    || matchesKnownType CompilerKnownSymbols.SyntaxFragmentType nameSegments ->
                    true
                | _ when tryInterpolatedMacroResultType environment.VisibleTypeAliases typeExpr |> Option.isSome ->
                    true
                | _ ->
                    false

            match expression with
            | Apply(Name [ "pure" ], [ argument ]) ->
                inferValidationExpressionType environment freshCounter locals argument
                |> Option.filter isPureElabPayloadType
                |> Option.map elabType
            | _ ->
                None

        let tryInferMacroAwareValidationType locals expression =
            tryInferPureElabResultType locals expression
            |> Option.orElseWith (fun () -> inferValidationExpressionType environment freshCounter locals expression)

        let tryInferTopLevelSpliceResultType locals expression =
            inferValidationExpressionType environment freshCounter locals expression
            |> Option.bind (tryUnwrapTopLevelSyntaxSpliceType environment.VisibleTypeAliases)
            |> Option.orElseWith (fun () ->
                tryInferPureElabResultType locals expression
                |> Option.bind (tryUnwrapTopLevelSyntaxSpliceType environment.VisibleTypeAliases))

        let tryResolveVisibleCallable name =
            environment.VisibleBindings
            |> Map.tryFind name
            |> Option.orElseWith (fun () -> environment.VisibleConstructors |> Map.tryFind name)

        let tryInstantiateVisibleCallableScheme name =
            tryResolveVisibleCallable name
            |> Option.map (fun bindingInfo ->
                let probe = ref freshCounter.Value
                TypeSignatures.instantiate "v" probe.Value bindingInfo.Scheme)

        let tryInferCallableElabResult name =
            tryInstantiateVisibleCallableScheme name
            |> Option.bind (fun instantiated ->
                instantiated
                |> TypeSignatures.schemeParts
                |> snd
                |> tryUnwrapElabType environment.VisibleTypeAliases)

        let rec patternIsDefinitelyIrrefutable pattern =
            match pattern with
            | WildcardPattern
            | NamePattern _ ->
                true
            | AsPattern(_, inner)
            | TypedPattern(inner, _) ->
                patternIsDefinitelyIrrefutable inner
            | TuplePattern elements ->
                elements |> List.forall patternIsDefinitelyIrrefutable
            | AnonymousRecordPattern(fields, rest) ->
                let fieldsIrrefutable =
                    fields |> List.forall (fun field -> patternIsDefinitelyIrrefutable field.Pattern)

                let restIrrefutable =
                    match rest with
                    | Some DiscardRecordPatternRest
                    | Some(BindRecordPatternRest _) -> true
                    | None -> true

                fieldsIrrefutable && restIrrefutable
            | LiteralPattern _
            | ConstructorPattern _
            | NamedConstructorPattern _
            | VariantPattern _
            | OrPattern _ ->
                false

        let tryResolveTraitConstraint typeExpr traitName =
            resolveConstraintInstanceWithSubstitution environment (unqualifiedTraitConstraint traitName [ typeExpr ])
            |> Option.map (fun (instanceInfo, substitution) ->
                instanceInfo,
                substitution)

        let tryParseInstanceAssociatedType substitution (instanceInfo: InstanceInfo) memberName =
            instanceInfo.Members
            |> Map.tryFind memberName
            |> Option.bind (fun memberDefinition ->
                memberDefinition.ReturnTypeTokens
                |> Option.bind TypeSignatures.parseType
                |> Option.orElseWith (fun () -> TypeSignatures.parseType memberDefinition.BodyTokens))
            |> Option.map (TypeSignatures.applySubstitution substitution)

        let tryParseInterpolatedMacroGoal body =
            let rec loop current =
                match current with
                | Apply(Name [ "pure" ], [ inner ]) ->
                    loop inner
                | Apply(Name [ "summonDict" ], [ argument ]) ->
                    tryParseTypeLikeSurfaceExpression argument
                    |> Option.bind (function
                        | TypeName(nameSegments, [ resultType ]) when nameSegments |> List.tryLast = Some "InterpolatedMacro" ->
                            Some resultType
                        | _ ->
                            None)
                | _ ->
                    None

            loop body

        let tryExtractFailElabDiagnosticEvidence body =
            let rec fromExpression current =
                match current with
                | Apply(Name [ "failElabWith" ], [ Literal(LiteralValue.String code); Literal(LiteralValue.String message); _ ]) ->
                    Some(ElaborationFailureFromFailElabWith(code, message))
                | Apply(Name [ calleeName ], arguments) ->
                    topLevelDefinitionsByName
                    |> Map.tryFind calleeName
                    |> Option.bind (fun definition -> definition.Body |> Option.bind fromExpression)
                    |> Option.orElseWith (fun () -> arguments |> List.tryPick fromExpression)
                | Apply(callee, arguments) ->
                    fromExpression callee
                    |> Option.orElseWith (fun () -> arguments |> List.tryPick fromExpression)
                | Do statements ->
                    statements |> List.tryPick fromDoStatement
                | LocalLet(_, value, inner) ->
                    fromExpression value |> Option.orElseWith (fun () -> fromExpression inner)
                | LocalSignature(_, inner)
                | LocalTypeAlias(_, inner)
                | LocalScopedEffect(_, inner)
                | SyntaxQuote inner
                | SyntaxSplice inner
                | TopLevelSyntaxSplice inner
                | CodeQuote inner
                | CodeSplice inner
                | MonadicSplice inner
                | ExplicitImplicitArgument inner
                | InoutArgument inner
                | Unary(_, inner) ->
                    fromExpression inner
                | TypeSyntaxTokens _ ->
                    None
                | IfThenElse(condition, whenTrue, whenFalse) ->
                    fromExpression condition
                    |> Option.orElseWith (fun () -> fromExpression whenTrue)
                    |> Option.orElseWith (fun () -> fromExpression whenFalse)
                | Handle(_, label, handledBody, returnClause, operationClauses) ->
                    fromExpression label
                    |> Option.orElseWith (fun () -> fromExpression handledBody)
                    |> Option.orElseWith (fun () -> fromExpression returnClause.Body)
                    |> Option.orElseWith (fun () -> operationClauses |> List.tryPick (fun clause -> fromExpression clause.Body))
                | Match(scrutinee, cases) ->
                    fromExpression scrutinee
                    |> Option.orElseWith (fun () ->
                        cases
                        |> List.tryPick (fun caseClause ->
                            caseClause.Guard
                            |> Option.bind fromExpression
                            |> Option.orElseWith (fun () -> fromExpression caseClause.Body)))
                | RecordLiteral fields ->
                    fields |> List.tryPick (fun field -> fromExpression field.Value)
                | RecordUpdate(receiver, fields) ->
                    fromExpression receiver
                    |> Option.orElseWith (fun () -> fields |> List.tryPick (fun field -> fromExpression field.Value))
                | MemberAccess(receiver, _, arguments) ->
                    fromExpression receiver
                    |> Option.orElseWith (fun () -> arguments |> List.tryPick fromExpression)
                | SafeNavigation(receiver, navigation) ->
                    fromExpression receiver
                    |> Option.orElseWith (fun () -> navigation.Arguments |> List.tryPick fromExpression)
                | NamedApplicationBlock fields ->
                    fields |> List.tryPick (fun field -> fromExpression field.Value)
                | Binary(left, _, right)
                | Elvis(left, right) ->
                    fromExpression left |> Option.orElseWith (fun () -> fromExpression right)
                | Comprehension comprehension ->
                    fromExpression comprehension.Lowered
                | PrefixedString(_, parts) ->
                    parts
                    |> List.tryPick (function
                        | StringText _ -> None
                        | StringInterpolation(inner, _) -> fromExpression inner)
                | Lambda(_, inner)
                | Seal(inner, _)
                | TagTest(inner, _) ->
                    fromExpression inner
                | Literal _
                | NumericLiteral _
                | KindQualifiedName _
                | Name _ ->
                    None

            and fromDoStatement statement =
                match statement with
                | DoLet(_, value)
                | DoBind(_, value)
                | DoUsing(_, value)
                | DoVar(_, value)
                | DoAssign(_, value)
                | DoDefer value
                | DoReturn value
                | DoExpression value ->
                    fromExpression value
                | DoLetQuestion(_, value, failure) ->
                    fromExpression value
                    |> Option.orElseWith (fun () ->
                        failure
                        |> Option.bind (fun failureBlock -> failureBlock.Body |> List.tryPick fromDoStatement))
                | DoIf(condition, whenTrue, whenFalse) ->
                    fromExpression condition
                    |> Option.orElseWith (fun () -> whenTrue |> List.tryPick fromDoStatement)
                    |> Option.orElseWith (fun () -> whenFalse |> List.tryPick fromDoStatement)
                | DoWhile(condition, body) ->
                    fromExpression condition
                    |> Option.orElseWith (fun () -> body |> List.tryPick fromDoStatement)

            fromExpression body

        let tryResolvePrefixedStringFailureDiagnostic prefix =
            topLevelDefinitionsByName
            |> Map.tryFind prefix
            |> Option.bind (fun prefixDefinition ->
                prefixDefinition.Body
                |> Option.bind tryParseInterpolatedMacroGoal
                |> Option.bind (fun resultType ->
                    tryResolveTraitConstraint resultType "InterpolatedMacro"
                    |> Option.bind (fun (instanceInfo, _) ->
                        instanceInfo.Members
                        |> Map.tryFind "buildInterpolated"
                        |> Option.bind (fun memberDefinition ->
                            memberDefinition.Body |> Option.bind tryExtractFailElabDiagnosticEvidence))))

        let comprehensionSinkItemTypesEqual expectedItemType actualItemType =
            let normalize = normalizeTypeAliases environment.VisibleTypeAliases

            let rec canonicalize typeExpr =
                let normalized = normalize typeExpr

                match QuerySemantics.tryParseQueryType normalize normalized with
                | Some queryType ->
                    let useName =
                        match queryType.Mode.Use with
                        | QuerySemantics.Reusable -> "Reusable"
                        | QuerySemantics.OneShot -> "OneShot"

                    let cardName =
                        match queryType.Mode.Card with
                        | QuerySemantics.QZero -> "QZero"
                        | QuerySemantics.QOne -> "QOne"
                        | QuerySemantics.QZeroOrOne -> "QZeroOrOne"
                        | QuerySemantics.QOneOrMore -> "QOneOrMore"
                        | QuerySemantics.QZeroOrMore -> "QZeroOrMore"

                    TypeName(
                        CompilerKnownSymbols.KnownTypePaths.bare CompilerKnownSymbols.KnownTypeNames.QueryCore,
                        [
                            TypeName(
                                CompilerKnownSymbols.KnownTypePaths.bare CompilerKnownSymbols.KnownTypeNames.QueryMode,
                                [ TypeName([ useName ], []); TypeName([ cardName ], []) ]
                            )
                            TypeName([ ResourceQuantity.toSurfaceText queryType.ItemQuantity ], [])
                            canonicalize queryType.ItemType
                        ]
                    )
                | None ->
                    match normalized with
                    | TypeName(nameSegments, arguments) ->
                        TypeName(nameSegments, arguments |> List.map canonicalize)
                    | TypeApply(callee, arguments) ->
                        TypeApply(canonicalize callee, arguments |> List.map canonicalize)
                    | TypeLambda(name, parameterSort, body) ->
                        TypeLambda(name, canonicalize parameterSort, canonicalize body)
                    | TypeDelay inner ->
                        TypeDelay(canonicalize inner)
                    | TypeMemo inner ->
                        TypeMemo(canonicalize inner)
                    | TypeForce inner ->
                        TypeForce(canonicalize inner)
                    | TypeProject(receiver, memberName) ->
                        TypeProject(canonicalize receiver, memberName)
                    | TypeArrow(quantity, parameterType, resultType) ->
                        TypeArrow(quantity, canonicalize parameterType, canonicalize resultType)
                    | TypeEquality(left, right) ->
                        TypeEquality(canonicalize left, canonicalize right)
                    | TypeCapture(inner, captures) ->
                        TypeCapture(canonicalize inner, captures)
                    | TypeEffectRow(entries, tail) ->
                        TypeEffectRow(
                            entries
                            |> List.map (fun entry ->
                                { Label = canonicalize entry.Label
                                  Effect = canonicalize entry.Effect }),
                            tail |> Option.map canonicalize
                        )
                    | TypeRecord fields ->
                        TypeRecord(
                            fields
                            |> List.map (fun field ->
                                { field with
                                    Type = canonicalize field.Type })
                        )
                    | TypeUnion options ->
                        TypeUnion(options |> List.map canonicalize)
                    | TypeVariable _
                    | TypeLevelLiteral _
                    | TypeUniverse _
                    | TypeIntrinsic _ ->
                        normalized

            let sameQueryShape =
                match
                    QuerySemantics.tryParseQueryType normalize expectedItemType,
                    QuerySemantics.tryParseQueryType normalize actualItemType
                with
                | Some expectedQuery, Some actualQuery ->
                    expectedQuery.Mode = actualQuery.Mode
                    && expectedQuery.ItemQuantity = actualQuery.ItemQuantity
                    && expectedQuery.CaptureSet = actualQuery.CaptureSet
                    && TypeSignatures.definitionallyEqual
                        (normalize expectedQuery.ItemType)
                        (normalize actualQuery.ItemType)
                | _ ->
                    false

            sameQueryShape
            || TypeSignatures.definitionallyEqual (canonicalize expectedItemType) (canonicalize actualItemType)

        let syntaxCarrierEscapeDiagnostics visibleNames valueType valueExpression =
            let unwrapSyntaxCarrier typeExpr =
                tryUnwrapSyntaxType environment.VisibleTypeAliases typeExpr
                |> Option.orElseWith (fun () ->
                    typeExpr
                    |> tryUnwrapElabType environment.VisibleTypeAliases
                    |> Option.bind (tryUnwrapSyntaxType environment.VisibleTypeAliases))

            let rec quotedVisibleNames visible current =
                seq {
                    match current with
                    | Name(root :: _) when Set.contains root visible ->
                        yield root
                    | Name [] ->
                        ()
                    | SyntaxQuote inner
                    | SyntaxSplice inner
                    | TopLevelSyntaxSplice inner
                    | CodeQuote inner
                    | CodeSplice inner
                    | MonadicSplice inner
                    | ExplicitImplicitArgument inner
                    | InoutArgument inner
                    | Unary(_, inner) ->
                        yield! quotedVisibleNames visible inner
                    | LocalLet(binding, value, body) ->
                        yield! quotedVisibleNames visible value

                        let nextVisible =
                            collectPatternNames binding.Pattern
                            |> Set.ofList
                            |> Set.union visible

                        yield! quotedVisibleNames nextVisible body
                    | LocalSignature(declaration, body) ->
                        yield! quotedVisibleNames (Set.add declaration.Name visible) body
                    | LocalTypeAlias(_, body) ->
                        yield! quotedVisibleNames visible body
                    | LocalScopedEffect(declaration, body) ->
                        yield! quotedVisibleNames (Set.add declaration.Name visible) body
                    | Lambda(parameters, body) ->
                        let nextVisible =
                            parameters
                            |> List.map (fun parameter -> parameter.Name)
                            |> Set.ofList
                            |> Set.union visible

                        yield! quotedVisibleNames nextVisible body
                    | Handle(_, label, body, returnClause, operationClauses) ->
                        yield! quotedVisibleNames visible label
                        yield! quotedVisibleNames visible body

                        let addClauseNames (clause: SurfaceEffectHandlerClause) visibleNames =
                            let argumentNames =
                                clause.ArgumentTokens
                                |> List.choose (fun tokens ->
                                    match significantTokens tokens with
                                    | [ token ] when Token.isName token ->
                                        Some(SyntaxFacts.trimIdentifierQuotes token.Text)
                                    | _ ->
                                        None)
                                |> Set.ofList

                            let resumptionNames =
                                clause.ResumptionName |> Option.toList |> Set.ofList

                            visibleNames
                            |> Set.union argumentNames
                            |> Set.union resumptionNames

                        yield! quotedVisibleNames (addClauseNames returnClause visible) returnClause.Body

                        for clause in operationClauses do
                            yield! quotedVisibleNames (addClauseNames clause visible) clause.Body
                    | IfThenElse(condition, whenTrue, whenFalse) ->
                        yield! quotedVisibleNames visible condition
                        yield! quotedVisibleNames visible whenTrue
                        yield! quotedVisibleNames visible whenFalse
                    | Match(scrutinee, cases) ->
                        yield! quotedVisibleNames visible scrutinee

                        for caseClause in cases do
                            let caseVisible =
                                collectPatternNames caseClause.Pattern
                                |> Set.ofList
                                |> Set.union visible

                            match caseClause.Guard with
                            | Some guard -> yield! quotedVisibleNames caseVisible guard
                            | None -> ()

                            yield! quotedVisibleNames caseVisible caseClause.Body
                    | RecordLiteral fields ->
                        for field in fields do
                            yield! quotedVisibleNames visible field.Value
                    | Seal(value, _) ->
                        yield! quotedVisibleNames visible value
                    | RecordUpdate(receiver, fields) ->
                        yield! quotedVisibleNames visible receiver

                        for field in fields do
                            yield! quotedVisibleNames visible field.Value
                    | MemberAccess(receiver, _, arguments) ->
                        yield! quotedVisibleNames visible receiver

                        for argument in arguments do
                            yield! quotedVisibleNames visible argument
                    | SafeNavigation(receiver, navigation) ->
                        yield! quotedVisibleNames visible receiver

                        for argument in navigation.Arguments do
                            yield! quotedVisibleNames visible argument
                    | TagTest(receiver, _) ->
                        yield! quotedVisibleNames visible receiver
                    | Do statements ->
                        for statement in statements do
                            match statement with
                            | DoLet(binding, expression)
                            | DoBind(binding, expression)
                            | DoUsing(binding, expression) ->
                                yield! quotedVisibleNames visible expression

                                let nextVisible =
                                    collectPatternNames binding.Pattern
                                    |> Set.ofList
                                    |> Set.union visible

                                yield! quotedVisibleNames nextVisible (Literal LiteralValue.Unit)
                            | DoLetQuestion(binding, expression, failure) ->
                                yield! quotedVisibleNames visible expression

                                match failure with
                                | Some failure ->
                                    let failureVisible =
                                        collectPatternNames failure.ResiduePattern.Pattern
                                        |> Set.ofList
                                        |> Set.union visible

                                    for failureStatement in failure.Body do
                                        match failureStatement with
                                        | DoExpression inner
                                        | DoReturn inner
                                        | DoDefer inner
                                        | DoVar(_, inner)
                                        | DoAssign(_, inner) ->
                                            yield! quotedVisibleNames failureVisible inner
                                        | _ ->
                                            ()
                                | None ->
                                    ()

                                let nextVisible =
                                    collectPatternNames binding.Pattern
                                    |> Set.ofList
                                    |> Set.union visible

                                yield! quotedVisibleNames nextVisible (Literal LiteralValue.Unit)
                            | DoVar(_, inner)
                            | DoAssign(_, inner)
                            | DoDefer inner
                            | DoExpression inner
                            | DoReturn inner ->
                                yield! quotedVisibleNames visible inner
                            | DoIf(condition, whenTrue, whenFalse) ->
                                yield! quotedVisibleNames visible condition

                                for nested in whenTrue @ whenFalse do
                                    match nested with
                                    | DoExpression inner
                                    | DoReturn inner
                                    | DoDefer inner
                                    | DoVar(_, inner)
                                    | DoAssign(_, inner) ->
                                        yield! quotedVisibleNames visible inner
                                    | _ ->
                                        ()
                            | DoWhile(condition, body) ->
                                yield! quotedVisibleNames visible condition

                                for nested in body do
                                    match nested with
                                    | DoExpression inner
                                    | DoReturn inner
                                    | DoDefer inner
                                    | DoVar(_, inner)
                                    | DoAssign(_, inner) ->
                                        yield! quotedVisibleNames visible inner
                                    | _ ->
                                        ()
                    | Apply(callee, arguments) ->
                        yield! quotedVisibleNames visible callee

                        for argument in arguments do
                            yield! quotedVisibleNames visible argument
                    | NamedApplicationBlock fields ->
                        for field in fields do
                            yield! quotedVisibleNames visible field.Value
                    | Binary(left, _, right)
                    | Elvis(left, right) ->
                        yield! quotedVisibleNames visible left
                        yield! quotedVisibleNames visible right
                    | PrefixedString(_, parts) ->
                        for part in parts do
                            match part with
                            | StringText _ -> ()
                            | StringInterpolation(inner, _) -> yield! quotedVisibleNames visible inner
                    | Literal _
                    | NumericLiteral _
                    | KindQualifiedName _ ->
                        ()
                    | _ ->
                        ()
                }

            let rec escapedCapturedNames bindingVisible currentVisible current =
                seq {
                    match current with
                    | SyntaxQuote inner ->
                        yield!
                            quotedVisibleNames currentVisible inner
                            |> Seq.filter (fun name -> not (Set.contains name bindingVisible))
                    | TypeSyntaxTokens _ ->
                        ()
                    | SyntaxSplice inner
                    | TopLevelSyntaxSplice inner
                    | CodeQuote inner
                    | CodeSplice inner
                    | MonadicSplice inner
                    | ExplicitImplicitArgument inner
                    | InoutArgument inner
                    | Unary(_, inner) ->
                        yield! escapedCapturedNames bindingVisible currentVisible inner
                    | LocalLet(binding, value, body) ->
                        yield! escapedCapturedNames bindingVisible currentVisible value

                        let nextVisible =
                            collectPatternNames binding.Pattern
                            |> Set.ofList
                            |> Set.union currentVisible

                        yield! escapedCapturedNames bindingVisible nextVisible body
                    | LocalSignature(declaration, body) ->
                        yield! escapedCapturedNames bindingVisible (Set.add declaration.Name currentVisible) body
                    | LocalTypeAlias(_, body) ->
                        yield! escapedCapturedNames bindingVisible currentVisible body
                    | LocalScopedEffect(declaration, body) ->
                        yield! escapedCapturedNames bindingVisible (Set.add declaration.Name currentVisible) body
                    | Lambda(parameters, body) ->
                        let nextVisible =
                            parameters
                            |> List.map (fun parameter -> parameter.Name)
                            |> Set.ofList
                            |> Set.union currentVisible

                        yield! escapedCapturedNames bindingVisible nextVisible body
                    | Handle(_, label, body, returnClause, operationClauses) ->
                        yield! escapedCapturedNames bindingVisible currentVisible label
                        yield! escapedCapturedNames bindingVisible currentVisible body
                        yield! escapedCapturedNames bindingVisible currentVisible returnClause.Body

                        for clause in operationClauses do
                            yield! escapedCapturedNames bindingVisible currentVisible clause.Body
                    | IfThenElse(condition, whenTrue, whenFalse) ->
                        yield! escapedCapturedNames bindingVisible currentVisible condition
                        yield! escapedCapturedNames bindingVisible currentVisible whenTrue
                        yield! escapedCapturedNames bindingVisible currentVisible whenFalse
                    | Match(scrutinee, cases) ->
                        yield! escapedCapturedNames bindingVisible currentVisible scrutinee

                        for caseClause in cases do
                            let nextVisible =
                                collectPatternNames caseClause.Pattern
                                |> Set.ofList
                                |> Set.union currentVisible

                            match caseClause.Guard with
                            | Some guard -> yield! escapedCapturedNames bindingVisible nextVisible guard
                            | None -> ()

                            yield! escapedCapturedNames bindingVisible nextVisible caseClause.Body
                    | RecordLiteral fields ->
                        for field in fields do
                            yield! escapedCapturedNames bindingVisible currentVisible field.Value
                    | Seal(value, _) ->
                        yield! escapedCapturedNames bindingVisible currentVisible value
                    | RecordUpdate(receiver, fields) ->
                        yield! escapedCapturedNames bindingVisible currentVisible receiver

                        for field in fields do
                            yield! escapedCapturedNames bindingVisible currentVisible field.Value
                    | MemberAccess(receiver, _, arguments) ->
                        yield! escapedCapturedNames bindingVisible currentVisible receiver

                        for argument in arguments do
                            yield! escapedCapturedNames bindingVisible currentVisible argument
                    | SafeNavigation(receiver, navigation) ->
                        yield! escapedCapturedNames bindingVisible currentVisible receiver

                        for argument in navigation.Arguments do
                            yield! escapedCapturedNames bindingVisible currentVisible argument
                    | TagTest(receiver, _) ->
                        yield! escapedCapturedNames bindingVisible currentVisible receiver
                    | Do statements ->
                        for statement in statements do
                            match statement with
                            | DoLet(binding, expression)
                            | DoBind(binding, expression)
                            | DoUsing(binding, expression) ->
                                yield! escapedCapturedNames bindingVisible currentVisible expression

                                let nextVisible =
                                    collectPatternNames binding.Pattern
                                    |> Set.ofList
                                    |> Set.union currentVisible

                                yield! escapedCapturedNames bindingVisible nextVisible (Literal LiteralValue.Unit)
                            | DoLetQuestion(binding, expression, _) ->
                                yield! escapedCapturedNames bindingVisible currentVisible expression

                                let nextVisible =
                                    collectPatternNames binding.Pattern
                                    |> Set.ofList
                                    |> Set.union currentVisible

                                yield! escapedCapturedNames bindingVisible nextVisible (Literal LiteralValue.Unit)
                            | DoVar(_, inner)
                            | DoAssign(_, inner)
                            | DoDefer inner
                            | DoExpression inner
                            | DoReturn inner ->
                                yield! escapedCapturedNames bindingVisible currentVisible inner
                            | DoIf(condition, whenTrue, whenFalse) ->
                                yield! escapedCapturedNames bindingVisible currentVisible condition

                                for nested in whenTrue @ whenFalse do
                                    match nested with
                                    | DoExpression inner
                                    | DoReturn inner
                                    | DoDefer inner
                                    | DoVar(_, inner)
                                    | DoAssign(_, inner) ->
                                        yield! escapedCapturedNames bindingVisible currentVisible inner
                                    | _ ->
                                        ()
                            | DoWhile(condition, body) ->
                                yield! escapedCapturedNames bindingVisible currentVisible condition

                                for nested in body do
                                    match nested with
                                    | DoExpression inner
                                    | DoReturn inner
                                    | DoDefer inner
                                    | DoVar(_, inner)
                                    | DoAssign(_, inner) ->
                                        yield! escapedCapturedNames bindingVisible currentVisible inner
                                    | _ ->
                                        ()
                    | Apply(callee, arguments) ->
                        yield! escapedCapturedNames bindingVisible currentVisible callee

                        for argument in arguments do
                            yield! escapedCapturedNames bindingVisible currentVisible argument
                    | Comprehension comprehension ->
                        yield! escapedCapturedNames bindingVisible currentVisible comprehension.Lowered
                    | NamedApplicationBlock fields ->
                        for field in fields do
                            yield! escapedCapturedNames bindingVisible currentVisible field.Value
                    | Binary(left, _, right)
                    | Elvis(left, right) ->
                        yield! escapedCapturedNames bindingVisible currentVisible left
                        yield! escapedCapturedNames bindingVisible currentVisible right
                    | PrefixedString(_, parts) ->
                        for part in parts do
                            match part with
                            | StringText _ -> ()
                            | StringInterpolation(inner, _) ->
                                yield! escapedCapturedNames bindingVisible currentVisible inner
                    | Literal _
                    | NumericLiteral _
                    | KindQualifiedName _
                    | Name _ ->
                        ()
                }

            match unwrapSyntaxCarrier valueType with
            | Some _ ->
                let escapedNames =
                    escapedCapturedNames visibleNames visibleNames valueExpression
                    |> Seq.distinct
                    |> Seq.toList

                if List.isEmpty escapedNames then
                    []
                else
                    [ makeSurfaceElaborationDiagnostic
                        (SyntaxCarrierEscapesCapturedBindings escapedNames) ]
            | None ->
                []

        let prefixedStringPrefixDiagnostics locals lexicalNames prefix =
            let prefixType =
                locals
                |> Map.tryFind prefix
                |> Option.orElseWith (fun () -> tryInstantiateVisibleBindingType prefix)

            match prefixType with
            | Some resolvedType ->
                let allowPlainDictionary =
                    not (Map.containsKey prefix locals) && Set.contains prefix environment.ElaborationAvailableBindings

                let resolvedResultType =
                    tryElabInterpolatedMacroResultType environment.VisibleTypeAliases resolvedType
                    |> Option.orElseWith (fun () ->
                        if allowPlainDictionary then
                            tryInterpolatedMacroResultType environment.VisibleTypeAliases resolvedType
                        else
                            None)

                match resolvedResultType with
                | Some _ -> []
                | None ->
                    [ makeSurfaceElaborationDiagnostic
                        (PrefixedStringPrefixMustResolveToInterpolatedMacro prefix) ]
            | None when Set.contains prefix lexicalNames ->
                []
            | None when allowUnresolvedCallDiagnostics && not (Set.contains prefix knownValueNames) ->
                [ makeNameUnresolvedDiagnostic prefix ]
            | None when Set.contains prefix knownSurfaceTermNames ->
                [ makeSurfaceElaborationDiagnostic
                    (PrefixedStringPrefixMustResolveToInterpolatedMacro prefix) ]
            | None ->
                []

        let numericLiteralRangeDiagnostic literal =
            let sourceText = SurfaceNumericLiteral.toSurfaceText literal
            Diagnostics.errorFact
                "KFrontIR"
                (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                None
                []
                (DiagnosticFact.numericLiteralOutOfRange sourceText)

        let tryNumericLiteralRangeDiagnostic expectedType expression =
            match tryInferNumericExpressionTypeFromContext environment expectedType expression with
            | Some _ when tryLowerNumericExpressionForRuntime expression |> Option.isNone ->
                match expression with
                | NumericLiteral literal ->
                    Some(numericLiteralRangeDiagnostic literal)
                | Unary("-", NumericLiteral(SurfaceIntegerLiteral(value, text, suffix))) ->
                    Some(numericLiteralRangeDiagnostic (SurfaceIntegerLiteral(-value, "-" + text, suffix)))
                | Unary("-", NumericLiteral(SurfaceRealLiteral(decimalValue, text, suffix))) ->
                    Some(numericLiteralRangeDiagnostic (SurfaceRealLiteral(decimalValue |> Option.map (~-), "-" + text, suffix)))
                | _ ->
                    None
            | _ ->
                None

        let isVisibleConstructorName name =
            environment.VisibleConstructors |> Map.containsKey name

        let rec expressionExposesManifestStaticObject expression =
            match tryResolveScopedStaticObject environment expression with
            | Some _ ->
                true
            | None ->
                match expression with
                | RecordLiteral _ ->
                    true
                | Seal(inner, _) ->
                    expressionExposesManifestStaticObject inner
                | _ ->
                    false

        let isTopLevelManifestStaticObjectRoot name =
            topLevelDefinitionsByName
            |> Map.tryFind name
            |> Option.exists (fun definition ->
                List.isEmpty definition.Parameters
                && (definition.Body |> Option.exists expressionExposesManifestStaticObject))

        let isVisibleQualifiedRootName locals lexicalNames name =
            let isVisibleModuleRoot =
                environment.VisibleModulePaths
                |> Map.keys
                |> Seq.exists (function
                    | root :: _ -> String.Equals(root, name, StringComparison.Ordinal)
                    | [] -> false)

            (Map.containsKey name locals)
            || (Set.contains name lexicalNames)
            || (Set.contains name knownValueNames)
            || String.Equals(name, "this", StringComparison.Ordinal)
            || isVisibleModuleRoot
            || (tryFindVisibleStaticGroup environment [ name ] |> Option.isSome)
            || (environment.VisibleOrdinaryGroups |> Map.containsKey name)
            || isTopLevelManifestStaticObjectRoot name
            || (tryResolveScopedStaticObject environment (Name [ name ]) |> Option.isSome)

        let qualifiedNamePreservesResolution nameSegments =
            let isVisibleQualifiedModule =
                tryResolveVisibleModuleIdentity environment nameSegments
                |> Option.isSome

            let resolvesAsQualifiedDeclaration =
                match List.rev nameSegments with
                | [] -> false
                | declaredName :: reversedModuleSegments ->
                    let declaringModuleSegments = List.rev reversedModuleSegments
                    let declaringModuleIdentity =
                        tryResolveVisibleModuleIdentity environment declaringModuleSegments
                        |> Option.defaultValue (moduleIdentityOfSegments declaringModuleSegments)

                    environment.SurfaceIndex
                    |> Map.tryFind declaringModuleIdentity
                    |> Option.exists (fun moduleInfo ->
                        Set.contains declaredName moduleInfo.ExportedTerms
                        || Set.contains declaredName moduleInfo.ExportedTypes
                        || Set.contains declaredName moduleInfo.ExportedTraits
                        || Set.contains declaredName moduleInfo.ExportedConstructors)

            isVisibleQualifiedModule
            || (tryResolveScopedStaticObject environment (Name nameSegments) |> Option.isSome)
            || (tryResolveVisibleTypeFacetInfo environment nameSegments |> Option.isSome)
            || resolvesAsQualifiedDeclaration

        let expressionSelectsOpaqueField expression =
            let tryRecordInfoFromType typeExpr =
                match typeExpr with
                | TypeName(nameSegments, []) ->
                    nameSegments
                    |> List.tryLast
                    |> Option.bind (fun name -> environment.VisibleRecordTypes |> Map.tryFind name)
                    |> Option.orElseWith (fun () ->
                        match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
                        | TypeRecord fields ->
                            Some
                                { Fields =
                                    fields
                                    |> List.map (fun field ->
                                        { Name = field.Name
                                          IsOpaque = false
                                          IsImplicit = field.Quantity = QuantityZero
                                          TypeTokens = [] })
                                  RowTail = None }
                        | _ ->
                            None)
                | _ ->
                    None

            let rootField expression =
                match expression with
                | Name [ root; fieldName ] ->
                    Some(root, fieldName)
                | MemberAccess(Name [ root ], [ fieldName ], []) ->
                    Some(root, fieldName)
                | _ ->
                    None

            rootField expression
            |> Option.bind (fun (root, fieldName) ->
                environment.VisibleBindings
                |> Map.tryFind root
                |> Option.bind (fun bindingInfo -> tryRecordInfoFromType bindingInfo.Scheme.Body)
                |> Option.bind (fun recordInfo ->
                    recordInfo.Fields
                    |> List.tryFind (fun field -> String.Equals(field.Name, fieldName, StringComparison.Ordinal))))
            |> Option.exists (fun field -> field.IsOpaque)

        let hasProvenStaticObjectIdentity locals expression =
            match expression with
            | KindQualifiedName(TypeKind, [ name ]) when Set.contains name (currentScopedEffectNames ()) ->
                true
            | KindQualifiedName(EffectLabelKind, [ name ]) when Set.contains name (currentScopedEffectNames ()) ->
                true
            | Name(root :: _) when locals |> Map.containsKey root ->
                not (Set.contains root parameterNames)
            | _ ->
                tryResolveStaticReceiverObject environment expression
                |> Option.isSome
                |> function
                    | true -> true
                    | false ->
                        match expression with
                        | Name _ ->
                            false
                        | _ ->
                            not (expressionSelectsOpaqueField expression)
                            && (inferValidationExpressionType environment (ref freshCounter.Value) locals expression
                                |> Option.exists (isReifiedStaticObjectType environment.VisibleTypeAliases))

        let staticConstructorIdentityDiagnostic locals receiver memberName =
            if isVisibleConstructorName memberName
               && not (hasProvenStaticObjectIdentity locals receiver) then
                [
                    Diagnostics.errorFact
                        "KFrontIR"
                        (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                        None
                        []
                        (DiagnosticFact.surfaceElaboration (StaticConstructorRequiresPreservedStaticObjectIdentity memberName))
                ]
            else
                []

        let rec staticPatternIdentityDiagnostics locals pattern =
            match pattern with
            | AsPattern(_, inner) ->
                staticPatternIdentityDiagnostics locals inner
            | TypedPattern(inner, _) ->
                staticPatternIdentityDiagnostics locals inner
            | ConstructorPattern(segments, arguments) ->
                let nested = arguments |> List.collect (staticPatternIdentityDiagnostics locals)

                match List.rev segments with
                | memberName :: receiverSegments when not (List.isEmpty receiverSegments) ->
                    let receiver = Name(List.rev receiverSegments)
                    staticConstructorIdentityDiagnostic locals receiver memberName @ nested
                | _ ->
                    nested
            | NamedConstructorPattern(segments, fields) ->
                staticPatternIdentityDiagnostics locals (ConstructorPattern(segments, fields |> List.map (fun field -> field.Pattern)))
            | TuplePattern elements ->
                elements |> List.collect (staticPatternIdentityDiagnostics locals)
            | VariantPattern _ ->
                []
            | OrPattern alternatives ->
                alternatives |> List.collect (staticPatternIdentityDiagnostics locals)
            | AnonymousRecordPattern(fields, _) ->
                fields |> List.collect (fun field -> staticPatternIdentityDiagnostics locals field.Pattern)
            | WildcardPattern
            | NamePattern _
            | LiteralPattern _ ->
                []

        let transparentSealFields ascriptionTokens =
            match tryParseRecordSurfaceInfo ascriptionTokens with
            | Some recordInfo ->
                recordInfo.Fields
                |> List.filter (fun field -> not field.IsOpaque)
                |> List.map (fun field -> field.Name)
                |> Set.ofList
                |> Some
            | None ->
                match significantTokens ascriptionTokens with
                | [ nameToken ] when Token.isName nameToken ->
                    environment.VisibleRecordTypes
                    |> Map.tryFind (SyntaxFacts.trimIdentifierQuotes nameToken.Text)
                    |> Option.map (fun recordInfo ->
                        recordInfo.Fields
                        |> List.filter (fun field -> not field.IsOpaque)
                        |> List.map (fun field -> field.Name)
                        |> Set.ofList)
                | _ ->
                    None

        let aliasesAsVisibleStaticObjects (aliases: Map<string list, StaticObjectInfo>) =
            aliases
            |> Map.fold (fun current segments staticObject -> Map.add segments staticObject current) environment.VisibleStaticObjects

        let tryResolveWithLocalAliases aliases expression =
            let aliasEnvironment =
                withVisibleStaticObjects environment (aliasesAsVisibleStaticObjects aliases)

            tryResolveScopedStaticObject aliasEnvironment expression

        let copyVisibleNestedAliases
            (sourcePrefix: string list)
            (targetPrefix: string list)
            fieldFilter
            (aliases: Map<string list, StaticObjectInfo>)
            =
            aliasesAsVisibleStaticObjects aliases
            |> Map.toList
            |> List.filter (fun (segments, _) ->
                match List.tryItem sourcePrefix.Length segments with
                | Some firstSuffixSegment
                    when List.length segments > sourcePrefix.Length
                         && List.take sourcePrefix.Length segments = sourcePrefix ->
                    fieldFilter firstSuffixSegment
                | _ ->
                    false)
            |> List.fold (fun current (segments, staticObject) ->
                let suffixSegments = segments |> List.skip sourcePrefix.Length
                Map.add (targetPrefix @ suffixSegments) staticObject current) aliases

        let rec collectExpressionStaticAliases prefix expression aliases =
            match tryResolveWithLocalAliases aliases expression with
            | Some staticObject ->
                let aliases = Map.add prefix staticObject aliases

                match expression with
                | Name sourcePrefix -> copyVisibleNestedAliases sourcePrefix prefix (fun _ -> true) aliases
                | _ -> aliases
            | None ->
                match expression with
                | RecordLiteral fields ->
                    fields
                    |> List.fold (fun current field -> collectExpressionStaticAliases (prefix @ [ field.Name ]) field.Value current) aliases
                | Seal(value, ascriptionTokens) ->
                    match value, transparentSealFields ascriptionTokens with
                    | Name sourcePrefix, Some transparentFields ->
                        copyVisibleNestedAliases sourcePrefix prefix (fun fieldName -> Set.contains fieldName transparentFields) aliases
                    | RecordLiteral fields, Some transparentFields ->
                        fields
                        |> List.filter (fun field -> Set.contains field.Name transparentFields)
                        |> List.fold (fun current field -> collectExpressionStaticAliases (prefix @ [ field.Name ]) field.Value current) aliases
                    | _, Some _ ->
                        aliases
                    | _ ->
                        collectExpressionStaticAliases prefix value aliases
                | _ ->
                    aliases

        let rec collectPatternStaticAliases pattern value aliases =
            match pattern with
            | NamePattern name ->
                collectExpressionStaticAliases [ name ] value aliases
            | AsPattern(name, inner) ->
                collectPatternStaticAliases inner value (collectExpressionStaticAliases [ name ] value aliases)
            | TypedPattern(inner, _) ->
                collectPatternStaticAliases inner value aliases
            | AnonymousRecordPattern(fields, rest) ->
                fields
                |> List.fold (fun current field ->
                    let fieldExpression =
                        match value with
                        | Name segments -> Name(segments @ [ field.Name ])
                        | _ -> MemberAccess(value, [ field.Name ], [])

                    collectPatternStaticAliases field.Pattern fieldExpression current) aliases
                |> fun current ->
                    match rest with
                    | Some(BindRecordPatternRest name) ->
                        collectExpressionStaticAliases [ name ] value current
                    | _ ->
                        current
            | ConstructorPattern(_, arguments) ->
                arguments |> List.fold (fun current argument -> collectPatternStaticAliases argument value current) aliases
            | NamedConstructorPattern(_, fields) ->
                fields |> List.fold (fun current field -> collectPatternStaticAliases field.Pattern value current) aliases
            | TuplePattern elements ->
                elements |> List.fold (fun current element -> collectPatternStaticAliases element value current) aliases
            | VariantPattern(BoundVariantPattern(name, _))
            | VariantPattern(RestVariantPattern name) ->
                collectExpressionStaticAliases [ name ] value aliases
            | VariantPattern(WildcardVariantPattern _) ->
                aliases
            | OrPattern alternatives ->
                alternatives
                |> List.tryHead
                |> Option.map (fun first -> collectPatternStaticAliases first value aliases)
                |> Option.defaultValue aliases
            | WildcardPattern
            | LiteralPattern _ ->
                aliases

        let typeHeadName typeExpr =
            match typeExpr with
            | TypeName(nameSegments, _) when not (List.isEmpty nameSegments) -> Some(List.last nameSegments)
            | _ -> None

        let rec finalResultType typeExpr =
            match typeExpr with
            | TypeArrow(_, _, resultType) -> finalResultType resultType
            | other -> other

        let isMonadicType typeExpr =
            match typeHeadName (finalResultType typeExpr) with
            | Some headName when
                String.Equals(headName, CompilerKnownSymbols.KnownTypeNames.IO, StringComparison.Ordinal)
                || String.Equals(headName, CompilerKnownSymbols.KnownTypeNames.UIO, StringComparison.Ordinal) ->
                true
            | _ -> false

        let activePatternResultKind (bindingInfo: BindingSchemeInfo) =
            match typeHeadName (finalResultType bindingInfo.Scheme.Body) with
            | Some headName when String.Equals(headName, CompilerKnownSymbols.KnownTypeNames.Option, StringComparison.Ordinal) ->
                Some CompilerKnownSymbols.KnownTypeNames.Option
            | Some headName when String.Equals(headName, CompilerKnownSymbols.KnownTypeNames.Match, StringComparison.Ordinal) ->
                Some CompilerKnownSymbols.KnownTypeNames.Match
            | Some _ -> Some "Total"
            | None -> None

        let activePatternScrutineeQuantity (bindingInfo: BindingSchemeInfo) =
            bindingInfo.ParameterLayouts
            |> Option.bind (fun layouts ->
                layouts
                |> List.filter (fun parameter -> not parameter.IsImplicit)
                |> List.tryLast
                |> Option.bind (fun parameter -> parameter.Quantity))

        let tryActivePatternBinding pattern =
            match pattern with
            | ConstructorPattern(nameSegments, _) when not (List.isEmpty nameSegments) ->
                environment.VisibleBindings
                |> Map.tryFind (List.last nameSegments)
                |> Option.filter (fun bindingInfo -> bindingInfo.IsPattern)
            | _ ->
                None

        let rec validatePatternHead pattern =
            match pattern with
            | AsPattern(_, inner) ->
                validatePatternHead inner
            | TypedPattern(inner, _) ->
                validatePatternHead inner
            | ConstructorPattern(nameSegments, arguments) ->
                let nestedDiagnostics = arguments |> List.collect validatePatternHead
                let headDiagnostics =
                    match nameSegments with
                    | [] -> []
                    | _ ->
                        let headName = List.last nameSegments
                        match tryVisiblePatternHeadAmbiguityCandidates headName with
                        | Some candidates ->
                            [ ordinaryNameAmbiguityDiagnostic headName candidates ]
                        | None ->
                            let isConstructor = environment.VisibleConstructors |> Map.containsKey headName

                            match environment.VisibleBindings |> Map.tryFind headName with
                            | Some bindingInfo when not bindingInfo.IsPattern && not isConstructor ->
                                [
                                    Diagnostics.errorFact
                                        "KFrontIR"
                                        (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                        None
                                        []
                                        (DiagnosticFact.surfaceElaboration (PatternHeadResolvedToOrdinaryTerm headName))
                                ]
                            | _ ->
                                []

                headDiagnostics @ nestedDiagnostics
            | NamedConstructorPattern(nameSegments, fields) ->
                validatePatternHead (ConstructorPattern(nameSegments, fields |> List.map (fun field -> field.Pattern)))
            | TuplePattern elements ->
                elements |> List.collect validatePatternHead
            | VariantPattern _ ->
                []
            | OrPattern alternatives ->
                alternatives |> List.collect validatePatternHead
            | AnonymousRecordPattern(fields, _) ->
                fields |> List.collect (fun field -> validatePatternHead field.Pattern)
            | WildcardPattern
            | NamePattern _
            | LiteralPattern _ ->
                []

        let activePatternLinearityDiagnostics pattern context =
            match tryActivePatternBinding pattern with
            | Some bindingInfo ->
                match activePatternResultKind bindingInfo, activePatternScrutineeQuantity bindingInfo with
                | Some resultKind, Some QuantityOne when String.Equals(resultKind, CompilerKnownSymbols.KnownTypeNames.Option, StringComparison.Ordinal) ->
                    [
                        Diagnostics.errorFact
                            "KFrontIR"
                            (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                            None
                            []
                            (DiagnosticFact.surfaceElaboration
                                (ActivePatternLinearlyConsumesScrutineeInRefutableContext(bindingInfo.Name, context)))
                    ]
                | Some resultKind, _ when
                    String.Equals(resultKind, CompilerKnownSymbols.KnownTypeNames.Match, StringComparison.Ordinal)
                    && String.Equals(context, "let?", StringComparison.Ordinal) ->
                    [
                        Diagnostics.errorFact
                            "KFrontIR"
                            (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                            None
                            []
                            (DiagnosticFact.surfaceElaboration
                                (MatchReturningActivePatternNotPermittedInPlainLetQuestion bindingInfo.Name))
                    ]
                | _ ->
                    []
            | None ->
                []

        let memberText (navigation: SurfaceSafeNavigationMember) =
            let argumentsText =
                navigation.Arguments
                |> List.map (fun _ -> "<arg>")
                |> String.concat " "

            let segmentsText = String.concat "." navigation.Segments
            match argumentsText with
            | "" -> segmentsText
            | _ -> $"{segmentsText} {argumentsText}"

        let tryRecordInfoFromTypeName name =
            environment.VisibleRecordTypes |> Map.tryFind name

        let tryRecordInfoFromTypeExpr typeExpr =
            match typeExpr with
            | TypeName(nameSegments, []) ->
                nameSegments
                |> List.tryLast
                |> Option.bind tryRecordInfoFromTypeName
                |> Option.orElseWith (fun () ->
                    match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
                    | TypeRecord fields ->
                        Some
                            { Fields =
                                fields
                                |> List.map (fun field ->
                                    { Name = field.Name
                                      IsOpaque = false
                                      IsImplicit = field.Quantity = QuantityZero
                                      TypeTokens = [] })
                              RowTail = None }
                    | _ ->
                        None)
            | _ ->
                match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
                | TypeRecord fields ->
                    Some
                        { Fields =
                            fields
                            |> List.map (fun field ->
                                { Name = field.Name
                                  IsOpaque = false
                                  IsImplicit = field.Quantity = QuantityZero
                                  TypeTokens = [] })
                          RowTail = None }
                | _ ->
                    None

        let tryRecordInfoFromTypeTokens tokens =
            tryParseRecordSurfaceInfo tokens
            |> Option.orElseWith (fun () ->
                match significantTokens tokens with
                | [ nameToken ] when Token.isName nameToken ->
                    tryRecordInfoFromTypeName (SyntaxFacts.trimIdentifierQuotes nameToken.Text)
                | _ ->
                    None)

        let localRecordTypes =
            effectiveParameters
            |> List.choose (fun parameter ->
                parameter.TypeTokens
                |> Option.bind tryRecordInfoFromTypeTokens
                |> Option.map (fun recordInfo -> parameter.Name, recordInfo))
            |> Map.ofList

        let tryRecordInfoForRoot locals root =
            localRecordTypes
            |> Map.tryFind root
            |> Option.orElseWith (fun () ->
                locals
                |> Map.tryFind root
                |> Option.bind tryRecordInfoFromTypeExpr)
            |> Option.orElseWith (fun () ->
                environment.VisibleBindings
                |> Map.tryFind root
                |> Option.bind (fun bindingInfo ->
                    tryRecordInfoFromTypeExpr bindingInfo.Scheme.Body
                    |> Option.orElseWith (fun () -> tryRecordInfoFromTypeTokens bindingInfo.TypeTokens)))

        let tryRecordInfoForExpression locals expression =
            match expression with
            | Name(root :: _) -> tryRecordInfoForRoot locals root
            | _ -> None

        let trueTermType = TypeName([ "True" ], [])
        let falseTermType = TypeName([ "False" ], [])
        let emptyStableAliases: Map<string, string> = Map.empty
        let emptyStaticAliases: Map<string list, StaticObjectInfo> = Map.empty
        let emptyConstructorFacts: Map<string, string option * Set<string>> = Map.empty

        let canonicalStableRoot aliases name =
            let rec loop seen current =
                if Set.contains current seen then
                    current
                else
                    match Map.tryFind current aliases with
                    | Some next -> loop (Set.add current seen) next
                    | None -> current

            loop Set.empty name

        let removeShadowedAliases aliases names =
            names |> List.fold (fun state name -> Map.remove name state) aliases

        let removeShadowedStaticAliases
            (aliases: Map<string list, StaticObjectInfo>)
            names
            =
            if List.isEmpty names then
                aliases
            else
                let shadowed = names |> Set.ofList

                aliases
                |> Map.filter (fun segments _ ->
                    match segments with
                    | root :: _ -> not (Set.contains root shadowed)
                    | [] -> true)

        let tryLocalRootType aliases locals root =
            Map.tryFind root locals
            |> Option.orElseWith (fun () ->
                let canonicalRoot = canonicalStableRoot aliases root
                Map.tryFind canonicalRoot locals)

        let visibleConstructorsForType typeExpr =
            match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
            | TypeName(nameSegments, _) ->
                match List.tryLast nameSegments with
                | Some typeName ->
                    environment.VisibleConstructors
                    |> Map.values
                    |> Seq.filter (fun info ->
                        info.ConstructorTypeName
                        |> Option.exists (fun constructorTypeName ->
                            String.Equals(constructorTypeName, typeName, StringComparison.Ordinal)))
                    |> Seq.toList
                | None ->
                    []
            | _ ->
                []

        let tryVisibleConstructorFieldType (constructorInfo: BindingSchemeInfo) fieldName =
            constructorInfo.ParameterLayouts
            |> Option.bind (fun layouts ->
                layouts
                |> List.tryPick (fun parameter ->
                    if parameter.IsImplicit || parameter.IsReceiver then
                        None
                    elif String.Equals(parameter.Name, fieldName, StringComparison.Ordinal) then
                        parameter.TypeTokens |> Option.bind TypeSignatures.parseType
                    else
                        None))

        let possibleConstructorsForRoot aliases constructorFacts locals root =
            tryLocalRootType aliases locals root
            |> Option.bind (fun rootType ->
                let visibleConstructors = visibleConstructorsForType rootType

                if List.isEmpty visibleConstructors then
                    None
                else
                    let canonicalRoot = canonicalStableRoot aliases root

                    let filteredConstructors =
                        match Map.tryFind canonicalRoot constructorFacts with
                        | Some(Some positiveConstructor, _) ->
                            visibleConstructors
                            |> List.filter (fun info ->
                                String.Equals(info.Name, positiveConstructor, StringComparison.Ordinal))
                        | Some(None, excludedConstructors) ->
                            visibleConstructors
                            |> List.filter (fun info ->
                                not (Set.contains info.Name excludedConstructors))
                        | None ->
                            visibleConstructors

                    Some filteredConstructors)

        let addPositiveConstructorFact aliases constructorFacts root constructorName =
            let canonicalRoot = canonicalStableRoot aliases root
            Map.add canonicalRoot (Some constructorName, Set.empty) constructorFacts

        let addNegativeConstructorFact aliases constructorFacts root constructorName =
            let canonicalRoot = canonicalStableRoot aliases root

            let positiveConstructor, excludedConstructors =
                Map.tryFind canonicalRoot constructorFacts
                |> Option.defaultValue (None, Set.empty)

            Map.add canonicalRoot (positiveConstructor, Set.add constructorName excludedConstructors) constructorFacts

        let rec conditionConstructorFacts aliases constructorFacts (condition: SurfaceExpression) =
            match condition with
            | TagTest(Name [ root ], constructorNameSegments) ->
                match List.tryLast constructorNameSegments with
                | Some constructorName ->
                    [ addPositiveConstructorFact aliases constructorFacts root constructorName ],
                    [ addNegativeConstructorFact aliases constructorFacts root constructorName ]
                | None ->
                    [ constructorFacts ], [ constructorFacts ]
            | Unary("not", inner) ->
                let whenTrue, whenFalse = conditionConstructorFacts aliases constructorFacts inner
                whenFalse, whenTrue
            | Binary(left, "&&", right) ->
                let leftTrue, leftFalse = conditionConstructorFacts aliases constructorFacts left

                let rightTrue =
                    leftTrue
                    |> List.collect (fun currentFacts ->
                        conditionConstructorFacts aliases currentFacts right |> fst)

                let rightFalse =
                    leftTrue
                    |> List.collect (fun currentFacts ->
                        conditionConstructorFacts aliases currentFacts right |> snd)

                rightTrue, leftFalse @ rightFalse
            | Binary(left, "||", right) ->
                let leftTrue, leftFalse = conditionConstructorFacts aliases constructorFacts left

                let rightTrue =
                    leftFalse
                    |> List.collect (fun currentFacts ->
                        conditionConstructorFacts aliases currentFacts right |> fst)

                let rightFalse =
                    leftFalse
                    |> List.collect (fun currentFacts ->
                        conditionConstructorFacts aliases currentFacts right |> snd)

                leftTrue @ rightTrue, rightFalse
            | _ ->
                [ constructorFacts ], [ constructorFacts ]

        let rec tryTopLevelSurfaceConstructorPatternName (pattern: SurfacePattern) =
            match pattern with
            | ConstructorPattern(nameSegments, _)
            | NamedConstructorPattern(nameSegments, _) ->
                List.tryLast nameSegments
            | AsPattern(_, inner)
            | TypedPattern(inner, _) ->
                tryTopLevelSurfaceConstructorPatternName inner
            | _ ->
                None

        let rec doBlockDefinitelyTerminal (statements: SurfaceDoStatement list) =
            match statements |> List.tryLast with
            | Some(DoReturn _) ->
                true
            | Some(DoExpression(Do nestedStatements)) ->
                doBlockDefinitelyTerminal nestedStatements
            | Some(DoIf(_, whenTrue, whenFalse)) ->
                doBlockDefinitelyTerminal whenTrue && doBlockDefinitelyTerminal whenFalse
            | _ ->
                false

        let extendStableAliases aliases (binding: SurfaceBindPattern) (value: SurfaceExpression) =
            let shadowedNames = collectPatternNames binding.Pattern
            let clearedAliases = removeShadowedAliases aliases shadowedNames

            match binding.Pattern, value with
            | NamePattern aliasName, Name [ targetName ] ->
                Map.add aliasName (canonicalStableRoot clearedAliases targetName) clearedAliases
            | _ ->
                clearedAliases

        let constructorProjectionDiagnostics aliases constructorFacts locals root fieldName =
            match tryRecordInfoForRoot locals root with
            | Some recordInfo ->
                if
                    recordInfo.Fields
                    |> List.exists (fun field -> String.Equals(field.Name, fieldName, StringComparison.Ordinal))
                then
                    []
                else
                    [
                        Diagnostics.errorFact
                            "KFrontIR"
                            (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                            None
                            []
                            (DiagnosticFact.surfaceElaboration (RecordProjectionFieldMissing fieldName))
                    ]
            | None ->
                match possibleConstructorsForRoot aliases constructorFacts locals root with
                | Some [] ->
                    []
                | Some [ constructorInfo ] ->
                    match tryVisibleConstructorFieldType constructorInfo fieldName with
                    | Some _
                    | None ->
                        []
                | Some _ ->
                    [
                        makeDiagnostic
                            SimpleDiagnosticKind.TypeEqualityMismatch
                            $"Constructor-field projection '{root}.{fieldName}' requires a unique constructor refinement in this branch."
                    ]
                | None ->
                    []

        let applyRefinements refinements typeExpr =
            TypeSignatures.applySubstitution refinements typeExpr

        let normalizeExpectedType refinements typeExpr =
            typeExpr
            |> applyRefinements refinements
            |> qualifyVisibleTypeNames environment
            |> normalizeTypeAliases environment.VisibleTypeAliases

        let rec typeContainsLocalTermVariable locals typeExpr =
            match typeExpr with
            | TypeLevelLiteral _ ->
                false
            | TypeUniverse None ->
                false
            | TypeUniverse(Some universeExpr) ->
                typeContainsLocalTermVariable locals universeExpr
            | TypeIntrinsic _ ->
                false
            | TypeApply(callee, arguments) ->
                typeContainsLocalTermVariable locals callee
                || (arguments |> List.exists (typeContainsLocalTermVariable locals))
            | TypeLambda(_, parameterSort, body) ->
                typeContainsLocalTermVariable locals parameterSort
                || typeContainsLocalTermVariable locals body
            | TypeDelay inner
            | TypeMemo inner
            | TypeForce inner ->
                typeContainsLocalTermVariable locals inner
            | TypeProject(target, _) ->
                typeContainsLocalTermVariable locals target
            | TypeVariable name ->
                Map.containsKey name locals
            | TypeName(_, arguments) ->
                arguments |> List.exists (typeContainsLocalTermVariable locals)
            | TypeArrow(_, parameterType, resultType) ->
                typeContainsLocalTermVariable locals parameterType
                || typeContainsLocalTermVariable locals resultType
            | TypeEquality(left, right) ->
                typeContainsLocalTermVariable locals left
                || typeContainsLocalTermVariable locals right
            | TypeCapture(inner, _) ->
                typeContainsLocalTermVariable locals inner
            | TypeEffectRow(entries, tail) ->
                entries
                |> List.exists (fun entry ->
                    typeContainsLocalTermVariable locals entry.Label
                    || typeContainsLocalTermVariable locals entry.Effect)
                || tail |> Option.exists (typeContainsLocalTermVariable locals)
            | TypeRecord fields ->
                fields |> List.exists (fun field -> typeContainsLocalTermVariable locals field.Type)
            | TypeUnion members ->
                members |> List.exists (typeContainsLocalTermVariable locals)

        let rec typeContainsSuspension typeExpr =
            match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
            | TypeDelay _
            | TypeMemo _
            | TypeForce _ ->
                true
            | TypeLevelLiteral _ ->
                false
            | TypeUniverse None ->
                false
            | TypeUniverse(Some universeExpr) ->
                typeContainsSuspension universeExpr
            | TypeIntrinsic _ ->
                false
            | TypeApply(callee, arguments) ->
                typeContainsSuspension callee || (arguments |> List.exists typeContainsSuspension)
            | TypeLambda(_, parameterSort, body) ->
                typeContainsSuspension parameterSort || typeContainsSuspension body
            | TypeProject(target, _) ->
                typeContainsSuspension target
            | TypeName(nameSegments, _) when
                matchesKnownType CompilerKnownSymbols.ThunkType nameSegments
                || matchesKnownType CompilerKnownSymbols.NeedType nameSegments ->
                true
            | TypeName(_, arguments) ->
                arguments |> List.exists typeContainsSuspension
            | TypeArrow(_, parameterType, resultType) ->
                typeContainsSuspension parameterType || typeContainsSuspension resultType
            | TypeEquality(left, right) ->
                typeContainsSuspension left || typeContainsSuspension right
            | TypeCapture(inner, _) ->
                typeContainsSuspension inner
            | TypeEffectRow(entries, tail) ->
                entries
                |> List.exists (fun entry ->
                    typeContainsSuspension entry.Label
                    || typeContainsSuspension entry.Effect)
                || tail |> Option.exists typeContainsSuspension
            | TypeRecord fields ->
                fields |> List.exists (fun field -> typeContainsSuspension field.Type)
            | TypeUnion members ->
                members |> List.exists typeContainsSuspension
            | TypeVariable _ ->
                false

        let rec typeContainsUnion typeExpr =
            match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
            | TypeLevelLiteral _ ->
                false
            | TypeUniverse None ->
                false
            | TypeUniverse(Some universeExpr) ->
                typeContainsUnion universeExpr
            | TypeIntrinsic _ ->
                false
            | TypeApply(callee, arguments) ->
                typeContainsUnion callee || (arguments |> List.exists typeContainsUnion)
            | TypeLambda(_, parameterSort, body) ->
                typeContainsUnion parameterSort || typeContainsUnion body
            | TypeDelay inner
            | TypeMemo inner
            | TypeForce inner ->
                typeContainsUnion inner
            | TypeProject(target, _) ->
                typeContainsUnion target
            | TypeUnion _ ->
                true
            | TypeName(_, arguments) ->
                arguments |> List.exists typeContainsUnion
            | TypeArrow(_, parameterType, resultType) ->
                typeContainsUnion parameterType || typeContainsUnion resultType
            | TypeEquality(left, right) ->
                typeContainsUnion left || typeContainsUnion right
            | TypeCapture(inner, _) ->
                typeContainsUnion inner
            | TypeEffectRow(entries, tail) ->
                entries
                |> List.exists (fun entry ->
                    typeContainsUnion entry.Label
                    || typeContainsUnion entry.Effect)
                || tail |> Option.exists typeContainsUnion
            | TypeRecord fields ->
                fields |> List.exists (fun field -> typeContainsUnion field.Type)
            | TypeVariable _ ->
                false

        let rec typeIsStableForValidationInference locals typeExpr =
            match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
            | TypeLevelLiteral _ ->
                true
            | TypeUniverse None ->
                true
            | TypeUniverse(Some universeExpr) ->
                typeIsStableForValidationInference locals universeExpr
            | TypeIntrinsic _ ->
                true
            | TypeApply _
            | TypeLambda _
            | TypeDelay _
            | TypeMemo _
            | TypeForce _
            | TypeProject _
            | TypeEquality _
            | TypeCapture _
            | TypeVariable _ ->
                false
            | TypeName(_, arguments) ->
                arguments |> List.forall (typeIsStableForValidationInference locals)
            | TypeArrow(quantity, parameterType, resultType) ->
                quantity = QuantityOmega
                && typeIsStableForValidationInference locals parameterType
                && typeIsStableForValidationInference locals resultType
            | TypeEffectRow(entries, tail) ->
                entries
                |> List.forall (fun entry ->
                    typeIsStableForValidationInference locals entry.Label
                    && typeIsStableForValidationInference locals entry.Effect)
                && tail |> Option.forall (typeIsStableForValidationInference locals)
            | TypeRecord fields ->
                fields
                |> List.forall (fun field ->
                    (field.Quantity = QuantityOmega || field.Quantity = QuantityZero)
                    && typeIsStableForValidationInference locals field.Type)
            | TypeUnion members ->
                members |> List.forall (typeIsStableForValidationInference locals)

        let canCompareInferredValidationTypes locals expectedType actualType =
            not (typeContainsLocalTermVariable locals expectedType)
            && not (typeContainsLocalTermVariable locals actualType)
            && typeIsStableForValidationInference locals expectedType
            && typeIsStableForValidationInference locals actualType

        let rec tryValidationTypeShape typeExpr =
            match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
            | TypeName(nameSegments, _) ->
                Some("name:" + (String.concat "." nameSegments))
            | TypeApply(callee, _) ->
                tryValidationTypeShape callee
            | TypeCapture(inner, _) ->
                tryValidationTypeShape inner
            | TypeDelay inner
            | TypeMemo inner
            | TypeForce inner ->
                tryValidationTypeShape inner
            | TypeArrow _ ->
                Some("arrow")
            | TypeIntrinsic intrinsic ->
                Some("intrinsic:" + string intrinsic)
            | TypeRecord _ ->
                Some("record")
            | TypeUnion _ ->
                Some("union")
            | TypeEffectRow _ ->
                Some("effect-row")
            | TypeUniverse _ ->
                Some("universe")
            | TypeLevelLiteral _ ->
                Some("type-literal")
            | TypeVariable _
            | TypeLambda _
            | TypeProject _
            | TypeEquality _ ->
                None

        let canCompareDistinctValidationShapes expectedType actualType =
            let normalizedExpected = normalizeTypeAliases environment.VisibleTypeAliases expectedType
            let normalizedActual = normalizeTypeAliases environment.VisibleTypeAliases actualType

            if isCompileTimeArgumentType environment.VisibleTypeAliases normalizedExpected
               || isCompileTimeArgumentType environment.VisibleTypeAliases normalizedActual
               || (tryTraitConstraintFromType environment normalizedExpected |> Option.isSome)
               || (tryTraitConstraintFromType environment normalizedActual |> Option.isSome) then
                false
            else
                match tryValidationTypeShape normalizedExpected, tryValidationTypeShape normalizedActual with
                | Some expectedShape, Some actualShape when not (String.Equals(expectedShape, actualShape, StringComparison.Ordinal)) ->
                    true
                | _ ->
                    false

        let rec typeIsCallableLikeForValidation typeExpr =
            match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
            | TypeCapture(innerType, _) ->
                typeIsCallableLikeForValidation innerType
            | normalizedType ->
                isCallableValidationType environment.VisibleTypeAliases normalizedType

        let canCompareDirectLocalNameArgumentTypes locals argument expectedType actualType =
            match argument with
            | Name [ name ]
                when Map.containsKey name locals
                     || environment.VisibleBindings.ContainsKey(name)
                     || environment.VisibleConstructors.ContainsKey(name) ->
                typeIsCallableLikeForValidation expectedType
                && typeIsCallableLikeForValidation actualType
            | _ ->
                false

        let needsDependentTransportComparison locals expectedType actualType =
            typeIsStableForValidationInference locals expectedType
            && typeContainsLocalTermVariable locals actualType

        let trySuspensionInner typeExpr =
            match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
            | TypeName(nameSegments, [ inner ]) when
                matchesKnownType CompilerKnownSymbols.ThunkType nameSegments ->
                Some inner
            | TypeName(nameSegments, [ inner ]) when
                matchesKnownType CompilerKnownSymbols.NeedType nameSegments ->
                Some inner
            | _ ->
                None

        let tryUnionMembers typeExpr =
            match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
            | TypeUnion members -> Some members
            | _ -> None

        let rec expectedTypeAccepts locals refinements expectedType actualType =
            let expectedType = normalizeExpectedType refinements expectedType
            let actualType = normalizeExpectedType refinements actualType

            if TypeSignatures.definitionallyEqual expectedType actualType then
                true
            else
                match trySuspensionInner expectedType with
                | Some innerType ->
                    expectedTypeAccepts locals refinements innerType actualType
                | None ->
                    match expectedType, actualType with
                    | TypeArrow(expectedQuantity, expectedParameter, expectedResult),
                      TypeArrow(actualQuantity, actualParameter, actualResult)
                        when TypeSignatures.definitionallyEqual expectedParameter actualParameter
                             && TypeSignatures.definitionallyEqual expectedResult actualResult
                             && ResourceModel.ResourceQuantity.satisfies
                                    (ResourceModel.ResourceQuantity.ofSurface expectedQuantity)
                                    (ResourceModel.ResourceQuantity.ofSurface actualQuantity) ->
                        true
                    | TypeRecord expectedFields, TypeRecord actualFields ->
                        let actualFieldMap =
                            actualFields
                            |> List.map (fun field -> field.Name, field)
                            |> Map.ofList

                        List.length expectedFields = List.length actualFields
                        && expectedFields
                           |> List.forall (fun expectedField ->
                               actualFieldMap
                               |> Map.tryFind expectedField.Name
                               |> Option.exists (fun actualField ->
                                   expectedField.Quantity = actualField.Quantity
                                   && expectedTypeAccepts locals refinements expectedField.Type actualField.Type))
                    | _ ->
                        match tryUnionMembers expectedType, tryUnionMembers actualType with
                        | Some expectedMembers, Some actualMembers ->
                            actualMembers
                            |> List.forall (fun actualMember ->
                                expectedMembers
                                |> List.exists (fun expectedMember ->
                                    expectedTypeAccepts locals refinements expectedMember actualMember))
                        | Some expectedMembers, None ->
                            expectedMembers
                            |> List.exists (fun expectedMember ->
                                expectedTypeAccepts locals refinements expectedMember actualType)
                        | _ when typeContainsLocalTermVariable locals expectedType
                                 || typeContainsLocalTermVariable locals actualType ->
                            false
                        | _ ->
                            tryUnifyVisibleTypes environment.VisibleTypeAliases [ expectedType, actualType ]
                            |> Option.isSome

        let bindablePayloadTypesAgree locals refinements expectedType actualType =
            match
                tryUnwrapBindablePayloadType environment.VisibleTypeAliases expectedType,
                tryUnwrapBindablePayloadType environment.VisibleTypeAliases actualType
            with
            | Some expectedPayload, Some actualPayload ->
                expectedTypeAccepts locals refinements expectedPayload actualPayload
            | _ ->
                false

        let expectedMismatchDiagnostic locals refinements mismatchKind context expectedType actualType =
            let expectedType = normalizeExpectedType refinements expectedType
            let actualType = normalizeExpectedType refinements actualType
            let expectedText = TypeSignatures.toText expectedType
            let actualText = TypeSignatures.toText actualType

            let reason =
                if typeContainsLocalTermVariable locals expectedType
                   || typeContainsLocalTermVariable locals actualType then
                    DependentEqualityTransportRequired
                elif
                    match expectedType, actualType with
                    | TypeArrow _, TypeArrow _ -> true
                    | _ -> false
                then
                    FunctionQuantityIncompatible
                elif typeContainsUnion expectedType then
                    UnionCompatibilityFailed
                elif typeContainsSuspension expectedType then
                    SuspensionCompatibilityFailed
                else
                    GeneralExpectedActualMismatch

            Diagnostics.errorFact
                "KFrontIR"
                (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                None
                []
                (DiagnosticFact.expectedActualTypeMismatch context expectedText actualText mismatchKind reason)

        let expectedTypeDiagnostics locals refinements context expectedType expression =
            match tryNumericLiteralRangeDiagnostic expectedType expression with
            | Some diagnostic ->
                [ diagnostic ]
            | None ->
                match tryInferNumericExpressionTypeFromContext environment expectedType expression with
                | Some actualType when not (expectedTypeAccepts locals refinements expectedType actualType) ->
                    [ expectedMismatchDiagnostic locals refinements ExpressionTypeMismatch context expectedType actualType ]
                | Some _ ->
                    []
                | None ->
                    match inferValidationExpressionType environment freshCounter locals expression with
                    | Some actualType when not (expectedTypeAccepts locals refinements expectedType actualType) ->
                        [ expectedMismatchDiagnostic locals refinements ExpressionTypeMismatch context expectedType actualType ]
                    | _ ->
                        []

        let bindableCarrierExpectedTypeDiagnostics locals refinements context expectedType expression =
            match expression with
            | Do statements ->
                match
                    tryUnwrapBindablePayloadType environment.VisibleTypeAliases expectedType,
                    inferValidationDoResultType environment freshCounter locals statements
                with
                | Some expectedPayload, Some actualDoResultType ->
                    let actualPayload =
                        tryUnwrapBindablePayloadType environment.VisibleTypeAliases actualDoResultType
                        |> Option.defaultValue actualDoResultType

                    if expectedTypeAccepts locals refinements expectedPayload actualPayload then
                        []
                    else
                        [ expectedMismatchDiagnostic
                            locals
                            refinements
                            ExpressionTypeMismatch
                            context
                            expectedPayload
                            actualPayload ]
                | _ ->
                    expectedTypeDiagnostics locals refinements context expectedType expression
            | _ ->
                match inferValidationExpressionType environment freshCounter locals expression with
                | Some actualType when bindablePayloadTypesAgree locals refinements expectedType actualType ->
                    []
                | _ ->
                    expectedTypeDiagnostics locals refinements context expectedType expression

        let rec isHandlerCarrierResultType typeExpr =
            match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
            | TypeCapture(innerType, _) ->
                isHandlerCarrierResultType innerType
            | TypeName(_, _ :: _) ->
                true
            | _ ->
                false

        let isSimpleExpectedBodyType locals typeExpr =
            match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
            | TypeIntrinsic _ ->
                true
            | TypeName(root :: _, []) ->
                not (
                    Map.containsKey root locals
                    || environment.VisibleBindings.ContainsKey(root)
                    || environment.VisibleConstructors.ContainsKey(root)
                )
            | TypeName([], []) ->
                true
            | _ ->
                false

        let fieldTypeReferences (recordInfo: RecordSurfaceInfo) (tokens: Token list) =
            let fieldNames = recordSurfaceFieldNames recordInfo
            let tokenArray = significantTokens tokens |> List.toArray
            let references = ResizeArray<string>()

            for index = 0 to tokenArray.Length - 1 do
                let token = tokenArray[index]

                if Token.isName token then
                    let name = SyntaxFacts.trimIdentifierQuotes token.Text

                    if String.Equals(name, "this", StringComparison.Ordinal)
                       && index + 2 < tokenArray.Length
                       && tokenArray[index + 1].Kind = Dot
                       && Token.isName tokenArray[index + 2] then
                        references.Add(SyntaxFacts.trimIdentifierQuotes tokenArray[index + 2].Text)
                    elif Set.contains name fieldNames then
                        references.Add(name)

            references |> Seq.toList |> List.distinct

        let expressionThisReferences expression =
            let rec loop current =
                seq {
                    match current with
                    | Name("this" :: fieldName :: _) ->
                        yield fieldName
                    | TypeSyntaxTokens _ ->
                        ()
                    | SyntaxQuote inner
                    | SyntaxSplice inner
                    | TopLevelSyntaxSplice inner
                    | CodeQuote inner
                    | CodeSplice inner ->
                        yield! loop inner
                    | LocalLet(_, value, body) ->
                        yield! loop value
                        yield! loop body
                    | LocalSignature(_, body) ->
                        yield! loop body
                    | LocalTypeAlias(_, body) ->
                        yield! loop body
                    | LocalScopedEffect(_, body) ->
                        yield! loop body
                    | Handle(_, label, body, returnClause, operationClauses) ->
                        yield! loop label
                        yield! loop body
                        yield! loop returnClause.Body

                        for clause in operationClauses do
                            yield! loop clause.Body
                    | Lambda(_, body) ->
                        yield! loop body
                    | IfThenElse(condition, whenTrue, whenFalse) ->
                        yield! loop condition
                        yield! loop whenTrue
                        yield! loop whenFalse
                    | Match(scrutinee, cases) ->
                        yield! loop scrutinee
                        for caseClause in cases do
                            match caseClause.Guard with
                            | Some guard -> yield! loop guard
                            | None -> ()
                            yield! loop caseClause.Body
                    | RecordLiteral fields ->
                        for field in fields do
                            yield! loop field.Value
                    | Seal(value, _) ->
                        yield! loop value
                    | RecordUpdate(receiver, fields) ->
                        yield! loop receiver
                        for field in fields do
                            yield! loop field.Value
                    | MemberAccess(receiver, _, arguments) ->
                        yield! loop receiver
                        for argument in arguments do
                            yield! loop argument
                    | SafeNavigation(receiver, navigation) ->
                        yield! loop receiver
                        for argument in navigation.Arguments do
                            yield! loop argument
                    | TagTest(receiver, _) ->
                        yield! loop receiver
                    | Do statements ->
                        for statement in statements do
                            match statement with
                            | DoLet(_, value)
                            | DoBind(_, value)
                            | DoUsing(_, value)
                            | DoVar(_, value)
                            | DoAssign(_, value)
                            | DoDefer value
                            | DoExpression value
                            | DoReturn value ->
                                yield! loop value
                            | DoLetQuestion(_, value, failure) ->
                                yield! loop value
                                match failure with
                                | Some failure ->
                                    for nested in failure.Body do
                                        match nested with
                                        | DoExpression expression -> yield! loop expression
                                        | _ -> ()
                                | None -> ()
                            | DoIf(condition, _, _) ->
                                yield! loop condition
                            | DoWhile(condition, _) ->
                                yield! loop condition
                    | MonadicSplice inner
                    | ExplicitImplicitArgument inner
                    | InoutArgument inner
                    | Unary(_, inner) ->
                        yield! loop inner
                    | NamedApplicationBlock fields ->
                        for field in fields do
                            yield! loop field.Value
                    | Apply(callee, arguments) ->
                        yield! loop callee
                        for argument in arguments do
                            yield! loop argument
                    | Binary(left, _, right)
                    | Elvis(left, right) ->
                        yield! loop left
                        yield! loop right
                    | Comprehension comprehension ->
                        yield! loop comprehension.Lowered
                    | PrefixedString(_, parts) ->
                        for part in parts do
                            match part with
                            | StringInterpolation(inner, _) -> yield! loop inner
                            | StringText _ -> ()
                    | Literal _
                    | NumericLiteral _
                    | KindQualifiedName _
                    | Name _ ->
                        ()
                }

            loop expression |> Seq.toList |> List.distinct

        let hasCycle (edges: Map<string, Set<string>>) =
            let rec visit visiting visited node =
                if Set.contains node visiting then
                    true
                elif Set.contains node visited then
                    false
                else
                    let nextVisiting = Set.add node visiting
                    let dependencies = edges |> Map.tryFind node |> Option.defaultValue Set.empty

                    dependencies
                    |> Set.exists (visit nextVisiting (Set.add node visited))

            edges |> Map.exists (fun node _ -> visit Set.empty Set.empty node)

        let validateRecordSurfaceInfo (recordInfo: RecordSurfaceInfo) =
            let duplicateDiagnostics =
                recordInfo.Fields
                |> List.countBy (fun field -> field.Name)
                |> List.choose (fun (name, count) ->
                    if count > 1 then
                        Some(Diagnostics.errorFact "KFrontIR" (Some(KFrontIRPhase.phaseName CORE_LOWERING)) None [] (DiagnosticFact.surfaceRecord (RecordFieldDeclaredMoreThanOnce name)))
                    else
                        None)

            let fieldNames = recordSurfaceFieldNames recordInfo

            let dependencyDiagnostics =
                recordInfo.Fields
                |> List.collect (fun field ->
                    fieldTypeReferences recordInfo field.TypeTokens
                    |> List.choose (fun referencedField ->
                        if Set.contains referencedField fieldNames then
                            None
                        else
                            Some(
                                Diagnostics.errorFact
                                    "KFrontIR"
                                    (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                    None
                                    []
                                    (DiagnosticFact.surfaceRecord (RecordFieldDependsOnUnknownField(field.Name, referencedField)))
                            )))

            let cycleDiagnostics =
                let dependencyMap =
                    recordInfo.Fields
                    |> List.map (fun field ->
                        field.Name,
                        fieldTypeReferences recordInfo field.TypeTokens
                        |> List.filter (fun referencedField ->
                            Set.contains referencedField fieldNames
                            && not (String.Equals(referencedField, field.Name, StringComparison.Ordinal)))
                        |> Set.ofList)
                    |> Map.ofList

                if hasCycle dependencyMap then
                    [ Diagnostics.errorFact "KFrontIR" (Some(KFrontIRPhase.phaseName CORE_LOWERING)) None [] (DiagnosticFact.surfaceRecord (RecordDependenciesMustBeAcyclic RecordTypeTelescope)) ]
                else
                    []

            duplicateDiagnostics @ dependencyDiagnostics @ cycleDiagnostics

        let pathKey (field: SurfaceRecordUpdateField) =
            field.Path
            |> List.map (fun segment -> if segment.IsImplicit then $"@{segment.Name}" else segment.Name)
            |> String.concat "."

        let isStrictPrefix left right =
            List.length left < List.length right
            && List.forall2
                (fun (leftSegment: SurfaceRecordUpdatePathSegment) (rightSegment: SurfaceRecordUpdatePathSegment) ->
                    leftSegment.IsImplicit = rightSegment.IsImplicit
                    && String.Equals(leftSegment.Name, rightSegment.Name, StringComparison.Ordinal))
                left
                (right |> List.take (List.length left))

        let hasLacksConstraint rowName labelName =
            let parameterHasConstraint =
                definition.Parameters
                |> List.exists (fun parameter ->
                    parameter.TypeTokens
                    |> Option.map tokenText
                    |> Option.exists (fun text -> String.Equals(text, $"LacksRec {rowName} {labelName}", StringComparison.Ordinal)))

            let schemeHasConstraint =
                scheme
                |> Option.exists (fun scheme ->
                    scheme.Constraints
                    |> List.exists (fun constraintInfo ->
                        String.Equals(traitConstraintLocalName constraintInfo, "LacksRec", StringComparison.Ordinal)
                        && match constraintInfo.Arguments with
                           | [ TypeVariable row; TypeVariable label ] ->
                               String.Equals(row, rowName, StringComparison.Ordinal)
                               && String.Equals(label, labelName, StringComparison.Ordinal)
                           | _ ->
                               false))

            parameterHasConstraint || schemeHasConstraint

        let validateRecordPatch locals receiver fields =
            let ordinaryFields = fields |> List.filter (fun field -> not field.IsExtension && field.Name <> "<missing>")
            let extensionFields = fields |> List.filter (fun field -> field.IsExtension && field.Name <> "<missing>")

            let projectionPatchInfo (field: SurfaceRecordUpdateField) =
                match receiver, field.Path with
                | Name [ receiverName ], [ segment ] ->
                    tryReceiverProjection environment locals receiverName segment.Name
                | _ ->
                    None

            let projectionSupportsSet (projectionInfo: ProjectionInfo) =
                match projectionInfo.Body with
                | Some(ProjectionAccessors clauses) ->
                    let clauseKinds =
                        clauses
                        |> List.map (function
                            | ProjectionGet _ -> "get"
                            | ProjectionInout _ -> "open"
                            | ProjectionSet _ -> "set"
                            | ProjectionSink _ -> "sink")
                        |> Set.ofList

                    Set.contains "set" clauseKinds || Set.contains "open" clauseKinds
                | Some _ ->
                    true
                | None ->
                    false

            let duplicatePathDiagnostics =
                ordinaryFields
                |> List.countBy pathKey
                |> List.choose (fun (path, count) ->
                    if count > 1 then
                        Some(Diagnostics.errorFact "KFrontIR" (Some(KFrontIRPhase.phaseName CORE_LOWERING)) None [] (DiagnosticFact.surfaceRecord (RecordPatchPathDeclaredMoreThanOnce path)))
                    else
                        None)

            let prefixDiagnostics =
                ordinaryFields
                |> List.allPairs ordinaryFields
                |> List.choose (fun (left, right) ->
                    if isStrictPrefix left.Path right.Path then
                        Some(
                            Diagnostics.errorFact
                                "KFrontIR"
                                (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                None
                                []
                                (DiagnosticFact.surfaceRecord (RecordPatchPathStrictPrefixConflict(pathKey left, pathKey right)))
                        )
                    else
                        None)
                |> List.distinctBy (fun diagnostic -> diagnostic.Message)

            let duplicateExtensionDiagnostics =
                extensionFields
                |> List.countBy (fun field -> field.Name)
                |> List.choose (fun (name, count) ->
                    if count > 1 then
                        Some(Diagnostics.errorFact "KFrontIR" (Some(KFrontIRPhase.phaseName CORE_LOWERING)) None [] (DiagnosticFact.surfaceRecord (RowExtensionLabelDeclaredMoreThanOnce name)))
                    else
                        None)

            let receiverRecordInfo = tryRecordInfoForExpression locals receiver

            let extensionDiagnostics =
                match receiverRecordInfo with
                | Some recordInfo ->
                    let explicitFields = recordSurfaceFieldNames recordInfo

                    extensionFields
                    |> List.choose (fun field ->
                        if Set.contains field.Name explicitFields then
                            Some(Diagnostics.errorFact "KFrontIR" (Some(KFrontIRPhase.phaseName CORE_LOWERING)) None [] (DiagnosticFact.surfaceRecord (RowExtensionLabelAlreadyExists field.Name)))
                        else
                            match recordInfo.RowTail with
                            | Some rowName when not (hasLacksConstraint rowName field.Name) ->
                                Some(
                                    Diagnostics.errorFact
                                        "KFrontIR"
                                        (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                        None
                                        []
                                        (DiagnosticFact.surfaceRecord (RowExtensionLabelMissingLacksConstraint(field.Name, rowName)))
                                )
                            | _ ->
                                None)
                | None ->
                    []

            let unknownPathDiagnostics =
                let rec validatePath (currentRecordInfo: RecordSurfaceInfo) (path: SurfaceRecordUpdatePathSegment list) =
                    match path with
                    | [] ->
                        []
                    | segment :: rest ->
                        match currentRecordInfo.Fields |> List.tryFind (fun (field: RecordSurfaceFieldInfo) -> String.Equals(field.Name, segment.Name, StringComparison.Ordinal)) with
                        | None ->
                            [ Diagnostics.errorFact "KFrontIR" (Some(KFrontIRPhase.phaseName CORE_LOWERING)) None [] (DiagnosticFact.surfaceRecord (RecordPatchUnknownField segment.Name)) ]
                        | Some field when List.isEmpty rest ->
                            []
                        | Some field ->
                            match tryRecordInfoFromTypeTokens field.TypeTokens with
                            | Some nestedRecordInfo -> validatePath nestedRecordInfo rest
                            | None ->
                                [ Diagnostics.errorFact "KFrontIR" (Some(KFrontIRPhase.phaseName CORE_LOWERING)) None [] (DiagnosticFact.surfaceRecord (RecordPatchContinuesThroughNonRecordField field.Name)) ]

                match receiverRecordInfo with
                | Some recordInfo ->
                    ordinaryFields
                    |> List.collect (fun field ->
                        match projectionPatchInfo field with
                        | Some _ -> []
                        | None -> validatePath recordInfo field.Path)
                | None ->
                    []

            let projectionPatchDiagnostics =
                ordinaryFields
                |> List.choose (fun field ->
                    projectionPatchInfo field
                    |> Option.bind (fun projectionInfo ->
                        if projectionSupportsSet projectionInfo then
                            None
                        else
                            Some(Diagnostics.errorFact "KFrontIR" (Some(KFrontIRPhase.phaseName CORE_LOWERING)) None [] (DiagnosticFact.surfaceRecord ProjectionSectionUpdateTargetUnsupported))))

            duplicatePathDiagnostics
            @ prefixDiagnostics
            @ duplicateExtensionDiagnostics
            @ extensionDiagnostics
            @ unknownPathDiagnostics
            @ projectionPatchDiagnostics

        let validateRecordLiteral (fields: SurfaceRecordLiteralField list) =
            let fieldNames = fields |> List.map (fun (field: SurfaceRecordLiteralField) -> field.Name) |> Set.ofList

            let dependencyMap =
                fields
                |> List.map (fun (field: SurfaceRecordLiteralField) ->
                    field.Name,
                    expressionThisReferences field.Value
                    |> List.filter (fun name -> Set.contains name fieldNames && not (String.Equals(name, field.Name, StringComparison.Ordinal)))
                    |> Set.ofList)
                |> Map.ofList

            if hasCycle dependencyMap then
                [ Diagnostics.errorFact "KFrontIR" (Some(KFrontIRPhase.phaseName CORE_LOWERING)) None [] (DiagnosticFact.surfaceRecord (RecordDependenciesMustBeAcyclic RecordLiteralFields)) ]
            else
                []

        let validateRecordLiteralFieldValuesWithRecordInfo
            (validateNested: SurfaceExpression -> Diagnostic list)
            (recordInfo: RecordSurfaceInfo)
            (fields: SurfaceRecordLiteralField list)
            =
            fields
            |> List.collect (fun literalField ->
                match recordInfo.Fields |> List.tryFind (fun field -> String.Equals(field.Name, literalField.Name, StringComparison.Ordinal)) with
                | Some recordField ->
                    match recordField.TypeTokens |> TypeSignatures.parseType with
                    | Some fieldType when isCompileTimeArgumentType environment.VisibleTypeAliases fieldType ->
                        match tryParseTypeLikeSurfaceExpression literalField.Value with
                        | Some _ ->
                            []
                        | None ->
                            match tryResolveScopedStaticObject environment literalField.Value with
                            | Some _ ->
                                []
                            | None ->
                                validateNested literalField.Value
                    | _ ->
                        validateNested literalField.Value
                | None ->
                    validateNested literalField.Value)

        let recordInfoHasOpaqueMembers (recordInfo: RecordSurfaceInfo) =
            recordInfo.Fields |> List.exists (fun (field: RecordSurfaceFieldInfo) -> field.IsOpaque)

        let compactTokenText tokens =
            tokens
            |> significantTokens
            |> List.map (fun token -> token.Text)
            |> String.concat ""

        let fieldMentionsOpaqueMember (recordInfo: RecordSurfaceInfo) (field: RecordSurfaceFieldInfo) =
            let opaqueNames =
                recordInfo.Fields
                |> List.filter (fun (item: RecordSurfaceFieldInfo) -> item.IsOpaque)
                |> List.map (fun item -> item.Name)
                |> Set.ofList

            let compactFieldType = compactTokenText field.TypeTokens

            (fieldTypeReferences recordInfo field.TypeTokens
             |> List.exists (fun name -> Set.contains name opaqueNames))
            || (opaqueNames
                |> Set.exists (fun opaqueName -> compactFieldType.Contains($"this.{opaqueName}", StringComparison.Ordinal)))

        let expectedTypeCompactText =
            definition.ReturnTypeTokens
            |> Option.map compactTokenText
            |> Option.orElseWith (fun () ->
                scheme
                |> Option.map (fun scheme -> TypeSignatures.toText scheme.Body)
                |> Option.map (fun text -> text.Replace(" ", "")))

        let isTransparentCompileTimeField (field: RecordSurfaceFieldInfo) =
            not field.IsOpaque
            &&
                match significantTokens field.TypeTokens with
                | [ typeToken ] when Token.isName typeToken ->
                    let typeName = SyntaxFacts.trimIdentifierQuotes typeToken.Text
                    List.contains
                        typeName
                        [ "Type"
                          CompilerKnownSymbols.KnownTypeNames.Constraint
                          CompilerKnownSymbols.KnownTypeNames.Quantity
                          CompilerKnownSymbols.KnownTypeNames.Region
                          CompilerKnownSymbols.KnownTypeNames.RecRow
                          CompilerKnownSymbols.KnownTypeNames.Label ]
                | _ ->
                    false

        let expressionOpaqueUnfoldingDiagnostic locals expression =
            let expectedText = expectedTypeCompactText |> Option.defaultValue ""

            let checkRootMember root memberName =
                tryRecordInfoForRoot locals root
                |> Option.bind (fun recordInfo ->
                    recordInfo.Fields
                    |> List.tryFind (fun (field: RecordSurfaceFieldInfo) -> String.Equals(field.Name, memberName, StringComparison.Ordinal))
                    |> Option.bind (fun field ->
                        if fieldMentionsOpaqueMember recordInfo field then
                            let opaqueNames =
                                recordInfo.Fields
                                |> List.filter (fun (item: RecordSurfaceFieldInfo) -> item.IsOpaque)
                                |> List.map (fun item -> $"{root}.{item.Name}")

                            if opaqueNames |> List.exists (fun opaqueName -> expectedText.Contains(opaqueName, StringComparison.Ordinal)) then
                                None
                            else
                                Some(
                                    Diagnostics.errorFact
                                        "KFrontIR"
                                        (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                        None
                                        []
                                        (DiagnosticFact.surfaceElaboration
                                            (SealProjectionWouldExposeOpaqueDependentMember(root, memberName)))
                                )
                        else
                            None))

            match expression with
            | Name(root :: memberName :: _) ->
                checkRootMember root memberName
            | Apply(Name(root :: memberName :: _), _) ->
                checkRootMember root memberName
            | MemberAccess(Name [ root ], [ memberName ], []) ->
                checkRootMember root memberName
            | Apply(MemberAccess(Name [ root ], [ memberName ], []), _) ->
                checkRootMember root memberName
            | _ ->
                None

        let projectionMismatchDiagnostics locals root memberName (expectedText: string) =
            match tryRecordInfoForRoot locals root with
            | Some recordInfo ->
                match recordInfo.Fields |> List.tryFind (fun (field: RecordSurfaceFieldInfo) -> String.Equals(field.Name, memberName, StringComparison.Ordinal)) with
                | Some field ->
                    if fieldMentionsOpaqueMember recordInfo field then
                        []
                    else
                        let unstableDependencies =
                            fieldTypeReferences recordInfo field.TypeTokens
                            |> List.choose (fun dependencyName ->
                                recordInfo.Fields
                                |> List.tryFind (fun candidate -> String.Equals(candidate.Name, dependencyName, StringComparison.Ordinal))
                                |> Option.filter (isTransparentCompileTimeField >> not)
                                |> Option.map (fun _ -> dependencyName))

                        if
                            unstableDependencies
                            |> List.exists (fun dependencyName -> expectedText.Contains($"{root}.{dependencyName}", StringComparison.Ordinal) |> not)
                        then
                            [ makeSurfaceElaborationDiagnostic
                                ProjectedFieldTypeDoesNotMatchDeclaredResultType ]
                        else
                            []
                | None ->
                    []
            | None ->
                []

        let validateExpectedBody locals body =
            let localImplicitTypes = buildLocalImplicitTypes effectiveScheme effectiveParameters

            let dropDefinitionParameters typeExpr =
                let rec loop remaining current =
                    if remaining <= 0 then
                        current
                    else
                        match current with
                        | TypeArrow(_, _, resultType) -> loop (remaining - 1) resultType
                        | _ -> current

                loop effectiveParameters.Length typeExpr

            let signatureExpectedBodyType =
                effectiveScheme
                |> Option.map (fun scheme ->
                    if List.isEmpty effectiveParameters then
                        scheme.Body
                    else
                        let schemeParameterTypes, schemeResultType = TypeSignatures.schemeParts scheme

                        let rec dropLeadingOmittableParameters remaining =
                            match remaining with
                            | parameterType :: rest
                                when isCompileTimeArgumentType environment.VisibleTypeAliases parameterType
                                     || (tryTraitConstraintFromType environment parameterType |> Option.isSome) ->
                                dropLeadingOmittableParameters rest
                            | _ ->
                                remaining

                        let alignableParameterTypes =
                            dropLeadingOmittableParameters schemeParameterTypes

                        match
                            tryAlignParameterTypesWithLayouts
                                environment
                                Map.empty
                                effectiveParameters
                                alignableParameterTypes
                        with
                        | Some(_, trailingParameterTypes) ->
                            trailingParameterTypes
                            |> List.rev
                            |> List.fold (fun current parameterType -> TypeArrow(QuantityOmega, parameterType, current)) schemeResultType
                        | None ->
                            dropDefinitionParameters scheme.Body)

            let expectedBodyType =
                definition.ReturnTypeTokens
                |> Option.bind TypeSignatures.parseType
                |> Option.orElse signatureExpectedBodyType

            let signatureReturnAnnotationDiagnostics =
                match definition.ReturnTypeTokens |> Option.bind TypeSignatures.parseType, signatureExpectedBodyType with
                | Some annotatedReturnType, Some signatureReturnType
                    when not (expectedTypeAccepts locals Map.empty signatureReturnType annotatedReturnType) ->
                    [ expectedMismatchDiagnostic
                        locals
                        Map.empty
                        FunctionResultMismatch
                        "Definition result annotation"
                        signatureReturnType
                        annotatedReturnType ]
                | _ ->
                    []

            let directSignatureLiteralDiagnostic =
                match body, definition.ReturnTypeTokens |> Option.bind tryRecordInfoFromTypeTokens with
                | RecordLiteral _, Some recordInfo when recordInfoHasOpaqueMembers recordInfo ->
                    [
                        Diagnostics.errorFact
                            "KFrontIR"
                            (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                            None
                            []
                            (DiagnosticFact.surfaceElaboration RecordLiteralCannotBeCheckedDirectlyAgainstSignatureType)
                    ]
                | _ ->
                    []

            let sealAscriptionDiagnostics =
                let rec loop expression =
                    match expression with
                    | Seal(value, ascriptionTokens) ->
                        let nested = loop value

                        match tryParseRecordSurfaceInfo ascriptionTokens with
                        | Some recordInfo when recordInfo.RowTail.IsSome ->
                            Diagnostics.errorFact
                                "KFrontIR"
                                (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                None
                                []
                                (DiagnosticFact.surfaceElaboration SealAscriptionMustBeClosedRecordType)
                            :: nested
                        | _ ->
                            nested
                    | LocalLet(_, value, nestedBody) -> loop value @ loop nestedBody
                    | LocalSignature(_, nestedBody) -> loop nestedBody
                    | LocalTypeAlias(_, nestedBody) -> loop nestedBody
                    | LocalScopedEffect(_, nestedBody) -> loop nestedBody
                    | Handle(_, label, nestedBody, returnClause, operationClauses) ->
                        loop label
                        @ loop nestedBody
                        @ loop returnClause.Body
                        @ (operationClauses |> List.collect (fun clause -> loop clause.Body))
                    | Lambda(_, nestedBody) -> loop nestedBody
                    | SyntaxQuote inner
                    | SyntaxSplice inner
                    | TopLevelSyntaxSplice inner
                    | CodeQuote inner
                    | CodeSplice inner -> loop inner
                    | IfThenElse(condition, whenTrue, whenFalse) -> loop condition @ loop whenTrue @ loop whenFalse
                    | Match(scrutinee, cases) ->
                        loop scrutinee
                        @ (cases
                           |> List.collect (fun caseClause ->
                               (caseClause.Guard |> Option.map loop |> Option.defaultValue [])
                               @ loop caseClause.Body))
                    | RecordLiteral fields -> fields |> List.collect (fun field -> loop field.Value)
                    | RecordUpdate(receiver, fields) -> loop receiver @ (fields |> List.collect (fun field -> loop field.Value))
                    | MemberAccess(receiver, _, arguments) -> loop receiver @ (arguments |> List.collect loop)
                    | SafeNavigation(receiver, navigation) -> loop receiver @ (navigation.Arguments |> List.collect loop)
                    | TagTest(receiver, _) -> loop receiver
                    | MonadicSplice inner
                    | ExplicitImplicitArgument inner
                    | InoutArgument inner
                    | Unary(_, inner) -> loop inner
                    | TypeSyntaxTokens _ -> []
                    | NamedApplicationBlock fields -> fields |> List.collect (fun field -> loop field.Value)
                    | Apply(callee, arguments) -> loop callee @ (arguments |> List.collect loop)
                    | Binary(left, _, right)
                    | Elvis(left, right) -> loop left @ loop right
                    | Comprehension comprehension -> loop comprehension.Lowered
                    | PrefixedString(_, parts) ->
                        parts
                        |> List.collect (function
                            | StringInterpolation(inner, _) -> loop inner
                            | StringText _ -> [])
                    | Literal _
                    | NumericLiteral _
                    | KindQualifiedName _
                    | Name _
                    | Do _ -> []

                loop body

            let opaqueUnfoldingDiagnostics =
                expressionOpaqueUnfoldingDiagnostic locals body |> Option.toList

            let projectionTypeMismatchDiagnostics =
                match body, expectedTypeCompactText with
                | Name(root :: memberName :: _), Some expectedText ->
                    projectionMismatchDiagnostics locals root memberName expectedText
                | MemberAccess(Name [ root ], [ memberName ], []), Some expectedText ->
                    projectionMismatchDiagnostics locals root memberName expectedText
                | _ ->
                    []

            let binaryExpectedBodyDiagnostics =
                match expectedBodyType, body with
                | Some expectedType, Binary(_, _, _) when isSimpleExpectedBodyType locals (normalizeExpectedType Map.empty expectedType) ->
                    expectedTypeDiagnostics locals Map.empty "Definition body" expectedType body
                | _ ->
                    []

            let listConsExpectedBodyDiagnostics =
                match expectedBodyType, body with
                | Some expectedType, Binary(left, "::", right) ->
                    match normalizeExpectedType Map.empty expectedType with
                    | TypeName(nameSegments, [ expectedElementType ]) when
                        matchesKnownType CompilerKnownSymbols.ListType nameSegments ->
                        let inferAgainstExpected expectedArgumentType argument =
                            match argument with
                            | Name [ argumentName ] when not (Map.containsKey argumentName locals) ->
                                let bindingInfo =
                                    if ordinarySurfaceNameShadowsVisiblePreludeBinding environment locals argumentName then
                                        None
                                    else
                                        environment.VisibleConstructors
                                        |> Map.tryFind argumentName
                                        |> Option.orElseWith (fun () -> environment.VisibleBindings |> Map.tryFind argumentName)

                                bindingInfo
                                |> Option.bind (fun currentBindingInfo ->
                                    let probeCounter = ref freshCounter.Value

                                    tryPrepareExpectedVisibleBindingValue
                                        environment
                                        probeCounter
                                        currentBindingInfo
                                        (Some localImplicitTypes)
                                        (inferValidationExpressionTypeWithContext
                                            environment
                                            probeCounter
                                            locals
                                            localImplicitTypes)
                                        (tryResolveUniqueLocalImplicitByType environment localImplicitTypes)
                                        expectedArgumentType
                                    |> Option.map (fun preparedCall -> preparedCall.ResultType))
                                |> Option.orElseWith (fun () ->
                                    inferValidationExpressionTypeWithContext
                                        environment
                                        freshCounter
                                        locals
                                        localImplicitTypes
                                        argument)
                            | _ ->
                                inferValidationExpressionTypeWithContext
                                    environment
                                    freshCounter
                                    locals
                                    localImplicitTypes
                                    argument

                        match
                            inferAgainstExpected expectedElementType left,
                            inferAgainstExpected expectedType right
                        with
                        | Some headType, Some tailType ->
                            let headDiagnostics =
                                if expectedTypeAccepts locals Map.empty expectedElementType headType then
                                    []
                                else
                                    [ expectedMismatchDiagnostic
                                        locals
                                        Map.empty
                                        ExpressionTypeMismatch
                                        "List cons head"
                                        expectedElementType
                                        headType ]

                            let tailDiagnostics =
                                if expectedTypeAccepts locals Map.empty expectedType tailType then
                                    []
                                else
                                    [ expectedMismatchDiagnostic
                                        locals
                                        Map.empty
                                        ExpressionTypeMismatch
                                        "List cons tail"
                                        expectedType
                                        tailType ]

                            headDiagnostics @ tailDiagnostics
                        | _ ->
                            []
                    | normalizedExpectedType ->
                        [
                            makeDiagnostic
                                SimpleDiagnosticKind.TypeEqualityMismatch
                                $"Definition body uses list-cons syntax and therefore must have a List result type, but the declared result type is '{TypeSignatures.toText normalizedExpectedType}'."
                        ]
                | _ ->
                    []

            let staticObjectResultDiagnostics =
                match expectedBodyType, inferValidationExpressionType environment freshCounter locals body with
                | Some expectedType, Some actualType
                    when isReifiedStaticObjectType environment.VisibleTypeAliases actualType
                         && not (expectedTypeAccepts locals Map.empty expectedType actualType) ->
                    expectedTypeDiagnostics locals Map.empty "Definition body" expectedType body
                | _ ->
                    []

            let staticObjectOnlyValueDiagnostics =
                match expectedBodyType, body with
                | Some expectedType, Name [ name ]
                    when not (Map.containsKey name locals)
                         && not (environment.VisibleBindings.ContainsKey name)
                         && not (environment.VisibleConstructors.ContainsKey name) ->
                    match tryResolveScopedStaticObject environment body with
                    | Some staticObject ->
                        let actualType =
                            staticObject.Scheme
                            |> Option.map (fun scheme -> scheme.Body)

                        match actualType with
                        | Some _ ->
                            []
                        | None ->
                            [ makeDiagnostic
                                SimpleDiagnosticKind.TypeEqualityMismatch
                                "A type or static object value cannot satisfy this definition body." ]
                    | None ->
                        []
                | _ ->
                    []

            let typeNamespaceOnlyNameDiagnostics =
                match body with
                | Name [ name ]
                    when not (Map.containsKey name locals)
                         && not (environment.VisibleBindings.ContainsKey name)
                         && not (environment.VisibleConstructors.ContainsKey name)
                         && (tryFindVisibleStaticGroup environment [ name] |> Option.isSome) ->
                    match tryResolveScopedStaticObject environment body with
                    | Some _ ->
                        []
                    | None ->
                        [ makeNameUnresolvedDiagnostic name ]
                | _ ->
                    []

            let constructorAsStaticObjectDiagnostics =
                match expectedBodyType, body with
                | Some expectedType, Name [ root ]
                    when isVisibleConstructorName root
                         && TypeSignatures.definitionallyEqual
                             (normalizeTypeAliases environment.VisibleTypeAliases expectedType)
                             typeObjectType ->
                    [ makeSurfaceElaborationDiagnostic
                        ConstructorTermCannotSatisfyTypeValuedDefinitionBody ]
                | _ ->
                    []

            let bareVisibleBindingImplicitDiagnostics =
                match body with
                | Name [ bindingName ] when not (Map.containsKey bindingName locals) ->
                    environment.VisibleBindings
                    |> Map.tryFind bindingName
                    |> Option.map (fun bindingInfo ->
                        let probeCounter = ref freshCounter.Value

                        let initialPreparedValue =
                            match expectedBodyType with
                            | Some expectedType ->
                                tryPrepareExpectedVisibleBindingValue
                                    environment
                                    probeCounter
                                    bindingInfo
                                    (Some localImplicitTypes)
                                    (inferValidationExpressionTypeWithContext
                                        environment
                                        probeCounter
                                        locals
                                        localImplicitTypes)
                                    (tryResolveUniqueLocalImplicitByType environment localImplicitTypes)
                                    expectedType
                            | None ->
                                None

                        let preparedValue =
                            initialPreparedValue
                            |> Option.orElseWith (fun () ->
                                tryPrepareVisibleBindingCall
                                    environment
                                    probeCounter
                                    bindingInfo
                                    (Some localImplicitTypes)
                                    (inferValidationExpressionTypeWithContext
                                        environment
                                        probeCounter
                                        locals
                                        localImplicitTypes)
                                    (tryResolveUniqueLocalImplicitByType environment localImplicitTypes)
                                    [])

                        match preparedValue with
                        | Some preparedCall
                            when (not (bindingHasRuntimeImplicitParameter environment bindingInfo))
                                 || not (List.isEmpty preparedCall.Arguments) ->
                            []
                        | None ->
                            let instantiated =
                                TypeSignatures.instantiate "v" probeCounter.Value bindingInfo.Scheme

                            let unresolvedImplicitDiagnostics =
                                let diagnosticParameterLayouts =
                                    normalizedVisibleBindingParameterLayouts bindingInfo instantiated
                                    |> Option.orElse bindingInfo.ParameterLayouts

                                match diagnosticParameterLayouts with
                                | Some layouts ->
                                    let parameterTypes, _ = TypeSignatures.schemeParts instantiated

                                    if List.length layouts = List.length parameterTypes then
                                        List.zip layouts parameterTypes
                                        |> List.tryPick (fun ((layout: Parameter), parameterType) ->
                                            if layout.IsImplicit
                                               && not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType)
                                               && Option.isNone
                                                   (tryResolveUniqueLocalImplicitByType environment localImplicitTypes parameterType) then
                                                match tryTraitConstraintFromType environment parameterType with
                                                | Some constraintInfo when constraintHasLocalDictionary environment constraintInfo ->
                                                    None
                                                | Some constraintInfo ->
                                                    match resolveConstraintInstanceDetailedWithSubstitution environment constraintInfo with
                                                    | ConstraintResolved _ ->
                                                        None
                                                    | ConstraintUnresolved ->
                                                        Some([ makeTraitConstraintUnresolvedDiagnostic constraintInfo ])
                                                    | ConstraintAmbiguous(ambiguousGoal, candidates) ->
                                                        Some([ makeTraitConstraintAmbiguousDiagnostic ambiguousGoal candidates ])
                                                | None ->
                                                    Some(
                                                        [ makeSurfaceElaborationDiagnostic
                                                            ImplicitApplicationArgumentUnresolvedOrMismatched ]
                                                    )
                                            else
                                                None)
                                        |> Option.defaultValue []
                                    else
                                        []
                                | None ->
                                    []

                            if not (List.isEmpty unresolvedImplicitDiagnostics) then
                                unresolvedImplicitDiagnostics
                            elif bindingHasRuntimeImplicitParameter environment bindingInfo then
                                let parameterTypes, _ = TypeSignatures.schemeParts instantiated

                                parameterTypes
                                |> List.tryPick (fun parameterType ->
                                    if isCompileTimeArgumentType environment.VisibleTypeAliases parameterType then
                                        None
                                    else
                                        match tryTraitConstraintFromType environment parameterType with
                                        | Some constraintInfo when constraintHasLocalDictionary environment constraintInfo ->
                                            None
                                        | Some constraintInfo ->
                                            match resolveConstraintInstanceDetailedWithSubstitution environment constraintInfo with
                                            | ConstraintResolved _ ->
                                                None
                                            | ConstraintUnresolved ->
                                                Some([ makeTraitConstraintUnresolvedDiagnostic constraintInfo ])
                                            | ConstraintAmbiguous(ambiguousGoal, candidates) ->
                                                Some([ makeTraitConstraintAmbiguousDiagnostic ambiguousGoal candidates ])
                                        | None ->
                                            Some(
                                                [ makeSurfaceElaborationDiagnostic
                                                    ImplicitApplicationArgumentUnresolvedOrMismatched ]
                                            ))
                                |> Option.defaultValue []
                            else
                                []
                        | Some _ ->
                            let instantiated =
                                TypeSignatures.instantiate "v" probeCounter.Value bindingInfo.Scheme
                            let parameterTypes, _ = TypeSignatures.schemeParts instantiated

                            parameterTypes
                            |> List.tryPick (fun parameterType ->
                                if isCompileTimeArgumentType environment.VisibleTypeAliases parameterType then
                                    None
                                else
                                    match tryTraitConstraintFromType environment parameterType with
                                    | Some constraintInfo ->
                                        Some([ makeTraitConstraintUnresolvedDiagnostic constraintInfo ])
                                    | None ->
                                        Some(
                                            [ makeSurfaceElaborationDiagnostic
                                                ImplicitApplicationArgumentUnresolvedOrMismatched ]
                                        ))
                            |> Option.defaultValue [])
                    |> Option.defaultValue []
                | _ ->
                    []

            let expectedUnionDiagnostics =
                match expectedBodyType with
                | Some expectedType when typeContainsUnion expectedType ->
                    expectedTypeDiagnostics locals Map.empty "Definition body" expectedType body
                | _ ->
                    []

            let contextualNumericBodyDiagnostics =
                match expectedBodyType, body with
                | Some expectedType, (NumericLiteral _ | Unary("-", NumericLiteral _)) ->
                    expectedTypeDiagnostics locals Map.empty "Definition body" expectedType body
                | Some _, _ ->
                    []
                | None, _ ->
                    []

            let rec expressionHasInoutMarkerContractViolation expression =
                let recurse = expressionHasInoutMarkerContractViolation

                let applicationHasMarkerViolation calleeName arguments =
                    environment.VisibleBindings
                    |> Map.tryFind calleeName
                    |> Option.bind (fun bindingInfo ->
                        tryPrepareVisibleBindingCall
                            environment
                            freshCounter
                            bindingInfo
                            (Some locals)
                            (inferValidationExpressionType environment freshCounter locals)
                            (tryResolveUniqueLocalImplicitByType environment locals)
                            arguments)
                    |> Option.exists (fun preparedCall ->
                        preparedCall.Parameters
                        |> List.exists (fun parameter ->
                            match parameter.Layout, parameter.AssignedArgument with
                            | Some layout, Some(ExplicitArgument(InoutArgument _)) when not layout.IsInout ->
                                true
                            | Some layout, Some(ExplicitArgument _) when layout.IsInout ->
                                true
                            | _ ->
                                false))

                match expression with
                | Apply(Name [ calleeName ], arguments) ->
                    applicationHasMarkerViolation calleeName arguments
                    || List.exists recurse arguments
                | Apply(callee, arguments) ->
                    recurse callee || List.exists recurse arguments
                | SyntaxQuote inner
                | SyntaxSplice inner
                | TopLevelSyntaxSplice inner
                | CodeQuote inner
                | CodeSplice inner
                | MonadicSplice inner
                | ExplicitImplicitArgument inner
                | InoutArgument inner
                | Unary(_, inner)
                | Seal(inner, _) ->
                    recurse inner
                | TypeSyntaxTokens _ ->
                    false
                | Handle(_, label, nestedBody, returnClause, operationClauses) ->
                    recurse label
                    || recurse nestedBody
                    || recurse returnClause.Body
                    || (operationClauses |> List.exists (fun clause -> recurse clause.Body))
                | LocalLet(_, value, nestedBody) ->
                    recurse value || recurse nestedBody
                | LocalSignature(_, nestedBody)
                | LocalTypeAlias(_, nestedBody)
                | LocalScopedEffect(_, nestedBody)
                | Lambda(_, nestedBody) ->
                    recurse nestedBody
                | IfThenElse(condition, whenTrue, whenFalse) ->
                    recurse condition || recurse whenTrue || recurse whenFalse
                | Match(scrutinee, cases) ->
                    recurse scrutinee
                    || (cases
                        |> List.exists (fun caseClause ->
                            (caseClause.Guard |> Option.exists recurse)
                            || recurse caseClause.Body))
                | RecordLiteral fields ->
                    fields |> List.exists (fun field -> recurse field.Value)
                | RecordUpdate(receiver, fields) ->
                    recurse receiver || (fields |> List.exists (fun field -> recurse field.Value))
                | MemberAccess(receiver, _, arguments) ->
                    recurse receiver || (arguments |> List.exists recurse)
                | SafeNavigation(receiver, navigation) ->
                    recurse receiver || (navigation.Arguments |> List.exists recurse)
                | TagTest(receiver, _) ->
                    recurse receiver
                | Do statements ->
                    statements |> List.exists recurseDoStatement
                | NamedApplicationBlock fields ->
                    fields |> List.exists (fun field -> recurse field.Value)
                | Binary(left, _, right)
                | Elvis(left, right) ->
                    recurse left || recurse right
                | Comprehension comprehension ->
                    recurse comprehension.Lowered
                | PrefixedString(_, parts) ->
                    parts
                    |> List.exists (function
                        | StringText _ -> false
                        | StringInterpolation(inner, _) -> recurse inner)
                | Literal _
                | NumericLiteral _
                | KindQualifiedName _
                | Name _ ->
                    false

            and recurseDoStatement statement =
                match statement with
                | DoLet(_, value)
                | DoBind(_, value)
                | DoUsing(_, value)
                | DoVar(_, value)
                | DoAssign(_, value)
                | DoDefer value
                | DoExpression value
                | DoReturn value ->
                    expressionHasInoutMarkerContractViolation value
                | DoLetQuestion(_, value, failure) ->
                    expressionHasInoutMarkerContractViolation value
                    || (failure |> Option.exists (fun block -> block.Body |> List.exists recurseDoStatement))
                | DoIf(condition, whenTrue, whenFalse) ->
                    expressionHasInoutMarkerContractViolation condition
                    || List.exists recurseDoStatement whenTrue
                    || List.exists recurseDoStatement whenFalse
                | DoWhile(condition, nestedBody) ->
                    expressionHasInoutMarkerContractViolation condition
                    || List.exists recurseDoStatement nestedBody

            let doBlockExpectedBodySatisfied =
                match body, expectedBodyType with
                | Do statements, Some expectedType ->
                    match
                        tryUnwrapBindablePayloadType environment.VisibleTypeAliases expectedType,
                        inferValidationDoResultType environment freshCounter locals statements
                    with
                    | Some expectedPayload, Some actualDoResultType ->
                        let actualPayload =
                            tryUnwrapBindablePayloadType environment.VisibleTypeAliases actualDoResultType
                            |> Option.defaultValue actualDoResultType

                        expectedTypeAccepts locals Map.empty expectedPayload actualPayload
                    | _ ->
                        false
                | _ ->
                    false

            let doBlockExpectedBodyDiagnostics =
                match body, expectedBodyType with
                | Do statements, Some expectedType
                    when not doBlockExpectedBodySatisfied
                         && List.isEmpty inoutDeclarationDiagnostics
                         && not (expressionHasInoutMarkerContractViolation body) ->
                    match
                        tryUnwrapBindablePayloadType environment.VisibleTypeAliases expectedType,
                        inferValidationDoResultType environment freshCounter locals statements
                    with
                    | Some expectedPayload, Some actualDoResultType ->
                        let actualPayload =
                            tryUnwrapBindablePayloadType environment.VisibleTypeAliases actualDoResultType
                            |> Option.defaultValue actualDoResultType

                        if expectedTypeAccepts locals Map.empty expectedPayload actualPayload then
                            []
                        else
                            [ expectedMismatchDiagnostic
                                locals
                                Map.empty
                                ExpressionTypeMismatch
                                "Definition body"
                                expectedPayload
                                actualPayload ]
                    | _ ->
                        []
                | _ ->
                    []

            let rec expectedTypeIsCallableLike typeExpr =
                match normalizeExpectedType Map.empty typeExpr with
                | TypeCapture(innerType, _) ->
                    expectedTypeIsCallableLike innerType
                | normalizedType ->
                    isCallableValidationType environment.VisibleTypeAliases normalizedType

            let lambdaExpectedBodyDiagnostics =
                match expectedBodyType, body with
                | Some expectedType, Lambda _
                    when not (expectedTypeIsCallableLike expectedType) ->
                    match inferValidationExpressionType environment freshCounter locals body with
                    | Some actualType ->
                        [ expectedMismatchDiagnostic
                            locals
                            Map.empty
                            ExpressionTypeMismatch
                            "Definition body"
                            expectedType
                            actualType ]
                    | None ->
                        []
                | _ ->
                    []

            let callableExpectedBodyDiagnostics =
                match expectedBodyType, inferValidationExpressionType environment freshCounter locals body with
                | Some expectedType, Some actualType
                    when typeIsCallableLikeForValidation expectedType
                         && (canCompareInferredValidationTypes locals expectedType actualType
                             || needsDependentTransportComparison locals expectedType actualType)
                         && not (expectedTypeAccepts locals Map.empty expectedType actualType) ->
                    [ expectedMismatchDiagnostic
                        locals
                        Map.empty
                        ExpressionTypeMismatch
                        "Definition body"
                        expectedType
                        actualType ]
                | _ ->
                    []

            let macroExpectedBodyDiagnostics =
                match expectedBodyType, tryInferMacroAwareValidationType locals body with
                | Some expectedType, Some actualType
                    when (match body with
                          | Name _
                          | Apply _
                          | PrefixedString _ -> true
                          | _ -> false)
                         && (typeMentionsMacroReflectionType expectedType
                             || typeMentionsMacroReflectionType actualType)
                         && not (expectedTypeAccepts locals Map.empty expectedType actualType) ->
                    [ expectedMismatchDiagnostic
                        locals
                        Map.empty
                        ExpressionTypeMismatch
                        "Definition body"
                        expectedType
                        actualType ]
                | _ ->
                    []

            let textBinaryExpectedBodyDiagnostics =
                let isTextBinarySurfaceType typeExpr =
                    match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
                    | TypeName(nameSegments, []) when
                        matchesKnownType CompilerKnownSymbols.StringType nameSegments
                        || matchesKnownType CompilerKnownSymbols.BytesType nameSegments
                        || matchesKnownType CompilerKnownSymbols.ByteType nameSegments
                        || matchesKnownType CompilerKnownSymbols.UnicodeScalarType nameSegments
                        || matchesKnownType CompilerKnownSymbols.GraphemeType nameSegments
                        || matchesKnownType CompilerKnownSymbols.CharType nameSegments ->
                        true
                    | _ ->
                        false

                match expectedBodyType, inferValidationExpressionType environment freshCounter locals body with
                | Some expectedType, Some actualType
                    when isTextBinarySurfaceType expectedType
                         && isTextBinarySurfaceType actualType
                         && not (expectedTypeAccepts locals Map.empty expectedType actualType) ->
                    [ expectedMismatchDiagnostic
                        locals
                        Map.empty
                        ExpressionTypeMismatch
                        "Definition body"
                        expectedType
                        actualType ]
                | _ ->
                    []

            let recordLiteralExpectedBodyDiagnostics =
                match expectedBodyType, body, inferValidationExpressionType environment freshCounter locals body with
                | Some expectedType, RecordLiteral _, Some actualType
                    when not doBlockExpectedBodySatisfied
                         && List.isEmpty projectionTypeMismatchDiagnostics
                         && List.isEmpty staticObjectResultDiagnostics
                         && List.isEmpty constructorAsStaticObjectDiagnostics
                         && List.isEmpty expectedUnionDiagnostics
                         && List.isEmpty binaryExpectedBodyDiagnostics
                         && List.isEmpty listConsExpectedBodyDiagnostics
                         && List.isEmpty contextualNumericBodyDiagnostics
                         && List.isEmpty doBlockExpectedBodyDiagnostics
                         && List.isEmpty lambdaExpectedBodyDiagnostics
                         && List.isEmpty callableExpectedBodyDiagnostics
                         && List.isEmpty macroExpectedBodyDiagnostics
                         && List.isEmpty textBinaryExpectedBodyDiagnostics ->
                    match normalizeTypeAliases environment.VisibleTypeAliases expectedType with
                    | TypeRecord _ ->
                        []
                    | _ ->
                        [ expectedMismatchDiagnostic
                            locals
                            Map.empty
                            ExpressionTypeMismatch
                            "Definition body"
                            expectedType
                            actualType ]
                | _ ->
                    []

            let generalInferredExpectedBodyDiagnostics =
                match expectedBodyType, inferValidationExpressionType environment freshCounter locals body with
                | Some expectedType, Some actualType
                    when definition.ReturnTypeTokens.IsSome
                         && (match body with
                             | Apply _
                             | MemberAccess _
                             | SafeNavigation _ -> true
                             | _ -> false)
                         && not doBlockExpectedBodySatisfied
                         && List.isEmpty projectionTypeMismatchDiagnostics
                         && List.isEmpty staticObjectResultDiagnostics
                         && List.isEmpty constructorAsStaticObjectDiagnostics
                         && List.isEmpty expectedUnionDiagnostics
                         && List.isEmpty binaryExpectedBodyDiagnostics
                         && List.isEmpty listConsExpectedBodyDiagnostics
                         && List.isEmpty contextualNumericBodyDiagnostics
                         && List.isEmpty doBlockExpectedBodyDiagnostics
                         && List.isEmpty lambdaExpectedBodyDiagnostics
                         && List.isEmpty callableExpectedBodyDiagnostics
                         && List.isEmpty macroExpectedBodyDiagnostics
                         && List.isEmpty textBinaryExpectedBodyDiagnostics
                         && List.isEmpty recordLiteralExpectedBodyDiagnostics
                         && (canCompareInferredValidationTypes locals expectedType actualType
                             || needsDependentTransportComparison locals expectedType actualType)
                         && not (expectedTypeAccepts locals Map.empty expectedType actualType) ->
                    [ expectedMismatchDiagnostic
                        locals
                        Map.empty
                        ExpressionTypeMismatch
                        "Definition body"
                        expectedType
                        actualType ]
                | _ ->
                    []

            let generalExpectedBodyDiagnostics =
                match expectedBodyType with
                | Some expectedType
                    when (match body with
                          | Literal _
                          | NumericLiteral _ -> true
                          | _ -> false)
                         && not doBlockExpectedBodySatisfied
                         && isSimpleExpectedBodyType locals (normalizeExpectedType Map.empty expectedType)
                         && List.isEmpty projectionTypeMismatchDiagnostics
                         && List.isEmpty staticObjectResultDiagnostics
                         && List.isEmpty constructorAsStaticObjectDiagnostics
                         && List.isEmpty expectedUnionDiagnostics
                         && List.isEmpty contextualNumericBodyDiagnostics
                         && List.isEmpty macroExpectedBodyDiagnostics
                         && List.isEmpty textBinaryExpectedBodyDiagnostics
                         && List.isEmpty generalInferredExpectedBodyDiagnostics ->
                    expectedTypeDiagnostics locals Map.empty "Definition body" expectedType body
                | Some expectedType
                    when (match body with
                          | Name [ _ ] -> true
                          | _ -> false)
                         && not doBlockExpectedBodySatisfied
                         && List.isEmpty projectionTypeMismatchDiagnostics
                         && List.isEmpty staticObjectResultDiagnostics
                         && List.isEmpty constructorAsStaticObjectDiagnostics
                         && List.isEmpty expectedUnionDiagnostics
                         && List.isEmpty contextualNumericBodyDiagnostics
                         && List.isEmpty macroExpectedBodyDiagnostics
                         && List.isEmpty textBinaryExpectedBodyDiagnostics
                         && List.isEmpty generalInferredExpectedBodyDiagnostics ->
                    match body with
                    | Name [ bindingName ] ->
                        let unresolvedImplicitDiagnostics =
                            environment.VisibleBindings
                            |> Map.tryFind bindingName
                            |> Option.map (fun bindingInfo ->
                                let probeCounter = ref freshCounter.Value

                                let initialPreparedValue =
                                    tryPrepareExpectedVisibleBindingValue
                                        environment
                                        probeCounter
                                        bindingInfo
                                        (Some localImplicitTypes)
                                        (inferValidationExpressionTypeWithContext
                                            environment
                                            probeCounter
                                            locals
                                            localImplicitTypes)
                                        (tryResolveUniqueLocalImplicitByType environment localImplicitTypes)
                                        expectedType

                                let preparedValue =
                                    initialPreparedValue
                                    |> Option.orElseWith (fun () ->
                                        tryPrepareVisibleBindingCall
                                            environment
                                            probeCounter
                                            bindingInfo
                                            (Some localImplicitTypes)
                                            (inferValidationExpressionTypeWithContext
                                                environment
                                                probeCounter
                                                locals
                                                localImplicitTypes)
                                            (tryResolveUniqueLocalImplicitByType environment localImplicitTypes)
                                            [])

                                match preparedValue with
                                | Some _ ->
                                    []
                                | None ->
                                    let instantiated =
                                        TypeSignatures.instantiate "v" probeCounter.Value bindingInfo.Scheme

                                    match
                                        normalizedVisibleBindingParameterLayouts bindingInfo instantiated
                                        |> Option.orElse bindingInfo.ParameterLayouts
                                    with
                                    | Some layouts ->
                                        let parameterTypes, _ = TypeSignatures.schemeParts instantiated

                                        if List.length layouts = List.length parameterTypes then
                                            List.zip layouts parameterTypes
                                            |> List.tryPick (fun ((layout: Parameter), parameterType) ->
                                                if layout.IsImplicit
                                                   && not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType)
                                                   && Option.isNone
                                                       (tryResolveUniqueLocalImplicitByType
                                                           environment
                                                           localImplicitTypes
                                                           parameterType) then
                                                    match tryTraitConstraintFromType environment parameterType with
                                                    | Some constraintInfo when constraintHasLocalDictionary environment constraintInfo ->
                                                        None
                                                    | Some constraintInfo ->
                                                        match resolveConstraintInstanceDetailedWithSubstitution environment constraintInfo with
                                                        | ConstraintResolved _ ->
                                                            None
                                                        | ConstraintUnresolved ->
                                                            Some([ makeTraitConstraintUnresolvedDiagnostic constraintInfo ])
                                                        | ConstraintAmbiguous(ambiguousGoal, candidates) ->
                                                            Some([ makeTraitConstraintAmbiguousDiagnostic ambiguousGoal candidates ])
                                                    | None ->
                                                        Some(
                                                            [ makeSurfaceElaborationDiagnostic
                                                                ImplicitApplicationArgumentUnresolvedOrMismatched ]
                                                        )
                                                else
                                                    None)
                                            |> Option.defaultValue []
                                        else
                                            []
                                    | None ->
                                        [])
                            |> Option.defaultValue []

                        if not (List.isEmpty unresolvedImplicitDiagnostics) then
                            unresolvedImplicitDiagnostics
                        else
                            match inferValidationExpressionType environment freshCounter locals body with
                            | Some actualType when isSimpleExpectedBodyType locals actualType ->
                                expectedTypeDiagnostics locals Map.empty "Definition body" expectedType body
                            | _ ->
                                []
                    | _ ->
                        match inferValidationExpressionType environment freshCounter locals body with
                        | Some actualType when isSimpleExpectedBodyType locals actualType ->
                            expectedTypeDiagnostics locals Map.empty "Definition body" expectedType body
                        | _ ->
                            []
                | _ ->
                    []

            directSignatureLiteralDiagnostic
            @ signatureReturnAnnotationDiagnostics
            @ sealAscriptionDiagnostics
            @ opaqueUnfoldingDiagnostics
            @ projectionTypeMismatchDiagnostics
            @ staticObjectResultDiagnostics
            @ staticObjectOnlyValueDiagnostics
            @ typeNamespaceOnlyNameDiagnostics
            @ constructorAsStaticObjectDiagnostics
            @ bareVisibleBindingImplicitDiagnostics
            @ expectedUnionDiagnostics
            @ binaryExpectedBodyDiagnostics
            @ listConsExpectedBodyDiagnostics
            @ contextualNumericBodyDiagnostics
            @ doBlockExpectedBodyDiagnostics
            @ lambdaExpectedBodyDiagnostics
            @ callableExpectedBodyDiagnostics
            @ macroExpectedBodyDiagnostics
            @ textBinaryExpectedBodyDiagnostics
            @ recordLiteralExpectedBodyDiagnostics
            @ generalInferredExpectedBodyDiagnostics
            @ generalExpectedBodyDiagnostics

        let tryResolveComparableOperandTypes locals left right =
            let normalizeVisibleType typeExpr =
                typeExpr |> qualifyVisibleTypeNames environment |> normalizeTypeAliases environment.VisibleTypeAliases

            let trySameType leftType rightType =
                let normalizedLeftType = normalizeVisibleType leftType
                let normalizedRightType = normalizeVisibleType rightType

                if TypeSignatures.definitionallyEqual normalizedLeftType normalizedRightType then
                    Some(normalizedLeftType, normalizedRightType, leftType, rightType)
                else
                    None

            match
                inferValidationExpressionType environment freshCounter locals left,
                inferValidationExpressionType environment freshCounter locals right
            with
            | Some leftType, Some rightType ->
                trySameType leftType rightType
                |> Option.orElseWith (fun () ->
                    tryInferNumericExpressionTypeFromContext environment leftType right
                    |> Option.bind (fun contextualRightType -> trySameType leftType contextualRightType))
                |> Option.orElseWith (fun () ->
                    tryInferNumericExpressionTypeFromContext environment rightType left
                    |> Option.bind (fun contextualLeftType -> trySameType contextualLeftType rightType))
            | _ ->
                None

        let rec dropLeadingCompileTimeArguments
            (remainingForall: TypeSignatures.ForallBinder list)
            (remainingArguments: SurfaceExpression list)
            =
            match remainingForall, remainingArguments with
            | _ :: restForall, ExplicitImplicitArgument _ :: restArguments ->
                dropLeadingCompileTimeArguments restForall restArguments
            | _ ->
                remainingArguments

        let applicationExpectedArgumentDiagnostics locals refinements lexicalNames (bindingInfo: BindingSchemeInfo) arguments =
            let inferArgumentTypeForParameter parameterType argument =
                tryInferNumericExpressionTypeFromContext environment parameterType argument
                |> Option.orElseWith (fun () -> inferValidationExpressionType environment freshCounter locals argument)

            let preserveOrdinaryConstructorApplication =
                bindingInfo.ConstructorTypeName.IsSome
                || environment.VisibleConstructors.ContainsKey(bindingInfo.Name)

            if preserveOrdinaryConstructorApplication then
                []
            else
                match bindingInfo.ParameterLayouts with
                | None ->
                        []
                | Some parameterLayouts ->
                    let instantiated = TypeSignatures.instantiate "v" freshCounter.Value bindingInfo.Scheme
                    let runtimeArguments = dropLeadingCompileTimeArguments instantiated.Forall arguments
                    let schemeParameterTypes, _ = TypeSignatures.schemeParts instantiated

                    let hasApplicationOnlyArgument =
                        runtimeArguments
                        |> List.exists (function
                            | ExplicitImplicitArgument _
                            | NamedApplicationBlock _ -> true
                            | _ -> false)

                    if hasApplicationOnlyArgument then
                        []
                    else
                        let layoutTypeSubstitution = forallInstantiationSubstitution bindingInfo.Scheme instantiated

                        match
                            tryAlignParameterTypesWithLayouts
                                environment
                                layoutTypeSubstitution
                                parameterLayouts
                                schemeParameterTypes
                        with
                        | Some(parameterTypes, []) ->
                            let remainingArguments = ref runtimeArguments
                            let substitution = ref Map.empty<string, TypeExpr>
                            let diagnostics = ResizeArray<Diagnostic>()

                            for parameterLayout, rawParameterType in List.zip parameterLayouts parameterTypes do
                                let parameterType =
                                    rawParameterType
                                    |> TypeSignatures.applySubstitution !substitution

                                if parameterLayout.IsImplicit then
                                    ()
                                elif isCompileTimeArgumentType environment.VisibleTypeAliases parameterType then
                                    match !remainingArguments with
                                    | nextArgument :: rest ->
                                        remainingArguments := rest

                                        match tryParseTypeLikeSurfaceExpression nextArgument with
                                        | Some typeArgument ->
                                            substitution :=
                                                composeTypeSubstitution
                                                    !substitution
                                                    (Map.ofList [ parameterLayout.Name, typeArgument ])
                                        | None ->
                                            ()
                                    | [] ->
                                        ()
                                else
                                    match !remainingArguments with
                                    | nextArgument :: rest ->
                                        remainingArguments := rest

                                        match parameterLayout.IsInout, nextArgument with
                                        | true, InoutArgument _ ->
                                            ()
                                        | true, _ ->
                                            diagnostics.Add(
                                                makeLocatedDiagnostic
                                                    SimpleDiagnosticKind.QttInoutMarkerRequired
                                                    "An argument supplied to an 'inout' parameter must be marked with '~'."
                                                    (tryFindArgumentLocation bindingInfo.Name nextArgument)
                                            )
                                        | false, InoutArgument _ ->
                                            diagnostics.Add(
                                                { (Diagnostics.errorFact
                                                    "KFrontIR"
                                                    (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                                    None
                                                    []
                                                    (DiagnosticFact.qttInoutMarkerUnexpected InoutMarkerUnexpected)) with
                                                    Location = tryFindArgumentLocation bindingInfo.Name nextArgument }
                                            )
                                        | false, _ ->
                                            ()

                                        match inferArgumentTypeForParameter parameterType nextArgument with
                                        | Some argumentType ->
                                            match tryNumericLiteralRangeDiagnostic parameterType nextArgument with
                                            | Some diagnostic ->
                                                diagnostics.Add(diagnostic)
                                            | None
                                                when (canCompareInferredValidationTypes locals parameterType argumentType
                                                      || canCompareDirectLocalNameArgumentTypes
                                                          locals
                                                          nextArgument
                                                          parameterType
                                                          argumentType
                                                      || canCompareDistinctValidationShapes parameterType argumentType
                                                      || needsDependentTransportComparison locals parameterType argumentType)
                                                     && not (expectedTypeAccepts locals refinements parameterType argumentType) ->
                                                diagnostics.Add(
                                                    expectedMismatchDiagnostic
                                                        locals
                                                        refinements
                                                        ApplicationArgumentMismatch
                                                        "Application argument"
                                                        parameterType
                                                        argumentType
                                                )
                                            | None ->
                                                match tryParseTypeLikeSurfaceExpression nextArgument with
                                                | Some termArgument ->
                                                    substitution :=
                                                        composeTypeSubstitution
                                                            !substitution
                                                            (Map.ofList [ parameterLayout.Name, termArgument ])
                                                | None ->
                                                    match tryUnifyVisibleTypes environment.VisibleTypeAliases [ parameterType, argumentType ] with
                                                    | Some inferredSubstitution ->
                                                        substitution :=
                                                            composeTypeSubstitution
                                                                !substitution
                                                                inferredSubstitution
                                                    | None ->
                                                        ()
                                        | None ->
                                            ()
                                    | [] ->
                                        ()

                            List.ofSeq diagnostics
                        | Some _
                        | None ->
                            []

        let localApplicationExpectedArgumentDiagnostics locals refinements calleeType arguments =
            let tryInferExpectedVisibleValueType parameterType argument =
                match argument with
                | Name [ argumentName ] when not (Map.containsKey argumentName locals) ->
                    let bindingInfo =
                        if ordinarySurfaceNameShadowsVisiblePreludeBinding environment locals argumentName then
                            None
                        else
                            environment.VisibleConstructors
                            |> Map.tryFind argumentName
                            |> Option.orElseWith (fun () -> environment.VisibleBindings |> Map.tryFind argumentName)

                    bindingInfo
                    |> Option.bind (fun currentBindingInfo ->
                        let probeCounter = ref freshCounter.Value

                        tryPrepareExpectedVisibleBindingValue
                            environment
                            probeCounter
                            currentBindingInfo
                            (Some locals)
                            (inferValidationExpressionType environment probeCounter locals)
                            (tryResolveUniqueLocalImplicitByType environment locals)
                            parameterType
                        |> Option.map (fun preparedCall -> preparedCall.ResultType))
                | _ ->
                    None

            let inferArgumentTypeForParameter parameterType argument =
                tryInferNumericExpressionTypeFromContext environment parameterType argument
                |> Option.orElseWith (fun () -> tryInferExpectedVisibleValueType parameterType argument)
                |> Option.orElseWith (fun () -> inferValidationExpressionType environment freshCounter locals argument)

            let hasApplicationOnlyArgument =
                arguments
                |> List.exists (function
                    | ExplicitImplicitArgument _
                    | NamedApplicationBlock _ -> true
                    | _ -> false)

            if hasApplicationOnlyArgument then
                []
            else
                let parameterTypes, _ = TypeSignatures.functionParts calleeType

                let rec collect substitution diagnostics remainingParameterTypes remainingArguments =
                    match remainingParameterTypes, remainingArguments with
                    | parameterType :: restParameterTypes, argument :: restArguments ->
                        let currentParameterType =
                            TypeSignatures.applySubstitution substitution parameterType

                        match inferArgumentTypeForParameter currentParameterType argument with
                        | Some argumentType ->
                            match tryNumericLiteralRangeDiagnostic currentParameterType argument with
                            | Some diagnostic ->
                                collect substitution (diagnostics @ [ diagnostic ]) restParameterTypes restArguments
                            | None ->
                                let inferredSubstitution =
                                    tryUnifyVisibleTypes
                                        environment.VisibleTypeAliases
                                        [ currentParameterType, argumentType ]

                                let nextSubstitution =
                                    inferredSubstitution
                                    |> Option.map (composeTypeSubstitution substitution)
                                    |> Option.defaultValue substitution

                                let nextParameterType =
                                    TypeSignatures.applySubstitution nextSubstitution currentParameterType

                                let nextArgumentType =
                                    TypeSignatures.applySubstitution nextSubstitution argumentType

                                let nextDiagnostics =
                                    if
                                        (canCompareInferredValidationTypes locals nextParameterType nextArgumentType
                                         || canCompareDirectLocalNameArgumentTypes
                                             locals
                                             argument
                                             nextParameterType
                                             nextArgumentType
                                         || canCompareDistinctValidationShapes nextParameterType nextArgumentType
                                         || needsDependentTransportComparison locals nextParameterType nextArgumentType)
                                        && not (expectedTypeAccepts locals refinements nextParameterType nextArgumentType)
                                    then
                                        diagnostics
                                        @ [
                                            expectedMismatchDiagnostic
                                                locals
                                                refinements
                                                ApplicationArgumentMismatch
                                                "Application argument"
                                                nextParameterType
                                                nextArgumentType
                                          ]
                                    else
                                        diagnostics

                                collect nextSubstitution nextDiagnostics restParameterTypes restArguments
                        | None ->
                            collect substitution diagnostics restParameterTypes restArguments
                    | _ ->
                        diagnostics

                collect Map.empty [] parameterTypes arguments

        let siblingFallbackDiagnostics expression =
            let normalize = normalizeTypeAliases environment.VisibleTypeAliases

            let isSiblingDefinitionFallbackCandidate name =
                topLevelDefinitionsByName
                |> Map.tryFind name
                |> Option.exists (fun definition ->
                    not definition.IsPattern
                    && not (Set.contains name explicitSignatureNames))

            let tryInferSiblingParameterTypeList calleeName =
                topLevelDefinitionsByName
                |> Map.tryFind calleeName
                |> Option.bind (fun siblingDefinition ->
                    siblingDefinition.Body
                    |> Option.bind (fun siblingBody ->
                        let nextVisited = Set.singleton calleeName
                        let bodyInferredParameterTypes =
                            tryInferSiblingParameterTypesFromNumericUse nextVisited siblingDefinition.Parameters siblingBody

                        let parameterTypes =
                            siblingDefinition.Parameters
                            |> List.map (fun parameter ->
                                tryParseParameterType parameter
                                |> Option.orElseWith (fun () -> Map.tryFind parameter.Name bodyInferredParameterTypes))

                        if parameterTypes |> List.exists Option.isNone then
                            None
                        else
                            Some(parameterTypes |> List.choose id)))

            let inferDirect currentLocals currentExpression =
                inferValidationExpressionType environment (ref freshCounter.Value) currentLocals currentExpression

            let inferWithSiblingFallback currentLocals currentExpression =
                tryInferExpressionTypeWithSiblingFallback Set.empty currentLocals currentExpression

            let applyFallbackDiagnostics currentLocals lexicalNames calleeName arguments =
                if Map.containsKey calleeName currentLocals
                   || Set.contains calleeName lexicalNames
                   || not (isSiblingDefinitionFallbackCandidate calleeName) then
                    []
                else
                    let parameterDiagnostics =
                        tryInferSiblingParameterTypeList calleeName
                        |> Option.map (fun parameterTypes ->
                            parameterTypes
                            |> List.rev
                            |> List.fold (fun current parameterType ->
                                TypeArrow(QuantityOmega, parameterType, current)) unitType
                            |> fun calleeType ->
                                localApplicationExpectedArgumentDiagnostics currentLocals Map.empty calleeType arguments)
                        |> Option.defaultValue []

                    if not (List.isEmpty parameterDiagnostics) then
                        parameterDiagnostics
                    else
                        match tryInferSiblingBindingType Set.empty calleeName with
                        | Some calleeType when not (isCallableValidationType environment.VisibleTypeAliases calleeType) ->
                            [ makeSurfaceElaborationDiagnostic
                                (ApplicationExpressionNotCallable(TypeSignatures.toText (normalize calleeType))) ]
                        | Some calleeType ->
                            localApplicationExpectedArgumentDiagnostics currentLocals Map.empty calleeType arguments
                        | None ->
                            []

            let literalApplicationDiagnostics currentLocals callee =
                match inferWithSiblingFallback currentLocals callee with
                | Some calleeType when not (isCallableValidationType environment.VisibleTypeAliases calleeType) ->
                    [ makeSurfaceElaborationDiagnostic
                        (ApplicationExpressionNotCallable(TypeSignatures.toText (normalize calleeType))) ]
                | _ ->
                    []

            let arithmeticFallbackDiagnostics currentLocals left right =
                let directLeft = inferDirect currentLocals left
                let directRight = inferDirect currentLocals right

                let isDirectNumeric typeExpr =
                    TypeSignatures.definitionallyEqual (normalize typeExpr) intType
                    || TypeSignatures.definitionallyEqual (normalize typeExpr) floatType

                let hasSiblingPlusConcreteNumericPair =
                    (match left, directRight with
                     | Name [ name ], Some rightType when isSiblingDefinitionFallbackCandidate name && isDirectNumeric rightType -> true
                     | _ -> false)
                    || (match right, directLeft with
                        | Name [ name ], Some leftType when isSiblingDefinitionFallbackCandidate name && isDirectNumeric leftType -> true
                        | _ -> false)

                if
                    (directLeft.IsSome && directRight.IsSome)
                    || not hasSiblingPlusConcreteNumericPair
                then
                    []
                else
                    match inferWithSiblingFallback currentLocals left, inferWithSiblingFallback currentLocals right with
                    | Some leftType, Some rightType
                        when TypeSignatures.definitionallyEqual (normalize leftType) intType
                             && TypeSignatures.definitionallyEqual (normalize rightType) intType ->
                        []
                    | Some leftType, Some rightType
                        when TypeSignatures.definitionallyEqual (normalize leftType) floatType
                             && TypeSignatures.definitionallyEqual (normalize rightType) floatType ->
                        []
                    | Some leftType, Some rightType
                        when typeIsCallableLikeForValidation leftType
                             || typeIsCallableLikeForValidation rightType ->
                        []
                    | Some leftType, Some rightType ->
                        [ makeSurfaceElaborationDiagnostic
                            (ArithmeticOperandsMustBeNumeric(
                                TypeSignatures.toText (normalize leftType),
                                TypeSignatures.toText (normalize rightType)
                            )) ]
                    | _ ->
                        []

            let rec validateExpression currentLocals lexicalNames current =
                let recurse = validateExpression currentLocals lexicalNames

                match current with
                | SyntaxQuote inner
                | SyntaxSplice inner
                | TopLevelSyntaxSplice inner
                | CodeQuote inner
                | CodeSplice inner
                | MonadicSplice inner
                | InoutArgument inner
                | Unary(_, inner)
                | Seal(inner, _) ->
                    recurse inner
                | TypeSyntaxTokens _ ->
                    []
                | ExplicitImplicitArgument inner ->
                    match tryParseTypeLikeSurfaceExpression inner with
                    | Some _ ->
                        []
                    | None ->
                        recurse inner
                | Handle(_, label, body, returnClause, operationClauses) ->
                    recurse label
                    @ recurse body
                    @ recurse returnClause.Body
                    @ (operationClauses |> List.collect (fun clause -> recurse clause.Body))
                | Apply(Name [ calleeName ], arguments) ->
                    (arguments |> List.collect recurse)
                    @ applyFallbackDiagnostics currentLocals lexicalNames calleeName arguments
                | Apply((Literal _ | NumericLiteral _) as callee, arguments) ->
                    recurse callee @ (arguments |> List.collect recurse)
                | Apply(callee, arguments) ->
                    recurse callee @ (arguments |> List.collect recurse)
                | LocalLet(binding, value, body) ->
                    let valueType = inferWithSiblingFallback currentLocals value
                    let nextLocals =
                        match valueType with
                        | Some inferredType ->
                            extendBindingLocalTypes
                                environment
                                (ref freshCounter.Value)
                                currentLocals
                                binding
                                (Some inferredType)
                        | None ->
                            currentLocals

                    let nextLexicalNames =
                        collectPatternNames binding.Pattern
                        |> Set.ofList
                        |> Set.union lexicalNames

                    recurse value @ validateExpression nextLocals nextLexicalNames body
                | LocalSignature(declaration, body) ->
                    let nextLocals =
                        declaration.TypeTokens
                        |> TypeSignatures.parseType
                        |> Option.map (fun declarationType -> Map.add declaration.Name declarationType currentLocals)
                        |> Option.defaultValue currentLocals

                    validateExpression nextLocals (Set.add declaration.Name lexicalNames) body
                | LocalTypeAlias(_, body) ->
                    validateExpression currentLocals lexicalNames body
                | LocalScopedEffect(_, body) ->
                    validateExpression currentLocals lexicalNames body
                | Lambda(parameters, body) ->
                    let nextLocals =
                        parameters
                        |> List.fold (fun state parameter ->
                            let parameterType =
                                tryParseParameterType parameter
                                |> Option.defaultValue (TypeVariable $"lambda{freshCounter.Value}")

                            Map.add parameter.Name parameterType state) currentLocals

                    let nextLexicalNames =
                        parameters
                        |> List.map (fun parameter -> parameter.Name)
                        |> Set.ofList
                        |> Set.union lexicalNames

                    validateExpression nextLocals nextLexicalNames body
                | IfThenElse(condition, whenTrue, whenFalse) ->
                    recurse condition
                    @ validateExpression currentLocals lexicalNames whenTrue
                    @ validateExpression currentLocals lexicalNames whenFalse
                | Match(scrutinee, cases) ->
                    let scrutineeType = inferWithSiblingFallback currentLocals scrutinee

                    recurse scrutinee
                    @ (cases
                       |> List.collect (fun caseClause ->
                           let caseLocals =
                               extendPatternLocalTypes
                                   environment
                                   (ref freshCounter.Value)
                                   currentLocals
                                   scrutineeType
                                   caseClause.Pattern

                           let caseLexicalNames =
                               collectPatternNames caseClause.Pattern
                               |> Set.ofList
                               |> Set.union lexicalNames

                           (caseClause.Guard
                            |> Option.map (validateExpression caseLocals caseLexicalNames)
                            |> Option.defaultValue [])
                           @ validateExpression caseLocals caseLexicalNames caseClause.Body))
                | RecordLiteral fields ->
                    fields |> List.collect (fun field -> recurse field.Value)
                | RecordUpdate(receiver, fields) ->
                    recurse receiver @ (fields |> List.collect (fun field -> recurse field.Value))
                | MemberAccess(receiver, _, arguments) ->
                    recurse receiver @ (arguments |> List.collect recurse)
                | SafeNavigation(receiver, navigation) ->
                    recurse receiver @ (navigation.Arguments |> List.collect recurse)
                | TagTest(receiver, _) ->
                    recurse receiver
                | Do statements ->
                    validateDo currentLocals lexicalNames statements
                | Binary(left, ("+" | "-" | "*" | "/"), right) ->
                    recurse left @ recurse right @ arithmeticFallbackDiagnostics currentLocals left right
                | Binary(left, _, right)
                | Elvis(left, right) ->
                    recurse left @ recurse right
                | Comprehension comprehension ->
                    validateExpression currentLocals lexicalNames comprehension.Lowered
                | PrefixedString(_, parts) ->
                    parts
                    |> List.collect (function
                        | StringText _ -> []
                        | StringInterpolation(inner, _) -> recurse inner)
                | NamedApplicationBlock fields ->
                    fields |> List.collect (fun field -> recurse field.Value)
                | Literal _
                | NumericLiteral _
                | KindQualifiedName _
                | Name _ ->
                    []

            and validateDo currentLocals lexicalNames statements =
                match statements with
                | [] ->
                    []
                | statement :: rest ->
                    match statement with
                    | DoLet(binding, value) ->
                        let valueType = inferWithSiblingFallback currentLocals value
                        let nextLocals =
                            match valueType with
                            | Some inferredType ->
                                extendBindingLocalTypes
                                    environment
                                    (ref freshCounter.Value)
                                    currentLocals
                                    binding
                                    (Some inferredType)
                            | None ->
                                currentLocals

                        let nextLexicalNames =
                            collectPatternNames binding.Pattern
                            |> Set.ofList
                            |> Set.union lexicalNames

                        validateExpression currentLocals lexicalNames value
                        @ validateDo nextLocals nextLexicalNames rest
                    | DoBind(binding, value) ->
                        let directSourceType = inferDirect currentLocals value
                        let shouldFallback =
                            match value with
                            | Name [ name ] when isSiblingDefinitionFallbackCandidate name -> true
                            | _ -> false

                        let fallbackSourceType =
                            if directSourceType.IsSome || not shouldFallback then
                                None
                            else
                                inferWithSiblingFallback currentLocals value

                        let bindDiagnostics =
                            match fallbackSourceType with
                            | Some sourceType when tryUnwrapBindablePayloadType environment.VisibleTypeAliases sourceType |> Option.isNone ->
                                [ makeSurfaceElaborationDiagnostic
                                    (DoBindRequiresBindableCarrier(TypeSignatures.toText sourceType)) ]
                            | _ ->
                                []

                        let nextLocals =
                            match fallbackSourceType |> Option.bind (tryUnwrapBindablePayloadType environment.VisibleTypeAliases) with
                            | Some payloadType ->
                                extendPatternLocalTypes
                                    environment
                                    (ref freshCounter.Value)
                                    currentLocals
                                    (Some payloadType)
                                    binding.Pattern
                            | None ->
                                currentLocals

                        let nextLexicalNames =
                            collectPatternNames binding.Pattern
                            |> Set.ofList
                            |> Set.union lexicalNames

                        validateExpression currentLocals lexicalNames value
                        @ bindDiagnostics
                        @ validateDo nextLocals nextLexicalNames rest
                    | DoLetQuestion(binding, value, failure) ->
                        let valueType = inferWithSiblingFallback currentLocals value
                        let nextLocals =
                            match valueType with
                            | Some inferredType ->
                                extendBindingLocalTypes
                                    environment
                                    (ref freshCounter.Value)
                                    currentLocals
                                    binding
                                    (Some inferredType)
                            | None ->
                                currentLocals

                        let nextLexicalNames =
                            collectPatternNames binding.Pattern
                            |> Set.ofList
                            |> Set.union lexicalNames

                        let failureDiagnostics =
                            failure
                            |> Option.map (fun block -> validateDo currentLocals lexicalNames block.Body)
                            |> Option.defaultValue []

                        validateExpression currentLocals lexicalNames value
                        @ failureDiagnostics
                        @ validateDo nextLocals nextLexicalNames rest
                    | DoUsing(binding, value) ->
                        let valueType = inferWithSiblingFallback currentLocals value
                        let nextLocals =
                            match valueType with
                            | Some inferredType ->
                                extendBindingLocalTypes
                                    environment
                                    (ref freshCounter.Value)
                                    currentLocals
                                    binding
                                    (Some(unwrapIoType inferredType))
                            | None ->
                                currentLocals

                        let nextLexicalNames =
                            collectPatternNames binding.Pattern
                            |> Set.ofList
                            |> Set.union lexicalNames

                        validateExpression currentLocals lexicalNames value
                        @ validateDo nextLocals nextLexicalNames rest
                    | DoVar(bindingName, value) ->
                        let nextLocals =
                            match inferWithSiblingFallback currentLocals value with
                            | Some inferredType -> Map.add bindingName (refType inferredType) currentLocals
                            | None -> currentLocals

                        validateExpression currentLocals lexicalNames value
                        @ validateDo nextLocals (Set.add bindingName lexicalNames) rest
                    | DoAssign(_, value)
                    | DoDefer value
                    | DoExpression value
                    | DoReturn value ->
                        validateExpression currentLocals lexicalNames value
                        @ validateDo currentLocals lexicalNames rest
                    | DoIf(condition, whenTrue, whenFalse) ->
                        validateExpression currentLocals lexicalNames condition
                        @ validateDo currentLocals lexicalNames whenTrue
                        @ validateDo currentLocals lexicalNames whenFalse
                        @ validateDo currentLocals lexicalNames rest
                    | DoWhile(condition, body) ->
                        validateExpression currentLocals lexicalNames condition
                        @ validateDo currentLocals lexicalNames body
                        @ validateDo currentLocals lexicalNames rest

            validateExpression localTypes parameterNames expression

        let rec validateExpressionWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts expression =
            let environment =
                withVisibleStaticObjects environment (aliasesAsVisibleStaticObjects staticAliases)

            let recurse = validateExpressionWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts

            let queryUseText useMode =
                match useMode with
                | QuerySemantics.Reusable -> "Reusable"
                | QuerySemantics.OneShot -> "OneShot"

            let queryCardText card =
                match card with
                | QuerySemantics.QZero -> "QZero"
                | QuerySemantics.QOne -> "QOne"
                | QuerySemantics.QZeroOrOne -> "QZeroOrOne"
                | QuerySemantics.QOneOrMore -> "QOneOrMore"
                | QuerySemantics.QZeroOrMore -> "QZeroOrMore"

            let rec comprehensionRemainderReferencesName target shadowed (comprehension: SurfaceComprehension) =
                let rec expressionReferences currentShadowed current =
                    match current with
                    | Name(root :: _) ->
                        String.Equals(root, target, StringComparison.Ordinal)
                        && not (Set.contains root currentShadowed)
                    | Name [] ->
                        false
                    | TypeSyntaxTokens _ ->
                        false
                    | SyntaxQuote inner
                    | SyntaxSplice inner
                    | TopLevelSyntaxSplice inner
                    | CodeQuote inner
                    | CodeSplice inner
                    | MonadicSplice inner
                    | ExplicitImplicitArgument inner
                    | InoutArgument inner
                    | Unary(_, inner) ->
                        expressionReferences currentShadowed inner
                    | LocalLet(binding, value, body) ->
                        expressionReferences currentShadowed value
                        || expressionReferences
                            (Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList))
                            body
                    | LocalSignature(declaration, body) ->
                        expressionReferences (Set.add declaration.Name currentShadowed) body
                    | LocalTypeAlias(_, body)
                    | LocalScopedEffect(_, body)
                    | Lambda(_, body) ->
                        expressionReferences currentShadowed body
                    | Handle(_, label, body, returnClause, operationClauses) ->
                        expressionReferences currentShadowed label
                        || expressionReferences currentShadowed body
                        || expressionReferences currentShadowed returnClause.Body
                        || (operationClauses |> List.exists (fun clause -> expressionReferences currentShadowed clause.Body))
                    | IfThenElse(condition, whenTrue, whenFalse) ->
                        expressionReferences currentShadowed condition
                        || expressionReferences currentShadowed whenTrue
                        || expressionReferences currentShadowed whenFalse
                    | Match(scrutinee, cases) ->
                        expressionReferences currentShadowed scrutinee
                        || (cases
                            |> List.exists (fun caseClause ->
                                let caseShadowed =
                                    Set.union currentShadowed (collectPatternNames caseClause.Pattern |> Set.ofList)

                                (caseClause.Guard |> Option.exists (expressionReferences caseShadowed))
                                || expressionReferences caseShadowed caseClause.Body))
                    | RecordLiteral fields ->
                        fields |> List.exists (fun field -> expressionReferences currentShadowed field.Value)
                    | Seal(value, _) ->
                        expressionReferences currentShadowed value
                    | RecordUpdate(receiver, fields) ->
                        expressionReferences currentShadowed receiver
                        || (fields |> List.exists (fun field -> expressionReferences currentShadowed field.Value))
                    | MemberAccess(receiver, _, arguments) ->
                        expressionReferences currentShadowed receiver
                        || (arguments |> List.exists (expressionReferences currentShadowed))
                    | SafeNavigation(receiver, navigation) ->
                        expressionReferences currentShadowed receiver
                        || (navigation.Arguments |> List.exists (expressionReferences currentShadowed))
                    | TagTest(receiver, _) ->
                        expressionReferences currentShadowed receiver
                    | Do statements ->
                        statements
                        |> List.exists (function
                            | DoLet(binding, value)
                            | DoBind(binding, value)
                            | DoUsing(binding, value) ->
                                expressionReferences currentShadowed value
                                || expressionReferences
                                    (Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList))
                                    (Literal LiteralValue.Unit)
                            | DoLetQuestion(binding, value, failure) ->
                                expressionReferences currentShadowed value
                                || (failure
                                    |> Option.exists (fun failure ->
                                        failure.Body
                                        |> List.exists (function
                                            | DoExpression inner
                                            | DoReturn inner
                                            | DoDefer inner
                                            | DoVar(_, inner)
                                            | DoAssign(_, inner) -> expressionReferences currentShadowed inner
                                            | _ -> false)))
                                || expressionReferences
                                    (Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList))
                                    (Literal LiteralValue.Unit)
                            | DoVar(_, value)
                            | DoAssign(_, value)
                            | DoDefer value
                            | DoExpression value
                            | DoReturn value -> expressionReferences currentShadowed value
                            | DoIf(condition, whenTrue, whenFalse) ->
                                expressionReferences currentShadowed condition
                                || (whenTrue |> List.exists (function DoExpression inner | DoReturn inner -> expressionReferences currentShadowed inner | _ -> false))
                                || (whenFalse |> List.exists (function DoExpression inner | DoReturn inner -> expressionReferences currentShadowed inner | _ -> false))
                            | DoWhile(condition, body) ->
                                expressionReferences currentShadowed condition
                                || (body |> List.exists (function DoExpression inner | DoReturn inner -> expressionReferences currentShadowed inner | _ -> false)))
                    | Apply(callee, arguments) ->
                        expressionReferences currentShadowed callee
                        || (arguments |> List.exists (expressionReferences currentShadowed))
                    | NamedApplicationBlock fields ->
                        fields |> List.exists (fun field -> expressionReferences currentShadowed field.Value)
                    | Binary(left, _, right)
                    | Elvis(left, right) ->
                        expressionReferences currentShadowed left
                        || expressionReferences currentShadowed right
                    | Comprehension nested ->
                        comprehensionRemainderReferencesName target currentShadowed nested
                    | PrefixedString(_, parts) ->
                        parts
                        |> List.exists (function
                            | StringText _ -> false
                            | StringInterpolation(inner, _) -> expressionReferences currentShadowed inner)
                    | Literal _
                    | NumericLiteral _
                    | KindQualifiedName _
                    | Name _ ->
                        false

                let yieldReferences currentShadowed =
                    match comprehension.Yield with
                    | YieldValue value ->
                        expressionReferences currentShadowed value
                    | YieldKeyValue(key, value) ->
                        expressionReferences currentShadowed key
                        || expressionReferences currentShadowed value

                let rec loop currentShadowed clauses =
                    match clauses with
                    | [] ->
                        yieldReferences currentShadowed
                    | clause :: rest ->
                        match clause with
                        | ForClause(_, _, binding, source) ->
                            expressionReferences currentShadowed source
                            || loop (Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)) rest
                        | JoinClause(binding, source, condition) ->
                            let nextShadowed =
                                Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)

                            expressionReferences currentShadowed source
                            || expressionReferences nextShadowed condition
                            || loop nextShadowed rest
                        | LetClause(_, binding, value) ->
                            expressionReferences currentShadowed value
                            || loop (Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)) rest
                        | IfClause condition ->
                            expressionReferences currentShadowed condition || loop currentShadowed rest
                        | GroupByClause(key, aggregations, intoName) ->
                            expressionReferences currentShadowed key
                            || (aggregations |> List.exists (fun field -> expressionReferences currentShadowed field.Value))
                            || loop (Set.singleton intoName) rest
                        | OrderByClause(_, key) ->
                            expressionReferences currentShadowed key || loop currentShadowed rest
                        | DistinctClause ->
                            loop currentShadowed rest
                        | DistinctByClause key ->
                            expressionReferences currentShadowed key || loop currentShadowed rest
                        | SkipClause count ->
                            expressionReferences currentShadowed count || loop currentShadowed rest
                        | TakeClause count ->
                            expressionReferences currentShadowed count || loop currentShadowed rest
                        | LeftJoinClause(binding, source, condition, intoName) ->
                            let joinShadowed =
                                Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)

                            expressionReferences currentShadowed source
                            || expressionReferences joinShadowed condition
                            || loop (Set.add intoName currentShadowed) rest

                loop shadowed comprehension.Clauses

            let recurseComprehension (comprehension: SurfaceComprehension) =
                let normalizeVisibleType = normalizeTypeAliases environment.VisibleTypeAliases
                let validateYield currentLocals currentLexical =
                    match comprehension.Yield with
                    | YieldValue value ->
                        validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts value
                    | YieldKeyValue(key, value) ->
                        validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts key
                        @ validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts value

                let rec loop currentLocals currentLexical clauses =
                    match clauses with
                    | [] ->
                        validateYield currentLocals currentLexical
                    | clause :: rest ->
                        match clause with
                        | ForClause(_, isRefutable, binding, source) ->
                            let sourceDiagnostics =
                                validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts source

                            let refutableDiagnostics =
                                if not isRefutable && not (patternIsDefinitelyIrrefutable binding.Pattern) then
                                    [
                                        makeDiagnostic
                                            SimpleDiagnosticKind.TypeEqualityMismatch
                                            "Refutable generator patterns must use 'for?'; plain 'for' requires an irrefutable pattern."
                                    ]
                                else
                                    []

                            let nextLocals =
                                inferValidationExpressionType environment freshCounter currentLocals source
                                |> Option.bind (QuerySemantics.tryInferBuiltinQuerySource normalizeVisibleType)
                                |> Option.map (fun sourceInfo ->
                                    extendBindingLocalTypes environment freshCounter currentLocals binding (Some sourceInfo.Query.ItemType))
                                |> Option.defaultValue (extendBindingLocalTypes environment freshCounter currentLocals binding None)

                            let nextLexical =
                                Set.union currentLexical (collectPatternNames binding.Pattern |> Set.ofList)

                            sourceDiagnostics @ refutableDiagnostics @ loop nextLocals nextLexical rest
                        | JoinClause(binding, source, condition) ->
                            let sourceDiagnostics =
                                validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts source

                            let nextLocals =
                                inferValidationExpressionType environment freshCounter currentLocals source
                                |> Option.bind (QuerySemantics.tryInferBuiltinQuerySource normalizeVisibleType)
                                |> Option.map (fun sourceInfo ->
                                    extendBindingLocalTypes environment freshCounter currentLocals binding (Some sourceInfo.Query.ItemType))
                                |> Option.defaultValue (extendBindingLocalTypes environment freshCounter currentLocals binding None)

                            let nextLexical =
                                Set.union currentLexical (collectPatternNames binding.Pattern |> Set.ofList)

                            let conditionDiagnostics =
                                validateExpressionWithFlow nextLocals refinements nextLexical aliases staticAliases constructorFacts condition

                            sourceDiagnostics @ conditionDiagnostics @ loop nextLocals nextLexical rest
                        | LetClause(_, binding, value) ->
                            let valueDiagnostics =
                                validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts value

                            let nextLocals =
                                inferValidationExpressionType environment freshCounter currentLocals value
                                |> Option.map (fun valueType ->
                                    extendBindingLocalTypes environment freshCounter currentLocals binding (Some valueType))
                                |> Option.defaultValue (extendBindingLocalTypes environment freshCounter currentLocals binding None)

                            let nextLexical =
                                Set.union currentLexical (collectPatternNames binding.Pattern |> Set.ofList)

                            valueDiagnostics @ loop nextLocals nextLexical rest
                        | IfClause condition ->
                            validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts condition
                            @ loop currentLocals currentLexical rest
                        | GroupByClause(key, aggregations, intoName) ->
                            let aggregationDiagnostics =
                                aggregations
                                |> List.collect (fun field ->
                                    validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts field.Value)

                            let nextLocals =
                                Map.add intoName (TypeSignatures.TypeVariable $"__kappa_group_{intoName}") Map.empty

                            let nextLexical = Set.singleton intoName

                            validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts key
                            @ aggregationDiagnostics
                            @ loop nextLocals nextLexical rest
                        | OrderByClause(_, key) ->
                            validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts key
                            @ loop currentLocals currentLexical rest
                        | DistinctClause ->
                            loop currentLocals currentLexical rest
                        | DistinctByClause key ->
                            validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts key
                            @ loop currentLocals currentLexical rest
                        | SkipClause count ->
                            validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts count
                            @ loop currentLocals currentLexical rest
                        | TakeClause count ->
                            validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts count
                            @ loop currentLocals currentLexical rest
                        | LeftJoinClause(binding, source, condition, intoName) ->
                            let sourceDiagnostics =
                                validateExpressionWithFlow currentLocals refinements currentLexical aliases staticAliases constructorFacts source

                            let joinLocals =
                                inferValidationExpressionType environment freshCounter currentLocals source
                                |> Option.bind (QuerySemantics.tryInferBuiltinQuerySource normalizeVisibleType)
                                |> Option.map (fun sourceInfo ->
                                    extendBindingLocalTypes environment freshCounter currentLocals binding (Some sourceInfo.Query.ItemType))
                                |> Option.defaultValue (extendBindingLocalTypes environment freshCounter currentLocals binding None)

                            let joinLexical =
                                Set.union currentLexical (collectPatternNames binding.Pattern |> Set.ofList)

                            let conditionDiagnostics =
                                validateExpressionWithFlow joinLocals refinements joinLexical aliases staticAliases constructorFacts condition

                            let nextLocals =
                                Map.add intoName (TypeSignatures.TypeVariable $"__kappa_left_join_{intoName}") currentLocals

                            let nextLexical = Set.add intoName currentLexical
                            let remainderComprehension =
                                { comprehension with
                                    Clauses = rest }

                            let leakedBindingNames =
                                collectPatternNames binding.Pattern
                                |> List.distinct
                                |> List.filter (fun bindingName ->
                                    not (Set.contains bindingName currentLexical)
                                    && comprehensionRemainderReferencesName bindingName currentLexical remainderComprehension)

                            let leakDiagnostics =
                                leakedBindingNames
                                |> List.map (fun bindingName ->
                                    makeDiagnostic
                                        SimpleDiagnosticKind.NameUnresolved
                                        $"Left-join binder '{bindingName}' is not in scope after the clause; only '{intoName}' remains available.")

                            let nextLexical =
                                leakedBindingNames
                                |> Set.ofList
                                |> Set.union nextLexical

                            sourceDiagnostics @ conditionDiagnostics @ leakDiagnostics @ loop nextLocals nextLexical rest

                loop locals lexicalNames comprehension.Clauses

            let simpleClauseBinderName (tokens: Token list) =
                match tokens |> List.filter (fun token -> token.Kind <> Newline && token.Kind <> Indent && token.Kind <> Dedent) with
                | [ token ] when Token.isName token ->
                    Some(SyntaxFacts.trimIdentifierQuotes token.Text)
                | _ ->
                    None

            let clauseBoundNames (clause: SurfaceEffectHandlerClause) =
                let argumentNames =
                    clause.ArgumentTokens
                    |> List.choose simpleClauseBinderName

                match clause.ResumptionName with
                | Some name -> name :: argumentNames
                | None -> argumentNames
                |> Set.ofList

            let rec expressionReferencesName target shadowed current =
                let recurseName = expressionReferencesName target shadowed

                let rec comprehensionReferencesName shadowed (comprehension: SurfaceComprehension) =
                    let yieldReferences currentShadowed =
                        match comprehension.Yield with
                        | YieldValue value ->
                            expressionReferencesName target currentShadowed value
                        | YieldKeyValue(key, value) ->
                            expressionReferencesName target currentShadowed key
                            || expressionReferencesName target currentShadowed value

                    let rec loop currentShadowed clauses =
                        match clauses with
                        | [] ->
                            yieldReferences currentShadowed
                        | clause :: rest ->
                            match clause with
                            | ForClause(_, _, binding, source) ->
                                expressionReferencesName target currentShadowed source
                                || loop (Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)) rest
                            | JoinClause(binding, source, condition) ->
                                let nextShadowed =
                                    Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)

                                expressionReferencesName target currentShadowed source
                                || expressionReferencesName target nextShadowed condition
                                || loop nextShadowed rest
                            | LetClause(_, binding, value) ->
                                expressionReferencesName target currentShadowed value
                                || loop (Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)) rest
                            | IfClause condition ->
                                expressionReferencesName target currentShadowed condition || loop currentShadowed rest
                            | GroupByClause(key, aggregations, intoName) ->
                                expressionReferencesName target currentShadowed key
                                || (aggregations
                                    |> List.exists (fun field -> expressionReferencesName target currentShadowed field.Value))
                                || loop (Set.singleton intoName) rest
                            | OrderByClause(_, key) ->
                                expressionReferencesName target currentShadowed key || loop currentShadowed rest
                            | DistinctClause ->
                                loop currentShadowed rest
                            | DistinctByClause key ->
                                expressionReferencesName target currentShadowed key || loop currentShadowed rest
                            | SkipClause count ->
                                expressionReferencesName target currentShadowed count || loop currentShadowed rest
                            | TakeClause count ->
                                expressionReferencesName target currentShadowed count || loop currentShadowed rest
                            | LeftJoinClause(binding, source, condition, intoName) ->
                                let joinShadowed =
                                    Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)

                                expressionReferencesName target currentShadowed source
                                || expressionReferencesName target joinShadowed condition
                                || loop (Set.add intoName currentShadowed) rest

                    loop shadowed comprehension.Clauses

                match current with
                | Name [ name ] ->
                    String.Equals(name, target, StringComparison.Ordinal)
                    && not (Set.contains name shadowed)
                | TypeSyntaxTokens _ ->
                    false
                | SyntaxQuote inner
                | SyntaxSplice inner
                | TopLevelSyntaxSplice inner
                | CodeQuote inner
                | CodeSplice inner
                | MonadicSplice inner
                | ExplicitImplicitArgument inner
                | InoutArgument inner
                | Unary(_, inner) ->
                    recurseName inner
                | LocalLet(binding, value, body) ->
                    recurseName value
                    || expressionReferencesName target (Set.union shadowed (collectPatternNames binding.Pattern |> Set.ofList)) body
                | LocalSignature(declaration, body) ->
                    if String.Equals(declaration.Name, target, StringComparison.Ordinal) then
                        recurseName body
                    else
                        expressionReferencesName target (Set.add declaration.Name shadowed) body
                | LocalTypeAlias(_, body) ->
                    recurseName body
                | LocalScopedEffect(declaration, body) ->
                    if String.Equals(declaration.Name, target, StringComparison.Ordinal) then
                        false
                    else
                        recurseName body
                | Lambda(parameters, body) ->
                    let shadowedParameters =
                        parameters |> List.map (fun parameter -> parameter.Name) |> Set.ofList |> Set.union shadowed

                    expressionReferencesName target shadowedParameters body
                | Handle(_, label, body, returnClause, operationClauses) ->
                    recurseName label
                    || recurseName body
                    || expressionReferencesName target (Set.union shadowed (clauseBoundNames returnClause)) returnClause.Body
                    || (operationClauses
                        |> List.exists (fun clause ->
                            expressionReferencesName target (Set.union shadowed (clauseBoundNames clause)) clause.Body))
                | IfThenElse(condition, whenTrue, whenFalse) ->
                    recurseName condition || recurseName whenTrue || recurseName whenFalse
                | Match(scrutinee, cases) ->
                    recurseName scrutinee
                    || (cases
                        |> List.exists (fun caseClause ->
                            let caseShadowed = Set.union shadowed (collectPatternNames caseClause.Pattern |> Set.ofList)
                            let guardUses =
                                caseClause.Guard
                                |> Option.exists (expressionReferencesName target caseShadowed)

                            guardUses || expressionReferencesName target caseShadowed caseClause.Body))
                | RecordLiteral fields ->
                    fields |> List.exists (fun field -> recurseName field.Value)
                | Seal(value, _) ->
                    recurseName value
                | RecordUpdate(receiver, fields) ->
                    recurseName receiver || (fields |> List.exists (fun field -> recurseName field.Value))
                | MemberAccess(receiver, _, arguments) ->
                    recurseName receiver || (arguments |> List.exists recurseName)
                | SafeNavigation(receiver, navigation) ->
                    recurseName receiver || (navigation.Arguments |> List.exists recurseName)
                | TagTest(receiver, _) ->
                    recurseName receiver
                | Do statements ->
                    statements
                    |> List.exists (function
                        | DoLet(binding, value)
                        | DoBind(binding, value)
                        | DoUsing(binding, value) ->
                            recurseName value
                            || expressionReferencesName target (Set.union shadowed (collectPatternNames binding.Pattern |> Set.ofList)) (Literal LiteralValue.Unit)
                        | DoLetQuestion(binding, value, failure) ->
                            recurseName value
                            || (failure
                                |> Option.exists (fun failure ->
                                    let failureShadowed =
                                        Set.union shadowed (collectPatternNames failure.ResiduePattern.Pattern |> Set.ofList)

                                    failure.Body
                                    |> List.exists (function
                                        | DoExpression inner
                                        | DoReturn inner
                                        | DoDefer inner
                                        | DoVar(_, inner)
                                        | DoAssign(_, inner) -> expressionReferencesName target failureShadowed inner
                                        | _ -> false)))
                            || expressionReferencesName target (Set.union shadowed (collectPatternNames binding.Pattern |> Set.ofList)) (Literal LiteralValue.Unit)
                        | DoVar(_, value)
                        | DoAssign(_, value)
                        | DoDefer value
                        | DoExpression value
                        | DoReturn value -> recurseName value
                        | DoIf(condition, whenTrue, whenFalse) ->
                            recurseName condition
                            || (whenTrue |> List.exists (function DoExpression inner | DoReturn inner -> recurseName inner | _ -> false))
                            || (whenFalse |> List.exists (function DoExpression inner | DoReturn inner -> recurseName inner | _ -> false))
                        | DoWhile(condition, body) ->
                            recurseName condition
                            || (body |> List.exists (function DoExpression inner | DoReturn inner -> recurseName inner | _ -> false)))
                | Apply(callee, arguments) ->
                    recurseName callee || (arguments |> List.exists recurseName)
                | NamedApplicationBlock fields ->
                    fields |> List.exists (fun field -> recurseName field.Value)
                | Binary(left, _, right)
                | Elvis(left, right) ->
                    recurseName left || recurseName right
                | Comprehension comprehension ->
                    comprehensionReferencesName shadowed comprehension
                | PrefixedString(_, parts) ->
                    parts
                    |> List.exists (function
                        | StringText _ -> false
                        | StringInterpolation(inner, _) -> recurseName inner)
                | Literal _
                | NumericLiteral _
                | KindQualifiedName _
                | Name _ ->
                    false

            let quoteSpliceDiagnostics inner =
                match inferValidationExpressionType environment freshCounter locals inner with
                | Some actualType ->
                    match tryUnwrapSyntaxType environment.VisibleTypeAliases actualType with
                    | Some _ ->
                        []
                    | None ->
                        match
                            actualType
                            |> tryUnwrapElabType environment.VisibleTypeAliases
                            |> Option.bind (tryUnwrapSyntaxType environment.VisibleTypeAliases)
                        with
                        | Some _ ->
                            [ makeSurfaceElaborationDiagnostic QuoteSpliceRequiresSyntaxNotElabSyntax ]
                        | None ->
                            [ makeSurfaceElaborationDiagnostic
                                (QuoteSpliceRequiresSyntax(TypeSignatures.toText actualType)) ]
                | None ->
                    []

            let topLevelSpliceTypeDiagnostics inner =
                match tryInferTopLevelSpliceResultType locals inner with
                | Some _ ->
                    []
                | None ->
                    match tryInferMacroAwareValidationType locals inner with
                    | Some actualType ->
                        [ makeSurfaceElaborationDiagnostic
                            (TopLevelSpliceRequiresSyntaxOrElabSyntax(TypeSignatures.toText actualType)) ]
                    | None ->
                        []

            let rec substituteSyntaxArguments substitutions shadowed current =
                let rewrite = substituteSyntaxArguments substitutions shadowed

                match current with
                | Name [ name ] when not (Set.contains name shadowed) ->
                    substitutions |> Map.tryFind name |> Option.defaultValue current
                | TypeSyntaxTokens _ ->
                    current
                | SyntaxQuote inner ->
                    SyntaxQuote(rewrite inner)
                | SyntaxSplice inner ->
                    SyntaxSplice(rewrite inner)
                | TopLevelSyntaxSplice inner ->
                    TopLevelSyntaxSplice(rewrite inner)
                | CodeQuote inner ->
                    CodeQuote(rewrite inner)
                | CodeSplice inner ->
                    CodeSplice(rewrite inner)
                | Handle(isDeep, label, body, returnClause, operationClauses) ->
                    let rewriteClause (clause: SurfaceEffectHandlerClause) =
                        { clause with
                            Body = rewrite clause.Body }

                    Handle(
                        isDeep,
                        rewrite label,
                        rewrite body,
                        rewriteClause returnClause,
                        operationClauses |> List.map rewriteClause
                    )
                | Apply(callee, arguments) ->
                    Apply(rewrite callee, arguments |> List.map rewrite)
                | LocalLet(binding, value, body) ->
                    let nextShadowed =
                        collectPatternNames binding.Pattern
                        |> Set.ofList
                        |> Set.union shadowed

                    LocalLet(binding, rewrite value, substituteSyntaxArguments substitutions nextShadowed body)
                | LocalSignature(declaration, body) ->
                    LocalSignature(declaration, substituteSyntaxArguments substitutions (Set.add declaration.Name shadowed) body)
                | LocalTypeAlias(declaration, body) ->
                    LocalTypeAlias(declaration, rewrite body)
                | LocalScopedEffect(declaration, body) ->
                    LocalScopedEffect(declaration, substituteSyntaxArguments substitutions (Set.add declaration.Name shadowed) body)
                | Lambda(parameters, body) ->
                    let nextShadowed =
                        parameters
                        |> List.map (fun parameter -> parameter.Name)
                        |> Set.ofList
                        |> Set.union shadowed

                    Lambda(parameters, substituteSyntaxArguments substitutions nextShadowed body)
                | IfThenElse(condition, whenTrue, whenFalse) ->
                    IfThenElse(rewrite condition, rewrite whenTrue, rewrite whenFalse)
                | Match(scrutinee, cases) ->
                    Match(
                        rewrite scrutinee,
                        cases
                        |> List.map (fun caseClause ->
                            let caseShadowed =
                                collectPatternNames caseClause.Pattern
                                |> Set.ofList
                                |> Set.union shadowed

                            { caseClause with
                                Guard = caseClause.Guard |> Option.map (substituteSyntaxArguments substitutions caseShadowed)
                                Body = substituteSyntaxArguments substitutions caseShadowed caseClause.Body })
                    )
                | RecordLiteral fields ->
                    RecordLiteral(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
                | Seal(value, ascriptionTokens) ->
                    Seal(rewrite value, ascriptionTokens)
                | RecordUpdate(receiver, fields) ->
                    RecordUpdate(rewrite receiver, fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
                | MemberAccess(receiver, segments, arguments) ->
                    MemberAccess(rewrite receiver, segments, arguments |> List.map rewrite)
                | SafeNavigation(receiver, navigation) ->
                    SafeNavigation(rewrite receiver, { navigation with Arguments = navigation.Arguments |> List.map rewrite })
                | TagTest(receiver, constructorName) ->
                    TagTest(rewrite receiver, constructorName)
                | Do statements ->
                    Do statements
                | MonadicSplice inner ->
                    MonadicSplice(rewrite inner)
                | ExplicitImplicitArgument inner ->
                    ExplicitImplicitArgument(rewrite inner)
                | NamedApplicationBlock fields ->
                    NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
                | InoutArgument inner ->
                    InoutArgument(rewrite inner)
                | Unary(operatorName, inner) ->
                    Unary(operatorName, rewrite inner)
                | Binary(left, operatorName, right) ->
                    Binary(rewrite left, operatorName, rewrite right)
                | Elvis(left, right) ->
                    Elvis(rewrite left, rewrite right)
                | Comprehension comprehension ->
                    Comprehension { comprehension with Lowered = rewrite comprehension.Lowered }
                | PrefixedString(prefix, parts) ->
                    PrefixedString(
                        prefix,
                        parts
                        |> List.map (function
                            | StringText text -> StringText text
                            | StringInterpolation(inner, format) -> StringInterpolation(rewrite inner, format))
                    )
                | Literal _
                | NumericLiteral _
                | KindQualifiedName _
                | TypeSyntaxTokens _
                | Name _ ->
                    current

            let rec inlineSyntaxQuoteSplices current =
                let rewrite = inlineSyntaxQuoteSplices

                match current with
                | SyntaxSplice(SyntaxQuote inner) ->
                    rewrite inner
                | SyntaxQuote inner ->
                    SyntaxQuote(rewrite inner)
                | SyntaxSplice inner ->
                    SyntaxSplice(rewrite inner)
                | TopLevelSyntaxSplice inner ->
                    TopLevelSyntaxSplice(rewrite inner)
                | CodeQuote inner ->
                    CodeQuote(rewrite inner)
                | CodeSplice inner ->
                    CodeSplice(rewrite inner)
                | Apply(callee, arguments) ->
                    Apply(rewrite callee, arguments |> List.map rewrite)
                | Handle(isDeep, label, body, returnClause, operationClauses) ->
                    let rewriteClause (clause: SurfaceEffectHandlerClause) =
                        { clause with
                            Body = rewrite clause.Body }

                    Handle(
                        isDeep,
                        rewrite label,
                        rewrite body,
                        rewriteClause returnClause,
                        operationClauses |> List.map rewriteClause
                    )
                | LocalLet(binding, value, body) ->
                    LocalLet(binding, rewrite value, rewrite body)
                | LocalSignature(declaration, body) ->
                    LocalSignature(declaration, rewrite body)
                | LocalTypeAlias(declaration, body) ->
                    LocalTypeAlias(declaration, rewrite body)
                | LocalScopedEffect(declaration, body) ->
                    LocalScopedEffect(declaration, rewrite body)
                | Lambda(parameters, body) ->
                    Lambda(parameters, rewrite body)
                | IfThenElse(condition, whenTrue, whenFalse) ->
                    IfThenElse(rewrite condition, rewrite whenTrue, rewrite whenFalse)
                | Match(scrutinee, cases) ->
                    Match(
                        rewrite scrutinee,
                        cases
                        |> List.map (fun caseClause ->
                            { caseClause with
                                Guard = caseClause.Guard |> Option.map rewrite
                                Body = rewrite caseClause.Body })
                    )
                | RecordLiteral fields ->
                    RecordLiteral(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
                | Seal(value, ascriptionTokens) ->
                    Seal(rewrite value, ascriptionTokens)
                | RecordUpdate(receiver, fields) ->
                    RecordUpdate(rewrite receiver, fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
                | MemberAccess(receiver, segments, arguments) ->
                    MemberAccess(rewrite receiver, segments, arguments |> List.map rewrite)
                | SafeNavigation(receiver, navigation) ->
                    SafeNavigation(rewrite receiver, { navigation with Arguments = navigation.Arguments |> List.map rewrite })
                | TagTest(receiver, constructorName) ->
                    TagTest(rewrite receiver, constructorName)
                | Do statements ->
                    Do statements
                | MonadicSplice inner ->
                    MonadicSplice(rewrite inner)
                | ExplicitImplicitArgument inner ->
                    ExplicitImplicitArgument(rewrite inner)
                | NamedApplicationBlock fields ->
                    NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
                | InoutArgument inner ->
                    InoutArgument(rewrite inner)
                | Unary(operatorName, inner) ->
                    Unary(operatorName, rewrite inner)
                | Binary(left, operatorName, right) ->
                    Binary(rewrite left, operatorName, rewrite right)
                | Elvis(left, right) ->
                    Elvis(rewrite left, rewrite right)
                | Comprehension comprehension ->
                    Comprehension { comprehension with Lowered = rewrite comprehension.Lowered }
                | PrefixedString(prefix, parts) ->
                    PrefixedString(
                        prefix,
                        parts
                        |> List.map (function
                            | StringText text -> StringText text
                            | StringInterpolation(inner, format) -> StringInterpolation(rewrite inner, format))
                    )
                | Literal _
                | NumericLiteral _
                | KindQualifiedName _
                | TypeSyntaxTokens _
                | Name _ ->
                    current

            let rec tryExpandDirectSyntaxProducer visited current =
                match current with
                | SyntaxQuote inner ->
                    Some(inlineSyntaxQuoteSplices inner)
                | Apply(Name [ "pure" ], [ SyntaxQuote inner ]) ->
                    Some(inlineSyntaxQuoteSplices inner)
                | Apply(Name [ macroName ], arguments) when not (Set.contains macroName visited) ->
                    topLevelDefinitionsByName
                    |> Map.tryFind macroName
                    |> Option.bind (fun macroDefinition ->
                        match macroDefinition.Body with
                        | Some macroBody when List.length macroDefinition.Parameters = List.length arguments ->
                            let substitutions =
                                List.zip macroDefinition.Parameters arguments
                                |> List.map (fun (parameter, argument) -> parameter.Name, argument)
                                |> Map.ofList

                            let substitutedBody =
                                substituteSyntaxArguments substitutions Set.empty macroBody

                            tryExpandDirectSyntaxProducer (Set.add macroName visited) substitutedBody
                        | _ ->
                            None)
                | _ ->
                    None

            let rec countNameUses target shadowed current =
                let recurseCount = countNameUses target shadowed

                match current with
                | Name [ name ] when String.Equals(name, target, StringComparison.Ordinal) && not (Set.contains name shadowed) ->
                    1
                | Name _ ->
                    0
                | TypeSyntaxTokens _ ->
                    0
                | SyntaxQuote inner
                | SyntaxSplice inner
                | TopLevelSyntaxSplice inner
                | CodeQuote inner
                | CodeSplice inner
                | MonadicSplice inner
                | ExplicitImplicitArgument inner
                | InoutArgument inner
                | Unary(_, inner) ->
                    recurseCount inner
                | LocalLet(binding, value, body) ->
                    recurseCount value
                    + countNameUses
                        target
                        (Set.union shadowed (collectPatternNames binding.Pattern |> Set.ofList))
                        body
                | LocalSignature(declaration, body) ->
                    countNameUses target (Set.add declaration.Name shadowed) body
                | LocalTypeAlias(_, body) ->
                    recurseCount body
                | LocalScopedEffect(declaration, body) ->
                    countNameUses target (Set.add declaration.Name shadowed) body
                | Lambda(parameters, body) ->
                    let nextShadowed =
                        parameters
                        |> List.map (fun parameter -> parameter.Name)
                        |> Set.ofList
                        |> Set.union shadowed

                    countNameUses target nextShadowed body
                | Handle(_, label, body, returnClause, operationClauses) ->
                    recurseCount label
                    + recurseCount body
                    + countNameUses target (Set.union shadowed (clauseBoundNames returnClause)) returnClause.Body
                    + (operationClauses
                       |> List.sumBy (fun clause ->
                           countNameUses target (Set.union shadowed (clauseBoundNames clause)) clause.Body))
                | IfThenElse(condition, whenTrue, whenFalse) ->
                    recurseCount condition + recurseCount whenTrue + recurseCount whenFalse
                | Match(scrutinee, cases) ->
                    recurseCount scrutinee
                    + (cases
                       |> List.sumBy (fun caseClause ->
                           let caseShadowed =
                               Set.union shadowed (collectPatternNames caseClause.Pattern |> Set.ofList)

                           let guardCount =
                               caseClause.Guard
                               |> Option.map (countNameUses target caseShadowed)
                               |> Option.defaultValue 0

                           guardCount + countNameUses target caseShadowed caseClause.Body))
                | RecordLiteral fields ->
                    fields |> List.sumBy (fun field -> recurseCount field.Value)
                | Seal(value, _) ->
                    recurseCount value
                | RecordUpdate(receiver, fields) ->
                    recurseCount receiver + (fields |> List.sumBy (fun field -> recurseCount field.Value))
                | MemberAccess(receiver, _, arguments) ->
                    recurseCount receiver + (arguments |> List.sumBy recurseCount)
                | SafeNavigation(receiver, navigation) ->
                    recurseCount receiver + (navigation.Arguments |> List.sumBy recurseCount)
                | TagTest(receiver, _) ->
                    recurseCount receiver
                | Do statements ->
                    statements
                    |> List.sumBy (function
                        | DoLet(binding, value)
                        | DoBind(binding, value)
                        | DoUsing(binding, value) ->
                            recurseCount value
                            + countNameUses
                                target
                                (Set.union shadowed (collectPatternNames binding.Pattern |> Set.ofList))
                                (Literal LiteralValue.Unit)
                        | DoLetQuestion(binding, value, failure) ->
                            let failureCount =
                                failure
                                |> Option.map (fun failure ->
                                    let failureShadowed =
                                        Set.union shadowed (collectPatternNames failure.ResiduePattern.Pattern |> Set.ofList)

                                    failure.Body
                                    |> List.sumBy (function
                                        | DoExpression inner
                                        | DoReturn inner
                                        | DoDefer inner
                                        | DoVar(_, inner)
                                        | DoAssign(_, inner) -> countNameUses target failureShadowed inner
                                        | _ -> 0))
                                |> Option.defaultValue 0

                            recurseCount value
                            + failureCount
                            + countNameUses
                                target
                                (Set.union shadowed (collectPatternNames binding.Pattern |> Set.ofList))
                                (Literal LiteralValue.Unit)
                        | DoVar(_, inner)
                        | DoAssign(_, inner)
                        | DoDefer inner
                        | DoExpression inner
                        | DoReturn inner -> recurseCount inner
                        | DoIf(condition, whenTrue, whenFalse) ->
                            recurseCount condition
                            + (whenTrue |> List.sumBy (function DoExpression inner | DoReturn inner -> recurseCount inner | _ -> 0))
                            + (whenFalse |> List.sumBy (function DoExpression inner | DoReturn inner -> recurseCount inner | _ -> 0))
                        | DoWhile(condition, body) ->
                            recurseCount condition
                            + (body |> List.sumBy (function DoExpression inner | DoReturn inner -> recurseCount inner | _ -> 0)))
                | Apply(callee, arguments) ->
                    recurseCount callee + (arguments |> List.sumBy recurseCount)
                | NamedApplicationBlock fields ->
                    fields |> List.sumBy (fun field -> recurseCount field.Value)
                | Binary(left, _, right)
                | Elvis(left, right) ->
                    recurseCount left + recurseCount right
                | Comprehension comprehension ->
                    recurseCount comprehension.Lowered
                | PrefixedString(_, parts) ->
                    parts
                    |> List.sumBy (function
                        | StringText _ -> 0
                        | StringInterpolation(inner, _) -> recurseCount inner)
                | Literal _
                | NumericLiteral _
                | KindQualifiedName _ ->
                    0

            let topLevelSpliceLinearityDiagnostics inner =
                match tryExpandDirectSyntaxProducer Set.empty inner with
                | Some expandedBody ->
                    let linearParameters =
                        definition.Name
                        |> Option.bind (fun name ->
                            environment.VisibleBindings
                            |> Map.tryFind name
                            |> Option.bind (fun bindingInfo -> bindingInfo.ParameterLayouts))
                        |> Option.defaultValue definition.Parameters

                    linearParameters
                    |> List.collect (fun parameter ->
                        match parameter.Quantity with
                        | Some QuantityOne
                        | Some QuantityAtMostOne ->
                            if countNameUses parameter.Name Set.empty expandedBody > 1 then
                                [
                                    makeDiagnostic
                                        SimpleDiagnosticKind.QttLinearOveruse
                                        $"Macro-expanded syntax uses linear binder '{parameter.Name}' more than once."
                                ]
                            else
                                []
                        | _ ->
                            [])
                | None ->
                    []

            let topLevelSpliceElabPhaseDiagnostics inner =
                let objectPhaseEscapeDiagnostic name =
                    makeSurfaceElaborationDiagnostic
                        (ObjectPhaseValueCannotBePassedDirectlyToElaboration name)

                let localIsCompileTimeOnly name =
                    locals
                    |> Map.tryFind name
                    |> Option.exists typeIsMetaPhaseTransferType

                let rec loop shadowed current =
                    let recurseCurrent = loop shadowed

                    match current with
                    | Name [ name ] when not (Set.contains name shadowed) ->
                        if localIsCompileTimeOnly name then
                            []
                        elif Map.containsKey name locals || Set.contains name lexicalNames then
                            [ objectPhaseEscapeDiagnostic name ]
                        else
                            []
                    | Name _
                    | Literal _
                    | NumericLiteral _
                    | KindQualifiedName _
                    | TypeSyntaxTokens _ ->
                        []
                    | SyntaxQuote _ ->
                        []
                    | SyntaxSplice nested
                    | TopLevelSyntaxSplice nested
                    | CodeSplice nested
                    | MonadicSplice nested
                    | InoutArgument nested
                    | Unary(_, nested)
                    | Seal(nested, _) ->
                        recurseCurrent nested
                    | ExplicitImplicitArgument nested ->
                        match tryParseTypeLikeSurfaceExpression nested with
                        | Some _ -> []
                        | None -> recurseCurrent nested
                    | CodeQuote _ ->
                        []
                    | Apply(callee, arguments) ->
                        recurseCurrent callee @ (arguments |> List.collect recurseCurrent)
                    | LocalLet(binding, value, body) ->
                        let nextShadowed =
                            Set.union shadowed (collectPatternNames binding.Pattern |> Set.ofList)

                        recurseCurrent value @ loop nextShadowed body
                    | LocalSignature(declaration, body) ->
                        loop (Set.add declaration.Name shadowed) body
                    | LocalTypeAlias(_, body) ->
                        recurseCurrent body
                    | LocalScopedEffect(declaration, body) ->
                        loop (Set.add declaration.Name shadowed) body
                    | Lambda(parameters, body) ->
                        let nextShadowed =
                            parameters
                            |> List.map (fun parameter -> parameter.Name)
                            |> Set.ofList
                            |> Set.union shadowed

                        loop nextShadowed body
                    | Handle(_, label, body, returnClause, operationClauses) ->
                        recurseCurrent label
                        @ recurseCurrent body
                        @ loop (Set.union shadowed (clauseBoundNames returnClause)) returnClause.Body
                        @ (operationClauses
                           |> List.collect (fun clause ->
                               loop (Set.union shadowed (clauseBoundNames clause)) clause.Body))
                    | IfThenElse(condition, whenTrue, whenFalse) ->
                        recurseCurrent condition @ recurseCurrent whenTrue @ recurseCurrent whenFalse
                    | Match(scrutinee, cases) ->
                        recurseCurrent scrutinee
                        @ (cases
                           |> List.collect (fun caseClause ->
                               let caseShadowed =
                                   Set.union shadowed (collectPatternNames caseClause.Pattern |> Set.ofList)

                               (caseClause.Guard |> Option.map (loop caseShadowed) |> Option.defaultValue [])
                               @ loop caseShadowed caseClause.Body))
                    | RecordLiteral fields ->
                        fields |> List.collect (fun field -> recurseCurrent field.Value)
                    | RecordUpdate(receiver, fields) ->
                        recurseCurrent receiver @ (fields |> List.collect (fun field -> recurseCurrent field.Value))
                    | MemberAccess(receiver, _, arguments) ->
                        recurseCurrent receiver @ (arguments |> List.collect recurseCurrent)
                    | SafeNavigation(receiver, navigation) ->
                        recurseCurrent receiver @ (navigation.Arguments |> List.collect recurseCurrent)
                    | TagTest(receiver, _) ->
                        recurseCurrent receiver
                    | Do statements ->
                        let rec loopStatements currentShadowed remaining =
                            match remaining with
                            | [] ->
                                []
                            | statement :: rest ->
                                match statement with
                                | DoLet(binding, value)
                                | DoBind(binding, value)
                                | DoUsing(binding, value) ->
                                    let nextShadowed =
                                        Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)

                                    loop currentShadowed value @ loopStatements nextShadowed rest
                                | DoLetQuestion(binding, value, failure) ->
                                    let nextShadowed =
                                        Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)

                                    let failureDiagnostics =
                                        failure
                                        |> Option.map (fun failure ->
                                            let failureShadowed =
                                                Set.union nextShadowed (collectPatternNames failure.ResiduePattern.Pattern |> Set.ofList)

                                            loopStatements failureShadowed failure.Body)
                                        |> Option.defaultValue []

                                    loop currentShadowed value @ failureDiagnostics @ loopStatements nextShadowed rest
                                | DoVar(name, value) ->
                                    let nextShadowed = Set.add name currentShadowed
                                    loop currentShadowed value @ loopStatements nextShadowed rest
                                | DoAssign(_, value)
                                | DoDefer value
                                | DoExpression value
                                | DoReturn value ->
                                    loop currentShadowed value @ loopStatements currentShadowed rest
                                | DoIf(condition, whenTrue, whenFalse) ->
                                    loop currentShadowed condition
                                    @ loopStatements currentShadowed whenTrue
                                    @ loopStatements currentShadowed whenFalse
                                    @ loopStatements currentShadowed rest
                                | DoWhile(condition, body) ->
                                    loop currentShadowed condition
                                    @ loopStatements currentShadowed body
                                    @ loopStatements currentShadowed rest

                        loopStatements shadowed statements
                    | NamedApplicationBlock fields ->
                        fields |> List.collect (fun field -> recurseCurrent field.Value)
                    | Binary(left, _, right)
                    | Elvis(left, right) ->
                        recurseCurrent left @ recurseCurrent right
                    | Comprehension comprehension ->
                        recurseCurrent comprehension.Lowered
                    | PrefixedString(_, parts) ->
                        parts
                        |> List.collect (function
                            | StringText _ -> []
                            | StringInterpolation(nested, _) -> recurseCurrent nested)

                loop Set.empty inner

            match expression with
            | SyntaxQuote inner ->
                recurse inner
            | SyntaxSplice inner ->
                recurse inner @ quoteSpliceDiagnostics inner
            | TopLevelSyntaxSplice inner ->
                recurse inner
                @ topLevelSpliceTypeDiagnostics inner
                @ topLevelSpliceElabPhaseDiagnostics inner
                @ topLevelSpliceLinearityDiagnostics inner
                @ (tryExtractFailElabDiagnosticEvidence inner
                   |> Option.map (fun evidence -> [ makeSurfaceElaborationDiagnostic evidence ])
                   |> Option.defaultValue [])
            | TypeSyntaxTokens _ ->
                []
            | CodeQuote inner
            | CodeSplice inner ->
                recurse inner
            | Handle(isDeep, label, body, returnClause, operationClauses) ->
                let returnClauseLexicalNames =
                    Set.union lexicalNames (clauseBoundNames returnClause)

                let handledBodyType =
                    inferValidationExpressionType environment freshCounter locals body

                let handledPayloadType =
                    handledBodyType
                    |> Option.bind tryUnwrapEffType
                    |> Option.map snd
                    |> Option.defaultValue (TypeVariable $"handlePayload{freshCounter.Value}")

                let handledEffectSplit =
                    match tryResolveHandledEffectDeclaration environment label, handledBodyType with
                    | Some declaration, Some handledType ->
                        match tryUnwrapEffType handledType with
                        | Some(effectRow, payloadType) ->
                            Some(declaration, effectRow, payloadType, trySplitHandledEffectRow environment.VisibleTypeAliases declaration effectRow)
                        | None ->
                            None
                    | _ ->
                        None

                let extendHandlerLocals argumentTokens argumentTypes resumptionName resumptionType currentLocals =
                    let nextLocals =
                        argumentTokens
                        |> List.mapi (fun index tokens -> tokens, argumentTypes |> List.tryItem index)
                        |> List.fold (fun state (tokens, argumentType) ->
                            match tryParseEffectHandlerArgumentName tokens, argumentType with
                            | Some name, Some currentArgumentType -> Map.add name currentArgumentType state
                            | _ -> state) currentLocals

                    match resumptionName, resumptionType with
                    | Some name, Some currentResumptionType ->
                        Map.add name currentResumptionType nextLocals
                    | _ ->
                        nextLocals

                let returnClauseLocals =
                    extendHandlerLocals returnClause.ArgumentTokens [ handledPayloadType ] None None locals

                let returnClauseType =
                    inferValidationExpressionType environment freshCounter returnClauseLocals returnClause.Body

                let splitDerivedHandlerResultType =
                    handledEffectSplit
                    |> Option.bind (fun (_, _, payloadType, splitResult) ->
                        match splitResult with
                        | SplitResolved remainderRow -> Some(effType remainderRow payloadType)
                        | _ -> None)

                let tryOperationClauseLocals (clause: SurfaceEffectHandlerClause) =
                    match tryResolveHandledEffectDeclaration environment label with
                    | Some declaration ->
                        EffectSemantics.tryFindOperation clause.OperationName declaration
                        |> Option.bind (fun operation ->
                            operation.SignatureTokens
                            |> TypeSignatures.parseType
                            |> Option.map (qualifyVisibleTypeNames environment)
                            |> Option.map TypeSignatures.functionParts
                            |> Option.map (fun (parameterTypes, resultType) ->
                                let resumptionResultType =
                                    if isDeep then
                                        splitDerivedHandlerResultType
                                        |> Option.orElse returnClauseType
                                    else
                                        handledBodyType

                                let resumptionType =
                                    resumptionResultType
                                    |> Option.map (fun currentResultType -> TypeArrow(QuantityOne, resultType, currentResultType))

                                extendHandlerLocals
                                    clause.ArgumentTokens
                                    parameterTypes
                                    clause.ResumptionName
                                    resumptionType
                                    locals))
                    | _ ->
                        None

                let operationClauseInfos =
                    operationClauses
                    |> List.map (fun clause ->
                        let clauseLocals = tryOperationClauseLocals clause |> Option.defaultValue locals
                        clause, clauseLocals, inferValidationExpressionType environment freshCounter clauseLocals clause.Body)

                let finalHandlerResultType =
                    splitDerivedHandlerResultType
                    |> Option.orElseWith (fun () ->
                        if isDeep then
                            returnClauseType
                            |> Option.orElseWith (fun () ->
                                operationClauseInfos
                                |> List.tryPick (fun (_, _, clauseType) -> clauseType))
                        else
                            returnClauseType)

                let operationClauseExpectedType =
                    if isDeep then
                        finalHandlerResultType
                    else
                        handledBodyType

                let handlerClauseTypeDiagnostics =
                    let carrierDiagnostics =
                        finalHandlerResultType
                        |> Option.filter (isHandlerCarrierResultType >> not)
                        |> Option.map (fun actualType ->
                            [ makeSurfaceElaborationDiagnostic
                                (HandlerClausesMustReturnCarrierResultType(TypeSignatures.toText actualType)) ])
                        |> Option.defaultValue []

                    let returnDiagnostics =
                        finalHandlerResultType
                        |> Option.map (fun expectedType ->
                            bindableCarrierExpectedTypeDiagnostics
                                returnClauseLocals
                                refinements
                                "Handler return clause"
                                expectedType
                                returnClause.Body)
                        |> Option.defaultValue []

                    let operationDiagnostics =
                        match operationClauseExpectedType with
                        | Some expectedType ->
                            operationClauseInfos
                            |> List.collect (fun (clause, clauseLocals, _) ->
                                bindableCarrierExpectedTypeDiagnostics
                                    clauseLocals
                                    refinements
                                    $"Handler clause for operation '{clause.OperationName}'"
                                    expectedType
                                    clause.Body)
                        | None ->
                            []

                    carrierDiagnostics @ returnDiagnostics @ operationDiagnostics

                let handledEffectRowDiagnostics =
                    match handledEffectSplit, handledBodyType with
                    | Some(declaration, effectRow, _, SplitMismatch), _ ->
                        [ makeSurfaceElaborationDiagnostic
                            (HandlerEffectRowMissingLabel(
                                declaration.VisibleName,
                                TypeSignatures.toText effectRow
                            )) ]
                    | Some(declaration, effectRow, _, SplitNeedsTailRefinement), _ ->
                        [ makeSurfaceElaborationDiagnostic
                            (HandlerEffectRowNeedsTailRefinement(
                                declaration.VisibleName,
                                TypeSignatures.toText effectRow
                            )) ]
                    | Some(_, _, _, SplitResolved _), _ ->
                        []
                    | None, Some handledType when tryUnwrapEffType handledType |> Option.isNone ->
                        [ makeSurfaceElaborationDiagnostic
                            (HandlerHandledExpressionMustBeEff(TypeSignatures.toText handledType)) ]
                    | _ ->
                        []

                let handlerDiagnostics =
                    match tryResolveHandledEffectDeclaration environment label with
                    | Some declaration ->
                        let declaredOperationNames =
                            declaration.Operations
                            |> List.map (fun operation -> operation.Name)
                            |> Set.ofList

                        let declaredOperationMap =
                            declaration.Operations
                            |> List.map (fun operation -> operation.Name, operation)
                            |> Map.ofList

                        let clauseGroups =
                            operationClauses
                            |> List.groupBy (fun clause -> clause.OperationName)

                        let missingDiagnostics =
                            declaration.Operations
                            |> List.choose (fun operation ->
                                if clauseGroups |> List.exists (fun (name, _) -> String.Equals(name, operation.Name, StringComparison.Ordinal)) then
                                    None
                                else
                                    Some(
                                        makeSurfaceElaborationDiagnostic
                                            (HandlerMissingOperationClause(
                                                declaration.VisibleName,
                                                operation.Name
                                            ))
                                    ))

                        let duplicateDiagnostics =
                            clauseGroups
                            |> List.collect (fun (operationName, clauses) ->
                                if List.length clauses > 1 then
                                    [ makeSurfaceElaborationDiagnostic
                                        (HandlerDuplicateOperationClause(
                                            declaration.VisibleName,
                                            operationName
                                        )) ]
                                else
                                    [])

                        let unexpectedDiagnostics =
                            clauseGroups
                            |> List.collect (fun (operationName, _) ->
                                if Set.contains operationName declaredOperationNames then
                                    []
                                else
                                    [ makeSurfaceElaborationDiagnostic
                                        (HandlerUnexpectedOperationClause(
                                            declaration.VisibleName,
                                            operationName
                                        )) ])

                        let resumptionDiagnostics =
                            operationClauses
                            |> List.collect (fun clause ->
                                match Map.tryFind clause.OperationName declaredOperationMap with
                                | Some operation ->
                                    let operationArity =
                                        operation.SignatureTokens
                                        |> TypeSignatures.parseType
                                        |> Option.map (qualifyVisibleTypeNames environment)
                                        |> Option.map TypeSignatures.functionParts
                                        |> Option.map (fun (parameterTypes, _) -> List.length parameterTypes)

                                    let arityDiagnostics =
                                        match operationArity with
                                        | Some expectedArity when expectedArity <> List.length clause.ArgumentTokens ->
                                            [ makeSurfaceElaborationDiagnostic
                                                (HandlerOperationClauseArityMismatch(
                                                    clause.OperationName,
                                                    List.length clause.ArgumentTokens,
                                                    expectedArity
                                                )) ]
                                        | _ ->
                                            []

                                    let resumptionUseDiagnostics =
                                        match operation.ResumptionQuantity, clause.ResumptionName with
                                        | Some QuantityZero, _
                                        | Some QuantityAtMostOne, _
                                        | None, _ ->
                                            []
                                        | Some _, Some resumptionName
                                            when not (expressionReferencesName resumptionName Set.empty clause.Body) ->
                                            [ makeSurfaceElaborationDiagnostic
                                                (HandlerRelevantResumptionUnused(
                                                    clause.OperationName,
                                                    resumptionName
                                                )) ]
                                        | Some _, _ ->
                                            []

                                    arityDiagnostics @ resumptionUseDiagnostics
                                | None ->
                                    [])

                        missingDiagnostics @ duplicateDiagnostics @ unexpectedDiagnostics @ resumptionDiagnostics
                    | _ ->
                        []

                recurse label
                @ recurse body
                @ validateExpressionWithFlow
                    (extendHandlerLocals returnClause.ArgumentTokens [ handledPayloadType ] None None locals)
                    refinements
                    returnClauseLexicalNames
                    aliases
                    staticAliases
                    constructorFacts
                    returnClause.Body
                @ (operationClauses
                   |> List.collect (fun clause ->
                       let clauseLexicalNames = Set.union lexicalNames (clauseBoundNames clause)
                       validateExpressionWithFlow
                           (tryOperationClauseLocals clause |> Option.defaultValue locals)
                           refinements
                           clauseLexicalNames
                           aliases
                           staticAliases
                           constructorFacts
                           clause.Body))
                @ handlerDiagnostics
                @ handlerClauseTypeDiagnostics
                @ handledEffectRowDiagnostics
            | Literal _ ->
                []
            | NumericLiteral _ ->
                []
            | KindQualifiedName(kind, nameSegments) ->
                match tryResolveScopedStaticObject environment expression with
                | Some _ ->
                    []
                | None ->
                    let kindText = kindSelectorText kind
                    let nameText = SyntaxFacts.moduleNameToText nameSegments

                    [
                        makeDiagnostic
                            SimpleDiagnosticKind.StaticObjectUnresolved
                            $"No {kindText} static object named '{nameText}' is visible."
                    ]
            | Name(root :: fieldName :: _) ->
                let receiverResolvesAsMemberCall =
                    (environment.VisibleBindings
                     |> Map.tryFind fieldName
                     |> Option.bind (fun bindingInfo -> tryBuildReceiverMethodArguments bindingInfo (Name [ root ]) [])
                     |> Option.isSome)
                    || (tryResolveTraitMemberProjection environment locals [ root; fieldName ] |> Option.isSome)
                    || ((tryPrepareVisibleTraitMemberCall
                            environment
                            (ref freshCounter.Value)
                            fieldName
                            (inferValidationExpressionType environment (ref freshCounter.Value) locals)
                            [ Name [ root ] ])
                        |> Option.isSome)

                let receiverHasStructuredProjectionTarget =
                    if receiverResolvesAsMemberCall then
                        true
                    else
                        match tryReceiverProjection environment locals root fieldName with
                        | Some _ ->
                            true
                        | None ->
                            match tryRecordInfoForRoot locals root with
                            | Some recordInfo ->
                                recordInfo.Fields
                                |> List.exists (fun (field: RecordSurfaceFieldInfo) -> String.Equals(field.Name, fieldName, StringComparison.Ordinal))
                            | None ->
                                possibleConstructorsForRoot aliases constructorFacts locals root
                                |> Option.isSome

                let missingFieldDiagnostics =
                    if receiverResolvesAsMemberCall then
                        []
                    else
                        match tryReceiverProjection environment locals root fieldName with
                        | Some _ ->
                            []
                        | None ->
                            match tryRecordInfoForRoot locals root with
                            | Some recordInfo
                                when recordInfo.Fields
                                     |> List.exists (fun (field: RecordSurfaceFieldInfo) -> String.Equals(field.Name, fieldName, StringComparison.Ordinal))
                                     |> not ->
                                [
                                    Diagnostics.errorFact
                                        "KFrontIR"
                                        (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                        None
                                        []
                                        (DiagnosticFact.surfaceElaboration (RecordProjectionFieldMissing fieldName))
                                ]
                            | _ ->
                                constructorProjectionDiagnostics aliases constructorFacts locals root fieldName
                let staticMemberDiagnostics =
                        match expression with
                        | Name segments ->
                            match List.rev segments with
                            | memberName :: receiverSegments when not (List.isEmpty receiverSegments) ->
                                staticConstructorIdentityDiagnostic locals (Name(List.rev receiverSegments)) memberName
                            | _ ->
                                []
                        | _ ->
                            []
                let unresolvedMemberDiagnostics =
                    let visibleRuntimeRoot =
                        environment.VisibleBindings.ContainsKey(root)
                        || environment.VisibleConstructors.ContainsKey(root)
                        || (topLevelDefinitionsByName |> Map.containsKey root)

                    let rootPreservesStaticObjectIdentity =
                        isTopLevelManifestStaticObjectRoot root
                        || (tryFindVisibleStaticGroup environment [ root ] |> Option.isSome)
                        || (tryResolveScopedStaticObject environment (Name [ root ]) |> Option.isSome)

                    if allowUnresolvedCallDiagnostics
                       && visibleRuntimeRoot
                       && not rootPreservesStaticObjectIdentity
                       && not receiverHasStructuredProjectionTarget
                       && List.isEmpty missingFieldDiagnostics
                       && List.isEmpty staticMemberDiagnostics then
                        [ makeNameUnresolvedDiagnostic fieldName ]
                    else
                        []
                let unresolvedRootDiagnostics =
                    if allowUnresolvedCallDiagnostics
                       && List.isEmpty missingFieldDiagnostics
                       && List.isEmpty staticMemberDiagnostics
                       && not (isVisibleQualifiedRootName locals lexicalNames root) then
                        if not (String.IsNullOrEmpty(root)) && Char.IsUpper(root[0]) then
                            [
                                Diagnostics.errorFact
                                    "KFrontIR"
                                    (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                    None
                                    []
                                    (DiagnosticFact.moduleQualifierUnresolved root)
                            ]
                        else
                            [ makeNameUnresolvedDiagnostic root ]
                    else
                        []

                let unresolvedQualifiedMemberDiagnostics =
                    let rootNamesRuntimeValue =
                        Map.containsKey root locals
                        || Set.contains root lexicalNames
                        || Set.contains root knownValueNames
                        || String.Equals(root, "this", StringComparison.Ordinal)
                        || isTopLevelManifestStaticObjectRoot root
                        || (tryResolveScopedStaticObject environment (Name [ root ]) |> Option.isSome)

                    if allowUnresolvedCallDiagnostics
                       && List.isEmpty missingFieldDiagnostics
                       && List.isEmpty staticMemberDiagnostics
                       && not rootNamesRuntimeValue
                       && isVisibleQualifiedRootName locals lexicalNames root
                       && not (qualifiedNamePreservesResolution (root :: fieldName :: [])) then
                        [ makeNameUnresolvedDiagnostic fieldName ]
                    else
                        []

                missingFieldDiagnostics
                @ staticMemberDiagnostics
                @ unresolvedMemberDiagnostics
                @ unresolvedRootDiagnostics
                @ unresolvedQualifiedMemberDiagnostics
            | Name [ name ]
                when allowUnresolvedCallDiagnostics
                     && not (Map.containsKey name locals)
                     && not (Set.contains name lexicalNames)
                     && not (Set.contains name knownTermLikeNames) ->
                match tryResolveScopedStaticObject environment expression with
                | Some _ ->
                    []
                | None ->
                    [ makeNameUnresolvedDiagnostic name ]
            | Name _ ->
                []
            | Comprehension comprehension ->
                recurseComprehension comprehension
            | LocalLet(binding, value, body) ->
                let value =
                    binding.TypeTokens
                    |> Option.map (fun typeTokens -> annotateLambdaWithTypeTokens typeTokens value)
                    |> Option.defaultValue value

                let aliasAwareEnvironment =
                    withVisibleStaticObjects environment (aliasesAsVisibleStaticObjects staticAliases)

                let declaredType =
                    binding.TypeTokens
                    |> Option.bind TypeSignatures.parseType
                    |> Option.map (qualifyVisibleTypeNames aliasAwareEnvironment)

                let valueLocals =
                    match binding.Pattern, declaredType, value with
                    | NamePattern bindingName, Some currentDeclaredType, Lambda _ ->
                        Map.add bindingName currentDeclaredType locals
                    | _ ->
                        locals

                let inferredValueType =
                    tryInferPureElabResultType valueLocals value
                    |> Option.orElseWith (fun () ->
                        inferValidationExpressionType aliasAwareEnvironment freshCounter valueLocals value)

                let valueType =
                    declaredType
                    |> Option.orElse inferredValueType

                let compareDeclaredAndInferredTypes
                    mismatchPrefix
                    currentDeclaredType
                    currentInferredType
                    =
                    let rec dropLeadingCompileTimeTypeBinders currentType =
                        match normalizeTypeAliases aliasAwareEnvironment.VisibleTypeAliases currentType with
                        | TypeLambda(_, parameterSort, body)
                            when isCompileTimeArgumentType aliasAwareEnvironment.VisibleTypeAliases parameterSort ->
                            dropLeadingCompileTimeTypeBinders body
                        | _ ->
                            currentType

                    let currentDeclaredType =
                        dropLeadingCompileTimeTypeBinders currentDeclaredType

                    let normalizedDeclaredType =
                        currentDeclaredType
                        |> qualifyVisibleTypeNames aliasAwareEnvironment
                        |> normalizeTypeAliases aliasAwareEnvironment.VisibleTypeAliases

                    let normalizedInferredType =
                        currentInferredType
                        |> qualifyVisibleTypeNames aliasAwareEnvironment
                        |> normalizeTypeAliases aliasAwareEnvironment.VisibleTypeAliases

                    match tryUnifyVisibleTypes aliasAwareEnvironment.VisibleTypeAliases [ currentDeclaredType, currentInferredType ] with
                    | Some _ ->
                        []
                    | None when TypeSignatures.definitionallyEqual normalizedDeclaredType normalizedInferredType ->
                        []
                    | None ->
                        [ makeDiagnostic
                              SimpleDiagnosticKind.TypeEqualityMismatch
                              $"{mismatchPrefix}: declared '{TypeSignatures.toText normalizedDeclaredType}' but inferred '{TypeSignatures.toText normalizedInferredType}'." ]

                let bindingTypeDiagnostics =
                    match declaredType, value, inferredValueType with
                    | Some currentDeclaredType, RecordLiteral _, Some currentInferredType ->
                        let recordInfo =
                            binding.TypeTokens
                            |> Option.bind tryParseRecordSurfaceInfo

                        let hasDependentFieldReferences =
                            recordInfo
                            |> Option.map (fun parsedRecordInfo ->
                                parsedRecordInfo.Fields
                                |> List.exists (fun field ->
                                    fieldTypeReferences parsedRecordInfo field.TypeTokens |> List.isEmpty |> not))
                            |> Option.defaultValue false

                        if hasDependentFieldReferences then
                            []
                        else
                            compareDeclaredAndInferredTypes
                                "Local binding value type mismatch"
                                currentDeclaredType
                                currentInferredType
                    | Some currentDeclaredType, Do statements, _ ->
                        match
                            tryUnwrapBindablePayloadType aliasAwareEnvironment.VisibleTypeAliases currentDeclaredType,
                            inferValidationDoResultType aliasAwareEnvironment freshCounter locals statements
                        with
                        | Some declaredPayloadType, Some actualDoResultType ->
                            let inferredPayloadType =
                                tryUnwrapBindablePayloadType aliasAwareEnvironment.VisibleTypeAliases actualDoResultType
                                |> Option.defaultValue actualDoResultType

                            compareDeclaredAndInferredTypes
                                "Local binding computation payload type mismatch"
                                declaredPayloadType
                                inferredPayloadType
                        | _ ->
                            []
                    | Some currentDeclaredType, _, Some currentInferredType ->
                        compareDeclaredAndInferredTypes
                            "Local binding value type mismatch"
                            currentDeclaredType
                            currentInferredType
                    | _ ->
                        []

                let nextLocals =
                    match valueType with
                    | Some valueType ->
                        extendBindingLocalTypes environment freshCounter locals binding (Some valueType)
                    | None ->
                        locals

                let rec rewriteNamedAliasUse aliasName targetName expression =
                    let rewrite = rewriteNamedAliasUse aliasName targetName

                    match expression with
                    | SyntaxQuote inner ->
                        SyntaxQuote(rewrite inner)
                    | SyntaxSplice inner ->
                        SyntaxSplice(rewrite inner)
                    | TopLevelSyntaxSplice inner ->
                        TopLevelSyntaxSplice(rewrite inner)
                    | TypeSyntaxTokens _ ->
                        expression
                    | CodeQuote inner ->
                        CodeQuote(rewrite inner)
                    | CodeSplice inner ->
                        CodeSplice(rewrite inner)
                    | Handle(isDeep, label, body, returnClause, operationClauses) ->
                        let rewriteClause (clause: SurfaceEffectHandlerClause) =
                            { clause with
                                Body = rewrite clause.Body }

                        Handle(
                            isDeep,
                            rewrite label,
                            rewrite body,
                            rewriteClause returnClause,
                            operationClauses |> List.map rewriteClause
                        )
                    | Apply(Name [ name ], arguments) when String.Equals(name, aliasName, StringComparison.Ordinal) ->
                        Apply(Name [ targetName ], arguments |> List.map rewrite)
                    | Apply(callee, arguments) ->
                        Apply(rewrite callee, arguments |> List.map rewrite)
                    | LocalLet(nestedBinding, nestedValue, nestedBody) ->
                        let shadowsAlias =
                            collectPatternNames nestedBinding.Pattern
                            |> List.exists (fun name -> String.Equals(name, aliasName, StringComparison.Ordinal))

                        LocalLet(
                            nestedBinding,
                            rewrite nestedValue,
                            if shadowsAlias then nestedBody else rewrite nestedBody
                        )
                    | LocalSignature(declaration, nestedBody) ->
                        if String.Equals(declaration.Name, aliasName, StringComparison.Ordinal) then
                            expression
                        else
                            LocalSignature(declaration, rewrite nestedBody)
                    | LocalTypeAlias(declaration, nestedBody) ->
                        LocalTypeAlias(declaration, rewrite nestedBody)
                    | LocalScopedEffect(declaration, nestedBody) ->
                        if String.Equals(declaration.Name, aliasName, StringComparison.Ordinal) then
                            expression
                        else
                            LocalScopedEffect(declaration, rewrite nestedBody)
                    | Lambda(parameters, nestedBody) ->
                        if parameters |> List.exists (fun parameter -> String.Equals(parameter.Name, aliasName, StringComparison.Ordinal)) then
                            expression
                        else
                            Lambda(parameters, rewrite nestedBody)
                    | IfThenElse(condition, whenTrue, whenFalse) ->
                        IfThenElse(rewrite condition, rewrite whenTrue, rewrite whenFalse)
                    | Match(scrutinee, cases) ->
                        Match(
                            rewrite scrutinee,
                            cases
                            |> List.map (fun caseClause ->
                                { caseClause with
                                    Guard = caseClause.Guard |> Option.map rewrite
                                    Body = rewrite caseClause.Body })
                        )
                    | RecordLiteral fields ->
                        RecordLiteral(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
                    | Seal(nestedValue, ascriptionTokens) ->
                        Seal(rewrite nestedValue, ascriptionTokens)
                    | RecordUpdate(receiver, fields) ->
                        RecordUpdate(rewrite receiver, fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
                    | MemberAccess(receiver, segments, arguments) ->
                        MemberAccess(rewrite receiver, segments, arguments |> List.map rewrite)
                    | SafeNavigation(receiver, navigation) ->
                        SafeNavigation(rewrite receiver, { navigation with Arguments = navigation.Arguments |> List.map rewrite })
                    | TagTest(receiver, constructorName) ->
                        TagTest(rewrite receiver, constructorName)
                    | Do statements ->
                        Do statements
                    | MonadicSplice inner ->
                        MonadicSplice(rewrite inner)
                    | ExplicitImplicitArgument inner ->
                        ExplicitImplicitArgument(rewrite inner)
                    | NamedApplicationBlock fields ->
                        NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
                    | InoutArgument inner ->
                        InoutArgument(rewrite inner)
                    | Unary(operatorName, inner) ->
                        Unary(operatorName, rewrite inner)
                    | Binary(left, operatorName, right) ->
                        Binary(rewrite left, operatorName, rewrite right)
                    | Elvis(left, right) ->
                        Elvis(rewrite left, rewrite right)
                    | Comprehension comprehension ->
                        Comprehension { comprehension with Lowered = rewrite comprehension.Lowered }
                    | PrefixedString(prefix, parts) ->
                        PrefixedString(
                            prefix,
                            parts
                            |> List.map (function
                                | StringText text -> StringText text
                                | StringInterpolation(inner, format) -> StringInterpolation(rewrite inner, format))
                        )
                    | Literal _
                    | NumericLiteral _
                    | KindQualifiedName _
                    | Name _ ->
                        expression

                let bodyForValidation =
                    match binding.Pattern, value with
                    | NamePattern aliasName, Name [ targetName ]
                        when (environment.VisibleBindings
                              |> Map.tryFind targetName
                              |> Option.orElseWith (fun () -> environment.VisibleConstructors |> Map.tryFind targetName))
                             |> Option.bind (fun bindingInfo -> bindingInfo.ParameterLayouts)
                             |> Option.isSome ->
                        rewriteNamedAliasUse aliasName targetName body
                    | NamePattern aliasName, Lambda(parameters, _) ->
                        rewriteNamedApplicationAliasUse aliasName parameters body
                    | _ ->
                        body

                let localStaticAliases = collectScopedPatternStaticAliases aliasAwareEnvironment binding.Pattern value
                let bodyForValidation = rewriteStaticObjectPathAliasUses localStaticAliases bodyForValidation
                let localEffectOperationAliases = collectScopedPatternEffectOperationAliases environment binding.Pattern value
                let bodyForValidation = rewriteEffectOperationPathAliasUses environment localEffectOperationAliases bodyForValidation

                let nextStaticAliases =
                    let shadowedNames = collectPatternNames binding.Pattern
                    let inheritedAliases = removeShadowedStaticAliases staticAliases shadowedNames

                    localStaticAliases
                    |> Map.fold (fun state segments staticObject -> Map.add segments staticObject state) inheritedAliases

                let nextLexicalNames =
                    collectPatternNames binding.Pattern
                    |> Set.ofList
                    |> Set.union lexicalNames

                let nextAliases =
                    extendStableAliases aliases binding value

                let visibleBindingSiteNames =
                    lexicalNames
                    |> Set.union parameterNames
                    |> Set.union (locals |> Map.keys |> Set.ofSeq)

                validateExpressionWithFlow valueLocals refinements lexicalNames aliases staticAliases constructorFacts value
                @ bindingTypeDiagnostics
                @ (valueType
                   |> Option.map (fun inferredType -> syntaxCarrierEscapeDiagnostics visibleBindingSiteNames inferredType value)
                   |> Option.defaultValue [])
                @ validateExpressionWithFlow nextLocals refinements nextLexicalNames nextAliases nextStaticAliases constructorFacts bodyForValidation
            | LocalSignature(declaration, LocalLet(binding, value, body))
                when binding.Pattern = NamePattern declaration.Name && binding.TypeTokens.IsNone ->
                let typedBinding =
                    { binding with
                        TypeTokens = Some declaration.TypeTokens }

                validateExpressionWithFlow
                    locals
                    refinements
                    lexicalNames
                    aliases
                    staticAliases
                    constructorFacts
                    (LocalLet(typedBinding, value, body))
            | LocalSignature(declaration, body) ->
                let nextLocals =
                    declaration.TypeTokens
                    |> TypeSignatures.parseType
                    |> Option.map (fun declarationType -> Map.add declaration.Name declarationType locals)
                    |> Option.defaultValue locals

                validateExpressionWithFlow
                    nextLocals
                    refinements
                    (Set.add declaration.Name lexicalNames)
                    (Map.remove declaration.Name aliases)
                    (removeShadowedStaticAliases staticAliases [ declaration.Name ])
                    constructorFacts
                    body
            | LocalTypeAlias(declaration, body) ->
                validateExpressionWithFlow
                    locals
                    refinements
                    (Set.add declaration.Name lexicalNames)
                    (Map.remove declaration.Name aliases)
                    staticAliases
                    constructorFacts
                    (rewriteLocalTypeAliasesInSurfaceExpression environment.CurrentModuleIdentity environment.VisibleTypeAliases expression)
            | LocalScopedEffect(declaration, body) ->
                borrowedEffectResumptionQuantityDiagnostics makeDiagnostic declaration
                @ withScopedEffectDeclaration environment.CurrentModuleIdentity declaration (fun () ->
                    validateExpressionWithFlow
                        locals
                        refinements
                        (Set.add declaration.Name lexicalNames)
                        (Map.remove declaration.Name aliases)
                        (removeShadowedStaticAliases staticAliases [ declaration.Name ])
                        constructorFacts
                        body)
            | Lambda(parameters, body) ->
                let nextLocals =
                    parameters
                    |> List.fold (fun state parameter ->
                        let parameterType =
                            tryParseParameterType parameter
                            |> Option.map (qualifyVisibleTypeNames environment)
                            |> Option.defaultValue (TypeVariable $"lambda{freshCounter.Value}")

                        Map.add parameter.Name parameterType state) locals

                let nextLexicalNames =
                    parameters
                    |> List.map (fun parameter -> parameter.Name)
                    |> Set.ofList
                    |> Set.union lexicalNames

                validateExpressionWithFlow
                    nextLocals
                    refinements
                    nextLexicalNames
                    (removeShadowedAliases aliases (parameters |> List.map (fun parameter -> parameter.Name)))
                    (removeShadowedStaticAliases staticAliases (parameters |> List.map (fun parameter -> parameter.Name)))
                    constructorFacts
                    body
            | IfThenElse(condition, whenTrue, whenFalse) ->
                let trueRefinements, falseRefinements =
                    match condition with
                    | Name [ conditionName ] when locals |> Map.containsKey conditionName ->
                        Map.add conditionName trueTermType refinements,
                        Map.add conditionName falseTermType refinements
                    | Unary("not", Name [ conditionName ]) when locals |> Map.containsKey conditionName ->
                        Map.add conditionName falseTermType refinements,
                        Map.add conditionName trueTermType refinements
                    | _ ->
                        refinements, refinements

                let trueConstructorFacts, falseConstructorFacts =
                    conditionConstructorFacts aliases constructorFacts condition

                recurse condition
                @ (trueConstructorFacts
                   |> List.collect (fun branchFacts ->
                       validateExpressionWithFlow locals trueRefinements lexicalNames aliases staticAliases branchFacts whenTrue))
                @ (falseConstructorFacts
                   |> List.collect (fun branchFacts ->
                       validateExpressionWithFlow locals falseRefinements lexicalNames aliases staticAliases branchFacts whenFalse))
            | Match(scrutinee, cases) ->
                let scrutineeType =
                    inferValidationExpressionType environment freshCounter locals scrutinee

                let scrutineeRoot =
                    match scrutinee with
                    | Name [ root ] -> Some root
                    | _ -> None

                let rec validateCases residualFacts (remainingCases: SurfaceMatchCase list) =
                    match remainingCases with
                    | [] ->
                        []
                    | caseClause :: restCases ->
                        let caseLocals =
                            extendPatternLocalTypes environment freshCounter locals scrutineeType caseClause.Pattern

                        let caseLexicalNames =
                            collectPatternNames caseClause.Pattern
                            |> Set.ofList
                            |> Set.union lexicalNames

                        let caseAliases =
                            removeShadowedAliases aliases (collectPatternNames caseClause.Pattern)

                        let caseStaticAliases =
                            removeShadowedStaticAliases staticAliases (collectPatternNames caseClause.Pattern)

                        let caseFacts =
                            match scrutineeRoot, tryTopLevelSurfaceConstructorPatternName caseClause.Pattern with
                            | Some root, Some constructorName ->
                                addPositiveConstructorFact aliases residualFacts root constructorName
                            | _ ->
                                residualFacts

                        let bodyFactSets =
                            match caseClause.Guard with
                            | Some guard ->
                                conditionConstructorFacts caseAliases caseFacts guard |> fst
                            | None ->
                                [ caseFacts ]

                        let caseDiagnostics =
                            validatePatternHead caseClause.Pattern
                            @ staticPatternIdentityDiagnostics locals caseClause.Pattern
                            @ activePatternLinearityDiagnostics caseClause.Pattern "match case"
                            @ (caseClause.Guard
                               |> Option.map (validateExpressionWithFlow caseLocals refinements caseLexicalNames caseAliases caseStaticAliases caseFacts)
                               |> Option.defaultValue [])
                            @ (bodyFactSets
                               |> List.collect (fun bodyFacts ->
                                   validateExpressionWithFlow caseLocals refinements caseLexicalNames caseAliases caseStaticAliases bodyFacts caseClause.Body))

                        let nextResidualFacts =
                            match scrutineeRoot, tryTopLevelSurfaceConstructorPatternName caseClause.Pattern, caseClause.Guard with
                            | Some root, Some constructorName, None ->
                                addNegativeConstructorFact aliases residualFacts root constructorName
                            | _ ->
                                residualFacts

                        caseDiagnostics @ validateCases nextResidualFacts restCases

                recurse scrutinee @ validateCases constructorFacts cases
            | RecordLiteral fields ->
                validateRecordLiteral fields @ (fields |> List.collect (fun field -> recurse field.Value))
            | Seal(RecordLiteral fields, ascriptionTokens) ->
                let nestedDiagnostics =
                    match tryParseRecordSurfaceInfo ascriptionTokens with
                    | Some recordInfo ->
                        validateRecordLiteralFieldValuesWithRecordInfo recurse recordInfo fields
                    | None ->
                        fields |> List.collect (fun field -> recurse field.Value)

                validateRecordLiteral fields @ nestedDiagnostics
            | Seal(value, _) ->
                recurse value
            | RecordUpdate(receiver, fields) ->
                let fieldExpectedDiagnostics =
                    match tryRecordInfoForExpression locals receiver with
                    | Some recordInfo ->
                        fields
                        |> List.collect (fun field ->
                            match field.Path with
                            | [ pathSegment ] ->
                                recordInfo.Fields
                                |> List.tryFind (fun recordField ->
                                    String.Equals(recordField.Name, pathSegment.Name, StringComparison.Ordinal))
                                |> Option.bind (fun recordField ->
                                    recordField.TypeTokens |> TypeSignatures.parseType)
                                |> Option.filter (fun expectedType ->
                                    typeContainsSuspension expectedType || typeContainsUnion expectedType)
                                |> Option.map (fun expectedType ->
                                    expectedTypeDiagnostics
                                        locals
                                        refinements
                                        $"Record update field '{field.Name}'"
                                        expectedType
                                        field.Value)
                                |> Option.defaultValue []
                            | _ ->
                                [])
                    | None ->
                        []

                recurse receiver
                @ (fields |> List.collect (fun field -> recurse field.Value))
                @ validateRecordPatch locals receiver fields
                @ fieldExpectedDiagnostics
            | MemberAccess(receiver, segments, arguments) ->
                let memberDiagnostics =
                    match segments with
                    | [ memberName ] ->
                        let receiverStaticDiagnostics =
                            staticConstructorIdentityDiagnostic locals receiver memberName

                        let receiverMethodDiagnostics =
                            match environment.VisibleBindings |> Map.tryFind memberName |> Option.bind (fun info -> info.ParameterLayouts) with
                            | Some layouts ->
                                let receiverParameters =
                                    layouts
                                    |> List.filter (fun layout -> layout.IsReceiver)

                                let precedingExplicitCount =
                                    layouts
                                    |> List.takeWhile (fun layout -> not layout.IsReceiver)
                                    |> List.filter (fun layout -> not layout.IsImplicit)
                                    |> List.length

                                let requiredExplicitArgumentCount =
                                    layouts
                                    |> List.filter (fun layout -> not layout.IsImplicit)
                                    |> List.length
                                    |> fun count -> max 0 (count - 1)

                                if List.length receiverParameters <> 1 then
                                    [ makeSurfaceElaborationDiagnostic
                                        (MemberCallRequiresExactlyOneReceiverBinder memberName) ]
                                elif List.length arguments < precedingExplicitCount then
                                    [ makeSurfaceElaborationDiagnostic
                                        (MemberCallMissingPrecedingExplicitArguments memberName) ]
                                elif List.length arguments < requiredExplicitArgumentCount then
                                    [ makeSurfaceElaborationDiagnostic
                                        (MemberCallMissingExplicitArguments memberName) ]
                                else
                                    []
                            | _ ->
                                []

                        let receiverProjectionDiagnostics =
                            match receiver, arguments with
                            | Name [ root ], [] ->
                                constructorProjectionDiagnostics aliases constructorFacts locals root memberName
                            | _ ->
                                []

                        let unresolvedMemberDiagnostics =
                            match inferValidationExpressionType environment freshCounter locals expression with
                            | Some _ ->
                                []
                            | None when not (List.isEmpty (receiverStaticDiagnostics @ receiverMethodDiagnostics @ receiverProjectionDiagnostics)) ->
                                []
                            | None when tryResolveScopedStaticObject environment receiver |> Option.isSome ->
                                []
                            | None ->
                                match inferValidationExpressionType environment freshCounter locals receiver with
                                | Some receiverType when not (Set.contains memberName knownValueNames) ->
                                    [ makeNameUnresolvedDiagnostic memberName ]
                                | Some receiverType ->
                                    [ makeSurfaceElaborationDiagnostic
                                        (MemberAccessNotWellFormedForReceiverType(
                                            memberName,
                                            TypeSignatures.toText receiverType
                                        )) ]
                                | None ->
                                    []

                        receiverStaticDiagnostics @ receiverMethodDiagnostics @ receiverProjectionDiagnostics @ unresolvedMemberDiagnostics
                    | _ ->
                        []

                recurse receiver @ (arguments |> List.collect recurse) @ memberDiagnostics
            | SafeNavigation(receiver, navigation) ->
                let receiverDiagnostics = recurse receiver
                let argumentDiagnostics = navigation.Arguments |> List.collect recurse

                let builtinDiagnostics =
                    match inferValidationExpressionType environment freshCounter locals receiver with
                    | Some receiverType ->
                        match tryOptionPayloadType environment.VisibleTypeAliases receiverType with
                        | Some payloadType ->
                            match
                                tryInferSafeNavigationMemberType
                                    environment.VisibleTypeAliases
                                    (qualifyVisibleTypeNames environment)
                                    (inferValidationExpressionType environment freshCounter locals)
                                    payloadType
                                    navigation
                            with
                            | Some _ ->
                                []
                            | None ->
                                [ makeSurfaceElaborationDiagnostic
                                    (SafeNavigationRequiresKnownResultType(memberText navigation)) ]
                        | None ->
                            [ makeSurfaceElaborationDiagnostic SafeNavigationReceiverMustBeOption ]
                    | None ->
                        [ makeSurfaceElaborationDiagnostic
                            (SafeNavigationRequiresKnownResultType(memberText navigation)) ]

                receiverDiagnostics @ argumentDiagnostics @ builtinDiagnostics
            | TagTest(receiver, _) ->
                recurse receiver
            | Do statements ->
                validateDoStatementsWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts statements
            | MonadicSplice inner
            | InoutArgument inner
            | Unary(_, inner) ->
                recurse inner
            | ExplicitImplicitArgument inner ->
                match tryParseTypeLikeSurfaceExpression inner with
                | Some _ ->
                    []
                | None ->
                    recurse inner
            | NamedApplicationBlock fields ->
                fields |> List.collect (fun field -> recurse field.Value)
            | Apply _ as application ->
                let rec collectApplicationSpine currentExpression collectedArguments =
                    match currentExpression with
                    | Apply(calleeExpression, currentArguments) ->
                        collectApplicationSpine calleeExpression (currentArguments @ collectedArguments)
                    | _ ->
                        currentExpression, collectedArguments

                let isConstructorHeadedApplication currentExpression =
                    match collectApplicationSpine currentExpression [] with
                    | Name [ calleeName ], _ -> environment.VisibleConstructors.ContainsKey(calleeName)
                    | _ -> false

                match tryMatchQueryCarrierShape application with
                | Some carrier ->
                    let metadataDiagnostics =
                        match carrier.Comprehension.CollectionKind with
                        | ListCollection ->
                            []
                        | MapCollection ->
                            [ makeSurfaceElaborationDiagnostic QueryCarrierCannotDiscardMapMetadata ]
                        | SetCollection ->
                            [ makeSurfaceElaborationDiagnostic QueryCarrierCannotDiscardSetMetadata ]

                    let compatibilityDiagnostics =
                        match
                            tryInferComprehensionPlanShape
                                environment
                                freshCounter
                                locals
                                (fun currentLocals currentExpression ->
                                    inferValidationExpressionType environment freshCounter currentLocals currentExpression)
                                carrier.Comprehension
                        with
                        | Some plan when not (QuerySemantics.canCheckUse plan.InferredMode.Use carrier.ExpectedMode.Use) ->
                            [ makeSurfaceElaborationDiagnostic
                                (QueryCarrierUseMismatch(
                                    queryUseText carrier.ExpectedMode.Use,
                                    queryUseText plan.InferredMode.Use
                                )) ]
                        | Some plan when not (QuerySemantics.canCheckCard plan.InferredMode.Card carrier.ExpectedMode.Card) ->
                            [ makeSurfaceElaborationDiagnostic
                                (QueryCarrierCardinalityMismatch(
                                    queryCardText plan.InferredMode.Card,
                                    queryCardText carrier.ExpectedMode.Card
                                )) ]
                        | Some plan when not (QuerySemantics.canCheckItemQuantity plan.InferredItemQuantity carrier.ExpectedItemQuantity) ->
                            [ makeSurfaceElaborationDiagnostic
                                (QueryCarrierItemQuantityMismatch(
                                    ResourceQuantity.toSurfaceText plan.InferredItemQuantity,
                                    ResourceQuantity.toSurfaceText carrier.ExpectedItemQuantity
                                )) ]
                        | _ ->
                            []

                    recurseComprehension carrier.Comprehension @ metadataDiagnostics @ compatibilityDiagnostics
                | None ->
                    match application with
                    | Apply(callee, arguments) ->
                        let isConstructorSpine = isConstructorHeadedApplication application
                        let comprehensionSinkDiagnostics =
                            match arguments with
                            | [ Comprehension comprehension ] ->
                                let sinkType =
                                    inferValidationExpressionType environment freshCounter locals application
                                    |> Option.orElseWith (fun () ->
                                        match definition.Body, scheme with
                                        | Some bodyExpression, Some bindingScheme when bodyExpression = application ->
                                            Some(bindingScheme |> TypeSignatures.schemeParts |> snd)
                                        | _ ->
                                            None)

                                sinkType
                                |> Option.bind (fun sinkType ->
                                    tryResolveTraitConstraint sinkType "FromComprehensionRaw"
                                    |> Option.orElseWith (fun () -> tryResolveTraitConstraint sinkType "FromComprehensionPlan"))
                                |> Option.bind (fun (instanceInfo, substitution) ->
                                    tryParseInstanceAssociatedType substitution instanceInfo "Item"
                                    |> Option.bind (fun expectedItemType ->
                                        tryInferComprehensionPlanShape
                                            environment
                                            freshCounter
                                            locals
                                            (fun currentLocals currentExpression ->
                                                inferValidationExpressionType environment freshCounter currentLocals currentExpression)
                                            comprehension
                                        |> Option.map (fun plan -> expectedItemType, plan.InferredItemType)))
                                |> Option.map (fun (expectedItemType, actualItemType) ->
                                    if comprehensionSinkItemTypesEqual expectedItemType actualItemType then
                                        []
                                    else
                                        [ makeSurfaceElaborationDiagnostic
                                            (ComprehensionSinkItemTypeMismatch(
                                                TypeSignatures.toText expectedItemType,
                                                TypeSignatures.toText actualItemType
                                            )) ])
                                |> Option.defaultValue []
                            | _ ->
                                []

                        let hasNamedBlock =
                            arguments
                            |> List.exists (function
                                | NamedApplicationBlock _ -> true
                                | _ -> false)

                        let hasExplicitImplicitArgument =
                            arguments
                            |> List.exists (function
                                | ExplicitImplicitArgument _ -> true
                                | _ -> false)

                        let validateCompileTimeArgument argument =
                            match tryParseTypeLikeSurfaceExpression argument with
                            | Some _ ->
                                []
                            | None ->
                                recurse argument

                        let validateArgumentsAgainstAlignedLayouts
                            (parameterLayouts: Parameter list)
                            (parameterTypes: TypeExpr list)
                            pendingArguments
                            =
                            let parameterConsumesCompileTimeArgument (layout: Parameter) (parameterType: TypeExpr) =
                                match tryParseParameterType layout with
                                | Some declaredParameterType ->
                                    isCompileTimeArgumentType environment.VisibleTypeAliases declaredParameterType
                                | None ->
                                    isCompileTimeArgumentType environment.VisibleTypeAliases parameterType

                            let rec walk (layouts: Parameter list) (types: TypeExpr list) remainingArguments =
                                match layouts, types, remainingArguments with
                                | [], _, remaining
                                | _, [], remaining ->
                                    remaining |> List.collect recurse
                                | layout :: restLayouts, parameterType :: restTypes, ExplicitImplicitArgument explicitArgument :: restArguments ->
                                    let consumesCompileTimeArgument =
                                        parameterConsumesCompileTimeArgument layout parameterType

                                    if consumesCompileTimeArgument then
                                        validateCompileTimeArgument explicitArgument
                                        @ walk restLayouts restTypes restArguments
                                    else
                                        recurse explicitArgument @ walk restLayouts restTypes restArguments
                                | layout :: restLayouts, parameterType :: restTypes, nextArgument :: restArguments when layout.IsImplicit ->
                                    if parameterConsumesCompileTimeArgument layout parameterType
                                       && (tryParseTypeLikeSurfaceExpression nextArgument |> Option.isSome) then
                                        validateCompileTimeArgument nextArgument
                                        @ walk restLayouts restTypes restArguments
                                    else
                                        walk restLayouts restTypes (nextArgument :: restArguments)
                                | layout :: restLayouts, parameterType :: restTypes, nextArgument :: restArguments ->
                                    let currentDiagnostics =
                                        if parameterConsumesCompileTimeArgument layout parameterType then
                                            validateCompileTimeArgument nextArgument
                                        else
                                            recurse nextArgument

                                    currentDiagnostics @ walk restLayouts restTypes restArguments
                                | _ :: restLayouts, _ :: restTypes, [] ->
                                    walk restLayouts restTypes []

                            walk parameterLayouts parameterTypes pendingArguments

                        let rec consumeLeadingCompileTimeArguments
                            (remainingForall: TypeSignatures.ForallBinder list)
                            (remainingArguments: SurfaceExpression list)
                            =
                            match remainingForall, remainingArguments with
                            | _ :: restForall, ExplicitImplicitArgument explicitArgument :: restArguments ->
                                let currentDiagnostics = validateCompileTimeArgument explicitArgument
                                let remainingDiagnostics, finalArguments =
                                    consumeLeadingCompileTimeArguments restForall restArguments

                                currentDiagnostics @ remainingDiagnostics, finalArguments
                            | _ ->
                                [], remainingArguments

                        let argumentDiagnosticsForBindingInfo (bindingInfo: BindingSchemeInfo) =
                            let preserveOrdinaryConstructorApplication =
                                bindingInfo.ConstructorTypeName.IsSome
                                || environment.VisibleConstructors.ContainsKey(bindingInfo.Name)

                            if preserveOrdinaryConstructorApplication then
                                let _, constructorArguments = collectApplicationSpine application []
                                constructorArguments |> List.collect recurse
                            else
                                match bindingInfo.ParameterLayouts with
                                | Some parameterLayouts ->
                                    let instantiated = TypeSignatures.instantiate "v" freshCounter.Value bindingInfo.Scheme
                                    let explicitTypeArgumentDiagnostics, alignedArguments =
                                        consumeLeadingCompileTimeArguments instantiated.Forall arguments

                                    let schemeParameterTypes, _ = TypeSignatures.schemeParts instantiated
                                    let layoutTypeSubstitution = forallInstantiationSubstitution bindingInfo.Scheme instantiated

                                    match
                                        tryAlignParameterTypesWithLayouts
                                            environment
                                            layoutTypeSubstitution
                                            parameterLayouts
                                            schemeParameterTypes
                                    with
                                    | Some(alignedParameterTypes, []) ->
                                        explicitTypeArgumentDiagnostics
                                        @ validateArgumentsAgainstAlignedLayouts parameterLayouts alignedParameterTypes alignedArguments
                                    | Some _
                                    | None ->
                                        explicitTypeArgumentDiagnostics @ (alignedArguments |> List.collect recurse)
                                | None ->
                                    arguments |> List.collect recurse

                        let argumentDiagnosticsForLocalBindingType calleeType =
                            let parameterTypes, _ = TypeSignatures.functionParts calleeType
                            let pairedArguments =
                                List.zip
                                    (arguments |> List.truncate parameterTypes.Length)
                                    (parameterTypes |> List.truncate arguments.Length)

                            let pairedDiagnostics =
                                pairedArguments
                                |> List.collect (fun (argument, parameterType) ->
                                    if isCompileTimeArgumentType environment.VisibleTypeAliases parameterType then
                                        validateCompileTimeArgument argument
                                    else
                                        recurse argument)

                            let remainingDiagnostics =
                                arguments
                                |> List.skip (min arguments.Length parameterTypes.Length)
                                |> List.collect recurse

                            pairedDiagnostics @ remainingDiagnostics

                        let argumentDiagnostics =
                            if isConstructorSpine then
                                let _, constructorArguments = collectApplicationSpine application []
                                constructorArguments |> List.collect recurse
                            else
                                match callee with
                                | Name [ calleeName ] ->
                                    let isLexicallyBoundName =
                                        Map.containsKey calleeName locals || Set.contains calleeName lexicalNames

                                    let localBindingType = Map.tryFind calleeName locals

                                    let siblingDefinitionShadowsVisibleBinding =
                                        topLevelDefinitionWithoutCurrentModuleSchemeShadowsVisibleBinding
                                            environment
                                            topLevelDefinitionsByName
                                            locals
                                            calleeName

                                    let currentModuleShadowsVisibleBinding =
                                        ordinarySurfaceNameShadowsVisiblePreludeBinding environment locals calleeName
                                        || siblingDefinitionShadowsVisibleBinding

                                    let bindingInfo =
                                        if isLexicallyBoundName || currentModuleShadowsVisibleBinding then
                                            None
                                        else
                                            environment.VisibleConstructors
                                            |> Map.tryFind calleeName
                                            |> Option.orElseWith (fun () -> environment.VisibleBindings |> Map.tryFind calleeName)

                                    match bindingInfo, localBindingType with
                                    | Some bindingInfo, _ ->
                                        argumentDiagnosticsForBindingInfo bindingInfo
                                    | None, Some localType ->
                                        argumentDiagnosticsForLocalBindingType localType
                                    | None, None
                                        when allowUnresolvedCallDiagnostics
                                             && not (Set.contains calleeName knownSurfaceTermNames)
                                             && not (Set.contains calleeName knownValueNames)
                                             && not (environment.VisibleProjections.ContainsKey(calleeName))
                                             && not (environment.ConstrainedMembers.ContainsKey(calleeName))
                                             && (tryResolveScopedStaticObject environment (Name [ calleeName ]) |> Option.isNone) ->
                                        []
                                    | _ ->
                                        arguments |> List.collect recurse
                                | _ ->
                                    let argumentDiagnostics =
                                        match inferValidationExpressionType environment (ref freshCounter.Value) locals callee with
                                        | Some calleeType ->
                                            argumentDiagnosticsForLocalBindingType calleeType
                                        | None ->
                                            arguments |> List.collect recurse

                                    recurse callee @ argumentDiagnostics

                        let runtimeRelevantParameterLayouts (bindingInfo: BindingSchemeInfo) =
                            bindingInfo.ParameterLayouts
                            |> Option.map (List.filter (fun layout ->
                                match tryParseParameterType layout with
                                | Some parameterType ->
                                    not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType)
                                | None ->
                                    true))

                        let localCanSatisfyImplicitParameter (bindingInfo: BindingSchemeInfo) =
                            match runtimeRelevantParameterLayouts bindingInfo with
                            | Some layouts when layouts |> List.exists (fun parameter -> parameter.IsImplicit) ->
                                let parameterTypes, _ = TypeSignatures.schemeParts bindingInfo.Scheme

                                if List.length layouts = List.length parameterTypes then
                                    List.zip layouts parameterTypes
                                    |> List.exists (fun (layout, parameterType) ->
                                        layout.IsImplicit
                                        && not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType)
                                        && (match classifyLocalImplicitByType environment locals parameterType with
                                            | UniqueLocalImplicitCandidate _ -> true
                                            | NoLocalImplicitCandidate
                                            | AmbiguousLocalImplicitCandidates -> false))
                                else
                                    false
                            | _ ->
                                false

                        let hasAmbiguousLocalImplicitParameter (bindingInfo: BindingSchemeInfo) =
                            match runtimeRelevantParameterLayouts bindingInfo with
                            | Some layouts when layouts |> List.exists (fun parameter -> parameter.IsImplicit) ->
                                let parameterTypes, _ = TypeSignatures.schemeParts bindingInfo.Scheme

                                if List.length layouts = List.length parameterTypes then
                                    List.zip layouts parameterTypes
                                    |> List.exists (fun (layout, parameterType) ->
                                        layout.IsImplicit
                                        && not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType)
                                        && (match classifyLocalImplicitByType environment locals parameterType with
                                            | AmbiguousLocalImplicitCandidates -> true
                                            | NoLocalImplicitCandidate
                                            | UniqueLocalImplicitCandidate _ -> false))
                                else
                                    false
                            | _ ->
                                false

                        let hasUnsatisfiedRuntimeImplicit (bindingInfo: BindingSchemeInfo) =
                            let preserveOrdinaryConstructorApplication =
                                bindingInfo.ConstructorTypeName.IsSome
                                || environment.VisibleConstructors.ContainsKey(bindingInfo.Name)

                            if preserveOrdinaryConstructorApplication then
                                false
                            else
                                match bindingInfo.ParameterLayouts with
                                | Some layouts ->
                                    let parameterTypes, _ = TypeSignatures.schemeParts bindingInfo.Scheme
                                    let isTraitConstraintType parameterType =
                                        tryTraitConstraintFromType environment parameterType |> Option.isSome

                                    List.length layouts = List.length parameterTypes
                                    && (List.zip layouts parameterTypes
                                        |> List.exists (fun (layout, parameterType) ->
                                            layout.IsImplicit
                                            && not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType)
                                            && not (isTraitConstraintType parameterType)
                                            && (match classifyLocalImplicitByType environment locals parameterType with
                                                | NoLocalImplicitCandidate -> true
                                                | UniqueLocalImplicitCandidate _
                                                | AmbiguousLocalImplicitCandidates -> false)))
                                | None ->
                                    false

                        let schemeOnlyImplicitTraitConstraintDiagnostics (bindingInfo: BindingSchemeInfo) =
                            let hasApplicationOnlyArgument =
                                arguments
                                |> List.exists (function
                                    | ExplicitImplicitArgument _
                                    | NamedApplicationBlock _ -> true
                                    | _ -> false)

                            if hasApplicationOnlyArgument then
                                []
                            else
                                let instantiated = TypeSignatures.instantiate "v" freshCounter.Value bindingInfo.Scheme
                                let argumentTypes =
                                    arguments
                                    |> List.map (fun argument ->
                                        inferValidationExpressionType environment freshCounter locals argument
                                        |> Option.orElseWith (fun () ->
                                            tryInferExpressionTypeWithSiblingFallback Set.empty locals argument))

                                if argumentTypes |> List.exists Option.isNone then
                                    []
                                else
                                    let explicitArgumentTypes = argumentTypes |> List.choose id
                                    let schemeParameterTypes, _ = TypeSignatures.schemeParts instantiated
                                    let maxLeadingImplicitCount = List.length schemeParameterTypes - List.length explicitArgumentTypes

                                    if maxLeadingImplicitCount < 0 then
                                        []
                                    else
                                        let tryCandidate leadingImplicitCount =
                                            let leadingImplicitTypes =
                                                schemeParameterTypes |> List.take leadingImplicitCount

                                            let remainingParameterTypes =
                                                schemeParameterTypes |> List.skip leadingImplicitCount

                                            let explicitParameterTypes =
                                                remainingParameterTypes |> List.truncate explicitArgumentTypes.Length

                                            if List.length explicitParameterTypes <> List.length explicitArgumentTypes then
                                                None
                                            else
                                                tryUnifyVisibleTypes
                                                    environment.VisibleTypeAliases
                                                    (List.zip explicitParameterTypes explicitArgumentTypes)
                                                |> Option.map (fun explicitSubstitution ->
                                                    leadingImplicitTypes
                                                    |> List.map (TypeSignatures.applySubstitution explicitSubstitution)
                                                    |> List.choose (fun parameterType ->
                                                        if isCompileTimeArgumentType environment.VisibleTypeAliases parameterType then
                                                            None
                                                        else
                                                            match classifyLocalImplicitByType environment locals parameterType with
                                                            | UniqueLocalImplicitCandidate _ ->
                                                                None
                                                            | NoLocalImplicitCandidate
                                                            | AmbiguousLocalImplicitCandidates ->
                                                                match tryTraitConstraintFromType environment parameterType with
                                                                | Some constraintInfo when constraintHasLocalDictionary environment constraintInfo ->
                                                                    None
                                                                | Some constraintInfo ->
                                                                    match resolveConstraintInstanceDetailedWithSubstitution environment constraintInfo with
                                                                    | ConstraintResolved _ ->
                                                                        None
                                                                    | ConstraintUnresolved ->
                                                                        Some(makeImplicitTraitConstraintUnresolvedDiagnostic constraintInfo)
                                                                    | ConstraintAmbiguous(ambiguousGoal, candidates) ->
                                                                        Some(
                                                                            makeTraitConstraintAmbiguousDiagnostic
                                                                                ambiguousGoal
                                                                                candidates
                                                                        )
                                                                | None ->
                                                                    None))

                                        [ maxLeadingImplicitCount .. -1 .. 0 ]
                                        |> List.tryPick (fun leadingImplicitCount ->
                                            tryCandidate leadingImplicitCount
                                            |> Option.filter (List.isEmpty >> not))
                                        |> Option.defaultValue []

                        let leadingImplicitTraitConstraintDiagnostics (bindingInfo: BindingSchemeInfo) =
                            let hasApplicationOnlyArgument =
                                arguments
                                |> List.exists (function
                                    | ExplicitImplicitArgument _
                                    | NamedApplicationBlock _ -> true
                                    | _ -> false)

                            if hasApplicationOnlyArgument || List.isEmpty arguments then
                                []
                            else
                                let instantiated = TypeSignatures.instantiate "v" freshCounter.Value bindingInfo.Scheme
                                let normalizedLayouts =
                                    normalizedVisibleBindingParameterLayouts bindingInfo instantiated
                                    |> Option.orElse bindingInfo.ParameterLayouts
                                let layoutTypeSubstitution = forallInstantiationSubstitution bindingInfo.Scheme instantiated

                                let renderConstraintFailure (constraintInfo: TraitConstraint) =
                                    match resolveConstraintInstanceDetailedWithSubstitution environment constraintInfo with
                                    | ConstraintResolved _ ->
                                        None
                                    | ConstraintUnresolved ->
                                        Some(makeImplicitTraitConstraintUnresolvedDiagnostic constraintInfo)
                                    | ConstraintAmbiguous(ambiguousGoal, candidates) ->
                                        Some(makeTraitConstraintAmbiguousDiagnostic ambiguousGoal candidates)

                                match normalizedLayouts with
                                | Some layouts when not (List.isEmpty layouts) ->
                                    let schemeParameterTypes, _ = TypeSignatures.schemeParts instantiated

                                    match
                                        tryAlignParameterTypesWithLayouts
                                            environment
                                            layoutTypeSubstitution
                                            layouts
                                            schemeParameterTypes
                                    with
                                    | Some(parameterTypes, _) ->
                                        let rec splitLeading
                                            (pendingLayouts: Parameter list)
                                            (pendingTypes: TypeExpr list)
                                            (consumedLeading: TypeExpr list)
                                            =
                                            match pendingLayouts, pendingTypes with
                                            | layout :: restLayouts, parameterType :: restTypes
                                                when layout.IsImplicit
                                                     && not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType) ->
                                                splitLeading restLayouts restTypes (parameterType :: consumedLeading)
                                            | _ ->
                                                List.rev consumedLeading, pendingLayouts, pendingTypes

                                        let leadingImplicitTypes, remainingLayouts, remainingTypes =
                                            splitLeading layouts parameterTypes []

                                        let rec collectExplicitParameterTypes
                                            (pendingLayouts: Parameter list)
                                            (pendingTypes: TypeExpr list)
                                            (pendingArguments: SurfaceExpression list)
                                            (explicitParameterTypes: TypeExpr list)
                                            =
                                            match pendingArguments with
                                            | [] ->
                                                Some(List.rev explicitParameterTypes)
                                            | _ ->
                                                match pendingLayouts, pendingTypes with
                                                | layout :: restLayouts, parameterType :: restTypes
                                                    when isCompileTimeArgumentType environment.VisibleTypeAliases parameterType ->
                                                    None
                                                | layout :: restLayouts, parameterType :: restTypes
                                                    when layout.IsImplicit ->
                                                    collectExplicitParameterTypes restLayouts restTypes pendingArguments explicitParameterTypes
                                                | _ :: restLayouts, parameterType :: restTypes ->
                                                    match pendingArguments with
                                                    | _ :: restArguments ->
                                                        collectExplicitParameterTypes
                                                            restLayouts
                                                            restTypes
                                                            restArguments
                                                            (parameterType :: explicitParameterTypes)
                                                    | [] ->
                                                        Some(List.rev explicitParameterTypes)
                                                | _ ->
                                                    None

                                        match collectExplicitParameterTypes remainingLayouts remainingTypes arguments [] with
                                        | Some explicitParameterTypes when not (List.isEmpty leadingImplicitTypes) ->
                                            let explicitArgumentTypes =
                                                List.zip explicitParameterTypes arguments
                                                |> List.map (fun (parameterType, argument) ->
                                                    tryInferNumericExpressionTypeFromContext environment parameterType argument
                                                    |> Option.orElseWith (fun () -> inferValidationExpressionType environment freshCounter locals argument)
                                                    |> Option.orElseWith (fun () ->
                                                        tryInferExpressionTypeWithSiblingFallback Set.empty locals argument))

                                            if explicitArgumentTypes |> List.exists Option.isNone then
                                                []
                                            else
                                                let explicitArgumentTypes = explicitArgumentTypes |> List.choose id

                                                match
                                                    tryUnifyVisibleTypes
                                                        environment.VisibleTypeAliases
                                                        (List.zip explicitParameterTypes explicitArgumentTypes)
                                                with
                                                | Some explicitSubstitution ->
                                                    leadingImplicitTypes
                                                    |> List.map (TypeSignatures.applySubstitution explicitSubstitution)
                                                    |> List.choose (fun parameterType ->
                                                        match classifyLocalImplicitByType environment locals parameterType with
                                                        | UniqueLocalImplicitCandidate _ ->
                                                            None
                                                        | NoLocalImplicitCandidate
                                                        | AmbiguousLocalImplicitCandidates ->
                                                            match tryTraitConstraintFromType environment parameterType with
                                                            | Some constraintInfo when constraintHasLocalDictionary environment constraintInfo ->
                                                                None
                                                            | Some constraintInfo ->
                                                                renderConstraintFailure constraintInfo
                                                            | None ->
                                                                None)
                                                | None ->
                                                    []
                                        | _ ->
                                            []
                                    | None ->
                                        []
                                | _ ->
                                    []

                        let implicitTraitConstraintDiagnostics (bindingInfo: BindingSchemeInfo) =
                            let preserveOrdinaryConstructorApplication =
                                bindingInfo.ConstructorTypeName.IsSome
                                || environment.VisibleConstructors.ContainsKey(bindingInfo.Name)

                            if preserveOrdinaryConstructorApplication then
                                []
                            else
                                match runtimeRelevantParameterLayouts bindingInfo with
                                | None ->
                                    schemeOnlyImplicitTraitConstraintDiagnostics bindingInfo
                                | Some layouts ->
                                    let leadingDiagnostics =
                                        leadingImplicitTraitConstraintDiagnostics bindingInfo

                                    if not (List.isEmpty leadingDiagnostics) then
                                        leadingDiagnostics
                                    else
                                        let parameterTypes, _ = TypeSignatures.schemeParts bindingInfo.Scheme

                                        if List.length layouts = List.length parameterTypes then
                                            List.zip layouts parameterTypes
                                            |> List.choose (fun (layout, parameterType) ->
                                                if layout.IsImplicit
                                                   && not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType)
                                                   && (match classifyLocalImplicitByType environment locals parameterType with
                                                       | NoLocalImplicitCandidate -> true
                                                       | UniqueLocalImplicitCandidate _
                                                       | AmbiguousLocalImplicitCandidates -> false) then
                                                    match tryTraitConstraintFromType environment parameterType with
                                                    | Some constraintInfo when constraintHasLocalDictionary environment constraintInfo ->
                                                        None
                                                    | Some constraintInfo ->
                                                        match resolveConstraintInstanceDetailedWithSubstitution environment constraintInfo with
                                                        | ConstraintResolved _ ->
                                                            None
                                                        | ConstraintUnresolved ->
                                                            Some(makeImplicitTraitConstraintUnresolvedDiagnostic constraintInfo)
                                                        | ConstraintAmbiguous(ambiguousGoal, candidates) ->
                                                            Some(makeTraitConstraintAmbiguousDiagnostic ambiguousGoal candidates)
                                                    | None ->
                                                        None
                                                else
                                                    None)
                                        else
                                            []
                        let hasTooManyArguments (bindingInfo: BindingSchemeInfo) =
                            let preserveOrdinaryConstructorApplication =
                                bindingInfo.ConstructorTypeName.IsSome
                                || environment.VisibleConstructors.ContainsKey(bindingInfo.Name)

                            if preserveOrdinaryConstructorApplication then
                                false
                            else
                                match runtimeRelevantParameterLayouts bindingInfo with
                                | Some layouts ->
                                    let instantiated = TypeSignatures.instantiate "v" freshCounter.Value bindingInfo.Scheme
                                    let runtimeArguments =
                                        consumeLeadingCompileTimeArguments instantiated.Forall arguments
                                        |> snd
                                    let visibleParameterCount =
                                        layouts
                                        |> List.filter (fun parameter -> not parameter.IsImplicit)
                                        |> List.length

                                    visibleParameterCount > 0 && runtimeArguments.Length > visibleParameterCount
                                | None ->
                                    false

                        let applicationStructuralDiagnostics (bindingInfo: BindingSchemeInfo) =
                            let preserveOrdinaryConstructorApplication =
                                bindingInfo.ConstructorTypeName.IsSome
                                || environment.VisibleConstructors.ContainsKey(bindingInfo.Name)

                            if preserveOrdinaryConstructorApplication then
                                []
                            else
                                let instantiatedForStructural =
                                    TypeSignatures.instantiate "v" freshCounter.Value bindingInfo.Scheme

                                let structuralParameterTypes, _ =
                                    TypeSignatures.schemeParts instantiatedForStructural

                                let structuralArguments =
                                    consumeLeadingCompileTimeArguments instantiatedForStructural.Forall arguments
                                    |> snd

                                let rec walk (parameters: (Parameter * TypeExpr) list) pendingArguments =
                                    match parameters, pendingArguments with
                                    | [], [] ->
                                        []
                                    | [], _ :: _ ->
                                        [ makeSurfaceElaborationDiagnostic
                                            ApplicationArgumentsDoNotMatchCalleeParameters ]
                                    | (layout, parameterType) :: restParameters, ExplicitImplicitArgument explicitArgument :: restArguments ->
                                        if not layout.IsImplicit then
                                            [ makeSurfaceElaborationDiagnostic
                                                ImplicitApplicationArgumentUnresolvedOrMismatched ]
                                        else
                                            if isCompileTimeArgumentType environment.VisibleTypeAliases parameterType then
                                                walk restParameters restArguments
                                            else
                                                match inferValidationExpressionType environment (ref freshCounter.Value) locals explicitArgument with
                                                | Some argumentType ->
                                                    if
                                                        canCompareInferredValidationTypes locals parameterType argumentType
                                                        && not (expectedTypeAccepts locals refinements parameterType argumentType)
                                                    then
                                                        [ expectedMismatchDiagnostic
                                                            locals
                                                            refinements
                                                            ApplicationArgumentMismatch
                                                            "Application argument"
                                                            parameterType
                                                            argumentType ]
                                                    else
                                                        walk restParameters restArguments
                                                | None ->
                                                    walk restParameters restArguments
                                    | (layout, _) :: _, (NamedApplicationBlock _ :: _) ->
                                        []
                                    | (layout, parameterType) :: restParameters, pending when layout.IsImplicit ->
                                        let isRuntimeImplicit =
                                            not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType)

                                        let isTraitImplicit =
                                            tryTraitConstraintFromType environment parameterType
                                            |> Option.isSome

                                        if not isRuntimeImplicit then
                                            walk restParameters pending
                                        elif
                                            match classifyLocalImplicitByType environment locals parameterType with
                                            | AmbiguousLocalImplicitCandidates -> true
                                            | NoLocalImplicitCandidate
                                            | UniqueLocalImplicitCandidate _ -> false
                                        then
                                            walk restParameters pending
                                        elif localCanSatisfyImplicitParameter bindingInfo || isTraitImplicit then
                                            walk restParameters pending
                                        elif List.isEmpty pending then
                                            []
                                        else
                                            [ makeSurfaceElaborationDiagnostic
                                                ImplicitApplicationArgumentUnresolvedOrMismatched ]
                                    | _ :: restParameters, _ :: restArguments ->
                                        walk restParameters restArguments
                                    | _ :: _, [] ->
                                        []

                                match bindingInfo.ParameterLayouts with
                                | Some [] ->
                                    []
                                | Some layouts ->
                                    match
                                        tryAlignParameterTypesWithLayouts
                                            environment
                                            Map.empty
                                            layouts
                                            structuralParameterTypes
                                    with
                                    | Some(alignedParameterTypes, _) ->
                                        walk (List.zip layouts alignedParameterTypes) structuralArguments
                                    | None ->
                                        []
                                | None -> []

                        let constraintResolutionDiagnostics constraints =
                            constraints
                            |> List.collect (fun constraintInfo ->
                                if constraintHasLocalDictionary environment constraintInfo then
                                    []
                                else
                                    match resolveConstraintInstanceDetailedWithSubstitution environment constraintInfo with
                                    | ConstraintResolved _ ->
                                        []
                                    | ConstraintUnresolved ->
                                        [ makeTraitConstraintUnresolvedDiagnostic constraintInfo ]
                                    | ConstraintAmbiguous(ambiguousGoal, candidates) ->
                                        [ makeTraitConstraintAmbiguousDiagnostic ambiguousGoal candidates ])

                        let applicationDiagnostics =
                            if isConstructorSpine then
                                []
                            else
                                match callee with
                                | Name [ calleeName ] ->
                                    let isLexicallyBoundName =
                                        Map.containsKey calleeName locals || Set.contains calleeName lexicalNames

                                    let localBindingType = Map.tryFind calleeName locals

                                    let siblingDefinitionShadowsVisibleBinding =
                                        topLevelDefinitionWithoutCurrentModuleSchemeShadowsVisibleBinding
                                            environment
                                            topLevelDefinitionsByName
                                            locals
                                            calleeName

                                    let ordinarySurfaceShadowsVisibleBinding =
                                        ordinarySurfaceNameShadowsVisiblePreludeBinding environment locals calleeName
                                        || siblingDefinitionShadowsVisibleBinding

                                    let bindingInfo =
                                        if isLexicallyBoundName || ordinarySurfaceShadowsVisibleBinding then
                                            None
                                        else
                                            environment.VisibleConstructors
                                            |> Map.tryFind calleeName
                                            |> Option.orElseWith (fun () -> environment.VisibleBindings |> Map.tryFind calleeName)

                                    let resolvesAsTraitMemberCall =
                                        if ordinarySurfaceShadowsVisibleBinding then
                                            false
                                        else
                                            tryPrepareVisibleTraitMemberCall
                                                environment
                                                (ref freshCounter.Value)
                                                calleeName
                                                (inferValidationExpressionType environment (ref freshCounter.Value) locals)
                                                arguments
                                            |> Option.isSome

                                    let traitMemberOwners =
                                        environment.VisibleTraits
                                        |> Map.values
                                        |> Seq.filter (fun traitInfo -> traitInfo.Members.ContainsKey(calleeName))
                                        |> Seq.toList

                                    let rec traitOrSupertraitProvidesMember traitName memberName =
                                        environment.VisibleTraits
                                        |> Map.tryFind traitName
                                        |> Option.exists (fun traitInfo ->
                                            traitInfo.Members.ContainsKey(memberName)
                                            || (traitInfo.Supertraits
                                                |> List.exists (fun supertrait ->
                                                    traitOrSupertraitProvidesMember (traitReferenceLocalName supertrait.Trait) memberName)))

                                    let localConstraintProjectionAvailable =
                                        locals
                                        |> Map.values
                                        |> Seq.exists (fun localType ->
                                            tryTraitConstraintFromType environment localType
                                            |> Option.exists (fun constraintInfo ->
                                                traitOrSupertraitProvidesMember (traitConstraintLocalName constraintInfo) calleeName))

                                    let isKnownVisibleCallee =
                                        isLexicallyBoundName
                                        || (Set.contains calleeName knownSurfaceTermNames)
                                        || (Set.contains calleeName knownValueNames)
                                        || environment.VisibleProjections.ContainsKey(calleeName)
                                        || not (List.isEmpty traitMemberOwners)
                                        || environment.ConstrainedMembers.ContainsKey(calleeName)
                                        || localConstraintProjectionAvailable
                                        || resolvesAsTraitMemberCall

                                    let siblingFallbackApplicationType =
                                        tryInferSiblingApplicationResultType Set.empty locals calleeName arguments

                                    match bindingInfo with
                                    | Some bindingInfo ->
                                        let probeCounter = ref freshCounter.Value
                                        let inferPreparedArgumentType =
                                            tryInferExpressionTypeWithSiblingFallback Set.empty locals

                                        let structuralDiagnostics = applicationStructuralDiagnostics bindingInfo
                                        let siblingFallbackCalleeType =
                                            if List.isEmpty bindingInfo.TypeTokens then
                                                tryInferSiblingBindingType Set.empty calleeName
                                            else
                                                None

                                        let siblingFallbackArgumentDiagnostics =
                                            siblingFallbackCalleeType
                                            |> Option.map (fun calleeType ->
                                                localApplicationExpectedArgumentDiagnostics
                                                    locals
                                                    refinements
                                                    calleeType
                                                    arguments)
                                            |> Option.defaultValue []

                                        let expectedArgumentDiagnostics =
                                            if not (List.isEmpty siblingFallbackArgumentDiagnostics) then
                                                siblingFallbackArgumentDiagnostics
                                            else
                                                applicationExpectedArgumentDiagnostics locals refinements lexicalNames bindingInfo arguments
                                        let traitConstraintDiagnostics = implicitTraitConstraintDiagnostics bindingInfo
                                        let zeroExplicitParameterCallDiagnostics () =
                                            let instantiated =
                                                TypeSignatures.instantiate "v" freshCounter.Value bindingInfo.Scheme

                                            let visibleExplicitParameterCount =
                                                bindingInfo.ParameterLayouts
                                                |> Option.map (fun layouts -> layouts |> List.filter (fun parameter -> not parameter.IsImplicit) |> List.length)
                                                |> Option.defaultValue 0

                                            if arguments.IsEmpty || visibleExplicitParameterCount <> 0 then
                                                []
                                            else
                                                let apparentCalleeType = instantiated.Body

                                                if isCallableValidationType environment.VisibleTypeAliases apparentCalleeType then
                                                    localApplicationExpectedArgumentDiagnostics
                                                        locals
                                                        refinements
                                                        apparentCalleeType
                                                        arguments
                                                else
                                                    [ makeSurfaceElaborationDiagnostic
                                                        (ApplicationExpressionNotCallable(
                                                            TypeSignatures.toText (normalizeTypeAliases environment.VisibleTypeAliases apparentCalleeType)
                                                        )) ]

                                        if not (List.isEmpty structuralDiagnostics) then
                                            structuralDiagnostics
                                        else
                                            match
                                                tryPrepareVisibleBindingCall
                                                    environment
                                                    probeCounter
                                                    bindingInfo
                                                    (Some locals)
                                                    inferPreparedArgumentType
                                                    (tryResolveUniqueLocalImplicitByType environment locals)
                                                    arguments
                                            with
                                            | Some preparedCall ->
                                                expectedArgumentDiagnostics
                                                @ constraintResolutionDiagnostics preparedCall.InstantiatedScheme.Constraints
                                            | None
                                                when hasNamedBlock
                                                     || hasExplicitImplicitArgument
                                                     || hasUnsatisfiedRuntimeImplicit bindingInfo
                                                     || hasAmbiguousLocalImplicitParameter bindingInfo
                                                     || not (List.isEmpty traitConstraintDiagnostics)
                                                     || hasTooManyArguments bindingInfo ->
                                                let mismatchDiagnostics =
                                                    if hasNamedBlock then
                                                        [ makeSurfaceElaborationDiagnostic
                                                            NamedApplicationArgumentsDoNotMatchCalleeParameterMetadata ]
                                                    elif not (List.isEmpty traitConstraintDiagnostics) then
                                                        []
                                                    elif hasAmbiguousLocalImplicitParameter bindingInfo then
                                                        []
                                                    elif hasExplicitImplicitArgument
                                                         || hasUnsatisfiedRuntimeImplicit bindingInfo then
                                                        [ makeSurfaceElaborationDiagnostic
                                                            ImplicitApplicationArgumentUnresolvedOrMismatched ]
                                                    else
                                                        [ makeSurfaceElaborationDiagnostic
                                                            ApplicationArgumentsDoNotMatchCalleeParameters ]

                                                expectedArgumentDiagnostics
                                                @ traitConstraintDiagnostics
                                                @ mismatchDiagnostics
                                            | None when localCanSatisfyImplicitParameter bindingInfo && not hasExplicitImplicitArgument ->
                                                expectedArgumentDiagnostics
                                            | None
                                                when List.isEmpty expectedArgumentDiagnostics
                                                     && List.isEmpty traitConstraintDiagnostics ->
                                                zeroExplicitParameterCallDiagnostics ()
                                            | None ->
                                                expectedArgumentDiagnostics
                                    | None
                                        when not resolvesAsTraitMemberCall
                                             && not ordinarySurfaceShadowsVisibleBinding
                                             && not (List.isEmpty traitMemberOwners)
                                             && not (environment.ConstrainedMembers.ContainsKey(calleeName))
                                             && not localConstraintProjectionAvailable ->
                                        let inferredArgumentTypes =
                                            arguments
                                            |> List.map (fun argument ->
                                                inferValidationExpressionType environment (ref freshCounter.Value) locals argument
                                                |> Option.map TypeSignatures.toText
                                                |> Option.defaultValue "_")

                                        let traitOwnerText =
                                            traitMemberOwners
                                            |> List.map (fun traitInfo -> traitInfo.Name)

                                        [
                                            makeSurfaceElaborationDiagnostic
                                                (OverloadedTraitMemberUnresolvedForArgumentTypes(
                                                    calleeName,
                                                    traitOwnerText,
                                                    inferredArgumentTypes
                                                ))
                                        ]
                                    | None
                                        when allowUnresolvedCallDiagnostics
                                             && not isKnownVisibleCallee ->
                                        [ makeNameUnresolvedDiagnostic calleeName ]
                                    | None when localBindingType |> Option.exists (fun _ -> not hasNamedBlock) ->
                                        localApplicationExpectedArgumentDiagnostics
                                            locals
                                            refinements
                                            (localBindingType.Value)
                                            arguments
                                    | None when hasNamedBlock ->
                                        [ makeSurfaceElaborationDiagnostic
                                            NamedApplicationRequiresPreservedParameterMetadata ]
                                    | _ ->
                                        []
                                | _ when hasNamedBlock ->
                                    [ makeSurfaceElaborationDiagnostic
                                        NamedApplicationRequiresPreservedParameterMetadata ]
                                | _ ->
                                    []

                        let nonCallableDiagnostics =
                            if isConstructorSpine || not (List.isEmpty applicationDiagnostics) then
                                []
                            elif
                                match callee with
                                | Name [ calleeName ] ->
                                    Set.contains calleeName lexicalNames && not (Map.containsKey calleeName locals)
                                | _ ->
                                    false
                            then
                                []
                            elif
                                match callee with
                                | Name [ projectionName ] -> environment.VisibleProjections.ContainsKey(projectionName)
                                | _ -> false
                            then
                                []
                            else
                                let suppressForPreparedVisibleCall =
                                    match callee with
                                    | Name [ calleeName ] when not (Map.containsKey calleeName locals || Set.contains calleeName lexicalNames) ->
                                        environment.VisibleConstructors
                                        |> Map.tryFind calleeName
                                        |> Option.orElseWith (fun () -> environment.VisibleBindings |> Map.tryFind calleeName)
                                        |> Option.exists (fun bindingInfo ->
                                            tryPrepareVisibleBindingCall
                                                environment
                                                (ref freshCounter.Value)
                                                bindingInfo
                                                (Some locals)
                                                (tryInferExpressionTypeWithSiblingFallback Set.empty locals)
                                                (tryResolveUniqueLocalImplicitByType environment locals)
                                                arguments
                                            |> Option.isSome)
                                    | _ ->
                                        false

                                if suppressForPreparedVisibleCall then
                                    []
                                else
                                    match inferValidationExpressionType environment (ref freshCounter.Value) locals callee with
                                    | Some calleeType ->
                                        let normalizedCalleeType =
                                            normalizeTypeAliases environment.VisibleTypeAliases calleeType

                                        match normalizedCalleeType with
                                        | _ when isCallableValidationType environment.VisibleTypeAliases normalizedCalleeType ->
                                            []
                                        | _ ->
                                            [ makeSurfaceElaborationDiagnostic
                                                (ApplicationExpressionNotCallable(TypeSignatures.toText normalizedCalleeType)) ]
                                    | None ->
                                        []

                        comprehensionSinkDiagnostics @ argumentDiagnostics @ applicationDiagnostics @ nonCallableDiagnostics
                    | _ ->
                        []
            | Elvis(left, right) ->
                let diagnostics = recurse left @ recurse right

                match inferValidationExpressionType environment freshCounter locals left with
                | Some leftType when tryOptionPayloadType environment.VisibleTypeAliases leftType |> Option.isNone ->
                    diagnostics
                    @ [ makeSurfaceElaborationDiagnostic ElvisReceiverMustBeOption ]
                | _ ->
                    diagnostics
            | Binary(left, operatorName, right) ->
                let diagnostics =
                    match operatorName with
                    | "&&" ->
                        let rightFacts =
                            conditionConstructorFacts aliases constructorFacts left |> fst

                        recurse left
                        @ (rightFacts
                           |> List.collect (fun branchFacts ->
                               validateExpressionWithFlow locals refinements lexicalNames aliases staticAliases branchFacts right))
                    | "||" ->
                        let rightFacts =
                            conditionConstructorFacts aliases constructorFacts left |> snd

                        recurse left
                        @ (rightFacts
                           |> List.collect (fun branchFacts ->
                               validateExpressionWithFlow locals refinements lexicalNames aliases staticAliases branchFacts right))
                    | _ ->
                        recurse left @ recurse right

                match operatorName with
                | "&&"
                | "||" ->
                    let operandDiagnostics operandLabel operand =
                        match inferValidationExpressionType environment freshCounter locals operand with
                        | Some operandType when not (expectedTypeAccepts locals refinements boolType operandType) ->
                            [ makeSurfaceElaborationDiagnostic
                                (ShortCircuitOperandMustBeSuspendedBool(
                                    operandLabel,
                                    TypeSignatures.toText operandType
                                )) ]
                        | _ ->
                            []

                    diagnostics
                    @ operandDiagnostics "left-hand side" left
                    @ operandDiagnostics "right-hand side" right
                | "=="
                | "!="
                | "<"
                | ">"
                | "<="
                | ">=" ->
                    let requiredTraitName =
                        match operatorName with
                        | "=="
                        | "!=" -> "Eq"
                        | _ -> "Ord"

                    let comparisonConstraintDiagnostics =
                        match tryResolveComparableOperandTypes locals left right with
                        | Some(normalizedLeftType, _, leftType, rightType) ->
                                let constraintInfo =
                                    unqualifiedTraitConstraint requiredTraitName [ normalizedLeftType ]

                                if constraintHasLocalDictionary environment constraintInfo then
                                    []
                                else
                                    match resolveConstraintInstanceDetailedWithSubstitution environment constraintInfo with
                                    | ConstraintResolved _ ->
                                        []
                                    | ConstraintUnresolved ->
                                        [ makeTraitConstraintUnresolvedDiagnostic constraintInfo ]
                                    | ConstraintAmbiguous(ambiguousGoal, candidates) ->
                                        [ makeTraitConstraintAmbiguousDiagnostic ambiguousGoal candidates ]
                        | None ->
                            match
                                inferValidationExpressionType environment freshCounter locals left,
                                inferValidationExpressionType environment freshCounter locals right
                            with
                            | Some leftType, Some rightType ->
                                [ expectedMismatchDiagnostic
                                    locals
                                    refinements
                                    ExpressionTypeMismatch
                                    "Comparison operator operands"
                                    leftType
                                    rightType ]
                            | _ ->
                                []

                    diagnostics @ comparisonConstraintDiagnostics
                | ".."
                | "..<" ->
                    let rangeConstraintDiagnostics =
                        match tryResolveComparableOperandTypes locals left right with
                        | Some(normalizedLeftType, _, leftType, rightType) ->
                                let constraintInfo =
                                    unqualifiedTraitConstraint "Rangeable" [ normalizedLeftType ]

                                if constraintHasLocalDictionary environment constraintInfo then
                                    []
                                else
                                    match resolveConstraintInstanceDetailedWithSubstitution environment constraintInfo with
                                    | ConstraintResolved _ ->
                                        []
                                    | ConstraintUnresolved ->
                                        [ makeTraitConstraintUnresolvedDiagnostic constraintInfo ]
                                    | ConstraintAmbiguous(ambiguousGoal, candidates) ->
                                        [ makeTraitConstraintAmbiguousDiagnostic ambiguousGoal candidates ]
                        | None ->
                            match
                                inferValidationExpressionType environment freshCounter locals left,
                                inferValidationExpressionType environment freshCounter locals right
                            with
                            | Some leftType, Some rightType ->
                                [ expectedMismatchDiagnostic
                                    locals
                                    refinements
                                    ExpressionTypeMismatch
                                    "Range operator operands"
                                    leftType
                                    rightType ]
                            | _ ->
                                []

                    diagnostics @ rangeConstraintDiagnostics
                | "+" | "-" | "*" | "/" ->
                    let operandDiagnostics operandLabel operand =
                        match operand with
                        | Name [ name ]
                            when not (Map.containsKey name locals)
                                 && not (
                                     definition.Name
                                     |> Option.exists (fun definitionName -> String.Equals(name, definitionName, StringComparison.Ordinal))
                                 ) ->
                            let inferredOperandType =
                                inferValidationExpressionType environment freshCounter locals operand
                                |> Option.orElseWith (fun () -> tryInferExpressionTypeWithSiblingFallback Set.empty locals operand)

                            match inferredOperandType with
                            | Some operandType when typeIsCallableLikeForValidation operandType ->
                                    [ makeSurfaceElaborationDiagnostic
                                        (ArithmeticOperandResolvesToCallableBinding(operandLabel, name)) ]
                            | _ ->
                                match topLevelDefinitionsByName |> Map.tryFind name with
                                | Some bindingInfo when not (List.isEmpty bindingInfo.Parameters) ->
                                    [ makeSurfaceElaborationDiagnostic
                                        (ArithmeticOperandResolvesToCallableBinding(operandLabel, name)) ]
                                | None ->
                                    []
                                | Some _ ->
                                    []
                        | _ ->
                            []

                    let leftOperandDiagnostics = operandDiagnostics "left-hand side" left
                    let rightOperandDiagnostics = operandDiagnostics "right-hand side" right

                    let numericTypeDiagnostics =
                        let isSupportedArithmeticType normalizedTypeExpr =
                            match normalizedTypeExpr with
                            | TypeName(nameSegments, []) when
                                matchesKnownType CompilerKnownSymbols.IntType nameSegments
                                || matchesKnownType CompilerKnownSymbols.FloatType nameSegments
                                || matchesKnownType CompilerKnownSymbols.DoubleType nameSegments ->
                                true
                            | _ ->
                                false

                        match
                            inferValidationExpressionType environment freshCounter locals left,
                            inferValidationExpressionType environment freshCounter locals right
                        with
                        | Some leftType, Some rightType ->
                            let normalizedLeftType = normalizeTypeAliases environment.VisibleTypeAliases leftType
                            let normalizedRightType = normalizeTypeAliases environment.VisibleTypeAliases rightType

                            match normalizedLeftType, normalizedRightType with
                            | _ when
                                isCompileTimeArgumentType environment.VisibleTypeAliases normalizedLeftType
                                || isCompileTimeArgumentType environment.VisibleTypeAliases normalizedRightType ->
                                [ makeSurfaceElaborationDiagnostic
                                    (ArithmeticOperandsMustBeNumeric(
                                        TypeSignatures.toText leftType,
                                        TypeSignatures.toText rightType
                                    )) ]
                            | _ when isSupportedArithmeticType normalizedLeftType && isSupportedArithmeticType normalizedRightType ->
                                []
                            | _ when not (canCompareInferredValidationTypes locals leftType rightType) ->
                                []
                            | _ ->
                                [ makeSurfaceElaborationDiagnostic
                                    (ArithmeticOperandsMustBeNumeric(
                                        TypeSignatures.toText leftType,
                                        TypeSignatures.toText rightType
                                    )) ]
                        | _ ->
                            []

                    diagnostics
                    @ leftOperandDiagnostics
                    @ rightOperandDiagnostics
                    @ (if List.isEmpty leftOperandDiagnostics && List.isEmpty rightOperandDiagnostics then
                           numericTypeDiagnostics
                       else
                           [])
                | _ ->
                    let operatorBindingDiagnostics =
                        if
                            ordinarySurfaceNameShadowsVisiblePreludeBinding environment locals operatorName
                            || topLevelDefinitionWithoutCurrentModuleSchemeShadowsVisibleBinding
                                environment
                                topLevelDefinitionsByName
                                locals
                                operatorName
                        then
                            []
                        else
                            environment.VisibleConstructors
                            |> Map.tryFind operatorName
                            |> Option.orElseWith (fun () -> environment.VisibleBindings |> Map.tryFind operatorName)
                            |> Option.map (fun bindingInfo ->
                                let instantiated = TypeSignatures.instantiate "v" freshCounter.Value bindingInfo.Scheme

                                localApplicationExpectedArgumentDiagnostics
                                    locals
                                    refinements
                                    instantiated.Body
                                    [ left; right ])
                            |> Option.defaultValue []

                    diagnostics
                    @ (if List.isEmpty operatorBindingDiagnostics then
                           validateExpressionWithFlow
                               locals
                               refinements
                               lexicalNames
                               aliases
                               staticAliases
                               constructorFacts
                               (Apply(Name [ operatorName ], [ left; right ]))
                       else
                           operatorBindingDiagnostics)
            | PrefixedString(prefix, parts) ->
                prefixedStringPrefixDiagnostics locals lexicalNames prefix
                @ (tryResolvePrefixedStringFailureDiagnostic prefix
                   |> Option.map (fun evidence -> [ makeSurfaceElaborationDiagnostic evidence ])
                   |> Option.defaultValue [])
                @ (parts
                   |> List.collect (function
                       | StringText _ -> []
                       | StringInterpolation(inner, _) -> recurse inner))

        and validateDoStatementsWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts statements =
            match statements with
            | [] ->
                []
            | statement :: rest ->
                match statement with
                | DoLet(binding, expression) ->
                    let aliasAwareEnvironment =
                        withVisibleStaticObjects environment (aliasesAsVisibleStaticObjects staticAliases)

                    let nextLexicalNames =
                        collectPatternNames binding.Pattern
                        |> Set.ofList
                        |> Set.union lexicalNames

                    let nextLocals =
                        match inferValidationExpressionType aliasAwareEnvironment freshCounter locals expression with
                        | Some valueType ->
                            extendBindingLocalTypes aliasAwareEnvironment freshCounter locals binding (Some valueType)
                        | None ->
                            locals

                    let localStaticAliases = collectScopedPatternStaticAliases aliasAwareEnvironment binding.Pattern expression
                    let restForValidation =
                        match rewriteStaticObjectPathAliasUses localStaticAliases (Do rest) with
                        | Do rewritten -> rewritten
                        | _ -> rest

                    let nextAliases =
                        extendStableAliases aliases binding expression

                    let nextStaticAliases =
                        let shadowedNames = collectPatternNames binding.Pattern
                        let inheritedAliases = removeShadowedStaticAliases staticAliases shadowedNames

                        localStaticAliases
                        |> Map.fold (fun state segments staticObject -> Map.add segments staticObject state) inheritedAliases

                    validateExpressionWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts expression
                    @ validateDoStatementsWithFlow nextLocals refinements nextLexicalNames nextAliases nextStaticAliases constructorFacts restForValidation
                | DoBind(binding, expression) ->
                    let aliasAwareEnvironment =
                        withVisibleStaticObjects environment (aliasesAsVisibleStaticObjects staticAliases)

                    let nextLexicalNames =
                        collectPatternNames binding.Pattern
                        |> Set.ofList
                        |> Set.union lexicalNames

                    let bindSourceDiagnostics =
                        match inferValidationExpressionType aliasAwareEnvironment freshCounter locals expression with
                        | Some sourceType when tryUnwrapBindablePayloadType environment.VisibleTypeAliases sourceType |> Option.isNone ->
                            [ makeSurfaceElaborationDiagnostic
                                (DoBindRequiresBindableCarrier(TypeSignatures.toText sourceType)) ]
                        | _ ->
                            []

                    let nextLocals =
                        match inferValidationExpressionType aliasAwareEnvironment freshCounter locals expression with
                        | Some valueType ->
                            match tryUnwrapBindablePayloadType environment.VisibleTypeAliases valueType with
                            | Some payloadType ->
                                extendBindingLocalTypes aliasAwareEnvironment freshCounter locals binding (Some payloadType)
                            | None ->
                                locals
                        | None ->
                            locals

                    let nextAliases =
                        removeShadowedAliases aliases (collectPatternNames binding.Pattern)

                    let nextStaticAliases =
                        removeShadowedStaticAliases staticAliases (collectPatternNames binding.Pattern)

                    validateExpressionWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts expression
                    @ bindSourceDiagnostics
                    @ validateDoStatementsWithFlow nextLocals refinements nextLexicalNames nextAliases nextStaticAliases constructorFacts rest
                | DoLetQuestion(binding, expression, failure) ->
                    let aliasAwareEnvironment =
                        withVisibleStaticObjects environment (aliasesAsVisibleStaticObjects staticAliases)

                    let nextLexicalNames =
                        collectPatternNames binding.Pattern
                        |> Set.ofList
                        |> Set.union lexicalNames

                    let nextLocals =
                        match inferValidationExpressionType aliasAwareEnvironment freshCounter locals expression with
                        | Some valueType ->
                            extendBindingLocalTypes aliasAwareEnvironment freshCounter locals binding (Some valueType)
                        | None ->
                            locals

                    let nextAliases =
                        removeShadowedAliases aliases (collectPatternNames binding.Pattern)

                    let nextStaticAliases =
                        removeShadowedStaticAliases staticAliases (collectPatternNames binding.Pattern)

                    let failureDiagnostics =
                        match failure with
                        | Some failure ->
                            let failureLexicalNames =
                                collectPatternNames failure.ResiduePattern.Pattern
                                |> Set.ofList
                                |> Set.union lexicalNames

                            validateDoStatementsWithFlow locals refinements failureLexicalNames aliases staticAliases constructorFacts failure.Body
                        | None -> []

                    validateExpressionWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts expression
                    @ validatePatternHead binding.Pattern
                    @ activePatternLinearityDiagnostics binding.Pattern "let?"
                    @ failureDiagnostics
                    @ validateDoStatementsWithFlow nextLocals refinements nextLexicalNames nextAliases nextStaticAliases constructorFacts rest
                | DoUsing(binding, expression) ->
                    let aliasAwareEnvironment =
                        withVisibleStaticObjects environment (aliasesAsVisibleStaticObjects staticAliases)

                    let nextLexicalNames =
                        collectPatternNames binding.Pattern
                        |> Set.ofList
                        |> Set.union lexicalNames

                    let nextLocals =
                        match binding.Pattern, inferValidationExpressionType aliasAwareEnvironment freshCounter locals expression with
                        | _, Some valueType ->
                            extendBindingLocalTypes aliasAwareEnvironment freshCounter locals binding (Some(unwrapIoType valueType))
                        | _ -> locals

                    let nextAliases =
                        removeShadowedAliases aliases (collectPatternNames binding.Pattern)

                    let nextStaticAliases =
                        removeShadowedStaticAliases staticAliases (collectPatternNames binding.Pattern)

                    validateExpressionWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts expression
                    @ validateDoStatementsWithFlow nextLocals refinements nextLexicalNames nextAliases nextStaticAliases constructorFacts rest
                | DoVar(bindingName, expression) ->
                    let aliasAwareEnvironment =
                        withVisibleStaticObjects environment (aliasesAsVisibleStaticObjects staticAliases)

                    let nextLocals =
                        match inferValidationExpressionType aliasAwareEnvironment freshCounter locals expression with
                        | Some valueType -> Map.add bindingName (refType valueType) locals
                        | None -> locals

                    validateExpressionWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts expression
                    @ validateDoStatementsWithFlow
                        nextLocals
                        refinements
                        (Set.add bindingName lexicalNames)
                        (Map.remove bindingName aliases)
                        (removeShadowedStaticAliases staticAliases [ bindingName ])
                        constructorFacts
                        rest
                | DoAssign(_, expression)
                | DoDefer expression
                | DoExpression expression ->
                    validateExpressionWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts expression
                    @ validateDoStatementsWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts rest
                | DoIf(condition, whenTrue, whenFalse) ->
                    let trueConstructorFacts, falseConstructorFacts =
                        conditionConstructorFacts aliases constructorFacts condition

                    let restDiagnostics =
                        match doBlockDefinitelyTerminal whenTrue, doBlockDefinitelyTerminal whenFalse with
                        | false, true ->
                            trueConstructorFacts
                            |> List.collect (fun branchFacts ->
                                validateDoStatementsWithFlow locals refinements lexicalNames aliases staticAliases branchFacts rest)
                        | true, false ->
                            falseConstructorFacts
                            |> List.collect (fun branchFacts ->
                                validateDoStatementsWithFlow locals refinements lexicalNames aliases staticAliases branchFacts rest)
                        | _ ->
                            validateDoStatementsWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts rest

                    validateExpressionWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts condition
                    @ (trueConstructorFacts
                       |> List.collect (fun branchFacts ->
                           validateDoStatementsWithFlow locals refinements lexicalNames aliases staticAliases branchFacts whenTrue))
                    @ (falseConstructorFacts
                       |> List.collect (fun branchFacts ->
                           validateDoStatementsWithFlow locals refinements lexicalNames aliases staticAliases branchFacts whenFalse))
                    @ restDiagnostics
                | DoWhile(condition, body) ->
                    let trueConstructorFacts, _ =
                        conditionConstructorFacts aliases constructorFacts condition

                    validateExpressionWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts condition
                    @ (trueConstructorFacts
                       |> List.collect (fun branchFacts ->
                           validateDoStatementsWithFlow locals refinements lexicalNames aliases staticAliases branchFacts body))
                    @ validateDoStatementsWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts rest
                | DoReturn expression ->
                    validateExpressionWithFlow locals refinements lexicalNames aliases staticAliases constructorFacts expression

        let validateExpression locals refinements lexicalNames expression =
            validateExpressionWithFlow locals refinements lexicalNames emptyStableAliases emptyStaticAliases emptyConstructorFacts expression

        let rec validateInoutPlacement insideDo expression =
            let recurse = validateInoutPlacement insideDo

            match expression with
            | InoutArgument inner ->
                let markerDiagnostics =
                    if insideDo then
                        []
                    else
                        [
                            Diagnostics.errorFact
                                "KFrontIR"
                                (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                None
                                []
                                (DiagnosticFact.qttInoutMarkerUnexpected InoutMarkerUnexpected)
                        ]

                markerDiagnostics @ recurse inner
            | TypeSyntaxTokens _ ->
                []
            | SyntaxQuote inner
            | SyntaxSplice inner
            | TopLevelSyntaxSplice inner
            | CodeQuote inner
            | CodeSplice inner ->
                recurse inner
            | Handle(_, label, body, returnClause, operationClauses) ->
                recurse label
                @ recurse body
                @ recurse returnClause.Body
                @ (operationClauses |> List.collect (fun clause -> recurse clause.Body))
            | LocalLet(_, value, body) ->
                recurse value @ recurse body
            | LocalSignature(_, body) ->
                recurse body
            | LocalTypeAlias(_, body) ->
                recurse body
            | LocalScopedEffect(_, body) ->
                recurse body
            | Lambda(_, body) ->
                validateInoutPlacement false body
            | IfThenElse(condition, whenTrue, whenFalse) ->
                recurse condition @ recurse whenTrue @ recurse whenFalse
            | Match(scrutinee, cases) ->
                recurse scrutinee
                @ (cases
                   |> List.collect (fun caseClause ->
                       (caseClause.Guard |> Option.map recurse |> Option.defaultValue [])
                       @ recurse caseClause.Body))
            | RecordLiteral fields ->
                fields |> List.collect (fun field -> recurse field.Value)
            | Seal(value, _) ->
                recurse value
            | RecordUpdate(receiver, fields) ->
                recurse receiver @ (fields |> List.collect (fun field -> recurse field.Value))
            | MemberAccess(receiver, _, arguments) ->
                recurse receiver @ (arguments |> List.collect recurse)
            | SafeNavigation(receiver, navigation) ->
                recurse receiver @ (navigation.Arguments |> List.collect recurse)
            | TagTest(receiver, _) ->
                recurse receiver
            | Do statements ->
                statements |> List.collect validateInoutDoStatement
            | MonadicSplice inner
            | ExplicitImplicitArgument inner
            | Unary(_, inner) ->
                recurse inner
            | NamedApplicationBlock fields ->
                fields |> List.collect (fun field -> recurse field.Value)
            | Apply(callee, arguments) ->
                recurse callee @ (arguments |> List.collect recurse)
            | Binary(left, _, right)
            | Elvis(left, right) ->
                recurse left @ recurse right
            | Comprehension comprehension ->
                recurse comprehension.Lowered
            | PrefixedString(_, parts) ->
                parts
                |> List.collect (function
                    | StringText _ -> []
                    | StringInterpolation(inner, _) -> recurse inner)
            | Literal _
            | NumericLiteral _
            | KindQualifiedName _
            | Name _ ->
                []

        and validateInoutDoStatement statement =
            match statement with
            | DoLet(_, expression)
            | DoLetQuestion(_, expression, _)
            | DoBind(_, expression)
            | DoVar(_, expression)
            | DoAssign(_, expression)
            | DoDefer expression
            | DoUsing(_, expression)
            | DoReturn expression
            | DoExpression expression ->
                validateInoutPlacement true expression
            | DoIf(condition, whenTrue, whenFalse) ->
                validateInoutPlacement true condition
                @ (whenTrue |> List.collect validateInoutDoStatement)
                @ (whenFalse |> List.collect validateInoutDoStatement)
            | DoWhile(condition, body) ->
                validateInoutPlacement true condition @ (body |> List.collect validateInoutDoStatement)

        let tryProjectionDescriptorAlias (expression: SurfaceExpression) =
            let tryBuild projectionName suppliedArguments =
                environment.VisibleProjections
                |> Map.tryFind projectionName
                |> Option.bind (fun projectionInfo ->
                    if List.length suppliedArguments >= List.length projectionInfo.Binders then
                        None
                    else
                        let suppliedBinders = projectionInfo.Binders |> List.take (List.length suppliedArguments)
                        let remainingBinders = projectionInfo.Binders |> List.skip (List.length suppliedArguments)

                        let suppliedAreValues =
                            suppliedBinders
                            |> List.forall (function
                                | ProjectionValueBinder _ -> true
                                | ProjectionPlaceBinder _ -> false)

                        let remainingPlaceBinders =
                            remainingBinders
                            |> List.choose (function
                                | ProjectionPlaceBinder binder -> Some binder
                                | ProjectionValueBinder _ -> None)

                        if suppliedAreValues && List.length remainingPlaceBinders = List.length remainingBinders then
                            Some
                                { Projection = projectionInfo
                                  RemainingPlaceBinders = remainingPlaceBinders }
                        else
                            None)

            match expression with
            | Name [ projectionName ] -> tryBuild projectionName []
            | Apply(Name [ projectionName ], suppliedArguments) -> tryBuild projectionName suppliedArguments
            | _ -> None

        let rec isStableDescriptorPlace (expression: SurfaceExpression) =
            match expression with
            | Name(_ :: _) ->
                true
            | Apply(Name [ projectionName ], arguments) ->
                environment.VisibleProjections
                |> Map.tryFind projectionName
                |> Option.exists (fun projectionInfo ->
                    match projectionInfo.Body with
                    | Some(ProjectionAccessors _) ->
                        false
                    | _ ->
                        List.length projectionInfo.Binders = List.length arguments
                        && (List.zip projectionInfo.Binders arguments
                            |> List.forall (fun (binder, argument) ->
                                match binder with
                                | ProjectionPlaceBinder _ -> isStableDescriptorPlace argument
                                | ProjectionValueBinder _ -> true)))
            | _ ->
                false

        let descriptorApplicationDiagnostics (remainingPlaceBinders: ProjectionPlaceBinder list) rootsArgument =
            let rootPackFieldMap (fields: SurfaceRecordLiteralField list) =
                fields
                |> List.map (fun field -> field.Name, field.Value)
                |> Map.ofList

            let unstableRootDiagnostics expressions =
                expressions
                |> List.choose (fun expression ->
                    if isStableDescriptorPlace expression then
                        None
                    else
                        Some(
                            Diagnostics.errorFact
                                "KFrontIR"
                                (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                None
                                []
                                (DiagnosticFact.surfaceElaboration ProjectionDescriptorRootsMustBeStablePlaces)
                        ))

            match remainingPlaceBinders with
            | [] ->
                [
                    Diagnostics.errorFact
                        "KFrontIR"
                        (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                        None
                        []
                        (DiagnosticFact.surfaceElaboration ProjectionDescriptorApplicationRequiresAtLeastOneRoot)
                ]
            | [ binder ] ->
                match rootsArgument with
                | RecordLiteral fields when fields |> List.exists (fun field -> String.Equals(field.Name, binder.Name, StringComparison.Ordinal)) ->
                    let fieldMap = rootPackFieldMap fields
                    let fieldNames = fieldMap |> Map.keys |> Set.ofSeq
                    let expectedNames = Set.singleton binder.Name

                    if fieldNames <> expectedNames then
                        [
                            Diagnostics.errorFact
                                "KFrontIR"
                                (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                None
                                []
                                (DiagnosticFact.surfaceElaboration ProjectionDescriptorRootsPackFieldsMustMatchBindersExactly)
                        ]
                    else
                        fieldMap |> Map.find binder.Name |> List.singleton |> unstableRootDiagnostics
                | RecordLiteral _ ->
                    [
                        Diagnostics.errorFact
                            "KFrontIR"
                            (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                            None
                            []
                            (DiagnosticFact.surfaceElaboration ProjectionDescriptorRootsPackFieldsMustMatchBindersExactly)
                    ]
                | _ ->
                    unstableRootDiagnostics [ rootsArgument ]
            | binders ->
                match rootsArgument with
                | RecordLiteral fields ->
                    let fieldMap = rootPackFieldMap fields
                    let fieldNames = fieldMap |> Map.keys |> Set.ofSeq
                    let expectedNames = binders |> List.map (fun binder -> binder.Name) |> Set.ofList

                    if fieldNames <> expectedNames then
                        [
                            Diagnostics.errorFact
                                "KFrontIR"
                                (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                None
                                []
                                (DiagnosticFact.surfaceElaboration ProjectionDescriptorRootsPackFieldsMustMatchBindersExactly)
                        ]
                    else
                        binders
                        |> List.map (fun binder -> fieldMap |> Map.find binder.Name)
                        |> unstableRootDiagnostics
                | _ ->
                    [
                        Diagnostics.errorFact
                            "KFrontIR"
                            (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                            None
                            []
                            (DiagnosticFact.surfaceElaboration MultiRootProjectionDescriptorRequiresRecordLiteralRootsPack)
                    ]

        let fullyAppliedProjectionReturningDescriptorDiagnostic body =
            let returnTypeIsProjector =
                definition.ReturnTypeTokens
                |> Option.bind TypeSignatures.parseType
                |> Option.exists (function
                    | TypeName(nameSegments, _) when
                        matchesKnownType CompilerKnownSymbols.ProjectorType nameSegments -> true
                    | _ -> false)

            match returnTypeIsProjector, body with
            | true, Apply(Name [ projectionName ], arguments) ->
                environment.VisibleProjections
                |> Map.tryFind projectionName
                |> Option.filter (fun projectionInfo -> List.length projectionInfo.Binders = List.length arguments)
                |> Option.map (fun _ ->
                    [
                        Diagnostics.errorFact
                            "KFrontIR"
                            (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                            None
                            []
                            (DiagnosticFact.surfaceElaboration FullyAppliedProjectionProducesProjectedFocusNotDescriptorValue)
                    ])
                |> Option.defaultValue []
            | _ ->
                []

        let rec validateProjectionDescriptorApplications (aliases: Map<string, ProjectionDescriptorAliasInfo>) (expression: SurfaceExpression) =
            let recurse = validateProjectionDescriptorApplications aliases

            match expression with
            | SyntaxQuote inner
            | SyntaxSplice inner
            | TopLevelSyntaxSplice inner
            | CodeQuote inner
            | CodeSplice inner ->
                recurse inner
            | TypeSyntaxTokens _ ->
                []
            | Handle(_, label, body, returnClause, operationClauses) ->
                recurse label
                @ recurse body
                @ recurse returnClause.Body
                @ (operationClauses |> List.collect (fun clause -> recurse clause.Body))
            | Apply(Name [ aliasName ], [ rootsArgument ]) ->
                let nested = validateProjectionDescriptorApplications aliases rootsArgument

                match aliases |> Map.tryFind aliasName with
                | Some aliasInfo ->
                    nested @ descriptorApplicationDiagnostics aliasInfo.RemainingPlaceBinders rootsArgument
                | None ->
                    nested
            | Apply(callee, arguments) ->
                recurse callee @ (arguments |> List.collect recurse)
            | LocalLet(binding, value, body) ->
                let valueDiagnostics = recurse value
                let shadowedAliases =
                    collectPatternNames binding.Pattern
                    |> List.fold (fun current name -> Map.remove name current) aliases

                let bodyAliases =
                    match binding.Pattern, tryProjectionDescriptorAlias value with
                    | NamePattern aliasName, Some aliasInfo -> Map.add aliasName aliasInfo shadowedAliases
                    | _ -> shadowedAliases

                valueDiagnostics @ validateProjectionDescriptorApplications bodyAliases body
            | LocalSignature(declaration, body) ->
                validateProjectionDescriptorApplications (Map.remove declaration.Name aliases) body
            | LocalTypeAlias(_, body) ->
                recurse body
            | LocalScopedEffect(_, body) ->
                recurse body
            | Lambda(parameters, body) ->
                let bodyAliases =
                    parameters
                    |> List.fold (fun current parameter -> Map.remove parameter.Name current) aliases

                validateProjectionDescriptorApplications bodyAliases body
            | IfThenElse(condition, whenTrue, whenFalse) ->
                recurse condition @ recurse whenTrue @ recurse whenFalse
            | Match(scrutinee, cases) ->
                recurse scrutinee
                @ (cases
                   |> List.collect (fun caseClause ->
                       (caseClause.Guard |> Option.map recurse |> Option.defaultValue [])
                       @ recurse caseClause.Body))
            | RecordLiteral fields ->
                fields |> List.collect (fun field -> recurse field.Value)
            | Seal(value, _) ->
                recurse value
            | RecordUpdate(receiver, fields) ->
                recurse receiver @ (fields |> List.collect (fun field -> recurse field.Value))
            | MemberAccess(receiver, _, arguments) ->
                recurse receiver @ (arguments |> List.collect recurse)
            | SafeNavigation(receiver, navigation) ->
                recurse receiver @ (navigation.Arguments |> List.collect recurse)
            | TagTest(receiver, _) ->
                recurse receiver
            | Do statements ->
                validateProjectionDescriptorDoStatements aliases statements
            | MonadicSplice inner
            | ExplicitImplicitArgument inner
            | InoutArgument inner
            | Unary(_, inner) ->
                recurse inner
            | NamedApplicationBlock fields ->
                fields |> List.collect (fun field -> recurse field.Value)
            | Binary(left, _, right)
            | Elvis(left, right) ->
                recurse left @ recurse right
            | Comprehension comprehension ->
                recurse comprehension.Lowered
            | PrefixedString(_, parts) ->
                parts
                |> List.collect (function
                    | StringText _ -> []
                    | StringInterpolation(inner, _) -> recurse inner)
            | Literal _
            | NumericLiteral _
            | KindQualifiedName _
            | Name _ ->
                []

        and validateProjectionDescriptorDoStatements (aliases: Map<string, ProjectionDescriptorAliasInfo>) (statements: SurfaceDoStatement list) =
            match statements with
            | [] ->
                []
            | statement :: rest ->
                match statement with
                | DoLet(binding, expression)
                | DoBind(binding, expression)
                | DoUsing(binding, expression) ->
                    let nextAliases =
                        collectPatternNames binding.Pattern
                        |> List.fold (fun current name -> Map.remove name current) aliases

                    validateProjectionDescriptorApplications aliases expression
                    @ validateProjectionDescriptorDoStatements nextAliases rest
                | DoLetQuestion(binding, expression, failure) ->
                    let nextAliases =
                        collectPatternNames binding.Pattern
                        |> List.fold (fun current name -> Map.remove name current) aliases

                    let failureDiagnostics =
                        failure
                        |> Option.map (fun block -> validateProjectionDescriptorDoStatements aliases block.Body)
                        |> Option.defaultValue []

                    validateProjectionDescriptorApplications aliases expression
                    @ failureDiagnostics
                    @ validateProjectionDescriptorDoStatements nextAliases rest
                | DoVar(name, expression) ->
                    validateProjectionDescriptorApplications aliases expression
                    @ validateProjectionDescriptorDoStatements (Map.remove name aliases) rest
                | DoAssign(target, expression) ->
                    validateProjectionDescriptorApplications aliases expression
                    @ validateProjectionDescriptorDoStatements aliases rest
                | DoDefer expression
                | DoExpression expression
                | DoReturn expression ->
                    validateProjectionDescriptorApplications aliases expression
                    @ validateProjectionDescriptorDoStatements aliases rest
                | DoIf(condition, whenTrue, whenFalse) ->
                    validateProjectionDescriptorApplications aliases condition
                    @ validateProjectionDescriptorDoStatements aliases whenTrue
                    @ validateProjectionDescriptorDoStatements aliases whenFalse
                    @ validateProjectionDescriptorDoStatements aliases rest
                | DoWhile(condition, body) ->
                    validateProjectionDescriptorApplications aliases condition
                    @ validateProjectionDescriptorDoStatements aliases body
                    @ validateProjectionDescriptorDoStatements aliases rest

        let validateLocalImplicitResolution body =
            let normalizeVisible typeExpr =
                typeExpr
                |> qualifyVisibleTypeNames environment
                |> normalizeTypeAliases environment.VisibleTypeAliases

            let normalizedKey typeExpr =
                normalizeVisible typeExpr |> TypeSignatures.toText

            let implicitQuantity quantity =
                quantity |> Option.defaultValue QuantityOmega

            let addCandidate name quantity typeExpr scope =
                let key = normalizedKey typeExpr
                let existing = scope |> Map.tryFind key |> Option.defaultValue []
                Map.add key ((name, implicitQuantity quantity) :: existing) scope

            let addImplicitBinding (binding: SurfaceBindPattern) valueType scope =
                if binding.IsImplicit then
                    collectPatternNames binding.Pattern
                    |> List.fold (fun current name -> addCandidate name binding.Quantity valueType current) scope
                else
                    scope

            let addImplicitParameter scope (parameter: Parameter) =
                if parameter.IsImplicit then
                    parameter.TypeTokens
                    |> Option.bind TypeSignatures.parseType
                    |> Option.map (fun parameterType ->
                        addCandidate parameter.Name parameter.Quantity (qualifyVisibleTypeNames environment parameterType) scope)
                    |> Option.defaultValue scope
                else
                    scope

            let initialScope =
                effectiveParameters
                |> List.fold addImplicitParameter Map.empty

            let resolveCandidates scopes parameterType =
                let key = normalizedKey parameterType

                scopes
                |> List.tryPick (fun scope ->
                    scope
                    |> Map.tryFind key
                    |> Option.filter (fun candidates -> not (List.isEmpty candidates)))

            let implicitDemandDiagnostics inEscapingLambda scopes (bindingInfo: BindingSchemeInfo) arguments =
                match bindingInfo.ParameterLayouts with
                | Some layouts ->
                    let parameterTypes, _ = TypeSignatures.schemeParts bindingInfo.Scheme

                    if List.length layouts <> List.length parameterTypes then
                        []
                    else
                        let visibleExplicitParameterCount =
                            List.zip layouts parameterTypes
                            |> List.filter (fun (layout, parameterType) ->
                                not layout.IsImplicit
                                && not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType))
                            |> List.length

                        let hasExplicitImplicitArgument =
                            arguments
                            |> List.exists (function
                                | ExplicitImplicitArgument _ -> true
                                | _ -> false)

                        if hasExplicitImplicitArgument
                           || (arguments.IsEmpty && visibleExplicitParameterCount > 0) then
                            []
                        else
                            List.zip layouts parameterTypes
                            |> List.collect (fun (layout, parameterType) ->
                                if not layout.IsImplicit
                                   || isCompileTimeArgumentType environment.VisibleTypeAliases parameterType then
                                    []
                                else
                                    match resolveCandidates scopes parameterType with
                                    | None ->
                                        []
                                    | Some candidates when List.length candidates > 1 ->
                                        [ makeSurfaceElaborationDiagnostic
                                            ImplicitApplicationArgumentAmbiguous ]
                                    | Some [ _, QuantityZero ] ->
                                        [ makeSurfaceElaborationDiagnostic
                                            QuantityZeroImplicitCannotSatisfyRuntimeParameter ]
                                    | Some [ _, QuantityBorrow _ ] when inEscapingLambda ->
                                        [ Diagnostics.errorFact
                                            "KFrontIR"
                                            (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                            None
                                            []
                                            (DiagnosticFact.qttBorrowEscape LambdaCapturesBorrowedRegion) ]
                                    | Some _ ->
                                        [])
                | None ->
                    []

            let rec validateExpr inEscapingLambda scopes expression =
                let recurse = validateExpr inEscapingLambda scopes

                match expression with
                | SyntaxQuote inner
                | SyntaxSplice inner
                | TopLevelSyntaxSplice inner
                | CodeQuote inner
                | CodeSplice inner ->
                    recurse inner
                | TypeSyntaxTokens _ ->
                    []
                | Handle(_, label, body, returnClause, operationClauses) ->
                    recurse label
                    @ recurse body
                    @ recurse returnClause.Body
                    @ (operationClauses |> List.collect (fun clause -> recurse clause.Body))
                | Apply(Name [ calleeName ], arguments) ->
                    let bindingDiagnostics =
                        if ordinarySurfaceNameShadowsVisiblePreludeBinding environment Map.empty calleeName then
                            []
                        else
                            environment.VisibleBindings
                            |> Map.tryFind calleeName
                            |> Option.map (fun bindingInfo -> implicitDemandDiagnostics inEscapingLambda scopes bindingInfo arguments)
                            |> Option.defaultValue []

                    bindingDiagnostics @ (arguments |> List.collect recurse)
                | Name [ calleeName ] ->
                    if ordinarySurfaceNameShadowsVisiblePreludeBinding environment Map.empty calleeName then
                        []
                    else
                        environment.VisibleBindings
                        |> Map.tryFind calleeName
                        |> Option.map (fun bindingInfo -> implicitDemandDiagnostics inEscapingLambda scopes bindingInfo [])
                        |> Option.defaultValue []
                | Apply(callee, arguments) ->
                    recurse callee @ (arguments |> List.collect recurse)
                | LocalSignature(_, nestedBody) ->
                    validateExpr inEscapingLambda scopes nestedBody
                | LocalTypeAlias(_, nestedBody) ->
                    validateExpr inEscapingLambda scopes nestedBody
                | LocalLet(binding, value, nestedBody) ->
                    let valueDiagnostics = recurse value
                    let valueType =
                        binding.TypeTokens
                        |> Option.bind TypeSignatures.parseType
                        |> Option.map (qualifyVisibleTypeNames environment)
                        |> Option.orElseWith (fun () -> inferValidationExpressionType environment freshCounter Map.empty value)
                    let nestedScopes =
                        valueType
                        |> Option.map (fun inferredType -> (addImplicitBinding binding inferredType Map.empty) :: scopes)
                        |> Option.defaultValue scopes

                    valueDiagnostics @ validateExpr inEscapingLambda nestedScopes nestedBody
                | LocalScopedEffect(_, nestedBody) ->
                    validateExpr inEscapingLambda scopes nestedBody
                | Lambda(parameters, nestedBody) ->
                    let lambdaScope =
                        parameters
                        |> List.fold addImplicitParameter Map.empty

                    validateExpr true (lambdaScope :: scopes) nestedBody
                | IfThenElse(condition, whenTrue, whenFalse) ->
                    recurse condition @ recurse whenTrue @ recurse whenFalse
                | Match(scrutinee, cases) ->
                    recurse scrutinee
                    @ (cases
                       |> List.collect (fun caseClause ->
                           (caseClause.Guard |> Option.map recurse |> Option.defaultValue [])
                           @ recurse caseClause.Body))
                | RecordLiteral fields ->
                    fields |> List.collect (fun field -> recurse field.Value)
                | RecordUpdate(receiver, fields) ->
                    recurse receiver @ (fields |> List.collect (fun field -> recurse field.Value))
                | MemberAccess(receiver, _, arguments) ->
                    recurse receiver @ (arguments |> List.collect recurse)
                | SafeNavigation(receiver, navigation) ->
                    recurse receiver @ (navigation.Arguments |> List.collect recurse)
                | TagTest(receiver, _) ->
                    recurse receiver
                | Do statements ->
                    validateDo inEscapingLambda scopes statements
                | MonadicSplice inner
                | ExplicitImplicitArgument inner
                | InoutArgument inner
                | Unary(_, inner)
                | Seal(inner, _) ->
                    recurse inner
                | NamedApplicationBlock fields ->
                    fields |> List.collect (fun field -> recurse field.Value)
                | Binary(left, _, right)
                | Elvis(left, right) ->
                    recurse left @ recurse right
                | Comprehension comprehension ->
                    recurse comprehension.Lowered
                | PrefixedString(_, parts) ->
                    parts
                    |> List.collect (function
                        | StringText _ -> []
                        | StringInterpolation(inner, _) -> recurse inner)
                | Literal _
                | NumericLiteral _
                | KindQualifiedName _
                | Name _ ->
                    []

            and validateDo inEscapingLambda scopes statements =
                match statements with
                | [] ->
                    []
                | statement :: rest ->
                    match statement with
                    | DoLet(binding, expression)
                    | DoBind(binding, expression) ->
                        let expressionDiagnostics = validateExpr inEscapingLambda scopes expression
                        let valueType =
                            binding.TypeTokens
                            |> Option.bind TypeSignatures.parseType
                            |> Option.map (qualifyVisibleTypeNames environment)
                            |> Option.orElseWith (fun () ->
                                inferValidationExpressionType environment freshCounter Map.empty expression
                                |> Option.map (fun typeExpr ->
                                    match statement with
                                    | DoBind _ -> unwrapBindPayloadType typeExpr
                                    | _ -> typeExpr))

                        let restScopes =
                            valueType
                            |> Option.map (fun inferredType -> (addImplicitBinding binding inferredType Map.empty) :: scopes)
                            |> Option.defaultValue scopes

                        expressionDiagnostics @ validateDo inEscapingLambda restScopes rest
                    | DoLetQuestion(binding, expression, failure) ->
                        let expressionDiagnostics = validateExpr inEscapingLambda scopes expression
                        let valueType =
                            binding.TypeTokens
                            |> Option.bind TypeSignatures.parseType
                            |> Option.map (qualifyVisibleTypeNames environment)
                            |> Option.orElseWith (fun () -> inferValidationExpressionType environment freshCounter Map.empty expression)

                        let restScopes =
                            valueType
                            |> Option.map (fun inferredType -> (addImplicitBinding binding inferredType Map.empty) :: scopes)
                            |> Option.defaultValue scopes

                        let failureDiagnostics =
                            failure
                            |> Option.map (fun block -> validateDo inEscapingLambda scopes block.Body)
                            |> Option.defaultValue []

                        expressionDiagnostics @ failureDiagnostics @ validateDo inEscapingLambda restScopes rest
                    | DoUsing(binding, expression) ->
                        validateExpr inEscapingLambda scopes expression @ validateDo inEscapingLambda scopes rest
                    | DoVar(_, expression)
                    | DoAssign(_, expression)
                    | DoDefer expression
                    | DoExpression expression
                    | DoReturn expression ->
                        validateExpr inEscapingLambda scopes expression @ validateDo inEscapingLambda scopes rest
                    | DoIf(condition, whenTrue, whenFalse) ->
                        validateExpr inEscapingLambda scopes condition
                        @ validateDo inEscapingLambda scopes whenTrue
                        @ validateDo inEscapingLambda scopes whenFalse
                        @ validateDo inEscapingLambda scopes rest
                    | DoWhile(condition, body) ->
                        validateExpr inEscapingLambda scopes condition
                        @ validateDo inEscapingLambda scopes body
                        @ validateDo inEscapingLambda scopes rest

            validateExpr false [ initialScope ] body

        let parameterRecordDiagnostics =
            effectiveParameters
            |> List.collect (fun parameter ->
                parameter.TypeTokens
                |> Option.bind tryRecordInfoFromTypeTokens
                |> Option.map validateRecordSurfaceInfo
                |> Option.defaultValue [])

        let activePatternDeclarationDiagnostics =
            if not definition.IsPattern then
                []
            else
                let explicitParameterCount =
                    effectiveParameters
                    |> List.filter (fun parameter -> not parameter.IsImplicit)
                    |> List.length

                let binderDiagnostics =
                    if explicitParameterCount = 0 then
                        [
                            Diagnostics.errorFact
                                "KFrontIR"
                                (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                None
                                []
                                (DiagnosticFact.surfaceElaboration ActivePatternDeclarationRequiresExplicitScrutineeBinder)
                        ]
                    else
                        []

                let resultDiagnostics =
                    scheme
                    |> Option.map (fun parsedScheme ->
                        if isMonadicType parsedScheme.Body then
                            [
                                Diagnostics.errorFact
                                    "KFrontIR"
                                    (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                    None
                                    []
                                    (DiagnosticFact.surfaceElaboration ActivePatternDeclarationResultMustNotBeMonadic)
                            ]
                        else
                            [])
                    |> Option.defaultValue []

                binderDiagnostics @ resultDiagnostics

        let directRecordLiteralBodyDiagnostics body =
            let expectedRecordInfo =
                definition.ReturnTypeTokens
                |> Option.bind tryRecordInfoFromTypeTokens

            match body, expectedRecordInfo with
            | RecordLiteral fields, Some recordInfo when recordInfoHasOpaqueMembers recordInfo ->
                validateRecordLiteral fields
                @ validateRecordLiteralFieldValuesWithRecordInfo
                    (validateExpression localTypes Map.empty parameterNames)
                    recordInfo
                    fields
            | _ ->
                validateExpression localTypes Map.empty parameterNames body

        parameterRecordDiagnostics
        @ inoutDeclarationDiagnostics
        @ activePatternDeclarationDiagnostics
        @ declaredParameterContextConflictDiagnostics
        @
            match effectiveBody with
            | Some body ->
                let bodyExpressionDiagnostics = directRecordLiteralBodyDiagnostics body
                let suppressExpectedBodyDiagnostics =
                    not (List.isEmpty inoutDeclarationDiagnostics)
                    || (bodyExpressionDiagnostics
                        |> List.exists (fun diagnostic ->
                            diagnostic.Code = DiagnosticCode.QttInoutMarkerRequired
                            || diagnostic.Code = DiagnosticCode.QttInoutMarkerUnexpected))

                bodyExpressionDiagnostics
                @ siblingFallbackDiagnostics body
                @ validateLocalImplicitResolution body
                @ (if suppressExpectedBodyDiagnostics then [] else validateExpectedBody localTypes body)
                @ validateInoutPlacement false body
                @ validateProjectionDescriptorApplications Map.empty body
                @ fullyAppliedProjectionReturningDescriptorDiagnostic body
            | None -> []

    let validateSurfaceModules
        backendProfile
        (frontendModules: KFrontIRModule list)
        (hostModules: Map<ModuleIdentity, HostBindings.HostModuleDescription>)
        =
        let surfaceIndex = buildSurfaceIndex frontendModules hostModules
        let effectDeclarationsByModule = buildEffectDeclarationIndex frontendModules

        let duplicateDeclarationDiagnostics =
            let moduleKey (frontendModule: KFrontIRModule) =
                frontendModule.ModuleIdentity
                |> Option.map SyntaxFacts.moduleNameToText
                |> Option.defaultValue $"<file:{frontendModule.FilePath}>"

            let makeDuplicateDiagnostic moduleName message =
                Diagnostics.errorFact
                    "KFrontIR"
                    (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                    None
                    []
                    (DiagnosticFact.duplicateDeclaration message (Some moduleName))

            frontendModules
            |> List.groupBy moduleKey
            |> List.collect (fun (_, moduleGroup) ->
                let moduleName =
                    moduleGroup
                    |> List.tryHead
                    |> Option.map (fun frontendModule -> moduleNameText frontendModule.ModuleIdentity)
                    |> Option.defaultValue "<unknown>"

                let groupedDeclarations =
                    moduleGroup
                    |> List.collect (fun frontendModule ->
                        frontendModule.Declarations
                        |> List.map (fun declaration -> frontendModule.FilePath, declaration))

                let termNamespaceDiagnostics =
                    groupedDeclarations
                    |> List.collect (fun (filePath, declaration) ->
                        match declaration with
                        | SignatureDeclaration declaration ->
                            [ declaration.Name, TermSignatureContributor, Some filePath ]
                        | LetDeclaration declaration ->
                            declaration.Name
                            |> Option.map (fun name -> [ name, TermLetContributor, Some filePath ])
                            |> Option.defaultValue []
                        | ProjectionDeclarationNode declaration ->
                            [ declaration.Name, TermProjectionContributor, Some filePath ]
                        | ExpectDeclarationNode (ExpectTermDeclaration declaration) ->
                            [ declaration.Name, TermExpectationContributor, Some filePath ]
                        | _ ->
                            [])
                    |> List.groupBy (fun (name, _, _) -> name)
                    |> List.choose (fun (name, entries) ->
                        let count contributor =
                            entries
                            |> List.filter (fun (_, currentContributor, _) -> currentContributor = contributor)
                            |> List.length

                        let trySingleFile contributor =
                            entries
                            |> List.tryPick (fun (_, currentContributor, filePath) ->
                                if currentContributor = contributor then
                                    filePath
                                else
                                    None)

                        let signatureCount = count TermSignatureContributor
                        let letCount = count TermLetContributor
                        let projectionCount = count TermProjectionContributor
                        let expectationCount = count TermExpectationContributor
                        let totalCount = entries.Length

                        let signatureLetsShareAFile =
                            match trySingleFile TermSignatureContributor, trySingleFile TermLetContributor with
                            | Some signatureFilePath, Some letFilePath ->
                                String.Equals(signatureFilePath, letFilePath, StringComparison.Ordinal)
                            | _ ->
                                false

                        let isAllowedTermNamespaceShape =
                            match totalCount with
                            | 0
                            | 1 -> true
                            | _ when letCount = 1 && projectionCount = 0 && expectationCount <= 1 ->
                                signatureCount = 0 || (signatureCount = 1 && signatureLetsShareAFile)
                            | _ when letCount = 0 && projectionCount = 1 && signatureCount = 0 ->
                                expectationCount <= 1
                            | _ -> false

                        if totalCount <= 1 || isAllowedTermNamespaceShape then
                            None
                        else
                            Some(makeDuplicateDiagnostic moduleName $"Term namespace name '{name}' is declared more than once"))

                let typeNamespaceDiagnostics =
                    groupedDeclarations
                    |> List.collect (fun (_, declaration) ->
                        match declaration with
                        | DataDeclarationNode declaration ->
                            [ declaration.Name, OrdinaryTypeContributor ]
                        | TypeAliasNode declaration ->
                            [ declaration.Name, OrdinaryTypeContributor ]
                        | EffectDeclarationNode declaration ->
                            [ declaration.Name, EffectTypeContributor ]
                        | ExpectDeclarationNode (ExpectTypeDeclaration declaration) ->
                            [ declaration.Name, ExpectTypeContributor ]
                        | _ ->
                            [])
                    |> List.groupBy fst
                    |> List.choose (fun (name, entries) ->
                        let count contributor =
                            entries
                            |> List.filter (fun (_, currentContributor) -> currentContributor = contributor)
                            |> List.length

                        let ordinaryTypeCount = count OrdinaryTypeContributor
                        let effectTypeCount = count EffectTypeContributor
                        let expectTypeCount = count ExpectTypeContributor
                        let totalCount = entries.Length

                        let isAllowedTypeNamespaceShape =
                            ordinaryTypeCount = 1 && effectTypeCount = 0 && expectTypeCount = 1 && totalCount = 2

                        if totalCount <= 1 || isAllowedTypeNamespaceShape then
                            None
                        else
                            Some(makeDuplicateDiagnostic moduleName $"Type declaration '{name}' is declared more than once"))

                let traitNamespaceDiagnostics =
                    groupedDeclarations
                    |> List.collect (fun (_, declaration) ->
                        match declaration with
                        | TraitDeclarationNode declaration ->
                            [ declaration.Name, OrdinaryTraitContributor ]
                        | ExpectDeclarationNode (ExpectTraitDeclaration declaration) ->
                            [ declaration.Name, ExpectTraitContributor ]
                        | _ ->
                            [])
                    |> List.groupBy fst
                    |> List.choose (fun (name, entries) ->
                        let count contributor =
                            entries
                            |> List.filter (fun (_, currentContributor) -> currentContributor = contributor)
                            |> List.length

                        let ordinaryTraitCount = count OrdinaryTraitContributor
                        let expectTraitCount = count ExpectTraitContributor
                        let totalCount = entries.Length

                        let isAllowedTraitNamespaceShape =
                            ordinaryTraitCount = 1 && expectTraitCount = 1 && totalCount = 2

                        if totalCount <= 1 || isAllowedTraitNamespaceShape then
                            None
                        else
                            Some(makeDuplicateDiagnostic moduleName $"Trait declaration '{name}' is declared more than once"))

                let constructorNamespaceDiagnostics =
                    groupedDeclarations
                    |> List.collect (fun (_, declaration) ->
                        match declaration with
                        | DataDeclarationNode declaration ->
                            declaration.Constructors
                            |> List.map (fun constructor -> constructor.Name)
                            |> List.filter (fun name -> not (String.Equals(name, "<anonymous>", StringComparison.Ordinal)))
                        | _ ->
                            [])
                    |> List.countBy id
                    |> List.choose (fun (name, count) ->
                        if count > 1 then
                            Some(makeDuplicateDiagnostic moduleName $"Constructor declaration '{name}' is declared more than once")
                        else
                            None)

                let instanceDiagnostics =
                    groupedDeclarations
                    |> List.choose (fun (_, declaration) ->
                        match declaration with
                        | InstanceDeclarationNode declaration ->
                            Some(tokensText declaration.FullHeaderTokens)
                        | _ ->
                            None)
                    |> List.countBy id
                    |> List.choose (fun (headerText, count) ->
                        if count > 1 then
                            Some(makeDuplicateDiagnostic moduleName $"Instance declaration '{headerText}' is declared more than once")
                        else
                            None)

                termNamespaceDiagnostics
                @ typeNamespaceDiagnostics
                @ traitNamespaceDiagnostics
                @ constructorNamespaceDiagnostics
                @ instanceDiagnostics)

        let validateNamedFrontendModule moduleName moduleIdentity (frontendModule: KFrontIRModule) =
            let topLevelNames =
                frontendModule.Declarations
                |> List.collect (function
                    | SignatureDeclaration declaration -> [ declaration.Name ]
                    | LetDeclaration declaration -> declaration.Name |> Option.toList
                    | ProjectionDeclarationNode declaration -> [ declaration.Name ]
                    | DataDeclarationNode declaration ->
                        declaration.Name :: (declaration.Constructors |> List.map (fun constructor -> constructor.Name))
                    | EffectDeclarationNode declaration -> [ declaration.Name ]
                    | TypeAliasNode declaration -> [ declaration.Name ]
                    | TraitDeclarationNode declaration -> [ declaration.Name ]
                    | ExpectDeclarationNode (ExpectTermDeclaration declaration) -> [ declaration.Name ]
                    | ExpectDeclarationNode (ExpectTypeDeclaration declaration) -> [ declaration.Name ]
                    | ExpectDeclarationNode (ExpectTraitDeclaration declaration) -> [ declaration.Name ]
                    | _ -> [])
                |> Set.ofList

            let topLevelEffects =
                let localEffects =
                    frontendModule.Declarations
                    |> List.choose (function
                        | EffectDeclarationNode declaration -> Some(EffectSemantics.ensureTopLevel moduleIdentity declaration)
                        | _ -> None)

                localEffects @ importedEffectDeclarations surfaceIndex effectDeclarationsByModule moduleIdentity

            withScopedEffectDeclarations moduleIdentity topLevelEffects (fun () ->
                let makeDiagnostic kind message =
                    Diagnostics.errorFact "KFrontIR" (Some(KFrontIRPhase.phaseName CORE_LOWERING)) None [] (DiagnosticFact.simple kind message)

                let makeNameUnresolvedDiagnostic name =
                    Diagnostics.errorFact
                        "KFrontIR"
                        (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                        None
                        []
                        (DiagnosticFact.nameUnresolved name)

                let makeSurfaceElaborationDiagnostic evidence =
                    Diagnostics.errorFact
                        "KFrontIR"
                        (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                        None
                        []
                        (DiagnosticFact.surfaceElaboration evidence)

                let _, sourceBindingInfosByName =
                    buildSourceBindingInfosByName moduleIdentity frontendModule.Declarations

                let visibleComponents =
                    computeVisibleEnvironmentComponents surfaceIndex moduleIdentity

                let visibleBindings =
                    sourceBindingInfosByName
                    |> Map.fold (fun state name bindingInfo -> Map.add name bindingInfo state) (mergeVisibleBindings surfaceIndex moduleIdentity)

                let baseEnvironment =
                    buildBaseBindingLoweringEnvironment
                        surfaceIndex
                        moduleIdentity
                        (topLevelDefinitionNames frontendModule.Declarations)
                        visibleBindings
                        visibleComponents

                let environment =
                    let staticObjectAliases =
                        let localAliases =
                            buildStaticObjectAliasesForModule baseEnvironment frontendModule.Declarations

                        topLevelEffects
                        |> List.filter (fun declaration -> declaration.Name.Contains("."))
                        |> List.fold (fun current declaration ->
                            let semanticDeclaration =
                                declaration
                                |> EffectSemantics.ensureTopLevel moduleIdentity
                                |> EffectSemantics.toSemantic (Some(topLevelDeclarationIdentity moduleIdentity declaration.Name EffectDeclaration))

                            Map.add (declaration.Name.Split('.', StringSplitOptions.RemoveEmptyEntries) |> Array.toList) (scopedEffectLabelStaticObject semanticDeclaration) current) localAliases

                    { baseEnvironment with
                        VisibleStaticGroups =
                            buildVisibleStaticGroups
                                baseEnvironment.VisibleTypeFacets
                                staticObjectAliases
                                baseEnvironment.VisibleTraits
                        VisibleStaticObjects = staticObjectAliases }

                let hasUnknownNonQualifiedImportSurface =
                    frontendModule.Declarations
                    |> List.exists (function
                        | ImportDeclaration (_, specs) ->
                            specs
                            |> List.exists (fun spec ->
                                match spec.Selection, spec.Source with
                                | QualifiedOnly, _ ->
                                    false
                                | _, Url _ ->
                                    true
                                | _, Dotted moduleSegments ->
                                    surfaceIndex.ContainsKey(moduleIdentityOfSegments moduleSegments) |> not)
                        | _ ->
                            false)

                let allowUnresolvedCallDiagnostics =
                    not (frontendModule.Diagnostics |> List.exists (fun diagnostic -> diagnostic.Severity = Error))
                    && not hasUnknownNonQualifiedImportSurface

                let knownSurfaceTermNames =
                    let preludeContract = IntrinsicCatalog.bundledPreludeExpectContract ()
                    let standardRuntimeNames =
                        Set.ofList
                            [ "bindModule"; "bindModuleOwned"; "bridgePackageValue"; "bridgePackageOrigin"; "bridgeFailureToCastBlame"
                              "checkedCast"; "checkedCastWith"; "sameDynRep"; "toDyn"; "toDynWith"
                              "Conservative"; "Exact"; "IntoKappa"; "LaterUse"; "Lossy"; "OutOfKappa" ]

                    let compilerKnownSurfaceTerms =
                        Set.ofList
                            [ "thunk"
                              "lazy"
                              "force"
                              "captureBorrow"
                              "withBorrowView"
                              "fork"
                              "defEqSyntax"
                              "headSymbolSyntax"
                              "sameSymbol" ]

                    let visibleTraitMemberNames =
                        environment.VisibleTraits
                        |> Map.values
                        |> Seq.collect (fun traitInfo -> traitInfo.Members.Keys)
                        |> Set.ofSeq

                    [ topLevelNames
                      preludeContract.TermNames
                      preludeContract.TypeNames
                      preludeContract.TraitNames
                      Set.ofList Stdlib.FixedPreludeConstructors
                      IntrinsicCatalog.namedIntrinsicTermNames ()
                      standardRuntimeNames
                      compilerKnownSurfaceTerms
                      environment.VisibleBindings |> Map.keys |> Set.ofSeq
                      environment.VisibleConstructors |> Map.keys |> Set.ofSeq
                      collectImportedOrdinarySurfaceNames surfaceIndex moduleIdentity
                      (environment.VisibleModulePaths
                       |> Map.keys
                       |> Seq.map SyntaxFacts.moduleNameToText
                       |> Set.ofSeq)
                      (environment.VisibleStaticGroups
                       |> Map.keys
                       |> Seq.map SyntaxFacts.moduleNameToText
                       |> Set.ofSeq)
                      visibleTraitMemberNames
                      environment.ConstrainedMembers |> Map.keys |> Set.ofSeq ]
                    |> Set.unionMany
                    |> Set.remove "<anonymous>"

                let ordinarySurfaceNameShadowsVisiblePreludeBinding
                    (_environment: BindingLoweringEnvironment)
                    (localTypes: Map<string, TypeExpr>)
                    name
                    =
                    currentModuleTopLevelDefinitionShadowsVisibleImportedBinding environment localTypes name

                let validateProjectionDeclaration (declaration: ProjectionDeclaration) =
                    let placeBinders =
                        declaration.Binders
                        |> List.choose (function
                            | ProjectionPlaceBinder binder -> Some binder
                            | ProjectionValueBinder _ -> None)

                    let placeBinderNames = placeBinders |> List.map (fun binder -> binder.Name) |> Set.ofList

                    let missingPlaceDiagnostics =
                        if List.isEmpty placeBinders then
                            [
                                Diagnostics.errorFact
                                    "KFrontIR"
                                    (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                    None
                                    []
                                    (DiagnosticFact.surfaceElaboration ProjectionDefinitionRequiresPlaceBinder)
                            ]
                        else
                            []

                    let rec selectorYieldDiagnostics body =
                        match body with
                        | ProjectionYield(Name(root :: _)) when Set.contains root placeBinderNames ->
                            []
                        | ProjectionYield(Apply(Name [ projectionName ], _)) ->
                            match environment.VisibleProjections |> Map.tryFind projectionName with
                            | Some nestedProjection ->
                                match nestedProjection.Body with
                                | Some(ProjectionAccessors _) ->
                                    [
                                        Diagnostics.errorFact
                                            "KFrontIR"
                                            (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                            None
                                            []
                                            (DiagnosticFact.surfaceElaboration
                                                (SelectorProjectionYieldInvalid ProjectionYieldMustDenoteStablePlaceNotAccessorBundle))
                                    ]
                                | _ ->
                                    []
                            | None ->
                                [
                                    Diagnostics.errorFact
                                        "KFrontIR"
                                        (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                        None
                                        []
                                        (DiagnosticFact.surfaceElaboration
                                            (SelectorProjectionYieldInvalid ProjectionYieldMustDenoteStablePlace))
                                ]
                        | ProjectionYield _ ->
                            [
                                Diagnostics.errorFact
                                    "KFrontIR"
                                    (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                    None
                                    []
                                    (DiagnosticFact.surfaceElaboration
                                        (SelectorProjectionYieldInvalid ProjectionYieldMustBeRootedInPlaceBinder))
                            ]
                        | ProjectionIfThenElse(_, whenTrue, whenFalse) ->
                            selectorYieldDiagnostics whenTrue @ selectorYieldDiagnostics whenFalse
                        | ProjectionMatch(_, cases) ->
                            cases |> List.collect (fun caseClause -> selectorYieldDiagnostics caseClause.Body)
                        | ProjectionAccessors _ ->
                            []

                    let expandedDiagnostics =
                        if List.isEmpty placeBinders then
                            []
                        else
                            match declaration.Body with
                            | Some(ProjectionAccessors clauses) ->
                                let placeCountDiagnostics =
                                    if List.length placeBinders = 1 then
                                        []
                                    else
                                        [
                                            Diagnostics.errorFact
                                                "KFrontIR"
                                                (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                                None
                                                []
                                                (DiagnosticFact.surfaceElaboration
                                                    ExpandedAccessorProjectionRequiresExactlyOnePlaceBinder)
                                        ]

                                let duplicateDiagnostics =
                                    clauses
                                    |> List.map (function
                                        | ProjectionGet _ -> "get"
                                        | ProjectionInout _ -> "inout"
                                        | ProjectionSet _ -> "set"
                                        | ProjectionSink _ -> "sink")
                                    |> List.countBy id
                                    |> List.choose (fun (kind, count) ->
                                        if count > 1 then
                                            Some(
                                                Diagnostics.errorFact
                                                    "KFrontIR"
                                                    (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                                    None
                                                    []
                                                    (DiagnosticFact.surfaceElaboration
                                                        (ProjectionAccessorClauseDeclaredMoreThanOnce kind))
                                            )
                                        else
                                            None)

                                placeCountDiagnostics @ duplicateDiagnostics
                            | Some body ->
                                selectorYieldDiagnostics body
                            | None ->
                                []

                    missingPlaceDiagnostics @ expandedDiagnostics

                let moduleAttributeDiagnostics =
                    let supportedAttributes =
                        ModuleAttribute.knownAttributes
                        |> Set.toList
                        |> List.sort

                    frontendModule.ModuleAttributes
                    |> List.choose (fun attributeName ->
                        if ModuleAttribute.isKnown attributeName then
                            None
                        else
                            Some(
                                Diagnostics.errorFact
                                    "KFrontIR"
                                    (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                    None
                                    []
                                    (DiagnosticFact.surfaceElaboration
                                        (UnknownModuleAttribute(attributeName, supportedAttributes)))
                            ))

                let totalityAssertionDiagnostics =
                    let allowAssertTerminates = moduleHasAttribute frontendModule ModuleAttribute.AllowAssertTerminates
                    let allowAssertReducible = moduleHasAttribute frontendModule ModuleAttribute.AllowAssertReducible

                    frontendModule.Declarations
                    |> List.choose (function
                        | LetDeclaration definition ->
                            match definition.TotalityAssertion with
                            | Some AssertTerminatesAssertion when not allowAssertTerminates ->
                                let bindingName = definition.Name |> Option.defaultValue "<anonymous>"
                                Some(
                                    Diagnostics.errorFact
                                        "KFrontIR"
                                        (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                        None
                                        []
                                        (DiagnosticFact.surfaceElaboration
                                            (AssertTerminatesRequiresAllowAttribute bindingName))
                                )
                            | Some AssertReducibleAssertion when not allowAssertReducible ->
                                let bindingName = definition.Name |> Option.defaultValue "<anonymous>"
                                Some(
                                    Diagnostics.errorFact
                                        "KFrontIR"
                                        (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                        None
                                        []
                                        (DiagnosticFact.surfaceElaboration
                                            (AssertReducibleRequiresAllowAttribute bindingName))
                                )
                            | _ ->
                                None
                        | _ ->
                            None)

                let typeAliasCycleDiagnostics =
                    let rec referencedTypeNames typeExpr =
                        seq {
                            match typeExpr with
                            | TypeLevelLiteral _ ->
                                ()
                            | TypeUniverse None ->
                                ()
                            | TypeUniverse(Some universeExpr) ->
                                yield! referencedTypeNames universeExpr
                            | TypeIntrinsic _ ->
                                ()
                            | TypeApply(callee, arguments) ->
                                yield! referencedTypeNames callee

                                for argument in arguments do
                                    yield! referencedTypeNames argument
                            | TypeLambda(_, parameterSort, body) ->
                                yield! referencedTypeNames parameterSort
                                yield! referencedTypeNames body
                            | TypeDelay inner
                            | TypeMemo inner
                            | TypeForce inner ->
                                yield! referencedTypeNames inner
                            | TypeProject(target, _) ->
                                yield! referencedTypeNames target
                            | TypeName(name, arguments) ->
                                match name with
                                | [ localName ] -> yield localName
                                | _ -> ()

                                for argument in arguments do
                                    yield! referencedTypeNames argument
                            | TypeVariable _ ->
                                ()
                            | TypeArrow(_, parameterType, resultType) ->
                                yield! referencedTypeNames parameterType
                                yield! referencedTypeNames resultType
                            | TypeEquality(left, right) ->
                                yield! referencedTypeNames left
                                yield! referencedTypeNames right
                            | TypeCapture(inner, _) ->
                                yield! referencedTypeNames inner
                            | TypeEffectRow(entries, tail) ->
                                for entry in entries do
                                    yield! referencedTypeNames entry.Label
                                    yield! referencedTypeNames entry.Effect

                                match tail with
                                | Some tailType -> yield! referencedTypeNames tailType
                                | None -> ()
                            | TypeRecord fields ->
                                for field in fields do
                                    yield! referencedTypeNames field.Type
                            | TypeUnion members ->
                                for memberType in members do
                                    yield! referencedTypeNames memberType
                        }

                    let localAliases =
                        frontendModule.Declarations
                        |> List.choose (function
                            | TypeAliasNode declaration -> tryParseTypeAliasInfo moduleIdentity declaration
                            | _ -> None)
                        |> Map.ofList

                    let aliasDependencies =
                        localAliases
                        |> Map.map (fun _ aliasInfo ->
                            referencedTypeNames aliasInfo.Body
                            |> Seq.filter (fun referencedName ->
                                Map.containsKey referencedName localAliases
                                && not (List.contains referencedName aliasInfo.Parameters))
                            |> Set.ofSeq)

                    let rec reaches start current visited =
                        aliasDependencies
                        |> Map.tryFind current
                        |> Option.defaultValue Set.empty
                        |> Seq.exists (fun dependency ->
                            String.Equals(dependency, start, StringComparison.Ordinal)
                            || (not (Set.contains dependency visited)
                                && reaches start dependency (Set.add dependency visited)))

                    aliasDependencies
                    |> Map.keys
                    |> Seq.filter (fun aliasName -> reaches aliasName aliasName (Set.singleton aliasName))
                    |> Seq.distinct
                    |> Seq.map (fun aliasName ->
                        Diagnostics.errorFact
                            "KFrontIR"
                            (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                            None
                            []
                            (DiagnosticFact.surfaceElaboration (RecursiveTypeAliasDependsOnItself aliasName)))
                    |> Seq.toList

                let malformedConstructorDiagnostics =
                    let declarationKeywordNames =
                        Set.ofList [ "data"; "expect"; "export"; "import"; "instance"; "let"; "module"; "opaque"; "private"; "projection"; "public"; "trait"; "type" ]

                    let exposesRuntimeTypeField (constructor: DataConstructor) =
                        let exposedFieldTypes =
                            match constructor.Parameters with
                            | Some parameters ->
                                parameters
                                |> List.choose (fun parameter ->
                                    if parameter.ParameterIsImplicit || parameter.ParameterQuantity = Some QuantityZero then
                                        None
                                    else
                                        TypeSignatures.parseType parameter.ParameterTypeTokens)
                            | None ->
                                TypeSignatures.constructorParameterTokenGroups constructor
                                |> List.choose (fun parameterTokens ->
                                    match parameterTokens with
                                    | { Kind = AtSign } :: _ ->
                                        None
                                    | { Kind = IntegerLiteral; Text = "0" } :: _ ->
                                        None
                                    | _ ->
                                        let typeTokens =
                                            match parameterTokens |> List.tryFindIndex (fun token -> token.Kind = Colon) with
                                            | Some colonIndex when colonIndex + 1 < parameterTokens.Length ->
                                                parameterTokens |> List.skip (colonIndex + 1)
                                            | _ ->
                                                parameterTokens

                                        TypeSignatures.parseType typeTokens)

                        exposedFieldTypes
                        |> List.exists (function
                            | TypeUniverse _ -> true
                            | TypeIntrinsic UniverseClassifier -> true
                            | TypeName([ "Type" ], _) -> true
                            | _ -> false)

                    let constructorHasMalformedShape (constructor: DataConstructor) =
                        let significant = significantTokens constructor.Tokens

                        let hasUnbalancedDelimiters tokens =
                            let mutable parenDepth = 0
                            let mutable braceDepth = 0
                            let mutable bracketDepth = 0
                            let mutable setBraceDepth = 0

                            for token in tokens do
                                match token.Kind with
                                | LeftParen -> parenDepth <- parenDepth + 1
                                | RightParen -> parenDepth <- max 0 (parenDepth - 1)
                                | LeftBrace -> braceDepth <- braceDepth + 1
                                | RightBrace -> braceDepth <- max 0 (braceDepth - 1)
                                | LeftBracket -> bracketDepth <- bracketDepth + 1
                                | RightBracket -> bracketDepth <- max 0 (bracketDepth - 1)
                                | LeftSetBrace -> setBraceDepth <- setBraceDepth + 1
                                | RightSetBrace -> setBraceDepth <- max 0 (setBraceDepth - 1)
                                | _ -> ()

                            parenDepth <> 0 || braceDepth <> 0 || bracketDepth <> 0 || setBraceDepth <> 0

                        if hasUnbalancedDelimiters significant then
                            false
                        else
                            let stripConstructorName tokens =
                                let isSymbolToken token =
                                    match token.Kind with
                                    | Operator
                                    | Colon
                                    | Equals -> true
                                    | _ -> false

                                match tokens with
                                | { Kind = LeftParen } :: rest ->
                                    let rec loop remaining =
                                        match remaining with
                                        | { Kind = RightParen } :: tail ->
                                            tail
                                        | token :: tail when isSymbolToken token ->
                                            loop tail
                                        | _ ->
                                            tokens

                                    loop rest
                                | _nameToken :: rest ->
                                    rest
                                | [] ->
                                    []

                            let remainingTokens =
                                match significant with
                                | { Kind = Operator; Text = "|" } :: rest -> stripConstructorName rest
                                | _ -> stripConstructorName significant

                            match constructor.Parameters, remainingTokens with
                            | Some _, _ ->
                                false
                            | None, [] ->
                                false
                            | None, { Kind = Colon } :: typeTokens ->
                                TypeSignatures.parseScheme typeTokens |> Option.isNone
                            | None, _ ->
                                List.isEmpty (TypeSignatures.constructorFieldTypes constructor)

                    frontendModule.Declarations
                    |> List.collect (function
                        | DataDeclarationNode declaration ->
                            declaration.Constructors
                            |> List.choose (fun constructor ->
                                if Set.contains constructor.Name declarationKeywordNames then
                                    Some(
                                        Diagnostics.errorFact
                                            "KFrontIR"
                                            (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                            None
                                            []
                                            (DiagnosticFact.surfaceElaboration
                                                (ConstructorDeclarationStartsWithDeclarationKeyword(declaration.Name, constructor.Name)))
                                    )
                                elif exposesRuntimeTypeField constructor then
                                    Some(
                                        Diagnostics.errorFact
                                            "KFrontIR"
                                            (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                            None
                                            []
                                            (DiagnosticFact.surfaceElaboration
                                                (ConstructorExposesRuntimeFieldMetadataOfType constructor.Name))
                                    )
                                elif constructorHasMalformedShape constructor then
                                    Some(
                                        Diagnostics.errorFact
                                            "KFrontIR"
                                            (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                            None
                                            []
                                            (DiagnosticFact.surfaceElaboration
                                                (ConstructorDeclarationMalformedInDataType(declaration.Name, constructor.Name)))
                                    )
                                else
                                    None)
                        | _ ->
                            [])

                let patternDuplicateDiagnostics pattern =
                    let duplicateNames current =
                        collectPatternNames current
                        |> List.countBy id
                        |> List.choose (fun (name, count) ->
                            if count > 1 then
                                Some(Diagnostics.errorFact "KFrontIR" (Some(KFrontIRPhase.phaseName CORE_LOWERING)) None [] (DiagnosticFact.duplicatePatternBinder name))
                            else
                                None)

                    let rec loop current =
                        match current with
                        | AsPattern(_, inner) ->
                            duplicateNames current @ loop inner
                        | TypedPattern(inner, _) ->
                            duplicateNames current @ loop inner
                        | OrPattern alternatives ->
                            alternatives |> List.collect loop
                        | ConstructorPattern(_, arguments) ->
                            duplicateNames current @ (arguments |> List.collect loop)
                        | NamedConstructorPattern(_, fields) ->
                            duplicateNames current @ (fields |> List.collect (fun field -> loop field.Pattern))
                        | TuplePattern elements ->
                            duplicateNames current @ (elements |> List.collect loop)
                        | VariantPattern _ ->
                            duplicateNames current
                        | AnonymousRecordPattern(fields, _) ->
                            duplicateNames current @ (fields |> List.collect (fun field -> loop field.Pattern))
                        | WildcardPattern
                        | NamePattern _
                        | LiteralPattern _ ->
                            []

                    loop pattern |> List.distinctBy (fun diagnostic -> diagnostic.Message)

                let extendPatternLocalsWithoutMutation locals expectedType pattern =
                    let localCounter = ref 0
                    extendPatternLocalTypes environment localCounter locals expectedType pattern

                let orPatternBinderTypeDiagnostics expectedType pattern =
                    let normalize = normalizeTypeAliases environment.VisibleTypeAliases

                    let typedBindingsForAlternative currentExpected alternative =
                        let boundNames =
                            collectPatternNames alternative |> Set.ofList

                        let inferredBindings =
                            extendPatternLocalsWithoutMutation Map.empty currentExpected alternative

                        boundNames
                        |> Seq.choose (fun name -> inferredBindings |> Map.tryFind name |> Option.map (fun bindingType -> name, bindingType))
                        |> Map.ofSeq

                    let rec loop expected currentPattern =
                        let currentDiagnostics =
                            match currentPattern with
                            | OrPattern alternatives ->
                                match alternatives with
                                | [] ->
                                    []
                                | firstAlternative :: restAlternatives ->
                                    let firstNames = collectPatternNames firstAlternative |> Set.ofList
                                    let firstBindings = typedBindingsForAlternative expected firstAlternative

                                    restAlternatives
                                    |> List.collect (fun alternative ->
                                        let alternativeNames = collectPatternNames alternative |> Set.ofList
                                        let alternativeBindings = typedBindingsForAlternative expected alternative

                                        if alternativeNames <> firstNames then
                                            []
                                        else
                                            let comparableNames =
                                                Set.intersect
                                                    (firstBindings |> Map.keys |> Set.ofSeq)
                                                    (alternativeBindings |> Map.keys |> Set.ofSeq)

                                            comparableNames
                                            |> Seq.choose (fun name ->
                                                let firstType = firstBindings[name] |> normalize
                                                let alternativeType = alternativeBindings[name] |> normalize

                                                if TypeSignatures.definitionallyEqual firstType alternativeType then
                                                    None
                                                else
                                                    Some(
                                                        makeDiagnostic
                                                            SimpleDiagnosticKind.OrPatternBinderTypeMismatch
                                                            $"Binder '{name}' has type '{TypeSignatures.toText firstType}' in one or-pattern alternative but '{TypeSignatures.toText alternativeType}' in another."
                                                    ))
                                            |> Seq.toList)
                            | _ ->
                                []

                        let nestedDiagnostics =
                            match currentPattern with
                            | AsPattern(_, inner) ->
                                loop expected inner
                            | TypedPattern(inner, typeTokens) ->
                                let ascribedType =
                                    TypeSignatures.parseType typeTokens
                                    |> Option.map (qualifyVisibleTypeNames environment)
                                    |> Option.orElse expected

                                loop ascribedType inner
                            | TuplePattern elements ->
                                let tupleFields =
                                    elements
                                    |> List.mapi (fun index element ->
                                        { Name = $"_{index + 1}"
                                          IsImplicit = false
                                          Pattern = element })

                                loop expected (AnonymousRecordPattern(tupleFields, None))
                            | AnonymousRecordPattern(fields, _) ->
                                match expected |> Option.bind (tryCanonicalRecordType environment.VisibleTypeAliases) with
                                | Some(TypeRecord recordFields) ->
                                    fields
                                    |> List.collect (fun field ->
                                        let fieldType =
                                            recordFields
                                            |> List.tryFind (fun recordField -> String.Equals(recordField.Name, field.Name, StringComparison.Ordinal))
                                            |> Option.map (fun recordField -> recordField.Type)

                                        loop fieldType field.Pattern)
                                | _ ->
                                    fields |> List.collect (fun field -> loop None field.Pattern)
                            | ConstructorPattern(nameSegments, arguments) ->
                                let argumentTypes =
                                    match expected, tryResolveVisibleConstructorInfo environment nameSegments with
                                    | Some expectedResultType, Some constructorInfo ->
                                        let localCounter = ref 0
                                        let instantiated = TypeSignatures.instantiate "t" !localCounter constructorInfo.Scheme
                                        localCounter.Value <- !localCounter + instantiated.Forall.Length

                                        let parameterTypes, constructorResultType = TypeSignatures.schemeParts instantiated

                                        if List.length parameterTypes = List.length arguments then
                                            match
                                                TypeSignatures.tryUnifyMany
                                                    [
                                                        qualifyVisibleTypeNames environment constructorResultType,
                                                        qualifyVisibleTypeNames environment expectedResultType
                                                    ]
                                            with
                                            | Some substitution ->
                                                parameterTypes
                                                |> List.map (TypeSignatures.applySubstitution substitution >> Some)
                                            | None ->
                                                List.replicate arguments.Length None
                                        else
                                            List.replicate arguments.Length None
                                    | _ ->
                                        List.replicate arguments.Length None

                                List.zip arguments argumentTypes
                                |> List.collect (fun (argumentPattern, argumentType) -> loop argumentType argumentPattern)
                            | NamedConstructorPattern(nameSegments, fields) ->
                                let argumentTypes =
                                    match expected, tryResolveVisibleConstructorInfo environment nameSegments with
                                    | Some expectedResultType, Some constructorInfo ->
                                        let localCounter = ref 0
                                        let instantiated = TypeSignatures.instantiate "t" !localCounter constructorInfo.Scheme
                                        localCounter.Value <- !localCounter + instantiated.Forall.Length

                                        let parameterTypes, constructorResultType = TypeSignatures.schemeParts instantiated

                                        let fieldTypeMap =
                                            constructorInfo.ParameterLayouts
                                            |> Option.map (fun layouts ->
                                                layouts
                                                |> List.filter (fun parameter -> not parameter.IsImplicit)
                                                |> List.map (fun parameter -> parameter.Name)
                                                |> List.zip parameterTypes
                                                |> List.map (fun (fieldType, fieldName) -> fieldName, fieldType)
                                                |> Map.ofList)
                                            |> Option.defaultValue Map.empty

                                        match
                                            TypeSignatures.tryUnifyMany
                                                [
                                                    qualifyVisibleTypeNames environment constructorResultType,
                                                    qualifyVisibleTypeNames environment expectedResultType
                                                ]
                                        with
                                        | Some substitution ->
                                            fieldTypeMap
                                            |> Map.map (fun _ fieldType -> TypeSignatures.applySubstitution substitution fieldType)
                                        | None ->
                                            Map.empty
                                    | _ ->
                                        Map.empty

                                fields
                                |> List.collect (fun field ->
                                    let fieldType = argumentTypes |> Map.tryFind field.Name
                                    loop fieldType field.Pattern)
                            | OrPattern alternatives ->
                                alternatives |> List.collect (loop expected)
                            | VariantPattern _
                            | WildcardPattern
                            | NamePattern _
                            | LiteralPattern _ ->
                                []

                        currentDiagnostics @ nestedDiagnostics

                    loop expectedType pattern

                let unsignedRecursiveBindingDiagnostics =
                    let signatureNames =
                        frontendModule.Declarations
                        |> List.choose (function
                            | SignatureDeclaration declaration -> Some declaration.Name
                            | _ -> None)
                        |> Set.ofList

                    let patternNames pattern =
                        collectPatternNames pattern |> Set.ofList

                    let parameterNames (parameters: Parameter list) =
                        parameters |> List.map (fun parameter -> parameter.Name) |> Set.ofList

                    let rec expressionReferences target shadowed expression =
                        let references = expressionReferences target shadowed

                        match expression with
                        | Name [ name ] ->
                            String.Equals(name, target, StringComparison.Ordinal)
                            && not (Set.contains name shadowed)
                        | TypeSyntaxTokens _ ->
                            false
                        | SyntaxQuote inner
                        | SyntaxSplice inner
                        | TopLevelSyntaxSplice inner
                        | CodeQuote inner
                        | CodeSplice inner ->
                            references inner
                        | Handle(_, label, body, returnClause, operationClauses) ->
                            references label
                            || references body
                            || references returnClause.Body
                            || (operationClauses |> List.exists (fun clause -> references clause.Body))
                        | Apply(callee, arguments) ->
                            references callee || (arguments |> List.exists references)
                        | LocalLet(binding, value, body) ->
                            references value
                            || expressionReferences target (Set.union shadowed (patternNames binding.Pattern)) body
                        | LocalSignature(declaration, body) ->
                            if String.Equals(declaration.Name, target, StringComparison.Ordinal) then
                                false
                            else
                                expressionReferences target (Set.add declaration.Name shadowed) body
                        | LocalTypeAlias(_, body) ->
                            references body
                        | LocalScopedEffect(_, body) ->
                            references body
                        | Lambda(parameters, body) ->
                            expressionReferences target (Set.union shadowed (parameterNames parameters)) body
                        | IfThenElse(condition, whenTrue, whenFalse) ->
                            references condition || references whenTrue || references whenFalse
                        | Match(scrutinee, cases) ->
                            references scrutinee
                            || (cases
                                |> List.exists (fun caseClause ->
                                    let caseShadowed = Set.union shadowed (patternNames caseClause.Pattern)
                                    (caseClause.Guard |> Option.exists (expressionReferences target caseShadowed))
                                    || expressionReferences target caseShadowed caseClause.Body))
                        | RecordLiteral fields ->
                            fields |> List.exists (fun field -> references field.Value)
                        | Seal(value, _) ->
                            references value
                        | RecordUpdate(receiver, fields) ->
                            references receiver || (fields |> List.exists (fun field -> references field.Value))
                        | MemberAccess(receiver, _, arguments) ->
                            references receiver || (arguments |> List.exists references)
                        | SafeNavigation(receiver, navigation) ->
                            references receiver || (navigation.Arguments |> List.exists references)
                        | TagTest(receiver, _) ->
                            references receiver
                        | Do statements ->
                            doStatementsReference target shadowed statements
                        | MonadicSplice inner
                        | ExplicitImplicitArgument inner
                        | InoutArgument inner
                        | Unary(_, inner) ->
                            references inner
                        | NamedApplicationBlock fields ->
                            fields |> List.exists (fun field -> references field.Value)
                        | Binary(left, _, right)
                        | Elvis(left, right) ->
                            references left || references right
                        | Comprehension comprehension ->
                            references comprehension.Lowered
                        | PrefixedString(_, parts) ->
                            parts
                            |> List.exists (function
                                | StringText _ -> false
                                | StringInterpolation(inner, _) -> references inner)
                        | Literal _
                        | NumericLiteral _
                        | KindQualifiedName _
                        | Name _ ->
                            false

                    and doStatementsReference target shadowed statements =
                        match statements with
                        | [] ->
                            false
                        | statement :: rest ->
                            match statement with
                            | DoLet(binding, expression)
                            | DoBind(binding, expression)
                            | DoUsing(binding, expression) ->
                                expressionReferences target shadowed expression
                                || doStatementsReference target (Set.union shadowed (patternNames binding.Pattern)) rest
                            | DoLetQuestion(binding, expression, failure) ->
                                let failureReferences =
                                    failure
                                    |> Option.exists (fun block ->
                                        doStatementsReference target (Set.union shadowed (patternNames block.ResiduePattern.Pattern)) block.Body)

                                expressionReferences target shadowed expression
                                || failureReferences
                                || doStatementsReference target (Set.union shadowed (patternNames binding.Pattern)) rest
                            | DoVar(name, expression) ->
                                expressionReferences target shadowed expression
                                || doStatementsReference target (Set.add name shadowed) rest
                            | DoAssign(_, expression)
                            | DoDefer expression
                            | DoExpression expression
                            | DoReturn expression ->
                                expressionReferences target shadowed expression
                                || doStatementsReference target shadowed rest
                            | DoIf(condition, whenTrue, whenFalse) ->
                                expressionReferences target shadowed condition
                                || doStatementsReference target shadowed whenTrue
                                || doStatementsReference target shadowed whenFalse
                                || doStatementsReference target shadowed rest
                            | DoWhile(condition, body) ->
                                expressionReferences target shadowed condition
                                || doStatementsReference target shadowed body
                                || doStatementsReference target shadowed rest

                    frontendModule.Declarations
                    |> List.choose (function
                        | LetDeclaration definition
                            when definition.Name.IsSome
                                 && definition.Body.IsSome
                                 && not (Set.contains definition.Name.Value signatureNames) ->
                            let name = definition.Name.Value
                            let shadowed = parameterNames definition.Parameters

                            if expressionReferences name shadowed definition.Body.Value then
                                Some(
                                    Diagnostics.errorFact
                                        "KFrontIR"
                                        (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                        None
                                        []
                                        (DiagnosticFact.surfaceElaboration
                                            (TopLevelRecursiveBindingRequiresPrecedingSignature name))
                                )
                            else
                                None
                        | _ ->
                            None)

                let trivialRecursiveCycleDiagnostics =
                    frontendModule.Declarations
                    |> List.choose (function
                        | LetDeclaration definition
                            when definition.Name.IsSome
                                 && definition.Body.IsSome
                                 && List.isEmpty definition.Parameters ->
                            let name = definition.Name.Value

                            match definition.Body.Value with
                            | Name [ referencedName ] when String.Equals(referencedName, name, StringComparison.Ordinal) ->
                                Some(
                                    Diagnostics.errorFact
                                        "KFrontIR"
                                        (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                        None
                                        []
                                        (DiagnosticFact.surfaceElaboration (TrivialRecursiveCycleMustBeRejected name))
                                )
                            | _ ->
                                None
                        | _ ->
                            None)

                let expressionPatternDiagnostics initialLocalTypes expression =
                    let extendParameterLocalTypes locals (parameters: Parameter list) =
                        parameters
                        |> List.fold
                            (fun current parameter ->
                                match parameter.TypeTokens |> Option.bind TypeSignatures.parseType with
                                | Some parameterType ->
                                    Map.add parameter.Name (qualifyVisibleTypeNames environment parameterType) current
                                | None ->
                                    current)
                            locals

                    let inferExpectedType localTypes expression =
                        inferValidationExpressionType environment (ref 0) localTypes expression

                    let rec validateExpression localTypes current =
                        match current with
                        | SyntaxQuote inner
                        | SyntaxSplice inner
                        | TopLevelSyntaxSplice inner
                        | CodeQuote inner
                        | CodeSplice inner ->
                            validateExpression localTypes inner
                        | TypeSyntaxTokens _ ->
                            []
                        | LocalLet(binding, value, body) ->
                            let valueType = inferExpectedType localTypes value
                            let nextLocals = extendPatternLocalsWithoutMutation localTypes valueType binding.Pattern

                            patternDuplicateDiagnostics binding.Pattern
                            @ orPatternBinderTypeDiagnostics valueType binding.Pattern
                            @ validateExpression localTypes value
                            @ validateExpression nextLocals body
                        | LocalSignature(_, body) ->
                            validateExpression localTypes body
                        | LocalTypeAlias(_, body) ->
                            validateExpression localTypes body
                        | LocalScopedEffect(_, body) ->
                            validateExpression localTypes body
                        | Handle(_, label, body, returnClause, operationClauses) ->
                            validateExpression localTypes label
                            @ validateExpression localTypes body
                            @ validateExpression localTypes returnClause.Body
                            @ (operationClauses |> List.collect (fun clause -> validateExpression localTypes clause.Body))
                        | Lambda(parameters, body) ->
                            validateExpression (extendParameterLocalTypes localTypes parameters) body
                        | IfThenElse(condition, whenTrue, whenFalse) ->
                            validateExpression localTypes condition
                            @ validateExpression localTypes whenTrue
                            @ validateExpression localTypes whenFalse
                        | Match(scrutinee, cases) ->
                            let scrutineeType = inferExpectedType localTypes scrutinee

                            validateExpression localTypes scrutinee
                            @ (cases
                               |> List.collect (fun caseClause ->
                                   let caseLocals =
                                       extendPatternLocalsWithoutMutation localTypes scrutineeType caseClause.Pattern

                                   patternDuplicateDiagnostics caseClause.Pattern
                                   @ orPatternBinderTypeDiagnostics scrutineeType caseClause.Pattern
                                   @ (caseClause.Guard |> Option.map (validateExpression caseLocals) |> Option.defaultValue [])
                                   @ validateExpression caseLocals caseClause.Body))
                        | RecordLiteral fields ->
                            fields |> List.collect (fun field -> validateExpression localTypes field.Value)
                        | Seal(value, _) ->
                            validateExpression localTypes value
                        | RecordUpdate(receiver, fields) ->
                            validateExpression localTypes receiver
                            @ (fields |> List.collect (fun field -> validateExpression localTypes field.Value))
                        | MemberAccess(receiver, _, arguments) ->
                            validateExpression localTypes receiver @ (arguments |> List.collect (validateExpression localTypes))
                        | SafeNavigation(receiver, navigation) ->
                            validateExpression localTypes receiver
                            @ (navigation.Arguments |> List.collect (validateExpression localTypes))
                        | TagTest(receiver, _) ->
                            validateExpression localTypes receiver
                        | Comprehension comprehension ->
                            validateExpression localTypes comprehension.Lowered
                        | Do statements ->
                            validateDo localTypes statements
                        | MonadicSplice inner
                        | ExplicitImplicitArgument inner
                        | InoutArgument inner
                        | Unary(_, inner) ->
                            validateExpression localTypes inner
                        | NamedApplicationBlock fields ->
                            fields |> List.collect (fun field -> validateExpression localTypes field.Value)
                        | Binary(left, _, right)
                        | Elvis(left, right) ->
                            validateExpression localTypes left @ validateExpression localTypes right
                        | Apply(callee, arguments) ->
                            validateExpression localTypes callee @ (arguments |> List.collect (validateExpression localTypes))
                        | PrefixedString(_, parts) ->
                            parts
                            |> List.collect (function
                                | StringText _ -> []
                                | StringInterpolation(inner, _) -> validateExpression localTypes inner)
                        | Literal _
                        | NumericLiteral _
                        | KindQualifiedName _
                        | Name _ ->
                            []

                    and validateDo localTypes statements =
                        statements
                        |> List.collect (function
                            | DoLet(binding, expression)
                            | DoBind(binding, expression)
                            | DoUsing(binding, expression) ->
                                let valueType = inferExpectedType localTypes expression

                                patternDuplicateDiagnostics binding.Pattern
                                @ orPatternBinderTypeDiagnostics valueType binding.Pattern
                                @ validateExpression localTypes expression
                                @ []
                            | DoLetQuestion(binding, expression, failure) ->
                                let valueType = inferExpectedType localTypes expression

                                patternDuplicateDiagnostics binding.Pattern
                                @ orPatternBinderTypeDiagnostics valueType binding.Pattern
                                @ validateExpression localTypes expression
                                @ (failure
                                   |> Option.map (fun block ->
                                       patternDuplicateDiagnostics block.ResiduePattern.Pattern
                                       @ orPatternBinderTypeDiagnostics valueType block.ResiduePattern.Pattern
                                       @ validateDo localTypes block.Body)
                                   |> Option.defaultValue [])
                            | DoVar(_, expression)
                            | DoAssign(_, expression)
                            | DoDefer expression
                            | DoExpression expression
                            | DoReturn expression ->
                                validateExpression localTypes expression
                            | DoIf(condition, whenTrue, whenFalse) ->
                                validateExpression localTypes condition
                                @ validateDo localTypes whenTrue
                                @ validateDo localTypes whenFalse
                            | DoWhile(condition, body) ->
                                validateExpression localTypes condition @ validateDo localTypes body)

                    validateExpression initialLocalTypes expression

                let expressionNameResolutionDiagnostics (definition: LetDefinition) expression =
                    let ordinaryNameAmbiguityDiagnostic name candidates =
                        Diagnostics.errorFact
                            "KFrontIR"
                            (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                            None
                            []
                            (DiagnosticFact.nameAmbiguous name (candidates |> List.map renderOrdinaryVisibleTermCandidate))

                    let simpleClauseBinderName (tokens: Token list) =
                        match significantTokens tokens with
                        | [ token ] when Token.isName token ->
                            Some(SyntaxFacts.trimIdentifierQuotes token.Text)
                        | _ ->
                            None

                    let clauseBoundNames (clause: SurfaceEffectHandlerClause) =
                        let argumentNames =
                            clause.ArgumentTokens
                            |> List.choose simpleClauseBinderName

                        match clause.ResumptionName with
                        | Some name -> name :: argumentNames
                        | None -> argumentNames
                        |> Set.ofList

                    let ordinaryNameAmbiguityDiagnostics name =
                        environment.VisibleOrdinaryGroups
                        |> Map.tryFind name
                        |> Option.bind (fun group ->
                            let admissible =
                                visibleOrdinaryTermCandidates group
                                |> List.filter (function
                                    | OrdinaryVisibleBindingCandidate _
                                    | OrdinaryVisibleExportedBindingCandidate _
                                    | OrdinaryVisibleConstructorCandidate _
                                    | OrdinaryVisibleModuleCandidate _ -> true)

                            if List.length admissible > 1 then Some admissible else None)
                        |> Option.map (fun candidates -> [ ordinaryNameAmbiguityDiagnostic name candidates ])
                        |> Option.defaultValue []

                    let rec walk shadowed current =
                        match current with
                        | Name [ name ] when not (Set.contains name shadowed) ->
                            ordinaryNameAmbiguityDiagnostics name
                        | Name _
                        | KindQualifiedName _
                        | Literal _
                        | NumericLiteral _ ->
                            []
                        | TypeSyntaxTokens _ ->
                            []
                        | SyntaxQuote inner
                        | SyntaxSplice inner
                        | TopLevelSyntaxSplice inner
                        | CodeQuote inner
                        | CodeSplice inner
                        | MonadicSplice inner
                        | ExplicitImplicitArgument inner
                        | InoutArgument inner
                        | Unary(_, inner)
                        | Seal(inner, _) ->
                            walk shadowed inner
                        | LocalLet(binding, value, body) ->
                            let nextShadowed =
                                Set.union shadowed (collectPatternNames binding.Pattern |> Set.ofList)

                            walk shadowed value @ walk nextShadowed body
                        | LocalSignature(declaration, body) ->
                            walk (Set.add declaration.Name shadowed) body
                        | LocalTypeAlias(_, body) ->
                            walk shadowed body
                        | LocalScopedEffect(declaration, body) ->
                            walk (Set.add declaration.Name shadowed) body
                        | Lambda(parameters, body) ->
                            let nextShadowed =
                                parameters
                                |> List.map (fun parameter -> parameter.Name)
                                |> Set.ofList
                                |> Set.union shadowed

                            walk nextShadowed body
                        | Handle(_, label, body, returnClause, operationClauses) ->
                            walk shadowed label
                            @ walk shadowed body
                            @ walk (Set.union shadowed (clauseBoundNames returnClause)) returnClause.Body
                            @ (operationClauses
                               |> List.collect (fun clause ->
                                   walk (Set.union shadowed (clauseBoundNames clause)) clause.Body))
                        | IfThenElse(condition, whenTrue, whenFalse) ->
                            walk shadowed condition @ walk shadowed whenTrue @ walk shadowed whenFalse
                        | Match(scrutinee, cases) ->
                            walk shadowed scrutinee
                            @ (cases
                               |> List.collect (fun caseClause ->
                                   let caseShadowed =
                                       Set.union shadowed (collectPatternNames caseClause.Pattern |> Set.ofList)

                                   (caseClause.Guard |> Option.map (walk caseShadowed) |> Option.defaultValue [])
                                   @ walk caseShadowed caseClause.Body))
                        | RecordLiteral fields ->
                            fields |> List.collect (fun field -> walk shadowed field.Value)
                        | RecordUpdate(receiver, fields) ->
                            walk shadowed receiver
                            @ (fields |> List.collect (fun field -> walk shadowed field.Value))
                        | MemberAccess(receiver, _, arguments) ->
                            walk shadowed receiver @ (arguments |> List.collect (walk shadowed))
                        | SafeNavigation(receiver, navigation) ->
                            walk shadowed receiver @ (navigation.Arguments |> List.collect (walk shadowed))
                        | TagTest(receiver, _) ->
                            walk shadowed receiver
                        | Do statements ->
                            walkDo shadowed statements
                        | Apply(callee, arguments) ->
                            walk shadowed callee @ (arguments |> List.collect (walk shadowed))
                        | NamedApplicationBlock fields ->
                            fields |> List.collect (fun field -> walk shadowed field.Value)
                        | Binary(left, _, right)
                        | Elvis(left, right) ->
                            walk shadowed left @ walk shadowed right
                        | Comprehension comprehension ->
                            walkComprehension shadowed comprehension
                        | PrefixedString(_, parts) ->
                            parts
                            |> List.collect (function
                                | StringText _ -> []
                                | StringInterpolation(inner, _) -> walk shadowed inner)

                    and walkComprehension shadowed (comprehension: SurfaceComprehension) =
                        let walkYield currentShadowed =
                            match comprehension.Yield with
                            | YieldValue value ->
                                walk currentShadowed value
                            | YieldKeyValue(key, value) ->
                                walk currentShadowed key @ walk currentShadowed value

                        let rec loop currentShadowed clauses =
                            match clauses with
                            | [] ->
                                walkYield currentShadowed
                            | clause :: rest ->
                                match clause with
                                | ForClause(_, _, binding, source) ->
                                    let nextShadowed =
                                        Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)

                                    walk currentShadowed source @ loop nextShadowed rest
                                | JoinClause(binding, source, condition) ->
                                    let nextShadowed =
                                        Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)

                                    walk currentShadowed source
                                    @ walk nextShadowed condition
                                    @ loop nextShadowed rest
                                | LetClause(_, binding, value) ->
                                    let nextShadowed =
                                        Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)

                                    walk currentShadowed value @ loop nextShadowed rest
                                | IfClause condition ->
                                    walk currentShadowed condition @ loop currentShadowed rest
                                | GroupByClause(key, aggregations, intoName) ->
                                    walk currentShadowed key
                                    @ (aggregations |> List.collect (fun field -> walk currentShadowed field.Value))
                                    @ loop (Set.singleton intoName) rest
                                | OrderByClause(_, key)
                                | DistinctByClause key
                                | SkipClause key
                                | TakeClause key ->
                                    walk currentShadowed key @ loop currentShadowed rest
                                | DistinctClause ->
                                    loop currentShadowed rest
                                | LeftJoinClause(binding, source, condition, intoName) ->
                                    let joinShadowed =
                                        Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)

                                    walk currentShadowed source
                                    @ walk joinShadowed condition
                                    @ loop (Set.add intoName currentShadowed) rest

                        loop shadowed comprehension.Clauses

                    and walkDo shadowed statements =
                        let rec loop currentShadowed remaining =
                            match remaining with
                            | [] ->
                                []
                            | statement :: rest ->
                                match statement with
                                | DoLet(binding, value)
                                | DoBind(binding, value)
                                | DoUsing(binding, value) ->
                                    let nextShadowed =
                                        Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)

                                    walk currentShadowed value @ loop nextShadowed rest
                                | DoLetQuestion(binding, value, failure) ->
                                    let nextShadowed =
                                        Set.union currentShadowed (collectPatternNames binding.Pattern |> Set.ofList)

                                    let failureDiagnostics =
                                        failure
                                        |> Option.map (fun block ->
                                            let failureShadowed =
                                                Set.union currentShadowed (collectPatternNames block.ResiduePattern.Pattern |> Set.ofList)

                                            walkDo failureShadowed block.Body)
                                        |> Option.defaultValue []

                                    walk currentShadowed value @ failureDiagnostics @ loop nextShadowed rest
                                | DoVar(name, value) ->
                                    walk currentShadowed value @ loop (Set.add name currentShadowed) rest
                                | DoAssign(_, value)
                                | DoDefer value
                                | DoExpression value
                                | DoReturn value ->
                                    walk currentShadowed value @ loop currentShadowed rest
                                | DoIf(condition, whenTrue, whenFalse) ->
                                    walk currentShadowed condition
                                    @ walkDo currentShadowed whenTrue
                                    @ walkDo currentShadowed whenFalse
                                    @ loop currentShadowed rest
                                | DoWhile(condition, body) ->
                                    walk currentShadowed condition
                                    @ walkDo currentShadowed body
                                    @ loop currentShadowed rest

                        loop shadowed statements

                    let initialShadowed =
                        definition.Parameters
                        |> List.map (fun parameter -> parameter.Name)
                        |> Set.ofList

                    walk initialShadowed expression

                let constructorDefaultDiagnostics =
                    let topLevelNames =
                        frontendModule.Declarations
                        |> List.collect (function
                            | SignatureDeclaration declaration -> [ declaration.Name ]
                            | LetDeclaration declaration -> declaration.Name |> Option.toList
                            | ProjectionDeclarationNode declaration -> [ declaration.Name ]
                            | DataDeclarationNode declaration ->
                                declaration.Name :: (declaration.Constructors |> List.map (fun constructor -> constructor.Name))
                            | TypeAliasNode declaration -> [ declaration.Name ]
                            | TraitDeclarationNode declaration -> [ declaration.Name ]
                            | ExpectDeclarationNode (ExpectTermDeclaration declaration) -> [ declaration.Name ]
                            | ExpectDeclarationNode (ExpectTypeDeclaration declaration) -> [ declaration.Name ]
                            | ExpectDeclarationNode (ExpectTraitDeclaration declaration) -> [ declaration.Name ]
                            | _ -> [])
                        |> Set.ofList

                    let baseVisibleNames =
                        let preludeContract = IntrinsicCatalog.bundledPreludeExpectContract ()

                        [ topLevelNames
                          preludeContract.TermNames
                          preludeContract.TypeNames
                          preludeContract.TraitNames
                          Set.ofList Stdlib.FixedPreludeConstructors
                          environment.VisibleBindings |> Map.keys |> Set.ofSeq
                          environment.VisibleConstructors |> Map.keys |> Set.ofSeq
                          (environment.VisibleModulePaths
                           |> Map.keys
                           |> Seq.map SyntaxFacts.moduleNameToText
                           |> Set.ofSeq)
                          (environment.VisibleStaticGroups
                           |> Map.keys
                           |> Seq.map SyntaxFacts.moduleNameToText
                           |> Set.ofSeq) ]
                        |> Set.unionMany
                        |> Set.remove "<anonymous>"

                    let diagnosticsForDefault parameters index parameterName parameterTypeTokens defaultValue =
                        let earlierParameters = parameters |> List.take index
                        let forbiddenNames =
                            parameters
                            |> List.skip index
                            |> List.choose (fun candidate -> candidate.ParameterName)
                            |> Set.ofList

                        let localTypes =
                            earlierParameters
                            |> List.choose (fun earlier ->
                                match earlier.ParameterName, TypeSignatures.parseType earlier.ParameterTypeTokens with
                                | Some name, Some parameterType -> Some(name, parameterType)
                                | _ -> None)
                            |> Map.ofList

                        let visibleNames =
                            earlierParameters
                            |> List.choose (fun earlier -> earlier.ParameterName)
                            |> Set.ofList
                            |> Set.union baseVisibleNames

                        let nameDiagnostics =
                            ResourceCheckingSurface.expressionNames defaultValue
                            |> Seq.distinct
                            |> Seq.choose (fun referencedName ->
                                if Set.contains referencedName forbiddenNames then
                                    Some(
                                        makeSurfaceElaborationDiagnostic
                                            (ConstructorDefaultReferencesUnavailableBinder(
                                                parameterName,
                                                referencedName
                                            ))
                                    )
                                elif not (Set.contains referencedName visibleNames) then
                                    Some(makeNameUnresolvedDiagnostic referencedName)
                                else
                                    None)
                            |> Seq.toList

                        let typeDiagnostics =
                            match TypeSignatures.parseType parameterTypeTokens, inferValidationExpressionType environment (ref 0) localTypes defaultValue with
                            | Some expectedType, Some actualType
                                when not (
                                    TypeSignatures.definitionallyEqual
                                        (normalizeTypeAliases environment.VisibleTypeAliases expectedType)
                                        (normalizeTypeAliases environment.VisibleTypeAliases actualType)
                                ) ->
                                [ makeSurfaceElaborationDiagnostic
                                    (ConstructorDefaultTypeMismatch(
                                        parameterName,
                                        TypeSignatures.toText actualType,
                                        TypeSignatures.toText expectedType
                                    )) ]
                            | Some _, None when List.isEmpty nameDiagnostics ->
                                [ makeSurfaceElaborationDiagnostic
                                    (ConstructorDefaultCouldNotBeChecked parameterName) ]
                            | _ ->
                                []

                        nameDiagnostics @ typeDiagnostics

                    let diagnosticsForConstructor (constructor: DataConstructor) =
                        match constructor.Parameters with
                        | Some parameters ->
                            parameters
                            |> List.mapi (fun index parameter -> index, parameter)
                            |> List.collect (fun (index, parameter) ->
                                match parameter.ParameterName, parameter.DefaultValue with
                                | Some parameterName, Some defaultValue ->
                                    diagnosticsForDefault parameters index parameterName parameter.ParameterTypeTokens defaultValue
                                | _ ->
                                    [])
                        | None ->
                            []

                    frontendModule.Declarations
                    |> List.collect (function
                        | DataDeclarationNode declaration ->
                            declaration.Constructors |> List.collect diagnosticsForConstructor
                        | _ ->
                            [])

                let instanceMemberSignatureDiagnostics =
                    frontendModule.Declarations
                    |> List.collect (function
                        | InstanceDeclarationNode declaration ->
                            tryParseInstanceHeader declaration
                            |> Option.toList
                            |> List.collect (fun (traitReference, _, headTypes) ->
                                let traitName = traitReferenceCanonicalName (attachResolvedTraitReference environment traitReference)
                                tryResolveTraitInfoByReference environment traitReference
                                |> Option.toList
                                |> List.collect (fun traitInfo ->
                                    let traitSubstitution =
                                        if List.length traitInfo.TypeParameters = List.length headTypes then
                                            List.zip traitInfo.TypeParameters headTypes |> Map.ofList
                                        else
                                            Map.empty

                                    declaration.Members
                                    |> List.collect (fun memberDeclaration ->
                                        match memberDeclaration.Name with
                                        | None ->
                                            []
                                        | Some memberName ->
                                            match traitInfo.Members |> Map.tryFind memberName with
                                            | None ->
                                                []
                                            | Some memberInfo ->
                                                match memberDeclaration.ReturnTypeTokens |> Option.bind TypeSignatures.parseType with
                                                | None ->
                                                    []
                                                | Some declaredReturnType ->
                                                    let expectedReturnType =
                                                        memberInfo.Scheme
                                                        |> TypeSignatures.applySchemeSubstitution traitSubstitution
                                                        |> TypeSignatures.schemeParts
                                                        |> snd

                                                    if
                                                        TypeSignatures.definitionallyEqual
                                                            (normalizeTypeAliases environment.VisibleTypeAliases declaredReturnType)
                                                            (normalizeTypeAliases environment.VisibleTypeAliases expectedReturnType)
                                                    then
                                                        []
                                                    else
                                                        [
                                                            makeDiagnostic
                                                                SimpleDiagnosticKind.TypeEqualityMismatch
                                                                $"Instance member '{memberName}' for trait '{traitName}' must return '{TypeSignatures.toText expectedReturnType}', but declares '{TypeSignatures.toText declaredReturnType}'."
                                                        ])))
                        | _ ->
                            [])

                let instanceSupertraitDiagnostics =
                    let constraintMatches (expected: TraitConstraint) (actual: TraitConstraint) =
                        let expected = attachResolvedTraitConstraint environment expected
                        let actual = attachResolvedTraitConstraint environment actual
                        TypeSignatures.TraitReference.matches expected.Trait actual.Trait
                        && List.length expected.Arguments = List.length actual.Arguments
                        && List.forall2
                            (fun left right ->
                                TypeSignatures.definitionallyEqual
                                    (normalizeTypeAliases environment.VisibleTypeAliases left)
                                    (normalizeTypeAliases environment.VisibleTypeAliases right))
                            expected.Arguments
                            actual.Arguments

                    let premisesSatisfy (premises: TraitConstraint list) (requiredConstraint: TraitConstraint) =
                        premises
                        |> List.exists (fun (premise: TraitConstraint) ->
                            reachableTraitConstraints environment premise
                            |> List.exists (constraintMatches requiredConstraint))

                    frontendModule.Declarations
                    |> List.collect (function
                        | InstanceDeclarationNode declaration ->
                            tryParseInstanceHeader declaration
                            |> Option.toList
                            |> List.collect (fun (traitReference, constraints, headTypes) ->
                                let traitName = traitReferenceCanonicalName (attachResolvedTraitReference environment traitReference)
                                tryResolveTraitInfoByReference environment traitReference
                                |> Option.toList
                                |> List.collect (fun traitInfo ->
                                    tryInstantiateTraitSupertraits traitInfo headTypes
                                    |> Option.defaultValue []
                                    |> List.choose (fun requiredConstraint ->
                                        let satisfied =
                                            premisesSatisfy constraints requiredConstraint
                                            || (resolveConstraintInstance environment requiredConstraint |> Option.isSome)

                                        if satisfied then
                                            None
                                        else
                                            Some(
                                                Diagnostics.errorFact
                                                    "KFrontIR"
                                                    (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                                    None
                                                    []
                                                    (DiagnosticFact.surfaceElaboration
                                                        (TraitSupertraitEvidenceUnsatisfied(
                                                            traitName,
                                                            renderTraitConstraint environment requiredConstraint
                                                        )))
                                            ))))
                        | _ ->
                            [])

                let effectDeclarationDiagnostics =
                    frontendModule.Declarations
                    |> List.collect (function
                        | EffectDeclarationNode declaration ->
                            borrowedEffectResumptionQuantityDiagnostics makeDiagnostic declaration
                        | _ ->
                            [])

                let structuralDiagnostics =
                    moduleAttributeDiagnostics
                    @ totalityAssertionDiagnostics
                    @ typeAliasCycleDiagnostics
                    @ malformedConstructorDiagnostics
                    @ unsignedRecursiveBindingDiagnostics
                    @ trivialRecursiveCycleDiagnostics
                    @ constructorDefaultDiagnostics
                    @ effectDeclarationDiagnostics
                    @ instanceSupertraitDiagnostics
                    @ instanceMemberSignatureDiagnostics

                let multishotBackendCapabilityDiagnostics =
                    if backendSupportsMultishotEffects backendProfile then
                        []
                    else
                        let normalizedBackendProfile = BackendProfile.toPortableName backendProfile
                        let privateByDefault = isPrivateByDefault frontendModule

                        let multishotInvocationMessage context effectName operationName =
                            $"Backend profile '{normalizedBackendProfile}' does not provide capability 'rt-multishot-effects' required by multi-shot operation '{effectName}.{operationName}' {context}."

                        let rec rewriteEffectLabelAliasUse aliasName effectName current =
                            let rewrite = rewriteEffectLabelAliasUse aliasName effectName

                            match current with
                            | Name [ name ] when String.Equals(name, aliasName, StringComparison.Ordinal) ->
                                KindQualifiedName(EffectLabelKind, [ effectName ])
                            | Name(root :: path) when String.Equals(root, aliasName, StringComparison.Ordinal) ->
                                Name(effectName :: path)
                            | Name _ ->
                                current
                            | TypeSyntaxTokens _ ->
                                current
                            | SyntaxQuote inner ->
                                SyntaxQuote(rewrite inner)
                            | SyntaxSplice inner ->
                                SyntaxSplice(rewrite inner)
                            | TopLevelSyntaxSplice inner ->
                                TopLevelSyntaxSplice(rewrite inner)
                            | CodeQuote inner ->
                                CodeQuote(rewrite inner)
                            | CodeSplice inner ->
                                CodeSplice(rewrite inner)
                            | Handle(isDeep, label, body, returnClause, operationClauses) ->
                                let rewriteClause (clause: SurfaceEffectHandlerClause) =
                                    { clause with Body = rewrite clause.Body }

                                Handle(isDeep, rewrite label, rewrite body, rewriteClause returnClause, operationClauses |> List.map rewriteClause)
                            | LocalLet(binding, value, body) ->
                                let shadowsAlias =
                                    collectPatternNames binding.Pattern
                                    |> List.exists (fun name -> String.Equals(name, aliasName, StringComparison.Ordinal))

                                LocalLet(binding, rewrite value, if shadowsAlias then body else rewrite body)
                            | LocalSignature(declaration, body) ->
                                if String.Equals(declaration.Name, aliasName, StringComparison.Ordinal) then current else LocalSignature(declaration, rewrite body)
                            | LocalTypeAlias(declaration, body) ->
                                LocalTypeAlias(declaration, rewrite body)
                            | LocalScopedEffect(declaration, body) ->
                                if String.Equals(declaration.Name, aliasName, StringComparison.Ordinal) then current else LocalScopedEffect(declaration, rewrite body)
                            | Lambda(parameters, body) ->
                                if parameters |> List.exists (fun parameter -> String.Equals(parameter.Name, aliasName, StringComparison.Ordinal)) then current else Lambda(parameters, rewrite body)
                            | IfThenElse(condition, whenTrue, whenFalse) ->
                                IfThenElse(rewrite condition, rewrite whenTrue, rewrite whenFalse)
                            | Match(scrutinee, cases) ->
                                Match(
                                    rewrite scrutinee,
                                    cases
                                    |> List.map (fun caseClause ->
                                        let shadowsAlias =
                                            collectPatternNames caseClause.Pattern
                                            |> List.exists (fun name -> String.Equals(name, aliasName, StringComparison.Ordinal))

                                        { caseClause with
                                            Guard = caseClause.Guard |> Option.map rewrite
                                            Body = if shadowsAlias then caseClause.Body else rewrite caseClause.Body })
                                )
                            | RecordLiteral fields ->
                                RecordLiteral(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
                            | Seal(value, ascriptionTokens) ->
                                Seal(rewrite value, ascriptionTokens)
                            | RecordUpdate(receiver, fields) ->
                                RecordUpdate(rewrite receiver, fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
                            | MemberAccess(receiver, segments, arguments) ->
                                MemberAccess(rewrite receiver, segments, arguments |> List.map rewrite)
                            | SafeNavigation(receiver, navigation) ->
                                SafeNavigation(rewrite receiver, { navigation with Arguments = navigation.Arguments |> List.map rewrite })
                            | TagTest(receiver, constructorName) ->
                                TagTest(rewrite receiver, constructorName)
                            | Do statements ->
                                Do(statements)
                            | MonadicSplice inner ->
                                MonadicSplice(rewrite inner)
                            | ExplicitImplicitArgument inner ->
                                ExplicitImplicitArgument(rewrite inner)
                            | NamedApplicationBlock fields ->
                                NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
                            | InoutArgument inner ->
                                InoutArgument(rewrite inner)
                            | Unary(operatorName, inner) ->
                                Unary(operatorName, rewrite inner)
                            | Apply(callee, arguments) ->
                                Apply(rewrite callee, arguments |> List.map rewrite)
                            | Binary(left, operatorName, right) ->
                                Binary(rewrite left, operatorName, rewrite right)
                            | Elvis(left, right) ->
                                Elvis(rewrite left, rewrite right)
                            | Comprehension comprehension ->
                                Comprehension { comprehension with Lowered = rewrite comprehension.Lowered }
                            | PrefixedString(prefix, parts) ->
                                PrefixedString(
                                    prefix,
                                    parts
                                    |> List.map (function
                                        | StringText text -> StringText text
                                        | StringInterpolation(inner, format) -> StringInterpolation(rewrite inner, format))
                                )
                            | Literal _
                            | NumericLiteral _
                            | KindQualifiedName _ ->
                                current

                        let tryMatchMultishotInvocation expression =
                            match expression with
                            | Apply(Name [ effectName; operationName ], _) ->
                                tryFindScopedEffectOperation effectName operationName
                                |> Option.bind (fun (_, operation) ->
                                    if quantityPermitsMultipleResumptions operation.ResumptionQuantity then
                                        Some(effectName, operationName)
                                    else
                                        None)
                            | Apply(MemberAccess(Name [ effectName ], [ operationName ], []), _) ->
                                tryFindScopedEffectOperation effectName operationName
                                |> Option.bind (fun (_, operation) ->
                                    if quantityPermitsMultipleResumptions operation.ResumptionQuantity then
                                        Some(effectName, operationName)
                                    else
                                        None)
                            | Apply(MemberAccess(KindQualifiedName(EffectLabelKind, [ effectName ]), [ operationName ], []), _) ->
                                tryFindScopedEffectOperation effectName operationName
                                |> Option.bind (fun (_, operation) ->
                                    if quantityPermitsMultipleResumptions operation.ResumptionQuantity then
                                        Some(effectName, operationName)
                                    else
                                        None)
                            | _ ->
                                None

                        let rec collectMultishotInvocations expression =
                            let nested =
                                match expression with
                                | SyntaxQuote _
                                | SyntaxSplice _
                                | TopLevelSyntaxSplice _
                                | CodeQuote _
                                | CodeSplice _ ->
                                    []
                                | TypeSyntaxTokens _ ->
                                    []
                                | LocalLet(binding, value, body) ->
                                    let bodyForCollection =
                                        match binding.Pattern, value with
                                        | NamePattern aliasName, Name [ effectName ] when tryFindScopedEffectDeclaration effectName |> Option.isSome ->
                                            rewriteEffectLabelAliasUse aliasName effectName body
                                        | NamePattern aliasName, KindQualifiedName(EffectLabelKind, [ effectName ])
                                            when tryFindScopedEffectDeclaration effectName |> Option.isSome ->
                                            rewriteEffectLabelAliasUse aliasName effectName body
                                        | _ ->
                                            body

                                    collectMultishotInvocations value @ collectMultishotInvocations bodyForCollection
                                | LocalSignature(_, body)
                                | LocalTypeAlias(_, body) ->
                                    collectMultishotInvocations body
                                | LocalScopedEffect(declaration, body) ->
                                    withScopedEffectDeclaration environment.CurrentModuleIdentity declaration (fun () -> collectMultishotInvocations body)
                                | Lambda(_, body) ->
                                    collectMultishotInvocations body
                                | Handle(_, label, body, returnClause, operationClauses) ->
                                    collectMultishotInvocations label
                                    @ collectMultishotInvocations body
                                    @ collectMultishotInvocations returnClause.Body
                                    @ (operationClauses |> List.collect (fun clause -> collectMultishotInvocations clause.Body))
                                | Match(scrutinee, cases) ->
                                    collectMultishotInvocations scrutinee
                                    @ (cases
                                       |> List.collect (fun caseClause ->
                                           (caseClause.Guard
                                            |> Option.map collectMultishotInvocations
                                            |> Option.defaultValue [])
                                           @ collectMultishotInvocations caseClause.Body))
                                | IfThenElse(condition, whenTrue, whenFalse) ->
                                    collectMultishotInvocations condition
                                    @ collectMultishotInvocations whenTrue
                                    @ collectMultishotInvocations whenFalse
                                | RecordLiteral fields ->
                                    fields |> List.collect (fun field -> collectMultishotInvocations field.Value)
                                | Seal(value, _) ->
                                    collectMultishotInvocations value
                                | RecordUpdate(receiver, fields) ->
                                    collectMultishotInvocations receiver
                                    @ (fields |> List.collect (fun field -> collectMultishotInvocations field.Value))
                                | MemberAccess(receiver, _, arguments) ->
                                    collectMultishotInvocations receiver
                                    @ (arguments |> List.collect collectMultishotInvocations)
                                | SafeNavigation(receiver, navigation) ->
                                    collectMultishotInvocations receiver
                                    @ (navigation.Arguments |> List.collect collectMultishotInvocations)
                                | TagTest(receiver, _) ->
                                    collectMultishotInvocations receiver
                                | Do statements ->
                                    let rec collectDo statements =
                                        match statements with
                                        | [] ->
                                            []
                                        | statement :: rest ->
                                            let restInvocations = collectDo rest

                                            match statement with
                                            | DoLet(_, value)
                                            | DoBind(_, value)
                                            | DoUsing(_, value)
                                            | DoVar(_, value)
                                            | DoAssign(_, value)
                                            | DoDefer value
                                            | DoExpression value
                                            | DoReturn value ->
                                                collectMultishotInvocations value @ restInvocations
                                            | DoLetQuestion(_, value, failure) ->
                                                let failureInvocations =
                                                    failure
                                                    |> Option.map (fun block -> collectDo block.Body)
                                                    |> Option.defaultValue []

                                                collectMultishotInvocations value @ failureInvocations @ restInvocations
                                            | DoIf(condition, whenTrue, whenFalse) ->
                                                collectMultishotInvocations condition
                                                @ collectDo whenTrue
                                                @ collectDo whenFalse
                                                @ restInvocations
                                            | DoWhile(condition, body) ->
                                                collectMultishotInvocations condition @ collectDo body @ restInvocations

                                    collectDo statements
                                | MonadicSplice inner
                                | ExplicitImplicitArgument inner
                                | InoutArgument inner
                                | Unary(_, inner) ->
                                    collectMultishotInvocations inner
                                | NamedApplicationBlock fields ->
                                    fields |> List.collect (fun field -> collectMultishotInvocations field.Value)
                                | Apply(callee, arguments) ->
                                    collectMultishotInvocations callee
                                    @ (arguments |> List.collect collectMultishotInvocations)
                                | Binary(left, _, right)
                                | Elvis(left, right) ->
                                    collectMultishotInvocations left @ collectMultishotInvocations right
                                | Comprehension comprehension ->
                                    collectMultishotInvocations comprehension.Lowered
                                | PrefixedString(_, parts) ->
                                    parts
                                    |> List.collect (function
                                        | StringText _ -> []
                                        | StringInterpolation(inner, _) -> collectMultishotInvocations inner)
                                | Literal _
                                | NumericLiteral _
                                | KindQualifiedName _
                                | Name _ ->
                                    []

                            match tryMatchMultishotInvocation expression with
                            | Some invocation -> invocation :: nested
                            | None -> nested

                        let uniqueMultishotInvocations expression =
                            collectMultishotInvocations expression
                            |> List.distinct

                        let exportedDeclarationDiagnostics =
                            frontendModule.Declarations
                            |> List.choose (function
                                | LetDeclaration definition when definition.Name.IsSome && definition.Body.IsSome ->
                                    let bindingName = definition.Name.Value

                                    if isExportedVisibility privateByDefault definition.Visibility then
                                        uniqueMultishotInvocations definition.Body.Value
                                        |> List.tryHead
                                        |> Option.map (fun (effectName, operationName) ->
                                            makeDiagnostic
                                                SimpleDiagnosticKind.MultishotEffectUnsupportedBackend
                                                (multishotInvocationMessage
                                                    $"from exported declaration '{bindingName}'"
                                                    effectName
                                                    operationName))
                                    else
                                        None
                                | _ ->
                                    None)

                        exportedDeclarationDiagnostics

                if not (List.isEmpty typeAliasCycleDiagnostics) then
                    structuralDiagnostics @ multishotBackendCapabilityDiagnostics
                else
                    structuralDiagnostics
                    @ multishotBackendCapabilityDiagnostics
                    @ (frontendModule.Declarations
                    |> List.collect (function
                        | TypeAliasNode declaration ->
                            declaration.BodyTokens
                            |> Option.bind tryParseRecordSurfaceInfo
                            |> Option.map (fun recordInfo ->
                                let duplicateDiagnostics =
                                    recordInfo.Fields
                                    |> List.countBy (fun field -> field.Name)
                                    |> List.choose (fun (name, count) ->
                                        if count > 1 then
                                            Some(
                                                Diagnostics.errorFact
                                                    "KFrontIR"
                                                    (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                                    None
                                                    []
                                                    (DiagnosticFact.surfaceRecord (RecordFieldDeclaredMoreThanOnce name))
                                            )
                                        else
                                            None)

                                let cycleDiagnostics =
                                    let parsedFields =
                                        recordInfo.Fields
                                        |> List.map (fun field ->
                                            parseType field.TypeTokens
                                            |> Option.map (fun parsedType ->
                                                { Name = field.Name
                                                  Quantity = QuantityOmega
                                                  Type = parsedType }))

                                    if parsedFields |> List.forall Option.isSome then
                                        let typeExpr = TypeRecord(parsedFields |> List.choose id)

                                        if hasCyclicRecordDependencies typeExpr then
                                            [
                                                Diagnostics.errorFact
                                                    "KFrontIR"
                                                    (Some(KFrontIRPhase.phaseName CORE_LOWERING))
                                                    None
                                                    []
                                                    (DiagnosticFact.surfaceRecord (RecordDependenciesMustBeAcyclic RecordTypeTelescope))
                                            ]
                                        else
                                            []
                                    else
                                        []

                                duplicateDiagnostics @ cycleDiagnostics)
                            |> Option.defaultValue []
                        | LetDeclaration definition ->
                            let scheme =
                                definition.Name
                                |> Option.bind (fun name -> Map.tryFind name sourceBindingInfosByName)
                                |> Option.map (fun bindingInfo -> bindingInfo.Scheme)

                            let effectiveValidationParameters =
                                definition.Name
                                |> Option.bind (fun name ->
                                    sourceBindingInfosByName
                                    |> Map.tryFind name
                                    |> Option.bind (fun bindingInfo -> bindingInfo.ParameterLayouts))
                                |> Option.defaultValue definition.Parameters

                            let bodyEnvironment =
                                match scheme with
                                | Some scheme ->
                                    let schemeConstrainedMembers =
                                        if List.isEmpty scheme.Constraints then
                                            Map.empty
                                        else
                                            buildConstrainedMembers environment scheme.Constraints

                                    let schemeConstraintDictionaries =
                                        scheme.Constraints
                                        |> List.mapi (fun index constraintInfo ->
                                            constraintInfo, KCoreName [ $"__kappa_dict_{traitConstraintBinderStem constraintInfo}_{index}" ])
                                        |> buildConstraintDictionaries environment

                                    let parameterConstrainedMembers =
                                        buildParameterConstrainedMembers environment scheme effectiveValidationParameters

                                    let parameterConstraintDictionaries =
                                        buildParameterConstraintDictionaries environment scheme effectiveValidationParameters

                                    { environment with
                                        ConstraintDictionaries =
                                            parameterConstraintDictionaries
                                            |> Map.fold (fun state key value ->
                                                if Map.containsKey key state then
                                                    state
                                                else
                                                    Map.add key value state) schemeConstraintDictionaries
                                        ConstrainedMembers =
                                            parameterConstrainedMembers
                                            |> Map.fold (fun state memberName route ->
                                                if Map.containsKey memberName state then
                                                    state
                                                else
                                                    Map.add memberName route state) schemeConstrainedMembers }
                                | _ ->
                                    environment

                            let moduleTopLevelDefinitionsByName =
                                frontendModule.Declarations
                                |> List.choose (function
                                    | LetDeclaration candidate ->
                                        match candidate.Name, candidate.Body with
                                        | Some name, Some _ -> Some(name, candidate)
                                        | _ -> None
                                    | _ ->
                                        None)
                                |> Map.ofList

                            let explicitSignatureNames =
                                frontendModule.Declarations
                                |> List.choose (function
                                    | SignatureDeclaration declaration -> Some declaration.Name
                                    | _ -> None)
                                |> Set.ofList

                            let sourceSignatureSchemesByName =
                                frontendModule.Declarations
                                |> List.choose (function
                                    | SignatureDeclaration declaration ->
                                        TypeSignatures.parseScheme declaration.TypeTokens
                                        |> Option.map (fun parsedScheme -> declaration.Name, parsedScheme)
                                    | _ ->
                                        None)
                                |> Map.ofList

                            let sourceSignatureScheme =
                                definition.Name
                                |> Option.bind (fun name -> Map.tryFind name sourceSignatureSchemesByName)

                            validateBuiltInExpressionsForBinding
                                bodyEnvironment
                                frontendModule.FilePath
                                knownSurfaceTermNames
                                allowUnresolvedCallDiagnostics
                                explicitSignatureNames
                                sourceSignatureScheme
                                moduleTopLevelDefinitionsByName
                                definition
                                scheme
                            @
                                (let initialParameterLocals =
                                     buildLocalTypes scheme effectiveValidationParameters
                                     |> Map.ofList

                                 definition.Body
                                 |> Option.map (fun body ->
                                     expressionPatternDiagnostics initialParameterLocals body
                                     @ expressionNameResolutionDiagnostics definition body)
                                 |> Option.defaultValue [])
                        | ProjectionDeclarationNode declaration ->
                            validateProjectionDeclaration declaration
                        | _ ->
                            [])))

        let validateFrontendModule (frontendModule: KFrontIRModule) =
            let moduleName = moduleNameText frontendModule.ModuleIdentity

            frontendModule.ModuleIdentity
            |> moduleIdentityOfOptionalSegments
            |> Option.map (fun moduleIdentity -> validateNamedFrontendModule moduleName moduleIdentity frontendModule)
            |> Option.defaultValue []

        duplicateDeclarationDiagnostics @ (frontendModules |> List.collect validateFrontendModule)

    let private makeSyntheticBindingDeclaration
        (name: string)
        (parameters: KCoreParameter list)
        (returnType: TypeExpr option)
        (body: KCoreExpression)
        (provenance: KCoreOrigin)
        =
        { Source = syntheticLetSource name
          Binding =
            Some
                { Visibility = Some Visibility.Private
                  IsOpaque = false
                  Name = Some name
                  Parameters = parameters
                  ReturnType = returnType
                  ReturnTypeText = returnType |> Option.map typeTextOf
                  Body = Some body
                  BodyText = Some ""
                  Provenance = provenance }
          Provenance = provenance }

    let private lowerBindingBody
        (environment: BindingLoweringEnvironment)
        (recordLayouts: Map<string, SyntheticRecordLayout> ref)
        (scheme: TypeScheme option)
        (parameters: Parameter list)
        (extraLocalTypes: (string * TypeExpr) list)
        (body: SurfaceExpression)
        =
        let freshCounter = ref 0
        let doScopeCounter = ref 0
        let usingCounter = ref 0

        let sanitizeInternalName (value: string) =
            if String.IsNullOrWhiteSpace value then
                "resource"
            else
                let characters =
                    value
                    |> Seq.map (fun character ->
                        if Char.IsLetterOrDigit character || character = '_' then
                            character
                        else
                            '_')
                    |> Seq.toArray

                String(characters)

        let freshDoScopeLabel () =
            let label = $"S{doScopeCounter.Value}"
            doScopeCounter.Value <- doScopeCounter.Value + 1
            label

        let freshUsingOwnedName bindingName =
            let index = usingCounter.Value
            usingCounter.Value <- usingCounter.Value + 1
            $"__kappa_using_{sanitizeInternalName bindingName}_{index}"

        let freshSyntheticName prefix =
            let index = freshCounter.Value
            freshCounter.Value <- freshCounter.Value + 1
            $"{prefix}{index}"

        let localTypes =
            buildLocalTypes scheme parameters
            |> Map.ofList
            |> fun state ->
                extraLocalTypes
                |> List.fold (fun current (name, parameterType) -> Map.add name parameterType current) state

        let localImplicitTypes =
            buildLocalImplicitTypes scheme parameters
            |> fun state ->
                extraLocalTypes
                |> List.fold (fun current (name, parameterType) -> Map.add name parameterType current) state

        let rec substituteZeroArityLocalTypeAliasInExpression (alias: TypeAlias) expression =
            let substituteTypeTokens tokens =
                let aliasBodyTokens = alias.BodyTokens |> Option.defaultValue []
                let tokenArray = tokens |> List.toArray
                let rewritten = ResizeArray<Token>()

                let isStandaloneAlias index =
                    let token = tokenArray[index]
                    let previousIsDot = index > 0 && tokenArray[index - 1].Kind = Dot
                    let nextIsDot = index + 1 < tokenArray.Length && tokenArray[index + 1].Kind = Dot

                    Token.isName token
                    && String.Equals(SyntaxFacts.trimIdentifierQuotes token.Text, alias.Name, StringComparison.Ordinal)
                    && not previousIsDot
                    && not nextIsDot

                for index = 0 to tokenArray.Length - 1 do
                    if isStandaloneAlias index then
                        rewritten.AddRange(aliasBodyTokens)
                    else
                        rewritten.Add(tokenArray[index])

                List.ofSeq rewritten

            let substituteParameter (parameter: Parameter) =
                { parameter with
                    TypeTokens = parameter.TypeTokens |> Option.map substituteTypeTokens }

            let substituteBinding (binding: SurfaceBindPattern) =
                { binding with
                    TypeTokens = binding.TypeTokens |> Option.map substituteTypeTokens }

            let rec substitute current =
                match current with
                | SyntaxQuote inner ->
                    SyntaxQuote(substitute inner)
                | SyntaxSplice inner ->
                    SyntaxSplice(substitute inner)
                | TopLevelSyntaxSplice inner ->
                    TopLevelSyntaxSplice(substitute inner)
                | TypeSyntaxTokens _ ->
                    current
                | CodeQuote inner ->
                    CodeQuote(substitute inner)
                | CodeSplice inner ->
                    CodeSplice(substitute inner)
                | Handle(isDeep, label, body, returnClause, operationClauses) ->
                    let substituteClause (clause: SurfaceEffectHandlerClause) =
                        { clause with
                            Body = substitute clause.Body }

                    Handle(
                        isDeep,
                        substitute label,
                        substitute body,
                        substituteClause returnClause,
                        operationClauses |> List.map substituteClause
                    )
                | LocalLet(binding, value, body) ->
                    LocalLet(substituteBinding binding, substitute value, substitute body)
                | LocalSignature(declaration, body) ->
                    LocalSignature({ declaration with TypeTokens = substituteTypeTokens declaration.TypeTokens }, substitute body)
                | LocalTypeAlias(declaration, body) ->
                    LocalTypeAlias(
                        { declaration with
                            HeaderTokens = substituteTypeTokens declaration.HeaderTokens
                            BodyTokens = declaration.BodyTokens |> Option.map substituteTypeTokens },
                        substitute body
                    )
                | LocalScopedEffect(declaration, body) ->
                    LocalScopedEffect(declaration, substitute body)
                | Lambda(parameters, body) ->
                    Lambda(parameters |> List.map substituteParameter, substitute body)
                | IfThenElse(condition, whenTrue, whenFalse) ->
                    IfThenElse(substitute condition, substitute whenTrue, substitute whenFalse)
                | Match(scrutinee, cases) ->
                    Match(
                        substitute scrutinee,
                        cases
                        |> List.map (fun caseClause ->
                            { caseClause with
                                Guard = caseClause.Guard |> Option.map substitute
                                Body = substitute caseClause.Body })
                    )
                | RecordLiteral fields ->
                    RecordLiteral(fields |> List.map (fun field -> { field with Value = substitute field.Value }))
                | Seal(value, ascriptionTokens) ->
                    Seal(substitute value, substituteTypeTokens ascriptionTokens)
                | RecordUpdate(receiver, fields) ->
                    RecordUpdate(substitute receiver, fields |> List.map (fun field -> { field with Value = substitute field.Value }))
                | MemberAccess(receiver, segments, arguments) ->
                    MemberAccess(substitute receiver, segments, arguments |> List.map substitute)
                | SafeNavigation(receiver, navigation) ->
                    SafeNavigation(substitute receiver, { navigation with Arguments = navigation.Arguments |> List.map substitute })
                | TagTest(receiver, constructorName) ->
                    TagTest(substitute receiver, constructorName)
                | Do statements ->
                    Do(statements |> List.map substituteDoStatement)
                | MonadicSplice inner ->
                    MonadicSplice(substitute inner)
                | Apply(callee, arguments) ->
                    Apply(substitute callee, arguments |> List.map substitute)
                | ExplicitImplicitArgument inner ->
                    ExplicitImplicitArgument(substitute inner)
                | NamedApplicationBlock fields ->
                    NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = substitute field.Value }))
                | InoutArgument inner ->
                    InoutArgument(substitute inner)
                | Unary(operatorName, inner) ->
                    Unary(operatorName, substitute inner)
                | Binary(left, operatorName, right) ->
                    Binary(substitute left, operatorName, substitute right)
                | Elvis(left, right) ->
                    Elvis(substitute left, substitute right)
                | Comprehension comprehension ->
                    Comprehension { comprehension with Lowered = substitute comprehension.Lowered }
                | PrefixedString(prefix, parts) ->
                    PrefixedString(
                        prefix,
                        parts
                        |> List.map (function
                            | StringText text -> StringText text
                            | StringInterpolation(inner, format) -> StringInterpolation(substitute inner, format))
                    )
                | Literal _
                | NumericLiteral _
                | KindQualifiedName _
                | Name _ ->
                    current

            and substituteDoStatement statement =
                match statement with
                | DoLet(binding, expression) ->
                    DoLet(substituteBinding binding, substitute expression)
                | DoLetQuestion(binding, expression, failure) ->
                    let substitutedFailure =
                        failure
                        |> Option.map (fun failure ->
                            { failure with
                                ResiduePattern = substituteBinding failure.ResiduePattern
                                Body = failure.Body |> List.map substituteDoStatement })

                    DoLetQuestion(substituteBinding binding, substitute expression, substitutedFailure)
                | DoBind(binding, expression) ->
                    DoBind(substituteBinding binding, substitute expression)
                | DoVar(name, expression) ->
                    DoVar(name, substitute expression)
                | DoAssign(name, expression) ->
                    DoAssign(name, substitute expression)
                | DoUsing(binding, expression) ->
                    DoUsing(substituteBinding binding, substitute expression)
                | DoDefer expression ->
                    DoDefer(substitute expression)
                | DoIf(condition, whenTrue, whenFalse) ->
                    DoIf(substitute condition, whenTrue |> List.map substituteDoStatement, whenFalse |> List.map substituteDoStatement)
                | DoWhile(condition, body) ->
                    DoWhile(substitute condition, body |> List.map substituteDoStatement)
                | DoReturn expression ->
                    DoReturn(substitute expression)
                | DoExpression expression ->
                    DoExpression(substitute expression)

            substitute expression

        let annotateLambdaFromSignature (declaration: BindingSignature) value =
            annotateLambdaWithTypeTokens declaration.TypeTokens value

        let mergeVisibleAndLocalTypeAliases localAliases =
            environment.VisibleTypeAliases
            |> Map.fold (fun state name info -> Map.add name info state) localAliases

        let renderLocalSchemeTokens (scheme: TypeScheme) =
            let binderText (binder: TypeSignatures.ForallBinder) =
                let quantityPrefix =
                    match binder.Quantity with
                    | QuantityZero -> ""
                    | quantity -> Quantity.toSurfaceText quantity + " "

                $"({quantityPrefix}{binder.Name} : {TypeSignatures.toText binder.Sort})"

            let constraintText (constraintInfo: TypeSignatures.TraitConstraint) =
                match constraintInfo.Arguments with
                | [] -> traitConstraintText constraintInfo
                | arguments ->
                    String.concat " " ((traitConstraintText constraintInfo) :: (arguments |> List.map TypeSignatures.toText))

            let forallPrefix =
                match scheme.Forall with
                | [] -> ""
                | binders ->
                    "forall " + (binders |> List.map binderText |> String.concat " ") + ". "

            let constraintsPrefix =
                match scheme.Constraints with
                | [] -> ""
                | constraints ->
                    (constraints |> List.map constraintText |> String.concat ", ") + " => "

            typeTextTokens (forallPrefix + constraintsPrefix + TypeSignatures.toText scheme.Body)

        let expandTypeTokensWithLocalAliases localAliases tokens =
            let aliases = mergeVisibleAndLocalTypeAliases localAliases

            match TypeSignatures.parseScheme tokens with
            | Some scheme ->
                { scheme with
                    Forall = scheme.Forall |> List.map (fun binder -> { binder with Sort = normalizeTypeAliases aliases binder.Sort })
                    Constraints =
                        scheme.Constraints
                        |> List.map (fun constraintInfo ->
                            { constraintInfo with
                                Arguments = constraintInfo.Arguments |> List.map (normalizeTypeAliases aliases) })
                    Body = normalizeTypeAliases aliases scheme.Body }
                |> renderLocalSchemeTokens
            | None ->
                tokens
                |> TypeSignatures.parseType
                |> Option.map (normalizeTypeAliases aliases)
                |> Option.map TypeSignatures.toText
                |> Option.map typeTextTokens
                |> Option.defaultValue tokens

        let expandTypeTokenOptionWithLocalAliases localAliases tokens =
            tokens |> Option.map (expandTypeTokensWithLocalAliases localAliases)

        let expandParameterTypeTokens localAliases (parameter: Parameter) =
            { parameter with
                TypeTokens = expandTypeTokenOptionWithLocalAliases localAliases parameter.TypeTokens }

        let expandBindingTypeTokens localAliases (binding: SurfaceBindPattern) =
            { binding with
                TypeTokens = expandTypeTokenOptionWithLocalAliases localAliases binding.TypeTokens }

        let expandEffectDeclarationTypeTokens localAliases (declaration: EffectDeclaration) =
            { declaration with
                HeaderTokens = expandTypeTokensWithLocalAliases localAliases declaration.HeaderTokens
                Operations =
                    declaration.Operations
                    |> List.map (fun operation ->
                        { operation with
                            SignatureTokens = expandTypeTokensWithLocalAliases localAliases operation.SignatureTokens }) }

        let expandTypeAliasTokens localAliases (declaration: TypeAlias) =
            { declaration with
                HeaderTokens = expandTypeTokensWithLocalAliases localAliases declaration.HeaderTokens
                BodyTokens = expandTypeTokenOptionWithLocalAliases localAliases declaration.BodyTokens }

        let rec normalizeLocalDeclarationsWithAliases localAliases expression =
            match expression with
            | SyntaxQuote inner ->
                SyntaxQuote(normalizeLocalDeclarationsWithAliases localAliases inner)
            | SyntaxSplice inner ->
                SyntaxSplice(normalizeLocalDeclarationsWithAliases localAliases inner)
            | TopLevelSyntaxSplice inner ->
                TopLevelSyntaxSplice(normalizeLocalDeclarationsWithAliases localAliases inner)
            | TypeSyntaxTokens _ ->
                expression
            | CodeQuote inner ->
                CodeQuote(normalizeLocalDeclarationsWithAliases localAliases inner)
            | CodeSplice inner ->
                CodeSplice(normalizeLocalDeclarationsWithAliases localAliases inner)
            | Handle(isDeep, label, body, returnClause, operationClauses) ->
                let normalizeClause (clause: SurfaceEffectHandlerClause) =
                    { clause with
                        Body = normalizeLocalDeclarationsWithAliases localAliases clause.Body }

                Handle(
                    isDeep,
                    normalizeLocalDeclarationsWithAliases localAliases label,
                    normalizeLocalDeclarationsWithAliases localAliases body,
                    normalizeClause returnClause,
                    operationClauses |> List.map normalizeClause
                )
            | LocalTypeAlias(declaration, body) ->
                let expandedDeclaration = expandTypeAliasTokens localAliases declaration

                match tryParseTypeAliasInfo environment.CurrentModuleIdentity expandedDeclaration with
                | Some(_, aliasInfo) ->
                    let nextLocalAliases = Map.add declaration.Name aliasInfo localAliases
                    normalizeLocalDeclarationsWithAliases nextLocalAliases body
                | None ->
                    LocalTypeAlias(expandedDeclaration, normalizeLocalDeclarationsWithAliases localAliases body)
            | LocalSignature(declaration, LocalLet(binding, value, body))
                when binding.Pattern = NamePattern declaration.Name ->
                let expandedDeclaration =
                    { declaration with
                        TypeTokens = expandTypeTokensWithLocalAliases localAliases declaration.TypeTokens }

                LocalLet(
                    expandBindingTypeTokens localAliases binding,
                    annotateLambdaFromSignature expandedDeclaration (normalizeLocalDeclarationsWithAliases localAliases value),
                    normalizeLocalDeclarationsWithAliases localAliases body
                )
            | LocalSignature(declaration, body) ->
                let expandedDeclaration =
                    { declaration with
                        TypeTokens = expandTypeTokensWithLocalAliases localAliases declaration.TypeTokens }

                LocalSignature(expandedDeclaration, normalizeLocalDeclarationsWithAliases localAliases body)
            | LocalLet(binding, value, body) ->
                LocalLet(
                    expandBindingTypeTokens localAliases binding,
                    normalizeLocalDeclarationsWithAliases localAliases value,
                    normalizeLocalDeclarationsWithAliases localAliases body
                )
            | LocalScopedEffect(declaration, body) ->
                LocalScopedEffect(
                    expandEffectDeclarationTypeTokens localAliases declaration,
                    normalizeLocalDeclarationsWithAliases localAliases body
                )
            | Lambda(parameters, body) ->
                Lambda(parameters |> List.map (expandParameterTypeTokens localAliases), normalizeLocalDeclarationsWithAliases localAliases body)
            | IfThenElse(condition, whenTrue, whenFalse) ->
                IfThenElse(
                    normalizeLocalDeclarationsWithAliases localAliases condition,
                    normalizeLocalDeclarationsWithAliases localAliases whenTrue,
                    normalizeLocalDeclarationsWithAliases localAliases whenFalse
                )
            | Match(scrutinee, cases) ->
                Match(
                    normalizeLocalDeclarationsWithAliases localAliases scrutinee,
                    cases
                    |> List.map (fun caseClause ->
                        { caseClause with
                            Guard = caseClause.Guard |> Option.map (normalizeLocalDeclarationsWithAliases localAliases)
                            Body = normalizeLocalDeclarationsWithAliases localAliases caseClause.Body })
                )
            | RecordLiteral fields ->
                RecordLiteral(fields |> List.map (fun field -> { field with Value = normalizeLocalDeclarationsWithAliases localAliases field.Value }))
            | Seal(value, ascriptionTokens) ->
                Seal(
                    normalizeLocalDeclarationsWithAliases localAliases value,
                    expandTypeTokensWithLocalAliases localAliases ascriptionTokens
                )
            | RecordUpdate(receiver, fields) ->
                RecordUpdate(
                    receiver |> normalizeLocalDeclarationsWithAliases localAliases,
                    fields |> List.map (fun field -> { field with Value = normalizeLocalDeclarationsWithAliases localAliases field.Value })
                )
            | MemberAccess(receiver, segments, arguments) ->
                MemberAccess(
                    normalizeLocalDeclarationsWithAliases localAliases receiver,
                    segments,
                    arguments |> List.map (normalizeLocalDeclarationsWithAliases localAliases)
                )
            | SafeNavigation(receiver, navigation) ->
                SafeNavigation(
                    normalizeLocalDeclarationsWithAliases localAliases receiver,
                    { navigation with
                        Arguments = navigation.Arguments |> List.map (normalizeLocalDeclarationsWithAliases localAliases) }
                )
            | TagTest(receiver, constructorName) ->
                TagTest(normalizeLocalDeclarationsWithAliases localAliases receiver, constructorName)
            | Do statements ->
                Do(statements |> List.map (normalizeLocalDoStatementWithAliases localAliases))
            | MonadicSplice inner ->
                MonadicSplice(normalizeLocalDeclarationsWithAliases localAliases inner)
            | Apply(callee, arguments) ->
                Apply(
                    normalizeLocalDeclarationsWithAliases localAliases callee,
                    arguments |> List.map (normalizeLocalDeclarationsWithAliases localAliases)
                )
            | ExplicitImplicitArgument inner ->
                ExplicitImplicitArgument(normalizeLocalDeclarationsWithAliases localAliases inner)
            | NamedApplicationBlock fields ->
                NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = normalizeLocalDeclarationsWithAliases localAliases field.Value }))
            | InoutArgument inner ->
                InoutArgument(normalizeLocalDeclarationsWithAliases localAliases inner)
            | Unary(operatorName, inner) ->
                Unary(operatorName, normalizeLocalDeclarationsWithAliases localAliases inner)
            | Binary(left, operatorName, right) ->
                Binary(
                    normalizeLocalDeclarationsWithAliases localAliases left,
                    operatorName,
                    normalizeLocalDeclarationsWithAliases localAliases right
                )
            | Elvis(left, right) ->
                Elvis(
                    normalizeLocalDeclarationsWithAliases localAliases left,
                    normalizeLocalDeclarationsWithAliases localAliases right
                )
            | Comprehension comprehension ->
                Comprehension { comprehension with Lowered = normalizeLocalDeclarationsWithAliases localAliases comprehension.Lowered }
            | PrefixedString(prefix, parts) ->
                PrefixedString(
                    prefix,
                    parts
                    |> List.map (function
                        | StringText text -> StringText text
                        | StringInterpolation(inner, format) -> StringInterpolation(normalizeLocalDeclarationsWithAliases localAliases inner, format))
                )
            | Literal _
            | NumericLiteral _
            | KindQualifiedName _
            | Name _ ->
                expression

        and normalizeLocalDoStatementWithAliases localAliases statement =
            match statement with
            | DoLet(binding, expression) ->
                DoLet(expandBindingTypeTokens localAliases binding, normalizeLocalDeclarationsWithAliases localAliases expression)
            | DoLetQuestion(binding, expression, failure) ->
                let normalizedFailure =
                    failure
                    |> Option.map (fun failure ->
                        { failure with
                            ResiduePattern = expandBindingTypeTokens localAliases failure.ResiduePattern
                            Body = failure.Body |> List.map (normalizeLocalDoStatementWithAliases localAliases) })

                DoLetQuestion(expandBindingTypeTokens localAliases binding, normalizeLocalDeclarationsWithAliases localAliases expression, normalizedFailure)
            | DoBind(binding, expression) ->
                DoBind(expandBindingTypeTokens localAliases binding, normalizeLocalDeclarationsWithAliases localAliases expression)
            | DoVar(name, expression) ->
                DoVar(name, normalizeLocalDeclarationsWithAliases localAliases expression)
            | DoAssign(name, expression) ->
                DoAssign(name, normalizeLocalDeclarationsWithAliases localAliases expression)
            | DoUsing(binding, expression) ->
                DoUsing(expandBindingTypeTokens localAliases binding, normalizeLocalDeclarationsWithAliases localAliases expression)
            | DoDefer expression ->
                DoDefer(normalizeLocalDeclarationsWithAliases localAliases expression)
            | DoIf(condition, whenTrue, whenFalse) ->
                DoIf(
                    normalizeLocalDeclarationsWithAliases localAliases condition,
                    whenTrue |> List.map (normalizeLocalDoStatementWithAliases localAliases),
                    whenFalse |> List.map (normalizeLocalDoStatementWithAliases localAliases)
                )
            | DoWhile(condition, body) ->
                DoWhile(
                    normalizeLocalDeclarationsWithAliases localAliases condition,
                    body |> List.map (normalizeLocalDoStatementWithAliases localAliases)
                )
            | DoReturn expression ->
                DoReturn(normalizeLocalDeclarationsWithAliases localAliases expression)
            | DoExpression expression ->
                DoExpression(normalizeLocalDeclarationsWithAliases localAliases expression)

        let body = normalizeLocalDeclarationsWithAliases Map.empty body

        let rec inferExpressionType localTypes expression =
            let normalizeVisibleType typeExpr =
                typeExpr |> qualifyVisibleTypeNames environment |> normalizeTypeAliases environment.VisibleTypeAliases
            let visibleTypeEquals left right =
                TypeSignatures.definitionallyEqual (normalizeVisibleType left) (normalizeVisibleType right)

            match expression with
            | Literal literal ->
                Some(inferLiteralType literal)
            | NumericLiteral literal ->
                match SurfaceNumericLiteral.suffix literal with
                | Some suffixName ->
                    inferExpressionType localTypes (Apply(Name [ suffixName ], [ NumericLiteral(SurfaceNumericLiteral.withoutSuffix literal) ]))
                | None ->
                    Some(inferSurfaceNumericLiteralType literal)
            | TypeSyntaxTokens tokens ->
                TypeSignatures.parseType tokens |> Option.map (fun _ -> TypeName([ "Type" ], []))
            | SyntaxQuote inner ->
                inferExpressionType localTypes inner
                |> Option.map syntaxType
            | SyntaxSplice inner ->
                inferExpressionType localTypes inner
                |> Option.bind (function
                    | TypeName(nameSegments, [ innerType ]) when
                        matchesKnownType CompilerKnownSymbols.SyntaxType nameSegments -> Some innerType
                    | _ -> None)
            | TopLevelSyntaxSplice inner ->
                inferExpressionType localTypes inner
                |> Option.bind (function
                    | TypeName(nameSegments, [ innerType ]) when
                        matchesKnownType CompilerKnownSymbols.SyntaxType nameSegments -> Some innerType
                    | _ -> None)
            | CodeQuote inner ->
                inferExpressionType localTypes inner
                |> Option.map codeType
            | CodeSplice inner ->
                inferExpressionType localTypes inner
                |> Option.bind (function
                    | TypeName(nameSegments, [ innerType ]) when
                        matchesKnownType CompilerKnownSymbols.CodeType nameSegments -> Some innerType
                    | _ -> None)
            | Name [ "True" ]
            | Name [ "False" ] ->
                Some boolType
            | KindQualifiedName _ ->
                tryResolveScopedStaticObject environment expression
                |> Option.bind (fun staticObject -> staticObject.Scheme)
                |> Option.map (fun scheme -> scheme.Body)
            | Name [ effectName ] when tryFindScopedEffectDeclaration effectName |> Option.isSome ->
                Some(TypeIntrinsic EffLabelClassifier)
            | Name(root :: path) ->
                let resolvedStaticObjectType =
                    tryResolveScopedStaticObject environment expression
                    |> Option.bind (fun staticObject ->
                        match staticObject.ObjectKind with
                        | EffectLabelObject ->
                            staticObject.Scheme |> Option.map (fun scheme -> scheme.Body)
                        | _ ->
                            None)

                let scopedEffectOperationType =
                    match path with
                    | [ operationName ] ->
                        tryFindScopedEffectOperation root operationName
                        |> Option.bind (fun (_, operation) ->
                            operation.SignatureTokens
                            |> TypeSignatures.parseType
                            |> Option.map (qualifyVisibleTypeNames environment))
                    | _ ->
                        None

                let resolvedEffectOperationType =
                    tryResolveEffectOperationNamePath environment (root :: path)
                    |> Option.bind (fun (_, _, operation) ->
                        operation.SignatureTokens
                        |> TypeSignatures.parseType
                        |> Option.map (qualifyVisibleTypeNames environment))

                let ordinaryResolution =
                    localTypes
                    |> Map.tryFind root
                    |> Option.orElseWith (fun () ->
                        environment.VisibleConstructors
                        |> Map.tryFind root
                        |> Option.bind (fun constructorInfo ->
                            if List.isEmpty path then
                                tryPrepareVisibleBindingCall
                                    environment
                                    freshCounter
                                    constructorInfo
                                    (Some localTypes)
                                    (inferValidationExpressionTypeWithContext
                                        environment
                                        freshCounter
                                        localTypes
                                        localTypes)
                                    (tryResolveUniqueLocalImplicitByType environment localTypes)
                                    []
                                |> Option.map (fun preparedCall -> preparedCall.ResultType)
                            else
                                None))
                    |> Option.orElseWith (fun () ->
                        environment.VisibleBindings
                        |> Map.tryFind root
                        |> Option.bind (fun bindingInfo ->
                            if List.isEmpty path then
                                if bindingHasResolvableLocalRuntimeImplicitParameter environment localTypes bindingInfo then
                                    tryPrepareVisibleBindingCall
                                        environment
                                        freshCounter
                                        bindingInfo
                                        (Some localTypes)
                                        (inferValidationExpressionTypeWithContext
                                            environment
                                            freshCounter
                                            localTypes
                                            localTypes)
                                        (tryResolveUniqueLocalImplicitByType environment localTypes)
                                        []
                                    |> Option.map (fun preparedCall -> preparedCall.ResultType)
                                    |> Option.orElseWith (fun () -> instantiateVisibleBindingBodyType environment freshCounter root)
                                elif bindingHasRuntimeImplicitParameter environment bindingInfo then
                                    None
                                else
                                    instantiateVisibleBindingBodyType environment freshCounter root
                            else
                                None))
                    |> Option.orElseWith (fun () ->
                        tryResolveScopedStaticObject environment (Name [ root ])
                        |> Option.bind (fun staticObject ->
                            if List.isEmpty path then
                                staticObject.Scheme |> Option.map (fun scheme -> scheme.Body)
                            else
                                None))
                    |> Option.bind (fun rootType -> tryProjectVisibleRecordType environment.VisibleTypeAliases rootType path)

                match path with
                | [ memberName ] ->
                    scopedEffectOperationType
                    |> Option.orElse resolvedStaticObjectType
                    |> Option.orElse resolvedEffectOperationType
                    |> Option.orElseWith (fun () -> tryReceiverProjection environment localTypes root memberName |> Option.map (fun projectionInfo -> projectionInfo.ReturnType))
                    |> Option.orElseWith (fun () ->
                        tryInferStaticConstructorCall
                            environment
                            freshCounter
                            (inferValidationExpressionTypeWithContext
                                environment
                                freshCounter
                                localTypes
                                localTypes)
                            (Name [ root ])
                            memberName
                            [])
                    |> Option.orElse ordinaryResolution
                | _ ->
                    resolvedStaticObjectType
                    |> Option.orElse resolvedEffectOperationType
                    |> Option.orElse ordinaryResolution
            | Name [] ->
                None
            | Apply(MemberAccess(receiver, [ memberName ], []), arguments) ->
                match
                    tryResolveHandledEffectDeclaration environment receiver
                    |> Option.bind (fun declaration ->
                        EffectSemantics.tryFindOperation memberName declaration
                        |> Option.bind (fun operation ->
                            operation.SignatureTokens
                            |> TypeSignatures.parseType
                            |> Option.map (qualifyVisibleTypeNames environment)
                            |> Option.map TypeSignatures.functionParts
                            |> Option.map (fun (parameterTypes, resultType) -> declaration, parameterTypes, resultType)))
                with
                | Some(declaration, parameterTypes, resultType) when List.length parameterTypes = List.length arguments ->
                    Some(effType (scopedEffectRowType declaration) resultType)
                | _ ->
                    match tryInferQueryCarrierType environment freshCounter localTypes inferExpressionType expression with
                    | Some queryCarrierType ->
                        Some queryCarrierType
                    | None ->
                        inferApplicationType localTypes expression
            | Apply(Name nameSegments, arguments) ->
                match
                    tryResolveEffectOperationNamePath environment nameSegments
                    |> Option.bind (fun (_, declaration, operation) ->
                        operation.SignatureTokens
                        |> TypeSignatures.parseType
                        |> Option.map (qualifyVisibleTypeNames environment)
                        |> Option.map (fun signature -> declaration, TypeSignatures.functionParts signature))
                with
                | Some(declaration, (parameterTypes, resultType)) when List.length parameterTypes = List.length arguments ->
                    Some(effType (scopedEffectRowType declaration) resultType)
                | _ ->
                    match tryInferQueryCarrierType environment freshCounter localTypes inferExpressionType expression with
                    | Some queryCarrierType ->
                        Some queryCarrierType
                    | None ->
                        inferApplicationType localTypes expression
            | LocalSignature(_, body) ->
                inferExpressionType localTypes body
            | LocalTypeAlias(_, body) ->
                inferExpressionType localTypes body
            | LocalLet(binding, value, body) ->
                let value =
                    binding.TypeTokens
                    |> Option.map (fun typeTokens -> annotateLambdaWithTypeTokens typeTokens value)
                    |> Option.defaultValue value

                let bindingNames = collectPatternNames binding.Pattern

                let bindingDeclaredType =
                    binding.TypeTokens
                    |> Option.bind TypeSignatures.parseType
                    |> Option.map (qualifyVisibleTypeNames environment)

                let valueLocals =
                    match binding.Pattern, bindingDeclaredType, value with
                    | NamePattern bindingName, Some declaredType, Lambda _ ->
                        Map.add bindingName declaredType localTypes
                    | _ ->
                        localTypes

                let nextLocals =
                    match inferExpressionType valueLocals value with
                    | Some valueType ->
                        extendBindingLocalTypes environment freshCounter localTypes binding (Some valueType)
                    | None ->
                        extendBindingLocalTypes
                            environment
                            freshCounter
                            localTypes
                            binding
                            (Some(inferFallbackLocalType freshCounter value))

                let bodyForInference =
                    match bindingNames, tryResolveScopedStaticObject environment value with
                    | [ aliasName ], Some staticObject ->
                        rewriteStaticObjectAliasUse aliasName staticObject body
                    | _ ->
                        body

                let localStaticAliases = collectScopedPatternStaticAliases environment binding.Pattern value
                let bodyForInference = rewriteStaticObjectPathAliasUses localStaticAliases bodyForInference
                let localEffectOperationAliases = collectScopedPatternEffectOperationAliases environment binding.Pattern value
                let bodyForInference = rewriteEffectOperationPathAliasUses environment localEffectOperationAliases bodyForInference

                inferExpressionType nextLocals bodyForInference
            | LocalScopedEffect(declaration, body) ->
                withScopedEffectDeclaration environment.CurrentModuleIdentity declaration (fun () -> inferExpressionType localTypes body)
            | Handle(_, label, body, returnClause, _) ->
                let handledResultType =
                    match
                        tryResolveHandledEffectDeclaration environment label,
                        inferExpressionType localTypes body |> Option.bind tryUnwrapEffType
                    with
                    | Some declaration, Some(effectRow, payloadType) ->
                        match trySplitHandledEffectRow environment.VisibleTypeAliases declaration effectRow with
                        | SplitResolved remainderRow -> Some(effType remainderRow payloadType)
                        | _ -> None
                    | _ ->
                        None

                handledResultType
                |> Option.orElseWith (fun () -> inferExpressionType localTypes returnClause.Body)
            | Lambda(lambdaParameters, lambdaBody) ->
                let parameterTypes =
                    lambdaParameters
                    |> List.map (fun parameter ->
                        tryParseParameterType parameter
                        |> Option.map (qualifyVisibleTypeNames environment)
                        |> Option.defaultValue (TypeVariable $"lambda{freshCounter.Value}"))

                let parameterQuantities =
                    lambdaParameters
                    |> List.map (fun parameter -> parameter.Quantity |> Option.defaultValue QuantityOmega)

                let lambdaLocals =
                    List.zip lambdaParameters parameterTypes
                    |> List.fold (fun state (parameter, parameterType) -> Map.add parameter.Name parameterType state) localTypes

                inferExpressionType lambdaLocals lambdaBody
                |> Option.map (fun resultType ->
                    List.zip parameterTypes parameterQuantities
                    |> List.rev
                    |> List.fold (fun state (parameterType, quantity) -> TypeArrow(quantity, parameterType, state)) resultType)
            | IfThenElse(_, whenTrue, whenFalse) ->
                match inferExpressionType localTypes whenTrue, inferExpressionType localTypes whenFalse with
                | Some trueType, Some falseType when trueType = falseType ->
                    Some trueType
                | _ ->
                    None
            | Match(scrutinee, cases) ->
                let scrutineeType = inferExpressionType localTypes scrutinee

                cases
                |> List.choose (fun caseClause ->
                    let caseLocals =
                        extendPatternLocalTypes environment freshCounter localTypes scrutineeType caseClause.Pattern

                    inferExpressionType caseLocals caseClause.Body)
                |> function
                    | first :: rest when rest |> List.forall ((=) first) -> Some first
                    | _ -> None
            | RecordLiteral fields ->
                let inferredFields =
                    fields
                    |> List.map (fun field ->
                        inferExpressionType localTypes field.Value
                        |> Option.map (fun fieldType ->
                            ({ Name = field.Name
                               Quantity = if field.IsImplicit then QuantityZero else QuantityOmega
                               Type = fieldType }: TypeSignatures.RecordField)))

                if inferredFields |> List.forall Option.isSome then
                    inferredFields
                    |> List.choose id
                    |> TypeRecord
                    |> Some
                else
                    None
            | Seal(value, _) ->
                inferExpressionType localTypes value
            | RecordUpdate(receiver, _) ->
                inferExpressionType localTypes receiver
            | MemberAccess(receiver, segments, arguments) ->
                match segments with
                | [] ->
                    inferExpressionType localTypes receiver
                    |> Option.bind (fun receiverType ->
                        tryInferVisibleAppliedType
                            environment.VisibleTypeAliases
                            (qualifyVisibleTypeNames environment)
                            (inferExpressionType localTypes)
                            receiverType
                            arguments)
                | [ memberName ] ->
                    (tryResolveHandledEffectDeclaration environment receiver
                     |> Option.bind (fun declaration ->
                         EffectSemantics.tryFindOperation memberName declaration
                         |> Option.bind (fun operation ->
                             operation.SignatureTokens
                             |> TypeSignatures.parseType
                             |> Option.map (qualifyVisibleTypeNames environment)
                             |> Option.bind (fun operationType ->
                                 let parameterTypes, resultType = TypeSignatures.functionParts operationType

                                 if List.length arguments = List.length parameterTypes then
                                     Some(effType (scopedEffectRowType declaration) resultType)
                                 else
                                 tryInferVisibleAppliedType
                                         environment.VisibleTypeAliases
                                         (qualifyVisibleTypeNames environment)
                                         (inferValidationExpressionTypeWithContext
                                             environment
                                             freshCounter
                                             localTypes
                                             localImplicitTypes)
                                         operationType
                                         arguments))))
                    |> Option.orElseWith (fun () ->
                        tryInferStaticConstructorCall
                            environment
                            freshCounter
                            (inferValidationExpressionTypeWithContext
                                environment
                                freshCounter
                                localTypes
                                localTypes)
                            receiver
                            memberName
                            arguments)
                    |> Option.orElseWith (fun () ->
                        environment.VisibleBindings
                        |> Map.tryFind memberName
                        |> Option.bind (fun bindingInfo ->
                            tryBuildReceiverMethodArguments bindingInfo receiver arguments
                            |> Option.bind (fun receiverArguments ->
                                tryPrepareVisibleBindingCall
                                    environment
                                    freshCounter
                                    bindingInfo
                                    (Some localTypes)
                                    (inferValidationExpressionTypeWithContext
                                        environment
                                        freshCounter
                                        localTypes
                                        localTypes)
                                    (tryResolveUniqueLocalImplicitByType environment localTypes)
                                    receiverArguments
                                |> Option.map (fun preparedCall -> preparedCall.ResultType))))
                    |> Option.orElseWith (fun () ->
                        inferExpressionType localTypes receiver
                        |> Option.bind (fun receiverType ->
                            tryProjectVisibleRecordType environment.VisibleTypeAliases receiverType [ memberName ]
                            |> Option.bind (fun memberType ->
                                tryInferVisibleAppliedType
                                    environment.VisibleTypeAliases
                                    (qualifyVisibleTypeNames environment)
                                    (inferValidationExpressionTypeWithContext
                                        environment
                                        freshCounter
                                        localTypes
                                        localImplicitTypes)
                                    memberType
                                    arguments)))
                    |> Option.orElseWith (fun () ->
                        inferExpressionType localTypes receiver
                        |> Option.bind (fun receiverType ->
                            tryResolveTraitMemberFromReceiverType environment receiverType memberName
                            |> Option.bind (fun (traitInfo, resolvedMemberName, resolvedArguments) ->
                                traitInfo.Members
                                |> Map.tryFind resolvedMemberName
                                |> Option.bind (fun memberInfo ->
                                    let specializedScheme =
                                        if List.length traitInfo.TypeParameters = List.length resolvedArguments then
                                            List.zip traitInfo.TypeParameters resolvedArguments
                                            |> Map.ofList
                                            |> fun substitution -> TypeSignatures.applySchemeSubstitution substitution memberInfo.Scheme
                                        else
                                            memberInfo.Scheme

                                    tryInferVisibleAppliedType
                                        environment.VisibleTypeAliases
                                        (qualifyVisibleTypeNames environment)
                                        (inferValidationExpressionTypeWithContext
                                            environment
                                            freshCounter
                                            localTypes
                                            localImplicitTypes)
                                        specializedScheme.Body
                                        arguments))))
                | memberName :: rest ->
                    inferExpressionType localTypes (MemberAccess(MemberAccess(receiver, [ memberName ], []), rest, arguments))
            | SafeNavigation(receiver, navigation) ->
                inferExpressionType localTypes receiver
                |> Option.bind (fun receiverType ->
                    tryOptionPayloadType environment.VisibleTypeAliases receiverType
                    |> Option.bind (fun payloadType ->
                        tryInferSafeNavigationMemberType
                            environment.VisibleTypeAliases
                            (qualifyVisibleTypeNames environment)
                            (inferExpressionType localTypes)
                            payloadType
                            navigation
                        |> Option.map (fun memberType ->
                            match tryOptionPayloadType environment.VisibleTypeAliases memberType with
                            | Some _ -> memberType
                            | None -> knownTypeExpr CompilerKnownSymbols.OptionType [ memberType ])))
            | TagTest _ ->
                Some boolType
            | Do statements ->
                inferDoResultType localTypes statements
            | MonadicSplice inner ->
                inferExpressionType localTypes inner |> Option.map unwrapIoType
            | ExplicitImplicitArgument inner ->
                inferExpressionType localTypes inner
            | NamedApplicationBlock _ ->
                None
            | InoutArgument inner ->
                inferExpressionType localTypes inner
            | Apply _ as application ->
                inferApplicationType localTypes application
            | Unary("not", _) ->
                Some boolType
            | Unary(("negate" | "-"), operand) ->
                inferExpressionType localTypes operand
            | Unary _ ->
                None
            | Binary(left, ("+" | "-" | "*" | "/"), right) ->
                match inferExpressionType localTypes left, inferExpressionType localTypes right with
                | Some leftType, Some rightType when visibleTypeEquals leftType intType && visibleTypeEquals rightType intType ->
                    Some intType
                | Some leftType, Some rightType when visibleTypeEquals leftType floatType && visibleTypeEquals rightType floatType ->
                    Some floatType
                | _ ->
                    None
            | Binary(_, ("==" | "!=" | "<" | ">" | "<=" | ">=" | "&&" | "||"), _) ->
                Some boolType
            | Binary(left, operatorName, right) ->
                inferExpressionType localTypes (Apply(Name [ operatorName ], [ left; right ]))
            | Elvis(left, right) ->
                match inferExpressionType localTypes left, inferExpressionType localTypes right with
                | Some leftType, Some defaultType ->
                    tryOptionPayloadType environment.VisibleTypeAliases leftType
                    |> Option.bind (fun payloadType ->
                        tryUnifyVisibleTypes environment.VisibleTypeAliases [ payloadType, defaultType ]
                        |> Option.map (fun substitution ->
                            TypeSignatures.applySubstitution substitution payloadType)
                        |> Option.orElseWith (fun () ->
                            if
                                TypeSignatures.definitionallyEqual
                                    (normalizeTypeAliases environment.VisibleTypeAliases payloadType)
                                    (normalizeTypeAliases environment.VisibleTypeAliases defaultType)
                            then
                                Some payloadType
                            else
                                None))
                | _ ->
                    None
            | Comprehension comprehension ->
                inferExpressionType localTypes comprehension.Lowered
            | PrefixedString(prefix, _) ->
                tryInferPrefixedStringMacroResultType environment freshCounter localTypes prefix

        and inferApplicationType localTypes application =
            tryInferQueryCarrierType
                environment
                freshCounter
                localTypes
                (fun currentLocals currentExpression -> inferExpressionType currentLocals currentExpression)
                application
            |> Option.orElseWith (fun () ->
                match application with
                | Apply(Name [ receiverName; memberName ], arguments) ->
                    tryInferStaticConstructorCall
                        environment
                        freshCounter
                        (inferValidationExpressionTypeWithContext
                            environment
                            freshCounter
                            localTypes
                            localImplicitTypes)
                        (Name [ receiverName ])
                        memberName
                        arguments
                    |> Option.orElseWith (fun () ->
                        tryPrepareResolvedTraitProjectionCall
                            environment
                            freshCounter
                            localTypes
                            [ receiverName; memberName ]
                            (inferExpressionType localTypes)
                            arguments
                        |> Option.map (fun preparedCall -> preparedCall.ResultType))
                    |> Option.orElseWith (fun () ->
                        environment.VisibleBindings
                        |> Map.tryFind memberName
                        |> Option.bind (fun bindingInfo ->
                            tryBuildReceiverMethodArguments bindingInfo (Name [ receiverName ]) arguments
                            |> Option.bind (fun receiverArguments ->
                            tryPrepareVisibleBindingCall
                                environment
                                freshCounter
                                bindingInfo
                                (Some localTypes)
                                (inferValidationExpressionTypeWithContext
                                    environment
                                    freshCounter
                                    localTypes
                                    localTypes)
                                (tryResolveUniqueLocalImplicitByType environment localTypes)
                                receiverArguments
                            |> Option.map (fun preparedCall -> preparedCall.ResultType))))
                | Apply(Name [ calleeName ], arguments) ->
                    localTypes
                    |> Map.tryFind calleeName
                    |> Option.bind (fun localType ->
                        tryInferVisibleAppliedType
                            environment.VisibleTypeAliases
                            (qualifyVisibleTypeNames environment)
                            (inferExpressionType localTypes)
                            localType
                            arguments)
                    |> Option.orElseWith (fun () ->
                        if ordinarySurfaceNameShadowsVisiblePreludeBinding environment localTypes calleeName then
                            None
                        else
                            environment.VisibleConstructors
                            |> Map.tryFind calleeName
                            |> Option.bind (fun constructorInfo ->
                                tryPrepareVisibleBindingCall
                                    environment
                                    freshCounter
                                    constructorInfo
                                    (Some localTypes)
                                    (inferValidationExpressionTypeWithContext
                                        environment
                                        freshCounter
                                        localTypes
                                        localTypes)
                                    (tryResolveUniqueLocalImplicitByType environment localTypes)
                                    arguments
                                |> Option.map (fun preparedCall -> preparedCall.ResultType)))
                    |> Option.orElseWith (fun () ->
                        if ordinarySurfaceNameShadowsVisiblePreludeBinding environment localTypes calleeName then
                            None
                        else
                            environment.VisibleBindings
                            |> Map.tryFind calleeName
                            |> Option.bind (fun bindingInfo ->
                                let preparedResultType =
                                    tryPrepareVisibleBindingCall
                                        environment
                                        freshCounter
                                        bindingInfo
                                        (Some localTypes)
                                        (inferValidationExpressionTypeWithContext
                                            environment
                                            freshCounter
                                            localTypes
                                            localTypes)
                                        (tryResolveUniqueLocalImplicitByType environment localTypes)
                                        arguments
                                    |> Option.map (fun preparedCall -> preparedCall.ResultType)

                                preparedResultType
                                |> Option.orElseWith (fun () ->
                                    instantiateVisibleBindingBodyType environment freshCounter calleeName
                                    |> Option.bind (fun bodyType ->
                                        tryInferVisibleAppliedType
                                            environment.VisibleTypeAliases
                                            (qualifyVisibleTypeNames environment)
                                            (inferValidationExpressionTypeWithContext
                                                environment
                                                freshCounter
                                                localTypes
                                                localTypes)
                                            bodyType
                                            arguments))))
                    |> Option.orElseWith (fun () ->
                        tryPrepareVisibleTraitMemberCall
                            environment
                            freshCounter
                            calleeName
                            (inferValidationExpressionTypeWithContext
                                environment
                                freshCounter
                                localTypes
                                localTypes)
                            arguments
                        |> Option.map (fun (_, _, preparedCall, _) -> preparedCall.ResultType))
                    |> Option.orElseWith (fun () ->
                        environment.VisibleProjections
                        |> Map.tryFind calleeName
                        |> Option.bind (fun projectionInfo ->
                            tryInferProjectionCallResultType localTypes projectionInfo arguments))
                | _ ->
                    None)

        and tryInferProjectionCallResultType localTypes (projectionInfo: ProjectionInfo) arguments =
            if List.length projectionInfo.Binders <> List.length arguments then
                None
            else
                let tryUnifyExpected expectedType actualType substitution =
                    let expectedType = TypeSignatures.applySubstitution substitution expectedType

                    tryUnifyVisibleTypes environment.VisibleTypeAliases [ expectedType, actualType ]
                    |> Option.map (composeTypeSubstitution substitution)
                    |> Option.orElseWith (fun () ->
                        if
                            TypeSignatures.definitionallyEqual
                                (normalizeTypeAliases environment.VisibleTypeAliases expectedType)
                                (normalizeTypeAliases environment.VisibleTypeAliases actualType)
                        then
                            Some substitution
                        else
                            None)

                let rec tryInferPlaceExpressionType expression =
                    match expression with
                    | Name(root :: path) ->
                        localTypes
                        |> Map.tryFind root
                        |> Option.bind (fun rootType ->
                            tryProjectVisibleRecordType environment.VisibleTypeAliases rootType path)
                    | Apply(Name [ projectionName ], projectionArguments) ->
                        environment.VisibleProjections
                        |> Map.tryFind projectionName
                        |> Option.bind (fun nestedProjectionInfo ->
                            tryInferProjectionCallResultType localTypes nestedProjectionInfo projectionArguments)
                    | _ ->
                        None

                (Some Map.empty, List.zip projectionInfo.Binders arguments)
                ||> List.fold (fun current (binder, argument) ->
                    current
                    |> Option.bind (fun substitution ->
                        match binder with
                        | ProjectionPlaceBinder placeBinder ->
                            match TypeSignatures.parseType placeBinder.TypeTokens, tryInferPlaceExpressionType argument with
                            | Some expectedType, Some actualType ->
                                tryUnifyExpected expectedType actualType substitution
                            | _ ->
                                None
                        | ProjectionValueBinder valueBinder ->
                            match tryParseParameterType valueBinder, inferExpressionType localTypes argument with
                            | Some expectedType, Some actualType ->
                                tryUnifyExpected expectedType actualType substitution
                            | _ ->
                                None))
                |> Option.map (fun substitution ->
                    TypeSignatures.applySubstitution substitution projectionInfo.ReturnType)

        and inferDoResultType localTypes statements =
            let tryMergeBranchResultTypes leftType rightType =
                tryUnifyVisibleTypes environment.VisibleTypeAliases [ leftType, rightType ]
                |> Option.map (fun substitution ->
                    TypeSignatures.applySubstitution substitution leftType)
                |> Option.orElseWith (fun () ->
                    if
                        TypeSignatures.definitionallyEqual
                            (normalizeTypeAliases environment.VisibleTypeAliases leftType)
                            (normalizeTypeAliases environment.VisibleTypeAliases rightType)
                    then
                        Some leftType
                    else
                        None)

            match statements with
            | [] ->
                Some unitType
            | DoExpression expression :: [] ->
                inferExpressionType localTypes expression
            | DoExpression _ :: rest ->
                inferDoResultType localTypes rest
            | DoLet(binding, expression) :: rest ->
                let nextLocals =
                    inferExpressionType localTypes expression
                    |> Option.map (fun valueType ->
                        extendPatternLocalTypes environment freshCounter localTypes (Some valueType) binding.Pattern)
                    |> Option.defaultValue localTypes

                inferDoResultType nextLocals rest
            | DoLetQuestion(binding, expression, failure) :: rest ->
                let nextLocals =
                    inferExpressionType localTypes expression
                    |> Option.map (fun valueType ->
                        extendPatternLocalTypes environment freshCounter localTypes (Some valueType) binding.Pattern)
                    |> Option.defaultValue localTypes

                failure
                |> Option.iter (fun failure -> inferDoResultType localTypes failure.Body |> ignore)

                inferDoResultType nextLocals rest
            | DoBind(binding, expression) :: rest ->
                let nextLocals =
                    inferExpressionType localTypes expression
                    |> Option.map (fun valueType ->
                        extendPatternLocalTypes
                            environment
                            freshCounter
                            localTypes
                            (Some(unwrapBindPayloadType valueType))
                            binding.Pattern)
                    |> Option.defaultValue localTypes

                inferDoResultType nextLocals rest
            | DoUsing(binding, expression) :: rest ->
                let nextLocals =
                    inferExpressionType localTypes expression
                    |> Option.map (fun valueType ->
                        extendPatternLocalTypes
                            environment
                            freshCounter
                            localTypes
                            (Some(unwrapIoType valueType))
                            binding.Pattern)
                    |> Option.defaultValue localTypes

                inferDoResultType nextLocals rest
            | DoVar(bindingName, expression) :: rest ->
                let nextLocals =
                    match inferExpressionType localTypes expression with
                    | Some valueType -> Map.add bindingName (refType valueType) localTypes
                    | None -> localTypes

                inferDoResultType nextLocals rest
            | DoAssign _ :: rest ->
                inferDoResultType localTypes rest
            | DoDefer _ :: rest ->
                inferDoResultType localTypes rest
            | DoIf(_, whenTrue, whenFalse) :: [] ->
                match inferDoResultType localTypes whenTrue, inferDoResultType localTypes whenFalse with
                | Some whenTrueType, Some whenFalseType ->
                    tryMergeBranchResultTypes whenTrueType whenFalseType
                | _ ->
                    None
            | DoIf(_, _, _) :: rest ->
                inferDoResultType localTypes rest
            | DoWhile _ :: rest ->
                inferDoResultType localTypes rest
            | DoReturn expression :: _ ->
                inferExpressionType localTypes expression

        and buildUsingReleaseAction localTypes expression hiddenOwnedName =
            let defaultRelease =
                KCoreRelease(None, KCoreName [ "release" ], KCoreName [ hiddenOwnedName ])

            match inferExpressionType localTypes expression with
            | Some(TypeName(monadName, [ resourceType ])) ->
                let monadType = TypeName(monadName, [])

                let releasableConstraint =
                    unqualifiedTraitConstraint "Releasable" [ monadType; resourceType ]

                match tryLowerResolvedDictionaryValue environment releasableConstraint with
                | Some dictionaryValue ->
                    KCoreRelease(
                        Some(TypeSignatures.toText resourceType),
                        KCoreTraitCall("Releasable", "release", dictionaryValue, []),
                        KCoreName [ hiddenOwnedName ]
                    )
                | None ->
                    defaultRelease
            | _ ->
                defaultRelease

        and buildPlaceWritebackExpression rootName path replacement =
            let rec loop currentSegments remainingPath =
                match remainingPath with
                | [] ->
                    replacement
                | fieldName :: rest ->
                    let nestedValue = loop (currentSegments @ [ fieldName ]) rest

                    RecordUpdate(
                        Name currentSegments,
                        [
                            { Name = fieldName
                              IsImplicit = false
                              IsExtension = false
                              Path =
                                  [ { Name = fieldName
                                      IsImplicit = false } ]
                              Value = nestedValue }
                        ]
                    )

            loop [ rootName ] path

        and tryExpressionPlace expression =
            match expression with
            | Name(root :: path) ->
                Some(root, path)
            | _ ->
                None

        and unwrapRefLikeType typeExpr =
            match normalizeTypeAliases environment.VisibleTypeAliases typeExpr with
            | TypeName(nameSegments, [ inner ]) when
                matchesKnownType CompilerKnownSymbols.RefType nameSegments -> Some inner
            | _ -> None

        and substituteProjectionExpression
            (placeArguments: Map<string, string * string list>)
            (valueArguments: Map<string, SurfaceExpression>)
            expression
            =
            let rec loop current =
                match current with
                | Name(root :: path) ->
                    match Map.tryFind root placeArguments with
                    | Some(actualRoot, actualPath) ->
                        Name(actualRoot :: (actualPath @ path))
                    | None ->
                        match Map.tryFind root valueArguments with
                        | Some replacement when List.isEmpty path ->
                            replacement
                        | Some(Name replacementSegments) ->
                            Name(replacementSegments @ path)
                        | _ ->
                            current
                | Name [] ->
                    current
                | TypeSyntaxTokens _ ->
                    current
                | SyntaxQuote inner ->
                    SyntaxQuote(loop inner)
                | SyntaxSplice inner ->
                    SyntaxSplice(loop inner)
                | TopLevelSyntaxSplice inner ->
                    TopLevelSyntaxSplice(loop inner)
                | CodeQuote inner ->
                    CodeQuote(loop inner)
                | CodeSplice inner ->
                    CodeSplice(loop inner)
                | Handle(isDeep, label, body, returnClause, operationClauses) ->
                    let loopClause (clause: SurfaceEffectHandlerClause) =
                        { clause with
                            Body = loop clause.Body }

                    Handle(
                        isDeep,
                        loop label,
                        loop body,
                        loopClause returnClause,
                        operationClauses |> List.map loopClause
                    )
                | LocalLet(binding, value, body) ->
                    LocalLet(binding, loop value, loop body)
                | LocalSignature(declaration, body) ->
                    LocalSignature(declaration, loop body)
                | LocalTypeAlias(declaration, body) ->
                    LocalTypeAlias(declaration, loop body)
                | LocalScopedEffect(declaration, body) ->
                    LocalScopedEffect(declaration, loop body)
                | Lambda(parameters, body) ->
                    Lambda(parameters, loop body)
                | IfThenElse(condition, whenTrue, whenFalse) ->
                    IfThenElse(loop condition, loop whenTrue, loop whenFalse)
                | Match(scrutinee, cases) ->
                    Match(
                        loop scrutinee,
                        cases
                        |> List.map (fun caseClause ->
                            { caseClause with
                                Guard = caseClause.Guard |> Option.map loop
                                Body = loop caseClause.Body })
                    )
                | RecordLiteral fields ->
                    RecordLiteral(fields |> List.map (fun field -> { field with Value = loop field.Value }))
                | Seal(value, ascriptionTokens) ->
                    Seal(loop value, ascriptionTokens)
                | RecordUpdate(receiver, fields) ->
                    RecordUpdate(receiver |> loop, fields |> List.map (fun field -> { field with Value = loop field.Value }))
                | MemberAccess(receiver, segments, arguments) ->
                    MemberAccess(receiver |> loop, segments, arguments |> List.map loop)
                | SafeNavigation(receiver, navigation) ->
                    SafeNavigation(receiver |> loop, { navigation with Arguments = navigation.Arguments |> List.map loop })
                | TagTest(receiver, constructorName) ->
                    TagTest(loop receiver, constructorName)
                | Do statements ->
                    let rec substituteDoStatement statement =
                        match statement with
                        | DoLet(binding, value) -> DoLet(binding, loop value)
                        | DoLetQuestion(binding, value, failure) ->
                            DoLetQuestion(
                                binding,
                                loop value,
                                failure
                                |> Option.map (fun failure ->
                                    { failure with
                                        Body = failure.Body |> List.map substituteDoStatement })
                            )
                        | DoBind(binding, value) -> DoBind(binding, loop value)
                        | DoVar(name, value) -> DoVar(name, loop value)
                        | DoAssign(name, value) -> DoAssign(name, loop value)
                        | DoUsing(binding, value) -> DoUsing(binding, loop value)
                        | DoDefer value -> DoDefer(loop value)
                        | DoIf(condition, whenTrue, whenFalse) ->
                            DoIf(
                                loop condition,
                                whenTrue |> List.map substituteDoStatement,
                                whenFalse |> List.map substituteDoStatement
                            )
                        | DoWhile(condition, body) ->
                            DoWhile(loop condition, body |> List.map substituteDoStatement)
                        | DoReturn value -> DoReturn(loop value)
                        | DoExpression value -> DoExpression(loop value)

                    Do(statements |> List.map substituteDoStatement)
                | MonadicSplice inner ->
                    MonadicSplice(loop inner)
                | ExplicitImplicitArgument inner ->
                    ExplicitImplicitArgument(loop inner)
                | NamedApplicationBlock fields ->
                    NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = loop field.Value }))
                | Apply(callee, arguments) ->
                    Apply(loop callee, arguments |> List.map loop)
                | InoutArgument inner ->
                    InoutArgument(loop inner)
                | Unary(operatorName, operand) ->
                    Unary(operatorName, loop operand)
                | Binary(left, operatorName, right) ->
                    Binary(loop left, operatorName, loop right)
                | Elvis(left, right) ->
                    Elvis(loop left, loop right)
                | Comprehension comprehension ->
                    Comprehension { comprehension with Lowered = loop comprehension.Lowered }
                | PrefixedString(prefix, parts) ->
                    PrefixedString(
                        prefix,
                        parts
                        |> List.map (function
                            | StringText text -> StringText text
                            | StringInterpolation(inner, format) -> StringInterpolation(loop inner, format))
                    )
                | Literal _
                | NumericLiteral _
                | KindQualifiedName _ ->
                    current

            loop expression

        and tryProjectionCallExpression expression =
            match expression with
            | Apply(Name [ projectionName ], projectionArguments) ->
                environment.VisibleProjections
                |> Map.tryFind projectionName
                |> Option.map (fun projectionInfo -> projectionInfo, projectionArguments)
            | _ ->
                None

        and tryProjectionArgumentBindings (projectionInfo: ProjectionInfo) projectionArguments =
            if List.length projectionInfo.Binders <> List.length projectionArguments then
                None
            else
                (Some(Map.empty, Map.empty), List.zip projectionInfo.Binders projectionArguments)
                ||> List.fold (fun state (binder, argument) ->
                    state
                    |> Option.bind (fun (placeArguments, valueArguments) ->
                        match binder with
                        | ProjectionPlaceBinder placeBinder ->
                            tryExpressionPlace argument
                            |> Option.map (fun place ->
                                Map.add placeBinder.Name place placeArguments, valueArguments)
                        | ProjectionValueBinder valueBinder ->
                            Some(placeArguments, Map.add valueBinder.Name argument valueArguments)))

        and lowerPatternBinding
            (localTypes: Map<string, TypeExpr>)
            valueType
            (binding: SurfaceBindPattern)
            valueExpression
            continueWith
            =
            let nextLocals =
                extendBindingLocalTypes environment freshCounter localTypes binding valueType

            let loweredBody = continueWith nextLocals

            match binding.Pattern with
            | NamePattern bindingName ->
                KCoreLet(bindingName, valueExpression, loweredBody)
            | _ ->
                let tempBindingName = freshSyntheticName "__kappa_bind_"

                KCoreLet(
                    tempBindingName,
                    valueExpression,
                    KCoreMatch(
                        KCoreName [ tempBindingName ],
                        [
                            { Pattern = lowerPattern nextLocals valueType binding.Pattern
                              Guard = None
                              Body = loweredBody }
                        ]
                    )
                )

        and tryLowerProjectionInoutDoSite
            scopeLabel
            (localTypes: Map<string, TypeExpr>)
            (binding: SurfaceBindPattern option)
            calleeName
            explicitParameters
            targetExplicitIndex
            (projectionInfo: ProjectionInfo)
            projectionArguments
            rest
            isMonadicSite
            =
            tryProjectionArgumentBindings projectionInfo projectionArguments
            |> Option.bind (fun (placeArguments, valueArguments) ->
                let substitute =
                    substituteProjectionExpression placeArguments valueArguments

                let rec lowerProjectionBody bodyLocals body =
                    match body with
                    | ProjectionYield yielded ->
                        let yieldedPlace = substitute yielded

                        match tryExpressionPlace yieldedPlace with
                        | Some _ ->
                            let rewrittenArguments =
                                explicitParameters
                                |> List.map (fun (explicitIndex, _, _, argument) ->
                                    if explicitIndex = targetExplicitIndex then
                                        InoutArgument yieldedPlace
                                    else
                                        argument)

                            tryLowerInoutDoSite
                                scopeLabel
                                bodyLocals
                                binding
                                (Apply(Name [ calleeName ], rewrittenArguments))
                                rest
                                isMonadicSite
                        | None ->
                            None
                    | ProjectionIfThenElse(condition, whenTrue, whenFalse) ->
                        match lowerProjectionBody bodyLocals whenTrue, lowerProjectionBody bodyLocals whenFalse with
                        | Some loweredTrue, Some loweredFalse ->
                            Some(KCoreIfThenElse(lowerExpression bodyLocals (substitute condition), loweredTrue, loweredFalse))
                        | _ ->
                            None
                    | ProjectionMatch(scrutinee, cases) ->
                        let loweredScrutinee = substitute scrutinee
                        let scrutineeType = inferExpressionType bodyLocals loweredScrutinee

                        let loweredCases : KCoreMatchCase option list =
                            cases
                            |> List.map (fun caseClause ->
                                let caseLocals =
                                    extendPatternLocalTypes environment freshCounter bodyLocals scrutineeType caseClause.Pattern

                                lowerProjectionBody caseLocals caseClause.Body
                                |> Option.map (fun loweredBody ->
                                    ({ Pattern = lowerPattern caseLocals scrutineeType caseClause.Pattern
                                       Guard = caseClause.Guard |> Option.map (substitute >> lowerExpression caseLocals)
                                       Body = loweredBody }
                                     : KCoreMatchCase)))

                        if loweredCases |> List.forall Option.isSome then
                            Some(
                                KCoreMatch(
                                    lowerExpression bodyLocals loweredScrutinee,
                                    loweredCases |> List.choose id
                                )
                            )
                        else
                            None
                    | ProjectionAccessors _ ->
                        None

                projectionInfo.Body |> Option.bind (lowerProjectionBody localTypes))

        and tryLowerInoutDoSite
            scopeLabel
            (localTypes: Map<string, TypeExpr>)
            (binding: SurfaceBindPattern option)
            expression
            rest
            isMonadicSite
            =
            match expression with
            | Apply(Name [ calleeName ], arguments) ->
                environment.VisibleBindings
                |> Map.tryFind calleeName
                |> Option.bind (fun bindingInfo ->
                    tryPrepareVisibleBindingCall
                        environment
                        freshCounter
                        bindingInfo
                        (Some localTypes)
                        (inferExpressionType localTypes)
                        (tryResolveUniqueLocalImplicitByType environment localTypes)
                        arguments
                    |> Option.bind (fun preparedCall ->
                        let explicitParameters =
                            preparedCall.Parameters
                            |> List.choose (fun parameter ->
                                match parameter.Layout, parameter.AssignedArgument with
                                | Some layout, Some(ExplicitArgument argument) ->
                                    Some(layout, parameter.ParameterType, argument)
                                | _ ->
                                    None)
                            |> List.mapi (fun explicitIndex (layout, parameterType, argument) ->
                                explicitIndex, layout, parameterType, argument)

                        let inoutParameters =
                            explicitParameters
                            |> List.choose (fun (explicitIndex, layout, parameterType, argument) ->
                                match layout.IsInout, argument with
                                | true, InoutArgument inner -> Some(explicitIndex, layout, parameterType, inner)
                                | _ -> None)

                        if List.isEmpty inoutParameters then
                            None
                        else
                            let siteResultType =
                                if isMonadicSite then
                                    unwrapIoType preparedCall.ResultType
                                else
                                    preparedCall.ResultType

                            match tryCanonicalRecordType environment.VisibleTypeAliases siteResultType with
                            | Some(TypeRecord resultFields as resultRecordType) ->
                                let inoutNames =
                                    inoutParameters |> List.map (fun (_, layout, _, _) -> layout.Name) |> Set.ofList

                                let residualFields =
                                    resultFields
                                    |> List.filter (fun field -> not (Set.contains field.Name inoutNames))

                                let projectionInoutParameter =
                                    inoutParameters
                                    |> List.tryPick (fun (explicitIndex, _, _, inner) ->
                                        tryProjectionCallExpression inner
                                        |> Option.map (fun (projectionInfo, projectionArguments) ->
                                            explicitIndex, projectionInfo, projectionArguments))

                                match projectionInoutParameter with
                                | Some(targetExplicitIndex, projectionInfo, projectionArguments) ->
                                    tryLowerProjectionInoutDoSite
                                        scopeLabel
                                        localTypes
                                        binding
                                        calleeName
                                        explicitParameters
                                        targetExplicitIndex
                                        projectionInfo
                                        projectionArguments
                                        rest
                                        isMonadicSite
                                | None ->
                                    let layout =
                                        ensureSyntheticRecordLayout environment.CurrentModuleIdentity "<binding>" recordLayouts resultRecordType

                                    let mutable rewrittenArguments = ResizeArray<SurfaceExpression>()
                                    let mutable callLocalTypes = localTypes
                                    let preludeBindings = ResizeArray<string * TypeExpr * KCoreExpression>()
                                    let restorePlans = ResizeArray<string * string * string list * bool>()

                                    for _, parameterLayout, _, argument in explicitParameters do
                                        match parameterLayout.IsInout, argument with
                                        | true, InoutArgument inner ->
                                            match tryExpressionPlace inner with
                                            | Some(rootName, path) ->
                                                match localTypes |> Map.tryFind rootName |> Option.bind unwrapRefLikeType with
                                                | Some refInnerType ->
                                                    let hiddenRootName = freshSyntheticName $"__kappa_inout_{rootName}_"
                                                    preludeBindings.Add(
                                                        hiddenRootName,
                                                        refInnerType,
                                                        KCoreExecute(
                                                            KCoreAppSpine(
                                                                KCoreName [ "readRef" ],
                                                                [ explicitKCoreArgument (KCoreName [ rootName ]) ]
                                                            )
                                                        )
                                                    )

                                                    callLocalTypes <- Map.add hiddenRootName refInnerType callLocalTypes
                                                    restorePlans.Add(parameterLayout.Name, rootName, path, true)
                                                    rewrittenArguments.Add(InoutArgument(Name(hiddenRootName :: path)))
                                                | None ->
                                                    restorePlans.Add(parameterLayout.Name, rootName, path, false)
                                                    rewrittenArguments.Add(argument)
                                            | None ->
                                                rewrittenArguments.Add(argument)
                                        | _ ->
                                            rewrittenArguments.Add(argument)

                                    let rewrittenCallExpression =
                                        Apply(Name [ calleeName ], List.ofSeq rewrittenArguments)

                                    let resultBindingName = freshSyntheticName "__kappa_inout_result_"
                                    let fieldBindingNames =
                                        layout.Fields
                                        |> List.map (fun field -> field.Name, freshSyntheticName $"__kappa_inout_field_{field.Name}_")
                                        |> Map.ofList

                                    let pattern =
                                        KCoreConstructorPattern(
                                            [ layout.ConstructorName ],
                                            layout.Fields
                                            |> List.map (fun field -> KCoreNamePattern fieldBindingNames[field.Name])
                                        )

                                    let matchLocalTypes =
                                        let withPrelude =
                                            preludeBindings
                                            |> Seq.fold (fun state (name, fieldType, _) -> Map.add name fieldType state) callLocalTypes

                                        layout.Fields
                                        |> List.fold (fun state field ->
                                            Map.add fieldBindingNames[field.Name] field.Type state) withPrelude

                                    let restLocalTypes =
                                        restorePlans
                                        |> Seq.fold (fun state (formalName, rootName, path, isVarRoot) ->
                                            match resultFields |> List.tryFind (fun field -> String.Equals(field.Name, formalName, StringComparison.Ordinal)) with
                                            | Some field when List.isEmpty path ->
                                                if isVarRoot then
                                                    Map.add rootName (refType field.Type) state
                                                else
                                                    Map.add rootName field.Type state
                                            | _ ->
                                                state) localTypes

                                    let residualResultType =
                                        match residualFields with
                                        | [] -> unitType
                                        | _ -> TypeRecord residualFields

                                    let loweredContinuation =
                                        match binding with
                                        | None ->
                                            if List.isEmpty residualFields then
                                                Some(lowerDoStatements scopeLabel restLocalTypes rest)
                                            else
                                                None
                                        | Some residualBinding ->
                                            let residualValueExpression =
                                                match residualFields with
                                                | [] ->
                                                    KCoreLiteral LiteralValue.Unit
                                                | _ ->
                                                    let residualLayout =
                                                        ensureSyntheticRecordLayout
                                                            environment.CurrentModuleIdentity
                                                            "<binding>"
                                                            recordLayouts
                                                            residualResultType

                                                    KCoreAppSpine(
                                                        KCoreName [ residualLayout.ConstructorName ],
                                                        residualLayout.Fields
                                                        |> List.map (fun field ->
                                                            explicitKCoreArgument (KCoreName [ fieldBindingNames[field.Name] ]))
                                                    )

                                            Some(
                                                lowerPatternBinding
                                                    restLocalTypes
                                                    (Some residualResultType)
                                                    residualBinding
                                                    residualValueExpression
                                                    (fun nextLocals -> lowerDoStatements scopeLabel nextLocals rest)
                                            )

                                    loweredContinuation
                                    |> Option.map (fun continuationBody ->
                                        let restoredBody =
                                            restorePlans
                                            |> Seq.toList
                                            |> List.rev
                                            |> List.fold (fun current (formalName, rootName, path, isVarRoot) ->
                                                let replacement = Name [ fieldBindingNames[formalName] ]

                                                let rebuiltValue =
                                                    if isVarRoot then
                                                        let hiddenRootName, hiddenRootType =
                                                            preludeBindings
                                                            |> Seq.find (fun (name, _, _) ->
                                                                name.StartsWith($"__kappa_inout_{rootName}_", StringComparison.Ordinal))
                                                            |> fun (name, fieldType, _) -> name, fieldType

                                                        if List.isEmpty path then
                                                            KCoreName [ fieldBindingNames[formalName] ]
                                                        else
                                                            lowerExpression
                                                                (Map.add hiddenRootName hiddenRootType matchLocalTypes)
                                                                (buildPlaceWritebackExpression hiddenRootName path replacement)
                                                    elif List.isEmpty path then
                                                        KCoreName [ fieldBindingNames[formalName] ]
                                                    else
                                                        lowerExpression
                                                            matchLocalTypes
                                                            (buildPlaceWritebackExpression rootName path replacement)

                                                if isVarRoot then
                                                    KCoreSequence(
                                                        KCoreExecute(
                                                            KCoreAppSpine(
                                                                KCoreName [ "writeRef" ],
                                                                [ explicitKCoreArgument (KCoreName [ rootName ])
                                                                  explicitKCoreArgument rebuiltValue ]
                                                            )
                                                        ),
                                                        current
                                                    )
                                                else
                                                    KCoreLet(rootName, rebuiltValue, current))
                                                continuationBody

                                        let matchBody =
                                            KCoreMatch(
                                                KCoreName [ resultBindingName ],
                                                [
                                                    { Pattern = pattern
                                                      Guard = None
                                                      Body = restoredBody }
                                                ]
                                            )

                                        let callValue =
                                            if isMonadicSite then
                                                KCoreExecute(lowerExpression callLocalTypes rewrittenCallExpression)
                                            else
                                                lowerExpression callLocalTypes rewrittenCallExpression

                                        let callBody =
                                            KCoreLet(
                                                resultBindingName,
                                                callValue,
                                                matchBody
                                            )

                                        preludeBindings
                                        |> Seq.toList
                                        |> List.rev
                                        |> List.fold (fun current (bindingName, _, valueExpression) ->
                                            KCoreLet(bindingName, valueExpression, current)) callBody)
                            | _ ->
                                None))
            | _ ->
                None

        and lowerDoStatements scopeLabel localTypes statements =
            let bindPatternName (binding: SurfaceBindPattern) =
                match binding.Pattern with
                | NamePattern name -> name
                | _ -> "__pattern"

            match statements with
            | [] ->
                KCoreLiteral LiteralValue.Unit
            | [ DoExpression expression ] ->
                match tryLowerInoutDoSite scopeLabel localTypes None expression [] true with
                | Some lowered ->
                    lowered
                | None ->
                    KCoreExecute(lowerExpression localTypes expression)
            | DoExpression expression :: rest ->
                match tryLowerInoutDoSite scopeLabel localTypes None expression rest true with
                | Some lowered ->
                    lowered
                | None ->
                    KCoreSequence(KCoreExecute(lowerExpression localTypes expression), lowerDoStatements scopeLabel localTypes rest)
            | DoLet(binding, expression) :: rest ->
                match tryLowerInoutDoSite scopeLabel localTypes (Some binding) expression rest false with
                | Some lowered ->
                    lowered
                | None ->
                    let loweredValue = lowerExpression localTypes expression
                    let valueType = inferExpressionType localTypes expression

                    lowerPatternBinding
                        localTypes
                        valueType
                        binding
                        loweredValue
                        (fun nextLocals -> lowerDoStatements scopeLabel nextLocals rest)
            | DoLetQuestion(binding, expression, failure) :: rest ->
                let valueType = inferExpressionType localTypes expression
                let successLocals =
                    extendPatternLocalTypes environment freshCounter localTypes valueType binding.Pattern

                let successCase: KCoreMatchCase =
                    { Pattern = lowerPattern localTypes valueType binding.Pattern
                      Guard = None
                      Body = lowerDoStatements scopeLabel successLocals rest }

                let failureCase: KCoreMatchCase =
                    match failure with
                    | Some failure ->
                        let failureLocals =
                            extendPatternLocalTypes environment freshCounter localTypes valueType failure.ResiduePattern.Pattern

                        { Pattern = lowerPattern localTypes valueType failure.ResiduePattern.Pattern
                          Guard = None
                          Body = lowerDoStatements scopeLabel failureLocals failure.Body }
                    | None ->
                        { Pattern = KCoreWildcardPattern
                          Guard = None
                          Body = KCoreExecute(KCoreName [ "empty" ]) }

                KCoreMatch(lowerExpression localTypes expression, [ successCase; failureCase ])
            | DoBind(binding, expression) :: rest ->
                match tryLowerInoutDoSite scopeLabel localTypes (Some binding) expression rest true with
                | Some lowered ->
                    lowered
                | None ->
                    let loweredValue = KCoreExecute(lowerExpression localTypes expression)
                    let valueType = inferExpressionType localTypes expression |> Option.map unwrapBindPayloadType

                    lowerPatternBinding
                        localTypes
                        valueType
                        binding
                        loweredValue
                        (fun nextLocals -> lowerDoStatements scopeLabel nextLocals rest)
            | DoUsing(binding, expression) :: rest ->
                let bindingName =
                    match binding.Pattern with
                    | NamePattern name -> name
                    | _ -> "__using"

                let hiddenOwnedName = freshUsingOwnedName bindingName
                let loweredValue = KCoreExecute(lowerExpression localTypes expression)

                let nextLocals =
                    match inferExpressionType localTypes expression with
                    | Some valueType -> Map.add bindingName (unwrapIoType valueType) localTypes
                    | None -> localTypes

                KCoreLet(
                    hiddenOwnedName,
                    loweredValue,
                    KCoreScheduleExit(
                        scopeLabel,
                        buildUsingReleaseAction localTypes expression hiddenOwnedName,
                        KCoreLet(bindingName, KCoreName [ hiddenOwnedName ], lowerDoStatements scopeLabel nextLocals rest)
                    )
                )
            | DoVar(bindingName, expression) :: rest ->
                let loweredValue =
                    KCoreExecute(
                        KCoreAppSpine(
                            KCoreName [ "newRef" ],
                            [ explicitKCoreArgument (lowerExpression localTypes expression) ]
                        )
                    )

                let nextLocals =
                    match inferExpressionType localTypes expression with
                    | Some valueType -> Map.add bindingName (refType valueType) localTypes
                    | None -> localTypes

                KCoreLet(bindingName, loweredValue, lowerDoStatements scopeLabel nextLocals rest)
            | DoAssign(bindingName, expression) :: rest ->
                KCoreSequence(
                    KCoreExecute(
                        KCoreAppSpine(
                            KCoreName [ "writeRef" ],
                            [ explicitKCoreArgument (KCoreName [ bindingName ])
                              explicitKCoreArgument (lowerExpression localTypes expression) ]
                        )
                    ),
                    lowerDoStatements scopeLabel localTypes rest
                )
            | DoDefer expression :: rest ->
                KCoreScheduleExit(
                    scopeLabel,
                    KCoreDeferred(lowerExpression localTypes expression),
                    lowerDoStatements scopeLabel localTypes rest
                )
            | [ DoIf(condition, whenTrue, whenFalse) ] ->
                KCoreIfThenElse(
                    lowerExpression localTypes condition,
                    lowerDoStatements scopeLabel localTypes whenTrue,
                    lowerDoStatements scopeLabel localTypes whenFalse
                )
            | DoIf(condition, whenTrue, whenFalse) :: rest ->
                KCoreSequence(
                    KCoreIfThenElse(
                        lowerExpression localTypes condition,
                        lowerDoStatements scopeLabel localTypes whenTrue,
                        lowerDoStatements scopeLabel localTypes whenFalse
                    ),
                    lowerDoStatements scopeLabel localTypes rest
                )
            | DoWhile(condition, body) :: rest ->
                KCoreSequence(
                    KCoreWhile(lowerExpression localTypes condition, lowerDoStatements scopeLabel localTypes body),
                    lowerDoStatements scopeLabel localTypes rest
                )
            | DoReturn expression :: _ ->
                KCoreExecute(
                    KCoreAppSpine(
                        KCoreName [ "return" ],
                        [ explicitKCoreArgument (lowerExpression localTypes expression) ]
                    )
                )

        and lowerPattern localTypes expectedType pattern =
            match pattern with
            | WildcardPattern ->
                KCoreWildcardPattern
            | NamePattern name ->
                KCoreNamePattern name
            | AsPattern(_, inner) ->
                lowerPattern localTypes expectedType inner
            | TypedPattern(inner, typeTokens) ->
                let narrowedExpected =
                    TypeSignatures.parseType typeTokens
                    |> Option.map (qualifyVisibleTypeNames environment)
                    |> Option.orElse expectedType

                lowerPattern localTypes narrowedExpected inner
            | LiteralPattern literal ->
                KCoreLiteralPattern literal
            | ConstructorPattern(name, arguments) ->
                let argumentTypes =
                    match expectedType, tryResolveVisibleConstructorInfo environment name with
                    | Some expectedResultType, Some constructorInfo ->
                        let instantiated = TypeSignatures.instantiate "t" freshCounter.Value constructorInfo.Scheme
                        freshCounter.Value <- freshCounter.Value + instantiated.Forall.Length

                        let parameterTypes, constructorResultType = TypeSignatures.schemeParts instantiated

                        if List.length parameterTypes = List.length arguments then
                            match
                                TypeSignatures.tryUnifyMany
                                    [
                                        qualifyVisibleTypeNames environment constructorResultType,
                                        qualifyVisibleTypeNames environment expectedResultType
                                    ]
                            with
                            | Some substitution ->
                                parameterTypes
                                |> List.map (TypeSignatures.applySubstitution substitution >> Some)
                            | None ->
                                List.replicate arguments.Length None
                        else
                            List.replicate arguments.Length None
                    | _ ->
                        List.replicate arguments.Length None

                KCoreConstructorPattern(
                    name,
                    List.zip arguments argumentTypes
                    |> List.map (fun (argumentPattern, argumentType) -> lowerPattern localTypes argumentType argumentPattern)
                )
            | NamedConstructorPattern(name, fields) ->
                let positionalPatterns =
                    match tryResolveVisibleConstructorInfo environment name with
                    | Some constructorInfo ->
                        let fieldMap =
                            fields
                            |> List.map (fun field -> field.Name, field.Pattern)
                            |> Map.ofList

                        constructorInfo.ParameterLayouts
                        |> Option.map (fun layouts ->
                            layouts
                            |> List.filter (fun parameter -> not parameter.IsImplicit)
                            |> List.map (fun parameter ->
                                fieldMap |> Map.tryFind parameter.Name |> Option.defaultValue WildcardPattern))
                        |> Option.defaultValue (fields |> List.map (fun field -> field.Pattern))
                    | None ->
                        fields |> List.map (fun field -> field.Pattern)

                lowerPattern localTypes expectedType (ConstructorPattern(name, positionalPatterns))
            | TuplePattern elements ->
                let tupleFields =
                    elements
                    |> List.mapi (fun index element ->
                        { Name = $"_{index + 1}"
                          IsImplicit = false
                          Pattern = element })

                lowerPattern localTypes expectedType (AnonymousRecordPattern(tupleFields, None))
            | VariantPattern(BoundVariantPattern(name, _)) ->
                KCoreNamePattern name
            | VariantPattern(RestVariantPattern name) ->
                KCoreNamePattern name
            | VariantPattern(WildcardVariantPattern _) ->
                KCoreWildcardPattern
            | OrPattern alternatives ->
                KCoreOrPattern(alternatives |> List.map (lowerPattern localTypes expectedType))
            | AnonymousRecordPattern(fields, _) ->
                match expectedType |> Option.bind (tryCanonicalRecordType environment.VisibleTypeAliases) with
                | Some recordType ->
                    let layout =
                        ensureSyntheticRecordLayout environment.CurrentModuleIdentity "<binding>" recordLayouts recordType

                    let fieldPatterns =
                        fields
                        |> List.map (fun field -> field.Name, field.Pattern)
                        |> Map.ofList

                    KCoreConstructorPattern(
                        [ layout.ConstructorName ],
                        layout.Fields
                        |> List.map (fun field ->
                            fieldPatterns
                            |> Map.tryFind field.Name
                            |> Option.map (lowerPattern localTypes (Some field.Type))
                            |> Option.defaultValue KCoreWildcardPattern)
                    )
                | None ->
                    KCoreWildcardPattern

        and lowerStaticObject (staticObject: StaticObjectInfo) =
            match staticObject.ObjectKind, staticObject.ScopedEffect, staticObject.NameSegments with
            | EffectLabelObject, Some declaration, _ ->
                scopedKCoreEffectLabel declaration
            | EffectLabelObject, None, [ effectName ] ->
                match tryFindScopedEffectDeclaration effectName with
                | Some declaration ->
                    scopedKCoreEffectLabel declaration
                | None ->
                    KCoreStaticObject
                        { ObjectKind = KCoreEffectLabelObject
                          Name = staticObject.NameSegments
                          Type = staticObjectTypeText staticObject |> Option.bind tryParseTypeText
                          TypeText = staticObjectTypeText staticObject }
            | _ ->
                let kind =
                    match staticObject.ObjectKind with
                    | TypeObject -> KCoreTypeObject
                    | TraitObject -> KCoreTraitObject
                    | EffectLabelObject -> KCoreEffectLabelObject
                    | ModuleObject -> KCoreModuleObject
                    | ProjectionObject ->
                        invalidOp "Projection objects do not lower directly to KCore static objects."

                KCoreStaticObject
                    { ObjectKind = kind
                      Name = staticObject.NameSegments
                      Type = staticObjectTypeText staticObject |> Option.bind tryParseTypeText
                      TypeText = staticObjectTypeText staticObject }

        and tryLowerRecordProjectionPath
            localTypes
            receiverValue
            receiverType
            path
            =
            match tryCanonicalRecordType environment.VisibleTypeAliases receiverType, path with
            | Some(TypeRecord fields), fieldName :: rest ->
                let layout =
                    ensureSyntheticRecordLayout environment.CurrentModuleIdentity "<binding>" recordLayouts (TypeRecord fields)

                let boundFields =
                    layout.Fields
                    |> List.map (fun field -> field.Name, freshSyntheticName $"__kappa_record_{field.Name}_")

                match
                    fields |> List.tryFind (fun field -> String.Equals(field.Name, fieldName, StringComparison.Ordinal)),
                    boundFields |> List.tryFind (fun (name, _) -> String.Equals(name, fieldName, StringComparison.Ordinal))
                with
                | Some field, Some(_, bindingName) ->
                    let fieldValue = KCoreName [ bindingName ]

                    let body =
                        match rest with
                        | [] ->
                            fieldValue
                        | _ ->
                            tryLowerRecordProjectionPath
                                (Map.add bindingName field.Type localTypes)
                                fieldValue
                                field.Type
                                rest
                            |> Option.defaultValue fieldValue

                    Some(
                        KCoreMatch(
                            receiverValue,
                            [
                                { Pattern =
                                    KCoreConstructorPattern(
                                        [ layout.ConstructorName ],
                                        boundFields
                                        |> List.map (fun (_, localName) -> KCoreNamePattern localName)
                                    )
                                  Guard = None
                                  Body = body }
                            ]
                        )
                    )
                | _ ->
                    None
            | _ ->
                None

        and lowerExpression localTypes expression =
            lowerExpressionWithExpectedType localTypes None expression

        and lowerExpressionWithExpectedType localTypes expectedType expression =
            let lowerArguments arguments =
                arguments
                |> List.map (function
                    | InoutArgument inner -> inoutKCoreArgument (lowerExpressionWithExpectedType localTypes None inner)
                    | ExplicitImplicitArgument inner -> implicitKCoreArgument (lowerExpressionWithExpectedType localTypes None inner)
                    | argument -> explicitKCoreArgument (lowerExpressionWithExpectedType localTypes None argument))

            let lowerArgumentExpressions arguments =
                arguments
                |> List.map (function
                    | InoutArgument inner -> lowerExpressionWithExpectedType localTypes None inner
                    | ExplicitImplicitArgument inner -> lowerExpressionWithExpectedType localTypes None inner
                    | argument -> lowerExpressionWithExpectedType localTypes None argument)

            let lowerPreparedArguments preparedArguments =
                preparedArguments
                |> List.map (function
                    | ExplicitArgument argument -> explicitKCoreArgument (lowerExpressionWithExpectedType localTypes None argument)
                    | ImplicitArgument implicitArgument -> implicitKCoreArgument implicitArgument)

            let lowerPreparedArgumentExpressions preparedArguments =
                preparedArguments
                |> List.map (function
                    | ExplicitArgument argument -> lowerExpressionWithExpectedType localTypes None argument
                    | ImplicitArgument implicitArgument -> implicitArgument)

            let lowerStaticConstructorCallee receiverExpression memberName =
                let receiverSegments =
                    match receiverExpression with
                    | Name segments
                    | KindQualifiedName(_, segments) ->
                        Some segments
                    | _ ->
                        tryResolveScopedStaticObject environment receiverExpression
                        |> Option.map (fun staticObject -> staticObject.NameSegments)

                KCoreName((receiverSegments |> Option.defaultValue []) @ [ memberName ])

            let lowerInterpolatedMacroTypeArgument inner =
                match inferExpressionType localTypes inner |> Option.map (normalizeTypeAliases environment.VisibleTypeAliases) with
                | Some(TypeName(nameSegments, [])) ->
                    KCoreStaticObject
                        { ObjectKind = KCoreTypeObject
                          Name = nameSegments
                          Type = Some(TypeName([ "Type" ], []))
                          TypeText = Some "Type" }
                | _ ->
                    KCoreLiteral LiteralValue.Unit

            let interpolatedFragmentConstructor name arguments =
                KCoreAppSpine(KCoreName [ name ], arguments |> List.map explicitKCoreArgument)

            let fragmentListExpression fragments =
                let cons head tail =
                    KCoreAppSpine(
                        KCoreName [ "Cons" ],
                        [ explicitKCoreArgument head
                          explicitKCoreArgument tail ]
                    )

                fragments
                |> List.rev
                |> List.fold (fun tail head -> cons head tail) (KCoreName [ "Nil" ])

            let lowerPrefixedStringFragments parts =
                let flushText pending acc =
                    match pending with
                    | Some text when not (String.IsNullOrEmpty(text)) ->
                        interpolatedFragmentConstructor "Lit" [ KCoreLiteral(LiteralValue.String text) ] :: acc
                    | _ ->
                        acc

                let interpolationFragment inner format =
                    let typeArgument = lowerInterpolatedMacroTypeArgument inner
                    let quoted = KCoreSyntaxQuote(lowerExpressionWithExpectedType localTypes None inner)

                    match format with
                    | None ->
                        interpolatedFragmentConstructor "Interp" [ typeArgument; quoted ]
                    | Some formatText ->
                        interpolatedFragmentConstructor
                            "InterpFmt"
                            [ typeArgument
                              quoted
                              KCoreLiteral(LiteralValue.String formatText) ]

                let rec loop pendingText acc remainingParts =
                    match remainingParts with
                    | [] ->
                        let completed = flushText pendingText acc |> List.rev

                        if List.isEmpty completed then
                            [ interpolatedFragmentConstructor "Lit" [ KCoreLiteral(LiteralValue.String "") ] ]
                        else
                            completed
                    | StringText text :: rest ->
                        let mergedText =
                            pendingText
                            |> Option.map (fun pending -> pending + text)
                            |> Option.defaultValue text

                        loop (Some mergedText) acc rest
                    | StringInterpolation(inner, format) :: rest ->
                        let nextAcc =
                            flushText pendingText acc
                            |> fun fragments -> interpolationFragment inner format :: fragments

                        loop None nextAcc rest

                loop None [] parts

            let lowerPrefixedString prefix parts =
                let fragments = lowerPrefixedStringFragments parts |> fragmentListExpression

                KCoreTopLevelSyntaxSplice(
                    KCoreTraitCall(
                        "InterpolatedMacro",
                        "buildInterpolated",
                        KCoreName [ prefix ],
                        [ fragments ]
                    )
                )

            let tryLowerEffectHandlerArgument tokens =
                match significantEffectHandlerTokens tokens with
                | [ leftParen; rightParen ] when leftParen.Kind = LeftParen && rightParen.Kind = RightParen ->
                    Some KCoreEffectUnitArgument
                | [ nameToken ] when Token.isName nameToken ->
                    let name = SyntaxFacts.trimIdentifierQuotes nameToken.Text

                    if String.Equals(name, "_", StringComparison.Ordinal) then
                        Some KCoreEffectWildcardArgument
                    else
                        Some(KCoreEffectNameArgument name)
                | leftParen :: nameToken :: colonToken :: _
                    when leftParen.Kind = LeftParen && Token.isName nameToken && colonToken.Kind = Colon ->
                    let name = SyntaxFacts.trimIdentifierQuotes nameToken.Text

                    if String.Equals(name, "_", StringComparison.Ordinal) then
                        Some KCoreEffectWildcardArgument
                    else
                        Some(KCoreEffectNameArgument name)
                | _ ->
                    None

            let effectHandlerArgumentName argument =
                match argument with
                | KCoreEffectNameArgument name -> Some name
                | _ -> None

            let asEffectComputation currentLocals innerExpression =
                let lowered = lowerExpression currentLocals innerExpression

                let inferredComputationType =
                    tryInferLocalAppliedType
                        environment.VisibleTypeAliases
                        (qualifyVisibleTypeNames environment)
                        (inferExpressionType currentLocals)
                        currentLocals
                        innerExpression
                    |> Option.orElseWith (fun () -> inferExpressionType currentLocals innerExpression)

                match inferredComputationType |> Option.bind tryUnwrapComputationPayloadType with
                | Some _ ->
                    lowered
                | None ->
                    KCoreAppSpine(KCoreName [ "pure" ], [ explicitKCoreArgument lowered ])

            let rec tryLowerEffectfulDoStatements currentLocals statements =
                match statements with
                | [] ->
                    Some(KCoreAppSpine(KCoreName [ "pure" ], [ explicitKCoreArgument (KCoreLiteral LiteralValue.Unit) ]))
                | [ DoReturn expression ] ->
                    Some(KCoreAppSpine(KCoreName [ "pure" ], [ explicitKCoreArgument (lowerExpression currentLocals expression) ]))
                | [ DoExpression expression ] ->
                    Some(asEffectComputation currentLocals expression)
                | DoExpression expression :: rest ->
                    tryLowerEffectfulDoStatements currentLocals rest
                    |> Option.map (fun loweredRest ->
                        KCoreAppSpine(
                            KCoreName [ ">>" ],
                            [
                                explicitKCoreArgument (asEffectComputation currentLocals expression)
                                explicitKCoreArgument loweredRest
                            ]
                        ))
                | DoReturn expression :: rest ->
                    tryLowerEffectfulDoStatements currentLocals rest
                    |> Option.map (fun loweredRest ->
                        KCoreAppSpine(
                            KCoreName [ ">>" ],
                            [
                                explicitKCoreArgument
                                    (KCoreAppSpine(
                                        KCoreName [ "pure" ],
                                        [ explicitKCoreArgument (lowerExpression currentLocals expression) ]
                                    ))
                                explicitKCoreArgument loweredRest
                            ]
                        ))
                | DoLet(binding, value) :: rest ->
                    match tryLowerEffectfulDoStatements currentLocals rest with
                    | Some loweredRest ->
                        let bindingExpectedType =
                            binding.TypeTokens
                            |> Option.bind TypeSignatures.parseType
                            |> Option.map (qualifyVisibleTypeNames environment)

                        let loweredValue = lowerExpressionWithExpectedType currentLocals bindingExpectedType value
                        let valueType = bindingExpectedType |> Option.orElseWith (fun () -> inferExpressionType currentLocals value)

                        Some(
                            lowerPatternBinding
                                currentLocals
                                valueType
                                binding
                                loweredValue
                                (fun _ -> loweredRest))
                    | None ->
                        None
                | DoBind(binding, expression) :: rest ->
                    let payloadType = inferExpressionType currentLocals expression |> Option.map unwrapBindPayloadType
                    let parameterName = freshSyntheticName "__kappa_eff_bind_"

                    let parameter =
                        { Name = parameterName
                          Quantity = Some QuantityOne
                          IsImplicit = false
                          Type = payloadType
                          TypeText = payloadType |> Option.map TypeSignatures.toText }

                    let parameterLocals =
                        payloadType
                        |> Option.map (fun typeExpr -> Map.add parameterName typeExpr currentLocals)
                        |> Option.defaultValue currentLocals

                    let restLocals =
                        extendBindingLocalTypes environment freshCounter currentLocals binding payloadType

                    match tryLowerEffectfulDoStatements restLocals rest with
                    | Some loweredRest ->
                        let lambdaBody =
                            lowerPatternBinding
                                parameterLocals
                                payloadType
                                binding
                                (KCoreName [ parameterName ])
                                (fun _ -> loweredRest)

                        Some(
                            KCoreAppSpine(
                                KCoreName [ ">>=" ],
                                [
                                    explicitKCoreArgument (asEffectComputation currentLocals expression)
                                    explicitKCoreArgument (KCoreLambda([ parameter ], lambdaBody))
                                ]
                            ))
                    | None ->
                        None
                | DoIf(condition, whenTrue, whenFalse) :: rest ->
                    match tryLowerEffectfulDoStatements currentLocals whenTrue, tryLowerEffectfulDoStatements currentLocals whenFalse with
                    | Some loweredWhenTrue, Some loweredWhenFalse ->
                        let loweredIf = KCoreIfThenElse(lowerExpression currentLocals condition, loweredWhenTrue, loweredWhenFalse)

                        match rest with
                        | [] ->
                            Some loweredIf
                        | _ ->
                            match tryLowerEffectfulDoStatements currentLocals rest with
                            | Some loweredRest ->
                                Some(
                                    KCoreAppSpine(
                                        KCoreName [ ">>" ],
                                        [
                                            explicitKCoreArgument loweredIf
                                            explicitKCoreArgument loweredRest
                                        ]
                                    ))
                            | None ->
                                None
                    | _ ->
                        None
                | DoLetQuestion _ :: _
                | DoVar _ :: _
                | DoAssign _ :: _
                | DoUsing _ :: _
                | DoDefer _ :: _
                | DoWhile _ :: _ ->
                    None

            let rec hasEffectfulDoFlow currentLocals statements =
                statements
                |> List.exists (function
                    | DoBind(_, innerExpression) ->
                        inferExpressionType currentLocals innerExpression
                        |> Option.bind tryUnwrapEffType
                        |> Option.isSome
                    | DoExpression innerExpression ->
                        inferExpressionType currentLocals innerExpression
                        |> Option.bind tryUnwrapEffType
                        |> Option.isSome
                    | DoIf(_, whenTrue, whenFalse) ->
                        hasEffectfulDoFlow currentLocals whenTrue || hasEffectfulDoFlow currentLocals whenFalse
                    | DoWhile(_, body) ->
                        hasEffectfulDoFlow currentLocals body
                    | DoLet _
                    | DoLetQuestion _
                    | DoVar _
                    | DoAssign _
                    | DoUsing _
                    | DoDefer _
                    | DoReturn _ ->
                        false)

            let tryInferSeededLambdaParameterTypes helperName parameters bodyExpression =
                let rec tryFind shadowed expression =
                    match expression with
                    | Apply(Name [ name ], arguments)
                        when String.Equals(name, helperName, StringComparison.Ordinal)
                             && not (Set.contains helperName shadowed)
                             && List.length arguments = List.length parameters ->
                        let argumentTypes = arguments |> List.map (inferExpressionType localTypes)

                        if argumentTypes |> List.forall Option.isSome then
                            Some(argumentTypes |> List.choose id)
                        else
                            None
                    | Apply(callee, arguments) ->
                        tryFind shadowed callee
                        |> Option.orElseWith (fun () -> arguments |> List.tryPick (tryFind shadowed))
                    | LocalLet(binding, value, body) ->
                        tryFind shadowed value
                        |> Option.orElseWith (fun () ->
                            let nextShadowed =
                                if collectPatternNames binding.Pattern |> List.exists (fun name -> String.Equals(name, helperName, StringComparison.Ordinal)) then
                                    Set.add helperName shadowed
                                else
                                    shadowed

                            tryFind nextShadowed body)
                    | LocalSignature(declaration, body) ->
                        if String.Equals(declaration.Name, helperName, StringComparison.Ordinal) then
                            None
                        else
                            tryFind shadowed body
                    | LocalTypeAlias(_, body) ->
                        tryFind shadowed body
                    | LocalScopedEffect(_, body) ->
                        tryFind shadowed body
                    | TypeSyntaxTokens _ ->
                        None
                    | Lambda(nestedParameters, body) ->
                        let nextShadowed =
                            if nestedParameters |> List.exists (fun parameter -> String.Equals(parameter.Name, helperName, StringComparison.Ordinal)) then
                                Set.add helperName shadowed
                            else
                                shadowed

                        tryFind nextShadowed body
                    | IfThenElse(condition, whenTrue, whenFalse) ->
                        tryFind shadowed condition
                        |> Option.orElseWith (fun () -> tryFind shadowed whenTrue)
                        |> Option.orElseWith (fun () -> tryFind shadowed whenFalse)
                    | Handle(_, label, body, returnClause, operationClauses) ->
                        tryFind shadowed label
                        |> Option.orElseWith (fun () -> tryFind shadowed body)
                        |> Option.orElseWith (fun () -> tryFind shadowed returnClause.Body)
                        |> Option.orElseWith (fun () -> operationClauses |> List.tryPick (fun clause -> tryFind shadowed clause.Body))
                    | Match(scrutinee, cases) ->
                        tryFind shadowed scrutinee
                        |> Option.orElseWith (fun () ->
                            cases
                            |> List.tryPick (fun caseClause ->
                                caseClause.Guard
                                |> Option.bind (tryFind shadowed)
                                |> Option.orElseWith (fun () -> tryFind shadowed caseClause.Body)))
                    | RecordLiteral fields ->
                        fields |> List.tryPick (fun field -> tryFind shadowed field.Value)
                    | RecordUpdate(receiver, fields) ->
                        tryFind shadowed receiver
                        |> Option.orElseWith (fun () -> fields |> List.tryPick (fun field -> tryFind shadowed field.Value))
                    | MemberAccess(receiver, _, arguments) ->
                        tryFind shadowed receiver
                        |> Option.orElseWith (fun () -> arguments |> List.tryPick (tryFind shadowed))
                    | SafeNavigation(receiver, navigation) ->
                        tryFind shadowed receiver
                        |> Option.orElseWith (fun () -> navigation.Arguments |> List.tryPick (tryFind shadowed))
                    | TagTest(receiver, _) ->
                        tryFind shadowed receiver
                    | MonadicSplice inner
                    | ExplicitImplicitArgument inner
                    | InoutArgument inner
                    | Unary(_, inner)
                    | SyntaxQuote inner
                    | SyntaxSplice inner
                    | TopLevelSyntaxSplice inner
                    | CodeQuote inner
                    | CodeSplice inner
                    | Seal(inner, _) ->
                        tryFind shadowed inner
                    | Binary(left, _, right)
                    | Elvis(left, right) ->
                        tryFind shadowed left
                        |> Option.orElseWith (fun () -> tryFind shadowed right)
                    | Comprehension comprehension ->
                        tryFind shadowed comprehension.Lowered
                    | PrefixedString(_, parts) ->
                        parts
                        |> List.tryPick (function
                            | StringText _ -> None
                            | StringInterpolation(inner, _) -> tryFind shadowed inner)
                    | NamedApplicationBlock fields ->
                        fields |> List.tryPick (fun field -> tryFind shadowed field.Value)
                    | Do _
                    | Literal _
                    | NumericLiteral _
                    | Name _
                    | KindQualifiedName _ ->
                        None

                tryFind Set.empty bodyExpression

            let lowerLambdaExpression baseLocals parameterTypeHints lambdaParameters lambdaBody =
                let resolvedParameterTypes =
                    lambdaParameters
                    |> List.mapi (fun index parameter ->
                        tryParseParameterType parameter
                        |> Option.orElseWith (fun () ->
                            parameterTypeHints |> Option.bind (List.tryItem index))
                        |> Option.defaultValue (TypeVariable $"lambda{freshCounter.Value}"))

                let lambdaLocals =
                    List.zip lambdaParameters resolvedParameterTypes
                    |> List.fold (fun state (parameter, parameterType) -> Map.add parameter.Name parameterType state) baseLocals

                KCoreLambda(
                    List.zip lambdaParameters resolvedParameterTypes
                    |> List.map (fun (parameter, parameterType) -> lowerKCoreParameter parameter (Some parameterType)),
                    lowerExpressionWithExpectedType lambdaLocals expectedType lambdaBody
                )

            let rec substituteKCoreNames substitutions current =
                match current with
                | KCoreName [ name ] ->
                    substitutions |> Map.tryFind name |> Option.defaultValue current
                | KCoreName _ ->
                    current
                | KCoreSyntaxQuote inner ->
                    KCoreSyntaxQuote(substituteKCoreNames substitutions inner)
                | KCoreSyntaxSplice inner ->
                    KCoreSyntaxSplice(substituteKCoreNames substitutions inner)
                | KCoreTopLevelSyntaxSplice inner ->
                    KCoreTopLevelSyntaxSplice(substituteKCoreNames substitutions inner)
                | KCoreCodeQuote inner ->
                    KCoreCodeQuote(substituteKCoreNames substitutions inner)
                | KCoreCodeSplice inner ->
                    KCoreCodeSplice(substituteKCoreNames substitutions inner)
                | KCoreLiteral _
                | KCoreDictionaryValue _
                | KCoreStaticObject _ ->
                    current
                | KCoreEffectLabel(labelName, interfaceId, labelId, operations) ->
                    KCoreEffectLabel(labelName, interfaceId, labelId, operations)
                | KCoreEffectOperation(label, operationId, operationName) ->
                    KCoreEffectOperation(substituteKCoreNames substitutions label, operationId, operationName)
                | KCoreLambda(parameters, body) ->
                    let nextSubstitutions =
                        parameters
                        |> List.fold (fun state parameter -> Map.remove parameter.Name state) substitutions

                    KCoreLambda(parameters, substituteKCoreNames nextSubstitutions body)
                | KCoreIfThenElse(condition, whenTrue, whenFalse) ->
                    KCoreIfThenElse(
                        substituteKCoreNames substitutions condition,
                        substituteKCoreNames substitutions whenTrue,
                        substituteKCoreNames substitutions whenFalse
                    )
                | KCoreHandle(isDeep, label, body, returnClause, operationClauses) ->
                    let lowerClause (clause: KCoreEffectHandlerClause) =
                        let nextSubstitutions =
                            clause.Arguments
                            |> List.choose effectHandlerArgumentName
                            |> List.fold (fun state name -> Map.remove name state) substitutions
                            |> fun state ->
                                clause.ResumptionName
                                |> Option.map (fun name -> Map.remove name state)
                                |> Option.defaultValue state

                        { clause with
                            Body = substituteKCoreNames nextSubstitutions clause.Body }

                    KCoreHandle(
                        isDeep,
                        substituteKCoreNames substitutions label,
                        substituteKCoreNames substitutions body,
                        lowerClause returnClause,
                        operationClauses |> List.map lowerClause
                    )
                | KCoreMatch(scrutinee, cases) ->
                    KCoreMatch(
                        substituteKCoreNames substitutions scrutinee,
                        cases
                        |> List.map (fun caseClause ->
                            { Pattern = caseClause.Pattern
                              Guard = caseClause.Guard |> Option.map (substituteKCoreNames substitutions)
                              Body = substituteKCoreNames substitutions caseClause.Body })
                    )
                | KCoreExecute inner ->
                    KCoreExecute(substituteKCoreNames substitutions inner)
                | KCoreLet(bindingName, value, body) ->
                    let nextSubstitutions = Map.remove bindingName substitutions
                    KCoreLet(
                        bindingName,
                        substituteKCoreNames substitutions value,
                        substituteKCoreNames nextSubstitutions body
                    )
                | KCoreDoScope(scopeLabel, body) ->
                    KCoreDoScope(scopeLabel, substituteKCoreNames substitutions body)
                | KCoreScheduleExit(scopeLabel, action, body) ->
                    let loweredAction =
                        match action with
                        | KCoreDeferred deferred -> KCoreDeferred(substituteKCoreNames substitutions deferred)
                        | KCoreRelease(typeText, release, resource) ->
                            KCoreRelease(
                                typeText,
                                substituteKCoreNames substitutions release,
                                substituteKCoreNames substitutions resource
                            )

                    KCoreScheduleExit(scopeLabel, loweredAction, substituteKCoreNames substitutions body)
                | KCoreSequence(first, second) ->
                    KCoreSequence(substituteKCoreNames substitutions first, substituteKCoreNames substitutions second)
                | KCoreWhile(condition, body) ->
                    KCoreWhile(substituteKCoreNames substitutions condition, substituteKCoreNames substitutions body)
                | KCoreAppSpine(callee, arguments) ->
                    KCoreAppSpine(
                        substituteKCoreNames substitutions callee,
                        arguments
                        |> List.map (fun argument ->
                            { argument with
                                Expression = substituteKCoreNames substitutions argument.Expression })
                    )
                | KCoreTraitCall(traitName, memberName, dictionary, arguments) ->
                    KCoreTraitCall(
                        traitName,
                        memberName,
                        substituteKCoreNames substitutions dictionary,
                        arguments |> List.map (substituteKCoreNames substitutions)
                    )
                | KCoreUnary(operatorName, operand) ->
                    KCoreUnary(operatorName, substituteKCoreNames substitutions operand)
                | KCoreBinary(left, operatorName, right) ->
                    KCoreBinary(
                        substituteKCoreNames substitutions left,
                        operatorName,
                        substituteKCoreNames substitutions right
                    )
                | KCorePrefixedString(prefix, parts) ->
                    KCorePrefixedString(
                        prefix,
                        parts
                        |> List.map (function
                            | KCoreStringText text -> KCoreStringText text
                            | KCoreStringInterpolation inner -> KCoreStringInterpolation(substituteKCoreNames substitutions inner))
                    )

            let eraseIntrinsicPreludeDictionaryArguments
                (bindingInfo: BindingSchemeInfo)
                (dictionaryArguments: KCoreArgument list)
                =
                let _ = bindingInfo
                dictionaryArguments

            let lowerPreparedBindingCallArguments
                (bindingInfo: BindingSchemeInfo)
                (preparedCall: PreparedBindingCall)
                =
                let _ = bindingInfo

                if List.isEmpty preparedCall.Parameters then
                    preparedCall.Arguments
                    |> lowerPreparedArguments
                else
                    let rec loop substitutions (parameters: PreparedCallParameter list) =
                        match parameters with
                        | [] ->
                            []
                        | parameter :: rest ->
                            let runtimeArgument, nextSubstitutions =
                                match parameter.Layout, parameter.AssignedArgument with
                                | _, Some(ExplicitArgument argument) ->
                                    let loweredArgument = lowerExpressionWithExpectedType localTypes (Some parameter.ParameterType) argument
                                    let substitutions =
                                        match parameter.Layout with
                                        | Some layout -> Map.add layout.Name loweredArgument substitutions
                                        | None -> substitutions

                                    Some(explicitKCoreArgument loweredArgument), substitutions
                                | Some layout, Some(ImplicitArgument implicitArgument) ->
                                    Some(implicitKCoreArgument implicitArgument), Map.add layout.Name implicitArgument substitutions
                                | Some layout, None when bindingInfo.DefaultArguments.ContainsKey(layout.Name) ->
                                    let loweredDefault =
                                        lowerExpressionWithExpectedType localTypes (Some parameter.ParameterType) bindingInfo.DefaultArguments[layout.Name]
                                        |> substituteKCoreNames substitutions

                                    Some(explicitKCoreArgument loweredDefault), Map.add layout.Name loweredDefault substitutions
                                | _ ->
                                    None, substitutions

                            match runtimeArgument with
                            | Some runtimeArgument -> runtimeArgument :: loop nextSubstitutions rest
                            | None -> loop nextSubstitutions rest

                    loop Map.empty preparedCall.Parameters

            match expression with
            | Literal literal ->
                KCoreLiteral literal
            | NumericLiteral literal ->
                match SurfaceNumericLiteral.suffix literal with
                | Some suffixName ->
                    lowerExpressionWithExpectedType
                        localTypes
                        expectedType
                        (Apply(Name [ suffixName ], [ NumericLiteral(SurfaceNumericLiteral.withoutSuffix literal) ]))
                | None ->
                    let contextualType =
                        expectedType
                        |> Option.bind (fun expectedResultType ->
                            tryResolveNumericLiteralContext environment expectedResultType literal)

                    match contextualType with
                    | Some(_, None) ->
                        tryLowerNumericLiteralForRuntime literal
                        |> Option.defaultValue (KCoreLiteral LiteralValue.Unit)
                    | Some(targetType, Some instanceInfo) ->
                        let literalConstraint =
                            unqualifiedTraitConstraint (numericLiteralConstraintName literal) [ targetType ]

                        let semanticArgument =
                            tryLowerNumericLiteralForRuntime literal
                            |> Option.defaultValue (KCoreLiteral LiteralValue.Unit)

                        KCoreTraitCall(
                            traitConstraintLocalName literalConstraint,
                            (if traitConstraintLocalName literalConstraint = "FromInteger" then
                                 "fromInteger"
                             else
                                 "fromFloat"),
                            (tryLowerResolvedDictionaryValue environment literalConstraint
                             |> Option.defaultValue (
                                 KCoreDictionaryValue(
                                     ModuleIdentity.text instanceInfo.ModuleIdentity,
                                     traitReferenceRuntimeName instanceInfo.Trait,
                                     instanceInfo.InstanceKey,
                                     []
                                 )
                             )),
                            [ semanticArgument ]
                        )
                    | None ->
                        tryLowerNumericLiteralForRuntime literal
                        |> Option.defaultValue (KCoreLiteral LiteralValue.Unit)
            | TypeSyntaxTokens _ ->
                KCoreLiteral LiteralValue.Unit
            | SyntaxQuote inner ->
                KCoreSyntaxQuote(lowerExpressionWithExpectedType localTypes None inner)
            | SyntaxSplice inner ->
                KCoreSyntaxSplice(lowerExpressionWithExpectedType localTypes None inner)
            | TopLevelSyntaxSplice inner ->
                KCoreTopLevelSyntaxSplice(lowerExpressionWithExpectedType localTypes None inner)
            | CodeQuote inner ->
                KCoreCodeQuote(lowerExpressionWithExpectedType localTypes None inner)
            | CodeSplice inner ->
                KCoreCodeSplice(lowerExpressionWithExpectedType localTypes None inner)
            | Comprehension comprehension ->
                let loweredComprehension =
                    tryBuildTypedComprehensionLoweredExpression
                        environment
                        freshCounter
                        localTypes
                        (fun currentLocals currentExpression ->
                            inferValidationExpressionTypeWithContext
                                environment
                                freshCounter
                                currentLocals
                                Map.empty
                                currentExpression
                            |> Option.orElseWith (fun () -> inferExpressionType currentLocals currentExpression))
                        comprehension
                    |> Option.defaultValue comprehension.Lowered

                lowerExpressionWithExpectedType localTypes expectedType loweredComprehension
            | Handle(isDeep, label, body, returnClause, operationClauses) ->
                let handledType =
                    expectedType
                    |> Option.orElseWith (fun () -> inferExpressionType localTypes expression)

                let handledBodyType =
                    inferExpressionType localTypes body

                let handledPayloadType =
                    handledBodyType
                    |> Option.bind tryUnwrapEffType
                    |> Option.map snd
                    |> Option.defaultValue (TypeVariable $"handlePayload{freshCounter.Value}")

                let handledEffectDeclaration =
                    tryResolveHandledEffectDeclaration environment label

                let lowerClause
                    (argumentTypes: TypeExpr list)
                    (resumptionType: TypeExpr option)
                    (clause: SurfaceEffectHandlerClause)
                    =
                    let loweredArguments =
                        clause.ArgumentTokens
                        |> List.map (fun tokens ->
                            tryLowerEffectHandlerArgument tokens
                            |> Option.defaultValue KCoreEffectWildcardArgument)

                    let clauseLocals =
                        (localTypes, loweredArguments |> List.mapi (fun index argument -> argument, argumentTypes |> List.tryItem index))
                        ||> List.fold (fun state (argument, argumentType) ->
                            match argument, argumentType with
                            | KCoreEffectNameArgument name, Some currentArgumentType -> Map.add name currentArgumentType state
                            | _ -> state)
                        |> fun state ->
                            match clause.ResumptionName, resumptionType with
                            | Some resumptionName, Some currentResumptionType ->
                                Map.add resumptionName currentResumptionType state
                            | _ ->
                                state

                    { OperationName = clause.OperationName
                      Arguments = loweredArguments
                      ResumptionName = clause.ResumptionName
                      Body = lowerExpressionWithExpectedType clauseLocals handledType clause.Body }

                let loweredReturnClause =
                    lowerClause [ handledPayloadType ] None returnClause

                let loweredOperationClauses =
                    operationClauses
                    |> List.map (fun clause ->
                        let parameterTypes, resultType =
                            handledEffectDeclaration
                            |> Option.bind (fun declaration ->
                                EffectSemantics.tryFindOperation clause.OperationName declaration
                                |> Option.bind (fun operation ->
                                    operation.SignatureTokens
                                    |> TypeSignatures.parseType
                                    |> Option.map (qualifyVisibleTypeNames environment)
                                    |> Option.map TypeSignatures.functionParts
                                    |> Option.map (fun (parameterTypes, resultType) -> parameterTypes, resultType)))
                            |> Option.defaultValue ([], TypeVariable $"opResult{freshCounter.Value}")

                        let resumptionResultType =
                            if isDeep then
                                handledType
                            else
                                handledBodyType

                        let resumptionType =
                            resumptionResultType
                            |> Option.map (fun currentHandledType -> TypeArrow(QuantityOne, resultType, currentHandledType))

                        lowerClause parameterTypes resumptionType clause, resultType)

                let loweredLabel = lowerExpressionWithExpectedType localTypes None label
                let loweredBody = lowerExpressionWithExpectedType localTypes handledType body

                if not isDeep then
                    KCoreHandle(
                        false,
                        loweredLabel,
                        loweredBody,
                        loweredReturnClause,
                        loweredOperationClauses |> List.map fst
                    )
                else
                    let goName = $"__kappa_deep_go_{freshCounter.Value}"
                    freshCounter.Value <- freshCounter.Value + 1
                    let compName = $"__kappa_deep_comp_{freshCounter.Value}"
                    freshCounter.Value <- freshCounter.Value + 1

                    let lowerDeepClause ((clause: KCoreEffectHandlerClause), resultType: TypeExpr) =
                        match clause.ResumptionName with
                        | Some resumptionName ->
                            let shallowResumptionName = $"__kappa_deep_shallow_k_{freshCounter.Value}"
                            freshCounter.Value <- freshCounter.Value + 1
                            let resultName = $"__kappa_deep_res_{freshCounter.Value}"
                            freshCounter.Value <- freshCounter.Value + 1

                            let wrapperParameter =
                                { Name = resultName
                                  Quantity = Some QuantityOne
                                  IsImplicit = false
                                  Type = Some resultType
                                  TypeText = Some(TypeSignatures.toText resultType) }

                            let wrapperBody =
                                KCoreAppSpine(
                                    KCoreName [ goName ],
                                    [
                                        explicitKCoreArgument
                                            (KCoreAppSpine(
                                                KCoreName [ shallowResumptionName ],
                                                [ explicitKCoreArgument(KCoreName [ resultName ]) ]
                                            ))
                                    ]
                                )

                            { clause with
                                ResumptionName = Some shallowResumptionName
                                Body =
                                    KCoreLet(
                                        resumptionName,
                                        KCoreLambda([ wrapperParameter ], wrapperBody),
                                        clause.Body
                                    ) }
                        | None ->
                            clause

                    let driverParameter =
                        { Name = compName
                          Quantity = None
                          IsImplicit = false
                          Type = handledBodyType
                          TypeText = handledBodyType |> Option.map TypeSignatures.toText }

                    let driverBody =
                        KCoreHandle(
                            false,
                            loweredLabel,
                            KCoreName [ compName ],
                            loweredReturnClause,
                            loweredOperationClauses |> List.map lowerDeepClause
                        )

                    KCoreLet(
                        goName,
                        KCoreLambda([ driverParameter ], driverBody),
                        KCoreAppSpine(KCoreName [ goName ], [ explicitKCoreArgument loweredBody ])
                    )
            | KindQualifiedName _ ->
                tryResolveScopedStaticObject environment expression
                |> Option.map lowerStaticObject
                |> Option.defaultValue (KCoreLiteral LiteralValue.Unit)
            | Name [ bindingName ]
                when not (Map.containsKey bindingName localTypes) ->
                let ordinaryResolution =
                    environment.VisibleOrdinaryGroups
                    |> Map.tryFind bindingName
                    |> Option.bind resolveVisibleOrdinaryTermGroup

                match ordinaryResolution with
                | Some(VisibleOrdinaryBinding bindingInfo) ->
                    if ordinarySurfaceNameShadowsVisiblePreludeBinding environment localTypes bindingName then
                        KCoreName [ bindingName ]
                    else
                        let initialPreparedCall =
                            tryPrepareVisibleBindingCall
                                environment
                                freshCounter
                                bindingInfo
                                (Some localTypes)
                                (inferValidationExpressionTypeWithContext
                                    environment
                                    freshCounter
                                    localTypes
                                    localTypes)
                                (tryResolveUniqueLocalImplicitByType environment localTypes)
                                []
                        let expectedPreparedCall =
                            expectedType
                            |> Option.bind (fun expectedResultType ->
                                tryPrepareExpectedVisibleBindingValue
                                    environment
                                    freshCounter
                                    bindingInfo
                                    (Some localTypes)
                                    (inferValidationExpressionTypeWithContext
                                        environment
                                        freshCounter
                                        localTypes
                                        localTypes)
                                    (tryResolveUniqueLocalImplicitByType environment localTypes)
                                    expectedResultType)

                        match expectedPreparedCall |> Option.orElse initialPreparedCall with
                        | Some preparedCall when not (List.isEmpty preparedCall.Arguments) ->
                            KCoreAppSpine(KCoreName [ bindingName ], lowerPreparedBindingCallArguments bindingInfo preparedCall)
                        | _ ->
                            KCoreName [ bindingName ]
                | Some(VisibleOrdinaryModule moduleIdentity) ->
                    lowerStaticObject
                        (staticObjectInfo
                            (semanticObjectIdentity (moduleDeclarationIdentity moduleIdentity) ModuleObject)
                            [ bindingName ]
                            None
                            None
                            None)
                | Some(VisibleOrdinaryConstructor _)
                | Some(VisibleOrdinaryAmbiguous _)
                | None ->
                    match tryFindScopedEffectDeclaration bindingName with
                    | Some declaration ->
                        scopedKCoreEffectLabel declaration
                    | None ->
                        match tryResolveScopedStaticObject environment expression with
                        | Some staticObject ->
                            lowerStaticObject staticObject
                        | None ->
                            KCoreName [ bindingName ]
            | Name [ bindingName ] ->
                KCoreName [ bindingName ]
            | Name (receiverName :: path) when not (List.isEmpty path) ->
                match tryResolveScopedStaticObject environment expression with
                | Some staticObject when staticObject.ObjectKind = EffectLabelObject ->
                    lowerStaticObject staticObject
                | Some _
                | None ->
                    match tryResolveEffectOperationNamePath environment (receiverName :: path) with
                    | Some(effectName, declaration, operation) ->
                        KCoreEffectOperation(
                            scopedKCoreEffectLabel declaration,
                            operation.OperationId,
                            operation.Name
                        )
                    | None ->
                        match path with
                        | [ operationName ] ->
                            match tryFindScopedEffectOperation receiverName operationName with
                            | Some(declaration, operation) ->
                                KCoreEffectOperation(
                                    scopedKCoreEffectLabel declaration,
                                    operation.OperationId,
                                    operation.Name
                                )
                            | None ->
                                let loweredReceiver = lowerExpression localTypes (Name [ receiverName ])

                                let recordProjection =
                                    inferExpressionType localTypes (Name [ receiverName ])
                                    |> Option.bind (fun receiverType ->
                                        tryLowerRecordProjectionPath localTypes loweredReceiver receiverType path)

                                match tryResolveStaticConstructor environment (Name [ receiverName ]) operationName with
                                | Some _ ->
                                    lowerStaticConstructorCallee (Name [ receiverName ]) operationName
                                | None ->
                                    match tryReceiverProjection environment localTypes receiverName operationName with
                                    | Some _ ->
                                        KCoreAppSpine(KCoreName [ operationName ], [ explicitKCoreArgument loweredReceiver ])
                                    | None ->
                                        recordProjection
                                        |> Option.defaultValue (KCoreName [ receiverName; operationName ])
                        | _ ->
                            let loweredReceiver = lowerExpression localTypes (Name [ receiverName ])

                            let recordProjection =
                                inferExpressionType localTypes (Name [ receiverName ])
                                |> Option.bind (fun receiverType ->
                                    tryLowerRecordProjectionPath localTypes loweredReceiver receiverType path)

                            recordProjection
                            |> Option.defaultValue (KCoreName(receiverName :: path))
            | Name segments ->
                match tryResolveTraitMemberProjection environment localTypes segments with
                | Some(traitInfo, memberName, _, receiverName) ->
                    KCoreTraitCall(
                        traitInfo.Name,
                        memberName,
                        lowerExpressionWithExpectedType localTypes None (Name [ receiverName ]),
                        []
                    )
                | None ->
                    KCoreName segments
            | LocalSignature(_, body) ->
                lowerExpressionWithExpectedType localTypes expectedType body
            | LocalTypeAlias(_, body) ->
                lowerExpressionWithExpectedType localTypes expectedType body
            | LocalLet(binding, value, body) ->
                let value =
                    binding.TypeTokens
                    |> Option.map (fun typeTokens -> annotateLambdaWithTypeTokens typeTokens value)
                    |> Option.defaultValue value

                let bindingNames = collectPatternNames binding.Pattern
                let bindingExpectedType =
                    binding.TypeTokens
                    |> Option.bind TypeSignatures.parseType
                    |> Option.map (qualifyVisibleTypeNames environment)

                let valueLocals =
                    match binding.Pattern, bindingExpectedType, value with
                    | NamePattern bindingName, Some declaredType, Lambda _ ->
                        Map.add bindingName declaredType localTypes
                    | _ ->
                        localTypes

                let loweredValue =
                    match binding.Pattern, value with
                    | NamePattern bindingName, Lambda(lambdaParameters, lambdaBody) ->
                        lowerLambdaExpression
                            valueLocals
                            (tryInferSeededLambdaParameterTypes bindingName lambdaParameters body)
                            lambdaParameters
                            lambdaBody
                    | _ ->
                        lowerExpressionWithExpectedType valueLocals bindingExpectedType value
                let bodyForLowering =
                    match bindingNames, tryResolveScopedStaticObject environment value with
                    | [ aliasName ], Some staticObject ->
                        rewriteStaticObjectAliasUse aliasName staticObject body
                    | [ aliasName ], _ ->
                        match value with
                        | Name [ targetName ]
                            when (environment.VisibleBindings
                                  |> Map.tryFind targetName
                                  |> Option.orElseWith (fun () -> environment.VisibleConstructors |> Map.tryFind targetName))
                                 |> Option.bind (fun bindingInfo -> bindingInfo.ParameterLayouts)
                                 |> Option.isSome ->
                            rewriteDirectAliasUse aliasName targetName body
                        | Lambda(parameters, _) ->
                            rewriteNamedApplicationAliasUse aliasName parameters body
                        | _ ->
                            body
                    | _ ->
                        body

                let localStaticAliases = collectScopedPatternStaticAliases environment binding.Pattern value
                let bodyForLowering = rewriteStaticObjectPathAliasUses localStaticAliases bodyForLowering
                let localEffectOperationAliases = collectScopedPatternEffectOperationAliases environment binding.Pattern value
                let bodyForLowering = rewriteEffectOperationPathAliasUses environment localEffectOperationAliases bodyForLowering

                let valueType = bindingExpectedType |> Option.orElseWith (fun () -> inferExpressionType valueLocals value)

                lowerPatternBinding
                    localTypes
                    valueType
                    binding
                    loweredValue
                    (fun loweredLocals -> lowerExpression loweredLocals bodyForLowering)
            | LocalScopedEffect(declaration, body) ->
                withScopedEffectDeclaration environment.CurrentModuleIdentity declaration (fun () -> lowerExpressionWithExpectedType localTypes expectedType body)
            | Lambda(lambdaParameters, lambdaBody) ->
                lowerLambdaExpression localTypes None lambdaParameters lambdaBody
            | IfThenElse(condition, whenTrue, whenFalse) ->
                KCoreIfThenElse(
                    lowerExpressionWithExpectedType localTypes None condition,
                    lowerExpressionWithExpectedType localTypes expectedType whenTrue,
                    lowerExpressionWithExpectedType localTypes expectedType whenFalse
                )
            | Match(scrutinee, cases) ->
                let scrutineeType = inferExpressionType localTypes scrutinee

                let loweredCases : KCoreMatchCase list =
                    cases
                    |> List.collect (fun caseClause ->
                        let alternatives =
                            match caseClause.Pattern with
                            | OrPattern options -> options
                            | other -> [ other ]

                        alternatives
                        |> List.map (fun pattern ->
                            let caseLocals =
                                extendPatternLocalTypes environment freshCounter localTypes scrutineeType pattern

                            ({ Pattern = lowerPattern caseLocals scrutineeType pattern
                               Guard = caseClause.Guard |> Option.map (lowerExpression caseLocals)
                               Body = lowerExpression caseLocals caseClause.Body }
                             : KCoreMatchCase)))

                KCoreMatch(
                    lowerExpression localTypes scrutinee,
                    loweredCases
                )
            | RecordLiteral fields ->
                let inferredFields =
                    fields
                    |> List.map (fun field ->
                        inferExpressionType localTypes field.Value
                        |> Option.map (fun fieldType ->
                            { Name = field.Name
                              Quantity = if field.IsImplicit then QuantityZero else QuantityOmega
                              Type = fieldType }))

                if inferredFields |> List.forall Option.isSome then
                    let recordType = TypeRecord(inferredFields |> List.choose id)
                    let layout =
                        ensureSyntheticRecordLayout environment.CurrentModuleIdentity "<binding>" recordLayouts recordType

                    let fieldValues =
                        fields
                        |> List.map (fun field -> field.Name, field.Value)
                        |> Map.ofList

                    KCoreAppSpine(
                        KCoreName [ layout.ConstructorName ],
                        layout.Fields
                        |> List.map (fun field ->
                            fieldValues
                            |> Map.tryFind field.Name
                            |> Option.map (lowerExpression localTypes >> explicitKCoreArgument)
                            |> Option.defaultValue (explicitKCoreArgument (KCoreLiteral LiteralValue.Unit)))
                    )
                else
                    KCoreLiteral LiteralValue.Unit
            | Seal(value, _) ->
                lowerExpressionWithExpectedType localTypes expectedType value
            | RecordUpdate(receiver, fields) ->
                let loweredReceiver = lowerExpression localTypes receiver

                match inferExpressionType localTypes receiver |> Option.bind (tryCanonicalRecordType environment.VisibleTypeAliases) with
                | Some recordType ->
                    let layout =
                        ensureSyntheticRecordLayout environment.CurrentModuleIdentity "<binding>" recordLayouts recordType

                    let boundFields =
                        layout.Fields
                        |> List.map (fun field -> field.Name, freshSyntheticName $"__kappa_record_{field.Name}_")

                    let receiverSegments =
                        match receiver with
                        | Name segments -> Some segments
                        | _ -> None

                    let ordinaryUpdateValue topLevelName (group: SurfaceRecordUpdateField list) =
                        match group |> List.tryFind (fun field -> List.length field.Path = 1) with
                        | Some directField ->
                            directField.Value
                        | None ->
                            match receiverSegments with
                            | Some segments ->
                                let nestedFields =
                                    group
                                    |> List.choose (fun field ->
                                        match field.Path with
                                        | _ :: child :: rest ->
                                            Some
                                                { field with
                                                    Name = child.Name
                                                    IsImplicit = child.IsImplicit
                                                    IsExtension = false
                                                    Path = child :: rest }
                                        | _ ->
                                            None)

                                RecordUpdate(Name(segments @ [ topLevelName ]), nestedFields)
                            | None ->
                                group
                                |> List.tryHead
                                |> Option.map (fun field -> field.Value)
                                |> Option.defaultValue (Literal LiteralValue.Unit)

                    let updatedFields =
                        fields
                        |> List.filter (fun field -> not field.IsExtension)
                        |> List.groupBy (fun field -> field.Name)
                        |> List.map (fun (name, group) -> name, ordinaryUpdateValue name group)
                        |> Map.ofList

                    let pattern =
                        KCoreConstructorPattern(
                            [ layout.ConstructorName ],
                            boundFields
                            |> List.map (fun (_, bindingName) -> KCoreNamePattern bindingName)
                        )

                    let rebuiltFields =
                        layout.Fields
                        |> List.map (fun field ->
                            updatedFields
                            |> Map.tryFind field.Name
                            |> Option.map (lowerExpression localTypes)
                            |> Option.defaultValue (
                                boundFields
                                |> List.find (fun (name, _) -> String.Equals(name, field.Name, StringComparison.Ordinal))
                                |> snd
                                |> fun bindingName -> KCoreName [ bindingName ]))

                    KCoreMatch(
                        loweredReceiver,
                        [
                            { Pattern = pattern
                              Guard = None
                              Body =
                                KCoreAppSpine(
                                    KCoreName [ layout.ConstructorName ],
                                    rebuiltFields |> List.map explicitKCoreArgument
                                ) }
                        ]
                    )
                | None ->
                    loweredReceiver
            | MemberAccess(receiver, segments, arguments) ->
                match segments with
                | [] ->
                    KCoreAppSpine(lowerExpression localTypes receiver, lowerArguments arguments)
                | [ memberName ] ->
                    match
                        tryResolveHandledEffectDeclaration environment receiver
                        |> Option.bind (fun declaration ->
                            EffectSemantics.tryFindOperation memberName declaration
                            |> Option.map (fun operation -> declaration.VisibleName, declaration, operation))
                    with
                    | Some(effectName, declaration, operation) ->
                        let loweredOperation =
                            KCoreEffectOperation(
                                scopedKCoreEffectLabel declaration,
                                operation.OperationId,
                                operation.Name
                            )

                        if List.isEmpty arguments then
                            loweredOperation
                        else
                            KCoreAppSpine(loweredOperation, lowerArguments arguments)
                    | None ->
                        match tryResolveStaticConstructor environment receiver memberName with
                        | Some _ ->
                            KCoreAppSpine(lowerStaticConstructorCallee receiver memberName, lowerArguments arguments)
                        | None ->
                            let loweredReceiver = lowerExpression localTypes receiver

                            match inferExpressionType localTypes receiver with
                            | Some receiverType ->
                                match tryResolveTraitMemberFromReceiverType environment receiverType memberName with
                                | Some(traitInfo, resolvedMemberName, _) ->
                                    KCoreTraitCall(
                                        traitInfo.Name,
                                        resolvedMemberName,
                                        loweredReceiver,
                                        lowerArgumentExpressions arguments
                                    )
                                | None ->
                                    match environment.VisibleBindings |> Map.tryFind memberName with
                                    | Some bindingInfo ->
                                        match tryBuildReceiverMethodArguments bindingInfo receiver arguments with
                                        | Some receiverArguments ->
                                            match
                                                tryPrepareVisibleBindingCall
                                                    environment
                                                    freshCounter
                                                    bindingInfo
                                                    (Some localTypes)
                                                    (inferValidationExpressionTypeWithContext
                                                        environment
                                                        freshCounter
                                                        localTypes
                                                        localTypes)
                                                    (tryResolveUniqueLocalImplicitByType environment localTypes)
                                                    receiverArguments
                                            with
                                            | Some preparedCall ->
                                                KCoreAppSpine(KCoreName [ memberName ], lowerPreparedBindingCallArguments bindingInfo preparedCall)
                                            | None ->
                                                KCoreAppSpine(KCoreName [ memberName ], lowerArguments receiverArguments)
                                        | None ->
                                            if List.isEmpty arguments then
                                                KCoreName [ memberName ]
                                            else
                                                KCoreAppSpine(KCoreName [ memberName ], lowerArguments arguments)
                                    | None ->
                                        tryLowerRecordProjectionPath localTypes loweredReceiver receiverType [ memberName ]
                                        |> Option.map (fun projected ->
                                            if List.isEmpty arguments then
                                                projected
                                            else
                                                KCoreAppSpine(projected, lowerArguments arguments))
                                        |> Option.defaultValue (KCoreName [ memberName ])
                            | None ->
                                match environment.VisibleBindings |> Map.tryFind memberName with
                                | Some bindingInfo ->
                                    match tryBuildReceiverMethodArguments bindingInfo receiver arguments with
                                    | Some receiverArguments ->
                                        match
                                            tryPrepareVisibleBindingCall
                                                environment
                                                freshCounter
                                                bindingInfo
                                                (Some localTypes)
                                                (inferValidationExpressionTypeWithContext
                                                    environment
                                                    freshCounter
                                                    localTypes
                                                    localTypes)
                                                (tryResolveUniqueLocalImplicitByType environment localTypes)
                                                receiverArguments
                                        with
                                        | Some preparedCall ->
                                            KCoreAppSpine(KCoreName [ memberName ], lowerPreparedBindingCallArguments bindingInfo preparedCall)
                                        | None ->
                                            KCoreAppSpine(KCoreName [ memberName ], lowerArguments receiverArguments)
                                    | None ->
                                        if List.isEmpty arguments then
                                            KCoreName [ memberName ]
                                        else
                                            KCoreAppSpine(KCoreName [ memberName ], lowerArguments arguments)
                                | None ->
                                    KCoreName [ memberName ]
                | memberName :: rest ->
                    lowerExpression localTypes (MemberAccess(MemberAccess(receiver, [ memberName ], []), rest, arguments))
            | SafeNavigation(receiver, navigation) ->
                let loweredReceiver = lowerExpression localTypes receiver
                let binderName = freshSyntheticName "__kappa_safe_"

                let loweredMember =
                    let callee = KCoreName(binderName :: navigation.Segments)

                    match navigation.Arguments with
                    | [] ->
                        callee
                    | arguments ->
                        KCoreAppSpine(callee, arguments |> List.map (lowerExpression localTypes >> explicitKCoreArgument))

                let wrapsResult =
                    inferExpressionType localTypes receiver
                    |> Option.bind (fun receiverType ->
                        tryOptionPayloadType environment.VisibleTypeAliases receiverType
                        |> Option.bind (fun payloadType ->
                            tryInferSafeNavigationMemberType
                                environment.VisibleTypeAliases
                                (qualifyVisibleTypeNames environment)
                                (inferExpressionType localTypes)
                                payloadType
                                navigation))
                    |> Option.bind (tryOptionPayloadType environment.VisibleTypeAliases)
                    |> Option.isNone

                let successBody =
                    if wrapsResult then
                        KCoreAppSpine(KCoreName [ "Some" ], [ explicitKCoreArgument loweredMember ])
                    else
                        loweredMember

                KCoreMatch(
                    loweredReceiver,
                    [
                        { Pattern = KCoreConstructorPattern([ "Some" ], [ KCoreNamePattern binderName ])
                          Guard = None
                          Body = successBody }
                        { Pattern = KCoreConstructorPattern([ "None" ], [])
                          Guard = None
                          Body = KCoreName [ "None" ] }
                    ]
                )
            | TagTest(receiver, constructorName) ->
                KCoreBinary(lowerExpression localTypes receiver, "is", KCoreName constructorName)
            | Do statements ->
                match
                    expectedType |> Option.bind tryUnwrapEffType |> Option.isSome
                    || hasEffectfulDoFlow localTypes statements
                with
                | true ->
                    match tryLowerEffectfulDoStatements localTypes statements with
                    | Some loweredEffectBody ->
                        loweredEffectBody
                    | None ->
                        let scopeLabel = freshDoScopeLabel ()
                        KCoreDoScope(scopeLabel, lowerDoStatements scopeLabel localTypes statements)
                | false ->
                    let scopeLabel = freshDoScopeLabel ()
                    KCoreDoScope(scopeLabel, lowerDoStatements scopeLabel localTypes statements)
            | MonadicSplice inner ->
                KCoreExecute(lowerExpressionWithExpectedType localTypes None inner)
            | ExplicitImplicitArgument inner ->
                lowerExpressionWithExpectedType localTypes None inner
            | NamedApplicationBlock _ ->
                KCoreLiteral LiteralValue.Unit
            | InoutArgument inner ->
                lowerExpressionWithExpectedType localTypes None inner
            | Apply _ as application when tryMatchQueryCarrierShape application |> Option.isSome ->
                let carrier = tryMatchQueryCarrierShape application |> Option.get
                lowerExpressionWithExpectedType localTypes expectedType carrier.Comprehension.Lowered
            | Apply(Name [ receiverName; memberName ], arguments) ->
                match tryResolveEffectOperationNamePath environment [ receiverName; memberName ] with
                | Some(effectName, declaration, operation) ->
                    KCoreAppSpine(
                        KCoreEffectOperation(
                            scopedKCoreEffectLabel declaration,
                            operation.OperationId,
                            operation.Name
                        ),
                        lowerArguments arguments
                    )
                | None ->
                    match tryResolveStaticConstructor environment (Name [ receiverName ]) memberName with
                    | Some _ ->
                        KCoreAppSpine(lowerStaticConstructorCallee (Name [ receiverName ]) memberName, lowerArguments arguments)
                    | None ->
                        match tryResolveTraitMemberProjection environment localTypes [ receiverName; memberName ] with
                        | Some(traitInfo, resolvedMemberName, _, resolvedReceiverName) ->
                                KCoreTraitCall(
                                    traitInfo.Name,
                                    resolvedMemberName,
                                    lowerExpressionWithExpectedType localTypes None (Name [ resolvedReceiverName ]),
                                    lowerArgumentExpressions arguments
                                )
                        | None ->
                            match environment.VisibleBindings |> Map.tryFind memberName with
                            | Some bindingInfo ->
                                match tryBuildReceiverMethodArguments bindingInfo (Name [ receiverName ]) arguments with
                                | Some receiverArguments ->
                                    match
                                        tryPrepareVisibleBindingCall
                                            environment
                                            freshCounter
                                            bindingInfo
                                            (Some localTypes)
                                            (inferValidationExpressionTypeWithContext
                                                environment
                                                freshCounter
                                                localTypes
                                                localTypes)
                                            (tryResolveUniqueLocalImplicitByType environment localTypes)
                                            receiverArguments
                                    with
                                    | Some preparedCall ->
                                        KCoreAppSpine(KCoreName [ memberName ], lowerPreparedBindingCallArguments bindingInfo preparedCall)
                                    | None ->
                                        KCoreAppSpine(KCoreName [ memberName ], lowerArguments receiverArguments)
                                | None ->
                                    KCoreAppSpine(lowerExpression localTypes (Name [ receiverName; memberName ]), lowerArguments arguments)
                            | None ->
                                KCoreAppSpine(lowerExpression localTypes (Name [ receiverName; memberName ]), lowerArguments arguments)
            | Apply(MemberAccess(receiver, [ memberName ], []), arguments) ->
                match tryResolveStaticConstructor environment receiver memberName with
                | Some _ ->
                    KCoreAppSpine(lowerStaticConstructorCallee receiver memberName, lowerArguments arguments)
                | None ->
                    KCoreAppSpine(
                        lowerExpressionWithExpectedType localTypes None (MemberAccess(receiver, [ memberName ], [])),
                        lowerArguments arguments
                    )
            | Apply(Name nameSegments, arguments) ->
                match tryResolveEffectOperationNamePath environment nameSegments with
                | Some(effectName, declaration, operation) ->
                    KCoreAppSpine(
                        KCoreEffectOperation(
                            scopedKCoreEffectLabel declaration,
                            operation.OperationId,
                            operation.Name
                        ),
                        lowerArguments arguments
                    )
                | None ->
                    match tryResolveTraitMemberProjection environment localTypes nameSegments with
                    | Some(traitInfo, memberName, _, receiverName) ->
                        KCoreTraitCall(
                            traitInfo.Name,
                            memberName,
                            lowerExpressionWithExpectedType localTypes None (Name [ receiverName ]),
                            lowerArgumentExpressions arguments
                        )
                    | None ->
                        match nameSegments with
                        | [ calleeName ]
                            when not (Map.containsKey calleeName localTypes)
                                 && environment.ConstrainedMembers.ContainsKey calleeName ->
                            let traitName, dictionaryParameterName = environment.ConstrainedMembers[calleeName]

                            KCoreTraitCall(
                                traitName,
                                calleeName,
                                KCoreName [ dictionaryParameterName ],
                                lowerArgumentExpressions arguments
                            )
                        | [ calleeName ] when environment.VisibleConstructors.ContainsKey calleeName ->
                            let constructorInfo = environment.VisibleConstructors[calleeName]
                            match
                                tryPrepareVisibleBindingCall
                                    environment
                                    freshCounter
                                    constructorInfo
                                    (Some localTypes)
                                    (inferValidationExpressionTypeWithContext
                                        environment
                                        freshCounter
                                        localTypes
                                        localTypes)
                                    (tryResolveUniqueLocalImplicitByType environment localTypes)
                                    arguments
                            with
                            | Some preparedCall ->
                                KCoreAppSpine(
                                    KCoreName [ calleeName ],
                                    lowerPreparedBindingCallArguments constructorInfo preparedCall
                                )
                            | None ->
                                KCoreAppSpine(KCoreName [ calleeName ], lowerArguments arguments)
                        | [ calleeName ] when ordinarySurfaceNameShadowsVisiblePreludeBinding environment localTypes calleeName ->
                            KCoreAppSpine(KCoreName [ calleeName ], lowerArguments arguments)
                        | [ calleeName ] when environment.VisibleBindings.ContainsKey calleeName ->
                            let bindingInfo = environment.VisibleBindings[calleeName]
                            match
                                tryPrepareVisibleBindingCall
                                    environment
                                    freshCounter
                                    bindingInfo
                                    (Some localTypes)
                                    (inferValidationExpressionTypeWithContext
                                        environment
                                        freshCounter
                                        localTypes
                                        localTypes)
                                    (tryResolveUniqueLocalImplicitByType environment localTypes)
                                    arguments
                            with
                            | Some preparedCall ->
                                let dictionaryArguments =
                                    preparedCall.InstantiatedScheme.Constraints
                                    |> List.choose (fun constraintInfo ->
                                        tryLowerResolvedDictionaryValue environment constraintInfo
                                        |> Option.map explicitKCoreArgument)
                                    |> eraseIntrinsicPreludeDictionaryArguments bindingInfo

                                KCoreAppSpine(
                                    KCoreName [ calleeName ],
                                    dictionaryArguments @ lowerPreparedBindingCallArguments bindingInfo preparedCall
                                )
                            | None ->
                                KCoreAppSpine(KCoreName [ calleeName ], lowerArguments arguments)
                        | [ calleeName ] ->
                            match
                                tryPrepareVisibleTraitMemberCall
                                    environment
                                    freshCounter
                                    calleeName
                                    (inferValidationExpressionTypeWithContext
                                        environment
                                        freshCounter
                                        localTypes
                                        localTypes)
                                    arguments
                            with
                            | Some(traitInfo, _, preparedCall, instanceInfo) ->
                                KCoreTraitCall(
                                    traitInfo.Name,
                                    calleeName,
                                    lowerResolvedOwningDictionaryValue
                                        environment
                                        traitInfo.Name
                                        preparedCall
                                        instanceInfo,
                                    lowerPreparedArgumentExpressions preparedCall.Arguments
                                )
                            | None ->
                                KCoreAppSpine(KCoreName [ calleeName ], lowerArguments arguments)
                        | _ ->
                            KCoreAppSpine(lowerExpression localTypes (Name nameSegments), lowerArguments arguments)
            | Apply(callee, arguments) ->
                KCoreAppSpine(lowerExpressionWithExpectedType localTypes None callee, lowerArguments arguments)
            | Unary(operatorName, operand) ->
                let operandExpectedType =
                    if operatorName = "-" || operatorName = "negate" then expectedType else None

                KCoreUnary(operatorName, lowerExpressionWithExpectedType localTypes operandExpectedType operand)
            | Binary(left, operatorName, right) ->
                let lowerAsApply () =
                    lowerExpressionWithExpectedType localTypes expectedType (Apply(Name [ operatorName ], [ left; right ]))

                let tryLowerVisibleTraitOperatorCall () =
                    match
                        tryPrepareVisibleTraitMemberCall
                            environment
                            freshCounter
                            operatorName
                            (inferExpressionType localTypes)
                            [ left; right ]
                    with
                    | Some(traitInfo, _, preparedCall, instanceInfo) ->
                        Some
                            (KCoreTraitCall(
                                traitInfo.Name,
                                operatorName,
                                lowerResolvedOwningDictionaryValue
                                    environment
                                    traitInfo.Name
                                    preparedCall
                                    instanceInfo,
                                lowerPreparedArgumentExpressions preparedCall.Arguments
                            ))
                    | None ->
                        None

                let shouldLowerBinaryAsOrdinaryApply =
                    environment.ConstrainedMembers.ContainsKey operatorName
                    || environment.VisibleBindings.ContainsKey operatorName
                    || environment.VisibleConstructors.ContainsKey operatorName
                    || match operatorName with
                       | "=="
                       | "!="
                       | "/="
                       | "<"
                       | ">"
                       | "<="
                       | ">="
                       | ".."
                       | "..<" -> true
                       | _ -> false

                if shouldLowerBinaryAsOrdinaryApply then
                    lowerAsApply ()
                else
                    match tryLowerVisibleTraitOperatorCall () with
                    | Some lowered -> lowered
                    | None ->
                        KCoreBinary(lowerExpression localTypes left, operatorName, lowerExpression localTypes right)
            | Elvis(left, right) ->
                let binderName = freshSyntheticName "__kappa_elvis_"

                KCoreMatch(
                    lowerExpression localTypes left,
                    [
                        { Pattern = KCoreConstructorPattern([ "Some" ], [ KCoreNamePattern binderName ])
                          Guard = None
                          Body = KCoreName [ binderName ] }
                        { Pattern = KCoreConstructorPattern([ "None" ], [])
                          Guard = None
                          Body = lowerExpression localTypes right }
                    ]
                )
            | PrefixedString(prefix, parts) ->
                lowerPrefixedString prefix parts

        let bodyForLowering =
            match parameters, scheme, body with
            | [], Some scheme, Lambda(lambdaParameters, lambdaBody) ->
                let parameterTypes, _ = TypeSignatures.schemeParts scheme

                if List.length parameterTypes = List.length lambdaParameters then
                    let annotatedParameters =
                        List.zip lambdaParameters parameterTypes
                        |> List.map (fun (parameter, parameterType) ->
                            if parameter.TypeTokens.IsSome then
                                parameter
                            else
                                { parameter with
                                    TypeTokens = Some(typeTextTokens (TypeSignatures.toText parameterType)) })

                    Lambda(annotatedParameters, lambdaBody)
                else
                    body
            | _ ->
                body

        lowerExpressionWithExpectedType localTypes (lowerBindingReturnTypeExpr scheme parameters None) bodyForLowering

    let private lowerUserBinding
        (environment: BindingLoweringEnvironment)
        (recordLayouts: Map<string, SyntheticRecordLayout> ref)
        (moduleTopLevelDefinitionsByName: Map<string, LetDefinition>)
        (filePath: string)
        (definition: LetDefinition)
        (sourceSignature: BindingSignature option)
        (bindingInfo: BindingSchemeInfo option)
        =
        let sourceSignatureScheme =
            sourceSignature
            |> Option.bind (fun declaration -> TypeSignatures.parseScheme declaration.TypeTokens)

        let sourceSignatureParameterLayouts =
            sourceSignature
            |> Option.bind (fun declaration ->
                declaration.TypeTokens
                |> splitSignatureParameterTokens
                |> function
                    | [] -> None
                    | parameterTokens -> Some(parameterTokens |> List.map tryParseSignatureParameterLayout))

        let scheme =
            sourceSignatureScheme
            |> Option.orElseWith (fun () -> bindingInfo |> Option.map (fun info -> info.Scheme))

        let explicitLeadingForallParameters, explicitRuntimeDefinitionParameters =
            splitLeadingForallParameters scheme definition.Parameters

        let synthesizedOmittedImplicitParameters =
            let isAnonymousSignatureLayoutName name =
                String.IsNullOrWhiteSpace name
                || String.Equals(name, "_", StringComparison.Ordinal)
                || name.StartsWith("__kappa_signature_wildcard_", StringComparison.Ordinal)

            let signatureLayoutMatchesExplicitParameter (layout: Parameter) (explicitParameter: Parameter) =
                layout.IsImplicit = explicitParameter.IsImplicit
                && layout.IsInout = explicitParameter.IsInout
                && layout.IsReceiver = explicitParameter.IsReceiver
                &&
                (if isAnonymousSignatureLayoutName layout.Name then
                     true
                 else
                     String.Equals(layout.Name, explicitParameter.Name, StringComparison.Ordinal))

            let synthesizeParameter (layout: Parameter) parameterType synthesizedIndex : Parameter =
                let parameterName =
                    if String.IsNullOrWhiteSpace layout.Name
                       || String.Equals(layout.Name, "_", StringComparison.Ordinal)
                       || layout.Name.StartsWith("__kappa_signature_wildcard_", StringComparison.Ordinal) then
                        $"__kappa_implicit_{synthesizedIndex}"
                    else
                        layout.Name

                { Name = parameterName
                  TypeTokens = Some(typeTextTokens (TypeSignatures.toText parameterType))
                  Quantity = layout.Quantity
                  IsImplicit = true
                  IsInout = layout.IsInout
                  IsReceiver = layout.IsReceiver }

            let synthesizeImplicitParameter parameterType synthesizedIndex : Parameter =
                synthesizeParameter
                    { Name = $"__kappa_implicit_{synthesizedIndex}"
                      TypeTokens = Some(typeTextTokens (TypeSignatures.toText parameterType))
                      Quantity = None
                      IsImplicit = true
                      IsInout = false
                      IsReceiver = false }
                    parameterType
                    synthesizedIndex

            let synthesizedFromSchemePrefix =
                match scheme with
                | Some bindingScheme ->
                    let parameterTypes, _ = TypeSignatures.schemeParts bindingScheme
                    let omittedLeadingCount = parameterTypes.Length - explicitRuntimeDefinitionParameters.Length

                    if omittedLeadingCount <= 0 then
                        []
                    else
                        parameterTypes
                        |> List.take omittedLeadingCount
                        |> List.mapi (fun index parameterType ->
                            if isCompileTimeArgumentType environment.VisibleTypeAliases parameterType then
                                None
                            elif tryTraitConstraintFromType environment parameterType |> Option.isSome then
                                Some(synthesizeImplicitParameter parameterType index)
                            else
                                None)
                        |> List.choose id
                | None ->
                    []

            let synthesizedFromSignatureLayouts =
                match scheme, sourceSignatureParameterLayouts with
                | Some bindingScheme, Some signatureLayouts ->
                    let parameterTypes, _ = TypeSignatures.schemeParts bindingScheme

                    if List.length signatureLayouts <> List.length parameterTypes then
                        []
                    else
                        let rec collectOmitted
                            (layouts: Parameter option list)
                            (types: TypeExpr list)
                            (explicitRuntimeParameters: Parameter list)
                            (synthesized: Parameter list)
                            synthesizedIndex
                            =
                            match layouts, types with
                            | layoutOpt :: restLayouts, parameterType :: restTypes ->
                                match layoutOpt, explicitRuntimeParameters with
                                | Some layout, explicitParameter :: restExplicit
                                    when signatureLayoutMatchesExplicitParameter layout explicitParameter ->
                                    collectOmitted
                                        restLayouts
                                        restTypes
                                        restExplicit
                                        synthesized
                                        synthesizedIndex
                                | Some layout, _
                                    when layout.IsImplicit
                                         && not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType) ->
                                    let synthesizedParameter = synthesizeParameter layout parameterType synthesizedIndex

                                    collectOmitted
                                        restLayouts
                                        restTypes
                                        explicitRuntimeParameters
                                        (synthesizedParameter :: synthesized)
                                        (synthesizedIndex + 1)
                                | Some _, _ :: restExplicit ->
                                    collectOmitted
                                        restLayouts
                                        restTypes
                                        restExplicit
                                        synthesized
                                        synthesizedIndex
                                | Some _, [] ->
                                    collectOmitted restLayouts restTypes [] synthesized synthesizedIndex
                                | None, _ :: restExplicit ->
                                    collectOmitted restLayouts restTypes restExplicit synthesized synthesizedIndex
                                | None, [] ->
                                    collectOmitted restLayouts restTypes [] synthesized synthesizedIndex
                            | _ ->
                                List.rev synthesized

                        collectOmitted
                            signatureLayouts
                            parameterTypes
                            explicitRuntimeDefinitionParameters
                            []
                            0
                | _, _ ->
                    []

            match scheme, sourceSignatureParameterLayouts |> Option.orElseWith (fun () -> bindingInfo |> Option.bind (fun info -> info.ParameterLayouts |> Option.map (List.map Some))) with
            | Some bindingScheme, Some parameterLayouts ->
                let parameterTypes, _ = TypeSignatures.schemeParts bindingScheme

                let resolvedParameterLayouts =
                    if parameterLayouts |> List.forall Option.isSome then
                        Some(parameterLayouts |> List.choose id)
                    else
                        None

                match
                    resolvedParameterLayouts
                    |> Option.bind (fun layouts ->
                        tryAlignParameterTypesWithLayouts environment Map.empty layouts parameterTypes)
                with
                | Some(alignedParameterTypes, _) ->
                    let synthesized =
                        if List.isEmpty synthesizedFromSignatureLayouts then
                            let rec collectOmitted
                                (layouts: Parameter list)
                                alignedTypes
                                (explicitRuntimeParameters: Parameter list)
                                (synthesized: Parameter list)
                                synthesizedIndex
                                =
                                match layouts, alignedTypes with
                                | layout :: restLayouts, parameterType :: restTypes ->
                                    let nextExplicitParameter =
                                        explicitRuntimeParameters |> List.tryHead

                                    let matchesExplicitParameter =
                                        nextExplicitParameter
                                        |> Option.exists (fun explicitParameter ->
                                            signatureLayoutMatchesExplicitParameter layout explicitParameter)

                                    if matchesExplicitParameter then
                                        collectOmitted
                                            restLayouts
                                            restTypes
                                            (explicitRuntimeParameters |> List.tail)
                                            synthesized
                                            synthesizedIndex
                                    elif layout.IsImplicit && not (isCompileTimeArgumentType environment.VisibleTypeAliases parameterType) then
                                        let synthesizedParameter = synthesizeParameter layout parameterType synthesizedIndex

                                        collectOmitted
                                            restLayouts
                                            restTypes
                                            explicitRuntimeParameters
                                            (synthesizedParameter :: synthesized)
                                            (synthesizedIndex + 1)
                                    elif isCompileTimeArgumentType environment.VisibleTypeAliases parameterType then
                                        collectOmitted
                                            restLayouts
                                            restTypes
                                            explicitRuntimeParameters
                                            synthesized
                                            synthesizedIndex
                                    else
                                        List.rev synthesized
                                | _ ->
                                    List.rev synthesized

                            collectOmitted
                                (resolvedParameterLayouts.Value)
                                alignedParameterTypes
                                explicitRuntimeDefinitionParameters
                                []
                                0
                        else
                            synthesizedFromSignatureLayouts

                    if List.isEmpty synthesized then
                        synthesizedFromSchemePrefix
                    else
                        synthesized
                | None ->
                    if List.isEmpty synthesizedFromSignatureLayouts then
                        synthesizedFromSchemePrefix
                    else
                        synthesizedFromSignatureLayouts
            | _, _ ->
                if List.isEmpty synthesizedFromSignatureLayouts then
                    synthesizedFromSchemePrefix
                else
                    synthesizedFromSignatureLayouts

        let initialEffectiveDefinitionParameters =
            explicitLeadingForallParameters
            @ synthesizedOmittedImplicitParameters
            @ explicitRuntimeDefinitionParameters

        let constraintRuntimeParameterNames, schemeConstraintParameterLocalTypes, effectiveDefinitionParameters =
            let constraintMatches
                (left: TypeSignatures.TraitConstraint)
                (right: TypeSignatures.TraitConstraint)
                =
                traitReferenceSegments left.Trait = traitReferenceSegments right.Trait
                && List.length left.Arguments = List.length right.Arguments
                && List.forall2 TypeSignatures.definitionallyEqual left.Arguments right.Arguments

            let tryParseParameterConstraint (parameter: Parameter) =
                parameter.TypeTokens
                |> Option.bind TypeSignatures.parseType
                |> Option.map (qualifyVisibleTypeNames environment)
                |> Option.bind (tryTraitConstraintFromType environment)

            match scheme with
            | Some bindingScheme ->
                let rec consumeLeadingConstraintParameters
                    (remainingConstraints: TypeSignatures.TraitConstraint list)
                    (remainingParameters: Parameter list)
                    (consumedNames: string list)
                    (consumedLocalTypes: (string * TypeExpr) list)
                    =
                    match remainingConstraints, remainingParameters with
                    | constraintInfo :: restConstraints, parameter :: restParameters when parameter.IsImplicit ->
                        match tryParseParameterConstraint parameter with
                        | Some parameterConstraint when constraintMatches constraintInfo parameterConstraint ->
                            consumeLeadingConstraintParameters
                                restConstraints
                                restParameters
                                (parameter.Name :: consumedNames)
                                ((parameter.Name, traitConstraintTypeName constraintInfo)
                                 :: consumedLocalTypes)
                        | None when parameter.TypeTokens.IsNone ->
                            consumeLeadingConstraintParameters
                                restConstraints
                                restParameters
                                (parameter.Name :: consumedNames)
                                ((parameter.Name, traitConstraintTypeName constraintInfo)
                                 :: consumedLocalTypes)
                        | _ ->
                            List.rev consumedNames, List.rev consumedLocalTypes, remainingParameters
                    | _ ->
                        List.rev consumedNames, List.rev consumedLocalTypes, remainingParameters

                let consumedNames, consumedLocalTypes, remainingParameters =
                    consumeLeadingConstraintParameters
                        bindingScheme.Constraints
                        initialEffectiveDefinitionParameters
                        []
                        []

                let runtimeParameterNames =
                    bindingScheme.Constraints
                    |> List.mapi (fun index constraintInfo ->
                        consumedNames
                        |> List.tryItem index
                        |> Option.defaultValue $"__kappa_dict_{traitConstraintBinderStem constraintInfo}_{index}")

                runtimeParameterNames, consumedLocalTypes, remainingParameters
            | None ->
                [], [], initialEffectiveDefinitionParameters

        let parameterConstraintLocalTypes =
            match scheme with
            | Some currentScheme ->
                buildParameterConstraintLocalTypes environment currentScheme effectiveDefinitionParameters
            | None ->
                []

        let constrainedMembers, hiddenParameters =
            match scheme with
            | Some scheme ->
                let memberEntries =
                    scheme.Constraints
                    |> List.mapi (fun index constraintInfo ->
                        let dictionaryParameterName =
                            constraintRuntimeParameterNames
                            |> List.tryItem index
                            |> Option.defaultValue $"__kappa_dict_{traitConstraintBinderStem constraintInfo}_{index}"

                        constraintInfo, dictionaryParameterName)

                let schemeConstrainedMembers =
                    if List.isEmpty scheme.Constraints then
                        Map.empty
                    else
                        buildConstrainedMembers environment scheme.Constraints

                let parameterConstrainedMembers =
                    buildParameterConstrainedMembers environment scheme effectiveDefinitionParameters

                let constrainedMembers =
                    parameterConstrainedMembers
                    |> Map.fold (fun state memberName route ->
                        if Map.containsKey memberName state then
                            state
                        else
                            Map.add memberName route state) schemeConstrainedMembers

                constrainedMembers, memberEntries
            | _ ->
                Map.empty, []

        let constraintDictionaries =
            match scheme with
            | Some currentScheme ->
                let schemeConstraintDictionaries =
                    hiddenParameters
                    |> List.map (fun (constraintInfo, dictionaryParameterName) ->
                        constraintInfo, KCoreName [ dictionaryParameterName ])
                    |> buildConstraintDictionaries environment

                let parameterConstraintDictionaries =
                    buildParameterConstraintDictionaries environment currentScheme effectiveDefinitionParameters

                parameterConstraintDictionaries
                |> Map.fold (fun state key value ->
                    if Map.containsKey key state then
                        state
                    else
                        Map.add key value state) schemeConstraintDictionaries
            | None ->
                Map.empty

        let bodyEnvironment =
            { environment with
                ConstraintDictionaries = constraintDictionaries
                ConstrainedMembers = constrainedMembers }

        let hiddenParameters =
            hiddenParameters
            |> List.map (fun (constraintInfo, dictionaryParameterName) ->
                lowerSyntheticKCoreParameter
                    dictionaryParameterName
                    None
                    true
                    (Some(dictionaryType (traitConstraintLocalName constraintInfo) constraintInfo.Arguments)))

        let tryInferLambdaParameterTypesFromTopLevelCalls (lambdaParameters: Parameter list) =
            definition.Name
            |> Option.bind (fun bindingName ->
                let inferArgumentType argument =
                    inferValidationExpressionType bodyEnvironment (ref 0) Map.empty argument

                let rec findCall expression =
                    match expression with
                    | Apply(Name [ calleeName ], arguments)
                        when String.Equals(calleeName, bindingName, StringComparison.Ordinal)
                             && List.length arguments = List.length lambdaParameters ->
                        let argumentTypes = arguments |> List.map inferArgumentType

                        if argumentTypes |> List.forall Option.isSome then
                            Some(argumentTypes |> List.choose id)
                        else
                            None
                    | Apply(callee, arguments) ->
                        findCall callee
                        |> Option.orElseWith (fun () -> arguments |> List.tryPick findCall)
                    | LocalLet(_, value, body) ->
                        findCall value |> Option.orElseWith (fun () -> findCall body)
                    | LocalSignature(_, body)
                    | LocalTypeAlias(_, body)
                    | LocalScopedEffect(_, body)
                    | Lambda(_, body)
                    | SyntaxQuote body
                    | SyntaxSplice body
                    | TopLevelSyntaxSplice body
                    | CodeQuote body
                    | CodeSplice body
                    | MonadicSplice body
                    | ExplicitImplicitArgument body
                    | InoutArgument body
                    | Unary(_, body)
                    | Seal(body, _)
                    | TagTest(body, _) ->
                        findCall body
                    | TypeSyntaxTokens _ ->
                        None
                    | Handle(_, label, body, returnClause, operationClauses) ->
                        findCall label
                        |> Option.orElseWith (fun () -> findCall body)
                        |> Option.orElseWith (fun () -> findCall returnClause.Body)
                        |> Option.orElseWith (fun () -> operationClauses |> List.tryPick (fun clause -> findCall clause.Body))
                    | IfThenElse(condition, whenTrue, whenFalse) ->
                        findCall condition
                        |> Option.orElseWith (fun () -> findCall whenTrue)
                        |> Option.orElseWith (fun () -> findCall whenFalse)
                    | Match(scrutinee, cases) ->
                        findCall scrutinee
                        |> Option.orElseWith (fun () ->
                            cases
                            |> List.tryPick (fun caseClause ->
                                caseClause.Guard
                                |> Option.bind findCall
                                |> Option.orElseWith (fun () -> findCall caseClause.Body)))
                    | RecordLiteral fields ->
                        fields |> List.tryPick (fun field -> findCall field.Value)
                    | RecordUpdate(receiver, fields) ->
                        findCall receiver
                        |> Option.orElseWith (fun () -> fields |> List.tryPick (fun field -> findCall field.Value))
                    | MemberAccess(receiver, _, arguments) ->
                        findCall receiver
                        |> Option.orElseWith (fun () -> arguments |> List.tryPick findCall)
                    | SafeNavigation(receiver, navigation) ->
                        findCall receiver
                        |> Option.orElseWith (fun () -> navigation.Arguments |> List.tryPick findCall)
                    | Do statements ->
                        statements
                        |> List.tryPick (function
                            | DoLet(_, value)
                            | DoBind(_, value)
                            | DoUsing(_, value)
                            | DoVar(_, value)
                            | DoAssign(_, value)
                            | DoDefer value
                            | DoExpression value
                            | DoReturn value ->
                                findCall value
                            | DoLetQuestion(_, value, failure) ->
                                findCall value
                                |> Option.orElseWith (fun () ->
                                    failure |> Option.bind (fun block -> block.Body |> List.tryPick (function
                                        | DoLet(_, nestedValue)
                                        | DoBind(_, nestedValue)
                                        | DoUsing(_, nestedValue)
                                        | DoVar(_, nestedValue)
                                        | DoAssign(_, nestedValue)
                                        | DoDefer nestedValue
                                        | DoExpression nestedValue
                                        | DoReturn nestedValue -> findCall nestedValue
                                        | _ -> None)))
                            | DoIf(condition, whenTrue, whenFalse) ->
                                findCall condition
                                |> Option.orElseWith (fun () -> whenTrue |> List.tryPick (fun statement ->
                                    match statement with
                                    | DoLet(_, value)
                                    | DoBind(_, value)
                                    | DoUsing(_, value)
                                    | DoVar(_, value)
                                    | DoAssign(_, value)
                                    | DoDefer value
                                    | DoExpression value
                                    | DoReturn value -> findCall value
                                    | _ -> None))
                                |> Option.orElseWith (fun () -> whenFalse |> List.tryPick (fun statement ->
                                    match statement with
                                    | DoLet(_, value)
                                    | DoBind(_, value)
                                    | DoUsing(_, value)
                                    | DoVar(_, value)
                                    | DoAssign(_, value)
                                    | DoDefer value
                                    | DoExpression value
                                    | DoReturn value -> findCall value
                                    | _ -> None))
                            | DoWhile(condition, body) ->
                                findCall condition
                                |> Option.orElseWith (fun () -> body |> List.tryPick (function
                                    | DoLet(_, value)
                                    | DoBind(_, value)
                                    | DoUsing(_, value)
                                    | DoVar(_, value)
                                    | DoAssign(_, value)
                                    | DoDefer value
                                    | DoExpression value
                                    | DoReturn value -> findCall value
                                    | _ -> None)))
                    | Binary(left, _, right)
                    | Elvis(left, right) ->
                        findCall left |> Option.orElseWith (fun () -> findCall right)
                    | Comprehension comprehension ->
                        findCall comprehension.Lowered
                    | PrefixedString(_, parts) ->
                        parts
                        |> List.tryPick (function
                            | StringText _ -> None
                            | StringInterpolation(inner, _) -> findCall inner)
                    | NamedApplicationBlock fields ->
                        fields |> List.tryPick (fun field -> findCall field.Value)
                    | Literal _
                    | NumericLiteral _
                    | KindQualifiedName _
                    | Name _ ->
                        None

                moduleTopLevelDefinitionsByName
                |> Map.toList
                |> List.filter (fun (candidateName, _) -> not (String.Equals(candidateName, bindingName, StringComparison.Ordinal)))
                |> List.tryPick (fun (_, candidateDefinition) ->
                    candidateDefinition.Body |> Option.bind findCall))

        let tryResolveManifestStaticFieldFromFunctionResult
            calleeName
            (arguments: SurfaceExpression list)
            fieldName
            =
            let rec tryResolveStaticValue parameterStaticObjects expression =
                match expression with
                | Name [ name ] ->
                    parameterStaticObjects
                    |> Map.tryFind name
                    |> Option.orElseWith (fun () -> tryResolveScopedStaticObject environment expression)
                | Seal(inner, _) ->
                    tryResolveStaticValue parameterStaticObjects inner
                | _ ->
                    tryResolveScopedStaticObject environment expression

            let rec tryResolveField parameterStaticObjects expression =
                match expression with
                | RecordLiteral fields ->
                    fields
                    |> List.tryFind (fun field -> String.Equals(field.Name, fieldName, StringComparison.Ordinal))
                    |> Option.bind (fun field -> tryResolveStaticValue parameterStaticObjects field.Value)
                | Seal(inner, _) ->
                    tryResolveField parameterStaticObjects inner
                | _ ->
                    None

            moduleTopLevelDefinitionsByName
            |> Map.tryFind calleeName
            |> Option.bind (fun calleeDefinition ->
                if List.length calleeDefinition.Parameters <> List.length arguments then
                    None
                else
                    let parameterStaticObjects =
                        List.zip calleeDefinition.Parameters arguments
                        |> List.choose (fun (parameter, argument) ->
                            tryResolveScopedStaticObject environment argument
                            |> Option.map (fun staticObject -> parameter.Name, staticObject))
                        |> Map.ofList

                    calleeDefinition.Body
                    |> Option.bind (tryResolveField parameterStaticObjects))

        let rec rewriteManifestStaticFieldUses expression =
            let rewrite = rewriteManifestStaticFieldUses

            match expression with
            | MemberAccess(Apply(Name [ calleeName ], callArguments), [ fieldName ], [])
                when moduleTopLevelDefinitionsByName.ContainsKey(calleeName) ->
                match tryResolveManifestStaticFieldFromFunctionResult calleeName callArguments fieldName with
                | Some staticObject ->
                    Name staticObject.NameSegments
                | None ->
                    MemberAccess(
                        Apply(Name [ calleeName ], callArguments |> List.map rewrite),
                        [ fieldName ],
                        []
                    )
            | TypeSyntaxTokens _ ->
                expression
            | LocalLet(binding, value, body) ->
                LocalLet(binding, rewrite value, rewrite body)
            | LocalSignature(signature, body) ->
                LocalSignature(signature, rewrite body)
            | LocalTypeAlias(declaration, body) ->
                LocalTypeAlias(declaration, rewrite body)
            | LocalScopedEffect(declaration, body) ->
                LocalScopedEffect(declaration, rewrite body)
            | Handle(isDeep, label, body, returnClause, operationClauses) ->
                Handle(
                    isDeep,
                    rewrite label,
                    rewrite body,
                    { returnClause with Body = rewrite returnClause.Body },
                    operationClauses
                    |> List.map (fun clause ->
                        { clause with
                            Body = rewrite clause.Body })
                )
            | Lambda(parameters, body) ->
                Lambda(parameters, rewrite body)
            | IfThenElse(condition, whenTrue, whenFalse) ->
                IfThenElse(rewrite condition, rewrite whenTrue, rewrite whenFalse)
            | Match(scrutinee, cases) ->
                Match(
                    rewrite scrutinee,
                    cases
                    |> List.map (fun caseClause ->
                        { caseClause with
                            Guard = caseClause.Guard |> Option.map rewrite
                            Body = rewrite caseClause.Body })
                )
            | RecordLiteral fields ->
                RecordLiteral(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | Seal(value, ascriptionTokens) ->
                Seal(rewrite value, ascriptionTokens)
            | RecordUpdate(receiver, fields) ->
                RecordUpdate(rewrite receiver, fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | MemberAccess(receiver, segments, arguments) ->
                MemberAccess(rewrite receiver, segments, arguments |> List.map rewrite)
            | SafeNavigation(receiver, navigation) ->
                SafeNavigation(
                    rewrite receiver,
                    { navigation with
                        Arguments = navigation.Arguments |> List.map rewrite }
                )
            | TagTest(receiver, constructorName) ->
                TagTest(rewrite receiver, constructorName)
            | Do statements ->
                let rec rewriteDoStatement statement =
                    match statement with
                    | DoLet(binding, inner) -> DoLet(binding, rewrite inner)
                    | DoLetQuestion(binding, inner, failure) ->
                        let rewrittenFailure =
                            failure
                            |> Option.map (fun block ->
                                { block with
                                    Body = block.Body |> List.map rewriteDoStatement })

                        DoLetQuestion(binding, rewrite inner, rewrittenFailure)
                    | DoBind(binding, inner) -> DoBind(binding, rewrite inner)
                    | DoVar(name, inner) -> DoVar(name, rewrite inner)
                    | DoAssign(name, inner) -> DoAssign(name, rewrite inner)
                    | DoUsing(binding, inner) -> DoUsing(binding, rewrite inner)
                    | DoDefer inner -> DoDefer(rewrite inner)
                    | DoIf(condition, whenTrue, whenFalse) ->
                        DoIf(rewrite condition, whenTrue |> List.map rewriteDoStatement, whenFalse |> List.map rewriteDoStatement)
                    | DoWhile(condition, body) ->
                        DoWhile(rewrite condition, body |> List.map rewriteDoStatement)
                    | DoReturn inner -> DoReturn(rewrite inner)
                    | DoExpression inner -> DoExpression(rewrite inner)

                Do(statements |> List.map rewriteDoStatement)
            | MonadicSplice inner ->
                MonadicSplice(rewrite inner)
            | ExplicitImplicitArgument inner ->
                ExplicitImplicitArgument(rewrite inner)
            | NamedApplicationBlock fields ->
                NamedApplicationBlock(fields |> List.map (fun field -> { field with Value = rewrite field.Value }))
            | InoutArgument inner ->
                InoutArgument(rewrite inner)
            | Apply(callee, arguments) ->
                Apply(rewrite callee, arguments |> List.map rewrite)
            | Unary(operatorName, inner) ->
                Unary(operatorName, rewrite inner)
            | Binary(left, operatorName, right) ->
                Binary(rewrite left, operatorName, rewrite right)
            | Elvis(left, right) ->
                Elvis(rewrite left, rewrite right)
            | Comprehension comprehension ->
                Comprehension { comprehension with Lowered = rewrite comprehension.Lowered }
            | PrefixedString(prefix, parts) ->
                PrefixedString(
                    prefix,
                    parts
                    |> List.map (function
                        | StringText _ as part -> part
                        | StringInterpolation(inner, format) -> StringInterpolation(rewrite inner, format))
                )
            | SyntaxQuote inner ->
                SyntaxQuote(rewrite inner)
            | SyntaxSplice inner ->
                SyntaxSplice(rewrite inner)
            | TopLevelSyntaxSplice inner ->
                TopLevelSyntaxSplice(rewrite inner)
            | CodeQuote inner ->
                CodeQuote(rewrite inner)
            | CodeSplice inner ->
                CodeSplice(rewrite inner)
            | Literal _
            | NumericLiteral _
            | KindQualifiedName _
            | Name _ ->
                expression

        let tryRewriteLegacyRecordDestructuringParameters
            (bindingScheme: TypeScheme)
            (parameters: Parameter list)
            (body: SurfaceExpression option)
            =
            let parameterTypes, _ = TypeSignatures.schemeParts bindingScheme

            match parameterTypes, parameters, body with
            | [ recordType ], firstParameter :: remainingParameters, Some body ->
                match normalizeTypeAliases environment.VisibleTypeAliases recordType with
                | TypeRecord fields when not (List.isEmpty fields) ->
                    let parameterCountMatches = List.length fields = List.length parameters
                    let collapsedLegacyRecordParameter = List.length parameters = 1 && List.length fields > 1

                    let trailingParametersMatchFieldTypes =
                        if parameterCountMatches then
                            remainingParameters
                            |> List.zip (fields |> List.skip 1)
                            |> List.forall (fun (field, parameter) ->
                                String.Equals(parameter.Name, field.Name, StringComparison.Ordinal)
                                && (parameter.TypeTokens
                                    |> Option.bind TypeSignatures.parseType
                                    |> Option.map (fun parameterType ->
                                        TypeSignatures.definitionallyEqual
                                            (normalizeTypeAliases environment.VisibleTypeAliases parameterType)
                                            (normalizeTypeAliases environment.VisibleTypeAliases field.Type))
                                    |> Option.defaultValue false))
                        else
                            false

                    let firstParameterMatchesFirstField =
                        String.Equals(firstParameter.Name, fields.Head.Name, StringComparison.Ordinal)

                    if not firstParameterMatchesFirstField
                       || not (collapsedLegacyRecordParameter || (parameterCountMatches && trailingParametersMatchFieldTypes)) then
                        None
                    else
                        let syntheticParameterName = "__kappa_record_param_0"
                        let recordTypeText = TypeSignatures.toText recordType

                        let syntheticParameter =
                            { Name = syntheticParameterName
                              TypeTokens = Some(typeTextTokens recordTypeText)
                              Quantity = None
                              IsImplicit = false
                              IsInout = false
                              IsReceiver = false }

                        let destructuringBinding =
                            { Pattern =
                                AnonymousRecordPattern(
                                    fields
                                    |> List.map (fun field ->
                                        { Name = field.Name
                                          IsImplicit = false
                                          Pattern = NamePattern field.Name }),
                                    None
                                )
                              Quantity = None
                              IsImplicit = false
                              TypeTokens = Some(typeTextTokens recordTypeText)
                              BinderSpans = Map.empty }

                        Some([ syntheticParameter ], Some(LocalLet(destructuringBinding, Name [ syntheticParameterName ], body)))
                | _ ->
                    None
            | _ ->
                None

        let rewrittenDefinitionBody =
            definition.Body
            |> Option.map (rewriteTopLevelManifestStaticFieldUses environment moduleTopLevelDefinitionsByName)

        let effectiveParameters, effectiveBody =
            match effectiveDefinitionParameters, rewrittenDefinitionBody, scheme with
            | parameters, body, Some bindingScheme ->
                match
                    tryRewriteLegacyRecordDestructuringParametersForBinding
                        environment.VisibleTypeAliases
                        bindingScheme
                        parameters
                        body
                with
                | Some rewritten ->
                    rewritten
                | None ->
                    match definition.Parameters, rewrittenDefinitionBody, scheme with
                    | [], Some(Lambda(lambdaParameters, lambdaBody)), bindingScheme ->
                        let callInferredParameterTypes =
                            if bindingScheme.IsSome then
                                None
                            else
                                tryInferLambdaParameterTypesFromTopLevelCalls lambdaParameters

                        let annotatedParameters =
                            match bindingScheme with
                            | Some bindingScheme ->
                                let parameterTypes, _ = TypeSignatures.schemeParts bindingScheme

                                if List.length parameterTypes = List.length lambdaParameters then
                                    lambdaParameters
                                    |> List.zip parameterTypes
                                    |> List.map (fun (parameterType, parameter) ->
                                        if parameter.TypeTokens.IsSome then
                                            parameter
                                        else
                                            { parameter with
                                                TypeTokens = Some(typeTextTokens (TypeSignatures.toText parameterType)) })
                                else
                                    lambdaParameters
                            | None ->
                                lambdaParameters
                                |> List.mapi (fun index parameter ->
                                    if parameter.TypeTokens.IsSome then
                                        parameter
                                    else
                                        match callInferredParameterTypes |> Option.bind (List.tryItem index) with
                                        | Some inferredType ->
                                            { parameter with
                                                TypeTokens = Some(typeTextTokens (TypeSignatures.toText inferredType)) }
                                        | None ->
                                            parameter)

                        annotatedParameters, Some lambdaBody
                    | _ ->
                        parameters, rewrittenDefinitionBody
            | [], Some(Lambda(lambdaParameters, lambdaBody)), bindingScheme ->
                let callInferredParameterTypes =
                    if bindingScheme.IsSome then
                        None
                    else
                        tryInferLambdaParameterTypesFromTopLevelCalls lambdaParameters

                let annotatedParameters =
                    match bindingScheme with
                    | Some bindingScheme ->
                        let parameterTypes, _ = TypeSignatures.schemeParts bindingScheme

                        if List.length parameterTypes = List.length lambdaParameters then
                            lambdaParameters
                            |> List.zip parameterTypes
                            |> List.map (fun (parameterType, parameter) ->
                                if parameter.TypeTokens.IsSome then
                                    parameter
                                else
                                    { parameter with
                                        TypeTokens = Some(typeTextTokens (TypeSignatures.toText parameterType)) })
                        else
                            lambdaParameters
                    | None ->
                        lambdaParameters
                        |> List.mapi (fun index parameter ->
                            if parameter.TypeTokens.IsSome then
                                parameter
                            else
                                match callInferredParameterTypes |> Option.bind (List.tryItem index) with
                                | Some inferredType ->
                                    { parameter with
                                        TypeTokens = Some(typeTextTokens (TypeSignatures.toText inferredType)) }
                                | None ->
                                    parameter)

                annotatedParameters, Some lambdaBody
            | _ ->
                effectiveDefinitionParameters, rewrittenDefinitionBody

        let loweredBody =
            effectiveBody
            |> Option.map (
                lowerBindingBody
                    bodyEnvironment
                    recordLayouts
                    scheme
                    effectiveParameters
                    (schemeConstraintParameterLocalTypes @ parameterConstraintLocalTypes)
            )

        let parameters =
            hiddenParameters @ buildBindingParameters environment.VisibleTypeAliases scheme effectiveParameters

        let provenance =
            declarationOrigin filePath (Some environment.CurrentModuleIdentity) (LetDeclaration definition)

        { Source = LetDeclaration definition
          Binding =
            Some
                { Visibility = definition.Visibility
                  IsOpaque = definition.IsOpaque
                  Name = definition.Name
                  Parameters = parameters
                  ReturnType = lowerBindingReturnTypeExpr scheme effectiveParameters definition.ReturnTypeTokens
                  ReturnTypeText = lowerBindingReturnType scheme effectiveParameters definition.ReturnTypeTokens
                  Body = loweredBody
                  BodyText = loweredBody |> Option.map (fun _ -> "")
                  Provenance = provenance }
          Provenance = provenance }

    let private synthesizeTraitDispatchBindings
        (filePath: string)
        (traitInfo: TraitInfo)
        =
        traitInfo.Members
        |> Map.toList
        |> List.map (fun (memberName, memberInfo) ->
            let parameterTypes, resultType = TypeSignatures.schemeParts memberInfo.Scheme
            let dictionaryParameterName = "__kappa_dict"
            let dictionaryArgumentTypes =
                traitInfo.TypeParameters |> List.map TypeVariable

            let valueParameterNames =
                parameterTypes
                |> List.mapi (fun index _ -> $"arg{index}")

            let parameters =
                lowerSyntheticKCoreParameter
                    dictionaryParameterName
                    None
                    false
                    (Some(dictionaryType traitInfo.Name dictionaryArgumentTypes))
                :: (List.zip valueParameterNames parameterTypes
                    |> List.map (fun (parameterName, parameterType) ->
                        lowerSyntheticKCoreParameter parameterName None false (Some parameterType)))

            let body =
                KCoreTraitCall(
                    traitInfo.Name,
                    memberName,
                    KCoreName [ dictionaryParameterName ],
                    valueParameterNames |> List.map (fun parameterName -> KCoreName [ parameterName ])
                )

            let provenance =
                syntheticOrigin
                    filePath
                    (Some traitInfo.ModuleIdentity)
                    (TraitRuntime.dispatchBindingName traitInfo.Name memberName)
                    "trait-dispatch"

            makeSyntheticBindingDeclaration
                (TraitRuntime.dispatchBindingName traitInfo.Name memberName)
                (lowerSyntheticKCoreParameter
                    dictionaryParameterName
                    None
                    false
                    (Some(dictionaryType traitInfo.Name dictionaryArgumentTypes))
                 :: (List.zip valueParameterNames parameterTypes
                     |> List.map (fun (parameterName, parameterType) ->
                         lowerSyntheticKCoreParameter parameterName None false (Some parameterType))))
                (Some resultType)
                body
                provenance)

    let private synthesizeInstanceBindings
        (surfaceIndex: Map<ModuleIdentity, ModuleSurfaceInfo>)
        (recordLayouts: Map<string, SyntheticRecordLayout> ref)
        (filePath: string)
        (moduleIdentity: ModuleIdentity)
        (instanceInfo: InstanceInfo)
        =
        let selfDictionaryName = "__kappa_self_dict"
        let instanceTraitName = traitReferenceRuntimeName instanceInfo.Trait

        let traitInfo =
            mergeVisibleTraits surfaceIndex moduleIdentity
            |> Map.tryFind instanceTraitName

        let substitution =
            match traitInfo with
            | Some traitInfo when List.length traitInfo.TypeParameters = List.length instanceInfo.HeadTypes ->
                List.zip traitInfo.TypeParameters instanceInfo.HeadTypes |> Map.ofList
            | _ ->
                Map.empty

        let visibleBindings = mergeVisibleBindings surfaceIndex moduleIdentity
        let visibleComponents = computeVisibleEnvironmentComponents surfaceIndex moduleIdentity

        let environment =
            buildBaseBindingLoweringEnvironment
                surfaceIndex
                moduleIdentity
                (surfaceIndex[moduleIdentity].BindingSchemes
                 |> Map.keys
                 |> Set.ofSeq)
                visibleBindings
                visibleComponents

        let instanceConstraints = instanceInfo.Constraints

        let hiddenConstraintEntries =
            instanceConstraints
            |> List.mapi (fun index constraintInfo ->
                let dictionaryParameterName = $"__kappa_dict_{traitConstraintBinderStem constraintInfo}_{index}"
                constraintInfo, dictionaryParameterName)

        let selfConstrainedMembers =
            traitInfo
            |> Option.map (fun currentTraitInfo ->
                currentTraitInfo.Members
                |> Map.toList
                |> List.map (fun (memberName, _) -> memberName, (instanceTraitName, selfDictionaryName))
                |> Map.ofList)
            |> Option.defaultValue Map.empty

        let bodyEnvironment =
            let premiseConstrainedMembers = buildConstrainedMembers environment instanceConstraints
            let premiseConstraintDictionaries =
                hiddenConstraintEntries
                |> List.map (fun (constraintInfo, dictionaryParameterName) ->
                    constraintInfo, KCoreName [ dictionaryParameterName ])
                |> buildConstraintDictionaries environment

            let selfConstraintDictionaries =
                buildConstraintDictionaries
                    environment
                    [ { Trait = instanceInfo.Trait
                        Arguments = instanceInfo.HeadTypes },
                      KCoreName [ selfDictionaryName ] ]

            { environment with
                ConstraintDictionaries =
                    premiseConstraintDictionaries
                    |> Map.fold (fun state key value ->
                        if Map.containsKey key state then
                            state
                        else
                            Map.add key value state) selfConstraintDictionaries
                ConstrainedMembers =
                    premiseConstrainedMembers
                    |> Map.fold (fun state memberName route ->
                        if Map.containsKey memberName state then
                            state
                        else
                            Map.add memberName route state) selfConstrainedMembers }

        let memberBindings =
            traitInfo
            |> Option.map (fun traitInfo ->
                traitInfo.Members
                |> Map.toList
                |> List.choose (fun (memberName, memberInfo) ->
                    let memberDefinition =
                        instanceInfo.Members
                        |> Map.tryFind memberName
                        |> Option.map (fun definition -> definition, false)
                        |> Option.orElseWith (fun () ->
                            memberInfo.DefaultDefinition
                            |> Option.map (fun definition -> definition, true))

                    memberDefinition
                    |> Option.map (fun (definition, isDefaultDefinition) ->
                        let specializedScheme =
                            memberInfo.Scheme |> TypeSignatures.applySchemeSubstitution substitution

                        let extraLocalTypes =
                            [ selfDictionaryName, TypeName([ instanceTraitName ], instanceInfo.HeadTypes) ]
                            @ (hiddenConstraintEntries
                               |> List.map (fun (constraintInfo, dictionaryParameterName) ->
                                   dictionaryParameterName, traitConstraintTypeName constraintInfo))

                        let loweredBody =
                            definition.Body
                            |> Option.map (
                                lowerBindingBody
                                    bodyEnvironment
                                    recordLayouts
                                    (Some specializedScheme)
                                    definition.Parameters
                                    extraLocalTypes
                            )

                        let parameters =
                            lowerSyntheticKCoreParameter
                                selfDictionaryName
                                None
                                true
                                (Some(dictionaryType instanceTraitName instanceInfo.HeadTypes))
                            :: (hiddenConstraintEntries
                                |> List.map (fun (constraintInfo, dictionaryParameterName) ->
                                    lowerSyntheticKCoreParameter
                                        dictionaryParameterName
                                        None
                                        true
                                        (Some(dictionaryType (traitConstraintRuntimeName (attachResolvedTraitConstraint environment constraintInfo)) constraintInfo.Arguments))))
                            @ buildBindingParameters environment.VisibleTypeAliases (Some specializedScheme) definition.Parameters

                        let provenance =
                            syntheticOrigin
                                filePath
                                (Some moduleIdentity)
                                (TraitRuntime.instanceMemberBindingName instanceTraitName instanceInfo.InstanceKey memberName)
                                (if isDefaultDefinition then "instance-default-member" else "instance-member")

                        makeSyntheticBindingDeclaration
                            (TraitRuntime.instanceMemberBindingName instanceTraitName instanceInfo.InstanceKey memberName)
                            parameters
                            (lowerBindingReturnTypeExpr (Some specializedScheme) definition.Parameters definition.ReturnTypeTokens)
                            (loweredBody |> Option.defaultValue (KCoreLiteral LiteralValue.Unit))
                            provenance)))
            |> Option.defaultValue []

        let dictionaryBinding =
            let dictionaryParameters =
                hiddenConstraintEntries
                |> List.map (fun (constraintInfo, dictionaryParameterName) ->
                    lowerSyntheticKCoreParameter
                        dictionaryParameterName
                        None
                        true
                        (Some(dictionaryType (traitConstraintRuntimeName (attachResolvedTraitConstraint environment constraintInfo)) constraintInfo.Arguments)))

            let dictionaryCaptures =
                hiddenConstraintEntries
                |> List.map (fun (_, dictionaryParameterName) -> KCoreName [ dictionaryParameterName ])

            let provenance =
                syntheticOrigin
                    filePath
                    (Some moduleIdentity)
                    (TraitRuntime.instanceDictionaryBindingName instanceTraitName instanceInfo.InstanceKey)
                    "instance-dictionary"

            makeSyntheticBindingDeclaration
                (TraitRuntime.instanceDictionaryBindingName instanceTraitName instanceInfo.InstanceKey)
                dictionaryParameters
                (Some(dictionaryType instanceTraitName instanceInfo.HeadTypes))
                (KCoreDictionaryValue(
                    ModuleIdentity.text moduleIdentity,
                    instanceTraitName,
                    instanceInfo.InstanceKey,
                    dictionaryCaptures
                ))
                provenance

        memberBindings @ [ dictionaryBinding ]

    let lowerKCoreModules
        backendProfile
        allowUnsafeConsume
        (frontendModules: KFrontIRModule list)
        (hostModules: Map<ModuleIdentity, HostBindings.HostModuleDescription>)
        =
        let surfaceIndex = buildSurfaceIndex frontendModules hostModules
        let effectDeclarationsByModule = buildEffectDeclarationIndex frontendModules

        frontendModules
        |> List.map (fun frontendModule ->
            let moduleName = moduleNameText frontendModule.ModuleIdentity
            match frontendModule.ModuleIdentity |> moduleIdentityOfOptionalSegments with
            | None ->
                { Name = moduleName
                  ModuleIdentity = None
                  SourceFile = frontendModule.FilePath
                  ModuleAttributes = frontendModule.ModuleAttributes
                  Imports = frontendModule.Imports
                  VisibleTraitTypeParameterCounts = Map.empty
                  IntrinsicTerms = []
                  SyntheticDataTypes = []
                  Ownership = frontendModule.Ownership
                  Declarations = [] }
            | Some moduleIdentity ->
                let topLevelEffects =
                    let localEffects =
                        frontendModule.Declarations
                        |> List.choose (function
                            | EffectDeclarationNode declaration -> Some(EffectSemantics.ensureTopLevel moduleIdentity declaration)
                            | _ -> None)

                    localEffects @ importedEffectDeclarations surfaceIndex effectDeclarationsByModule moduleIdentity

                withScopedEffectDeclarations moduleIdentity topLevelEffects (fun () ->
                    let moduleInfo = surfaceIndex[moduleIdentity]
                    let recordLayouts = ref Map.empty
                    let visibleComponents = computeVisibleEnvironmentComponents surfaceIndex moduleIdentity
                    let visibleBindings = mergeVisibleBindings surfaceIndex moduleIdentity

                    let baseEnvironment =
                        buildBaseBindingLoweringEnvironment
                            surfaceIndex
                            moduleIdentity
                            (topLevelDefinitionNames frontendModule.Declarations)
                            visibleBindings
                            visibleComponents

                    let environment =
                        let staticObjectAliases =
                            let localAliases =
                                buildStaticObjectAliasesForModule baseEnvironment frontendModule.Declarations

                            topLevelEffects
                            |> List.filter (fun declaration -> declaration.Name.Contains("."))
                            |> List.fold (fun current declaration ->
                                let semanticDeclaration =
                                    declaration
                                    |> EffectSemantics.ensureTopLevel moduleIdentity
                                    |> EffectSemantics.toSemantic (Some(topLevelDeclarationIdentity moduleIdentity declaration.Name EffectDeclaration))

                                Map.add (declaration.Name.Split('.', StringSplitOptions.RemoveEmptyEntries) |> Array.toList) (scopedEffectLabelStaticObject semanticDeclaration) current) localAliases

                        { baseEnvironment with
                            VisibleStaticGroups =
                                buildVisibleStaticGroups
                                    baseEnvironment.VisibleTypeFacets
                                    staticObjectAliases
                                    baseEnvironment.VisibleTraits
                            VisibleStaticObjects = staticObjectAliases }

                    let declarations =
                        let moduleTopLevelDefinitionsByName, sourceBindingInfosByName =
                            buildSourceBindingInfosByName moduleIdentity frontendModule.Declarations

                        let availableTopLevelDefinitionsByName =
                            mergeVisibleBindingDefinitions surfaceIndex moduleIdentity
                            |> Map.fold (fun state name definition -> Map.add name definition state) moduleTopLevelDefinitionsByName

                        let sourceSignatureDeclarationsByName =
                            frontendModule.Declarations
                            |> List.choose (function
                                | SignatureDeclaration declaration -> Some(declaration.Name, declaration)
                                | _ -> None)
                            |> Map.ofList

                        frontendModule.Declarations
                        |> List.collect (fun declaration ->
                            let provenance = declarationOrigin frontendModule.FilePath (Some moduleIdentity) declaration

                            let originalDeclaration =
                                match declaration with
                                | LetDeclaration definition when definition.Name.IsSome ->
                                    let sourceSignature =
                                        sourceSignatureDeclarationsByName
                                        |> Map.tryFind definition.Name.Value

                                    let bindingInfo =
                                        sourceBindingInfosByName
                                        |> Map.tryFind definition.Name.Value

                                    [ lowerUserBinding
                                          environment
                                          recordLayouts
                                          availableTopLevelDefinitionsByName
                                          frontendModule.FilePath
                                          definition
                                          sourceSignature
                                          bindingInfo ]
                                | _ ->
                                    [ { Source = declaration
                                        Binding = None
                                        Provenance = provenance } ]

                            match declaration with
                            | TraitDeclarationNode declaration ->
                                originalDeclaration
                            | InstanceDeclarationNode declaration ->
                                let instanceKey = TraitRuntime.instanceKeyFromTokens declaration.HeaderTokens
                                let parsedInstanceHeader = tryParseInstanceHeader declaration
                                let inline rebuildInstanceInfo () =
                                    parsedInstanceHeader
                                    |> Option.map (fun (traitReference, constraints, headTypes) ->
                                        { ModuleIdentity = moduleIdentity
                                          Trait = traitReference
                                          InstanceKey = instanceKey
                                          Constraints = constraints
                                          HeadTypes = headTypes
                                          Members =
                                            declaration.Members
                                            |> List.choose (fun memberDeclaration ->
                                                memberDeclaration.Name
                                                |> Option.map (fun memberName -> memberName, memberDeclaration))
                                            |> Map.ofList })

                                match
                                    parsedInstanceHeader
                                    |> Option.bind (fun (traitReference, _, _) ->
                                        moduleInfo.Instances
                                        |> List.tryFind (fun info ->
                                            String.Equals(info.InstanceKey, instanceKey, StringComparison.Ordinal)
                                            && TypeSignatures.TraitReference.matches info.Trait traitReference))
                                    |> Option.orElseWith rebuildInstanceInfo
                                with
                                | Some instanceInfo ->
                                    originalDeclaration
                                    @ synthesizeInstanceBindings surfaceIndex recordLayouts frontendModule.FilePath moduleIdentity instanceInfo
                                | None ->
                                    // Parse-invalid instance declarations may survive as surface nodes with diagnostics but
                                    // intentionally produce no semantic instance info. Lowering must not crash on them.
                                    originalDeclaration
                            | _ ->
                                originalDeclaration)

                    let intrinsicTerms =
                        match frontendModule.ModuleIdentity with
                        | Some moduleNameSegments ->
                            frontendModule.Declarations
                            |> List.choose (function
                                | ExpectDeclarationNode declaration
                                    when Stdlib.intrinsicallySatisfiesExpectForCompilationProfile
                                            backendProfile
                                            allowUnsafeConsume
                                            moduleNameSegments
                                            declaration ->
                                    match declaration with
                                    | ExpectTermDeclaration termDeclaration -> Some termDeclaration.Name
                                    | _ -> None
                                | _ ->
                                    None)
                        | None ->
                            []

                    { Name = moduleName
                      ModuleIdentity = Some moduleIdentity
                      SourceFile = frontendModule.FilePath
                      ModuleAttributes = frontendModule.ModuleAttributes
                      Imports = frontendModule.Imports
                      VisibleTraitTypeParameterCounts =
                        environment.VisibleTraits
                        |> Map.map (fun _ traitInfo -> traitInfo.TypeParameters.Length)
                      IntrinsicTerms = intrinsicTerms |> List.distinct |> List.sort
                      SyntheticDataTypes =
                        recordLayouts.Value
                        |> Map.toList
                        |> List.map snd
                        |> List.sortBy (fun layout -> layout.TypeName)
                        |> List.map (fun layout ->
                            { Name = layout.TypeName
                              TypeParameters = layout.TypeParameters
                              ConstructorName = layout.ConstructorName
                              FieldNames = layout.Fields |> List.map (fun field -> field.Name)
                              FieldTypeTexts = layout.Fields |> List.map (fun field -> TypeSignatures.toText field.Type)
                              Provenance = layout.Provenance })
                      Ownership = frontendModule.Ownership
                      Declarations = declarations }))
